export const SUBJECT = "Fizyoloji";
export const QUESTIONS = [{"id":1,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":5,"q":"I-cell (İnklüzyon cisimciği) hastalığında, Golgi aygıtında lizozomal enzimlerin hedeflenmesinden sorumlu olan ve eksikliği hücresel düzeyde enzimlerin lizozom yerine ekstraselüler alana salgılanmasına yol açan enzim aşağıdakilerden hangisidir?","options":["Hekzozaminidaz A","Sfingomiyelinaz","Glukoserebrozidaz","Asit alfa-glukozidaz","N-asetilglukozaminil-1-fosfotransferaz"],"correct":4,"exp":"I-cell hastalığında cis-Golgi'de lizozomal enzimlere mannoz-6-fosfat eklentisini yapan N-asetilglukozaminil-1-fosfotransferaz enzimi eksiktir. Bu spesifik sinyal (M6P) olmaksızın hidrolitik enzimler lizozoma yönlendirilemez ve hücre dışına atılır."},{"id":2,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":5,"q":"Böbrek Henle kulbunun çıkan kalın kolunda parasellüler magnezyum ve kalsiyum geçişini düzenleyen; mutasyonu Ailesel Hipomagnezemi ile Hiperkalsiüri (fhhnc) sendromuna yol açan intersellüler bağlantı (zonula okludens) proteini aşağıdakilerden hangisidir?","options":["Klaudin-16","Konneksin-26","Desmoglein-1","İntegrin alfa-6","Okludin"],"correct":0,"exp":"Klaudin-16 (Parasellin-1), tight junction (zonula okludens) yapısına katılan ve böbreklerde parasellüler Mg+2 ve Ca+2 geri emilimini düzenleyen spesifik bir proteindir. Mutasyonunda böbreklerden magnezyum israfı görülür."},{"id":3,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"İskelet kası sarkomerinde ince filamentlerin (aktin) etrafına sarılarak onların tam uzunluğunu belirleyen ve Z çizgisine tutunmasını stabilize eden regülatör/yapısal dev protein aşağıdakilerden hangisidir?","options":["Nebulin","Titin","Distrofin","Tropomiyozin","Troponin T"],"correct":0,"exp":"Nebulin, ince (aktin) filamentlere sarılarak onların uzunluğunu regüle eden, bir moleküler 'cetvel' görevi gören ve Z çizgisine tutunmalarına yardımcı olan yapısal proteindir. Titin (kalın filamentleri regüle eden) ile karıştırılmamalıdır."},{"id":4,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":5,"q":"Testiste kan-testis bariyerini oluşturan Sertoli-Sertoli hücreleri arasındaki sıkı bağlantı kompleksleri (tight junctions), mayoz bölünme sürecindeki hangi germ hücresinin bazal kompartımandan adluminal kompartımana geçişine izin vermek için geçici olarak açılır?","options":["Preleptoten primer spermatosit","Tip B spermatogonyum","Tip A spermatogonyum","Sekonder spermatosit","Geç spermatid"],"correct":0,"exp":"Kan-testis bariyeri dinamik bir yapıdır. Mayoz I'e yeni girecek olan 'preleptoten evresindeki primer spermatositlerin' adluminal bölgeye güvenle geçmesi için Sertoli hücre bağlantıları aşağıdan açılıp, hücre geçtikten sonra yukarıdan kapanır."},{"id":5,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Embriyolojik gelişim sürecinde epiblast hücrelerinin primitif çizgi boyunca invajinasyonu ile oluşan; ektoderm, mezoderm ve endodermin (3 germ yaprağının) farklılaşmasıyla karakterize gastrulasyon evresi embriyonik gelişimin kaçıncı haftasında başlar?","options":["1. hafta","2. hafta","3. hafta","4. hafta","5. hafta"],"correct":2,"exp":"Gastrulasyon (primitif çizginin oluşumu ve üçlü embriyonik diskin meydana gelmesi) embriyolojik gelişimin 3. haftasının en karakteristik ve kritik olayıdır."},{"id":6,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":5,"q":"Lenf düğümü parakortikal bölgesinde yer alan ve naif T lenfositlerin dolaşımdan diapedez ile lenf düğümüne geçişini (homing) sağlayan yüksek endotelli venüller (hev), lenfositlerdeki L-Selektin'e bağlanmak için yüzeylerinde hangi spesifik adezyon molekülünü eksprese eder?","options":["Pnad (Periferal Nod Adressin)","E-Kaderin","İntegrin alfa-4-beta-7","CD31 (PECAM-1)","VCAM-1"],"correct":0,"exp":"hev endotel hücreleri L-Selektin ligandı olan pnad (Periferal Nod Adressin) adı verilen karbonhidrat zengini proteinleri eksprese eder. Bu molekül dolaşımdaki naif T hücrelerinin L-selektini tarafından tanınarak spesifik homing işlemini başlatır."},{"id":7,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Mide fundus bezlerinde yerleşmiş olan, gastrin ve vagal uyarı sonrası parakrin yolla histamin salgılayarak paryetal hücrelerin asit sekresyonunu (H2 reseptörleri üzerinden) güçlü bir şekilde stimüle eden hücre tipi aşağıdakilerden hangisidir?","options":["G hücreleri","D hücreleri","Paneth hücreleri","Enterokromafin-benzeri (ECL) hücreler","Şef hücreleri"],"correct":3,"exp":"ECL (Enterokromafin-benzeri) hücreler, midenin oksintik (fundik) bezlerinde bulunur ve histamin deposudurlar. Asit sekresyonunun ana stimülatör aksı Gastrin -> ECL hücresi -> Histamin -> Paryetal hücre (H2 reseptörü) şeklindedir."},{"id":8,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Ventriküler miyositlerde aksiyon potansiyelinde plato fazının (Faz 2) oluşumundan ve eksitasyon-kontraksiyon eşleşmesini başlatarak sarkoplazmik retikulumdan 'kalsiyumun tetiklediği kalsiyum salınımını' sağlayan iyon kanalı aşağıdakilerden hangisidir?","options":["L-tipi Kalsiyum kanalı (DHP reseptörü)","T-tipi Kalsiyum kanalı","KATP kanalı","HCN (Funny) kanalı","Na-Ca değiştirici (NCX)"],"correct":0,"exp":"Faz 2'de hücre dışından yavaş kalsiyum girişini sağlayan kanallar L-tipi (Long-lasting) kalsiyum kanallarıdır (Dihidropiridin reseptörleri). Bu yavaş Ca+2 girişi, hücre içindeki ryanodin reseptörlerini aktive ederek kontraksiyonu başlatır."},{"id":9,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Adrenal kortekste en kalın tabaka olan zona fasikülata'da yer alan, steroidogenez (glukokortikoid sentezi) için bol miktarda lipid (kolesterol damlacıkları) içerdiği için rutin histolojik preparasyonlarda hücre sitoplazması köpüksü-süngerimsi görünen hücrelere ne ad verilir?","options":["Spongiyositler","Kromafin hücreler","Pituasitler","Parafolliküler hücreler","Leydig hücreleri"],"correct":0,"exp":"Zona fasikülata hücreleri lipitten çok zengin olduğu için doku takibi sırasında lipidler eridiğinde hücreler açık renkli ve bağlayıcı olarak görünür. Bu nedenle bu hücrelere spesifik olarak 'Spongiyosit' adı verilir."},{"id":10,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Terminal ve respiratuar bronşiyol epitelinde yer alan, silikapsız, apikal yüzeyleri kubbe şeklinde olan; glikozaminoglikan, sörfaktan apoproteinleri ve anti-enflamatuar CC16 proteini salgılayıp sitokrom P450 enzimleri ile detoksifikasyon yapan hücre hangisidir?","options":["Tip 1 Pnömosit","Club (Clara) hücresi","Kulçitski (K) hücresi","Goblet hücresi","Fırçamsı (Brush) hücre"],"correct":1,"exp":"Club (eski adıyla Clara) hücreleri, bronşiyollerin karakteristik hücreleridir. Klor sekresyonu yaparlar, kök hücre potansiyelleri vardır, CC16 salgılarlar ve CYP450 enzimleri aracılığıyla solunan toksinleri nötralize ederler."},{"id":11,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Merkezi sinir sisteminde doku hasarı veya demiyelinizan hastalıklar sonrasında hipertrofiye/hiperplaziye uğrayarak skar dokusu (gliozis) oluşturan ve perivasküler ayakçıkları (pedikül) ile kan-beyin bariyerini destekleyen nöroglial hücre aşağıdakilerden hangisidir?","options":["Oligodendrosit","Mikroglia","Ependim hücresi","Astrosit","Schwann hücresi"],"correct":3,"exp":"Astrositler, MSS'nin yapısal destek hücreleridir. Kapillerleri saran ayakçıkları ile kan-beyin bariyerinin hücresel kılıfını oluştururlar ve nöronal hasar sonrası çoğalarak astrositik skar (reaktif gliozis) meydana getirirler."},{"id":12,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Böbrekte glomerüler filtrasyon bariyerini oluşturan podositlerin ayakçıkları (pediseller) arasında yer alan filtrasyon yarıklarında bulunan ve mutasyonu masif proteinüri ile seyreden Fin Tipi Konjenital Nefrotik Sendroma yol açan transmembran protein hangisidir?","options":["Nefrin","Podoksin","Aktinin-4","Kollajen Tip IV","Heparan sülfat proteoglikan"],"correct":0,"exp":"Nefrin (NPHS1 geni tarafından kodlanır), filtrasyon slit diyaframının iskeletini oluşturan en önemli hücresel adezyon molekülüdür. Mutasyonlarında filtrasyon bariyeri bozulur ve in utero dönemden itibaren ağır proteinüri (Fin tipi nefrotik sendrom) ortaya çıkar."},{"id":13,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Farengeal (brankiyal) aparat gelişiminde, 3. farengeal cebin (pouch) ventral kanadından köken alan; gelişim bozukluğunda (DiGeorge Sendromu - 22q11.2 delesyonu) organın agenezisi nedeniyle sekonder lenfoid dokularda parakortikal alanların boş kaldığı ve şiddetli hücresel immün yetmezlik görülen yapı aşağıdakilerden hangisidir?","options":["Tiroid bezi","Superior paratiroid bezi","İnferior paratiroid bezi","Tonsilla palatina","Timus"],"correct":4,"exp":"3. farengeal cebin dorsal kanadından inferior paratiroid bezleri, ventral kanadından ise timus primordiyumu gelişir. DiGeorge sendromunda timus gelişemediği için T hücre maturasyonu bozulur ve T lenfositlerin yerleştiği lenf düğümü parakortikal bölgeleri (timusa bağımlı alanlar) atrofik kalır."},{"id":565,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Konjestif kalp yetmezliği tedavisi için Digoksin (bir kardiyak glikozid) kullanan hastada miyokardiyal kasılma gücünün (inotropi) artması amaçlanmaktadır. Digoksinin hücre zarındaki 'Na+/K+ ATPaz' pompasını inhibe etmesinin ardından, miyokard hücresi içinde kalsiyum (Ca+2) artışını sağlayan sekonder mekanizma aşağıdakilerden hangisidir?","options":["İnhibe olan pompanın hücre zarında depolarizasyon yaparak voltaj kapılı kalsiyum kanallarını tetiklemesi","Sodyumun doğrudan sarkoplazmik retikulumdaki Ryanodin reseptörlerini uyarması","Hücre dışında biriken potasyumun L-tipi kalsiyum kanallarını kalıcı biçimde açık tutarak kalsiyum girişini artırması","Azalan ATP tüketiminin, Ca+2 ATPaz (serca) pompasını aşırı aktifleştirmesi","Hücre içinde biriken sodyumun (Na+), 'Na+/Ca+2 değiştirici (NCX)' pompasının çalışma yönünü tersine çevirerek kalsiyumu hücre içine alması"],"correct":4,"exp":"Na+/K+ ATPaz pompası normalde 3 Na'yı dışarı atar, 2 K'yı içeri alır. Ouabain veya Digoksin bu pompanın potasyum bağlanan bölgesine yapışarak onu bloke eder. Pompa durunca hücre içindeki Na+ dışarı atılamaz ve sitoplazmada birikir. Miyokard zarında bulunan ve normalde kalsiyumu dışarı atıp sodyumu içeri alan 'Na+/Ca+2 Değiştirici (NCX)' adlı sekonder aktif taşıma pompası, içeride sodyumun çok arttığını (gradyentin bozulduğunu) görünce çalışma yönünü tersine çevirir. Fazla sodyumu dışarı atmak için karşılığında dışarıdan Kalsiyumu (Ca+2) hücre içine çekmeye başlar."},{"id":566,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Hücre içi veziküler transport mekanizmalarını araştıran bir çalışmada, proteinlerin Golgi aygıtından (cis-Golgi) Granüllü Endoplazmik Retikuluma (rer) doğru 'retrograd (geriye doğru)' taşınmasından sorumlu olan vezikül örtü proteini incelenmektedir. Bu retrograd taşımayı sağlayan ve özellikle 'kdel' aminoasit dizisine sahip ER proteinlerini geri kurtaran örtü proteini aşağıdakilerden hangisidir?","options":["Klatrin (Clathrin)","Dinamin","Cop II (Coatomer II)","Kaveolin","Cop I (Coatomer I)"],"correct":4,"exp":"Hücre içi vezikül trafiğinde kaplayıcı (coat) proteinler rotayı belirler. 1) cop II (İleri/Anterograd): Proteinleri Granüllü ER'den alır, Golgi'ye (cis) taşır (Step 2 = cop II = İleri). 2) cop I (Geri/Retrograd): Golgi'den ER'ye geri taşır (Step 1 = cop I = Geri). Yanlışlıkla Golgi'ye kaçmış olan ve üzerinde 'kdel' (ER tutunma sinyali) şifresi bulunan demirbaş ER proteinlerini cop I yakalar ve evine (ER'ye) geri getirir. 3) Klatrin: Golgi'den lizozoma gidenleri (M6P işaretli) veya hücre zarından reseptör aracılı endositozla (LDL gibi) içeri girenleri kaplar."},{"id":567,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Kırk beş yaşında kadın hasta, cildinde kolayca patlayan ve içi sıvı dolu gevşek büllerle (Pemphigus Vulgaris) başvuruyor. Yapılan immünfloresan incelemede, epidermal hücreleri birbirine bağlayan bağlantı komplekslerine karşı gelişmiş (Anti-Desmoglein) IgG tipi otoantikorlar saptanıyor. Bu hastada fonksiyonu bozulan ve hücreleri 'perçin (punto)' şeklinde birbirine bağlayarak mekanik strese karşı koruyan hücreler arası bağlantı yapısı aşağıdakilerden hangisidir?","options":["Zonula occludens (Sıkı bağlantılar / Tight junctions)","Macula adherens (Desmozomlar)","Zonula adherens (Kemer bağlantıları)","Hemidesmozomlar","Neksus (Oluklu bağlantılar / Gap junctions)"],"correct":1,"exp":"Epitel dokusunda hücreleri bir arada tutan yapılar klinik için çok önemlidir. Pemphigus Vulgaris'te otoantikorların hedefi 'Desmoglein 1 ve 3' adlı kaderin ailesi proteinlerdir. Desmoglein, hücreleri birbirine bir perçin gibi sıkıca bağlayan 'Macula Adherens (Desmozom)'lerin ana yapısıdır. Desmozomlar hücre içindeki keratin (ara) filamanlarına tutunarak deriye mekanik dayanıklılık verir. Bunlar yıkılınca epidermis hücreleri birbirinden kopar (akantoliz) ve büller oluşur."},{"id":568,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":5,"q":"Sempatik sinir sistemi aktivasyonu sırasında, nörotransmitter olan Noradrenalin, damar düz kas hücrelerindeki Alfa-1 (α1) adrenerjik reseptörlere bağlanır. Bu reseptör bir G-protein kenetli reseptördür (Gq). Alfa-1 reseptörünün aktivasyonu ile başlayıp düz kas kasılmasıyla sonuçlanan hücre içi ikinci haberci yolağındaki sıra aşağıdakilerden hangisinde doğru verilmiştir?","options":["Fosfolipaz C aktivasyonu → pıp2'nin yıkılması → IP3 ve dag oluşumu → IP3'ün endoplazmik retikulumdan kalsiyum salgılatması","Adenilat Siklaz aktivasyonu → cAMP artışı → Protein Kinaz A aktivasyonu → Miyozin hafif zincir kinaz inhibisyonu","Fosfolipaz A2 aktivasyonu → Araşidonik asit salınımı → Lökotrien sentezi","Guanilat Siklaz aktivasyonu → cgmp artışı → Protein Kinaz G aktivasyonu → Düz kas gevşemesi","Tirozin Kinaz aktivasyonu → stat proteinlerinin fosforilasyonu → Çekirdekte transkripsiyon"],"correct":0,"exp":"Otonom sinir sistemi reseptörlerinin hücre içi sinyal yolakları qıss ve qıq (Kıs-kik) kuralını hatırlayalım. Alfa-1 reseptörü 'Gq' kenetlidir. Gq proteinleri daima 'Fosfolipaz C' enzimini aktive eder. Fosfolipaz C, hücre zarındaki pıp2'yi ikiye böler: IP3 ve dag. İkincil habercilerden dag zarda kalarak Protein Kinaz C'yi (PKC) uyarır."},{"id":569,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"İstirahat halindeki tipik bir memeli nöronunun hücre zarı potansiyeli (Resting Membrane Potential - rmp) yaklaşık -70 mV civarındadır. Bu potansiyelin oluşmasında hücre zarının belirli iyonlara karşı seçici geçirgenliği rol oynar. Nöronun istirahat zar potansiyelini kendi denge (Nernst) potansiyeline en çok yaklaştıran (ve zarın istirahatte en geçirgen olduğu) iyon aşağıdakilerden hangisidir?","options":["Sodyum (Na+)","Kalsiyum (Ca+2)","Klor (Cl-)","Potasyum (K+)","Magnezyum (Mg+2)"],"correct":3,"exp":"Hücre zarının İstirahat Potansiyelinin (rmp) ana sorumlusu 'Potasyum (K+)' iyonudur. Çünkü hücre zarı, istirahat halindeyken (hiçbir uyarı yokken) sızma kanalları (leak channels) aracılığıyla Potasyuma karşı diğer iyonlardan çok daha fazla (yaklaşık 50-100 kat) geçirgendir. Sodyum için denge potansiyeli +60 mV, Potasyum için -90 mV'dur. Zar potasyuma aşırı geçirgen olduğu için, istirahat potansiyeli (-70 mV) mecburen potasyumun denge potansiyeline doğru çekilir (Nernst denklemi ve Goldman-Hodgkin-Katz eşitliği). Sodyum içeri sızarak bu değeri -90'dan -70'e getirir."},{"id":570,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Çocukluk çağından beri tekrarlayan sinüzit, bronşektazi ve otitis media atakları olan 25 yaşındaki erkek hasta, infertilite (kısırlık) şikayetiyle başvuruyor. Çekilen akciğer grafisinde kalbin sağ tarafta yerleştiği (Dextrocardia) ve tam situs inversus olduğu görülüyor. Kartagener Sendromu tanısı alan bu hastada, solunum epiteli ve sperm kuyruğundaki (kamçı) hareketliliği bozarak bu klinik tabloya yol açan ultrastrüktürel hücre iskeleti defekti aşağıdakilerden hangisidir?","options":["Aktin mikrofilamanlarında polimerizasyon kusuru","Konneksin proteinlerindeki mutasyon","Kollajen tip IV sentez defekti","Mikrovillus yapısındaki miyozin-1 eksikliği","Mikrotübüllerin 'Dinein (Dynein)' kollarındaki yapısal eksiklik"],"correct":4,"exp":"Kartagener Sendromu (Primer Siliyer Diskinezi), 'Silya (Tüy)' ve 'Flagella (Kamçı)' yapısının genetik defektidir. Solunum yolunda silyalar mukusu itemez (bronşektazi, sinüzit). Sperm kamçısı hareket edemez (infertilite). Fallop tüpü silyaları embriyoyu itemez (ektopik gebelik). Anne karnında embriyonun organ yerleşimini belirleyen silyalar çalışmazsa organlar ters yerleşir."},{"id":571,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Sık kemik kırıkları, işitme kaybı ve göz aklarında mavimsi renk değişikliği (mavi sklera) ile karakterize Osteogenezis İmperfekta (Cam Kemik Hastalığı) hastası bir çocuk değerlendiriliyor. Bu hastalıkta, bağ dokusunun en bol bulunan proteini olan 'Tip 1 Kollajen'in sentez basamaklarından hangisi ve nerede bozulmuştur?","options":["Hücre dışında propeptidaz enzimleriyle tropokollajen oluşumunun gerçekleşememesi","Golgi aygıtında kollajenin salgı veziküllerine paketlenerek taşınamaması","Granüllü endoplazmik retikulumda üç alfa zincirinin üçlü sarmal yapıyı oluşturamaması","Hücre dışında lizil oksidazla lifler arasında çapraz bağ kurulamaması","Prolin ve lizin kalıntılarının C vitamini eksikliği nedeniyle hidroksillenememesi"],"correct":2,"exp":"Osteogenezis İmperfekta (Oİ), genellikle Tip 1 Kollajeni kodlayan (col1A1 veya col1A2) genlerdeki otozomal dominant bir mutasyondur. Sıklıkla kollajen zincirindeki en küçük aminoasit olan 'Glisin'in yerine başka (daha büyük) bir aminoasit geçer. Kollajenin çok sıkı olan 'Üçlü Sarmal (Triple Helix)' yapısının oluşabilmesi için her 3 aminoasitten birinin mutlaka Glisin olması şarttır. Glisin mutasyona uğrayınca, rer (Granüllü ER) lümeninde üçlü sarmal düzgün kıvrılamaz ve hatalı kollajen üretilir (veya yıkılır). Bu da kemiği, dişi ve sklerayı dayanıksız hale getirir."},{"id":572,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Kısa kollar ve bacaklar (rizomelik cücelik), belirgin bir alın ve normal boyutta bir gövde ile karakterize Akondroplazi hastası bir çocuk inceleniyor. Hastalığın temelinde Fibroblast Büyüme Faktörü Reseptörü-3 (FGFR3) geninde otozomal dominant 'kazanç (gain-of-function)' mutasyonu saptanıyor. FGFR3 reseptörünün sürekli aktif kalması, epifiz kıkırdağında (büyüme plağında) endokondral kemikleşmeyi nasıl etkileyerek cüceliğe yol açar?","options":["Kondrosit proliferasyonunu aşırı uyararak büyüme plağının erken kapanmasına yol açması","Epifiz plağındaki osteoklastik aktiviteyi artırarak yeni oluşan kemiği hızla eritmesi","Osteoblastların matriks sentezini bloke ederek kemikleşmenin hiç başlayamaması","Kondrositlerin proliferasyon ve hipertrofisini sürekli baskılayarak kıkırdak çoğalmasını durdurması","Tip X kollajen sentezini bozarak hipertrofik kıkırdağın kalsifiye olamaması"],"correct":3,"exp":"Akondroplazi, cüceliğin en sık nedenidir (Endokondral kemikleşme bozukluğudur). Membranöz kemikleşme (kafatası, köprücük kemiği) normal olduğu için baş büyüktür, kol ve bacaklar kısadır. İnsan vücudunda FGFR3 reseptörünün normal (fizyolojik) görevi, epifiz plağındaki kondrositlerin (kıkırdak hücrelerinin) büyümesini 'frenlemek' (inhibe etmek) tir. Mutasyon bir 'Gain-of-Function (işlev kazancı)' mutasyonudur. Yani fren pedalı takılı kalır (sürekli aktiftir)."},{"id":573,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Yenidoğan bebeklerde üşümeye karşı vücut sıcaklığını korumak için titremesiz termojenez (non-shivering thermogenesis) çok önemlidir. Bu ısı üretimi, özellikle boyun, sırt ve böbrek çevresinde bulunan 'Kahverengi Yağ Dokusu (Brown Adipose Tissue)' tarafından sağlanır. Kahverengi yağ dokusunun mitokondrilerinde ısı üretimini sağlayan ve oksidatif fosforilasyonu ayırarak ATP yerine ısı açığa çıkaran spesifik protein aşağıdakilerden hangisidir?","options":["Sitokrom c oksidaz","Leptin","Adiponektin","Termogenin (ucp-1)","ATP Sentaz"],"correct":3,"exp":"Beyaz yağ dokusu tek bir büyük yağ damlacığı içerir (enerji deposudur). Kahverengi yağ dokusu ise bol miktarda küçük yağ damlacığı ve belirgin miktarda demir içeren mitokondri içerir (rengi bu yüzden kahverengidir). Yenidoğanlarda titreme refleksi gelişmediği için soğuğa karşı Kahverengi Yağ dokusunu kullanırlar. Bu dokunun mitokondri iç zarında 'Termogenin (Uncoupling Protein 1 - ucp-1)' adı verilen özel bir kanal vardır. Bu kanal, solunum zincirinde zarlar arasına pompalanan protonların (H+) ATP sentazdan geçerek ATP yapmasını engeller (Ayırıcı/Uncoupler)."},{"id":574,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Ergenlik döneminde artan androjenlerin etkisiyle yüzde ve sırtta sivilce (Akne Vulgaris) oluşumu hızlanmaktadır. Akne patogenezinde kilit rol oynayan 'Sebase (yağ) bezleri', salgılarını kıl folikülüne boşaltırken hücrenin tümünün parçalanarak salgının bir parçası haline geldiği bir yöntem kullanırlar. Epitel hücrelerinde görülen bu spesifik salgılama (sekresyon) tipi aşağıdakilerden hangisidir?","options":["Holokrin sekresyon","Apokrin sekresyon","Merokrin sekresyon","Parakrin sekresyon","Endokrin sekresyon"],"correct":0,"exp":"Glandüler (bez) epitelinin salgılama yöntemleri histolojide 3'e ayrılır: 1) Merokrin (Ekrin): Salgı sadece ekzositozla atılır, hücre hiç zarar görmez (Ter bezleri, pankreas, tükürük bezleri). 2) Apokrin: Hücrenin tepe (apikal) kısmı salgıyla birlikte kopar ve atılır (Koltuk altı koku bezleri, Meme bezi lipid salgısı). 3) Holokrin: Tüm hücre (holo=bütün) salgıyla dolar, çekirdeği parçalanır, hücre ölür ve tamamı salgının kendisi haline gelir. Sebase (yağ) bezlerinin salgılama şekli her zaman holokrin'dir."},{"id":575,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Ölümden birkaç saat sonra tüm iskelet kaslarının kaskatı kesilmesi durumuna 'Rigor Mortis (Ölüm Katılığı)' adı verilir. Çapraz köprü (cross-bridge) döngüsü göz önüne alındığında, kasların gevşeyemeyip sürekli kasılı kalmasına neden olan biyokimyasal eksiklik ve bu eksikliğin kasılma döngüsündeki karşılığı aşağıdakilerden hangisidir?","options":["ATP eksikliği / Miyozin başının aktin flamanından kopamaması (ayrılamaması)","Asetilkolin eksikliği / Motor uç plakta aksiyon potansiyelinin durması","Kalsiyum eksikliği / Tropomiyozinin aktin üzerinden çekilememesi","Kreatin fosfat eksikliği / Z çizgilerinin birbirinden uzaklaşamaması","Magnezyum eksikliği / Miyozin hafif zincir kinazın aktive olamaması"],"correct":0,"exp":"İskelet kası kasılmasında miyozin başı aktine bağlanarak (power stroke) kası büzer. Ancak bu kasılmanın bitmesi ve miyozin başının aktinden 'kurtulup/ayrılıp' kasın gevşemesi için ortama yeni bir ATP molekülünün gelip miyozin başına bağlanması şarttır. Kişi öldüğünde hücresel solunum durur ve ATP üretimi biter. Ortamda yeni ATP kalmadığı için, miyozin başları aktin flamanlarına sıkıca kenetli kalır ve asla ayrılamaz. Tüm kaslar kaskatı kesilir (Rigor Mortis)."},{"id":576,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Gastrointestinal kanal, kan damarları ve solunum yollarında bulunan Düz Kas hücrelerinin kasılma fizyolojisi iskelet kasından farklıdır. Düz kasta çizgilenme (sarkomer) yoktur ve troponin kompleksi bulunmaz. Düz kasta kalsiyumun (Ca+2) hücre içine girdikten sonra kasılmayı başlatmak için bağlandığı spesifik protein ve aktive ettiği yolak aşağıdakilerden hangisidir?","options":["Kalsiyumun kalmoduline bağlanıp miyozin hafif zincir kinazı aktive ederek miyozini fosforillemesi","Kalsiyumun tropomiyozine bağlanarak aktin üzerindeki bağlanma bölgelerini açması","Kalsiyumun miyozin fosfataz enzimini aktive ederek kasılmayı başlatması","Kalsiyumun troponin C'ye bağlanarak ince filamentte yapısal değişiklik yaratması","Kalsiyumun kaldesmona bağlanıp miyozin ATPaz etkinliğini durdurması"],"correct":0,"exp":"İskelet ve Kalp kasında kalsiyumun hedefi Troponin C'dir. Ancak Düz Kasta troponin yoktur. Düz kasta hücre içine giren kalsiyum, 'Kalmodulin' adı verilen özel bir proteine bağlanır (Ca-Kalmodulin kompleksi). Bu kompleks gider, hücredeki 'Miyozin Hafif Zincir Kinaz (MLCK)' enzimini uyarır. Adı üzerinde, bu kinaz enzimi miyozinin boynundaki hafif zincire bir fosfat (P) takar."},{"id":577,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Kardiyak ventrikül kas hücresinin (miyosit) aksiyon potansiyeli grafiği incelendiğinde, iskelet kasından farklı olarak çok uzun süren bir 'Plato Fazı (Faz 2)' olduğu görülür. Bu plato fazı, kalp kasının tetaniye (krampa) girmesini engelleyen uzun bir refrakter periyot sağlar. Plato fazının oluşmasını ve hücrenin o sürede pozitif kalmasını sağlayan, birbirini dengeleyen iki ana iyon akımı aşağıdakilerden hangisidir?","options":["Hücre içine Sodyum (Na+) girişi ve Hücre içine Kalsiyum (Ca+2) girişi","Hücre içine Kalsiyum (T-tipi Ca+2) girişi ile Hücre dışına Sodyum (Na+) çıkışı","Hücre dışına Sodyum (Na+) çıkışı ile Hücre içine Klor (Cl-) girişi","Hücre içine yavaş Kalsiyum (L-tipi Ca+2) girişi ile Hücre dışına Potasyum (K+) çıkışı","Hücre dışına Potasyum (K+) çıkışı ile Hücre dışına Kalsiyum (Ca+2) çıkışı"],"correct":3,"exp":"Kalp ventrikül kasının aksiyon potansiyeli 5 fazdır: Faz 0 (Hızlı depolarizasyon): Sodyum (Na) içeri girer. Faz 1 (Erken repolarizasyon): Sodyum kanalı kapanır, Potasyum (K) dışarı çıkmaya başlar. **Faz 2 (Plato): ** Repolarizasyon (voltajın düşmesi) aniden durur ve düz bir çizgi (plato) oluşur. Bunun nedeni, hücre zarındaki yavaş 'L-Tipi Kalsiyum kanalları'nın açılmasıdır. Pozitif Kalsiyum içeri girerken, pozitif Potasyum dışarı çıkmaktadır."},{"id":578,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":5,"q":"Ağır bir yük kaldırmaya çalışan haltercide, kas tendonu kopma sınırına geldiği anda refleks olarak tüm iskelet kasları aniden gevşer ve yük elinden düşer (Uzama / Gevşeme refleksi). Aşırı kasılma gücü (gerilim/tansiyon) durumunda kası korumak amacıyla alfa motor nöronları inhibe ederek bu refleks gevşemeyi başlatan duyusal reseptör ve bağlı olduğu sinir lifi tipi aşağıdakilerden hangisidir?","options":["Kas iğciği (Muscle spindle) / Ia afferent lifler","Pacini cisimciği / A-beta lifleri","Eklem kapsül reseptörleri / Grup III lifler","Ruffini sonlanmaları / C lifleri","Golgi Tendon Organı (gto) / Ib afferent lifler"],"correct":4,"exp":"İskelet kaslarında iki önemli propriyoseptör (koruyucu sensör) vardır: Kas İğciği ve Golgi Tendon Organı. 1) Kas İğciği (Kasın ortasındadır): Kasın uzunluğunu (boyunu) algılar. Kas aniden gerilirse/uzarsa, iğcik Ia lifleriyle uyarılır ve kasın kopmasını önlemek için kası kastırır (Patella germe refleksi budur). 2) Golgi Tendon Organı (gto - Kasın tendonundadır): Kasın uyguladığı gerilimi (Tansiyonu/Gücü) algılar. Eğer kas tendonu kopartacak kadar aşırı kasılırsa, gto Ib lifleriyle uyarılır, inhibitör ara nöronlar üzerinden kasın motor sinirini işlevini bozar ve kası aniden gevşetir (Ters miyotatik refleks)."},{"id":579,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Uluslararası bir maraton koşucusunun bacak kaslarından alınan biyopside, ağırlıklı olarak Tip 1 iskelet kası liflerinin hakim olduğu görülüyor. Yavaş kasılan ve yorulmaya karşı son derece dirençli olan Tip 1 kas liflerinin (kırmızı kas) bu dayanıklılığını sağlayan temel metabolik ve hücresel özellikler aşağıdakilerden hangisidir?","options":["Çok yüksek glikojen depoları, zengin glikolitik enzimler ve belirgin çap","Çok yüksek miyoglobin içeriği, bol kapiller ağ, zengin mitokondri ve yüksek oksidatif kapasite","Düşük miyoglobin, az mitokondri ve anaerobik glikoliz kapasitesi","Yüksek miyozin ATPaz aktivitesi ve hızlı kalsiyum pompalanması","Sadece yağ asitlerini değil, ağırlıklı olarak laktik asidi kullanabilme yeteneği"],"correct":1,"exp":"İskelet kası lifleri temel olarak Tip 1 ve Tip 2 olarak ayrılır. Tip 1 lifler (Yavaş Oksidatif / Kırmızı kas): Maraton koşucuları ve sırt/postür kaslarında hakimdir. Renkleri kırmızıdır çünkü oksijen taşıyan 'Miyoglobin'leri çok fazladır. Çapları küçüktür, etrafları çok zengin kılcal damarlarla çevrilidir. Bol mitokondrileri vardır ve enerjiyi Aerobik Oksidatif fosforilasyonla üretirler."},{"id":580,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"İnfertilite (kısırlık) şikayetiyle başvuran 28 yaşındaki erkek hastanın testis biyopsisinde, seminifer tübüllerde otoimmün bir inflamasyon saptanıyor ve hastanın kendi spermlerine karşı antikor ürettiği (Anti-sperm antikorları) tespit ediliyor. Normal fizyolojide bağışıklık sisteminin, genetik olarak farklılaşmış olan (haploid) sperm hücrelerini tanımasını ve onlara saldırmasını engelleyen 'Kan-Testis Bariyeri'ni oluşturan hücreler arası bağlantı kompleksi aşağıdakilerden hangisidir?","options":["Leydig hücreleri arasındaki neksuslar (Gap junctions)","Sertoli hücreleri arasındaki sıkı bağlantılar (Zonula occludens)","Miyoid hücreler ile bazal membran arasındaki hemidesmozomlar","Spermatogoniumlar arasındaki desmozomlar (Macula adherens)","Sertoli hücreleri ile spermatidler arasındaki adezyon plakları"],"correct":1,"exp":"Kan-Testis bariyeri, puberteden sonra mayoz bölünme geçirerek 'yabancı (haploid)' hale gelen spermleri, vücudun kendi bağışıklık sisteminden koruyan hayati bir duvardır. Bu bariyer, seminifer tübülün destek hücreleri olan 'Sertoli hücreleri'nin birbirlerine sıkıca bağlanmasıyla (Zonula occludens / Tight junctions) oluşur. Bariyer, tübülü bazal (immün sisteme açık) ve adluminal (immün sistemden izole) olarak iki kompartmana ayırır. Bariyer yıkılırsa vücut spermlere antikor üretir ve infertilite gelişir."},{"id":581,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Erkek üreme sisteminin hormonal kontrolü incelendiğinde, ön hipofizden salgılanan Luteinleştirici Hormonun (LH), testislerde spesifik bir hücre grubunu uyararak androjen sentezini (özellikle testosteron) başlattığı bilinmektedir. LH'nin bağlandığı bu hücrelerin histolojik incelemesinde, steroid hormon sentezinden sorumlu oldukları için sitoplazmalarında aşırı derecede gelişmiş (baskın) olarak bulunan organel aşağıdakilerden hangisidir?","options":["Granüllü Endoplazmik Retikulum (rer)","Golgi Aygıtı","Düz (Granülsüz) Endoplazmik Retikulum (ser)","Lizozomlar","Peroksizomlar"],"correct":2,"exp":"Erkeklerde LH'nin hedefi testis interstisyumunda bulunan 'Leydig hücreleri'dir (L-L kuralı). Leydig hücreleri testosteron (steroid) üretir. Protein ve peptit yapılı hormon (örn: insülin, büyüme hormonu) üreten hücrelerde Granüllü ER (rer) ve Golgi çok gelişmişken; kolesterolden 'Steroid' hormon (testosteron, östrojen, kortizol vb. ) üreten tüm hücrelerde (Leydig hücreleri, adrenal korteks hücreleri, korpus luteum) 'Düz Endoplazmik Retikulum (ser)' ve tübüler kristalı mitokondriler aşırı gelişmiştir. Çünkü steroid sentez enzimleri ser zarlarında yer alır."},{"id":582,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":5,"q":"Otuz yaşında sağlıklı bir kadının 28 günlük düzenli menstrüel döngüsünün 21. gününde (Luteal Faz) endometrium biyopsisi yapılıyor. Biyopside endometrial bezlerin kıvrımlı ve salgıyla dolu olduğu (sekretuvar faz) izleniyor. Endometriumu bu evrede tutarak embriyonun tutunması için hazırlayan ve esas olarak 'Progesteron' salgılayan overyan yapı (Korpus Luteum), ovülasyon (yumurtlama) öncesi folikülün hangi hücrelerinin hipertrofisi ve luteinizasyonu ile oluşur?","options":["Sadece Oosit ve korona radiata hücreleri","Granüloza ve Teka İnterna hücreleri","Sadece Granüloza hücreleri","Teka Eksterna hücreleri ve over stroma hücreleri","Primordiyal folikülün yassı epitel hücreleri"],"correct":1,"exp":"Ovülasyon (LH piki) gerçekleştikten sonra, çatlayan (yırtılan) folikülün geride kalan duvarları hızla değişime uğrar ve 'Korpus Luteum (Sarı cisim)' adını alır. Korpus luteumu oluşturan ana hücreler, ovülasyon öncesi folikülü döşeyen 'Granüloza hücreleri' (Granüloza lutein hücrelerine dönüşür) ve 'Teka İnterna hücreleri'dir (Teka lutein hücrelerine dönüşür). Bu iki hücre grubu da LH etkisiyle sitoplazmalarında lipid (kolesterol) biriktirerek (sarı renk) hızla hipertrofiye uğrar ve bol miktarda Progesteron (ve az miktarda östrojen) sentezleyerek rahmi gebeliğe hazırlar."},{"id":583,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Yirmi beş yaşındaki sağlıklı bir kadında gebelik gerçekleşmediği için korpus luteum gerilemiş (korpus albikansa dönüşmüş) ve kandaki progesteron ile östrojen seviyeleri aniden düşmüştür. Bu hormonal çekilme (withdrawal) sonucunda, endometriumda iskemi ve nekroz gelişerek menstrüel kanama (adet kanaması) başlamıştır. Menstrüasyon sırasında endometriumun fonksiyonel tabakasının (Stratum functionale) dökülmesini sağlayan şiddetli vazospazm (kasılma), spesifik olarak hangi damarlarda gerçekleşir?","options":["Arkuad arterler","Düz (Straight) arterler","Spiral (Helikozal) arterler","Radyal arterler","Uterin venöz pleksus"],"correct":2,"exp":"Endometrium histolojik olarak iki tabakadan oluşur: Altta kalıcı olan 'Stratum basale' (Düz arterler besler) ve her ay dökülüp yeniden yapılan 'Stratum functionale' (Spiral arterler besler). Gebelik olmazsa düşen progesteron seviyesi, prostaglandin (pgf2-alfa) salınımını tetikler. Prostaglandinler, fonksiyonel tabakayı besleyen kıvrımlı 'Spiral Arterler'de saatlerce süren çok şiddetli bir vazospazm (kasılma) yapar. Kan gitmeyen fonksiyonel tabaka iskemiden ölür (nekroz) ve damarlar tekrar gevşediğinde kan basıncıyla koparak adet kanaması şeklinde vajinadan atılır."},{"id":584,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Tubal ektopik gebelik (dış gebelik) geçiren bir hastanın Fallop tüpü (Tuba uterina) cerrahi olarak çıkarılıyor. Tüp mukozasının histolojik incelemesinde tek katlı prizmatik (silindirik) epitel izleniyor. Bu epitelde, döllenmiş ovumu uterusa doğru süpüren silyalı hücrelerin yanı sıra, embriyoyu beslemek ve spermi kapasitasyona uğratmak için gerekli besleyici sıvıyı salgılayan, apikal yüzeyleri silyasız ve kubbe şeklinde lümene taşan spesifik hücreler saptanıyor. Tuba uterinada bu salgı fonksiyonunu üstlenen hücre aşağıdakilerden hangisidir?","options":["Goblet hücreleri","Klara (Clara) hücreleri","Paneth hücreleri","Peg (Çivi) hücreleri","M hücreleri"],"correct":3,"exp":"Tuba uterina (Fallop tüpü) epiteli iki ana hücre tipinden oluşur: 1) Silyalı hücreler: Östrojen etkisiyle sayıları artar ve yumurtayı rahme doğru süpürürler. 2) Peg (Çivi/Sekretuvar) hücreleri: Progesteron etkisiyle sayıları/salgıları artar. Apikal kısımları silyasızdır, bir kubbe veya çivi gibi lümene taşarlar. Görevleri, yumurtanın, spermin ve döllenmiş embriyonun tüpteki yolculuğu (3-4 gün sürer) boyunca beslenmesini sağlayacak glikoprotein ve lipidden zengin besleyici sıvıyı salgılamaktır. (Not: Goblet bağırsağın, Clara solunum yolunun, Paneth ince bağırsağın dibindeki antimikrobiyal hücredir)."},{"id":585,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Fertilizasyon (döllenme) sırasında, kapasitasyona uğramış bir sperm hücresi oositin etrafındaki Zona Pellucida'yı (ZP3 reseptörleri aracılığıyla) delip oosit zarına ulaştığında ve kaynaştığında, oositin içinde ani bir hücre içi kalsiyum (Ca+2) dalgası oluşur. Bu kalsiyum dalgası, oosit zarının hemen altındaki kortikal granüllerin ekzositozla dışarı boşalmasına (Kortikal Reaksiyon) neden olur. Kortikal reaksiyonun embriyolojik açıdan en kritik fizyolojik işlevi aşağıdakilerden hangisidir?","options":["Oositin 2. mayoz bölünmesini tamamlamasını başlatmak","Embriyonun endometriyuma tutunabilmesi için gereken proteolitik enzimlerin kontrollü biçimde serbest bırakılması","Erkek ve dişi pronükleuslarının birleşmesini (singami) kolaylaştırmak","Zigotun mitoz bölünmelerini (klivaj) tetikleyecek ATP sentezini başlatmak","Zona Pellucida'nın yapısını (ZP3 reseptörlerini) değiştirerek ve sertleştirerek polispermiyi engellemek"],"correct":4,"exp":"Fertilizasyonda en büyük risk 'Polispermi'dir (bir yumurtaya iki sperm girerse 69 kromozomlu, yaşamaz bir triploidi oluşur). İlk sperm yumurta zarına dokunduğu anda, yumurta içindeki kalsiyum yükselir ve zardaki kortikal granüller dışarı kusulur (Kortikal reaksiyon). Bu granüllerin içindeki enzimler, yumurtayı saran jölemsi kılıf olan 'Zona Pellucida'yı anında sertleştirir ve üzerindeki sperm bağlayıcı ZP3 reseptörlerini yıkar. Buna 'Zona Reaksiyonu' denir. Böylece arkadan gelen diğer spermlerin yumurtaya girmesi mekanik olarak engellenir ve polispermi önlenir."},{"id":586,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Döllenmeden yaklaşık 6-7 gün sonra, blastosist aşamasındaki embriyo uterus (rahim) endometriumuna tutunmaya (implantasyon) başlar. Blastosistin dış tabakası olan trofoblastlar iki farklı hücre tabakasına farklılaşır. Bu tabakalardan biri hücre sınırlarını kaybederek anne dokusunun içine doğru agresif bir şekilde invaze olan ve aynı zamanda gebelik testi için kullanılan Human Koryonik Gonadotropin (hCG) hormonunu sentezleyen çok çekirdekli dev bir kitle oluşturur. Bu agresif ve hormon sentezleyen embriyolojik doku aşağıdakilerden hangisidir?","options":["Sitotrofoblast","Embriyoblast (İç hücre kitlesi)","Belirti vermeyentyotrofoblast","Ekstraembriyonik mezoderm","Hipoblast"],"correct":2,"exp":"İmplantasyon sırasında embriyonun dış zarı olan Trofoblastlar ikiye ayrılır: İçte tek çekirdekli, düzgün sınırlı 'Sitotrofoblastlar' (hücre fabrikasıdır, sürekli bölünürler) ve dışta bu hücrelerin birleşerek oluşturduğu, hücre zarlarının eridiği, çok çekirdekli dev bir süngerimsi doku olan 'belirti vermeyentyotrofoblastlar'. belirti vermeyentyotrofoblastlar, annenin kan damarlarını ve dokusunu eriterek embriyoyu rahme gömen agresif parmakçuklardır. Aynı zamanda kana 'hCG (Human Koryonik Gonadotropin)' salgılayarak annenin overindeki Korpus Luteum'a 'Ben geldim, progesteron üretmeye devam et, adet kanaması yapma' mesajını iletirler."},{"id":587,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":5,"q":"Gelişimin 3. haftasında (Gastrulasyon evresi), epiblast hücreleri primitif çizgi (primitive streak) boyunca göç ederek üç temel germ yaprağını (Ektoderm, Mezoderm ve Endoderm) oluştururlar. Aynı dönemde primitif düğümden başa doğru (kraniyal yönde) uzanan silindirik bir hücre kordonu olan 'Notokord' gelişir. Notokordun embriyolojik gelişimdeki (organogenez) en önemli birincil indükleyici (uyarıcı) görevi aşağıdakilerden hangisidir?","options":["Altındaki endodermi uyararak sindirim kanalını oluşturmak","İlkel kalp tüpünün birleşmesi için kılavuzluk etmek","Yanlarındaki paraksiyal mezodermi uyararak somitlerin parçalanmasını sağlamak","Üzerindeki ektodermi indükleyerek Nöral Plağın gelişmesini başlatmak","Gelecekteki göbek kordonunun kan damarlarını oluşturmak"],"correct":3,"exp":"Gastrulasyonun en kritik olayı Notokordun oluşumudur (Notokord mezoderm kökenlidir). Notokord, embriyonun ilkel omurgası gibidir. Organogenezde 'İndüksiyon (bir dokunun diğerine emir vermesi)' kavramının en meşhur örneği Notokord'dur. Notokord, hemen kendi üzerinde bulunan yüzey ektodermi hücrelerine moleküler sinyaller (Sonic Hedgehog / shh vb. ) göndererek onları kalınlaştırır ve 'Nöral Plak' olmasını sağlar (Nöroektoderm)."},{"id":588,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Gelişimin 3. ve 4. haftalarında notokordun her iki yanında yer alan 'Paraksiyal Mezoderm', baş-kuyruk ekseni boyunca parçalara ayrılarak 'Somit' adı verilen kübik blokları oluşturur. Somitler daha sonra üç farklı embriyolojik taslağa farklılaşır. Bu somitlerin medial ve ventral kısmında yer alan ve göç ederek notokord ile nöral tüpün etrafını sarıp gelecekteki 'Vertebraları (Omurları)' ve kaburgaları oluşturacak olan embriyolojik doku taslağı aşağıdakilerden hangisidir?","options":["Dermatom","Miyotom","Somatoplevrik mezoderm","Ara (İntermediate) mezoderm","Sklerotom"],"correct":4,"exp":"Somitler (Paraksiyal mezoderm kökenli), insan vücudunun segmental (bölmeli) yapısını oluşturur. Her bir somit 3 parçaya ayrılır: 1) Sklerotom: En içte ve alttadır (ventromedial). Göç ederek nöral tüpü sarar ve eksenel iskeleti (Vertebralar/Omurlar ve Kaburgalar) oluşturur (Sklero=Sert/Kemik). 2) Miyotom: Ortadadır, vücudun tüm iskelet kaslarını oluşturur. 3) Dermatom: En dıştadır, sırt bölgesindeki cildin dermis tabakasını oluşturur."},{"id":589,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Nöral tüpün kapanması sırasında, nöral katlantıların tepe kısmında yer alan özel bir hücre grubu, ektodermal bağlantılarını kopararak embriyonun dört bir yanına göç etmeye başlar. 'Dördüncü germ yaprağı' olarak da adlandırılan bu Nöral Krest (Neural Crest) hücreleri birçok farklı organın gelişimine katılır. Aşağıdaki doku veya hücre tiplerinden hangisi Nöral Krest hücrelerinden köken almaz?","options":["Ciltteki melanositler (pigment hücreleri)","Santral sinir sistemindeki mikroglialar","Periferik sinir sistemindeki Schwann hücreleri","Yüz ve kafatası kemiklerinin büyük bir kısmı (Fasiyal iskelet)","Adrenal (Böbrek üstü) bezin medullası"],"correct":1,"exp":"Nöral Krest (Krista) hücreleri ektoderm kökenli belirgin göçmen hücrelerdir. Gittikleri yerde şu yapıları oluştururlar: Adrenal medulla (katekolamin üreten kromaffin hücreler), Melanositler (cilde renk verenler), Schwann hücreleri (periferik miyelin), Pia ve Araknoid zarlar, Tiroidin C (kalsitonin) hücreleri, Yüz-çene (fasiyal) kemikleri ve kıkırdakları, Kalpteki aortikopulmoner septum, Otonom ve arka kök ganglionları. Ancak, santral sinir sisteminin çöpçüleri olan 'Mikroglialar' nöral krestten değil, kemik iliğindeki makrofajlar gibi 'Mezodermden (Mononükleer fagositik sistem)' köken alırlar."},{"id":590,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Akut kan kaybı sonrası kemik iliğinde eritropoez (kırmızı kan hücresi yapımı) hızlanan bir hastanın periferik kan yayması supravital boyalarla (örn: Yeni Metilen Mavisi) inceleniyor. Yaymada, olgun eritrositlerden biraz daha büyük olan ve sitoplazmalarında ağsı (retiküler) lacivert iplikçikler içeren hücrelerin sayısında artış saptanıyor. Eritrosit olgunlaşma serisinin kana çıkan en son öncül hücresi olan bu retikülositlerde boyanan ağsı (retiküler) materyalin hücresel kaynağı aşağıdakilerden hangisidir?","options":["Parçalanmış hücre çekirdeği (DNA) kalıntıları","Mitokondriyal krista döküntüleri","Ribozomal RNA (rRNA) ve poliribozom kalıntıları","Golgi aygıtı vezikülleri","Denatüre olmuş hemoglobin çökeltileri"],"correct":2,"exp":"Eritrositler kemik iliğinde olgunlaşırken önce çekirdeklerini atarlar. Çekirdeğini yeni atmış, henüz tam olgunlaşmamış genç alyuvarlara 'Retikülosit' denir. Retikülositler kemik iliğinden çıkıp kanda 1-2 gün dolaştıktan sonra içlerindeki son organelleri de atıp olgun eritrosite dönüşürler. Normal boyalarla polikromatofilik (morumsu) görünürler. Ancak supravital boyalarla (Yeni Metilen Mavisi, Parlak Krezil Mavisi) boyandıklarında sitoplazmalarında bir ağ (retikulum) belirir."},{"id":591,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Trombopoetin (tpo) hormonunun uyarısıyla kemik iliğinde trombosit üretimi gerçekleşmektedir. Trombositlerin köken aldığı Megakaryositler, vücudun en büyük hücrelerinden biridir ve belirgin (poliploid) bir çekirdeğe sahiptirler. Megakaryositlerin, hücre bölünmesi (sitokinez) olmaksızın sadece DNA'larını kopyalayarak belirgin çekirdeklere ulaşmasını sağlayan spesifik hücre döngüsü mekanizması (ve trombosit oluşturma yöntemi) aşağıdakilerden hangisinde doğru verilmiştir?","options":["Mayoz bölünmeyle çekirdek sayısının azalması / ekzositozla protein salgılanması","Amitoz bölünmeyle çoğalma / pinositoz keseciklerinin dışarı atılması","Endomitozla poliploidi gelişmesi / demarkasyon kanallarıyla sitoplazmanın parçalanması","Klivaj bölünmesiyle çoğalma / apoptotik cisimciklerin dolaşıma karışması","Şizogoniyle çoğalma / hücre zarının tomurcuklanarak ayrılması"],"correct":2,"exp":"Trombositler bir hücre değil, kemik iliğindeki belirgin bir hücrenin (Megakaryosit) kopan sitoplazma parçacıklarıdır. Megakaryositler büyürken çok ilginç bir yol izlerler: 'Endomitoz (Endoreduplikasyon)'. Yani hücre DNA'sını 2n, 4n, 8n, 16n, 32n, 64n şeklinde sürekli kopyalar ama hücre ve çekirdek asla bölünmez. Sonuçta belirgin loblu bir çekirdek ve dev bir sitoplazma oluşur. Yeterince büyüyen megakaryosit, sitoplazmasının içine 'Demarkasyon Kanalları' adı verilen zarlar çizer."},{"id":592,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"X'e bağlı Agammaglobulinemi (Bruton Hastalığı) tanısı alan ve vücudunda hiç B lenfositi (CD19+ hücre) bulunmayan bir erkek çocuğun lenf nodu biyopsisi histolojik olarak inceleniyor. Lenf nodunun yapısında T hücrelerine ait bölgelerin normal olduğu görülürken, spesifik olarak B hücrelerinin yerleştiği ve çoğaldığı bölgelerin tamamen boş (hipoplastik) olduğu gözleniyor. Bu hastanın lenf nodunda gelişmemiş ve boş görünen anatomik bölge aşağıdakilerden hangisidir?","options":["Yüzeyel (Dış) Korteks","Parakorteks","Medüller kordlar","Subkapsüler sinüs","Trabeküler sinüs"],"correct":0,"exp":"Lenf nodları histolojik olarak T ve B lenfositlerin ayrı ayrı yerleştiği mahallelere sahiptir. 1) Yüzeyel (Dış) Korteks: B lenfositlerin mahallesidir. Burada yuvarlak 'Foliküller' ve ortalarında B hücrelerinin antijenle karşılaşıp çoğaldığı 'Germinal Merkezler' bulunur. B hücre eksikliği olan Bruton hastalığında bu bölge tamamen bomboştur. 2) Parakorteks (İç korteks): T lenfositlerin mahallesidir (Timus bağımlı bölge)."},{"id":593,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":5,"q":"Timus bezi, immün sistemin eğitim merkezi olup T lenfositlerinin olgunlaştığı (T hücre toleransının geliştiği) organdır. Timus histolojisi incelendiğinde, medüllada (öz bölgesinde) sadece timusa özgü olan, Tip VI epitelyoretiküler hücrelerin soğan zarı gibi eşmerkezli (konsantrik) olarak dizilmesiyle oluşan ve merkezinde keratinleşme/nekroz görülebilen eozinofilik yapılar saptanır. İlerleyen yaşla birlikte sayısı ve boyutu artan bu spesifik histolojik yapı aşağıdakilerden hangisidir?","options":["Peyer plakları","Malpighi cisimcikleri","Billroth kordonları","Hassall cisimcikleri (Hassall korpüskülleri)","Herring cisimcikleri"],"correct":3,"exp":"Hematopoetik organların kendilerine has (kimlik kartı niteliğinde) histolojik yapıları vardır. Timusun kimlik kartı medüllasında bulunan 'Hassall Cisimcikleri'dir. Bunlar Tip VI (6) epitelyoretiküler hücrelerin kendi etraflarında soğan zarı gibi (konsantrik) sarılıp, merkezlerinde keratinleşmesi veya kireçlenmesiyle oluşur. Kesin görevleri tam bilinmemekle birlikte IL-T (Timik stromal lenfopoetin) salgılayarak T hücrelerinin eğitimine ve dendritik hücre aktivasyonuna katıldıkları düşünülmektedir. (Not: Peyer plakları ileumda, Billroth kordonları dalak kırmızı pulpasında, Malpighi cisimcikleri dalak beyaz pulpasında, Herring cisimcikleri ise nörohipofizde bulunur)."},{"id":594,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Herediter Sferositoz hastasında eritrositlerin esnekliği (deformabilitesi) kaybolmuş ve küre şeklini (sferosit) almışlardır. Bu anormal alyuvarlar dolaşırken dalağa geldiklerinde, dalağın 'Kırmızı Pulpa'sında bulunan spesifik bir anatomik bariyerden (dar yarıklar) esneyip geçemezler ve dalak kordonlarında hapsolarak makrofajlar tarafından parçalanırlar. Dalak sinüzoidlerinin duvarını döşeyen ve alyuvarların esnekliğini test eden bu uzun, çubuk şeklindeki endotel hücrelerine ne ad verilir?","options":["Karaciğer sinüzoidlerini döşeyen Kupffer hücreleri","Dalak sinüzoidlerinde bulunan littoral hücreler","Peyer plakları üzerindeki mikrofold (M) hücreleri","Germinal merkezlerdeki foliküler dendritik hücreler","Dalak sinüzoid duvarını oluşturan çıtak (fıçı) hücreleri"],"correct":4,"exp":"Dalak, kanın kalite kontrol merkezidir. Kan, dalaktaki Kırmızı Pulpaya (Billroth kordonlarına) dökülür. Buradan tekrar venöz dolaşıma dönebilmek için 'Dalak Sinüzoidleri'nin (venöz sinüslerin) içine girmek zorundadır. Ancak bu sinüzoidlerin duvarı sıva gibi düz değildir; fıçı (varil) tahtaları gibi yan yana dizilmiş uzun, ince endotel hücrelerinden (Fıçı hücreleri / Stave cells / Çıtak hücreler) oluşur. İki fıçı hücresi arasındaki boşluk (yarık) yaklaşık 2-3 mikrometre kadardır."},{"id":595,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Mide mukozasında asit salgılanmasından sorumlu olan paryetal (oksintik) hücrelerin histolojik incelemesinde, hücre istirahat halindeyken (asit salgılamıyorken) apikal sitoplazmada yoğun olarak bulunan ancak hücre aktifleştiğinde azalıp kaybolan spesifik membranöz yapı aşağıdakilerden hangisidir?","options":["Golgi sisternaları","Lizozomal granüller","Tübüloveziküler sistem (ağ)","Zymogen (zimojen) granülleri","Kaba Endoplazmik Retikulum (rer) kesecikleri"],"correct":2,"exp":"Paryetal hücreler, midede HCl (asit) ve İntrinsik Faktör salgılayan dev, eozinofilik hücrelerdir. Bu hücrelerin asit salgılayabilmesi için apikal yüzey alanlarının çok geniş olması gerekir. İstirahat halindeki bir paryetal hücrenin apikal sitoplazması, içinde H+/K+ ATPaz (Proton pompası) barındıran 'Tübüloveziküler Sistem' adı verilen sayısız kesecikle (vezikül) doludur. Hücre gastrin, histamin veya asetilkolin ile uyarıldığında, bu tübüloveziküller hızla apikal hücre zarına doğru göç eder ve zarla kaynaşarak derin 'İntraselüler Kanaliküller' oluştururlar. Bu sayede hücrenin yüzey alanı saniyeler içinde belirgin boyutlara ulaşır ve asit pompalanmaya başlar."},{"id":596,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"İnce bağırsak mukozasının histolojik kesitleri incelendiğinde, Lieberkühn kriptlerinin en taban (bazal) kısmında yerleşmiş, apikal sitoplazmalarında irili ufaklı, yoğun eozinofilik (pembe-kırmızı boyanan) sekretuvar granüller içeren spesifik hücreler saptanır. Bağırsak florasının düzenlenmesinde rol alan ve alfa-defensin (kriptidin) ile lizozim salgılayan bu hücre aşağıdakilerden hangisidir?","options":["Goblet hücreleri","Brunner bez hücreleri","Enteroendokrin hücreler","M (Mikrofold) hücreleri","Paneth hücreleri"],"correct":4,"exp":"GİS histolojisinin favori hücrelerinden biri Paneth hücreleridir. Sadece ince bağırsakta (özellikle ileumda) Lieberkühn kriptlerinin tam dibinde (bazalinde) bulunurlar. Çok belirgin apikal eozinofilik granülleri vardır (mikroskopta kolayca tanınırlar). Bu granüllerin içinde anti-mikrobiyal peptitler olan 'Lizozim, Alfa-defensin ve Fosfolipaz A2' bulunur. Temel görevleri bağırsağın doğal immünitesini sağlamak ve bağırsak florasını (kök hücreleri koruyarak) kontrol altında tutmaktır."},{"id":597,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Mide ve bağırsakların düz kas tabakalarında spontan olarak ortaya çıkan ve aksiyon potansiyellerine zemin hazırlayan elektriksel 'Yavaş Dalgalar (Slow Waves)' mevcuttur. Gastrointestinal sistemin temel ritmini belirleyen bu elektriksel yavaş dalgaları üreten ve GİS'in 'pacemaker (ritim oluşturucu)' hücreleri olarak bilinen yapı aşağıdakilerden hangisidir?","options":["Meissner pleksusu nöronları","Cajal'ın interstisyel hücreleri (ICC)","Auerbach pleksusu motor nöronları","Kupffer hücreleri","Enterokromafin benzeri (ECL) hücreler"],"correct":1,"exp":"Gastrointestinal sistemin kendi kendine kasılmasını (peristaltizm) sağlayan bir ritim üreteci vardır. İnce bağırsakta sirküler ve longitudinal düz kas tabakaları arasında (Auerbach pleksusuna komşu) yerleşmiş olan yıldızsı şekilli hücrelere 'Cajal'ın İnterstisyel Hücreleri (ICC)' denir. ICC'ler GİS'in pacemaker (kalp pili) hücreleridir. Kendi kendilerine 'Yavaş Dalgalar (Slow waves / Bazal elektriksel ritim)' üretirler ve bu elektriği gap junction'lar (neksus) aracılığıyla düz kaslara iletirler. Yavaş dalgalar tek başlarına kasılma yapmaz, ancak eşik değeri aşarlarsa (örneğin gerilme veya asetilkolin uyarısıyla) aksiyon potansiyeli (diken dalgası) doğurur ve kasılma gerçekleşir."},{"id":598,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Karaciğer histolojisi incelendiğinde, hepatositlerin bazolateral yüzü ile sinüzoid endoteli arasında kalan ve kan plazmasının serbestçe dolaştığı 'Disse mesafesi (Perisinüzoidal alan)' adı verilen bir boşluk bulunur. Normalde A vitamini (retinoid) depolamakla görevli olan, ancak kronik karaciğer hasarında (siroz) aktive olarak Tip I Kollajen sentezleyen miyofibroblastlara dönüşen hücre aşağıdakilerden hangisidir?","options":["Kupffer hücreleri","Pit hücreleri","Kolanjiyositler","Oval hücreler","Hepatik stellat hücreler (İto hücreleri)"],"correct":4,"exp":"Karaciğerin Disse mesafesinde yer alan Hepatik Stellat Hücreler (İto Hücreleri), histolojide ve patolojide çok kritiktir. Sağlıklı bir insanda bu hücreler lipidden çok zengindir ve vücudun 'A Vitamini' deposu olarak görev yaparlar. Ancak hepatit, alkol toksisitesi veya kronik hasar durumunda, Kupffer hücrelerinden salınan TGF-beta ve PDGF gibi sitokinlerin etkisiyle bu İto hücreleri uyanır. A vitamini depolarını kaybederler ve kasılabilen, bolca 'Tip I Kollajen' üreten 'Miyofibroblastlara' dönüşürler. Ürettikleri bu kollajen Disse mesafesini doldurarak kanın hepatositlere ulaşmasını engeller ve sirozun (fibrozis/portal hipertansiyon) temelini oluştururlar."},{"id":599,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":5,"q":"Tükürük bezlerinin asinuslarında üretilen primer tükürük sıvısı (primer sekresyon), kan plazmasına göre izotoniktir. Ancak bu sıvı, bezin kanallarından (özellikle Çizgili/Striated kanallar) geçerek ağız boşluğuna ulaştığında 'hipotonik' bir hal alır. Tükürüğün hipotonik hale gelmesini sağlayan kanallardaki iyon değişimi ve su geçirgenliği özellikleri aşağıdakilerden hangisinde doğru verilmiştir?","options":["Kanallar suya serbestçe geçirgendir; sodyum ve klor salgılanır, potasyum emilir","Kanallar suya serbestçe geçirgendir; kalsiyum emilir, fosfat salgılanır","Kanallar suya geçirgen değildir; sodyum ve klor emilir, potasyum ve bikarbonat salgılanır","Kanallar suya geçirgen değildir; potasyum emilir, sodyum lümene salgılanır","Kanallar suya serbestçe geçirgendir; tüm iyonlar aktif taşımayla emilir"],"correct":2,"exp":"Tükürük bezleri, salgılarını ağza iletirken modifiye ederler. Asinüslerde üretilen ilk tükürük kana eşdeğerdir (İzotonik). Bu sıvı 'Çizgili Kanallardan (Striated ducts)' geçerken çok önemli bir işlem olur: Kanal hücreleri aktif olarak 'Sodyum (Na) ve Kloru (Cl)' sıvıdan geri emerken, karşılığında sıvıya 'Potasyum (K) ve Bikarbonat (HCO3)' salgılarlar. Ancak en önemli kural şudur: Bu kanalların duvarı suya karşı geçirgen değildir (Su iyonların peşinden gidemez). Sıvının içinden tuzu (Na, Cl) çekip alırsanız ama suyu bırakırsanız, geriye kalan sıvı mecburen seyreltik, yani 'Hipotonik' bir sıvı olur."},{"id":600,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kalbin iletim sistemi histolojik olarak incelendiğinde, ventriküllerin subendokardiyal tabakasında yerleşmiş olan özel modifiye kalp kası hücreleri saptanır. Normal kardiyomiyositlere göre çok daha büyük çaplı olan, bol miktarda glikojen içerdikleri için mikroskopta daha soluk boyanan ve hücre çevresine itilmiş az sayıda miyofibril içeren bu hücreler, kalpteki en hızlı elektriksel iletimi sağlamakla görevlidir. Tanımlanan bu hücre grubu aşağıdakilerden hangisidir?","options":["Sinoatriyal (SA) düğüm P hücreleri","Atriyoventriküler (AV) düğüm geçiş hücreleri","Purkinje lifleri","Pektinat kas hücreleri","Korda tendinea fibroblastları"],"correct":2,"exp":"Kalbin histolojik kesitlerinde boyanma farklılıkları önemlidir. Purkinje lifleri, ventriküllerin subendokardiyal tabakasında bulunan modifiye (özelleşmiş) kalp kası hücreleridir. Enerjilerini güvenceye almak için sitoplazmalarında belirgin miktarda 'Glikojen' depolarlar. Glikojen boya almadığı için H&E boyamasında hücrenin ortası bomboş, soluk (halo) görünür; kasılma proteinleri (miyofibriller) ise hücrenin zarına doğru (perifere) itilmiştir. Hücre çapları normal miyositlerden çok daha büyüktür ve aralarında bolca 'Gap junction (Neksus)' bulunur."},{"id":601,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Büyük arterlerin (örneğin Aort) histolojik yapısı incelendiğinde, duvarlarının çok kalın olması nedeniyle lümenden geçen kanın en dış tabakaları (Tunica media'nın dışı ve Tunica adventitia) beslemede yetersiz kaldığı görülür. Bu nedenle büyük damarlar, kendi duvarlarını beslemek için spesifik küçük kan damarı ağlarına sahiptirler. 'Damarların damarı' olarak adlandırılan bu besleyici yapı aşağıdakilerden hangisidir?","options":["Sinüzoidal kapiller ağ","Nervi vascularis","Arteriyovenöz anastomoz","Glomus cisimciği","Vasa vasorum"],"correct":4,"exp":"Damar duvarları (intima, media, adventitia) oksijen ve besine ihtiyaç duyar. Küçük damarlarda bu ihtiyaç lümenden geçen kandan diffüzyonla karşılanır. Ancak Aort gibi kalın duvarlı 'Elastik Arterler'de veya kalın venlerde (Vena Kava), diffüzyon en dış tabakalara (Tunica media'nın dış 1/3'üne ve Tunica adventitia'ya) ulaşamaz. Bu bölgeler, adventitia tabakası içinde yer alan kendi özel küçük kapiller/arteriyol ağları ile beslenir. Bu yapıya 'Vasa vasorum (Damarların damarı)' denir."},{"id":602,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"İnsan vücudundaki kapiller (kılcal damar) ağları, geçirgenlik özelliklerine göre üç ana gruba ayrılır. Bunlardan bazılarının endotel hücreleri arasında çok geniş boşluklar bulunur, bazal membranları ya kesintilidir ya da hiç yoktur. Makromoleküllerin, hatta tam kan hücrelerinin (eritrosit/lökosit) damar dışına kolayca çıkmasına (veya girmesine) izin veren bu en geçirgen kapiller tipi (Sinüzoidal / Süreksiz kapiller) aşağıdaki organlardan hangisinde bulunur?","options":["Kan-Beyin Bariyeri (Serebral korteks)","İskelet kası ve Kalp kası","İnce bağırsak villusları ve Endokrin bezler","Böbrek glomerülleri","Kemik İliği, Karaciğer ve Dalak"],"correct":4,"exp":"Kapillerler 3 tiptir: 1) Sürekli (Somatic) Kapillerler: Endotel ve bazal membran kesintisizdir. Sıkı bağlantılar (tight junction) vardır. Kas, beyin, akciğer ve ekzokrin bezlerde bulunur. (Beyindeki en sıkı olanıdır). 2) Fenestralı (Pencereli) Kapillerler: Endotelde delikler (fenestra) vardır ama bazal membran süreklidir."},{"id":603,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kardiyak siklus (Kalp Döngüsü) sırasında, elektrokardiyogramda (EKG) qrs kompleksinin hemen ardından ventriküllerin kasılmaya başlamasıyla ilk kalp sesi (S1) duyulur. S1 sesinin duyulduğu bu an ile aort kapağının açıldığı an arasında geçen çok kısa süreye 'İzovolümetrik Kontraksiyon Fazı' denir. Bu faz sırasında kalpteki mekanik ve hemodinamik durum için aşağıdakilerden hangisi doğrudur?","options":["Ventrikül içindeki basınç hızla artar ancak ventrikülün içindeki kan hacmi (volümü) değişmez.","Atriyoventriküler (Mitral/Triküspit) kapaklar açıktır, aort/pulmoner kapaklar kapalıdır.","Ventrikül basıncı, aort basıncını aşmıştır ve kan hızla aortaya fırlatılmaktadır.","Tüm kalp kapakları (AV ve Semilunar) ardına kadar açıktır.","Ventrikül içindeki basınç hızla düşerken, atriyumlardan kan emilmektedir."],"correct":0,"exp":"Kalp siklusunun en kritik dönemeçleri basınç/hacim değişimleridir. Ventrikül kanla dolduktan sonra kasılmaya başlar (Sistol başlangıcı). Basınç yükselir yükselmez, kanın geri kaçmaması için Atriyoventriküler (Mitral/Triküspit) kapaklar şiddetle kapanır (Bu kapanma 'S1' sesidir). Ancak ventrikülün basıncı henüz aort basıncını yenip Aort kapağını açacak seviyeye (Örn: 80 mmHg) ulaşmamıştır. İşte bu saniyede (Mitral kapanmış, Aort henüz açılmamış) Kalpteki tüm kapaklar kapalıdır."},{"id":604,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Sinoatriyal (SA) düğüm hücreleri, kalbin birincil pacemaker'ı (ritim oluşturucusu) olup kendi kendilerine otomatik olarak depolarize olabilme (aksiyon potansiyeli üretme) yeteneğine sahiptirler. SA düğüm hücresinin aksiyon potansiyelinde, zar potansiyelinin en düşük eksi (-) değere inmesinin ardından, yavaş yavaş tekrar eşik değere doğru kendi kendine yükselmesini (Faz 4 Spontan Depolarizasyon) sağlayan asıl elektriksel akım aşağıdakilerden hangisidir?","options":["Hızlı voltaj kapılı sodyum kanallarının eşik altı potansiyelde açılması","Hücre dışına potasyum sızıntısının giderek artması ve zarın hiperpolarize olması","Hiperpolarizasyonla aktifleşen ve içeriye sodyum girişi sağlayan If (funny) akımı","L-tipi kalsiyum kanallarından hücre içine masif kalsiyum girişi olması","Na+/K+ ATPaz pompasının durarak hücre içi sodyumun birikmesi"],"correct":2,"exp":"Kalp kası hücreleri dışarıdan uyarı beklerken, Pacemaker (SA, AV) hücreleri hiç beklemez. Pacemaker aksiyon potansiyelinin en önemli sırrı 'Faz 4'tür (İstirahat fazı düz değildir, eğimlidir). Repolarizasyon sonrası hücre eksi (-60 mV) değerlere düştüğünde (Hiperpolarizasyon), bu hücrelerin zarında özel bir kanal açılır. Bu kanal eksi değerlerde çalışmayı sevdiği için fizyologlar ona şakacı/garip (Funny) adını vermiştir. 'İf (Funny) akımı', hücre içine sürekli Sodyum (ve biraz Potasyum) sızdırarak voltajı yavaş yavaş, kendi kendine eşik değere (-40 mV) doğru çeker."},{"id":605,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Otuz beş yaşında kadın hasta, görme alanında daralma (bitemporal hemianopsi) ve ellerinde/ayaklarında büyüme (Akromegali) şikayetiyle başvuruyor. Kranial MR'de hipofiz bezinde makroadenom saptanıyor. Tümör dokusunun histolojik boyanmasında, hücre sitoplazmalarının asidik boyaları (eozin) tutarak pembe-kırmızı renkte boyandığı görülüyor. Adenohipofizdeki (Ön Hipofiz) hücre boyanma paternleri dikkate alındığında, bu 'Asidofilik' boyanan tümör hücrelerinin salgılaması en muhtemel olan iki hormon aşağıdakilerden hangisinde doğru verilmiştir?","options":["ACTH ve TSH","Melanosit Uyarıcı Hormon (msh) ve ACTH","FSH ve LH","Büyüme Hormonu (GH) ve Prolaktin","Antidiüretik Hormon (ADH) ve Oksitosin"],"correct":3,"exp":"Ön Hipofiz (Adenohipofiz) hücreleri histolojik boyanmalarına göre 3'e ayrılır: Asidofiller (pembe/kırmızı), Bazofiller (mor/mavi) ve Kromofoblar (boyanmayanlar). Hatırlamak için 'B-flat' kuralı kullanılır. Bazofiller: FSH, LH, ACTH ve TSH üretirler. Geriye kalan iki majör hormon olan 'Büyüme Hormonu (Somatotrop)' ve 'Prolaktin (Laktotrop)', asidofilik hücreler tarafından üretilir. Akromegali hastasındaki büyüme hormonu salgılayan tümör bu nedenle histolojide asidofilik (eozinofilik) bir adenomdur."},{"id":606,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Tiroid bezinin histolojik kesitleri incelendiğinde, kanda kalsiyum seviyesini düşürmekle görevli 'Kalsitonin' hormonunu sentezleyen 'Parafoliküler (C) hücreleri' gözlenmektedir. Bu hücrelerin embriyolojik kökeni ve tiroid dokusu içindeki anatomik yerleşimi aşağıdakilerden hangisinde doğru ifade edilmiştir?","options":["Nöral Krest hücrelerinden köken alırlar / Folikül epiteli ile bazal lamina arasında yer alırlar, lümene (koloide) asla temas etmezler","Endoderm kökenlidirler / folikül lümenindeki kolloid ile doğrudan temas hâlinde bulunurlar ve tiroglobulin salgılarlar","Yüzey Ektodermi kökenlidirler / Folikül epitelinin tam ortasında silyalı hücre olarak bulunurlar","Mezoderm kökenlidirler / Tiroid kapsülünün dışında, paratiroid bezine yapışık bulunurlar","Nöral Tüp kökenlidirler / Doğrudan kan damarlarının lümenine bakarlar"],"correct":0,"exp":"Tiroid bezi iki farklı hormon üreten iki farklı hücre popülasyonuna sahiptir. 1) Foliküler hücreler: Endoderm kökenlidir (dil kökünden inerler), T3/T4 üretirler ve ortadaki göle (Kolloid) doğrudan temas ederler. 2) Parafoliküler C hücreleri: Embriyolojik olarak 4. yutak cebinden göç eden 'Nöral Krest (Krista)' hücrelerinden köken alırlar. Kalsitonin üretirler."},{"id":607,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Böbrek üstü bezinin (Adrenal Gland) korteks tabakası dıştan içe doğru üç ayrı zondur: Zona Glomeruloza, Zona Fasikülata ve Zona Retikülaris. Renin-Anjiyotensin sisteminin ürünü olan Anjiyotensin II ve kanda artan Potasyum (K+) iyonları, adrenal korteksin hangi tabakasını spesifik olarak uyararak ilgili steroid hormonun salınımını tetikler?","options":["Zona Fasikülata'yı uyararak Kortizol salınımı","Zona Retikülaris'i uyararak dhea (Androjen) salınımı","Zona Glomeruloza'yı uyararak Aldosteron salınımı","Adrenal Medulla'yı uyararak Adrenalin salınımı","Kromaffin hücreleri uyararak Noradrenalin salınımı"],"correct":2,"exp":"Adrenal korteksin 3 tabakası vardır ve her birinin uyarılma mekanizması (patronu) farklıdır. (Dıştan içe: G-F-R). 1) Zona Glomeruloza (En dış tabaka): Mineralokortikoid olan 'Aldosteron' (Tuz hormonu) üretir. Bu tabakanın patronu (uyarıcısı) Hipofizdeki ACTH değildir; patron 'Anjiyotensin II' ve 'Hiperkalemi (Artmış K+)'dir. 2) Zona Fasikülata (Orta/Kalın tabaka): Glukokortikoid olan 'Kortizol' (Şeker hormonu) üretir."},{"id":608,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Hipoglisemi atakları ile araştırılan bir hastada kanda yüksek İnsülin düzeyleri tespit ediliyor. Bu durumun hastanın dışarıdan gizlice insülin iğnesi yapmasından (yapay/faktisyoz hipoglisemi) mı, yoksa hastanın kendi pankreasında bir insülinoma (tümör) olmasından mı kaynaklandığını anlamak için 'C-peptid' seviyesi ölçülüyor. Sağlıklı bir endokrin pankreasta (Langerhans adacıklarındaki Beta hücrelerinde) İnsülin sentezi sırasında C-peptid'in oluşum aşaması aşağıdakilerden hangisidir?","options":["Ribozomda preproinsülinden sinyal peptidinin kesilmesiyle açığa çıkması","Alfa hücrelerinde glukagon yıkımı sırasında yan ürün olarak oluşması","Karaciğerde insüline eklenen ve dolaşımda taşınmasını sağlayan bir parça olması","Golgi veya salgı veziküllerinde proinsülinin proteazlarla kesilmesiyle ayrılması","İnsülin reseptörüne bağlandıktan sonra hücre içinde yıkılarak kana geçmesi"],"correct":3,"exp":"Endojen (vücudun kendi ürettiği) insülinin marker'ı C-peptid'dir. Pankreas beta hücresi insülini sıfırdan yaparken şu yolları izler: Ribozomda üretilen ilk koca molekül 'Preproinsülin'dir. ER lümeninde başındaki sinyal dizisi kesilip atılır ve 'Proinsülin' adını alır. Proinsülin, katlanmış ve A, B, C zincirlerinden oluşan tek parça bir iptir. Bu proinsülin, Golgi'ye gelip sekretuvar granüllere (veziküllere) hapsedildiğinde içindeki enzimler (proteazlar) makasla aradaki bağı keser."},{"id":609,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Karanlık ortamda Melatonin hormonu salgılayarak sirkadiyen ritmimizi (uyku-uyanıklık döngüsünü) düzenleyen Pineal Bez (Epifiz Bezi), histolojik olarak incelendiğinde yaşla birlikte artış gösteren çok spesifik radyolojik/histolojik yapılara sahiptir. Çoğunlukla kalsiyum fosfat ve kalsiyum karbonat birikimlerinden oluşan, beynin tam orta hattında yer aldığı için radyolojik görüntülerde (BT/Röntgen) 'orta hat kaymasını' değerlendirmekte işaretçi (marker) olarak kullanılan bu yapılar aşağıdakilerden hangisidir?","options":["Negri cisimcikleri","Corpora arenacea (Beyin kumu / Acervuli cerebri)","Corpora amylacea (Amiloid cisimcikler)","Lewy cisimcikleri","Psammoma cisimcikleri"],"correct":1,"exp":"Pineal bez (Epifiz), diensefalonda yer alan ve karanlıkta Melatonin üreten nöroendokrin bir organdır. Bu bezin histolojisinin en büyük özelliği, parankimi içinde yaş ilerledikçe artan kalsifiye (kireçlenmiş) kalsiyum fosfat çökeltileridir. Bu yapılara 'Corpora arenacea', 'Acervuli cerebri' veya Türkçe adıyla 'Beyin Kumu (Brain sand)' denir. Klinik/Radyolojik önemi çok büyüktür: Pineal bez beynin tam geometrik merkezindedir ve bu beyin kumları kireçli olduğu için tomografide (BT) veya röntgende bembeyaz parlar."},{"id":610,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Otuzuncu gebelik haftasında doğan prematüre bir bebek, doğumdan kısa süre sonra şiddetli solunum sıkıntısı (Respiratuar Distres Sendromu) geliştiriyor. Bebeğin akciğerlerinde Tip II pnömositlerden salgılanan 'Sürfaktan' maddesinin yetersiz olduğu saptanıyor. Fizyolojik olarak sürfaktanın temel görevi olan 'alveollerin sönmesini (kollabe olmasını) engelleme' mekanizmasını açıklayan fiziksel yasa (yüzey gerilimi ile basınç ve yarıçap ilişkisi) aşağıdakilerden hangisidir?","options":["Boyle-Mariotte Yasası","Poiseuille Yasası","Laplace Yasası","Henry Yasası","Fick Difüzyon Yasası"],"correct":2,"exp":"Sürfaktanın fizyolojisi 'Laplace Yasası' ile açıklanır (P = 2T / r). Bu yasaya göre; içi sıvı ile kaplı küresel bir yapının (alveol) büzülmesini (çökmesini) sağlayan basınç (P), yüzey gerilimi (T) ile doğru, alveolün yarıçapı (r) ile ters orantılıdır. Yani küçük alveollerin büzülme eğilimi, büyük olanlara göre çok daha fazladır ve hava küçükten büyüğe kaçmak ister. Sürfaktan (Dipalmitoilfosfatidilkolin), alveol küçüldükçe molekülleri birbirine yaklaşarak yüzey gerilimini (T) belirgin şekilde düşürür. Böylece küçük alveollerin içindeki çökme basıncı azalır ve nefes verirken sönmeleri (atelektazi) engellenir."},{"id":611,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Solunum yollarının histolojik incelenmesinde, kıkırdak ve bez içermeyen, çapı 1 mm'den küçük olan terminal bronşiyollerin epiteline gelindiğinde Goblet hücrelerinin kaybolduğu görülür. Goblet hücrelerinin yerini, apikal kısımları lümene kubbe şeklinde taşan, silyasız ve sekretuvar granüller içeren spesifik hücreler alır. Solunan havadaki toksinleri (Sitokrom P450 enzimleri aracılığıyla) detoksifiye eden ve CC16 (Clara Hücre Proteini) salgılayan bu hücre aşağıdakilerden hangisidir?","options":["Tip I Pnömosit","Kulchitsky (Nöroendokrin) hücreleri","Fırçamsı (Brush) hücreler","Klara (Club / Clara) hücreleri","Alveoler makrofajlar"],"correct":3,"exp":"Solunum ağacı aşağıya doğru indikçe (Terminal bronşiyollere gelindiğinde) yapı değişir. Kıkırdak, bez ve Goblet (mukus) hücreleri kaybolur. (Çünkü o derinlikte mukus olsaydı hava yollarını tıkar ve atılamazdı). Goblet hücrelerinin yerini 'Klara (yeni adıyla Club) Hücreleri' alır. Silyasız, kubbe şeklindeki bu hücrelerin 3 önemli görevi vardır: 1) Sürfaktan benzeri bir madde salgılayarak bronşiyollerin yapışmasını önlemek."},{"id":612,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Alveol lümenindeki oksijenin kana, kandaki karbondioksitin ise alveol lümenine geçişi 'Kan-Gaz Bariyeri (Solunum Membranı)' üzerinden basit difüzyonla gerçekleşir. Gaz alışverişinin en optimum seviyede yapıldığı, solunum membranının en ince (yaklaşık 0.2 mikrometre) bölgesini oluşturan histolojik katmanlar dıştan içe (alveolden kana doğru) hangi sırayla dizilmiştir?","options":["Tip II pnömosit sitoplazması, interstisyel bağ dokusu ve kapiller endotel sırasıyla","Sürfaktan tabakası, tip I pnömosit sitoplazması, kaynaşmış bazal lamina ve kapiller endotel sırasıyla","Alveoler makrofaj, tip I pnömosit ve fenestralı endotel sırasıyla","Sürfaktan tabakası, tip II pnömosit, iki ayrı bazal lamina ve sinüzoidal endotel sırasıyla","Tip I pnömosit, elastik lif ağı ve kapiller endotel sırasıyla"],"correct":1,"exp":"Kan-Gaz bariyeri akciğerin kalbidir ve Fick yasasına göre difüzyon hızını maksimize etmek için etkili incelikte tasarlanmıştır. En ince yerinde bağ dokusu yoktur. Sıralama alveol havasından kana doğru şöyledir: 1) Alveol yüzeyini döşeyen ince Sürfaktan sıvı tabakası. 2) Alveol duvarının %95'ini kaplayan yassı 'Tip I Pnömosit' hücresinin ince sitoplazması. 3) Hem epitelin hem de endotelin bazal laminalarının birbiriyle birleştiği 'Kaynaşmış (Fused) Bazal Lamina'."},{"id":613,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":5,"q":"Metabolizması yüksek olan periferik dokularda (örneğin egzersiz yapan kasta) üretilen bol miktardaki Karbondioksit (CO2), kapiller damarlara geçer ve eritrositlerin içine girer. Eritrosit içinde Karbonik Anhidraz enzimi CO2'yi suyla birleştirerek Bikarbonat (HCO3-) ve Hidrojen (H+) iyonlarına ayırır. Bikarbonatın eritrositten kan plazmasına çıkabilmesi için hücre zarı potansiyelini korumak amacıyla gerçekleşen ve 'Klor Şifti (Hamburger Fenomeni)' olarak bilinen olayda, eritrosit zarındaki 'Band 3' proteini (Anyon Değiştirici 1) hangi değişimi yapar?","options":["Hidrojen (H+) iyonunu dışarı atarken, Potasyum (K+) iyonunu içeri alır.","Karbondioksiti (CO2) içeri alırken, Sodyum (Na+) iyonunu dışarı atar.","Bikarbonatı (HCO3-) içeri alırken, Klor (Cl-) iyonunu dışarı atar.","Bikarbonatı (HCO3-) dışarı atarken, karşılığında Klor (Cl-) iyonunu eritrosit içine alır.","Klor (Cl-) iyonunu ve Suyu (H2O) eş zamanlı olarak dışarı atar."],"correct":3,"exp":"Karbondioksitin kanda taşınmasının en büyük (%70) yolu plazmada 'Bikarbonat (HCO3-)' formudur. Ancak bikarbonat eritrositin içinde üretilir. Üretilen eksi (-) yüklü bikarbonatın plazmaya çıkabilmesi için (hücre zarının elektriksel dengesinin bozulmaması adına) karşılığında dışarıdan içeriye bir başka eksi (-) yüklü iyon alınması gerekir. Bu görevi eritrosit zarındaki 'Band 3 (Anyon Değiştirici 1 - AE1)' proteini üstlenir. Bikarbonatı dışarı (plazmaya) atarken, plazmadaki Kloru (Cl-) eritrosit içine çeker."},{"id":614,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Ağır KOAH hastasında arteriyel kanda oksijen parsiyel basıncının (PaO2) 50 mmHg'ye (Hipoksemi) düşmesi, solunum merkezini uyararak hiperventilasyon başlatır. Oksijen düşüklüğünü (hipoksiyi) algılayan ve beyin sapına vagus/glossofaringeal sinirler aracılığıyla sinyal gönderen Periferik Kemoreseptörlerin (Örn: Glomus Caroticum / Karotis Cisimciği) içindeki Tip I Glomus hücrelerinin hipoksiye yanıt olarak verdikleri ilk hücresel/elektriksel tepki aşağıdakilerden hangisidir?","options":["Voltaj kapılı sodyum kanallarının açılarak hücre içine sodyum girmesi","Hücre içi kalsiyum depolarının doğrudan boşalarak tükenmesi","Oksijene duyarlı potasyum kanallarının kapanmasıyla hücrenin depolarize olması","Adenilat siklaz aktivasyonuyla hücre içi cAMP düzeyinin düşmesi","Asetilkolin reseptörlerinin yüzeyden çekilerek sayıca azalması"],"correct":2,"exp":"Kan oksijeninin (PaO2) düşüklüğünü beyindeki santral kemoreseptörler algılayamaz. Oksijen düşüklüğünü (<60 mmHg) algılayan tek yer 'Periferik Kemoreseptörler'dir (Karotis cisimciği ve Aort cisimciği). Bu organların içindeki sensör hücrelere 'Tip I Glomus Hücreleri' denir. Oksijen basıncı 60 mmHg'nin altına düştüğünde, glomus hücresi zarında bulunan oksijene duyarlı özel 'Potasyum (K+) kanalları kapanır'. Potasyum dışarı çıkamayınca hücrenin içi pozitifleşir (Depolarizasyon)."},{"id":615,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Optik nörit ve internükleer oftalmopleji atakları olan hastanın beyin MR'ında periventriküler demiyelinizan plaklar görülüyor. Bu hastalıkta hedeflenen ve tek hücresi birden fazla aksonun farklı internodlarını miyelinleyebilen glia hücresi aşağıdakilerden hangisidir?","options":["Oligodendrosit","Astrosit","Mikroglia","Ependim hücresi","Schwann hücresi"],"correct":0,"exp":"Merkezi sinir sisteminde miyelini oligodendrositler oluşturur; bir oligodendrosit birden fazla akson segmentini miyelinleyebilir. Periferik sinir sisteminde ise her Schwann hücresi tek bir aksonun tek internodunu miyelinler."},{"id":616,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Sinir sisteminde aksiyon potansiyelinin sıçrayıcı (saltatorik) ve çok hızlı bir şekilde iletilmesini sağlayan yapı, aksonların etrafını saran lipidden zengin Miyelin Kılıftır. Santral Sinir Sisteminde (MSS) miyelin kılıfı üreten glia hücresi ile Periferik Sinir Sisteminde (pss) miyelin kılıfı üreten glia hücresi arasındaki temel morfolojik / fonksiyonel fark aşağıdakilerden hangisinde doğru ifade edilmiştir?","options":["Merkezi sinir sisteminde mikroglia, periferde satellit hücrelerin miyelin üretmesi","Merkezi sinir sisteminde bir astrositin tek aksonu, periferde bir Schwann hücresinin birden çok aksonu sarması","Merkezi sinir sistemi miyelininde Ranvier boğumu bulunmaması, periferde bulunması","Bir oligodendrositin birden çok aksonu sarabilmesi, bir Schwann hücresinin ise tek aksonun tek internodunu sarması","Merkezi sinir sistemi miyelininin nöral krestten, periferik miyelinin mezodermden köken alması"],"correct":3,"exp":"Miyelinizasyon MSS ve pss'de farklı hücreler tarafından yapılır. Santral Sinir Sisteminde (Beyin, Omurilik) miyelini 'Oligodendrositler' yapar. Bir Oligodendrosit ahtapot gibidir; kolları (uzantıları) ile çevresinden geçen 30-50 farklı aksonu aynı anda sarabilir (Bu nedenle Multipl Skleroz gibi otoimmün bir hastalıkta bir oligodendrosit ölünce onlarca akson çıplak kalır). Periferik Sinir Sisteminde (Kraniyal/Spinal sinirler) ise miyelini 'Schwann Hücreleri' yapar. Schwann hücresi tembeldir; gövdesiyle birlikte sadece tek bir aksonun, küçücük bir parçasına (tek bir internoda) sarılır (Bir aksonu miyelinlemek için binlerce Schwann hücresi yan yana dizilmelidir)."},{"id":617,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Presinaptik nöronun uç kısmına (terminal buton) bir aksiyon potansiyeli ulaştığında, hücre zarı depolarize olur. Bu depolarizasyon, nörotransmitter dolu veziküllerin sinaptik boşluğa ekzositozla dökülmesini tetikler. Ekzositoz olayının (vezikül füzyonunun) gerçekleşebilmesi için presinaptik terminale girmesi zorunlu olan iyon ve vezikül zarında bu iyonu algılayıp SNARE proteinlerini tetikleyen 'kalsiyum sensörü' protein aşağıdakilerden hangisidir?","options":["Sodyum (Na+) / Sinapsin","Klor (Cl-) / Sinaptobrevin","Potasyum (K+) / Sintaksin","Kalsiyum (Ca+2) / Sinaptotagmin","Magnezyum (Mg+2) / snap-25"],"correct":3,"exp":"Sinapslarda kimyasal iletim (nörotransmitter salınımı) Kalsiyum (Ca+2) bağımlıdır. Aksiyon potansiyeli (elektrik) akson ucuna gelince, uçtaki 'Voltaj Kapılı Kalsiyum (N veya P/Q tipi) kanalları' açılır. Hücre içine giren Kalsiyum, nörotransmitter vezikülünün zarında bulunan 'Sinaptotagmin' adlı proteine bağlanır. Sinaptotagmin bir kalsiyum sensörüdür; kalsiyumu bağlayınca şekil değiştirir ve vezikülü hücre zarına zımbalayan 'SNARE kompleksi' proteinlerini (Sinaptobrevin, Sintaksin, snap-25) kopararak vezikülün zardan dışarı fışkırmasını (ekzositoz) sağlar. (Not: Botulinum ve Tetanus toksinleri işte bu SNARE proteinlerini parçalayarak felç yaparlar)."},{"id":618,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Santral sinir sisteminin ana inhibitör nörotransmitteri olan GABA (Gama-Aminobütirik Asit), postsinaptik nöronun zarında bulunan gabaa reseptörlerine bağlandığında İnhibitör postsinaptik Potansiyel (ıpsp) oluşturur. gabaa reseptörünün uyarılmasıyla postsinaptik nöronda inhibisyonu (hiperpolarizasyonu) sağlayan elektriksel/iyonsal değişim aşağıdakilerden hangisidir?","options":["Sodyum kanallarının açılarak hücre içine pozitif iyon girmesi","Kalsiyumun aktif taşımayla hücre dışına pompalanması","Klor kanallarının açılarak hücre içine negatif iyon girmesi","Kalsiyum kanallarının açılarak hücre içine kalsiyum girmesi","Sodyum-potasyum pompasının durarak gradiyentin bozulması"],"correct":2,"exp":"Sinapslarda iki tür yanıt oluşur: Eksitatör (epsp - uyarıcı) ve İnhibitör (ıpsp - baskılayıcı). Glutamat gibi uyarıcılar Sodyum (Na) kanallarını açarak hücreyi pozitifleştirir (depolarizasyon). Beynin en büyük freni olan GABA ise 'İnhibitör'dür. GABA, ligand kapılı bir iyon kanalı olan gabaa reseptörüne bağlandığında ortasındaki kapı açılır ve dışarıdaki eksi (-) yüklü 'Klor (Cl-)' iyonları hücre içine hücum eder. Hücre içi normalden daha da eksi/negatif (örneğin -70'den -80 mV'ye) hale gelir."},{"id":619,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Kan-Beyin Bariyeri (bbb), beyin dokusunu kandaki toksinlerden koruyan, endoteller arası 'Sıkı Bağlantılar (Tight junctions)' ve astrosit ayaklarından oluşan sıkı bir duvardır. Ancak beynin bazı özel bölgelerinde (Sirkümventriküler organlar) bu bariyer kasten yer almaz. Kandaki hormonları, toksinleri ve osmolariteyi anında algılayabilmek için pencereli (fenestralı) kapillerlere sahip olan ve kandaki toksik maddeleri algılayarak kusma refleksini (Kemoreseptör Tetikleyici Zon - ctz) başlatan sirkümventriküler organ aşağıdakilerden hangisidir?","options":["Pineal bez (Epifiz)","Area postrema","Subfornikal organ","Nörohipofiz (Arka hipofiz)","Organum vasculosum of lamina terminalis (ovlt)"],"correct":1,"exp":"Beyinde Kan-Beyin Bariyerinin olmadığı 7 bölge (Sirkümventriküler organlar) vardır. Bu organlar kanın tadına bakmak veya kana hormon salgılamak için bilerek bariyere dahil edilmemişlerdir (Kapillerleri deliklidir). Dördüncü ventrikülün tabanında yer alan 'Area Postrema', beynin toksin dedektörüdür. Kan-beyin bariyeri olmadığı için kana karışan herhangi bir zehri, ilacı (örn: kemoterapi, apomorfin, digoksin zehirlenmesi) veya üremiyi anında algılar. Burası Kemoreseptör Tetikleyici Zon (ctz) olarak bilinir."},{"id":620,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Çocukluk çağında başlayan, steroid tedavisine dirençli nefrotik sendromlu hastada NPHS2 mutasyonu saptanıyor. Slit diyafram kompleksinde nefrini lipid raftlara bağlayarak sinyal ve iskelet organizasyonuna katılan protein aşağıdakilerden hangisidir?","options":["Nefrin","Megalin","Alportin","Üromodulin","Podosin"],"correct":4,"exp":"NPHS2 geni podosini kodlar. Podosin, slit diyaframda nefrin kompleksinin membran ve hücre iskeletiyle işlevsel bağlantısını destekler. NPHS2 değişiklikleri kalıtsal steroid dirençli nefrotik sendromun önemli nedenlerindendir."},{"id":621,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kan basıncı aniden yükseldiğinde böbreğe (glomerüle) gelen kan akımı (rbf) ve süzme hızı (gfr) artar. gfr arttığı için Henle kulbuna daha fazla sıvı ve sodyum-klorür (NaCl) yükü gelir. Distal tübülün başlangıcında yer alan özelleşmiş hücre grubu, lümenden geçen bu artmış NaCl yükünü algılar ve glomerüle 'Çok sıvı geliyor, akımı kıs' sinyali (Adenozin) göndererek afferent arteriyolü daraltır. 'Tübüloglomerüler Geribildirim (geri bildirim)' adı verilen bu oto-regülasyon mekanizmasının sensörü (algılayıcısı) olan Jukstaglomerüler Aparat hücresi aşağıdakilerden hangisidir?","options":["Ekstraglomerüler mezangial hücreler (Lacis hücreleri)","Jukstaglomerüler (Granüler) hücreler","Makula Densa hücreleri","Podositler","İnterkale hücreler"],"correct":2,"exp":"Böbreğin kendini koruma sistemi (Oto-regülasyon) Jukstaglomerüler Aparat (JGA) üzerinden yürür. JGA 3 hücreden oluşur: 1) Makula Densa: Distal tübül duvarındaki dar/uzun epitel hücreleridir. Görevi lümenden geçen idrarın 'NaCl (Tuz)' tadına bakmaktır (Sensör/Dedektör). 2) Jukstaglomerüler (JG) Granüler Hücreler: Afferent arteriyol duvarındaki düz kaslardır, 'Renin' salgılarlar. Eğer tansiyon artar, gfr yükselir ve tübüle çok tuzlu (NaCl) su gelirse; 'Makula Densa' bunu (nkcc2 pompasıyla içine alarak) algılar."},{"id":622,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Glomerülden süzülen ultrafiltratın içindeki organik besinlerin tamamına yakını (özellikle glukoz ve amino asitler) Proksimal Tübül'de geri emilir. Proksimal tübül hücrelerinin lümene bakan apikal zarında glukozun hücre içine alınmasını sağlayan spesifik taşıyıcı protein ve bu işlemin enerji/termodinamik mekanizması aşağıdakilerden hangisinde doğru verilmiştir?","options":["Glut-1 taşıyıcısı ile kolaylaştırılmış difüzyon (Enerji harcamadan)","H+/Glukoz antiportu ile zıt yönlü transport","Na+/K+ ATPaz pompası ile Primer Aktif Taşıma","Glut-4 taşıyıcısı ile İnsülin bağımlı endositoz","SGLT-2 (Sodyum-Glukoz Ko-transporter 2) taşıyıcısı ile Sekonder Aktif Taşıma"],"correct":4,"exp":"Proksimal tübül histolojik olarak belirgin fırçamsı kenarlara (mikrovilluslara) sahiptir. Sağlıklı bir insanda idrarda şeker (glukoz) sıfırdır, çünkü %100'ü proksimal tübülde geri emilir. Bu emilim hücrenin apikal zarında (lümene bakan yüzünde) bulunan SGLT-2 (Sodium-Glucose Linked Transporter 2) pompasıyla olur. Bu pompa 'Sekonder Aktif Taşıma' yapar: Kendi ATP'sini harcamaz; hücrenin arka kanalındaki (bazolateral zardaki) Na/K ATPaz'ın yarattığı 'Sodyum (Na) eksikliği/gradyentini' enerji olarak kullanır. Na idrardan hücreye girmek isterken, SGLT-2 'Eğer yanına bir glukoz alırsan geçmene izin veririm' der."},{"id":623,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Böbrek medullasında (öz bölgesinde) hiperozmolar (çok tuzlu) bir interstisyel alan yaratmak, idrarın konsantre edilebilmesi (suyun tutulabilmesi) için şarttır. Bu hiperozmolariteyi yaratan ve 'Zıt Akımlar Çoğaltıcı (Countercurrent Multiplier)' sisteminin ana motoru olan, suya tamamen geçirgensiz olup lümendeki tuzu (Na-K-2Cl) aktif olarak dokuya pompalayan Henle kulbu segmenti aşağıdakilerden hangisidir?","options":["Proksimal kıvrımlı tübül","Henle kulbunun çıkan kalın kolu (tal)","Henle kulbunun inen ince kolu","Kortikal toplayıcı kanallar","Distal kıvrımlı tübül"],"correct":1,"exp":"Henle kulbunun iki kolu birbirinden tamamen zıt çalışır (Asimetri). 1) İnen İnce Kol: Sadece 'Suya' geçirgendir, tuza geçirgen değildir. Su medullaya kaçar, içindeki idrar yoğunlaşır/tuzlanır. 2) Çıkan Kalın Kol (Thick Ascending Limb - tal): Burası idrar yoğunlaştırma mekanizmasının motorudur. En önemli özelliği suya geçirgensiz olmasıdır."},{"id":624,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"İdrar yollarının (renal pelvis, üreter, mesane ve üretra başlangıcı) iç yüzeyini döşeyen Çok Katlı Değişici (Transizyonel) Epitelin (Üroepitel) en üst tabakasında bulunan belirgin hücreler vardır. Bu hücrelerin apikal membranlarında 'Uroplakin' adı verilen özel protein plakları bulunur. İdrarın dokulara sızmasını (toksisitesini) %100 engelleyen sızdırmaz bir bariyer oluşturan ve mesane dolduğunda esneyerek yassılaşan (çift çekirdekli olabilen) bu yüzeyel hücre grubuna ne ad verilir?","options":["Kadeh hücreleri","Bazal (Kök) hücreler","Şemsiye (Umbrella) hücreleri","Klara (Club) hücreleri","Glogi hücreleri"],"correct":2,"exp":"Üroepitel (Transizyonel epitel), idrar yollarına özgü eşsiz bir epiteldir. Mesane boşken 5-6 katlı görünür, dolduğunda esneyerek 2-3 katlı ince bir zar haline gelir. Bu esnemeyi ve korumayı sağlayan, epitelin en üstündeki belirgin 'Şemsiye (Umbrella / Dome)' hücreleridir. Şemsiye hücreleri altlarındaki hücreleri bir şemsiye gibi örterler (sıklıkla iki çekirdeklidirler). Asidik ve zehirli olan idrarın kana sızmasını önleyen etkili bir sızdırmazlıkları vardır."},{"id":625,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Yenidoğan muayenesinde belirgin mikrognati (küçük çene), dilin geriye kaçması (glossopitozis) ve U şeklinde yarık damak saptanıyor. Çekilen radyolojik görüntülemede orta kulak kemikçiklerinden malleus (çekiç) ve inkus (örs) kemiklerinin gelişmediği görülüyor. Pierre Robin sekansı/sendromu ile uyumlu bu konjenital anomalide, gelişim kusuru olan embriyolojik yapı ve bu yapıdan köken alan kasları inerve eden kranial sinir aşağıdakilerden hangisinde doğru verilmiştir?","options":["1. Faringeal Arkus / Nervus Trigeminus (CN V)","2. Faringeal Arkus / Nervus Facialis (CN VII)","3. Faringeal Arkus / Nervus Glossopharyngeus (CN IX)","1. Faringeal Cep (Pouch) / Nervus Vagus (CN X)","4. Faringeal Arkus / Nervus Vagus (CN X)"],"correct":0,"exp":"Baş ve boyun gelişiminin temel taşları Faringeal (Brankial) Arkuslardır. 1. Faringeal Arkus (Mandibular Arkus); kıkırdak yapısı olarak Meckel kıkırdağını içerir. Mandibula (alt çene), maksilla (üst çene), malleus ve inkus kemikleri bu arkustan gelişir. Çiğneme kaslarını (M."},{"id":626,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Beş yaşında erkek çocuk, boynunun tam orta hattında, tiroid kıkırdağının hemen üzerinde yer alan ve yutkunmakla (veya dilini dışarı çıkarmakla) yukarı doğru hareket eden ağrısız, kistik bir kitle nedeniyle getiriliyor. Tiroglossal kanal kisti (Duktus tiroglossus kisti) tanısı alan bu lezyonun embriyolojik olarak oluşumuna neden olan ve tiroid bezinin göç etmeye başladığı ilk anatomik başlangıç noktası (orijini) neresidir?","options":["Dil kökündeki Foramen Çekum (Foramen caecum)","Rathke kesesi","3. faringeal cep (pouch)","2. faringeal yarık (cleft)","Ultimobrankial cisim"],"correct":0,"exp":"Tiroid bezi, embriyolojik hayatta boynun altında (trakea önünde) oluşmaz. Tiroid, gelişimin 24. gününde ilkel yutağın tabanında, dil kökünde yer alan 'Foramen Çekum (Foramen caecum)' adı verilen bir noktadan epitelin kalınlaşmasıyla başlar. Buradan aşağıya, boyna doğru bir tüp aracılığıyla göç eder. Normalde bu kanal tiroid yerine ulaştığında kaybolur."},{"id":627,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Doğumda boynunun yan tarafında, sternokleidomastoid (skm) kasının ön kenarında akıntılı bir delik saptanan yenidoğana 'Brankial Fistül (Servikal Fistül)' tanısı konuyor. Normal embriyolojik gelişim sırasında, 2., 3. ve 4. faringeal yarıkların (cleft) üzerini bir örtü gibi kapatarak bu boşlukları yok etmesi gereken, ancak bu hastada kapanmayıp kist/fistül oluşumuna neden olan embriyolojik doku hareketi aşağıdakilerden hangisidir?","options":["1. Faringeal Arkus mezenşiminin arkaya doğru büyümesi","Nöral tüp ektoderminin boyun bölgesinde invajinasyonu","3. Faringeal Cepin (Pouch) dışarıya doğru fıtıklaşması","Maksiller çıkıntının orta hatta frontonazal çıkıntı ile birleşmesi","2. Faringeal Arkusun mezenşiminin aşağıya doğru aşırı büyüyerek diğer yarıkları örtmesi"],"correct":4,"exp":"Boynun dış yüzeyini faringeal yarıklar (cleftler - ektoderm kökenli) oluşturur. 1. Yarık açık kalarak 'Dış Kulak Yolunu' oluşturur. Diğer yarıklar (2, 3 ve 4) ise boyunda açık kalmamalıdır. Gelişim sırasında '2."},{"id":628,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Tiroidektomi ameliyatı sonrası ses kısıklığı ve yutma güçlüğü gelişen hastada sol rekürren laringeal sinir felci saptanıyor. Larinks (gırtlak) kaslarını inerve eden bu sinirin embriyolojik kökeni incelendiğinde, bu sinirin ve uyardığı intrinsik larinks kaslarının (krikotiroid kas hariç) hangi faringeal arkustan (yutak kavsinden) köken aldığı bilinmektedir?","options":["1. Arkus","2. Arkus","4. ve 6. Arkuslar","3. Arkus","Sadece 3. Arkus"],"correct":2,"exp":"Faringeal arkusların kranial sinir eşleşmeleri çok klasiktir. 1. Arkus = CN V (Trigeminal, çiğneme). 2. Arkus = CN VII (Fasiyal, mimik kasları)."},{"id":629,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Yarık dudak ve yarık damak (Cleft lip and palate) anomalisi ile doğan bir bebeğin embriyolojik öyküsü inceleniyor. Yüz gelişiminin 5. ve 6. haftalarında gerçekleşen birleşme (füzyon) kusurları bu anomalilere yol açar. İzole 'Yarık Dudak' (Tavşan dudak) anomalisinin temelinde, üst dudağın bütünlüğünü sağlamak için hangi iki yüz çıkıntısının orta hatta birleşememesi yatmaktadır?","options":["Medial nazal çıkıntılar ile Maksiller çıkıntılar","Lateral nazal çıkıntılar ile Maksiller çıkıntılar","Her iki Mandibular çıkıntının tam ortada birleşememesi","Maksiller çıkıntılar ile Palatin (damak) raflarının birleşememesi","Frontonazal çıkıntı ile Lateral nazal çıkıntılar"],"correct":0,"exp":"Yüz embriyolojisinde üst dudağın oluşumu spesifik çıkıntıların birleşmesine bağlıdır. Üst dudağın orta kısmını (filtrum) 'Medial Nazal Çıkıntılar' oluştururken, üst dudağın sağ ve sol yan kısımlarını 'Maksiller Çıkıntılar' oluşturur. Normal gelişimde bu iki yapı (Medial Nazal + Maksiller) karşılıklı gelerek sıkıca kaynaşır. Eğer mezenşim hücreleri bu bölgeye göç edemez ve bu yapılar birleşemezse, üst dudakta bir yarık kalır (Yarık Dudak / Cleft lip). Damak yarığı (Cleft palate) ise daha arkada, maksiller çıkıntılardan uzanan 'Palatin rafların (çıkıntıların)' orta hatta birleşememesi sonucu oluşur."},{"id":2338,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Böbrek yetmezliği olan hastada potasyum 8,0 mEq/L'ye yükselirken önce sivri T dalgaları, ardından QRS genişlemesi gelişiyor. Hiperkaleminin iletimi yavaşlatan hücresel etkisi hangisidir?","options":["İstirahat potansiyelini daha negatif yapıp kalsiyum kanallarını kapatması","Klor girişini artırıp membranı hiperpolarize etmesi","Potasyum denge potansiyelini değiştirmeden yalnız ATP'yi azaltması","Membranı kalıcı depolarize ederek hızlı sodyum kanallarını inaktive etmesi","Gap junction sayısını birkaç dakika içinde artırması"],"correct":3,"exp":"Ekstrasellüler potasyum artışı istirahat potansiyelini daha az negatif yapar. Süreğen depolarizasyon hızlı sodyum kanallarını inaktive eder; yükseliş hızı ve iletim yavaşlar, QRS genişler."},{"id":2339,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Eritrositler 150 mOsm/kg'lık, hücre zarını geçemeyen çözücü içeren ortama konduğunda şişip hemolize oluyor. Suyun hücre içine net hareketini belirleyen temel güç hangisidir?","options":["Hidrostatik basınç farkı olmadan aktif su pompası","Çözünen maddenin ATP'ye bağlı taşınması","Membran potansiyelinin suyu doğrudan çekmesi","Etkin osmolarite farkına bağlı ozmotik basınç","Hemoglobinin ekzositoyla atılması"],"correct":3,"exp":"Hücre dışı etkin osmolarite düşük olduğunda su, kimyasal potansiyel farkıyla aquaporinlerden hücreye geçer. Toniciteyi yalnız zarı geçemeyen etkin osmoller belirler."},{"id":2340,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Tip 1 diyabetli hastada insülin yokluğunda iskelet kası ve yağ dokusuna glukoz girişi azalırken beyin glukoz kullanımını büyük ölçüde sürdürür. Nöronal taşıyıcının hangi özelliği bu farkı açıklar?","options":["Yalnız insülinle membrana taşınması","Yüksek afiniteli, insülinden bağımsız GLUT3 olması","Sodyumla birlikte sekonder aktif taşıma yapması","Sadece hiperglisemide çalışması","Glukozu hücre dışına pompalaması"],"correct":1,"exp":"Nöronlardaki GLUT3 yüksek afiniteli ve insülinden bağımsızdır. Kas ve yağdaki GLUT4'ün membrana taşınması ise insülinle artar; bu nedenle insülin eksikliği dokuları farklı etkiler."},{"id":2341,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Kronik sinüzit, bronşektazi, situs inversus ve erkek infertilitesi olan hastanın nazal biyopsisinde silyalar yapısal olarak mevcut ancak etkili vuru yapamıyor. En olası ultrastrüktürel kusur hangisidir?","options":["Aktin filamentlerinin yokluğu","Keratinin aşırı sentezi","Desmozomların parçalanması","Kinesinle anterograd taşınmanın artması","Aksonemal dinein kollarının kusuru"],"correct":4,"exp":"Motil silyadaki 9+2 mikrotübül çiftleri arasında kaymayı aksonemal dinein sağlar. Dinein kusuru mukosiliyer temizliği, sperm hareketini ve embriyonik lateralizasyonu bozar."},{"id":2342,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Açlıkta glukagon hepatosit reseptörüne bağlandıktan saniyeler içinde glikojen fosforilaz aktive oluyor. Beta-1 adrenerjik uyarı da kalpte aynı G proteini ailesini kullanıyor. Ortak baskın ikinci haberci hangisidir?","options":["cGMP","cAMP","IP3 olmadan yalnız kalsiyum","Nükleer tirozin kinaz","Seramid"],"correct":1,"exp":"Glukagon ve beta-1 reseptörleri Gs üzerinden adenilat siklazı aktive eder; cAMP artar ve PKA hedefleri fosforile eder. Bu, hızlı hormon yanıtının amplifikasyonunu sağlar."},{"id":2343,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Bir agonist hedef hücrede fosfolipaz C'yi aktive ediyor; membran fosfolipidinden IP3 ve DAG oluşuyor, sitozolik kalsiyum ve protein kinaz C aktivitesi artıyor. Bu reseptör hangi G proteiniyle eşleşmiştir?","options":["Gs","Gi","Gq","Transdüsin","Golf"],"correct":2,"exp":"Gq, fosfolipaz C-beta üzerinden PIP2'yi IP3 ve DAG'a ayırır. IP3 endoplazmik retikulumdan kalsiyum salarken DAG ve kalsiyum PKC'yi aktive eder."},{"id":2344,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"DNA hasarı sonrası tek hücre küçülüyor, kromatini yoğunlaşıyor ve membranla çevrili cisimciklere ayrılıyor; komşu dokuda inflamasyon gelişmiyor. En tipik mekanizma hangisidir?","options":["Kaspazların düzenli biçimde aktive olduğu apoptoz","ATP kaybına bağlı koagülasyon nekrozu","Kompleman aracılı osmotik lizis","Hücre dışı matriksin kalsifikasyonu","Kontrolsüz lizozom rüptürü"],"correct":0,"exp":"Apoptoz enerji bağımlı kaspaz aktivasyonu, hücre küçülmesi ve apoptotik cisimciklerle seyreder; membran bütünlüğü korunduğu için inflamasyon minimaldir."},{"id":2345,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":5,"q":"İskemik miyokard sınırında komşu kardiyomiyositler arasında iyon akışı azalıyor ve elektriksel eşleşme bozuluyor. Bu iletişimi normalde sağlayan bağlantı hangisidir?","options":["Zonula okludens","Hemidesmozom","Gap junction","Fokal adezyon","Zonula adherens"],"correct":2,"exp":"Connexonlardan oluşan gap junctionlar düşük dirençli iyon geçişi sağlayarak kardiyomiyositlerin elektriksel senkronizasyonunu sağlar. Mekanik bağ ise adherens bağlantı ve desmozomlarla güçlenir."},{"id":2346,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Bağırsak inflamasyonunda epitel hücreleri arasından antijen geçişi artıyor. Claudin ve occludin kaybı saptanıyor. Hangi bağlantı kompleksi bozulmuştur?","options":["Desmozom","Gap junction","Zonula okludens","Hemidesmozom","Neksus dışı sinaps"],"correct":2,"exp":"Claudin ve occludin tight junctionın temel transmembran proteinleridir. Apikal paracellular bariyeri ve epitel polaritesini korurlar; kayıpları geçirgenliği artırır."},{"id":2347,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Tekrarlayan kırıkları, mavi sklerası ve işitme kaybı olan çocukta COL1A1 patojenik varyantı saptanıyor. En çok etkilenen matriks proteini hangisidir?","options":["Tip I kollajen","Tip II kollajen","Tip IV kollajen","Elastin","Fibrillin-1"],"correct":0,"exp":"Osteogenezis imperfekta çoğunlukla kemik, dentin ve sklerada bulunan tip I kollajenin miktar veya yapı kusuruna bağlıdır. Tip II kollajen kıkırdakta, tip IV bazal membranda baskındır."},{"id":2348,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Diz eklemindeki tam kat kıkırdak lezyonu uzun süre iyileşmiyor. Kondrositlerin sınırlı metabolik kapasitesine ek olarak iyileşmeyi en çok kısıtlayan doku özelliği aşağıdakilerden hangisidir?","options":["Yoğun lenfatik ağ içermesi","Yüksek mitotik hızlı epitel tabakası taşıması","Zengin sinir pleksusuyla beslenmesi","Çok sayıda osteon içermesi","Avasküler olması ve besinleri difüzyonla alması"],"correct":4,"exp":"Hiyalin eklem kıkırdağı avaskülerdir; kondrositler sinovyal sıvıdan difüzyonla beslenir. Düşük hücre yoğunluğu ve progenitör erişiminin azlığı onarım kapasitesini sınırlar."},{"id":2349,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Cerrahi yara iyileşmesinin erken granülasyon evresinde biriken kollajen daha sonra yeniden düzenlenerek çekme dayanımı artıyor. Erken kollajenin yerini alan değişim hangisidir?","options":["Tip III kollajenin tip I kollajenle değiştirilmesi","Tip I kollajenin tip II ile değiştirilmesi","Tip IV kollajenin elastine dönüşmesi","Fibronektinin keratine dönüşmesi","Lamininin tip III kollajene dönüşmesi"],"correct":0,"exp":"Erken yara dokusunda daha ince tip III kollajen baskındır. Remodelling sırasında tip I kollajen artar ve liflerin çapraz bağlanmasıyla çekme dayanımı yükselir."},{"id":2350,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"İskelet kası lifinde T-tübül depolarizasyonu riyanodin reseptörlerini açıp sitozolik kalsiyumu artırıyor. İnce filament üzerinde çapraz köprü oluşumunu doğrudan başlatan olay hangisidir?","options":["Kalsiyumun kalmoduline bağlanması","Miyozin hafif zincirinin fosforilasyonu","Titinin parçalanması","Kalsiyumun troponin C'ye bağlanması","ATP'nin tamamen tükenmesi"],"correct":3,"exp":"İskelet kasında kalsiyum troponin C'ye bağlanır; tropomiyozin aktin üzerindeki miyozin bağlanma bölgelerinden uzaklaşır ve çapraz köprü döngüsü başlar."},{"id":2351,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Bağırsak düz kasında muskarinik uyarı sonrası hücre içi kalsiyum artıyor. Troponin bulunmayan bu hücrede kalsiyum hangi proteine bağlanarak miyozin hafif zincir kinazını aktive eder?","options":["Troponin T","Tropomiyozin","Kalmodulin","Distrofin","Nebulin"],"correct":2,"exp":"Düz kasta kalsiyum-kalmodulin kompleksi MLCK'yi aktive eder; miyozin hafif zinciri fosforillenince aktinle etkileşim başlar. Gevşeme miyozin fosfataz aktivitesiyle desteklenir."},{"id":2352,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":5,"q":"Süksinilkolin ve volatil anestezik sonrası hastada masseter rijiditesi, hızla yükselen end-tidal CO2, hipertermi ve asidoz gelişiyor. RYR1 kusurunda kontrolsüz artan sitozolik iyon hangisidir?","options":["Sodyum","Klor","Kalsiyum","Magnezyum","Fosfat"],"correct":2,"exp":"RYR1 üzerinden sarkoplazmik retikulumdan kontrolsüz kalsiyum salınması sürekli kasılma ve hiperemetabolizma yapar. Tetikleyici kesilir ve dantrolen riyanodin reseptör aracılı salınımı azaltmak için verilir."},{"id":2353,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Ölümden sonra ATP üretimi durunca kas lifleri kısalmış durumda kilitlenir ve rigor mortis gelişir. Çapraz köprü döngüsünde hangi ATP bağımlı basamak yapılamaz?","options":["Miyozin başının aktinden ayrılması","Kalsiyumun troponine bağlanması","Aktinin polimerleşmesi","Asetilkolinin reseptöre bağlanması","Sodyum kanalının açılması"],"correct":0,"exp":"Yeni ATP'nin miyozine bağlanması aktin-miyozin köprüsünü ayırır. ATP olmayınca kalsiyum da sarkoplazmik retikuluma pompalanamaz ve köprüler bağlı kalır."},{"id":2354,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Miyastenia gravisli hastada tekrarlayan uyarıda bileşik kas aksiyon potansiyeli giderek azalıyor ve pitoz artıyor. Temel nöromüsküler kavşak kusuru hangisidir?","options":["Presinaptik voltaj kapılı kalsiyum kanalı antikoru","Asetilkolinesterazın kalıtsal yokluğu","Motor nöron kaybı","Postsinaptik nikotinik asetilkolin reseptörlerinin azalması","Kas riyanodin reseptörünün sürekli açık kalması"],"correct":3,"exp":"Miyastenide postsinaptik ACh reseptörü veya ilişkili proteinlere karşı antikorlar güvenlik faktörünü azaltır. Ardışık salımlarda uç plak potansiyeli eşiğe ulaşamaz ve dekrement oluşur."},{"id":2355,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Ev yapımı konserve sonrası diplopi, pupilla genişliği, disfaji ve inen flask paralizi gelişiyor. Botulinum toksininin nöromüsküler kavşaktaki temel etkisi hangisidir?","options":["Postsinaptik reseptörü sürekli uyarmak","Asetilkolinesterazı geri dönüşsüz inhibe etmek","Kas sodyum kanalını açmak","Miyozin ATPazını bloke etmek","Asetilkolin vezikül salımının engellenmesi"],"correct":4,"exp":"Botulinum toksini presinaptik SNARE proteinlerini keser ve asetilkolin ekzositozunu engeller. Otonom ve kraniyal sinir bulgularıyla inen paralizi yapar."},{"id":2356,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"İzole iskelet kasına gevşeme tamamlanmadan art arda uyarı verildiğinde gerilim summasyonla artıyor ve sonunda tetanik plato oluşuyor. Bu artışın doğrudan nedeni hangisidir?","options":["Sitozolik kalsiyum birikimi","Aksiyon potansiyelinin genliğinin her uyarıda artması","Motor nöron sayısının laboratuvarda çoğalması","ATP sentezinin tamamen durması","Tropomiyozinin parçalanması"],"correct":0,"exp":"İskelet kası refrakter dönemi kasılmadan kısadır. Sık uyarıda kalsiyum SR'ye tamamen dönmeden yeni salım olur, aktif çapraz köprü sayısı ve kuvvet artar."},{"id":2357,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Kalsiyum kanal blokeri kalp kası kasılmasını iskelet kasına göre belirgin azaltıyor. Bu farkı açıklayan temel eşleşme mekanizması hangisidir?","options":["Kalpte troponin bulunmaması","İskelet kasında sarkoplazmik retikulum olmaması","Kalpte kalsiyumun yalnız çekirdekten salınması","Kalsiyumla indüklenen kalsiyum salımı","İskelet kasının sadece sodyumla kasılması"],"correct":3,"exp":"Kardiyomiyositte L-tipi kanaldan giren kalsiyum RYR2'yi açarak SR'den daha fazla kalsiyum salınmasını tetikler. İskelet kasında DHPR-RYR1 mekanik eşleşmesi dış kalsiyuma daha az bağımlıdır."},{"id":2358,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Kademeli kuvvet isteyen bir harekette önce az sayıda küçük kas lifini yöneten motor nöronlar, sonra büyük motor üniteler aktive oluyor. Henneman büyüklük ilkesinin işlevsel sonucu hangisidir?","options":["Tüm hareketlerin maksimal kuvvetle başlaması","Hızlı liflerin her zaman önce yorulması","Kuvvetin ekonomik ve ince derecelendirilmesi","Motor ünite sayısının azalması","Kas iğciği duyusunun kaybolması"],"correct":2,"exp":"Küçük, düşük eşikli ve yorulmaya dirençli motor ünitelerin önce; büyük hızlı ünitelerin gereksinim arttıkça katılması kuvveti hassas ve enerji verimli biçimde derecelendirir."},{"id":2359,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":5,"q":"İzole kas lifinde çok kısa sarkomerlerde aktin filamentleri aşırı örtüşüyor, çok uzun sarkomerlerde aktin-miyozin örtüşmesi azalıyor; orta uzunlukta aktif gerilim en yüksek ölçülüyor. Bu gözlem hangi ilişkiyi gösterir?","options":["Kuvvet-hız ilişkisi","Uzunluk-gerilim ilişkisi","Frank-Starling yasası yalnız kalpte","Laplace yasası","Fick ilkesi"],"correct":1,"exp":"Aktif kuvvet kurulabilecek çapraz köprü sayısına bağlıdır. Optimum sarkomer uzunluğunda aktin-miyozin örtüşmesi uygundur; aşırı kısalma veya uzama kuvveti azaltır."},{"id":2360,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"İnfertil erkekte sperm sayısı çok düşük, FSH yüksek, LH ve testosteron normal sınıra yakındır. Seminifer tübül hasarı düşünülüyor. FSH'nin spermatogenezi desteklemek için başlıca hedeflediği hücre hangisidir?","options":["Leydig hücresi","Peritübüler miyoid hücre","Spermatid","Sertoli hücresi","Epididim epitel hücresi"],"correct":3,"exp":"FSH Sertoli hücrelerini uyararak inhibin B, androjen bağlayıcı protein ve germ hücresi desteğini artırır. LH ise Leydig hücresinde testosteron sentezini uyarır."},{"id":2361,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Orşit sonrası kan-testis bariyeri bozulan erkekte antisperm antikorları gelişiyor. Bu bariyeri oluşturan temel yapı hangisidir?","options":["Komşu Sertoli hücreleri arasındaki sıkı bağlantılar","Leydig hücreleri arasındaki gap junctionlar","Spermatidler arasındaki desmozomlar","Epididim düz kasının bazal laminası","Tunika albugineadaki elastik lifler"],"correct":0,"exp":"Sertoli hücrelerinin tight junctionları seminifer epiteli bazal ve adluminal kompartımana ayırır; mayoz sonrası antijenik germ hücrelerini bağışıklık sisteminden korur."},{"id":2362,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Siklus ortasında servikal mukus bol, berrak, esnek ve ferning pozitiftir; sperm geçişi kolaylaşmıştır. Bu değişiklik hangi hormonal ortamla uyumludur?","options":["Progesteron baskınlığı","Östrojen baskınlığı","Prolaktin fazlalığı","Düşük gonadotropin düzeyi","Yüksek inhibin A tek başına"],"correct":1,"exp":"Ovulasyon öncesi yüksek östrojen servikal mukusu ince, sulu ve geçirgen yapar. Luteal progesteron mukusu koyulaştırarak sperm geçişini azaltır."},{"id":2363,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Endometrium biyopsisinde bezler testere dişi görünümünde ve glikojenden zengin sekresyonlu, stroma ödemlidir. Örnek ovulasyondan bir hafta sonra alınmıştır. Baskın hormon hangisidir?","options":["FSH","Progesteron","Oksitosin","Prolaktin","Testosteron"],"correct":1,"exp":"Korpus luteumdan salgılanan progesteron proliferatif endometriumu implantasyona uygun sekretuar endometriuma dönüştürür. Bez kıvrımlanması ve stromal ödem tipiktir."},{"id":2364,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Ejakülattaki sperm başlangıçta zona pellusidayı geçemez. Kadın genital kanalında membran kolesterolü ve yüzey glikoproteinleri değiştikten sonra hiperaktif hareket ve akrozom reaksiyonu yeteneği kazanır. Bu süreç hangisidir?","options":["Spermatogenez","Spermiogenez","Mayoz I","Kapasitasyon","Kortikal reaksiyon"],"correct":3,"exp":"Kapasitasyon kadın genital kanalında spermin membran özelliklerini ve hareketini değiştirerek zona bağlanması ve akrozom reaksiyonuna hazırlar. Kortikal reaksiyon ise döllenme sonrası polispermi engelidir."},{"id":2365,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Emziren annede süt üretimi yeterli olduğu hâlde yoğun stres sırasında süt akışı azalıyor. Bebeğin emmesiyle normalde mioepitelyal hücreleri kasarak süt ejeksiyonunu sağlayan hormon hangisidir?","options":["Oksitosin","Prolaktin","FSH","Östrojen","Kortizol"],"correct":0,"exp":"Oksitosin alveol çevresi mioepitelyal hücreleri kasar ve sütü kanallara iter. Prolaktin süt sentezini destekler; stres oksitosin refleksini baskılayabilir."},{"id":2366,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":5,"q":"Yoğun egzersiz yapan ve enerji alımı düşük genç kadında kilo kaybı, amenore ve düşük LH-FSH vardır. Bu işlevsel hipotalamik amenorenin temel düzenleyici kusuru hangisidir?","options":["GnRH puls frekansı ve amplitüdünün baskılanması","Ovaryumda sürekli LH reseptör aktivasyonu","Hipofizden FSH'nin otonom salgılanması","Endometriumun progesterona aşırı yanıtı","Korpus luteumun kalıcı olması"],"correct":0,"exp":"Enerji yetersizliği, stres ve egzersiz leptin/kisspeptin sinyallerini etkileyerek GnRH pulslarını baskılar; gonadotropin ve östrojen düşer. Kemik sağlığı ve enerji erişilebilirliği birlikte ele alınır."},{"id":2367,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Gebeliğin ilk ayında fark edilmeden yüksek riskli teratojene maruz kalan kadında majör organ malformasyonu riski maruziyet zamanına göre değerlendiriliyor. Organogenez açısından en duyarlı dönem hangisidir?","options":["Döllenmeden sonraki ilk 24 saat","İmplantasyon öncesi yalnız iki hücreli dönem","Fetal dönemin son üç haftası","Döllenmeden sonraki 3–8. haftalar","Doğumdan sonraki neonatal dönem"],"correct":3,"exp":"Embriyonik 3–8. haftalarda organogenez gerçekleşir ve teratojenler majör yapısal anomalilere yol açabilir. İlk iki haftada daha çok hep-ya-da-hiç etkisi, fetal dönemde büyüme ve işlev bozukluğu beklenir."},{"id":2368,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Primitif çizgi gelişim kusuru bulunan embriyoda gastrulasyon tamamlanamıyor. Normal gastrulasyonda epiblasttan hangi üç tabaka oluşur?","options":["Amniyon, koriyon ve allantois","Trofoblast, sinsityum ve sitotrofoblast","Nöral tüp, notokord ve somit","Yolk kesesi, amniyon ve plasenta","Ektoderm, mezoderm ve endoderm"],"correct":4,"exp":"Gastrulasyonda epiblast hücreleri primitif çizgiden göç ederek definitif endoderm ve mezodermi oluşturur; yüzeyde kalanlar ektoderme dönüşür."},{"id":2369,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Perikonsepsiyonel folat almayan gebede açık nöral tüp defekti saptanıyor. Folatın koruyucu olabilmesi için en kritik gelişimsel olay hangisidir?","options":["Nöral tüpün gebeliğin ilk dört haftasında kapanması","Alveollerin üçüncü trimesterde çoğalması","Diş sürmesinin başlaması","Korpus kallozumun doğum sonrası miyelinizasyonu","Plasentanın doğumda ayrılması"],"correct":0,"exp":"Nöroporların kapanması konsepsiyondan sonraki 3–4. haftada gerçekleşir; çoğu kadın henüz gebeliği bilmez. Bu yüzden folat konsepsiyon öncesi başlanmalıdır."},{"id":2370,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"İkiz gebelikte tek plasenta, iki koryon yerine tek koryon ve iki ayrı amniyon kesesi saptanıyor. Monozigotik embriyonun en olası ayrılma zamanı aşağıdakilerden hangisidir?","options":["İlk üç günde","On üçüncü günden sonra","Nöral tüp kapandıktan sonra","İkinci trimesterde","Dördüncü-sekizinci günler arasında"],"correct":4,"exp":"Ayrılma 4–8. günlerde, koryon oluşmuş fakat amniyon oluşmadan gerçekleşirse monokoryonik diamniyotik ikizler gelişir. Daha erken ayrılma dikoryonik, daha geç ayrılma monoamniyotik sonuç verir."},{"id":2371,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"İmplantasyondan sonra sinsityotrofoblastın salgıladığı hormon korpus luteumun steroid üretimini sürdürür ve gebelik testinde saptanır. Bu hormon hangisidir?","options":["İnsan koryonik gonadotropini","İnsan plasental laktojeni","Progesteron","İnhibin B","Relaksin"],"correct":0,"exp":"hCG, LH reseptörünü uyararak plasenta steroid sentezini devralana kadar korpus luteumu korur. Beta alt birimi gebelik testlerinin özgüllüğünü sağlar."},{"id":2372,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Kronik hipoksemik akciğer hastalığında hematokrit yükseliyor ve eritropoietin artıyor. Böbrekte EPO sentezini başlatan temel değişiklik hangisidir?","options":["Arteriyel karbondioksitin tek başına artması","Plazma hacminin artması","Renal hipoksi ve HIF stabilizasyonu","Serum demirinin yükselmesi","Trombosit sayısının azalması"],"correct":2,"exp":"Peritübüler interstisyel hücrelerde hipoksi HIF'yi stabilize eder ve EPO transkripsiyonunu artırır. EPO kemik iliğinde eritroid progenitörlerin yaşamını ve çoğalmasını destekler."},{"id":2373,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Hemoglobini 5 g/dL olan hastanın PaO2'si 95 mmHg ve pulse oksimetresi %98'dir; yine de eforla doku hipoksisi gelişiyor. En doğru açıklama hangisidir?","options":["Pulse oksimetre çözünmüş oksijeni düşük gösterir","Normal satürasyona karşın düşük oksijen içeriği","PaO2 doğrudan hemoglobin miktarını ölçer","Anemide oksijen içeriği değişmez","Doku oksijen sunumu yalnız PaCO2'ye bağlıdır"],"correct":1,"exp":"Arteriyel oksijen içeriğinin büyük kısmı hemoglobine bağlı oksijendir: CaO2 yaklaşık 1,34×Hb×SaO2'dir. Satürasyon doluluk oranını gösterir; taşıyıcı miktarı azsa içerik ve sunum düşer."},{"id":2374,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":5,"q":"Yüksek irtifada birkaç gün kalan kişide ventilasyon ve eritropoietin artışına ek olarak hemoglobin-oksijen eğrisi sağa kayıyor. Eritrositte artan hangi metabolit dokuda oksijen boşalmasını kolaylaştırır?","options":["ATP sentaz","Karbaminohemoglobin","2,3-bisfosfogliserat","Methemoglobin","Haptoglobin"],"correct":2,"exp":"2,3-BPG deoksihemoglobinin beta zincirlerine bağlanarak T durumunu stabilize eder, oksijen afinitesini düşürür ve eğriyi sağa kaydırır."},{"id":2375,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Von Willebrand hastalığı olan çocukta burun kanaması ve menoraji vardır. Trombosit sayısı normal ancak primer tıkaç oluşumu gecikmiştir. Temel kusur hangisidir?","options":["Fibrinojenin fibrine dönüşmemesi","Faktör X aktivasyonunun yokluğu","vWF aracılı trombosit adezyonunun azalması","Plazminin inhibe olması","Protein C fazlalığı"],"correct":2,"exp":"vWF damar hasarında kollajene bağlanır ve trombosit GPIb için köprü oluşturur. Ayrıca faktör VIII'i taşır; bu nedenle ağır eksiklik aPTT'yi de uzatabilir."},{"id":2376,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Akut inflamasyon sırasında eritrosit sedimantasyon hızı artıyor ve yaymada rouleaux oluşuyor. Bu değişikliği en çok artıran plazma proteini hangisidir?","options":["Albümin","Fibrinojen","Transferrin","Prealbümin","Antitrombin"],"correct":1,"exp":"Fibrinojen gibi akut faz proteinleri eritrositlerin negatif yüzey yükünü maskeler, rouleaux ve daha hızlı çökmeye yol açar. ESR özgül olmayan dolaylı inflamasyon göstergesidir."},{"id":2377,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"Kemik iliğini baskılayan kemoterapi sonrası nötrofiller birkaç gün içinde azalırken eritrosit sayısı daha yavaş düşüyor. Bu farkın en önemli nedeni hangisidir?","options":["Eritrositlerin çekirdekli olması","Nötrofillerin dolaşımda çoğalması","Eritropoietinin nötrofil yapımını artırması","Eritrositlerin dalakta sürekli yeniden üretilmesi","Eritrositlerin yaklaşık 120 günlük uzun dolaşım ömrü"],"correct":4,"exp":"Nötrofillerin dolaşım ömrü kısadır ve üretim kesilince hızla azalırlar. Olgun eritrositlerin ortalama 120 günlük ömrü olduğundan anemi daha geç belirginleşir."},{"id":2378,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Embriyodan doğuma hematopoezin baskın yeri değişir. Doğru kronolojik sıra hangisidir?","options":["Kemik iliği → yolk kesesi → karaciğer","Dalak → timus → yolk kesesi","Yolk kesesi → karaciğer/dalak → kemik iliği","Karaciğer → yolk kesesi → böbrek","Böbrek → dalak → kemik iliği"],"correct":2,"exp":"İlk kan adacıkları yolk kesesinde oluşur; fetal dönemde karaciğer baskın, dalak katkılıdır. Gebeliğin ilerleyen döneminde kemik iliği ana hematopoetik organ hâline gelir."},{"id":2379,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Demir eksikliğinde hem sentezinin son mitokondriyal basamağı yavaşlar. Ferroşelataz normalde Fe2+'yi hangi yapıya ekler?","options":["Protoporfirin IX","Biliverdin","Globin zinciri","Üroporfirinojen III","Süksinil-KoA"],"correct":0,"exp":"Ferroşelataz mitokondride ferroz demiri protoporfirin IX halkasına yerleştirerek hem oluşturur. Kurşun bu enzimi de inhibe eder."},{"id":2380,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Zollinger-Ellison sendromunda gastrin düzeyi çok yüksek ve mide asit sekresyonu fazladır. Gastrin parietal hücreyi doğrudan uyarmanın yanında hangi hücreden mediyatör salarak güçlü dolaylı etki oluşturur?","options":["D hücresinden somatostatin","G hücresinden sekretin","S hücresinden bikarbonat","Baş hücresinden pepsinojen","Enterokromafin benzeri hücreden histamin"],"correct":4,"exp":"Gastrin ECL hücrelerindeki CCK-B reseptörlerini uyararak histamin salınımını artırır. Histamin parietal hücre H2 reseptörü üzerinden cAMP'yi ve H+/K+-ATPaz etkinliğini yükseltir."},{"id":2381,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Yağlı yemek duodenuma ulaştığında safra kesesi kasılıyor, Oddi sfinkteri gevşiyor ve pankreatik enzimden zengin salgı artıyor. Bu eşgüdümlü yanıtın başlıca hormonu aşağıdakilerden hangisidir?","options":["Gastrin","Sekretin","Kolesistokinin","Motilin","Ghrelin"],"correct":2,"exp":"Duodenal I hücrelerinden yağ asidi ve aminoasitlere yanıtla salınan CCK safra kesesini kasar, Oddi sfinkterini gevşetir, pankreas asinüs enzim salgısını artırır ve mide boşalmasını yavaşlatır."},{"id":2382,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Duodenal pH 4'e düştüğünde pankreas kanal hücrelerinden bikarbonattan zengin sıvı salgısı artıyor. Bu yanıtın baskın hormonal uyarıcısı hangisidir?","options":["Motilin","Ghrelin","Gastrin","Somatostatin","Sekretin"],"correct":4,"exp":"Duodenal S hücreleri aside yanıtla sekretin salgılar. Sekretin pankreas ve safra kanallarında cAMP aracılığıyla bikarbonat salgısını artırıp asidi nötralize eder."},{"id":2383,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Crohn hastalığı nedeniyle terminal ileumu çıkarılan hastada safra asidi havuzu azalıyor, steatore ve kolonda safra asidine bağlı ishal gelişiyor. Safra tuzlarının aktif geri emildiği ana bölge aşağıdakilerden hangisidir?","options":["Duodenum","Jejunum","Terminal ileum","Çekum","Rektum"],"correct":2,"exp":"Safra tuzları terminal ileumda apikal sodyum bağımlı taşıyıcıyla geri emilir ve portal yolla karaciğere döner. Geniş rezeksiyon havuzu azaltarak yağ malabsorpsiyonu yapar."},{"id":2384,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":5,"q":"Kolera toksini enterositte cAMP'yi artırarak klor ve su sekresyonunu sürdürür. Buna rağmen glukoz-sodyum içeren oral rehidrasyon solüsyonu su emilimini artırır. Korunmuş taşıyıcı hangisidir?","options":["CFTR","ENaC","Na+/H+ değiştirici tek başına","GLUT5","Sodyum-glukoz kotransporteri 1"],"correct":4,"exp":"SGLT1 glukozla sodyumu enterosite birlikte alır; su osmotik olarak izler. Kolera cAMP-CFTR sekresyonunu artırsa da SGLT1 işlevi korunur, oral rehidrasyon bu nedenle etkilidir."},{"id":2385,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Kronik pankreatitli hastada steatore, kilo kaybı ve A-D-E-K vitamini eksikliği vardır. Karbonhidrat ve protein sindirimi göreceli korunurken yağ malabsorpsiyonunu en çok açıklayan eksik salgı hangisidir?","options":["Tükürük amilazı","Pankreatik lipaz","Enteropeptidaz","Pepsin","Laktaz"],"correct":1,"exp":"Pankreatik lipaz trigliserid sindiriminin ana enzimidir ve yedek kapasitesi diğer pankreas enzimlerinden daha sınırlıdır. Bu yüzden ekzokrin yetersizlikte steatore erken belirginleşir."},{"id":2386,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Otoimmün gastritli hastada parietal hücre kaybı, aklorhidri ve makrositik anemi vardır. Vitamin B12'nin terminal ileum reseptörüne bağlanabilmesi için gerekli mide proteini hangisidir?","options":["Haptokorrin","Pepsinojen","Transkobalamin II","İntrinsik faktör","Enteropeptidaz"],"correct":3,"exp":"Parietal hücre intrinsik faktör salgılar. Duodenumda pankreas enzimleri B12'yi haptokorrinden ayırır; B12-intrinsik faktör kompleksi terminal ileumda cubilin aracılığıyla emilir."},{"id":2387,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Açlıkta mide ve ince bağırsakta yaklaşık 90 dakikada bir güçlü peristaltik aktivite oluşuyor; yemekle bu patern kayboluyor. Göç eden motor kompleksin başlıca hormonal düzenleyicisi hangisidir?","options":["Motilin","Sekretin","Kolesistokinin","Gastrik inhibitör peptit","Leptin"],"correct":0,"exp":"Motilin açlık döneminde göç eden motor kompleksi başlatır; lümen artıklarını distale süpüren bu aktivite öğünle baskılanır. Makrolidlerin motilin reseptör agonizmi prokinetik etki yapabilir."},{"id":2388,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Yağlı ve hiperozmolar kimus duodenuma geçtiğinde antral kasılmalar azalıyor, pilor tonusu artıyor ve mide boşalması yavaşlıyor. Bu yanıtın fizyolojik amacı hangisidir?","options":["Duodenuma daha hızlı yük göndermek","Pankreas bikarbonatını azaltmak","Safra kesesi kasılmasını engellemek","Duodenal sindirim kapasitesini korumak","Gastrik asit salgısını kalıcı olarak durdurmak"],"correct":3,"exp":"Duodenal yağ, asit, hiperozmolarite ve distansiyon enterogastrik refleksler ve CCK/sekretin aracılığıyla mide boşalmasını yavaşlatır; duodenuma kontrollü yük sağlar."},{"id":2389,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"Süt içtikten sonra gaz, kramp ve sulu ishal gelişen hastada dışkı ozmotik açıklığı yüksek, pH düşüktür; açlıkla yakınmalar kaybolur. En uygun fizyolojik açıklama aşağıdakilerden hangisidir?","options":["Aktif klor sekresyonunun açlıkta artması","Yağ emiliminin bozulması","Emilmeyen laktozun ozmotik ve fermentatif etkisi","Kolonda sodyum emiliminin artması","Safra asidi sentezinin azalması"],"correct":2,"exp":"Laktaz eksikliğinde emilmeyen laktoz ozmotik olarak su tutar; kolonik bakteriler kısa zincirli asit ve gaz üretir. Açlıkla düzelme ozmotik ishali sekretuar ishalden ayırır."},{"id":2390,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Proton pompa inhibitörü kullanan ve çölyak açısından değerlendirilen demir eksikliği hastasında emilim bölgesi sorgulanıyor. Nonhem demirin DMT1 aracılığıyla en yoğun alındığı bölüm aşağıdakilerden hangisidir?","options":["Terminal ileum","Çekum","Kolon","Mide fundusu","Duodenum ve proksimal jejunum"],"correct":4,"exp":"Diyet demiri başlıca duodenum ve proksimal jejunumda emilir. Asit ferrik demirin çözünmesini/indirgenmesini kolaylaştırır; enterositten ferroportinle çıkar ve hepsidin bunu düzenler."},{"id":2391,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Uzun zincirli yağ asitleri enterositte yeniden esterifiye edilip apoB-48 içeren parçacıklara paketleniyor. Portal kapilleri atlayıp lakteallere geçen bu parçacık hangisidir?","options":["VLDL","Şilomikron","LDL","HDL","Misel"],"correct":1,"exp":"Şilomikronlar uzun zincirli trigliseridleri lenf yoluyla dolaşıma taşır. Miseller lümende emilimi kolaylaştırır ancak enterositten lenfe giren taşıyıcı değildir; kısa-orta zincir yağ asitleri portal kana geçebilir."},{"id":2392,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":5,"q":"VIPoma hastasında litrelerce sulu ishal, hipokalemi ve aklorhidri var. Dışkılama açlıkta da sürüyor. VIP'nin enterositte artırdığı ana lüminal akım aşağıdakilerden hangisidir?","options":["Klor ve bikarbonat sekresyonu ve bunu izleyen su","Safra tuzu geri emilimi","Demir emilimi","Kalsiyum emilimi","Glukoz ve aminoasit emilimi"],"correct":0,"exp":"VIP cAMP üzerinden intestinal klor/bikarbonat ve su sekresyonunu artırır, sodyum emilimini ve mide asidini azaltır. Açlıkta sürmesi sekretuar ishali destekler."},{"id":2393,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Tükürük bezinin primer asinüs sıvısı plazmaya yakın izotonikken kanal çıkışında hipotonik hâle gelir. Akım hızı düşükken bu değişimin temel nedeni hangisidir?","options":["Kanalın suyu sodyumdan daha hızlı emmesi","NaCl geri emilimi ve su geçirimsizliği","Asinüslerin yalnız saf su salgılaması","Kanalda tüm iyon taşınmasının durması","Proteinlerin ozmotik basıncı artırması"],"correct":1,"exp":"Çizgili kanallar Na ve Cl'yi net geri emer, K ve bikarbonat salgılar; su geçirgenliği düşüktür. Bu nedenle solüt azalırken su izleyemez ve son tükürük hipotonik olur."},{"id":2394,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Rektal distansiyon iç anal sfinkteri gevşetiyor; kişi defekasyonu ertelemek için dış anal sfinkteri istemli kasıyor. Dış sfinkerin efferent kontrolü hangisidir?","options":["Vagus parasempatik lifleri","Pelvik splanknik otonom lifler","Hipogastrik sempatik lifler","Enterik pleksus","Pudendal sinirin somatik motor lifleri"],"correct":4,"exp":"İç anal sfinkter düz kastır ve rektoanal inhibitör refleksle gevşer. Dış sfinkter çizgili kastır; S2-S4 kökenli pudendal somatik liflerle istemli kontrol edilir."},{"id":2395,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Akut kan kaybı sonrası sıvı verilince sol ventrikül diyastol sonu hacmi artıyor; kontraktilite değişmeden atım hacmi yükseliyor. Bu yanıtı açıklayan ilke hangisidir?","options":["Laplace yasası","Frank-Starling mekanizması","Fick difüzyon yasası","Poiseuille yasası","Bernoulli ilkesi"],"correct":1,"exp":"Artan venöz dönüş miyofibrilleri optimal uzunluğa yaklaştırır ve kalsiyum duyarlılığını artırır; aynı kontraktilitede sistolik kuvvet ve atım hacmi yükselir."},{"id":2396,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sağlıklı kişi aniden ayağa kalkınca arter basıncı kısa süre düşüyor; saniyeler içinde kalp hızı ve periferik direnç artıyor. Bu hızlı refleksi başlatan gerilme reseptörleri nerede bulunur?","options":["Pulmoner alveoller","Renal medulla","Adrenal korteks","Hipofiz arka lobu","Karotis sinüsü ve aort kavsi"],"correct":4,"exp":"Arter basıncı düşünce karotis sinüsü ve aort kavsi baroreseptör ateşlemesi azalır; medüller merkez sempatik aktiviteyi artırıp vagal aktiviteyi azaltır."},{"id":2397,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Ciddi aort stenozunda kontraktilite ve preload başlangıçta aynı kabul edilirse sol ventrikül basınç-hacim döngüsünde artmış afterloadun ilk etkisi aşağıdakilerden hangisidir?","options":["End-sistolik hacmin azalması","Ejeksiyon basıncının düşmesi","İzovolümetrik kontraksiyonun kaybolması","End-sistolik hacmin artması ve atım hacminin azalması","End-diyastolik hacmin sıfırlanması"],"correct":3,"exp":"Artan aort çıkış direnci ventrikülün daha yüksek basınç üretmesini gerektirir ve daha az kan ejekte edilir. Akut olarak end-sistolik hacim artar, atım hacmi azalır."},{"id":2398,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Ağır mitral yetersizliğinde sol ventrikül basınç-hacim döngüsünde hem izovolümetrik kontraksiyon hem izovolümetrik gevşeme belirgin kaybolur. Bunun nedeni hangisidir?","options":["Aort kapağının tüm siklus açık olması","Ventrikülün hiç dolmaması","Atriyum ile ventrikül basınçlarının eşit olması","Mitral kaçak nedeniyle hacmin sürekli değişmesi","Elektriksel sistolün ortadan kalkması"],"correct":3,"exp":"Mitral kapak sistolde kapalı kalamadığı için ventrikül daha aort kapağı açılmadan atriyuma kan kaçırır; aort kapandıktan sonra da kaçak sürer. Bu nedenle hacim sabit izovolümetrik fazlar kaybolur."},{"id":2399,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Derin inspirasyonda sağ ventrikül dolumu ve ejeksiyon süresi artarken sol ventriküle geçici olarak daha az kan gelir. İkinci kalp sesinin fizyolojik çiftleşmesinde geciken bileşen hangisidir?","options":["Aort kapağının kapanması","Pulmoner kapağın kapanması","Mitral kapağın açılması","Triküspit kapağın açılması","Mitral kapağın kapanması"],"correct":1,"exp":"İnspirasyonda artan sağ kalp dolumu pulmoner ejeksiyonu uzatır ve P2'yi geciktirir; eş zamanlı azalan sol dolum A2'yi hafif erkene çekebilir."},{"id":2400,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sağlıklı kişide dinamik egzersizde kardiyak debi belirgin artarken sistolik basınç yükseliyor, diyastolik basınç aynı kalıyor veya hafif düşüyor. Bu basınç örüntüsünü açıklayan periferik değişiklik hangisidir?","options":["Çalışan kasta alfa-1 aracılı yaygın vazokonstriksiyon","Koroner akımın durması","Tüm organlarda direnç artışı","Çalışan kasta metabolik vazodilatasyon","Venöz dönüşün tamamen kesilmesi"],"correct":3,"exp":"Aktif kasta adenozin, potasyum, CO2 ve H+ gibi metabolitler lokal vazodilatasyon yapar. Kardiyak debi artışı sistolik basıncı yükseltirken toplam periferik direncin düşmesi diyastolik basıncın yükselmesini sınırlar."},{"id":2401,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Restriktif kardiyomiyopatili hastada sol ventriküle 20 mL ek hacim verildiğinde diyastol sonu basıncı 12 mmHg artıyor; sağlıklı kişide aynı hacim artışı basıncı yalnız 3 mmHg yükseltiyor. Hastadaki değişikliği en iyi tanımlayan ifade hangisidir?","options":["Ventrikül kompliyansı artmıştır","Ventrikül kompliyansı azalmıştır","Kontraktilite artmıştır","Afterload azalmıştır","Ejeksiyon fraksiyonu mutlaka artmıştır"],"correct":1,"exp":"Kompliyans ΔV/ΔP'dir. Aynı hacim artışının daha büyük basınç artışı oluşturması diyastolik basınç-hacim eğrisinin dikleştiğini ve kompliyansın azaldığını gösterir."},{"id":2402,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Nefrotik sendromlu hastada serum albümini 1,7 g/dL ve yaygın ödem vardır. Kalp ve böbrek fonksiyonları başlangıçta normal kabul edilirse kapiller filtrasyonu artıran başlıca Starling değişikliği hangisidir?","options":["Plazma kolloid ozmotik basıncının azalması","İnterstisyel hidrostatik basıncın artması","Kapiller hidrostatik basıncın azalması","Lenf akımının artması","Plazma sodyumunun tek başına düşmesi"],"correct":0,"exp":"Hipoalbüminemi kapiller içindeki onkotik geri emici kuvveti azaltır ve net filtrasyonu artırır. İkincil sodyum tutulumu ödemi ağırlaştırabilir ancak verilen başlangıç değişikliği düşük plazma onkotik basıncıdır."},{"id":2403,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Akut kan kaybı sonrası ortalama arter basıncı düşen hastada karotis sinüsü baroreseptör ateşleme hızı azalıyor. İlk dakikalardaki telafi yanıtı hangisidir?","options":["Vagal aktivitede artış ve bradikardi","Sempatik aktivitede azalma","Arterioler vazodilatasyon","Venöz kapasitans artışı","Sempatik aktivite artışı ve vagal çekilme"],"correct":4,"exp":"Baroreseptör ateşlemesinin azalması medüller merkezde sempatik çıkışı artırır, vagal tonu azaltır. Taşikardi, artmış kontraktilite, venokonstriksiyon ve arterioler vazokonstriksiyon gelişir."},{"id":2404,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sol ventrikül hipertrofisi olan hastada taşikardi sırasında subendokardiyal iskemi gelişiyor. Sol koroner akımın özellikle diyastole bağımlı olmasının temel nedeni aşağıdakilerden hangisidir?","options":["Sistolde intramiyokardiyal damarların ventrikül basıncıyla sıkışması","Aort kapağının diyastolde kapanmaması","Koroner sinüsün sistolde tıkanması","Diyastolde aort basıncının sıfıra inmesi","Koroner arterlerin yalnız venöz basınçla perfüze olması"],"correct":0,"exp":"Sol ventrikül sistolünde yüksek intramiyokardiyal basınç, özellikle subendokardiyal damarları sıkıştırır. Diyastolde gevşeme ve aort-koroner basınç gradyanı akımı artırır; taşikardi diyastolü kısaltarak iskemi riskini yükseltir."},{"id":2405,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"İvabradin verilen hastada SA nodunun faz 4 depolarizasyon eğimi azalıyor ve kalp hızı düşüyor. İlaç başlıca hangi akımı inhibe eder?","options":["Hızlı voltaj kapılı sodyum akımı","HCN kanallarından geçen funny akımı","L-tipi kalsiyum akımı","İçe doğrultucu potasyum akımı","Klor akımı"],"correct":1,"exp":"SA nodunda hiperpolarizasyonla aktive olan HCN kanalları yavaş inward funny akımını oluşturur ve faz 4 depolarizasyonuna katkı verir. İvabradin bu akımı azaltarak hızı düşürür."},{"id":2406,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Ventrikül miyositinde aksiyon potansiyelinin plato fazı uzun refrakter dönem ve tetaninin önlenmesini sağlar. Plato sırasında baskın net iyon dengesi hangisidir?","options":["Yalnız hızlı sodyum girişi","Klor girişi ve kalsiyum çıkışı","Potasyum girişinin durması","L-tipi kalsiyum girişiyle potasyum çıkışının dengelenmesi","Sodyum-potasyum pompasının tek başına depolarizasyon oluşturması"],"correct":3,"exp":"Faz 2'de L-tipi kanallardan yavaş kalsiyum girişi, gecikmiş doğrultucu potasyum çıkışıyla dengelenir. Uzun plato mekanik kasılmayı destekler ve refrakter dönemi uzatır."},{"id":2407,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Hemoglobini 5 g/dL olan hastada istirahatte kardiyak debi yüksek, sistemik vasküler direnç düşüktür. Anemiye bağlı vazodilatasyonu en iyi açıklayan mekanizma hangisidir?","options":["Doku oksijen sunumunun artması","Doku hipoksisine bağlı lokal metabolit birikimi","Kan viskozitesinin artması","Baroreseptörlerin sürekli uyarılması","Parasempatik arterioler vazokonstriksiyon"],"correct":1,"exp":"Düşük arteriyel oksijen içeriği dokuda adenozin, CO2, H+ ve K+ gibi vazodilatör metabolitleri artırır. Düşük viskozite ve sempatik yanıtla birlikte yüksek debili dolaşıma katkı sağlar."},{"id":2408,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Fick yöntemiyle kardiyak debi hesaplanırken oksijen tüketimi 250 mL/dakika sabit tutuluyor. Arteriyovenöz oksijen içerik farkı 5'ten 10 mL/dL'ye çıkarsa hesaplanan kardiyak debi nasıl değişir?","options":["İki kat artar","Değişmez","Yarıya iner","Dört kat artar","Sıfıra iner"],"correct":2,"exp":"Fick eşitliği CO=VO2/(CaO2−CvO2)'dir. Payda iki katına çıktığında oksijen tüketimi sabitse kardiyak debi yarıya düşer."},{"id":2409,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Valsalva manevrasının devam eden ıkınma fazında intratorasik basınç yüksek, venöz dönüş ve atım hacmi azalmıştır. Arter basıncındaki düşüşe karşı beklenen refleks yanıt hangisidir?","options":["Bradikardi ve vazodilatasyon","Vagal tonus artışı","Renin salınımının hemen baskılanması","Venöz kapasitans artışı","Taşikardi ve periferik vazokonstriksiyon"],"correct":4,"exp":"Valsalva faz II'nin geç bölümünde azalan basınç barorefleksle sempatik aktiviteyi artırır; taşikardi ve vazokonstriksiyon basıncı kısmen toparlar."},{"id":2410,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Tam atriyoventriküler blokta atriyum 75/dakika, ventrikül 32/dakika hızla bağımsız çalışıyor. Ventrikül kaçış ritminin yavaş olmasını en iyi açıklayan özellik hangisidir?","options":["Purkinje liflerinde otomatisite olmaması","Ventrikülün vagal innervasyonunun fazla olması","AV düğümünün atriyumu hızlandırması","Distal odaklarda daha düşük faz 4 depolarizasyon eğimi","Ventrikül miyositlerinin sürekli refrakter kalması"],"correct":3,"exp":"İletim sisteminde intrinsik pacemaker hızı SA noddan distale doğru azalır. His-Purkinje kaçış odaklarının spontan faz 4 depolarizasyonu daha yavaştır."},{"id":2411,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Uzun süreli hipertansiyonda sol ventrikül duvarı kalınlaşırken boşluk yarıçapı başlangıçta değişmeden kalıyor. Laplace ilişkisine göre bu adaptasyon duvar gerilimini nasıl etkiler?","options":["Duvar kalınlığından bağımsız olarak artırır","Duvar kalınlığı arttığı için azaltır","Yarıçap değişmediği için etkilemez","Yalnız kalp hızıyla belirlenir","İntraventriküler basıncı sıfırlar"],"correct":1,"exp":"Küresel modele göre duvar gerilimi basınç ve yarıçapla artar, duvar kalınlığıyla azalır. Konsantrik hipertrofi basınç yükünde gerilimi normalize etmeye çalışan adaptasyondur."},{"id":2412,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Hacim yüklenmesi sonrası atriyal gerilimi artan hastada natriürez, afferent arteriol genişlemesi ve renin-aldosteron baskılanması bekleniyor. Bu yanıtın temel hormonu aşağıdakilerden hangisidir?","options":["Vazopressin","Anjiyotensin II","Aldosteron","Endotelin","Atriyal natriüretik peptit"],"correct":4,"exp":"ANP atriyal miyositlerden gerilmeyle salınır; cGMP üzerinden natriürez ve vazodilatasyon yapar, renin-aldosteron eksenini baskılar."},{"id":2413,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Mitral yetersizlikli hastada pulmoner arter kateteriyle ölçülen kama basıncı ve V dalgaları belirgin yüksektir. Pulmoner kapiller kama basıncı en yakın olarak hangi basıncı yansıtır?","options":["Sağ atriyum basıncı","Pulmoner arter sistolik basıncı","Sağ ventrikül diyastol sonu basıncı","Aort diyastolik basıncı","Sol atriyum basıncı"],"correct":4,"exp":"Balonla küçük pulmoner arter dalı oklüde edildiğinde akımsız kan sütunu pulmoner ven ve sol atriyum basıncına uzanır. Mitral yetersizlikte dev V dalgaları görülebilir."},{"id":2414,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sıcak ortamda uzun süre hareketsiz ayakta kalan kişide cilt vazodilatasyonu ve bacak venlerinde göllenme sonrası senkop gelişiyor. Bilinç kaybından önceki temel hemodinamik değişiklik hangisidir?","options":["Venöz dönüş ve atım hacminde artış","Sistemik vasküler dirençte belirgin artış","Sol ventrikül afterloadunda artış","Venöz dönüş, preload ve kardiyak debide azalma","Pulmoner kapiller basınçta artış"],"correct":3,"exp":"Venöz göllenme merkezi kan hacmini, venöz dönüşü ve atım hacmini azaltır. Cilt vazodilatasyonu da direnci düşürür; yetersiz refleks telafi serebral perfüzyonu azaltır."},{"id":2415,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kalp yetmezliğinde venöz basınç artışı alt ekstremite ödemine yol açıyor. Sistemik kapillerde net filtrasyonu doğrudan artıran Starling kuvveti hangisidir?","options":["Plazma kolloid ozmotik basıncı","İnterstisyel hidrostatik basınç","Kapiller hidrostatik basınç","Lenfatik pompa aktivitesi","İnterstisyel kolloid basıncının azalması"],"correct":2,"exp":"Venöz basınç kapiller hidrostatik basınca yansır ve sıvıyı interstisyuma iten kuvveti artırır. Lenf akımı başlangıçta artarak ödemi sınırlamaya çalışır."},{"id":2416,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Hipertrofik kardiyomiyopatili hasta atriyal fibrilasyon başlayınca dispnesi belirgin artıyor. Sert ve yavaş gevşeyen sol ventrikülde atriyal sistol kaybının daha ağır tolere edilmesinin nedeni aşağıdakilerden hangisidir?","options":["Atriyal sistolün afterloadu artırması","Geç diyastolik dolumun atriyal katkıya daha bağımlı olması","Mitral kapağın sürekli açık kalması","Ventrikülün erken diyastolde aşırı dolması","Atriyal sistolün koroner akımı durdurması"],"correct":1,"exp":"Diyastolik disfonksiyonda pasif erken dolum kısıtlıdır; atriyal kick ventrikül dolumuna daha büyük katkı sağlar. Atrial fibrilasyon bu katkıyı ve diyastol süresini azaltır."},{"id":2417,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Sağlıklı kişide son öğünden sekiz saat sonra insülin azalıyor, glukagon artıyor. Karaciğerin kan glukozunu korumak için ilk kullandığı başlıca kaynak hangisidir?","options":["Yağ dokusunda lipogenez","Kas glikojeninin kana doğrudan verilmesi","Karaciğerde ketonların glukoza çevrilmesi","Karaciğer glikojenolizi","Böbrekte glukoz atılımı"],"correct":3,"exp":"Kısa açlıkta karaciğer glikojenolizi baskındır. Açlık uzadıkça glukoneogenez artar; kas glikojeni glukoz-6-fosfataz olmadığı için kana serbest glukoz veremez."},{"id":2418,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"İnsülin enjeksiyonundan dakikalar sonra iskelet kasında glukoz alımı artıyor; yeni protein sentezi için süre geçmemiştir. Hızlı yanıtı sağlayan olay hangisidir?","options":["GLUT2 sentezinin artması","GLUT4'ün plazma membranına taşınması","SGLT1'in sodyumdan bağımsız çalışması","Glukoneogenezin artması","Glikojen fosforilazın aktive olması"],"correct":1,"exp":"İnsülin reseptörü-PI3K-Akt sinyali kas ve yağ hücrelerinde hazır GLUT4 veziküllerini hızla membrana taşır. Etki protein sentezinden önce başlar."},{"id":2419,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Primer hiperparatiroidili hastada hiperkalsemiye hipofosfatemi eşlik ediyor. Parathormonun proksimal tübüldeki etkisi aşağıdakilerden hangisidir?","options":["Fosfat sekresyonunu azaltmak","Na-K-ATPaz aktivitesini baskılamak","Proksimal tübülde fosfat geri emiliminin azalması","Distal tübülde fosfat emilimini artırmak","Glomerüler fosfat filtrasyonunu azaltmak"],"correct":2,"exp":"PTH proksimal tübül apikal Na-fosfat kotransporterlerini içselleştirir ve fosfat geri emilimini azaltır. Böylece fosfatüri ve hipofosfatemi gelişir."},{"id":2420,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"D vitamini eksikliği olan çocukta kalsiyum düşük-normal, fosfor düşük ve PTH yüksektir. Kalsitriolün bağırsakta mineralizasyonu destekleyen temel etkisi hangisidir?","options":["Kalsiyum ve fosfat sekresyonunu artırmak","Yalnız magnezyum emilimini engellemek","Safra asidi geri emilimini azaltmak","Kalsiyum ve fosfat emilimini artırmak","Pankreas lipazını baskılamak"],"correct":3,"exp":"Kalsitriol enterositte kalsiyum taşıma proteinlerini ve fosfat emilimini artırır. Eksiklikte sekonder hiperparatiroidi fosfat kaybını ağırlaştırır ve kemik mineralizasyonu bozulur."},{"id":2421,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Vardiyalı çalışmayan sağlıklı kişide kortizol sabah uyanmadan önce yükselir, gece yarısında düşer. Bu sirkadiyen salınımı taşıyan temel eksen hangisidir?","options":["TRH-TSH-tiroid","GnRH-LH-gonad","CRH-ACTH-kortizol","GHRH-prolaktin","Renin-aldosteron"],"correct":2,"exp":"Suprakiazmatik çekirdek ritmi hipotalamik CRH, hipofizer ACTH ve adrenal kortizol eksenine aktarır. Stres bu ritmin üzerine ek ACTH-kortizol yanıtı bindirebilir."},{"id":2422,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Primer hipotiroidide serbest T4 düşerken TSH belirgin yükseliyor. Bu laboratuvar örüntüsünün temel geri bildirim açıklaması hangisidir?","options":["T4'ün hipofizi daha güçlü baskılaması","TSH reseptörünün sürekli uyarılması","TRH'nin tamamen kaybolması","Hipofiz nekrozu","Negatif geri bildirimin azalması"],"correct":4,"exp":"Düşük T4, hipotalamus ve hipofizde negatif geri bildirimi azaltır; TRH ve TSH yükselir. Santral hipotiroidide TSH düşük veya uygunsuz normal olur."},{"id":2423,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Doğumda masif kanama geçiren kadında hipotansiyon sonrası süt gelmiyor; diğer ön hipofiz hormonlarında da eksiklik vardır. Süt sentezini başlatıp sürdüren hormon hangisidir?","options":["Prolaktin","Oksitosin","Östrojen","Progesteron","İnsan plasental laktojeni"],"correct":0,"exp":"Prolaktin meme alveol epitelinde süt sentezini uyarır. Oksitosin mioepitelyal hücreleri kasarak süt ejeksiyonunu sağlar; Sheehan sendromunda agalakti erken bulgu olabilir."},{"id":2424,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":5,"q":"Normal ovaryan siklusta dominant folikül büyürken östradiol giderek yükseliyor. Ovulasyonu tetikleyen LH pikinin oluşması için hangi hormonal koşul gerekir?","options":["Östradiolün hipofizde pozitif geri bildirimi","Progesteronun erken foliküler fazda yükselmesi","İnhibin B'nin tamamen kaybolması","FSH'nin sürekli baskılanması","Prolaktinin pulsatil artışı"],"correct":0,"exp":"Orta siklusta yüksek östradiol yaklaşık 36 saat sürünce geri bildirim pozitifleşir ve GnRH-LH yanıtı güçlenir. LH piki ovulasyon ve luteinizasyonu başlatır."},{"id":2425,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"İki hücre-iki gonadotropin modelinde teka hücresi androjen üretirken granüloza hücresi bu androjenleri östradiole çevirir. Granüloza aromatazını uyaran hormon hangisidir?","options":["LH","hCG","FSH","ACTH","Prolaktin"],"correct":2,"exp":"LH teka interna hücresinde androjen sentezini, FSH granüloza hücresinde aromatazı uyarır. Androjen granülozada östradiole çevrilir."},{"id":2426,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Erken gebelikte plasenta yeterli progesteron üretimini devralmadan önce korpus luteumun devamı gereklidir. Korpus luteumu kurtaran trofoblast hormonu hangisidir?","options":["İnhibin A","İnsan koryonik gonadotropini","İnsan plasental laktojeni","Relaksin","Oksitosin"],"correct":1,"exp":"Sinsityotrofoblast hCG salgılar; LH reseptörü üzerinden korpus luteumu sürdürür ve erken progesteron üretimini korur."},{"id":2427,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Primer adrenal yetmezlikli hastada hipotansiyon, hiperkalemi ve tuz isteği vardır. Eksik olan mineralokortikoidin kortikal toplayıcı kanaldaki normal etkisi aşağıdakilerden hangisidir?","options":["ENaC kanallarını baskılaması","Potasyum sekresyonunu azaltması","Suyu aquaporinden bağımsız geri emmesi","Sodyum emilimini artırırken potasyum ve hidrojen sekresyonunu artırması","Üre geçirgenliğini azaltması"],"correct":3,"exp":"Aldosteron principal hücrede ENaC ve Na-K-ATPazı artırır; sodyum emilir, ROMK üzerinden potasyum atılır. Alfa-interkale hücrede hidrojen sekresyonunu da artırır."},{"id":2428,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Santral diabetes insipiduslu hastada desmopressin sonrası idrar osmolalitesi belirgin yükseliyor. Vazopressinin toplayıcı kanalda su geçirgenliğini artıran mekanizması aşağıdakilerden hangisidir?","options":["V2-cAMP yoluyla aquaporin-2'nin apikal membrana yerleştirilmesi","V1 reseptörüyle ENaC'nin kapatılması","Aldosteron reseptörüyle aquaporin-1 sentezi","Na-glukoz kotransportunun artırılması","Henle çıkan kalın kolunda su kanalı açılması"],"correct":0,"exp":"ADH bazolateral V2 reseptörü-Gs-cAMP-PKA yoluyla AQP2 veziküllerini apikal membrana taşır. Su AQP2'den hücreye, AQP3/4'ten interstisyuma geçer."},{"id":2429,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Küçük hücreli akciğer kanserli hastada sodyum 118 mEq/L, serum ozmolalitesi düşük; idrar uygunsuz yoğun ve idrar sodyumu yüksektir. Övolemik hiponatreminin temel su dengesi kusuru hangisidir?","options":["Primer sodyum fazlalığı","Glomerüler filtrasyonun sıfırlanması","Elektrolitsiz su atılımının azalması","Zorunlu hipertonik idrar kaybı","Aldosteron fazlalığı"],"correct":2,"exp":"Uygunsuz ADH toplayıcı kanal su geçirgenliğini artırır ve serbest su atılımını azaltır. Hafif hacim artışı natriürezi tetiklediği için hasta klinik olarak övolemik görünür."},{"id":2430,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Elli iki yaşındaki kadında 14 aydır amenore ve sıcak basması vardır. Primer folikül tükenmesine bağlı beklenen hormon örüntüsü hangisidir?","options":["FSH ve LH yüksek, östradiol düşük","FSH düşük, östradiol yüksek","FSH ve LH düşük, prolaktin yüksek","Progesteron sürekli yüksek","GnRH tamamen yok"],"correct":0,"exp":"Ovaryan folikül ve inhibin kaybı östradiolü azaltır, hipofizer negatif geri bildirimi kaldırır. Özellikle FSH belirgin yükselir."},{"id":2431,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Akromegalili hastada oral glukozla GH baskılanmıyor ve IGF-1 yüksektir. GH'nin büyüme ve anabolik etkilerinin önemli bölümünü taşıyan mediyatörün başlıca kaynağı hangisidir?","options":["Tiroid bezi","Adrenal medulla","Pankreas alfa hücresi","Karaciğerden salgılanan IGF-1","Böbrekten salgılanan renin"],"correct":3,"exp":"GH karaciğer ve yerel dokularda IGF-1 sentezini uyarır. IGF-1 kıkırdak, kemik ve yumuşak doku büyümesinin birçok uzun dönem etkisini aracılar."},{"id":2432,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":5,"q":"İnsülin reseptörüne bağlandıktan sonra reseptörün beta alt birimleri otofosforile oluyor ve IRS proteinleri üzerinden PI3K-Akt yolu aktive oluyor. Reseptör sınıfı hangisidir?","options":["G proteinine kenetli reseptör","Ligand kapılı iyon kanalı","Nükleer steroid reseptörü","Serin-treonin kinaz reseptörü","Reseptör tirozin kinaz"],"correct":4,"exp":"İnsülin reseptörü intrinsik tirozin kinaz aktivitesine sahip tetramerik reseptördür. Otofosforilasyon metabolik ve mitojenik sinyalleri başlatır."},{"id":2433,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Sağlıklı gebeliğin ikinci yarısında insan plasental laktojeni ve diğer hormonlar annenin periferik insülin duyarlılığını azaltır. Bu fizyolojik değişikliğin temel amacı aşağıdakilerden hangisidir?","options":["Glukozu fetoplasental dolaşım için erişilebilir tutması","Fetal glukoz geçişini durdurması","Anne keton üretimini baskılaması","Maternal yağ kullanımını engellemesi","Plasental aminoasit taşınmasını azaltması"],"correct":0,"exp":"Maternal insülin direnci glukozun fetüse ayrılmasını kolaylaştırır; anne enerji için lipolize daha fazla yönelir. Beta hücre telafisi yetersizse gestasyonel diyabet gelişir."},{"id":2434,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Tirotoksikozlu hastada kilo kaybı, ısı intoleransı, yüksek istirahat oksijen tüketimi ve taşikardi vardır. Bu bulgular tiroid hormonlarının hangi genel etkisini gösterir?","options":["Bazal metabolizma hızını azaltma","Mitokondri sayısını azaltma","Bazal metabolizma ve termogenezi artırma","Katekolamin duyarlılığını azaltma","Protein döngüsünü durdurma"],"correct":2,"exp":"Tiroid hormonu mitokondriyal aktiviteyi, oksijen tüketimini ve Na-K-ATPaz gibi enerji kullanan süreçleri artırır; beta-adrenerjik duyarlılığı güçlendirir."},{"id":2435,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Deniz düzeyinden 3.500 metreye hızla çıkan kişide PaO2 düşer düşmez ventilasyon artıyor. Bu saniyeler içindeki yanıtı başlatan reseptörler hangisidir?","options":["Medüller merkezi kemoreseptörler","Pulmoner gerim reseptörleri","J reseptörleri","Periferik kemoreseptörler","Üst hava yolu irritan reseptörleri"],"correct":3,"exp":"Periferik kemoreseptörler özellikle PaO2 yaklaşık 60 mmHg altına indiğinde hızla uyarılır. Merkezi kemoreseptörler doğrudan hipoksemiye değil BOS H+ değişimine yanıt verir."},{"id":2436,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Opioid aşırı dozunda PaCO2 yükselirken normalde ventilasyonu güçlü biçimde artıracak merkezi kemoreseptör sinyali baskılanıyor. Merkezi kemoreseptörlerin algıladığı temel değişiklik hangisidir?","options":["Arteriyel oksijen içeriğinin düşmesi","CO2'nin BOS'a geçmesiyle oluşan hidrojen iyonu artışı","Plazma bikarbonatının doğrudan reseptöre bağlanması","Karotis cisminde potasyum azalması","Akciğer geriminin azalması"],"correct":1,"exp":"CO2 kan-beyin bariyerini geçer ve BOS'ta karbonik asit üzerinden H+ oluşturur. Merkezi kemoreseptörler bu pH düşüşüne yanıt verir; opioidler beyin sapı yanıtını baskılar."},{"id":2437,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Dokuda oluşan CO2 eritrosite giriyor, karbonik anhidrazla dönüştürülüyor ve klor kayması eşliğinde plazmaya taşınıyor. CO2'nin kandaki en büyük fraksiyonu hangi biçimdedir?","options":["Çözünmüş CO2","Bikarbonat iyonu","Karbaminohemoglobin","Karbon monoksit","Karbonik asit"],"correct":1,"exp":"CO2'nin çoğu eritrositte bikarbonata çevrilir; HCO3− plazmaya çıkarken klor hücreye girer. Daha küçük bölümler çözünmüş veya proteinlere karbamino bağlı taşınır."},{"id":2438,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":5,"q":"Akut pulmoner embolide bazı alveoller iyi ventile edildiği hâlde kapiller kan akımı kesiliyor. Bu alveollerdeki ventilasyon fizyolojik olarak neye eklenir?","options":["Anatomik şanta","Düşük V/Q alanına","Alveoler ölü boşluğa","Rezidüel hacme","Difüzyon kapasitesine"],"correct":2,"exp":"Ventilasyon var ancak perfüzyon yoksa V/Q sonsuza yaklaşır ve alveoler ölü boşluk oluşur. Pulmoner emboli fizyolojik ölü boşluğu artırır."},{"id":2439,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":5,"q":"Lober pnömonide konsolide alveoller perfüze olmaya devam ediyor ancak hiç havalanmıyor. Yüksek akım oksijene yanıtın sınırlı olmasını açıklayan bozukluk hangisidir?","options":["İntrapulmoner sağdan sola şant","Saf difüzyon kısıtlılığı","Artmış ölü boşluk","Hipoventilasyonsuz düşük FiO2","Yalnız düşük kardiyak debi"],"correct":0,"exp":"Perfüze fakat ventile olmayan birimde V/Q=0'dır; venöz kan oksijenlenmeden sistemik dolaşıma karışır. Gerçek şant yüksek FiO2'ye diğer V/Q bozukluklarından daha az yanıt verir."},{"id":2440,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Sigara öykülü hastada FEV1 %42, FVC %78 ve FEV1/FVC %48 bulunuyor; ekspiratuvar akım eğrisi konkavdır. Bu spirometri paterni hangisidir?","options":["Normal varyant","Saf restriksiyon","Obstrüktif ventilatuvar bozukluk","Nöromüsküler hipoventilasyon","İzole difüzyon kusuru"],"correct":2,"exp":"FEV1'in FVC'ye göre orantısız azalması ve düşük oran obstrüksiyonu gösterir. Restriksiyon spirometriyle şüphe edilir, düşük total akciğer kapasitesiyle doğrulanır."},{"id":2441,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"İdiyopatik pulmoner fibrozisli hastada FVC ve total akciğer kapasitesi azalmış, FEV1/FVC normal-yüksek ve DLCO düşüktür. Patern hangisidir?","options":["Obstrüktif bozukluk","Üst hava yolu obstrüksiyonu","Restriktif ventilatuvar bozukluk","Normal spirometri","Yalnız hiperventilasyon"],"correct":2,"exp":"Düşük TLC restriksiyonu doğrular. Fibroziste elastik recoil artar, akciğer kompliyansı ve difüzyon kapasitesi azalır; FEV1/FVC korunur veya yükselir."},{"id":2442,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yirmi sekiz haftalık prematüre bebekte surfaktan eksikliği nedeniyle yaygın atelektazi gelişiyor. Surfaktanın normalde alveol stabilitesini sağlayan temel etkisi hangisidir?","options":["Yüzey gerilimini azaltıp kompliyansı artırmak","Alveol sıvı sekresyonunu artırmak","Pulmoner damar direncini artırmak","Mukus viskozitesini artırmak","Oksijen tüketimini durdurmak"],"correct":0,"exp":"Surfaktan hava-sıvı arayüzündeki yüzey gerilimini azaltır; özellikle küçük alveollerin kollapsını önler, kompliyansı yükseltir ve solunum işini azaltır."},{"id":2443,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Amfizemli hastada total akciğer kapasitesi artmış ancak DLCO düşüktür. Difüzyon azalmasının başlıca yapısal nedeni hangisidir?","options":["Alveol membranının kalınlaşması","Hemoglobin afinitesinin artması","Hava yolu mukusunun azalması","Plevral basıncın pozitifleşmesi","Alveol-kapiller yüzey alanının kaybı"],"correct":4,"exp":"Amfizem alveol duvar ve kapiller yatağı yıkar; gaz değişim yüzey alanı azalır. Fibroziste ise temel sorun membran kalınlığıdır."},{"id":2444,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Ateşi 39,5 °C olan ve egzersiz yapan kişide dokuda CO2 ile H+ artmıştır. Hemoglobinin dokuda oksijen bırakmasını kolaylaştıran eğri değişikliği hangisidir?","options":["Sola kayma ve P50 azalması","Sağa kayma ve P50 artması","Eğrinin tamamen düzleşmesi","Oksijen kapasitesinin değişmeden sola kayması","Fetal hemoglobin oluşumu"],"correct":1,"exp":"Isı, CO2, H+ ve 2,3-BPG artışı hemoglobin afinitesini azaltır; eğri sağa kayar, P50 yükselir ve dokuda boşalma kolaylaşır."},{"id":2445,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yüksek irtifaya çıkan kişide hipoksemiye bağlı hiperventilasyon ve akut respiratuvar alkaloz gelişiyor. Birkaç günlük renal uyum hangisidir?","options":["Bikarbonat geri emilimini artırmak","Hidrojen atılımını artırmak","Amonyum atılımını artırmak","Klorür atılımını tamamen durdurmak","Bikarbonat atılımını artırmak"],"correct":4,"exp":"Kronik respiratuvar alkalozda böbrek HCO3− geri emilimini ve yeni bikarbonat üretimini azaltır; bikarbonat atılımı artar. BOS pH'sının normale yaklaşması ventilasyonun sürmesini kolaylaştırır."},{"id":2446,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Plasentada maternal ve fetal hemoglobin aynı PO2 ortamında karşılaştırılıyor. HbF'nin 2,3-BPG'ye daha az bağlanmasının eğriye etkisi hangisidir?","options":["Sağa kayma ve düşük afinite","P50 artışı","Maksimum satürasyonun sıfırlanması","Bohr etkisinin kaybolması","Sola kayma ve yüksek oksijen afinitesi"],"correct":4,"exp":"HbF'nin gamma zincirleri 2,3-BPG'ye zayıf bağlanır; oksijen afinitesi yüksektir ve eğri sola kayar. Bu, plasentada maternal kandan oksijen alımını kolaylaştırır."},{"id":2447,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":5,"q":"Uzun süredir hiperkapnik KOAH'ı olan hastada renal bikarbonat tutulumu BOS pH'sını kısmen düzeltmiştir. Ventilasyonun sürdürülmesinde göreceli önemi artan uyarı aşağıdakilerden hangisidir?","options":["Yüksek arteriyel pH","Artmış hemoglobin miktarı","Düşük venöz basınç","Periferik kemoreseptörlerin algıladığı hipoksemi","Akciğer kompliyansının artması"],"correct":3,"exp":"Kronik hiperkapnide merkezi CO2 yanıtı kısmen adapte olur. Düşük PaO2'ye yanıt veren karotis cisimlerinin katkısı göreceli artar; yine de oksijen gerekli hastada kesilmez, kontrollü verilir."},{"id":2448,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Kardiyojenik pulmoner ödemde interstisyel ve alveoler sıvı artıyor; basınç-hacim eğrisi sağa ve aşağı kayıyor. Azalan mekanik özellik hangisidir?","options":["Hava yolu direnci","Elastik recoil","Fonksiyonel rezidüel kapasite tek başına","Plevral negatiflik","Akciğer kompliyansı"],"correct":4,"exp":"Ödemli akciğer aynı basınç değişikliğinde daha az hacim değiştirir; kompliyans azalır ve solunum işi artar."},{"id":2449,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Travmatik pnömotoraksta plevra boşluğu atmosferle bağlantı kurunca akciğer kollabe oluyor. Normalde transpulmoner basıncı oluşturarak akciğeri açık tutan özellik aşağıdakilerden hangisidir?","options":["İntraplevral basıncın alveol basıncından daha negatif olması","İntraplevral basıncın sürekli pozitif olması","Alveol basıncının atmosfer basıncına eşit olması","Plevrada hava bulunması","Göğüs duvarının içe recoil yapması"],"correct":0,"exp":"Akciğer içe, göğüs duvarı dışa recoil yapar; kapalı plevrada negatif basınç oluşur. Pnömotoraksta bu gradyan kaybolur ve akciğer elastik recoil ile kollabe olur."},{"id":2450,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Mekanik ventilasyonda aşırı tidal hacimle akciğer gerimi artınca inspirasyonun sonlanmasına katkı veren vagal refleks aşağıdakilerden hangisidir?","options":["Karotis cismi refleksi","Hering-Breuer inflasyon refleksi","Baroreseptör refleksi","Cushing refleksi","Bainbridge refleksi"],"correct":1,"exp":"Yavaş adapte olan pulmoner gerim reseptörleri aşırı inflasyonda vagus üzerinden inspiratuvar nöronları inhibe eder. Erişkinde sakin solunumda sınırlı, büyük hacimlerde daha belirgindir."},{"id":2451,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Patellar tendona vurulduğunda kuadriseps kasılırken hamstring kaslarında gevşeme oluyor. Kuadriseps kasılmasını başlatan afferent lif ve spinal bağlantı hangisidir?","options":["Golgi tendon organından Ib lif; inhibitör internöron üzerinden alfa motor nöron","Kas iğciğinden Ia lif; alfa motor nöronla monosaptik bağlantı","Serbest sinir ucundan C lifi; polisinaptik fleksör devre","Kas iğciğinden II lif; yalnız gama motor nöronla bağlantı","Eklem reseptöründen A-delta lifi; sempatik preganglionik nöronla bağlantı"],"correct":1,"exp":"Tendon vuruşu kası kısa süreli gerer; kas iğciğinin primer ucundan çıkan Ia afferenti aynı kasın alfa motor nöronunu monosaptik olarak uyarır. Antagonist gevşemesi ise inhibitör internöron aracılıdır."},{"id":2452,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Akut internal kapsül infarktından haftalar sonra karşı ekstremitelerde spastisite, klonus ve hiperrefleksi gelişiyor. Bu bulguların temel fizyolojik açıklaması hangisidir?","options":["Kas iğciği primer sonlanmalarının dejenerasyonu","Alfa motor nöronların denervasyonu","Spinal refleks devreleri üzerindeki inen inhibitör etkinin azalması","Nöromüsküler kavşakta asetilkolin veziküllerinin tükenmesi","Golgi tendon organı afferentlerinin seçici kaybı"],"correct":2,"exp":"Üst motor nöron hasarı inen inhibitör kontrolü azaltır; gerilme refleksinin kazancı artar ve spastisite, klonus, hiperrefleksi gelişir. Alfa motor nöron kaybı ise gevşek paraliziye yol açar."},{"id":2453,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Peroneal sinir kesisi sonrası ön tibial kasında kısa sürede fasikülasyon, fibrilasyon potansiyelleri ve belirgin atrofi gelişiyor. Bu hızlı atrofiye en fazla katkıda bulunan değişiklik hangisidir?","options":["Kas iğciği duyarlılığının artması","Kortikospinal uyarının seçici azalması","Antagonist kastan resiprokal inhibisyonun artması","Motor innervasyonun ve nöral trofik etkinin kaybı","Kas liflerinde asetilkolin reseptörü sayısının azalması"],"correct":3,"exp":"Alt motor nöron lezyonunda kas doğrudan denervasyona uğrar; nöral trofik destek kaybı ve kullanılmama hızlı, belirgin atrofiye neden olur. Denervasyonda ekstrasınaptik asetilkolin reseptörleri azalmaz, yaygınlaşır."},{"id":2454,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Sağ hemikord lezyonu olan hastada lezyonun birkaç segment altından başlayarak sol tarafta ağrı ve sıcaklık duyusu kayboluyor. Bu dağılım hangi yolun çaprazlaşma özelliğiyle açıklanır?","options":["Dorsal kolon liflerinin giriş segmentinde arka komisürden geçmesi","Spinotalamik liflerin omuriliğe girdikten sonra ön beyaz komisürden karşıya geçmesi","Kortikospinal liflerin spinal segmentte iki kez çaprazlaşması","Spinosebellar liflerin yalnız medullada çaprazlaşması","Medial lemniskus liflerinin talamusta çaprazlaşması"],"correct":1,"exp":"Ağrı-sıcaklık lifleri Lissauer traktında birkaç segment ilerleyebilir, arka boynuzda sinaps yaptıktan sonra ön beyaz komisürden çaprazlanır. Bu nedenle hemikord lezyonunda karşı taraftaki kayıp birkaç segment aşağıdan başlayabilir."},{"id":2455,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"B12 eksikliğinde alt ekstremitelerde vibrasyon ve pozisyon duyusu kaybolan hastada dorsal kolon lifleri omurilik boyunca ipsilateral yükselir. İkinci nöronların aksonları nerede çaprazlaşır?","options":["Medullada internal arkuat lifler olarak","Giriş yaptıkları spinal segmentte ön beyaz komisürde","Pons düzeyinde trapezoid cisimde","Orta beyinde superior serebellar pedinkülde","Talamustan kortekse çıkarken internal kapsülde"],"correct":0,"exp":"Birinci nöronlar fasciculus gracilis/cuneatus içinde ipsilateral medullaya ulaşır. Nükleus gracilis ve cuneatus'ta sinaps yapan ikinci nöronlar internal arkuat lifler olarak çaprazlaşıp medial lemniskusu oluşturur."},{"id":2456,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Enfekte, asidik bir dokuda lidokain infiltrasyonuna rağmen yeterli analjezi sağlanamıyor. İlacın hedefi ve düşük etkinliğin temel nedeni birlikte hangisidir?","options":["Ligand kapılı klor kanalı; alkalozda iyonize fraksiyonun artması","L tipi kalsiyum kanalı; asidozda kanal sayısının azalması","Voltaj kapılı sodyum kanalı; asidozda yüksüz fraksiyonun azalması","Nikotinik reseptör; asidozda asetilkolinesterazın artması","ATP duyarlı potasyum kanalı; asidozda albumin bağlanmasının kaybolması"],"correct":2,"exp":"Lokal anestezikler voltaj kapılı Na kanallarını hücre içinden bloke eder. Asidik ortamda ilacın iyonize fraksiyonu artar; membranı geçebilen yüksüz fraksiyon azaldığı için etki zayıflar."},{"id":2457,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Demiyelinizan bir periferik nöropatide internodal membran direnci azalırken kapasitans artıyor. İletim yavaşlamasını en iyi açıklayan değişiklik aşağıdakilerden hangisidir?","options":["Aksiyon potansiyelinin dendritlerde oluşması","Sinaptik gecikmenin ortadan kalkması","Akson çapının akut olarak artması","Nörotransmitter sentezinin durması","Lokal akımın bir sonraki Ranvier düğümüne güvenle ulaşamaması"],"correct":4,"exp":"Miyelin membran direncini artırıp kapasitansı azaltarak lokal akımın uzak düğüme hızla yayılmasını sağlar. Demyelinizasyon akım kaçağına, iletim yavaşlamasına ve ağırsa iletim bloğuna yol açar."},{"id":2458,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Botulinum toksini maruziyetinden sonra presinaptik uçta aksiyon potansiyeli ve kalsiyum girişi korunmasına rağmen asetilkolin salınamıyor. Toksinin doğrudan bozduğu olay hangisidir?","options":["Postsinaptik nikotinik reseptörün kanal açması","Asetilkolinin kolin ve asetata hidrolizi","SNARE proteinleri aracılı vezikül-membran füzyonu","Akson boyunca saltatuvar iletim","Kas hücresinde kalsiyumun troponine bağlanması"],"correct":2,"exp":"Presinaptik Ca girişi sinaptotagmin ve SNARE kompleksi üzerinden vezikül füzyonunu tetikler. Botulinum toksini SNARE proteinlerini parçalayarak asetilkolin ekzositozunu engeller."},{"id":2459,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Bir inhibitör sinapsta GABA-A reseptörleri açıldığında membran potansiyeli değişmeden eşik altı eksitatör akımın etkisi azalıyor. Bu durum en iyi hangi mekanizmayla açıklanır?","options":["Klor iletkenliğinin artmasına bağlı şant inhibisyonu","Sodyum denge potansiyelinin pozitifleşmesi","Voltaj kapılı kalsiyum kanallarının kalıcı açılması","Potasyum denge potansiyelinin sıfıra yaklaşması","Na/K-ATPazın geri dönüşsüz inhibisyonu"],"correct":0,"exp":"GABA-A ile Cl iletkenliğinin artması membranı Cl denge potansiyeline sabitler ve eksitatör akımı şantlar. İnhibisyon için her zaman belirgin hiperpolarizasyon gerekmez."},{"id":2460,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Başını hızla sağa çeviren kişinin gözleri hedef üzerinde kalmak için sola deviye oluyor. Sağ horizontal semisirküler kanal uyarısından sonra bu yanıtı oluşturan refleks hangisidir?","options":["Okülosefalik yanıtın kortikal komponenti","Pupiller ışık refleksi","Optokinetik nistagmus","Vestibülo-oküler refleks","Yakına uyum refleksi"],"correct":3,"exp":"Vestibülo-oküler refleks baş hareketini vestibüler çekirdekler ve medial longitudinal fasikül aracılığıyla eşit-zıt göz hareketine çevirir; görüntüyü foveada sabit tutar."},{"id":2461,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Koklear dış saçlı hücrelerin stereosilyaları en uzun stereosilyaya doğru eğiliyor. Endolenfin iyon bileşimi dikkate alındığında ilk elektriksel olay hangisidir?","options":["Klorun hücre dışına çıkması","Perilenften sodyumun stereosilyaya girmesi","Bazal membrandan potasyumun hücreye girmesi","Mekanotransdüksiyon kanallarından potasyum girişiyle depolarizasyon","Kalsiyumun hücreden aktif olarak atılmasıyla depolarizasyon"],"correct":3,"exp":"Endolenf K'dan zengin ve endokoklear potansiyel nedeniyle pozitiftir. Tip-link kanalları açıldığında K saçlı hücreye girer, depolarizasyon ve bazalde nörotransmitter salınımı gelişir."},{"id":2462,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Işık alan bir rod hücresinde transdusin-fosfodiesteraz yolu etkinleşiyor. Bunun membran potansiyeli ve glutamat salınımına etkisi hangisidir?","options":["Depolarizasyon; glutamat artışı","Depolarizasyon; glutamat azalması","Membran potansiyeli değişmez; glutamat artışı","Aksiyon potansiyeli oluşur; glutamat kesilir","Hiperpolarizasyon; glutamat azalması"],"correct":4,"exp":"Işık cGMP'yi azaltır; cGMP kapılı katyon kanalları kapanır, fotoreseptör hiperpolarize olur ve glutamat salınımı azalır. Fotoreseptörler aksiyon potansiyeli değil dereceli potansiyel üretir."},{"id":2463,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Uzağa bakarken yakındaki yazıya odaklanan sağlıklı kişide lensin kırıcılığı artıyor. Bu değişikliğin doğru sıralaması hangisidir?","options":["Sempatik uyarı → siliyer kas gevşemesi → zonül geriliminin azalması","Parasempatik uyarı → siliyer kas kasılması → zonül geriliminin azalması","Somatik uyarı → iris dilatatör kasılması → lensin düzleşmesi","Parasempatik uyarı → siliyer kas gevşemesi → zonül geriliminin artması","Sempatik uyarı → sfinkter pupilla kasılması → lensin kalınlaşması"],"correct":1,"exp":"Edinger-Westphal kaynaklı parasempatik uyarı siliyer kası kasar. Siliyer halkanın çapı küçülür, zonüller gevşer ve elastik lens daha küresel hâle gelerek yakın odağı sağlar."},{"id":2464,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":5,"q":"Parkinson hastalığında nigrostriatal dopamin azalması direkt ve indirekt yolları farklı etkiliyor. Hareket azalmasına yol açan net bazal ganglion çıktısı aşağıdakilerden hangisidir?","options":["Globus pallidus internus/substantia nigra reticulata kaynaklı talamik inhibisyonun artması","Talamusun motor korteksi inhibisyonunun azalması","Subtalamik çekirdeğin globus pallidus internusu daha az uyarması","Striatumdan globus pallidus internusa direkt inhibisyonun artması","Serebellar çekirdeklerden vestibüler çekirdeğe çıkışın azalması"],"correct":0,"exp":"Dopamin kaybı D1-dirençli direkt yolu zayıflatır, D2 üzerinden indirekt yolu güçlendirir. GPi/SNr'nin talamusa inhibitör çıkışı artar ve talamokortikal motor uyarı azalır."},{"id":2465,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Sağ serebellar hemisfer lezyonu olan hastada sağ kolla parmak-burun testinde hedefi aşma ve intansiyon tremoru var; kas gücü tamdır. Serebellumun hangi işlevi bozulmuştur?","options":["Alt motor nöronlara primer kuvvet komutu üretme","Somatik duyuyu talamusa taşıma","Bazal kas tonusunu yalnız gama motor nöronla oluşturma","Planlanan hareket ile gerçekleşen hareketi karşılaştırıp hata düzeltme","İstemli hareketi kortikospinal traktla başlatma"],"correct":3,"exp":"Serebellum motor plan ile proprioseptif geri bildirimi karşılaştırır; zamanlama ve çevrim içi hata düzeltmesi yapar. Lezyon ipsilateral dismetri ve intansiyon tremoru yapar, primer paralizi yapmaz."},{"id":2466,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Uykuda bağıran ve rüyasındaki hareketleri yatakta uygulayan yaşlı erkekte REM uykusu davranış bozukluğu düşünülüyor. Normal REM atonisinin kaybı en çok hangi yolun bozulmasıyla ilişkilidir?","options":["Retinadan suprachiasmatik çekirdeğe giden yol","Locus coeruleus'tan kortekse noradrenerjik çıkış","Pontomedüller merkezlerden spinal motor nöronlara inen inhibitör yol","Dorsal kolon-medial lemniskus yolu","Hipotalamustan nörohipofize giden aksonlar"],"correct":2,"exp":"REM'de pontomedüller devreler spinal alfa motor nöronları glisin/GABA aracılığıyla inhibe eder. Bu atoni bozulursa kişi rüya içeriğini motor davranışa dönüştürebilir."},{"id":2467,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Ayak tabanına ağrılı uyaran verildiğinde aynı tarafta fleksiyon, karşı tarafta ekstansiyon gelişiyor. Aynı ekstremitedeki antagonist ekstansörlerin baskılanması hangi spinal düzenekle olur?","options":["Renshaw hücresiyle rekürren eksitasyon","Postsinaptik fasilitasyon","Presinaptik oklüzyon","Gamma motor nöron inhibisyonu olmadan alfa blokajı","İnhibitör internöron aracılı resiprokal inhibisyon"],"correct":4,"exp":"Fleksör çekilme refleksinde agonist fleksörler aktive olurken inhibitör internöronlar aynı taraftaki ekstansör alfa motor nöronlarını baskılar. Karşı tarafta ise çapraz ekstansör refleks postürü destekler."},{"id":2468,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"İstemli kasılmada alfa motor nöronlarla birlikte gama motor nöronların da etkinleşmesi hangi sonucu sağlar?","options":["Golgi tendon organının gerilime duyarsızlaşması","Kas kısalırken kas iğciğinin gerginliğini ve duyarlılığını koruması","Nöromüsküler kavşakta asetilkolinin daha hızlı yıkılması","Antagonist kasın alfa motor nöronunun doğrudan uyarılması","Ekstrafüzal liflerin miyozin ATPazının baskılanması"],"correct":1,"exp":"Alfa-gama koaktivasyonunda ekstrafüzal lifler kısalırken gama nöronlar intrafüzal uçları kasar; iğciğin santral duysal bölgesi gevşemez ve uzunluk değişimini bildirmeyi sürdürür."},{"id":2469,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":5,"q":"Bir kasın tendonu aşırı gerildiğinde aynı kasın alfa motor nöronları inhibitör internöron üzerinden baskılanıyor. Bu ters miyotatik refleksin reseptör ve afferenti hangisidir?","options":["Kas iğciği—Ia","Golgi tendon organı—Ib","Pacinian cisimciği—A-beta","Serbest sinir ucu—C","Ruffini sonlanması—II"],"correct":1,"exp":"Golgi tendon organı seri yerleşimlidir ve kas gerilimini Ib liflerle iletir. Spinal inhibitör internöron üzerinden aynı kasın alfa motor nöron aktivitesini azaltabilir."},{"id":2470,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Organofosfat maruziyetli tarım işçisinde miyozis, bronkore, bradikardi ve fasikülasyon vardır. Atropin sonrası sekresyonlar azalmasına rağmen kas güçsüzlüğü sürüyor. Sinaptik aralıkta biriken mediyatör hangisidir?","options":["Asetilkolin","Dopamin","GABA","Glutamat","Serotonin"],"correct":0,"exp":"Asetilkolinesteraz inhibisyonu muskarinik ve nikotinik sinapslarda asetilkolin birikimine yol açar. Atropin muskarinik bulguları düzeltir; nikotinik güçsüzlük için enzim reaktivasyonu amacıyla erken pralidoksim gerekir."},{"id":2471,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Gastroenterit nedeniyle hipovolemik olan ve ibuprofen kullanan yaşlı hastada oligüri ile kreatinin artışı gelişiyor. Böbrek kan akımı düşükken GFR'yi koruyan prostaglandinlerin baskılanması hangi değişikliğe yol açmıştır?","options":["Efferent arteriol dilatasyonu","Efferent arteriol vazokonstriksiyonu","Mezangial hücre gevşemesi","Afferent arteriol vazokonstriksiyonu","Toplayıcı kanalda su geçirgenliği artışı"],"correct":3,"exp":"Düşük efektif hacimde lokal prostaglandinler afferent dilatasyonla glomerüler perfüzyonu destekler. NSAİİ kullanımı bu yanıtı kaldırıp afferent vazokonstriksiyon ve prerenal GFR düşüşü oluşturabilir."},{"id":2472,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Bilateral renal arter stenozu olan hastaya ACE inhibitörü başlanınca kreatinin belirgin yükseliyor. İlaç öncesinde anjiyotensin II'nin GFR'yi koruyan etkisi hangisidir?","options":["Afferent arteriolü seçici dilate etmesi","Mezangial hücreleri gevşetip filtrasyon yüzeyini artırması","Efferent arteriolü daraltarak glomerüler kapiller basıncı sürdürmesi","Proksimal tübülde kreatinin sekresyonunu engellemesi","Bowman boşluğu hidrostatik basıncını azaltması"],"correct":2,"exp":"Renal perfüzyon azaldığında anjiyotensin II özellikle efferent arteriolü daraltır ve intraglomerüler basıncı korur. ACE inhibisyonu efferent dilatasyon yaparak iki taraflı stenozda GFR'yi belirgin düşürebilir."},{"id":2473,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Renal perfüzyonu azalan hastada makula densaya ulaşan NaCl azalıyor. Tubuloglomerüler geri bildirimde beklenen erken yanıt hangisidir?","options":["Afferent vazokonstriksiyon ve renin baskılanması","Efferent dilatasyon ve aldosteron baskılanması","Afferent dilatasyon ve renin salınımı","Mezangial kasılma ve filtrasyon yüzeyinin azalması","Toplayıcı kanalda ENaC'nin doğrudan inhibisyonu"],"correct":2,"exp":"Düşük NaCl, makula densada ATP/adenozin sinyalini azaltıp prostaglandin-NO yolunu destekler; afferent dilatasyon ve renin salınımı gelişir. Amaç distal NaCl teslimini ve GFR'yi düzeltmektir."},{"id":2474,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Bir deney maddesi glomerülden serbestçe filtreleniyor; tübüllerde ne geri emiliyor ne de sekrete ediliyor. Plazma düzeyi sabitken idrar konsantrasyonu ve akımı ölçülüyor. Bu maddenin klirensi neyi verir?","options":["Glomerüler filtrasyon hızı","Efektif renal plazma akımı","Renal kan akımı","Filtrasyon fraksiyonu","Net serbest su geri emilimi"],"correct":0,"exp":"Bu özellikleri taşıyan ideal belirtecin atılım hızı filtre edilen yüke eşittir; klirensi GFR'yi verir. İnülin klasik örnektir."},{"id":2475,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Düşük plazma konsantrasyonunda verilen para-aminohippuratın renal arter ile renal ven arasındaki ekstraksiyonu çok yüksektir. Bu nedenle klirensi en iyi hangi değişkeni yaklaşık olarak gösterir?","options":["Gerçek renal kan akımı","Filtrasyon fraksiyonu","Sadece proksimal tübül akımı","Efektif renal plazma akımı","Glomerüler filtrasyon hızı"],"correct":3,"exp":"PAH filtre edilir ve proksimal tübülden etkin biçimde sekrete edilir; tek geçişte plazmadan büyük ölçüde temizlenir. Tam ekstrakte edilmediği için gerçek değil efektif renal plazma akımını tahmin eder."},{"id":2476,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Hiperglisemi giderek artırılan bir deneyde glukoz geri emilimi, plazma eşik değerinden önce tam plato yapmadan kıvrılmaya başlıyor. Bu ‘splay’ olgusunun başlıca açıklaması hangisidir?","options":["Glukozun albumine giderek daha çok bağlanması","Nefronların taşıma kapasitesine farklı düzeylerde ulaşması","Glukozun distal nefrondan aktif sekresyonu","GFR'nin hiperglisemide sıfıra yaklaşması","ADH'nin SGLT taşıyıcılarını aniden inhibe etmesi"],"correct":1,"exp":"Glukoz geri emilimi taşıma maksimumuyla sınırlıdır. Nefronlar aynı anda doymadığı ve taşıyıcı kinetiği kademeli olduğu için glukozüri ideal Tm noktasından önce başlar; eğride splay oluşur."},{"id":2477,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Furosemid verilen hastada medüller ozmotik gradyan ve idrarı yoğunlaştırma yeteneği azalıyor. İnhibe edilen nefron segmentinin normal özelliği hangisidir?","options":["Suyu aquaporin-1 ile solütten daha hızlı emmesi","Glukozu SGLT2 ile geri emmesi","Na-K-2Cl kotransportu yaparken suya geçirimsiz olması","ADH varlığında üreyi geri emmesi","ENaC aracılığıyla sodyum geri emmesi"],"correct":2,"exp":"Henle çıkan kalın kolu NKCC2 ile NaCl geri emer fakat suya geçirimsizdir. Bu ‘seyreltici segment’ karşı akım çoğaltıcısının ve medüller hipertonisitenin temelidir."},{"id":2478,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Uzun süren su kısıtlamasında ADH artışı, iç medüller toplayıcı kanalın yalnız suya değil üreye geçirgenliğini de artırıyor. Bu ikinci etkinin işlevi hangisidir?","options":["Üre üretimini karaciğerde baskılamak","Medüller üre geri dönüşümünün artması","Üreyi glukoza çevirip tübül içine vermek","Kortikal interstisyumu hipertonik hâle getirmek","Proksimal tübülde üre filtrasyonunu engellemek"],"correct":1,"exp":"ADH, UT-A taşıyıcılarını artırarak iç medüller toplayıcı kanaldan interstisyuma üre geçişini ve üre geri dönüşümünü artırır. Böylece su geri emilimini sağlayan medüller hipertonisite desteklenir."},{"id":2479,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Fanconi sendromlu çocukta normoglisemiye rağmen glukozüri, fosfatüri, aminoasidüri ve proksimal renal tübüler asidoz vardır. Hasarlı segmentin normal taşıma özelliği hangisidir?","options":["Filtre edilen sodyumun yalnız aldosteron varlığında geri emilmesi","Suyun solütten bağımsız olarak hipotonik geri emilmesi","Filtre edilen su ve solütlerin büyük bölümünün yaklaşık izoozmotik geri emilimi","İdrarın son ozmolalitesinin ADH'den bağımsız belirlenmesi","Potasyumun yalnız aktif sekresyonla lümene verilmesi"],"correct":2,"exp":"Proksimal tübül filtre edilen Na ve suyun yaklaşık üçte ikisini, ayrıca glukoz, aminoasit, fosfat ve bikarbonatın büyük bölümünü geri emer. Su-solüt geri emilimi yaklaşık izoozmotiktir."},{"id":2480,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Primer hiperaldosteronizmli hastada hipokalemi ve metabolik alkaloz gelişiyor. Principal hücrede potasyum sekresyonunu artıran olaylar dizisi hangisidir?","options":["Na/K-ATPaz azalması → hücre içi K azalması → ROMK kapanması","ENaC azalması → lümen pozitifliği → K sekresyonu","NKCC2 artışı → distal akım azalması → K sekresyonu","ENaC ve Na/K-ATPaz artışı → lümen negatifliği → ROMK üzerinden K çıkışı","Aquaporin-2 azalması → medüller gradyan artışı → K çıkışı"],"correct":3,"exp":"Aldosteron ENaC, Na/K-ATPaz ve K kanalı aktivitesini artırır. Na geri emilimi lümeni negatifleştirir; hücre içi K ve elektrokimyasal gradyan artınca ROMK üzerinden sekresyon kolaylaşır."},{"id":2481,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kronik metabolik asidozda böbrek net asit atılımını artırırken yeni bikarbonat üretir. Proksimal tübülde amonyagenezin başlıca substratı hangisidir?","options":["Glutamin","Alanin","Fenilalanin","Lizin","Triptofan"],"correct":0,"exp":"Glutamin metabolizması NH4+ ve yeni HCO3− oluşturur. NH4+ lümene atılır, bikarbonat kana verilir; kronik asidoz bu yolu belirgin artırır."},{"id":2482,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Salisilat zehirlenmesinin erken döneminde PaCO2 24 mmHg, HCO3− 20 mEq/L ve pH 7,47 bulunuyor. Primer bozukluğa uygun renal adaptasyon hangisidir?","options":["Hidrojen sekresyonunu ve amonyagenezi artırma","Bikarbonat geri emilimini artırma","Titratabl asit atılımını artırma","Bikarbonat geri emilimini azaltıp alkali idrar oluşturma","Distal nefronda klor geri emilimini durdurma"],"correct":3,"exp":"Erken salisilat etkisi santral hiperventilasyonla respiratuvar alkalozdur. Böbrek H+ sekresyonu ve HCO3− geri emilimini azaltarak bikarbonat atılımını artırır; kronik yanıt günler içinde belirginleşir."},{"id":2483,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Yüksek potasyum içeren öğün sonrası, plazma potasyumu belirgin yükselmeden renal atılım artıyor. Distal nefronda bu ‘feed-forward’ yanıtı güçlendiren başlıca hormon hangisidir?","options":["ADH","Parathormon","Atriyal natriüretik peptid","Kortizol","Aldosteron"],"correct":4,"exp":"Plazma K artışı adrenal zona glomerulozayı doğrudan uyarır. Aldosteron principal hücrelerde Na/K-ATPaz, ENaC ve ROMK etkinliğini artırarak distal K sekresyonunu yükseltir."},{"id":2484,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Santral diabetes insipiduslu hastada su kısıtlamasına rağmen idrar ozmolalitesi düşük kalıyor; desmopressin sonrası belirgin artıyor. Tedavi öncesi toplayıcı kanaldaki temel kusur hangisidir?","options":["V2 reseptör uyarısının artması","İç medüller interstisyumun mutlak hipertonisitesi","Proksimal tübülde su geri emiliminin tamamen durması","Aldosteron aracılı ENaC artışı","Apikal AQP2 yerleşiminin azalması"],"correct":4,"exp":"ADH yokluğunda V2-cAMP sinyali ve AQP2'nin apikal membrana yerleşimi azalır; toplayıcı kanal suya geçirimsiz kalır. Desmopressinle düzelme santral diabetes insipidusu destekler."},{"id":2485,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kas kütlesi sabit bir kişide kreatinin klirensi, aynı anda ölçülen inülin klirensinden hafif yüksek bulunuyor. Bu farkın en uygun açıklaması aşağıdakilerden hangisidir?","options":["Kreatininin az miktarda proksimal tübüler sekresyona uğraması","İnülinin tübülden geri emilmesi","Kreatininin glomerülden filtre edilmemesi","İnülinin distal nefronda sentezlenmesi","Kreatininin tümüyle albumine bağlanması"],"correct":0,"exp":"Kreatinin serbestçe filtrelenir ve az miktarda tübüler sekresyona uğrar; bu nedenle klirensi gerçek GFR'yi hafif fazla tahmin eder. İleri böbrek yetmezliğinde göreceli hata büyüyebilir."},{"id":2486,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Boyun orta hattında, dil çıkarınca ve yutkunmakla hareket eden kistik kitle saptanıyor. Cerrahide yalnız kistin çıkarılması nüks riskini artırır. Bu lezyonun embriyolojik kökeni hangisidir?","options":["Üçüncü faringeal poş artığı","Servikal sinüs artığı","Tiroglossal kanal artığı","Birinci faringeal yarık artığı","Ultimobrankiyal cisim artığı"],"correct":2,"exp":"Tiroglossal kanal kisti tiroidin foramen çekumdan boyuna iniş traktında gelişir. Sistrunk işleminde kist, trakt ve hiyoid kemiğin orta bölümü çıkarılarak nüks azaltılır."},{"id":2487,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Mikrognati, dış kulak anomalisi ve iletim tipi işitme kaybı olan yenidoğanda birinci faringeal ark gelişim kusuru düşünülüyor. Bu arkın normal türevi hangisidir?","options":["Stapes ve processus styloideus","Malleus, incus ve çiğneme kasları","Larenks kıkırdakları ve intrinsik larenks kasları","Mimik kasları ve stapes kası","Palatofaringeus kası ve üst paratiroid bezleri"],"correct":1,"exp":"Birinci ark Meckel kıkırdağıyla ilişkilidir; malleus, incus ve çiğneme kaslarını oluşturur, trigeminal sinirin mandibular dalıyla innerve edilir. Stapes ve mimik kasları ikinci arka aittir."},{"id":3580,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"24 yaşındaki erkek hasta 2 gündür tekrarlayan kusma ve halsizlik yakınmasıyla başvuruyor. Serum potasyumu düşük saptanan bu hastada hücre içi istirahat membran potansiyeli için hangi değişiklik beklenir?","options":["Aksiyon potansiyeli eşik değerinin değişmeden kalması","Sodyum denge potansiyelinin daha negatif hale gelmesi","Klorür geçirgenliğinin tamamen kaybolması","Hücre içi kalsiyumun hızla sıfırlanması","Membran potansiyelinin daha negatif hale gelmesi"],"correct":4,"exp":"Hipokalemi, potasyumun hücre dışı konsantrasyonunu azaltır ve potasyum denge potansiyelini daha negatif yapar. Dinlenim membran potansiyeli potasyum geçirgenliğine çok bağımlı olduğu için hücre hiperpolarize olur. Kısa akıl notu: dış K azalırsa hücre daha 'kapalı' kalır."},{"id":3581,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"31 yaşındaki kadın hasta 6 saattir süren ishal ve baş dönmesi yakınmasıyla başvuruyor. İnce bağırsak epitelinde glukoz ve sodyumun lümenden birlikte emilimi için hangi taşıma özelliği gereklidir?","options":["Bazolateral Na-K ATPazın oluşturduğu sodyum gradyenti","Apikal potasyum kanallarının kapanması","Hücre içine pasif klorür girişinin tamamen durması","Glukozun sadece basit difüzyonla geçmesi","Mitokondri dış membranında proton kanalı açılması"],"correct":0,"exp":"SGLT aracılı glukoz emilimi sekonder aktif taşımadır. Enerji doğrudan SGLT tarafından değil, bazolateral Na-K ATPazın düşük hücre içi sodyum oluşturarak sağladığı gradyentten gelir."},{"id":3582,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"67 yaşındaki erkek hasta 1 gündür süren bilinç bulanıklığı ve nöbet yakınmasıyla getiriliyor. Hipertansiyon dışında kronik hastalığı yok, amlodipin kullanıyor. Serum sodyumu belirgin düşük olan bu hastada beyin hücrelerinde erken dönemde hangi olay öne çıkar?","options":["Miyelin sentezinin ani artışı","Hücre dışına masif potasyum çıkışıyla hücre büzüşmesi","Sodyum kanallarının geri dönüşümsüz yıkımı","Laktat üretiminin tamamen durması","Hücre içine su girişi ve hücresel şişme"],"correct":4,"exp":"Akut hiponatremide plazma ozmolalitesi düşer ve su hücre içine geçer. Beyin kapalı bir alanda olduğu için hücresel şişme nöbet ve bilinç değişikliği yapabilir."},{"id":3583,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"45 yaşındaki kadın hasta 3 gündür kas güçsüzlüğü ve çabuk yorulma yakınmasıyla başvuruyor. Hipotiroidi öyküsü var, levotiroksin kullanıyor. Hücrede ATP üretimi azaldığında iyon dengesini en erken bozan süreç hangisidir?","options":["Lizozomal pH'nin nötrleşmeden sabit kalması","Nükleer porlardan mRNA çıkışının artması","Ribozomlarda peptid bağının hızlanması","Na-K ATPaz aktivitesinin azalması","Hücre dışı matriks sentezinin artması"],"correct":3,"exp":"Na-K ATPaz ATP'ye bağımlıdır ve hücre hacmi ile membran potansiyelinin korunmasında kritiktir. ATP azalınca sodyum hücre içinde birikir, su onu izler ve hücre şişer."},{"id":3584,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Bir hücrede kolaylaştırılmış difüzyon ile basit difüzyonu ayırmada en belirleyici özellik hangisidir?","options":["Maddenin mutlaka elektrokimyasal gradyentine ters taşınması","Enerjinin doğrudan ATP hidrolizinden sağlanması","Taşıyıcı doygunluğuna bağlı maksimum taşıma hızının bulunması","Taşınan molekülün her zaman lipofilik olması","Hücre zarının iki yaprakçığının kalıcı ayrılması"],"correct":2,"exp":"Kolaylaştırılmış difüzyon taşıyıcı veya kanal aracılıdır ve taşıyıcı sayısı sınırlıysa doygunluk gösterir. Basit difüzyon ise genellikle konsantrasyon farkıyla orantılı ilerler."},{"id":3585,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"58 yaşındaki erkek hasta 2 haftadır ayak bileklerinde şişlik yakınmasıyla başvuruyor. Kronik karaciğer hastalığı var, spironolakton kullanıyor. Serum albümini düşük saptanan hastada interstisyel sıvı artışını en iyi açıklayan değişiklik hangisidir?","options":["İnterstisyel proteinlerin tamamen temizlenmesi","Lenfatik drenajın aşırı artması","Arteriyol direncinin tamamen kaybolması","Kapiller hidrostatik basıncın sıfıra düşmesi","Kapiller plazma onkotik basıncının azalması"],"correct":4,"exp":"Albüminden kaynaklanan plazma onkotik basıncı sıvıyı kapiller içinde tutar. Albümin azalınca Starling dengesi filtrasyon lehine kayar ve ödem gelişir."},{"id":3586,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"36 yaşındaki kadın hasta 4 gündür bacakta kızarıklık, ağrı ve şişlik yakınmasıyla başvuruyor. Diyabeti var, metformin kullanıyor. İnflame dokuda nötrofil göçünün damar dışına çıkış aşamasında hangi olay en kritik basamağı oluşturur?","options":["Fibroblastların miyelin sentezini artırması","Eritrositlerin bazal membranı enzimatik olarak parçalaması","Albuminin lenfatiklerden kana geri taşınması","Endotel adezyon molekülleriyle lökosit integrinlerinin sıkı bağlanması","Düz kas hücresinin aksoplazmik taşımaya başlaması"],"correct":3,"exp":"Lökosit ekstravazasyonunda yuvarlanma, adezyon ve transmigrasyon sıralanır. Sıkı adezyonda lökosit integrinleri endotel ICAM/VCAM gibi moleküllerle bağlanır."},{"id":3587,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"28 yaşındaki erkek hasta 10 gündür iyileşmeyen yüzeyel kesi nedeniyle başvuruyor. Granülasyon dokusunda kontraksiyonu sağlayan hücre tipi için hangi ifade doğrudur?","options":["Aktin içeren miyofibroblastlar yara kenarlarını yaklaştırır","Mast hücreleri kolajen liflerini mekanik olarak kısaltır","Adipositler bazal membranı kasılır hale getirir","Plazma hücreleri aktin-miyozin köprüleriyle epitel çeker","Endotel hücreleri sarkomer oluşturarak tüm yarayı kapatır"],"correct":0,"exp":"Yara kontraksiyonunda alfa düz kas aktini taşıyan miyofibroblastlar rol oynar. Bunlar fibroblast benzeri hücrelerdir fakat kasılabilme özelliği kazanırlar."},{"id":3588,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Sürekli kapillerleri fenestralı kapillerlerden ayıran temel yapısal özellik hangisidir?","options":["Bazal membranın tamamen olmaması","Endotel hücreleri arasında belirgin pencerelerin bulunmaması","Eritrositlerin endotel sitoplazmasından geçmesi","Damar duvarında kıkırdak matriks bulunması","Endotel hücrelerinin miyelin kılıf oluşturması"],"correct":1,"exp":"Sürekli kapillerlerde endotel hücreleri sıkı bağlantılarla düzenlenir ve fenestra yoktur. Kas, sinir ve akciğerde tipiktir. Fenestralı kapillerlerde ise emilim ve filtrasyon için pencereler bulunur."},{"id":3589,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"22 yaşındaki erkek hasta 30 dakikadır süren yoğun egzersiz sonrası baldır ağrısı ve güçsüzlük yakınmasıyla başvuruyor. İskelet kasında kasılma sonrası gevşemeyi doğrudan sağlayan olay hangisidir?","options":["Kalsiyumun SERCA ile sarkoplazmik retikuluma geri alınması","Troponin C'nin aktine kalıcı bağlanması","Miyozin başının ATP olmadan aktinden ayrılması","Asetilkolinin sarkomer içinde depolanması","Tropomiyozinin miyozin başını hidrolize etmesi"],"correct":0,"exp":"Kas gevşemesi için sitozolik kalsiyum düşmelidir. SERCA pompası kalsiyumu sarkoplazmik retikuluma geri taşır; kalsiyum troponinden ayrılınca aktin-miyozin etkileşimi azalır."},{"id":3590,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"63 yaşındaki kadın hasta 3 aydır merdiven çıkarken uyluk kaslarında çabuk yorulma yakınmasıyla başvuruyor. Tip 2 diyabeti var, metformin kullanıyor. Tip I kas liflerinin dayanıklılığını en iyi açıklayan özellik hangisidir?","options":["Nöromüsküler kavşakta asetilkolin salınmaması","Glikolitik enzimlerin tamamen yokluğu","Sarkoplazmik retikulumun hiç bulunmaması","Mitokondri ve miyoglobin içeriğinin yüksek olması","Kalsiyum bağlayan troponinin olmaması"],"correct":3,"exp":"Tip I lifler yavaş kasılır, oksidatif metabolizmaya dayanır, mitokondri ve miyoglobin içerikleri yüksektir. Bu nedenle yorgunluğa dirençlidir."},{"id":3591,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"46 yaşındaki erkek hasta 2 gündür çarpıntı ve eforla nefes darlığı yakınmasıyla başvuruyor. Hipertansiyonu var, hidroklorotiyazid kullanıyor. Ventrikül kasında aksiyon potansiyeli platosunu sürdüren iyon hareketi için hangi seçenek doğrudur?","options":["L tipi kalsiyum kanallarından hücre içine kalsiyum girişi","Hızlı sodyum kanallarından sürekli sodyum çıkışı","Potasyumun hücre içine masif girişi","Klorür kanallarının geri dönüşümsüz kapanması","Sodyum-kalsiyum değiştiricinin tamamen durması"],"correct":0,"exp":"Kardiyak ventrikül aksiyon potansiyelinin plato fazında L tipi kalsiyum kanallarından kalsiyum girişi ile potasyum çıkışı dengelenir. Bu plato, uzun refrakter dönem ve tetani gelişmemesi için önemlidir."},{"id":3592,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"35 yaşındaki kadın hasta 1 gündür bulanık görme, ağız kuruluğu ve güçsüzlük yakınmasıyla başvuruyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor; ev yapımı konserve tüketmiş. Nöromüsküler kavşakta kuvvet kaybını açıklayan olay hangisidir?","options":["Kas lifinde miyoglobin sentezinin artması","Postsinaptik nikotinik reseptör sayısının artması","Presinaptik asetilkolin salınımının azalması","Sarkomer Z çizgisinin tamamen kaybolması","Asetilkolinesterazın tam inhibisyonu"],"correct":2,"exp":"Botulinum toksini SNARE proteinlerini etkileyerek presinaptik asetilkolin salınımını azaltır. Sonuç gevşek paralizidir. Asetilkolinesteraz inhibisyonu ise kolinerjik fazlalık yapar."},{"id":3593,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"42 yaşındaki erkek hasta 6 aydır aralıklı hışıltı ve nefes darlığı tarifliyor; salbutamol inhaler kullanıyor. Bronş düz kasında hücre içi kalsiyum artışından sonra kasılmayı başlatan en kritik basamak aşağıdakilerden hangisidir?","options":["Miyozin ATPaz aktivitesinin kaybı","Troponin C'nin tropomiyozini yer değiştirmesi","Sarkomer Z çizgilerinin birbirinden uzaklaşması","Ryanodin reseptörlerinin kapanması","Kalmodulin aracılığıyla miyozin hafif zincir kinazın aktive olması"],"correct":4,"exp":"Düz kasta troponin yoktur. Kalsiyum kalmoduline bağlanır, miyozin hafif zincir kinazı aktive eder ve miyozin fosforilasyonu ile kasılma başlar."},{"id":3594,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"29 yaşındaki kadın hasta 14 aydır gebe kalamama yakınmasıyla başvuruyor; siklusları 35-45 günde bir oluyor. Ovulasyon öncesi LH artışını doğrudan tetikleyen fizyolojik değişiklik aşağıdakilerden hangisidir?","options":["İnhibin B'nin FSH'yi artırması","Progesteronun foliküler faz başında hızla yükselmesi","Sürdürülen yüksek estradiol düzeyinin hipofize pozitif geri bildirim yapması","Prolaktinin GnRH pulslarını hızlandırması","Kortizolün granüloza hücrelerinde aromatazı baskılaması"],"correct":2,"exp":"Siklus ortasında yeterli süre yüksek kalan estradiol, klasik negatif geri bildirimin tersine pozitif geri bildirim oluşturur ve LH piki gelişir. LH piki ovulasyonu başlatır."},{"id":3595,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"34 yaşındaki erkek hasta 1 yıldır infertilite yakınmasıyla başvuruyor. Kronik hastalığı yok, ilaç kullanmıyor; semen analizinde sperm sayısı düşük. Sertoli hücrelerinden salgılanan ve FSH üzerine geri bildirim sağlayan madde hangisidir?","options":["Dihidrotestosteron","Testosteron","İnhibin B","Anti-Müllerian hormon","Oksitosin"],"correct":2,"exp":"Sertoli hücreleri spermatogenezi destekler ve inhibin B salgılayarak hipofizden FSH salınımını baskılar. Leydig hücreleri ise LH etkisiyle testosteron üretir."},{"id":3596,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"26 yaşındaki kadın hasta 6 haftadır adet gecikmesi ve sabah bulantısı yakınmasıyla başvuruyor. Erken gebelikte korpus luteumun progesteron üretimini sürdürmesini sağlayan hormon hangisidir?","options":["Folikül uyarıcı hormon","İnsan koryonik gonadotropini","Prolaktin","Oksitosin","Melatonin"],"correct":1,"exp":"Erken gebelikte trofoblasttan salgılanan hCG, LH benzeri etkiyle korpus luteumu destekler. Progesteron devamı endometriumun korunması için gereklidir."},{"id":3597,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"25 yaşındaki kadın hasta doğumdan 5 gün sonra bebeğini emzirirken süt miktarının az olması yakınmasıyla başvuruyor. Meme alveol hücrelerinden süt sentezini artıran, fakat süt ejeksiyonundan sorumlu olmayan hormon hangisidir?","options":["Adrenalin","Oksitosin","Vazopressin","Prolaktin","İnhibin A"],"correct":3,"exp":"Prolaktin süt üretimini artırır; oksitosin ise miyoeptelyal hücreleri kasarak süt salınımını sağlar."},{"id":3598,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"30 yaşındaki kadın hasta gebeliğin 8. haftasında ultrason kontrolüne geliyor. Bu haftada organ taslaklarının büyük kısmının gelişmiş olmasını açıklayan embriyolojik dönem için hangi ifade doğrudur?","options":["İmplantasyon fertilizasyondan hemen sonraki ilk saatte tamamlanır","Organogenez esas olarak 3-8. haftalar arasında gerçekleşir","Nörülasyon yalnızca üçüncü trimesterde başlar","Gastrulasyon doğumdan sonra sürer","Somitler sadece plasenta içinde oluşur"],"correct":1,"exp":"Embriyonik dönem 3-8. haftaları kapsar ve organogenez açısından en kritik aralıktır. Teratojenlere duyarlılık bu dönemde yüksektir."},{"id":3599,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"27 yaşındaki kadın hasta gebeliğin 5. haftasında, folik asit kullanmama öyküsüyle başvuruyor. Nöral tüp kapanma kusuru riskini azaltmada folatın temel fizyolojik rolü aşağıdakilerden hangisidir?","options":["Tek karbon metabolizması üzerinden DNA sentezi ve metilasyonu desteklemesi","Miyozin hafif zincirini doğrudan fosforile etmesi","Fetal hemoglobini erişkin tipine dönüştürmesi","Amniyon sıvısındaki surfaktanı yıkması","Trofoblast invazyonunu baskılaması"],"correct":0,"exp":"Folat tek karbon metabolizmasında DNA sentezi ve metilasyon reaksiyonları için gereklidir. Hızla bölünen embriyonik dokular folat eksikliğine duyarlıdır."},{"id":3600,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"32 yaşındaki kadın hasta gebeliğin 7. haftasında hafif vajinal lekelenme yakınmasıyla başvuruyor. Kronik hastalığı yok, levotiroksin kullanıyor. Plasentada anne ve fetal kanın normalde doğrudan karışmamasını sağlayan yapı için hangi seçenek en doğrudur?","options":["Koryon villuslarında trofoblast ve fetal kapiller bariyerin bulunması","Fetal eritrositlerin anne arterlerine serbest geçmesi","Amniyon boşluğunun maternal venöz sinüs olması","Yolk kesesinin tüm gebelik boyunca gaz değişimini üstlenmesi","Desiduanın tamamen avasküler kalması"],"correct":0,"exp":"Plasental değişim koryon villusları üzerinden olur; maternal kan intervillöz aralıktadır, fetal kan ise villus içi kapillerlerdedir. Normalde iki dolaşım doğrudan karışmaz."},{"id":3601,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"28 yaşındaki kadın hasta gebeliğin 4. haftasında rutin kontrole geliyor. Bu dönemde gastrulasyonun embriyolojik açıdan en temel sonucu hangisidir?","options":["Korpus luteumun gerilemesi","Spermatogonyumların pubertede çoğalması","Fetal akciğerde surfaktan salgısının başlaması","Ektoderm, mezoderm ve endoderm germ yapraklarının oluşması","Amniyon sıvısının tamamen kaybolması"],"correct":3,"exp":"Gastrulasyon üç primer germ yaprağını oluşturur. Sonraki organ ve doku farklılaşmasının haritası bu katmanlardan gelişir."},{"id":3602,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"72 yaşındaki erkek hasta 2 aydır eforla nefes darlığı ve halsizlik yakınmasıyla başvuruyor. Kronik böbrek hastalığı var, kalsiyum asetat kullanıyor. Normositer aneminin temel nedeni olarak hangi mekanizma beklenir?","options":["Trombopoietinin tamamen baskılanması","İntrensek faktör salgısının aşırı artması","Renal eritropoietin üretiminin azalması","Demirin makrofajlardan sınırsız salınması","Hemoglobinin oksijen afinitesinin sıfırlanması"],"correct":2,"exp":"Eritropoietin esas olarak böbrekte peritübüler interstisyel hücrelerden salınır. Kronik böbrek hastalığında EPO azalır ve normositer normokrom anemi gelişebilir."},{"id":3603,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"25 yaşındaki kadın hasta 4 haftadır halsizlik, çarpıntı ve tırnak kırılması yakınmasıyla başvuruyor. Kronik hastalığı yok, ilaç kullanmıyor; menstrüasyonları yoğun. Demir eksikliğinde eritropoezi sınırlayan en temel basamak hangisidir?","options":["B12'nin demire dönüşememesi","Eritropoietin reseptörünün her zaman aşırı uyarılması","Globin zincirlerinin mitokondride parçalanması","Hem sentezi için yeterli demirin bulunmaması","Trombositlerin eritrosite farklılaşması"],"correct":3,"exp":"Demir hem sentezi için zorunludur. Demir eksikliği hemoglobin sentezini azaltır, mikrositer hipokrom eritrositler oluşur."},{"id":3604,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"59 yaşındaki erkek hasta 3 gündür ateş ve öksürük tarifliyor. Akut inflamasyonda karaciğerden hepsidin artışının ardından serum demirinin düşmesini aşağıdakilerden hangisi açıklar?","options":["Transferrinin oksijeni doğrudan bağlaması","Ferroportinin yıkılmasıyla demirin makrofaj ve enterositlerden çıkışının azalması","Eritropoietinin trombosit serisine kayması","Haptoglobinin böbrekte glukoz geri emilimini artırması","Albüminin hem sentezini hızlandırması"],"correct":1,"exp":"Hepsidin ferroportini internalize edip yıktırır. Böylece demirin barsaktan emilimi ve makrofajlardan kana salınımı azalır; inflamasyon anemisinde işlevsel demir kısıtlanması gelişir."},{"id":3605,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"41 yaşındaki kadın hasta 1 aydır uyuşma ve dengesizlik yakınmasıyla başvuruyor. Hashimoto tiroiditi var. B12 eksikliğinde megaloblastik değişimin temel nedeni aşağıdakilerden hangisidir?","options":["DNA sentezinin bozulması nedeniyle nükleer olgunlaşmanın gecikmesi","Hemoglobinin oksijene bağlanma kapasitesinin kaybı","Trombositlerin nötrofil serisine kayması","Eritrosit zarında kolesterol içeriğinin azalması","2,3-BPG sentezinin artıp eritropoezi baskılaması"],"correct":0,"exp":"B12 ve folat DNA sentezi için gereklidir. Eksiklikte çekirdek olgunlaşması sitoplazmaya göre geri kalır; makroovalositler ve hipersegmente nötrofiller görülebilir."},{"id":3606,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"66 yaşındaki erkek hasta 1 yıldır eforla nefes darlığı yakınmasıyla başvuruyor. KOAH öyküsü var, tiotropium kullanıyor. Kronik hipokside hemoglobinin oksijen afinitesini azaltarak dokulara oksijen bırakılmasını kolaylaştıran eritrosit içi metabolit hangisidir?","options":["Ferritin","2,3-bisfosfogliserat","Haptoglobin","Seruloplazmin","Miyeloperoksidaz"],"correct":1,"exp":"2,3-BPG deoksihemoglobine bağlanır ve oksijen afinitesini azaltır. Böylece eğri sağa kayar, dokulara oksijen bırakılması kolaylaşır."},{"id":3607,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Primer hemostazda trombositlerin subendotelyal kollajene tutunmasını sağlayan ana köprü molekül hangisidir?","options":["Plazminojen","Antitrombin","Protein C","von Willebrand faktör","Fibrinojen yıkım ürünü"],"correct":3,"exp":"vWF subendotelyal kollajen ile trombosit GPIb reseptörü arasında köprü kurar. Primer hemostazın erken yapışma basamağı için kritiktir."},{"id":3608,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"44 yaşındaki erkek hasta 6 aydır epigastrik yanma ve gece ağrısı yakınmasıyla başvuruyor. Kronik hastalığı yok, aralıklı NSAİİ kullanıyor. Parietal hücreden asit salgısını doğrudan artıran ortak son basamak hangisidir?","options":["Mükus hücrelerinden tripsin salınması","Pepsinojenin duodenumda bikarbonata dönüşmesi","Enterokinazın gastrini parçalaması","İntrensek faktörün klorüre bağlanması","Apikal H-K ATPaz aktivasyonunun artması"],"correct":4,"exp":"Parietal hücrede asit salgısının son basamağı apikal H-K ATPazdır. Asetilkolin, histamin ve gastrin farklı reseptörlerden bu pompaya giden yolu güçlendirir."},{"id":3609,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"52 yaşındaki kadın hasta 3 aydır yağlı dışkılama ve kilo kaybı yakınmasıyla başvuruyor. Tip 2 diyabeti var, metformin kullanıyor. Pankreatik enzim sekresyonunu protein ve yağ içeren öğünden sonra en güçlü artıran hormon hangisidir?","options":["Motilin","Sekretin","Gastrik inhibitör peptid","Kolesistokinin","Somatostatin"],"correct":3,"exp":"CCK duodenum ve jejunum I hücrelerinden yağ asitleri ve aminoasitlere yanıt olarak salınır; pankreatik enzim sekresyonunu ve safra kesesi kasılmasını artırır. Sekretin daha çok bikarbonat salgısını artırır."},{"id":3610,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"61 yaşındaki erkek hasta 2 haftadır sulu ishal ve halsizlik yakınmasıyla başvuruyor. Duodenum lümenine asit içeriği geldiğinde pankreatik bikarbonat salgısını artıran hormon hangisidir?","options":["Motilin","Gastrin","Kolesistokinin","Sekretin","Ghrelin"],"correct":3,"exp":"Sekretin duodenal S hücrelerinden asit yanıtıyla salınır ve pankreas kanal hücrelerinden bikarbonat salgısını artırır. Amaç duodenal pH'yi yükseltmek ve enzimler için uygun ortam oluşturmaktır."},{"id":3611,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"33 yaşındaki kadın hasta 10 gündür kabızlık ve karında şişkinlik yakınmasıyla başvuruyor. Kronik hastalığı yok, demir preparatı kullanmaya başlamış. Kolon motilitesinde kitle hareketlerini başlatan ana refleks uyaranı hangisidir?","options":["Kolon epitelinde pepsin salgılanması","İleumda B12 emiliminin durması","Safra tuzlarının midede parçalanması","Pankreas kanalında pH'nin düşmesi","Mideye gıda girmesiyle gelişen gastro-kolik refleks"],"correct":4,"exp":"Yemekten sonra mide distansiyonu ve otonom-enterik yollar kolon kitle hareketlerini artırır. Bu gastro-kolik refleks defekasyon ihtiyacını tetikleyebilir."},{"id":3612,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"İnce bağırsakta safra tuzlarının enterohepatik dolaşıma geri kazandırıldığı başlıca bölge hangisidir?","options":["Duodenum başlangıcı","Mide fundusu","Özofagus alt ucu","Transvers kolon","Terminal ileum"],"correct":4,"exp":"Safra tuzları terminal ileumdan aktif olarak geri emilir ve portal dolaşımla karaciğere döner. Terminal ileum hastalıklarında safra tuzu kaybı yağ emilimini bozar."},{"id":3613,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Mide boşken yaklaşık 90 dakikalık aralıklarla ortaya çıkan interdigestif motor aktiviteyi başlatmada öne çıkan hormon hangisidir?","options":["Leptin","Motilin","Sekretin","Kolesistokinin","İnsülin"],"correct":1,"exp":"Motilin açlıkta migratuvar motor kompleksi uyarır. Bu kompleks mide ve ince bağırsakta artıkları ileri taşır. Kısa not: Motilin, mideyi 'motor' gibi çalıştırır."},{"id":3614,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşındaki erkek hasta 2 saattir süren baş dönmesi ve soğuk terleme yakınmasıyla başvuruyor. Hipertansiyonu var, beta-blokör kullanıyor. Ani ayağa kalkınca kan basıncını kısa sürede korumaya çalışan refleks için hangi yanıt beklenir?","options":["Vagal tonusun artmasıyla kalp hızının düşmesi","Karotis cisimciğinde oksijen algısının tamamen durması","Baroreseptör ateşlemesinin azalmasıyla sempatik tonusun artması","Aldosteronun saniyeler içinde maksimuma çıkması","Natriüretik peptidin arteriolleri kasması"],"correct":2,"exp":"Ortostatik durumda arter basıncı azalır, baroreseptör ateşlemesi düşer. Medüller yanıt sempatik aktiviteyi artırır, kalp hızı ve damar tonusu yükselir."},{"id":3615,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"57 yaşındaki kadın hasta 3 aydır eforla nefes darlığı yakınmasıyla başvuruyor. Hipertansiyonu var, losartan kullanıyor. Diyastolik disfonksiyonda ventrikül doluş basıncı artarken atım hacminin korunmaya çalışılmasını en iyi açıklayan ilişki aşağıdakilerden hangisidir?","options":["Koroner akımın yalnızca sistolde gerçekleşmesi","Afterload azaldığında venöz dönüşün kesilmesi","Vagus aktivitesinin miyokard kontraktilitesini doğrudan artırması","Frank-Starling mekanizmasıyla artan diyastol sonu hacmin kasılma kuvvetini artırması","Kapiller onkotik basıncın ventrikül basıncını belirlemesi"],"correct":3,"exp":"Frank-Starling mekanizması, miyokard lif uzunluğunun artmasıyla kasılma kuvvetinin artmasını açıklar. Ancak diyastolik disfonksiyonda doluş basıncı yükselir ve kompansasyon sınırlanır."},{"id":3616,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"49 yaşındaki erkek hasta 1 saattir göğüs ağrısı yakınmasıyla acile geliyor. Sigara kullanıyor, kronik hastalığı yok. Koroner perfüzyonun sol ventrikülde en çok diyastolde gerçekleşmesini hangi mekanizma açıklar?","options":["Koroner sinüsün sistolde arterleşmesi","Diyastolde aort kapağının tam açık kalması","Sistolde intramiyokardiyal basıncın koroner damarları sıkıştırması","Endokardın oksijen ihtiyacının diyastolde sıfırlanması","Miyokardın kapiller içermemesi"],"correct":2,"exp":"Sol ventrikül sistolünde yüksek duvar içi basınç koroner damarları sıkıştırır. Bu nedenle sol koroner akımın büyük kısmı diyastolde olur."},{"id":3617,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"26 yaşındaki kadın hasta 2 gündür ateş ve ishal sonrası çarpıntı yakınmasıyla başvuruyor. Hipovolemide renin salınımını artıran böbrek içi algılayıcı değişiklik aşağıdakilerden hangisidir?","options":["Eferent arteriyol çapının belirgin biçimde daralması","Distal tübülde sodyum klorür yükünün artması","ANP salınımının belirgin biçimde yükselmesi","Renal sempatik beta-1 uyarının azalması","Jukstaglomerüler aparatta afferent arteriyol basıncının azalması"],"correct":4,"exp":"Renin salınımı afferent arteriyol basıncının azalması, makula densaya NaCl gelişinin azalması ve beta-1 sempatik uyarıyla artar. Hipovolemide bu yollar RAAS'ı aktive eder."},{"id":3618,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"Total periferik direnci en fazla belirleyen damar segmenti hangisidir?","options":["Pulmoner venler","Büyük venler","Kapillerler","Lenfatik kanallar","Arteriyoller"],"correct":4,"exp":"Arteriyoller küçük yarıçapları ve düz kas tonusları nedeniyle sistemik vasküler direncin ana belirleyicisidir. Poiseuille yasasında direnç yarıçapın dördüncü kuvvetiyle ters orantılıdır."},{"id":3619,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Einthoven üçgeninde derivasyon II için elektriksel kayıt hangi iki elektrot arasındaki potansiyel farkını temsil eder?","options":["Sol kol ile sağ kol arasındaki fark","Sağ kol ile sol bacak arasındaki fark","Sol kol ile sol bacak arasındaki fark","Göğüs elektrodu ile sağ bacak arasındaki fark","Sağ bacak ile sol bacak arasındaki fark"],"correct":1,"exp":"Derivasyon II sağ kol negatif, sol bacak pozitif olacak şekilde kayıt yapar. P dalgası ve QRS kompleksinin çoğu kişide belirgin görünmesinin nedeni kalbin ana elektrik aksına yakın olmasıdır."},{"id":3620,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kapiller filtrasyonu artıran Starling kuvveti hangisidir?","options":["Kapiller geçirgenlikte kalıcı azalma","Plazma onkotik basınç artışı","Lenfatik drenaj artışı","İnterstisyel hidrostatik basınç artışı","Kapiller hidrostatik basınç artışı"],"correct":4,"exp":"Kapiller hidrostatik basınç sıvıyı damar dışına iter ve filtrasyonu artırır. Plazma onkotik basıncı ise sıvıyı damar içinde tutma yönünde etki eder."},{"id":3621,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sinoatriyal düğüm hücresinde faz 4 spontan depolarizasyonunu başlatmada önemli olan akım hangisidir?","options":["Hızlı sodyum kanal akımı","Funny sodyum akımı","Klorürün hücre dışına masif çıkışı","Miyozin ATPaz akımı","Hemoglobinin oksijen bağlama akımı"],"correct":1,"exp":"SA düğümde stabil istirahat potansiyeli yoktur. Faz 4 spontan depolarizasyonda funny akımı, T tipi kalsiyum akımı ve azalan potasyum çıkışı rol oynar."},{"id":3622,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"38 yaşındaki kadın hasta 2 aydır çarpıntı, kilo kaybı ve sıcak intoleransı yakınmasıyla başvuruyor. Tiroid hormonlarının bazal metabolizma hızını artırmasında hangi hücresel etki öne çıkar?","options":["Kalsitoninin tüm dokularda ATP üretimini kapatması","İnsülin reseptörlerinin tamamen kaybolması","Parathormonun tiroid folikülünde sentezlenmesi","Glukagonun TSH salınımını durdurması","Na-K ATPaz ve mitokondriyal oksidatif süreçlerin artması"],"correct":4,"exp":"Tiroid hormonları birçok dokuda Na-K ATPaz aktivitesini, mitokondriyal enzimleri ve oksijen tüketimini artırır. Bu nedenle ısı üretimi ve bazal metabolizma hızı yükselir."},{"id":3623,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"55 yaşındaki erkek hasta 1 gündür poliüri, susuzluk ve halsizlik yakınmasıyla başvuruyor. Tip 2 diyabeti var, insülin glarjin kullanıyor. İnsülinin iskelet kası ve yağ dokusunda glukoz alımını artıran temel etkisi hangisidir?","options":["SGLT1'i pankreas beta hücresinde kapatması","GLUT2 taşıyıcılarını böbrek proksimal tübülde yıkması","GLUT4 taşıyıcılarının hücre zarına translokasyonunu artırması","Heksokinazı tüm dokularda kalıcı inhibe etmesi","Glukagon reseptörünü doğrudan aktive etmesi"],"correct":2,"exp":"İnsülin kas ve yağ dokusunda GLUT4 veziküllerinin membrana taşınmasını sağlar. Böylece hücre içine glukoz girişi artar."},{"id":3624,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"47 yaşındaki kadın hasta 3 haftadır kas krampları ve ağız çevresinde uyuşma yakınmasıyla başvuruyor. Total tiroidektomi öyküsü var, levotiroksin kullanıyor. Hipokalsemiye karşı normalde en hızlı artması beklenen hormonun böbrekteki etkisi hangisidir?","options":["Distal tübülde kalsiyum geri emilimini artırması","Proksimal tübülde fosfat geri emilimini artırması","Kolekting kanalda su geçirgenliğini azaltması","Henle kulpunda sodyum emilimini tamamen durdurması","Böbrekte eritropoietin üretimini baskılaması"],"correct":0,"exp":"Parathormon hipokalsemiye yanıt olarak artar; distal tübülde kalsiyum geri emilimini artırır, proksimal tübülde fosfat geri emilimini azaltır ve 1-alfa hidroksilazı uyarır."},{"id":3625,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"33 yaşındaki kadın hasta 5 aydır adet düzensizliği ve memeden süt gelmesi yakınmasıyla başvuruyor. Prolaktin yüksekliğinin ovulasyonu bozmasını en iyi açıklayan mekanizma hangisidir?","options":["GnRH pulslarının baskılanması","LH reseptörlerinin adrenal kortekse taşınması","Estradiolün böbrekten atılımının artması","Oksitosinin tiroid bezini uyarması","İnhibin B'nin prolaktine dönüşmesi"],"correct":0,"exp":"Hiperprolaktinemi hipotalamik GnRH pulslarını baskılar; LH ve FSH salınımı bozulur. Bu nedenle anovulasyon, amenore ve infertilite gelişebilir."},{"id":3626,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":3,"q":"Steroid hormonların hücresel etki mekanizmasını peptid hormonlardan ayıran temel özellik aşağıdakilerden hangisidir?","options":["Kanda yalnızca serbest halde taşınmaları","Membran reseptörü üzerinden cAMP üretmeleri","Hücre içi reseptörlere bağlanıp gen transkripsiyonunu düzenlemeleri","Ribozomlarda doğrudan sentezlenmeleri","Etkilerinin saniyeler içinde ortaya çıkıp kaybolması"],"correct":2,"exp":"Steroid hormonlar lipofilik oldukları için hücre zarını geçebilir ve sitozolik ya da nükleer reseptörlerle gen transkripsiyonunu değiştirir. Peptid hormonlar çoğunlukla membran reseptörleriyle çalışır."},{"id":3627,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Kortizolün stres yanıtında kan glukozunu artırmasına katkı veren temel metabolik etkisi hangisidir?","options":["İskelet kasında GLUT4 translokasyonunu doğrudan artırması","Karaciğerde glukoneogenezi artırması","Pankreas beta hücresinden insülin salınımını sürekli artırması","Böbrekte glukoz filtrasyonunu tamamen durdurması","Yağ dokusunda lipolizi sıfırlaması"],"correct":1,"exp":"Kortizol karaciğerde glukoneogenezi artırır, periferik glukoz kullanımını azaltır ve protein katabolizmasını destekler. Stres hiperglisemisine bu yüzden katkı verir."},{"id":3628,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Aldosteronun esas etki gösterdiği nefron segmenti ve bu etkinin sonucu için aşağıdakilerden hangisi doğrudur?","options":["Kortikal toplayıcı kanalda sodyum geri emilimini ve potasyum sekresyonunu artırması","Proksimal tübülde glukoz geri emilimini durdurması","Henle inen kolunda su geçirgenliğini azaltması","Glomerülde protein filtrasyonunu artırması","Distal tübülde bikarbonat sekresyonunu baskılaması"],"correct":0,"exp":"Aldosteron kortikal toplayıcı kanal principal hücrelerinde ENaC ve Na-K ATPaz etkisini artırır. Sodyum tutulur, potasyum sekresyonu artar."},{"id":3629,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":3,"q":"Büyüme hormonunun çocukluk çağındaki lineer büyümeyi büyük ölçüde hangi mediyatör üzerinden artırdığı hangisidir?","options":["Atrial natriüretik peptid","İnhibin A","Kalsitonin","IGF-1","Sekretin"],"correct":3,"exp":"Büyüme hormonu karaciğer ve perifer dokularda IGF-1 üretimini artırır. IGF-1 epifiz plağında kondrosit proliferasyonu ve lineer büyümeye aracılık eder."},{"id":3630,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"69 yaşındaki erkek hasta 6 aydır giderek artan efor dispnesi ve kuru öksürük yakınmasıyla başvuruyor. İdiyopatik pulmoner fibrozis tanısı var, antifibrotik tedavi kullanıyor. Bu hastada spirometride hangi patern beklenir?","options":["Rezidüel volüm dramatik artar, FVC artar","FEV1/FVC oranı belirgin azalır, total akciğer kapasitesi artar","FVC azalır, FEV1/FVC oranı normal ya da artmış bulunur","Difüzyon kapasitesi her zaman artar","Pik ekspiratuvar akım tamamen normal kalır"],"correct":2,"exp":"Restriktif hastalıkta akciğer kompliansı azalır, FVC düşer. FEV1 de azalabilir fakat oran genellikle korunur veya artar. Fibroziste DLCO çoğu zaman azalır."},{"id":3631,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"58 yaşındaki erkek hasta 4 yıldır öksürük ve son 1 haftadır artan nefes darlığı yakınmasıyla başvuruyor. KOAH öyküsü var, tiotropium kullanıyor. Amfizemde elastik geri çekilmenin azalması hangi değişikliğe yol açar?","options":["Total akciğer kapasitesinin zorunlu olarak azalması","Ekspirasyonda hava yolu kollapsı ve rezidüel volüm artışı","Difüzyon mesafesinin kısalıp DLCO'nun artması","Surfaktan üretiminin hızla çoğalması","Alveol ventilasyonunun her bölgede eşitlenmesi"],"correct":1,"exp":"Amfizemde alveol duvarları ve elastik destek azalır. Küçük hava yolları ekspirasyonda kollabe olur, hava hapsi ve rezidüel volüm artışı gelişir."},{"id":3632,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşındaki erkek hasta 2 saattir panik hissi, nefes alamama ve ellerde karıncalanma yakınmasıyla başvuruyor. Hiperventilasyon sonrası iyonize kalsiyumun azalmasını en iyi açıklayan değişiklik hangisidir?","options":["Böbrekten kalsiyum filtrasyonunun durması","Parathormonun saniyeler içinde tamamen kaybolması","Alkalozda albümine kalsiyum bağlanmasının artması","Hemoglobinin oksijene bağlanmasının imkansızlaşması","Surfaktanın alveolde yıkılması"],"correct":2,"exp":"Respiratuvar alkalozda albüminin negatif yükleri artar ve kalsiyum bağlanması yükselir. İyonize kalsiyum azalınca parestezi ve tetani bulguları gelişebilir."},{"id":3633,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"46 yaşındaki kadın hasta 3 gündür ateş, balgam ve nefes darlığı yakınmasıyla başvuruyor. Astımı var, inhaler steroid kullanıyor. Pnömoni olan akciğer bölgesinde ventilasyon azalırken perfüzyon sürerse hangi gaz değişim bozukluğu gelişir?","options":["Düşük ventilasyon-perfüzyon oranı ve hipoksemi","Ölü boşluk ventilasyonunun tek başına artması","Alveoler oksijenin kesin olarak yükselmesi","Arteriyel karbondioksitin daima sıfırlanması","Oksijen difüzyonunun perfüzyondan bağımsız hale gelmesi"],"correct":0,"exp":"Pnömonide konsolide alanda ventilasyon azalır fakat perfüzyon devam edebilir. Bu düşük V/Q oranı şant benzeri etki yaparak hipoksemiye yol açar."},{"id":3634,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"29 yaşındaki kadın hasta 12 saattir süren ani nefes darlığı ve plöritik göğüs ağrısı yakınmasıyla başvuruyor. Oral kontraseptif kullanıyor, kronik hastalığı yok. Pulmoner embolide etkilenen bölgede temel fizyolojik değişiklik hangisidir?","options":["Perfüzyonun artıp ventilasyonun sıfırlanması","Ventilasyonun korunup perfüzyonun azalmasıyla alveoler ölü boşluk artışı","Tüm akciğerde surfaktan sentezinin durması","Alveoler kapiller membranın kalınlığının azalması","Solunum merkezinin karbondioksite duyarsızlaşması"],"correct":1,"exp":"Pulmoner embolide bazı alveoller havalanır ancak perfüze olmaz. Bu fizyolojik ölü boşluğu artırır ve V/Q oranını yükseltir."},{"id":3635,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Oksijen-hemoglobin ayrışma eğrisini sağa kaydıran değişiklik hangisidir?","options":["Azalmış sıcaklık","Azalmış karbondioksit düzeyi","Artmış 2,3-BPG düzeyi","Artmış pH","Fetal hemoglobin artışı"],"correct":2,"exp":"2,3-BPG artışı hemoglobinin oksijen afinitesini azaltır ve eğriyi sağa kaydırır. Böylece dokulara oksijen bırakılması kolaylaşır. Sağ kayma için 'CADET, face Right': CO2, Acid, 2,3-DPG, Exercise, Temperature."},{"id":3636,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Surfaktanın alveoldeki temel fizyolojik etkisi aşağıdakilerden hangisidir?","options":["Yüzey gerilimini azaltarak küçük alveollerin kollabe olmasını önlemesi","Alveoler-kapiller membranı oksijene geçirimsiz hale getirmesi","Bronş düz kasını sürekli kasılı tutması","Hemoglobinin oksijen afinitesini azaltması","Karbondioksitin plazmada taşınmasını engellemesi"],"correct":0,"exp":"Surfaktan yüzey gerilimini azaltır, özellikle küçük alveollerin kollapsını önler ve akciğer kompliansını artırır. Laplace yasası bu mantığın temelidir."},{"id":3637,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yüksek irtifaya çıkan sağlıklı bir kişide ilk saatlerde arteriyel oksijen azalmasına verilen en erken ventilatuvar yanıt hangisidir?","options":["Surfaktan salgısının aniden kesilmesi","Santral kemoreseptörlerin oksijeni doğrudan algılaması","Periferik kemoreseptör uyarısıyla hiperventilasyon","Hemoglobinin tamamen methemoglobine dönüşmesi","Pulmoner venlerin sistemik arter haline gelmesi"],"correct":2,"exp":"Hipoksemi karotis ve aort cisimciklerindeki periferik kemoreseptörleri uyarır. İlk yanıt hiperventilasyondur; bu da respiratuvar alkaloza yol açabilir."},{"id":3638,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"71 yaşındaki erkek hasta 90 dakikadır süren sağ kol güçsüzlüğü ve konuşma bozukluğu yakınmasıyla getiriliyor. Hipertansiyon ve atriyal fibrilasyonu var, apiksabanı düzensiz kullanıyor. Sol orta serebral arter kortikal alanında beklenen nörolojik bulgu hangisidir?","options":["İki taraflı pitozis ve pupilla genişlemesi","Sol bacak baskın güçsüzlük ve anosmi","Sağ yüz-kol baskın güçsüzlük ve afazi","Sağ kulakta iletim tipi işitme kaybı","Saf bilateral alt motor nöron bulgusu"],"correct":2,"exp":"Dominant hemisfer MCA alanı yüz ve üst ekstremite motor korteksi ile Broca/Wernicke dil alanlarını etkileyebilir. Bu nedenle karşı yüz-kol güçsüzlüğü ve afazi beklenir."},{"id":3639,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşındaki kadın hasta 3 gündür sağ gözde ağrılı görme azalması yakınmasıyla başvuruyor. Multipl skleroz öyküsü var, interferon beta kullanıyor. Miyelin kaybının aksiyon potansiyeli iletimini bozmasının temel nedeni hangisidir?","options":["Sinaptik veziküllerin miyelin içinde depolanması","Akson çapının her zaman artması","Sodyum kanallarının yalnızca hücre gövdesinde bulunması","Ranvier düğümleri arasında saltatorik iletimin aksaması","Kalsiyumun nükleustan tamamen uzaklaşması"],"correct":3,"exp":"Miyelin internodlarda akımı izole eder ve iletimin Ranvier düğümleri arasında sıçramalı olmasını sağlar. Demiyelinizasyon iletim hızını düşürür ve iletim bloğu oluşturabilir."},{"id":3640,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"42 yaşındaki erkek hasta 5 gündür yükselen tarzda bacak güçsüzlüğü ve uyuşma yakınmasıyla başvuruyor. Kronik hastalığı yok, düzenli ilaç kullanmıyor; 2 hafta önce ishal geçirmiş. Derin tendon reflekslerinin azalmasını hangi fizyolojik bozukluk açıklar?","options":["Görme korteksinde lateral inhibisyonun artması","Kortikospinal traktusta üst motor nöron hiperaktivitesi","Bazal ganglion dopamin sentezinin artması","Serebellar Purkinje hücrelerinin aşırı uyarılması","Periferik sinir iletiminde demiyelinizasyona bağlı yavaşlama"],"correct":4,"exp":"Guillain-Barré sendromunda periferik sinir ve köklerde demiyelinizasyon olur. Refleks arkı iletimi bozulduğu için arefleksi veya hiporefleksi gelişir."},{"id":3641,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"60 yaşındaki erkek hasta 1 yıldır istirahat tremoru ve hareketlerde yavaşlama yakınmasıyla başvuruyor. Bu tabloda bazal ganglion devrelerinde hareketi azaltan değişiklik aşağıdakilerden hangisidir?","options":["Substantia nigra dopaminerjik uyarısının azalmasıyla direkt yol aktivitesinin düşmesi","Serebellar vermisin vestibüler çekirdeği baskılaması","Motor kortekste GABA'erjik iletimin baskılanması","Dorsal kolon liflerinde ağrı iletiminin artması","Hipokampusta asetilkolinin kas kasılmasını başlatması"],"correct":0,"exp":"Dopamin direkt yolu D1 üzerinden kolaylaştırır, indirekt yolu D2 üzerinden baskılar. Nigrostriatal dopamin azalınca talamokortikal aktivasyon düşer ve bradikinezi gelişir."},{"id":3642,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"19 yaşındaki erkek hasta 20 dakikadır süren jeneralize tonik-klonik nöbet sonrası değerlendiriliyor. Epilepsi öyküsü var, levetirasetam kullanıyor. İnhibitör sinaptik iletimde postsinaptik nöronu hiperpolarize eden temel iyon hareketi hangisidir?","options":["Glisin reseptörü üzerinden kalsiyum çıkışının artması","NMDA reseptörü üzerinden sodyum çıkışının artması","AMPA reseptörü üzerinden potasyum girişinin artması","GABA-A reseptörü üzerinden klorür girişinin artması","Dopamin reseptörü üzerinden klorürün pompalanması"],"correct":3,"exp":"GABA-A ligand kapılı klorür kanalıdır. Klorür iletkenliği artınca membran potansiyeli genellikle inhibisyon yönünde stabilize olur veya hiperpolarize olur."},{"id":3643,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"51 yaşındaki kadın hasta 3 aydır gece artan yanıcı ayak ağrısı yakınmasıyla başvuruyor. Diyabeti var, metformin kullanıyor. İnce miyelinsiz C liflerinin ilettiği duyusal modalite hangisidir?","options":["Hızlı motor komut","Propriyosepsiyon","Vibrasyon","Yavaş ağrı ve sıcaklık","Keskin diskriminatif dokunma"],"correct":3,"exp":"C lifleri miyelinsiz, yavaş ileten liflerdir; yavaş ağrı, sıcaklık ve otonomik bazı fonksiyonlarda rol alır. A-delta lifleri daha hızlı keskin ağrı taşır."},{"id":3644,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Dorsal kolon-medial lemniskus sistemi en belirgin olarak aşağıdaki duyulardan hangisini taşır?","options":["Otonom parasempatik çıkışı","Kaba ağrı ve sıcaklık duyusunu","Koku duyusunu","Tat duyusunu","Vibrasyon ve bilinçli propriosepsiyonu"],"correct":4,"exp":"Dorsal kolon-medial lemniskus sistemi vibrasyon, ince dokunma ve bilinçli propriosepsiyonu taşır. Ağrı ve sıcaklık daha çok anterolateral sistemle taşınır."},{"id":3645,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Uzun süreli potansiyasyonun hipokampal öğrenme modelinde postsinaptik nörona kalsiyum girişini sağlayan reseptör hangisidir?","options":["NMDA reseptörü","GABA-B reseptörü","Nikotinik asetilkolin reseptörü","Dopamin D2 reseptörü","Opioid mü reseptörü"],"correct":0,"exp":"NMDA reseptörü voltaj ve ligand bağımlı özellik taşır. Magnezyum blokunun kalkması ve glutamat bağlanmasıyla kalsiyum girişi olur; bu sinaptik güçlenmeyi tetikler."},{"id":3646,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Serebellar hemisfer lezyonunda beklenen motor bozukluk hangisidir?","options":["İpsilateral dismetri ve ataksi","Kontralateral spastik paralizi","Bilateral alt motor nöron fasikülasyonu","Primer duyu kaybı olmadan anosmi","Pupiller ışık refleksinin tek başına kaybı"],"correct":0,"exp":"Serebellum motor hareketin koordinasyonunu düzenler. Serebellar lezyonlar genellikle ipsilateral ataksi, dismetri, intansiyon tremoru ve dizartri yapar."},{"id":3647,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"64 yaşındaki erkek hasta 4 gündür halsizlik ve idrar miktarında azalma yakınmasıyla başvuruyor. Kalp yetersizliği var, furosemid kullanıyor. Efektif arteriyel kan hacmi azaldığında proksimal tübülde sodyum ve su geri emilimini artıran temel sistem hangisidir?","options":["ANP aracılı proksimal sodyum tutulumu","Anjiyotensin II aracılı proksimal sodyum geri emilimi","Dopaminin Na-K ATPazı sürekli uyarması","ADH'nin proksimal tübülü suya geçirimsiz yapması","Aldosteronun glomerülde filtrasyonu kapatması"],"correct":1,"exp":"Anjiyotensin II proksimal tübülde Na-H değiştiriciyi ve sodyum geri emilimini artırır. Hipovolemi yanıtında su ve tuz tutulumu sağlanır."},{"id":3648,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"40 yaşındaki kadın hasta 2 gündür poliüri ve aşırı susama yakınmasıyla başvuruyor. Bipolar bozukluğu var, lityum kullanıyor. Toplayıcı kanalda su geçirgenliğinin azalmasını en iyi açıklayan mekanizma hangisidir?","options":["Henle inen kolunda sodyum geri emiliminin artması","ADH yanıtıyla aquaporin-2 kanallarının lüminal membrana taşınamaması","Glomerüler filtrasyon bariyerinin glukoza geçirimsizleşmesi","Proksimal tübülde karbonik anhidrazın artması","Distal tübülde kalsiyum sekresyonunun artması"],"correct":1,"exp":"ADH V2 reseptörü üzerinden aquaporin-2 kanallarını toplayıcı kanal apikal membranına taşır. Lityum nefrojenik diabetes insipidus yaparak bu yanıtı bozabilir."},{"id":3649,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"23 yaşındaki erkek hasta yoğun egzersiz sonrası koyu idrar ve kas ağrısı tarifliyor. GFR'nin erken azalmasında afferent arteriyol tonusunu artıran lokal geri bildirim aşağıdaki yapılardan hangisiyle ilişkilidir?","options":["Distal tübülün albümin sentezlemesi","Podositlerin renin salgısını doğrudan artırması","Mezangial hücrelerin eritropoietin üretmesi","Toplayıcı kanalın glukozu filtre etmesi","Makula densanın yüksek NaCl algılamasıyla tubuloglomerüler geri bildirim"],"correct":4,"exp":"Makula densa distal tübüle gelen NaCl'yi algılar. Yüksek NaCl GFR'nin fazla olduğuna işaret eder ve afferent arteriyol vazokonstriksiyonu ile GFR azaltılır."},{"id":3650,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"52 yaşındaki erkek hasta tekrarlayan böbrek taşı ağrılarıyla başvuruyor. Medüller hiperozmolaritenin korunmasında en önemli anatomik-fizyolojik düzenek aşağıdakilerden hangisidir?","options":["Henle kulpu karşı akım çoğaltıcı sistemi ve vasa recta karşı akım değişimi","Proksimal tübülde glukozun pasif difüzyonu","Bowman kapsülünde protein geri emilimi","Üreter peristaltizminin GFR'yi artırması","Mesanede üre sentezinin artması"],"correct":0,"exp":"Henle kulpu medüller gradyenti oluşturur; vasa recta bu gradyenti yıkmadan kan akımını sağlar. Üre geri dönüşümü de iç medüller ozmolaliteye katkı verir."},{"id":3651,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"30 yaşındaki kadın hasta 12 saattir kusma sonrası halsizlik ve parestezi yakınmasıyla başvuruyor. Metabolik alkalozda böbreğin bikarbonat atma kapasitesini azaltan durum aşağıdakilerden hangisidir?","options":["Karbonik anhidraz aktivitesinin kendiliğinden durması","Aldosteron salınımının baskılanması","Hipokaleminin hidrojen sekresyonunu azaltması","Sodyum geri emiliminin tüm nefron boyunca durması","Ekstraselüler hacim azalmasına bağlı proksimal bikarbonat geri emiliminin artması"],"correct":4,"exp":"Kusma sonrası hacim kaybı RAAS'ı ve proksimal sodyum-bikarbonat geri emilimini artırır. Bu nedenle klor duyarlı metabolik alkaloz sürer."},{"id":3652,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"Glukozun böbrekte normal koşullarda en çok geri emildiği nefron segmenti hangisidir?","options":["Papiller kanal","İnce inen Henle kolu","Kalın çıkan Henle kolu","Kortikal toplayıcı kanal","Proksimal tübül"],"correct":4,"exp":"Filtre edilen glukozun büyük kısmı proksimal tübülde SGLT aracılı geri emilir. Taşıma maksimumu aşılırsa glukozüri gelişir."},{"id":3653,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"İnülin klerensinin GFR ölçümünde kullanılmasının temel nedeni aşağıdakilerden hangisidir?","options":["Glomerülden filtre edilmemesi","Plazma proteinlerine yüksek oranda bağlanması","Proksimal tübülde aktif olarak salgılanması","Serbestçe filtre edilip geri emilmemesi ve salgılanmaması","Toplayıcı kanalda su gibi geri emilmesi"],"correct":3,"exp":"İnülin serbest filtre edilir, tübülde geri emilmez ve salgılanmaz. Bu nedenle idrara geçen miktarı filtre edilen miktarı yansıtır."},{"id":3654,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kalın çıkan Henle kolunun idrarı seyreltici segment olarak adlandırılmasının nedeni hangisidir?","options":["Glukozun tamamını burada geri emmesi","Suyu yoğun biçimde geri emip elektrolit geçirmemesi","Sodyum, potasyum ve klor emmesine rağmen suya geçirgen olmaması","Albumini aktif olarak idrara salgılaması","ADH olmadığında tamamen kapanması"],"correct":2,"exp":"Kalın çıkan Henle kolu NKCC2 ile tuz geri emer, fakat suya geçirgen değildir. Bu nedenle tübül sıvısı seyrelir ve medüller gradyent oluşur."},{"id":3655,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"2 aylık erkek bebek 3 haftadır beslenirken morarma ve tekrarlayan öksürük yakınmasıyla getiriliyor. Doğuştan kalp hastalığı dışında Trakeoözofageal fistül gelişimini en iyi açıklayan embriyolojik bozukluk hangisidir?","options":["Otosistlerin böbrek toplayıcı sistemine katılması","Nöral krest hücrelerinin adrenal medullaya göç etmesi","Üçüncü faringeal arkın mandibulaya dönüşmesi","Ön bağırsağın trakea ve özofagusa ayrılmasında septasyon kusuru","Mezonefrik kanalın akciğer tomurcuğunu oluşturması"],"correct":3,"exp":"Trakea ve özofagus ön bağırsaktan gelişir. Trakeoözofageal septumun hatalı oluşumu fistül ve özofagus atrezisine yol açabilir."},{"id":3656,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"6 yaşındaki kız çocuk 2 aydır boyunda orta hatta şişlik yakınmasıyla getiriliyor. Şişlik yutkunmakla hareket ediyor. Bu yapının embriyolojik kökeniyle ilişkili kalıntı hangisidir?","options":["Tiroglossal kanal","Brankiyal yarık","Ultimobrankiyal cisim","Meckel divertikülü","Nöral tüp arka nöroporu"],"correct":0,"exp":"Tiroid primordiyumu foramen çekumdan aşağı iner. Bu iniş yolunun kapanmaması tiroglossal kanal kistine yol açabilir; orta hatta ve yutkunmakla hareketlidir."},{"id":3657,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"3 yaşındaki erkek çocuk 1 aydır boynun lateralinde akıntılı açıklık yakınmasıyla getiriliyor. Lateral servikal kist veya fistül en sık hangi embriyolojik yapının kalıntısıyla ilişkilidir?","options":["İkinci faringeal yarık","Birinci faringeal poş","Dördüncü aort arkı","Tiroglossal kanal","Nazolakrimal kanal"],"correct":0,"exp":"Lateral boyun kistleri en sık ikinci faringeal yarık kalıntısından gelişir. Orta hat tiroglossal kistten ayrılır."},{"id":3658,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"DiGeorge sendromunda hipokalsemiye yol açan paratiroid hipoplazisi hangi faringeal poşların gelişim kusuruyla ilişkilidir?","options":["Birinci faringeal yarık ve otik plakod","Birinci ve ikinci faringeal arklar","Üçüncü ve dördüncü faringeal poşlar","İkinci ve üçüncü brankiyal yarıklar","Maksiller ve mandibular çıkıntılar"],"correct":2,"exp":"Üçüncü ve dördüncü faringeal poşlar timus ve paratiroid gelişiminde rol oynar. DiGeorge sendromunda bu yapıların gelişimi bozulur."},{"id":3659,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Oksijen-hemoglobin eğrisinde fetal hemoglobinin erişkin hemoglobine göre sola kaymasının temel nedeni hangisidir?","options":["Karbondioksiti hiç bağlamaması","Demir yerine bakır taşıması","Heme grubu içermemesi","2,3-BPG'ye daha düşük afinitesi olması","Albüminle kovalent bağ kurması"],"correct":3,"exp":"Fetal hemoglobin 2,3-BPG'ye daha az bağlanır ve oksijene afinitesi daha yüksektir. Bu özellik plasentada anneden fetüse oksijen geçişini kolaylaştırır."},{"id":4721,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Acil servise kas güçsüzlüğü ve sivri T dalgaları ile gelen kronik böbrek hastasında serum potasyumu yüksek bulunuyor. Bu hastada iskelet kası hücresinin istirahat membran potansiyelinde hangi değişiklik beklenir?","options":["Membran potansiyelinin daha az negatif hale gelmesi","Membran potansiyelinin daha negatif hale gelmesi","Sodyum denge potansiyelinin potasyuma yaklaşması","Klor geçirgenliğinin tamamen kaybolması","Aksiyon potansiyeli eşik değerinin mutlak olarak sıfırlanması"],"correct":0,"exp":"Ekstrasellüler potasyum artışı potasyumun hücre dışına çıkış gradyanını azaltır ve istirahat membran potansiyelini depolarize ederek daha az negatif yapar."},{"id":4722,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Dijital zehirlenmesi olan yaşlı bir hastada Na+/K+ ATPaz baskılanıyor. Uzun süreli pompa inhibisyonunun hücre hacmi üzerine en olası etkisi hangisidir?","options":["Hücreden su çıkışı ile büzüşme","Hücre içine sodyum ve su girişi ile şişme","Hücre membranında kolesterol kaybı ile lizis","Sadece potasyumun hücre içine pasif geçişinin artması","Ozmotik gradyan oluşmadan hacmin sabit kalması"],"correct":1,"exp":"Na+/K+ ATPaz hücre içi sodyumu düşük tutar. Pompa baskılanınca sodyum hücre içinde birikir ve suyu izleyerek hücre şişmesine yol açar."},{"id":4723,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Uygunsuz ADH salınımı olan bir hastada hiponatremi gelişiyor. Plazma osmolalitesindeki bu düşüş nöronlarda en erken hangi su hareketine yol açar?","options":["Nörondan interstisyuma su çıkışı","Nöron ile plazma arasında su hareketinin durması","Ekstrasellüler alandan nöron içine su girişi","Suyun yalnızca kapiller lümende tutulması","Aquaporinlerden bağımsız aktif su atılımı"],"correct":2,"exp":"Hipotonik ekstrasellüler ortam suyun hücre içine geçmesine neden olur; beyinde bu durum hücresel şişme ve nörolojik bulgularla sonuçlanabilir."},{"id":4724,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Epinefrin verilen bir hastada karaciğerde glikojen yıkımı artıyor. Bu yanıtın hücre içi iletiminde hangi ikinci haberci yolunun baskın olması beklenir?","options":["Guanilat siklaz aktivasyonu ile cGMP artışı","Tirozin kinaz reseptör otofosforilasyonu","IP3 aracılı nükleer reseptör aktivasyonu","Gs aracılı adenilat siklaz aktivasyonu ve cAMP artışı","JAK-STAT yoluyla doğrudan DNA transkripsiyonu"],"correct":3,"exp":"Beta adrenerjik reseptörler Gs üzerinden adenilat siklazı aktive eder, cAMP ve PKA artışı glikojenolizi hızlandırır."},{"id":4725,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Nitrogliserin sonrası koroner düz kas gevşemesi belirginleşen bir hastada bu gevşemeyi doğrudan artıran hücre içi olay hangisidir?","options":["cAMP yıkımının hızlanması","Fosfolipaz C inhibisyonu","Sarkolemmal sodyum kanallarının açılması","Nükleer mineralokortikoid reseptör aktivasyonu","Guanilat siklaz aktivasyonu ile cGMP artışı"],"correct":4,"exp":"Nitrik oksit çözünür guanilat siklazı aktive ederek cGMP artırır; cGMP düz kasta kalsiyum etkisini azaltıp gevşeme sağlar."},{"id":4726,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"İnsülin reseptöründe fonksiyon kaybı olan bir hücre kültüründe glukoz taşıyıcılarının membrana taşınması azalıyor. Bu reseptör için en uygun tanım hangisidir?","options":["Ligand bağlanınca tirozin kinaz aktivitesi artan membran reseptörü","Ligand bağımsız çalışan voltaj kapılı iyon kanalı","Steroid hormonlarla aktive olan sitozolik reseptör","cGMP yıkan G protein bağlı reseptör","Hücre dışı matrikse bağlanan mekanik adezyon proteini"],"correct":0,"exp":"İnsülin reseptörü intrinsik tirozin kinaz aktivitesine sahiptir ve otofosforilasyon sonrası metabolik sinyal yollarını başlatır."},{"id":4727,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Düz kas hücresinde alfa-1 adrenerjik uyarı sonrası sitozolik kalsiyum hızla artıyor. Bu artışta hangi olay en olası ara basamaktır?","options":["cAMP üzerinden protein kinaz A aktivasyonu","IP3 aracılığıyla endoplazmik retikulumdan kalsiyum salınması","Tirozin kinaz reseptörünün insülinle uyarılması","Nükleer reseptörün DNA'ya bağlanması","Potasyum kanallarının kalıcı aktivasyonu"],"correct":1,"exp":"Alfa-1 reseptör Gq-PLC yolunu aktive eder; IP3 endoplazmik retikulumdan kalsiyum salınımını artırır."},{"id":4728,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Kemoterapi sonrası tümör dokusunda tek tek hücrelerde büzüşme ve nükleer parçalanma izleniyor, çevrede belirgin inflamasyon yok. Bu hücre ölümünde hangi özellik beklenir?","options":["Hücre membranının erken dönemde yırtılması","Lizozomal enzimlerin çevre dokuya yayılması","Kaspaz aktivasyonu ile apoptotik cisimcik oluşması","Kompleman aracılı nötrofil göçünün baskın olması","Mitokondri olmadan enerji bağımsız ilerlemesi"],"correct":2,"exp":"Apoptoz kaspaz aracılı, kontrollü hücre ölümüdür; membran bütünlüğü korunduğu için inflamasyon genellikle belirgin değildir."},{"id":4729,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"İnflamatuvar bağırsak hastalığında epitel bariyer geçirgenliği artan bir hastada paracellular geçişin artması en çok hangi hücresel bağlantının bozulmasıyla açıklanır?","options":["Desmozom","Hemidesmozom","Gap junction","Sıkı bağlantı","Fokal adezyon"],"correct":3,"exp":"Sıkı bağlantılar epitel hücreleri arasında paracellular geçirgenliği sınırlar; bozulmaları bariyer kaybına yol açar."},{"id":4730,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Bazal laminada ağ biçimli bir iskelet oluşturan başlıca kollajen tipi aşağıdakilerden hangisidir?","options":["Tip I","Tip II","Tip III","Tip IV","Tip V"],"correct":3,"exp":"Tip IV kollajen fibril oluşturmaz; bazal laminada laminin ve diğer matriks bileşenleriyle birlikte ağ biçimli bir yapı kurar. Tip I kemik, tendon ve deride; tip II kıkırdakta; tip III retiküler liflerde belirgindir."},{"id":4731,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Eklem kıkırdağı hasarı sonrası iyileşmenin sınırlı olmasının temel nedeni hangisidir?","options":["Hyalin kıkırdağın avasküler olup beslenmesini difüzyonla sağlaması","Kondroblastların sadece kemik iliğinde bulunması","Kıkırdakta proteoglikan sentezinin hiç olmaması","Tip II kollajenin bağ dokusunda bulunmaması","Kondrositlerin sinir uçlarıyla doğrudan innerve olması"],"correct":0,"exp":"Hyalin kıkırdak avaskülerdir; beslenme difüzyonla olduğu için onarım kapasitesi sınırlıdır."},{"id":4732,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Glomerüler bazal membran yapısını bozan genetik bir hastalıkta filtrasyon bariyeri zayıflıyor. Bazal laminanın temel yapısal bileşeni olarak hangi protein çifti beklenir?","options":["Tip I kollajen ve elastin","Keratin ve desmin","Aktin ve miyozin","Fibrinojen ve trombin","Tip IV kollajen ve laminin"],"correct":4,"exp":"Bazal lamina özellikle tip IV kollajen ve laminin içerir; epitel desteği ve seçici bariyer fonksiyonunda rol oynar."},{"id":4733,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Tekrarlayan sinüzit ve infertilite öyküsü olan bir erkekte primer siliyer diskinezi düşünülüyor. Bu tabloda bozuk olan yapı hangisidir?","options":["Keratin ara filamentleri","Hemidesmozomal integrinler","Dynein kolları","Tip I kollajen lifleri","Bazal membran laminini"],"correct":2,"exp":"Siliyer hareket mikrotübül dynein kollarına bağlıdır; bozukluk mukosiliyer klirens ve sperm motilitesini azaltır."},{"id":4734,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Kalp kası hücreleri arasında elektriksel uyarının hızlı yayılması hangi bağlantı yapısının işleviyle en iyi açıklanır?","options":["Sıkı bağlantı","Hemidesmozom","Zonula adherens","Gap junction","Bazal lamina"],"correct":3,"exp":"Gap junctionlar connexon kanallarıyla iyon geçişine izin verir ve kalp kasında elektriksel senkronizasyonu sağlar."},{"id":4735,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Yara iyileşmesinin erken granülasyon döneminde geçici matriksin daha esnek kurulmasını sağlayan kollajen tipi hangisidir?","options":["Tip II kollajen","Tip IV kollajen","Tip VII kollajen","Tip X kollajen","Tip III kollajen"],"correct":4,"exp":"Erken yara iyileşmesinde tip III kollajen baskındır; daha sonra yerini daha dayanıklı tip I kollajene bırakır."},{"id":4736,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Kronik inflamasyon odağında antijen sunumu ve fagositoz kapasitesi artmış hücreler baskın hale geliyor. Bu hücrelerin en olası kökeni hangisidir?","options":["Monositlerden farklılaşan makrofajlar","Megakaryositlerden kopan sitoplazmik parçalar","Eritroid öncül hücreler","Adipositlerden dönüşen mast hücreleri","Keratinositlerden gelişen lenfositler"],"correct":0,"exp":"Makrofajlar monosit kökenlidir; fagositoz, sitokin salınımı ve MHC II ile antijen sunumunda görev alır."},{"id":4737,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Miyastenia gravisli bir kadında tekrarlayan kullanım sonrası göz kapağı düşüklüğü artıyor. Nöromüsküler kavşakta hangi değişiklik kas aksiyon potansiyeli oluşmasını zorlaştırır?","options":["Asetilkolin salınımının kalsiyumdan bağımsız hale gelmesi","Motor son plak potansiyelinin amplitüdünün azalması","Kas hücresinde troponin C miktarının artması","Sarkomer boyunun optimal aralığa gelmesi","Asetilkolinesteraz aktivitesinin tamamen kaybolması"],"correct":1,"exp":"Postsinaptik nikotinik reseptör azalması son plak potansiyelini küçültür ve eşik değere ulaşmayı zorlaştırır."},{"id":4738,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Genel anestezi sonrası ateş, rijidite ve metabolik asidoz gelişen bir hastada malign hipertermi düşünülüyor. İskelet kasında primer olarak hangi olay artmıştır?","options":["SERCA pompasının aşırı aktivasyonu ile sitozolik kalsiyum azalması","Asetilkolin veziküllerinin presinaptik tükenmesi","Ryanodin reseptöründen kontrolsüz kalsiyum salınımı","Troponin I'nin aktine bağlanmasının kalıcı artması","Miyozin ATPaz aktivitesinin tamamen durması"],"correct":2,"exp":"Malign hipertermide ryanodin reseptör bozukluğu sarkoplazmik retikulumdan aşırı kalsiyum salınımına ve kas kontraksiyonuna yol açar."},{"id":4739,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"İskelet kasında kalsiyum artışı sonrası aktin-miyozin etkileşimi başlıyor. Kalsiyumun bağlandığı düzenleyici protein hangisidir?","options":["Tropomiyozin","Miyozin hafif zincir kinaz","Nebulin","Distrofin","Troponin C"],"correct":4,"exp":"İskelet ve kalp kasında kalsiyum troponin C'ye bağlanır; tropomiyozin yer değiştirerek aktin üzerindeki bağlanma bölgelerini açar."},{"id":4740,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Bronş düz kasında kolinerjik uyarı sonrası kasılma artıyor. Düz kas kasılmasında iskelet kasından farklı olarak hangi olay zorunludur?","options":["Troponin C'ye kalsiyum bağlanması","Dihidropiridin reseptörünün mekanik kapı görevi görmesi","Sarkomer Z çizgilerinin yaklaşması","Tropomiyozinin aktinden tamamen ayrılması","Miyozin hafif zincirinin fosforilasyonu"],"correct":4,"exp":"Düz kasta kalsiyum-kalmodulin MLCK'yi aktive eder; miyozin hafif zinciri fosforilasyonu kasılmayı başlatır."},{"id":4741,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"İskelet kası lifi çok kısa veya çok uzun başlangıç uzunluğunda daha az güç üretiyor. Maksimal aktif gerilim hangi durumda beklenir?","options":["Aktin ve miyozin filament örtüşmesinin optimal olduğu sarkomer uzunluğunda","Aktin filamentlerinin birbirini tamamen üst üste örttüğü en kısa uzunlukta","Miyozin başlarının aktine hiç ulaşamadığı en uzun uzunlukta","Sarkoplazmik retikulum kalsiyumunun tamamen boşaldığı durumda","ATP bulunmadığı için çapraz köprülerin kilitlendiği durumda"],"correct":0,"exp":"Uzunluk-gerilim ilişkisi optimal aktin-miyozin örtüşmesinde en yüksek aktif gerilimin oluşmasını açıklar."},{"id":4742,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Kalp kasında tetani gelişmemesi iskelet kasına göre uzun refrakter dönemle ilişkilidir. Bu uzun refrakter döneme en çok katkı sağlayan olay hangisidir?","options":["Hızlı sodyum kanallarının hiç açılmaması","L tipi kalsiyum kanallarına bağlı plato fazı","Klor kanallarının aksiyon potansiyelini başlatması","Asetilkolinesterazın interkale diskte bulunması","Troponin kompleksinin kalpte olmaması"],"correct":1,"exp":"Kalp aksiyon potansiyelindeki plato fazı L tipi kalsiyum girişiyle uzar ve uzun refrakter dönem tetaniyi engeller."},{"id":4743,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Ölümden birkaç saat sonra gelişen rigor mortiste kaslar sertleşir. Bu sertliğin temel nedeni hangisidir?","options":["Asetilkolin reseptörlerinin aşırı yıkılması","Troponin C'nin kalsiyuma bağlanamaması","ATP eksikliği nedeniyle miyozinin aktinden ayrılamaması","Miyozin hafif zincir fosfatazının aşırı çalışması","Sarkomerlerin pasif olarak tamamen uzaması"],"correct":2,"exp":"ATP miyozin başının aktinden ayrılması için gereklidir; ATP tükenince çapraz köprüler kilitli kalır."},{"id":4744,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Yokuş aşağı koşu sonrası kas ağrısı gelişen bir kişide egzersiz sırasında kas aktifken uzamıştır. Bu kontraksiyon tipi için hangisi doğrudur?","options":["İzometrik kontraksiyonda kas boyu kısalır","Konsantrik kontraksiyonda yük kası uzatır","Pasif gerilim tamamen ortadan kalkar","Eksantrik kontraksiyonda aktif kas uzarken yüksek gerilim üretir","Çapraz köprü siklusu ATP kullanmaz"],"correct":3,"exp":"Eksantrik kontraksiyonda kas aktif olduğu halde dış yük nedeniyle uzar; yüksek gerilim ve mikrozedeleme daha belirgindir."},{"id":4745,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Spermatogenez bozukluğu olan bir erkekte FSH yüksek, testis hacmi küçüktür. Sertoli hücre fonksiyonunu yansıtan ve FSH üzerine negatif geri bildirim yapan hormon hangisidir?","options":["Testosteron","LH","Progesteron","Estradiol","İnhibin B"],"correct":4,"exp":"İnhibin B Sertoli hücrelerinden salınır ve FSH sekresyonunu baskılar; spermatogenez kapasitesini yansıtır."},{"id":4746,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Hipogonadotropik hipogonadizmi olan bir erkekte LH düzeyi düşük bulunuyor. LH eksikliğinde öncelikle hangi hücresel ürün azalır?","options":["Leydig hücresinden testosteron üretimi","Sertoli hücresinden inhibin B üretimi","Epididimden sperm matürasyonu","Granüloza hücresinden aromataz aktivitesi","Prostat epitelinden sitrat salınımı"],"correct":0,"exp":"LH testiste Leydig hücrelerini uyararak testosteron sentezini artırır."},{"id":4747,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Kadın genital kanalında ilerleyen sperm hücresinin zona pellucidaya bağlanma ve akrozom reaksiyonu kapasitesi kazanması için hangi süreç gereklidir?","options":["Spermatidlerin mayoz I'i tamamlaması","Kapasitasyon","Korpus luteum regresyonu","Endometriyal deskuamasyon","Tübüler sıvıda FSH sentezi"],"correct":1,"exp":"Kapasitasyon sperm membranında değişiklikler oluşturarak zona bağlanması ve akrozom reaksiyonu için gerekli hale getirir."},{"id":4748,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Ovulasyondan sonra endometriumda bezler kıvrımlı ve salgılayıcı hale geliyor. Bu histofizyolojik değişim en çok hangi hormonun etkisiyle oluşur?","options":["FSH","Oksitosin","Progesteron","Prolaktin","GnRH"],"correct":2,"exp":"Progesteron luteal fazda endometriumu sekretuar faza geçirir ve implantasyona hazırlar."},{"id":4749,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Menstrüasyon sonrası endometriumun yeniden kalınlaşması ve stromal proliferasyonun artması hangi hormonal etkiyle en iyi açıklanır?","options":["Progesteronun sekretuar etkisi","hCG'nin luteotropik etkisi","İnhibin B'nin FSH baskılaması","Östrojenin proliferatif etkisi","Relaksinin serviksi yumuşatması"],"correct":3,"exp":"Foliküler fazda östrojen endometriumun proliferatif yenilenmesini sağlar."},{"id":4750,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Erken gebelikte korpus luteumun devamlılığını sağlayan sinyal kaybolursa progesteron hızla düşer. Bu dönemde korpus luteumu sürdüren hormon hangisidir?","options":["FSH","LH","Oksitosin","Prolaktin","hCG"],"correct":4,"exp":"Trofoblast kaynaklı hCG LH benzeri etkiyle korpus luteumu korur ve erken gebelikte progesteron üretimini sürdürür."},{"id":4751,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Bilateral inmemiş testisi olan bir çocukta ileride infertilite riski artar. Spermatogenez için skrotal yerleşimin avantajı hangisidir?","options":["Testis sıcaklığının vücut sıcaklığından düşük tutulması","Leydig hücresinde FSH reseptörünün artması","Epididimde mayoz bölünmenin başlaması","Prostat sekresyonunun tamamen durması","Sertoli hücresinin testosteron üretmesi"],"correct":0,"exp":"Spermatogenez için testis sıcaklığının vücut sıcaklığından birkaç derece düşük olması gerekir."},{"id":4752,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Fertilizasyon sırasında sperm zona pellucidayı geçebilmek için enzimlerini serbest bırakır. Bu olay hangi yapıdan kaynaklanır?","options":["Mitokondriyal kılıf","Akrozom","Annulus","Sentriyol","Kortikal granül"],"correct":1,"exp":"Akrozom sperm başında yer alır ve zona pellucidayı aşmaya yardım eden enzimleri içerir."},{"id":4753,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Üçüncü gebelik haftasında primitif çizgi üzerinden hücre göçü bozulursa embriyonik tabakaların oluşumu etkilenir. Bu süreçte temel olarak hangi olay gerçekleşir?","options":["Nöral tüpün kranial kapanması","Plasental villuslarda gaz değişimi","Ektodermden mezoderm ve endoderm gelişiminin başlaması","Somitlerin dermatom ve sklerotoma ayrılması","Faringeal arkusların kıkırdaklaşması"],"correct":2,"exp":"Gastrulasyon primitif çizgi üzerinden hücre göçüyle üç germ yaprağının oluştuğu süreçtir."},{"id":4754,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Gebelik öncesi folat desteği almayan bir annede nöral tüp defekti riski artar. Bu kusurun önlenmesinde kritik dönem en çok hangi yapı kapanmasıyla ilişkilidir?","options":["Primitif kalp tüpünün kıvrılması","Ürogenital sinüsün bölünmesi","Lens plakodunun invajinasyonu","Nöral tüp nöroporlarının kapanması","Korpus luteumun regresyonu"],"correct":3,"exp":"Folat eksikliği nöral tüp kapanma defektleri riskini artırır; kapanma gebeliğin erken haftalarında gerçekleşir."},{"id":4755,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Nöral plak gelişimi erken embriyoda alttaki aksiyel mezodermden gelen indüksiyonla başlar. Bu indükleyici yapı hangisidir?","options":["Amniyon","Yolk kesesi","Allantois","Koriyonik plak","Notokord"],"correct":4,"exp":"Notokord üzerindeki ektodermi indükleyerek nöral plak ve santral sinir sistemi gelişimini başlatır."},{"id":4756,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Döllenmeden sonraki ilk iki haftada yüksek doz teratojene maruz kalan embriyoda ya kayıp olur ya da kalıcı malformasyon gelişmeyebilir. Bu dönem için en uygun ifade hangisidir?","options":["Ya hep ya hiç dönemidir","Organogenez malformasyonlarının en yoğun dönemidir","Fetal büyüme geriliğinin tek dönemidir","Plasental bariyerin tamamen kapandığı dönemdir","Nöral krest migrasyonunun tamamlandığı dönemdir"],"correct":0,"exp":"Preimplantasyon ve erken implantasyon döneminde ağır hasar embriyo kaybına yol açabilir; sağ kalırsa malformasyon beklenmeyebilir."},{"id":4757,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Gebeliğin çok erken döneminde anne serumunda saptanan hCG'nin temel kaynağı hangi trofoblastik yapıdır?","options":["Sitotrofoblast","Sinsityotrofoblast","Amniyoblast","Epiblast","Hipoblast"],"correct":1,"exp":"Sinsityotrofoblast hCG salgılayarak korpus luteumun devamını sağlar."},{"id":4758,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Tek yumurta ikizlerinde embriyonik diskin geç ayrılması sonucu iki fetüs aynı amniyon ve aynı koriyonu paylaşır. Bu ayrılma en olası hangi dönemde olmuştur?","options":["Döllenmeden önce oogenez sırasında","İki hücreli blastomer döneminde","Bilaminar embriyonik disk oluştuktan sonra","Morula kompaksiyonu tamamlanmadan önce","Fertilizasyondan hemen önce"],"correct":2,"exp":"Geç ayrılma, özellikle amniyon oluştuktan sonra olursa monoamniyotik monokoryonik ikizlik gelişir."},{"id":4759,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Paraksiyel mezoderm gelişimindeki bozukluk vertebra ve iskelet kası gelişimini etkiliyor. Bu yapıların kaynağı olan segmental oluşum hangisidir?","options":["Nöral tüp","Lateral plak mezoderm","Primitif düğüm","Somit","Koriyon villusu"],"correct":3,"exp":"Somitler sklerotom, miyotom ve dermatom bölümlerine ayrılarak aksiyel iskelet, iskelet kası ve dermisin bir kısmını oluşturur."},{"id":4760,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Anne-fetüs gaz ve besin alışverişinin gerçekleştiği plasental fonksiyonel yüzey öncelikle hangi yapı üzerinden sağlanır?","options":["Amniyon zarı","Yolk kesesi duvarı","Allantois lümeni","Primitif çizgi","Koriyon villusları"],"correct":4,"exp":"Koriyon villusları maternal kanla temas eden geniş yüzey oluşturarak plasental değişimin temelini sağlar."},{"id":4761,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Kronik akciğer hastalığı olan bir erkekte hematokrit yüksek bulunuyor. Hipoksiye yanıt olarak eritropoezi artıran hormonun erişkinde başlıca üretim yeri hangisidir?","options":["Dalak beyaz pulpası","Karaciğer Kupffer hücreleri","Böbrek peritübüler interstisyel hücreleri","Kemik iliği megakaryositleri","Timus kortikal epiteli"],"correct":2,"exp":"Erişkinde eritropoietin büyük ölçüde böbrek peritübüler interstisyel hücrelerinden salınır ve hipoksiyle artar."},{"id":4762,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Kronik hipokside eritrosit 2,3-BPG düzeyi artıyor. Bu artışın dokulara oksijen sunumu açısından beklenen etkisi hangisidir?","options":["Hemoglobinin oksijene afinitesini artırarak eğriyi sola kaydırması","Hemoglobinin oksijene afinitesini azaltarak eğriyi sağa kaydırması","Methemoglobin oluşumunu engelleyerek PaO2'yi yükseltmesi","Plazma bikarbonatını azaltarak ventilasyonu durdurması","Eritrosit yaşam süresini dakikalar düzeyine indirmesi"],"correct":1,"exp":"2,3-BPG hemoglobinin oksijene afinitesini azaltır ve oksijenin dokulara bırakılmasını kolaylaştırır."},{"id":4763,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Yenidoğanda fetal hemoglobinin oksijen satürasyonu erişkine göre daha yüksek seyreder. Fetal hemoglobinin bu özelliği en iyi hangi nedenle açıklanır?","options":["Karbon monoksite bağlanamaması","Hem grubunun demir içermemesi","2,3-BPG'ye daha düşük afinite göstermesi","Oksijeni yalnızca venöz kanda bağlaması","Eritrosit membranında spektrin taşımaması"],"correct":2,"exp":"HbF, 2,3-BPG'ye daha zayıf bağlanır; bu nedenle oksijene afinitesi daha yüksektir ve plasental oksijen alımını kolaylaştırır."},{"id":4764,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Burun kanamaları olan bir çocukta trombosit sayısı normal, ancak adezyon kusuru saptanıyor. Subendotelyal kollajene trombosit tutunmasında hangi etkileşim kritiktir?","options":["Fibrinojen ile GPIIb/IIIa","Trombin ile antitrombin","Protein C ile trombomodulin","vWF ile GPIb","Plazmin ile fibrin"],"correct":3,"exp":"Trombosit adezyonunda von Willebrand faktörü subendotelyal kollajen ile trombosit GPIb reseptörü arasında köprü görevi görür."},{"id":4765,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Warfarin başlanan hastada ilk uzayan koagülasyon testi protrombin zamanı oluyor. Bu duyarlılık en çok hangi faktör yoluyla açıklanır?","options":["Faktör XII","Faktör XI","Faktör VIII","Faktör XIII","Faktör VII"],"correct":4,"exp":"Ekstrinsik yol faktör VII ile değerlendirilir; kısa yarı ömrü nedeniyle PT warfarine erken duyarlıdır."},{"id":4766,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Kronik inflamasyonu olan hastada serum demiri düşük, ferritin yüksek ve hepsidin artmıştır. Hepsidin artışı demir metabolizmasını nasıl etkiler?","options":["Ferroportini inhibe ederek demirin plazmaya çıkışını azaltır","Duedonumda demir emilimini sınırsız artırır","Transferrini hemoglobine dönüştürür","Eritropoietin reseptörünü aktive eder","Ferritini eritrosit membranına taşır"],"correct":0,"exp":"Hepsidin ferroportini baskılar; enterosit ve makrofajlardan kana demir çıkışı azalır, inflamasyon anemisi gelişir."},{"id":4767,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Tekrarlayan bakteriyel enfeksiyonları olan bir çocukta nötrofillerin damar dışına geçemediği saptanıyor. Lökosit adezyon eksikliğinde beklenen bozukluk hangisidir?","options":["Selektin ligandlarının eritrositte artması","CD18 integrin aracılı sıkı adezyonun bozulması","Nötrofil myeloperoksidazının aşırı çalışması","T hücre reseptör rekombinasyonunun artması","Kompleman C3'ün trombine dönüşmesi"],"correct":1,"exp":"LAD tip 1'de CD18 integrin bozukluğu sıkı adezyonu ve transmigrasyonu engeller."},{"id":4768,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Lenf nodu biyopsisinde T lenfositlerin yoğun olduğu bölge değerlendirilmek isteniyor. Bu hücrelerin baskın bulunduğu alan hangisidir?","options":["Primer folikül germinal merkezi","Medüller sinüs","Parakorteks","Kırmızı pulpa kordonları","Subkapsüler yağ dokusu"],"correct":2,"exp":"Lenf nodunda parakorteks T hücre bölgesidir; foliküller ise B hücrelerden zengindir."},{"id":4769,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Zollinger-Ellison sendromlu hastada belirgin asit hipersekresyonu ve peptik ülserler izleniyor. Gastrinin parietal hücre asit salgısını artırmasında en önemli ara hücre hangisidir?","options":["D hücresi","I hücresi","S hücresi","ECL hücresi","Goblet hücresi"],"correct":3,"exp":"Gastrin ECL hücrelerinden histamin salınımını artırır; histamin H2 reseptörleri üzerinden parietal hücre asit sekresyonunu güçlendirir."},{"id":4770,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Asidik kimus duodenuma geçtiğinde pankreas kanal hücrelerinden bikarbonat salınımı artar. Bu yanıtı en güçlü uyaran hormon hangisidir?","options":["Gastrin","Motilin","Ghrelin","Somatostatin","Sekretin"],"correct":4,"exp":"Sekretin duodenal asitle uyarılır ve pankreas kanal hücrelerinden bikarbonatça zengin sıvı salınımını artırır."},{"id":4771,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Yağlı yemek sonrası safra kesesi kasılması ve pankreatik enzim sekresyonu artıyor. Bu yanıtı başlatan başlıca hormon hangisidir?","options":["Kolesistokinin","Sekretin","Gastrin","GIP","Motilin"],"correct":0,"exp":"Kolesistokinin yağ ve aminoasitlerle uyarılır; safra kesesini kasar ve pankreas asiner enzim sekresyonunu artırır."},{"id":4772,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Vagal uyarı mide asit sekresyonunu artırırken G hücrelerini de aktive eder. Vagusun G hücresinde gastrin salınımını artıran nörotransmitteri hangisidir?","options":["Somatostatin","Gastrin salgılatıcı peptid","Sekretin","Histamin","Nitrik oksit"],"correct":1,"exp":"Vagus parietal hücreleri asetilkolinle uyarırken G hücrelerinde gastrin salınımını GRP üzerinden artırır."},{"id":4773,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Terminal ileum rezeksiyonu sonrası yağlı dışkılama gelişen hastada safra tuzu havuzu azalıyor. Bu malabsorpsiyonun temel nedeni hangisidir?","options":["Mide intrinsic faktörünün aşırı artması","Pankreatik amilazın aktive olmaması","Safra tuzlarının enterohepatik dolaşıma geri alınamaması","Kolonda kısa zincirli yağ asidi üretiminin artması","Gastrinin parietal hücreleri uyarmaması"],"correct":2,"exp":"Safra tuzları terminal ileumda geri emilir; rezeksiyon safra tuzu kaybı ve yağ emilim bozukluğu yapar."},{"id":4774,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Otoimmün gastriti olan hastada makrositik anemi gelişiyor. B12 emilimi için gerekli faktör ve emilim yeri hangi seçenekte birlikte verilmiştir?","options":["Sekretin ve jejunum","Gastrin ve mide korpusu","Pepsinojen ve duodenum","Intrinsic faktör ve terminal ileum","Kolesistokinin ve kolon"],"correct":3,"exp":"Parietal hücre kaynaklı intrinsic faktör B12 ile kompleks oluşturur ve terminal ileumdan emilimi sağlar."},{"id":4775,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Aynı miktarda glukoz oral verildiğinde intravenöz verilmesine göre daha fazla insülin yanıtı oluşuyor. Bu farkı açıklayan hormon grubu hangisidir?","options":["Katekolaminler","Mineralokortikoidler","Tiroid hormonları","Somatomedinler","İnkretinler"],"correct":4,"exp":"GIP ve GLP-1 gibi inkretinler oral besin alımı sonrası glukoza bağımlı insülin sekresyonunu artırır."},{"id":4776,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Primer hiperaldosteronizmi olan hastada kolonda elektrolit taşınması değişiyor. Kolon epitelinde beklenen net etki hangisidir?","options":["Sodyum emiliminin ve potasyum sekresyonunun artması","Klor emiliminin tamamen durması","Bikarbonat salınımının tümüyle kaybolması","Glukoz emiliminin SGLT1'den bağımsızlaşması","Safra tuzu geri emiliminin kolona kayması"],"correct":0,"exp":"Aldosteron distal kolon dahil epitellerde sodyum emilimini artırırken potasyum sekresyonunu kolaylaştırır."},{"id":4777,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sağlıklı bir kişiye sıvı yüklenmesinden sonra atım hacmi artıyor. Frank-Starling mekanizmasına göre bu artışın temel açıklaması hangisidir?","options":["Diyastol sonu hacmin artmasıyla sarkomer uzunluğunun daha uygun düzeye gelmesi ve kasılma gücünün artması","Kalp hızının zorunlu olarak azalması","Ard yükün artmasıyla aort kapağının daha geç kapanması","Atriyoventriküler düğüm iletiminin baskılanması","Koroner kan akımının yalnız sistolde artması"],"correct":0,"exp":"Artan venöz dönüş diyastol sonu hacmi ve miyokard lif uzunluğunu artırır. Sarkomerlerin daha uygun çalışma uzunluğuna gelmesi ve uzunluğa bağlı aktivasyon, kasılma gücü ile atım hacmini artırır."},{"id":4778,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Akut aort basıncı artan bir hastada sol ventrikül aynı preload ve kontraktilitede çalışıyor. Afterload artışının beklenen ilk etkisi hangisidir?","options":["Atım hacminin artması","Ejeksiyon süresinin kısalması ve atım hacminin değişmemesi","Atım hacminin azalması ve diyastol sonu hacmin artma eğilimi","Venöz dönüşün doğrudan sıfırlanması","Kalp kasında refrakter dönemin kaybolması"],"correct":2,"exp":"Afterload artışı ventrikülün kanı boşaltmasını zorlaştırır; atım hacmi azalır ve rezidüel hacim artabilir."},{"id":4779,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Boyun masajı sırasında karotis sinüs baroreseptörleri geriliyor ve hastanın kalp hızı düşüyor. Bu refleks yanıtta hangi otonom değişiklik baskındır?","options":["Sempatik çıkış artışı ve taşikardi","Vagal tonus azalması ve taşikardi","Renin salınımı artışı","Vagal tonus artışı ve sempatik çıkış azalması","Adrenal medulladan kortizol salınımı"],"correct":3,"exp":"Baroreseptör gerilimi artınca medüller merkezler vagal aktiviteyi artırır, sempatik aktiviteyi azaltır ve kalp hızı düşer."},{"id":4780,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Yoğun bakımda pulmoner kapiller kama basıncı yüksek bulunan bir hastada sol kalp dolum basıncı değerlendirilmek isteniyor. Bu ölçüm en çok hangi basıncı yansıtır?","options":["Sağ atriyum basıncı","Pulmoner arter sistolik basıncı","Aort nabız basıncı","Serebral perfüzyon basıncı","Sol atriyum basıncı"],"correct":4,"exp":"Pulmoner kapiller kama basıncı, mitral kapak ve pulmoner venöz engel yoksa sol atriyum basıncını yansıtır."},{"id":4781,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Tam AV bloklu hastada juguler venöz nabızda aralıklı dev a dalgaları izleniyor. Bu bulgu hangi olayla açıklanır?","options":["Atriyumun kapalı triküspit kapağa karşı kasılması","Sağ ventrikülün sistolde gevşemesi","Aort kapağının diyastolde açılması","Sol atriyum basıncının sıfırlanması","Pulmoner venlerin kollabe olması"],"correct":0,"exp":"AV disosiyasyonda atriyum bazen kapalı triküspit kapağa karşı kasılır ve cannon a dalgası oluşur."},{"id":4782,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Konjestif kalp yetmezliği olan hastada ayak bileği ödemi belirgindir. Starling kuvvetleri açısından bu ödemi en iyi açıklayan değişiklik hangisidir?","options":["Plazma onkotik basıncının artması","Kapiller hidrostatik basıncın artması","Lenf akımının aşırı artması","İnterstisyel hidrostatik basıncın çok negatifleşmemesi","Kapiller filtrasyon katsayısının sıfırlanması"],"correct":1,"exp":"Venöz basınç artışı kapiller hidrostatik basıncı yükseltir ve interstisyuma sıvı filtrasyonunu artırır."},{"id":4783,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Taşikardi sırasında koroner iskemi gelişen hastada sol ventrikül miyokardı özellikle etkileniyor. Sol koroner perfüzyonun esas olarak diyastolde olmasının nedeni hangisidir?","options":["Aort basıncının diyastolde sıfır olması","Koroner damarların sistolde sol ventrikül basıncıyla sıkışması","Koroner arterlerde kapak bulunmaması","Hemoglobinin diyastolde oksijen bağlamaması","Pulmoner ven basıncının koroner akımı belirlemesi"],"correct":1,"exp":"Sol ventrikül sistolünde intramiyokardiyal basınç koroner damarları sıkıştırır; perfüzyon daha çok diyastolde olur."},{"id":4784,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"AV düğümde iletinin yavaş olması atriyumların ventriküllerden önce boşalmasına izin verir. AV düğüm hücrelerinde faz 0 depolarizasyonundan esas sorumlu akım hangisidir?","options":["Hızlı sodyum girişi","Klor çıkışı","Potasyum girişi","Kalsiyum girişi","Magnezyum çıkışı"],"correct":3,"exp":"AV ve SA nodal hücrelerinde hızlı depolarizasyon esas olarak L tipi kalsiyum kanallarından kalsiyum girişiyle olur."},{"id":4785,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Yüksek iyot alımı sonrası tiroid hormon sentezi geçici olarak baskılanıyor. Bu yanıt hangi fizyolojik etkiyle adlandırılır?","options":["Jod-Basedow etkisi","Somogyi etkisi","Dawn fenomeni","Cushing refleksi","Wolff-Chaikoff etkisi"],"correct":4,"exp":"Aşırı iyot yükü tiroid hormon organifikasyonunu geçici baskılar; bu Wolff-Chaikoff etkisidir."},{"id":4786,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Kilo kaybı, hipotansiyon, hiponatremi ve hiperpigmentasyonla gelen hastada primer adrenal yetmezlik düşünülüyor. Hiperpigmentasyonu en iyi açıklayan değişiklik hangisidir?","options":["ACTH ve POMC türevlerinin artması","TSH reseptörlerinin baskılanması","Aldosteronun melanositleri inhibe etmesi","İnsülinin melanin yıkımını artırması","Kortizol fazlalığının deriyi inceltmesi"],"correct":0,"exp":"Primer adrenal yetmezlikte kortizol düşer, ACTH yükselir; POMC türevleri melanokortin etkisiyle hiperpigmentasyon yapar."},{"id":4787,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Hipokalsemi gelişen hastada PTH salınımı artıyor. Böbrekte PTH etkisi için en doğru ifade hangisidir?","options":["Proksimal tübülde fosfat geri emilimini artırır","Distal tübülde kalsiyum geri emilimini artırır ve proksimal fosfat geri emilimini azaltır","Toplayıcı kanalda su geçirgenliğini azaltır","Henle inen kolunda sodyum emilimini durdurur","Glomerül filtrasyon bariyerinde albümin geçirgenliğini artırır"],"correct":1,"exp":"PTH distal nefronda kalsiyum geri emilimini artırır, proksimal tübülde fosfat geri emilimini azaltır."},{"id":4788,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Pankreas beta hücresinde glukoz artışı sonrası insülin sekresyonu başlıyor. Sekresyonu başlatan membran olayı hangisidir?","options":["Na+/K+ ATPazın tamamen durması","Kalsiyum kanallarının kapanması","ATP duyarlı potasyum kanallarının kapanmasıyla depolarizasyon","Glukagon reseptörünün beta hücrede yıkılması","Klor kanallarından masif klor girişi"],"correct":2,"exp":"Glukoz metabolizması ATP'yi artırır, KATP kanalları kapanır, depolarizasyon ve kalsiyum girişi insülin salınımını tetikler."},{"id":4789,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Santral diabetes insipiduslu hastaya desmopressin verildikten sonra idrar osmolalitesi artıyor. ADH'nin toplayıcı kanaldaki temel etkisi hangisidir?","options":["ENaC kanallarını tamamen yıkmak","Glukoz taşıyıcılarını apikal membrana taşımak","Fosfat atılımını artırmak","Aquaporin-2 kanallarını apikal membrana yerleştirmek","Ürik asit sentezini durdurmak"],"correct":3,"exp":"ADH V2 reseptörü üzerinden aquaporin-2'nin apikal membrana eklenmesini sağlar ve su geri emilimini artırır."},{"id":4790,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Akromegalili hastada yumuşak doku büyümesi ve insülin direnci izleniyor. Büyüme hormonunun lineer büyüme üzerindeki birçok etkisi hangi mediyatörle gerçekleşir?","options":["Kortizol","Aldosteron","Prolaktin","Kalsitonin","IGF-1"],"correct":4,"exp":"Büyüme hormonu karaciğer ve dokularda IGF-1 üretimini artırır; büyüme etkilerinin çoğu IGF-1 aracılıdır."},{"id":4791,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Antipsikotik kullanan kadında galaktore ve amenore gelişiyor. Bu tablo dopaminerjik blokajın hangi hipofizer etkisiyle açıklanır?","options":["Prolaktin salınımının artması","ACTH salınımının azalması","TSH salınımının tamamen durması","FSH reseptörlerinin overde yıkılması","Oksitosinin adrenal korteksten salınması"],"correct":0,"exp":"Dopamin prolaktin salınımını tonik olarak inhibe eder; dopamin blokajı hiperprolaktinemiye yol açar."},{"id":4792,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Primer hiperaldosteronizmli hastada hipokalemi ve metabolik alkaloz saptanıyor. Aldosteronun kortikal toplayıcı kanaldaki temel etkisi hangisidir?","options":["A tipi interkale hücrede bikarbonat sekresyonunu artırması","Principal hücrede sodyum geri emilimini ve potasyum sekresyonunu artırması","Proksimal tübülde glukoz atılımını artırması","Henle inen kolunu suya geçirimsiz hale getirmesi","Glomerül bazal membranını kalınlaştırması"],"correct":1,"exp":"Aldosteron principal hücrelerde ENaC ve Na+/K+ ATPaz aktivitesini artırır; sodyum tutulur, potasyum ve hidrojen sekresyonu artar."},{"id":4793,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Ani dispne ve plöritik ağrı ile gelen hastada pulmoner emboli düşünülüyor. Arteriyel oksijen düşüklüğüne rağmen alveoler oksijenin görece korunması hangi bulguyu artırır?","options":["Serum bikarbonatını","Ölü boşluk hacmini sıfıra indirir","Alveol-arter oksijen gradyanını","Hemoglobinin oksijen kapasitesini","Fonksiyonel rezidüel kapasiteyi mutlak azaltır"],"correct":2,"exp":"Pulmoner embolide ventilasyon korunup perfüzyon azalır; V/Q uyumsuzluğu A-a oksijen gradyanını artırır."},{"id":4794,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yüksek irtifaya çıkan sağlıklı kişide ilk saatlerde ventilasyon artıyor. Erken dönemde arter kan gazında hangi değişiklik beklenir?","options":["Respiratuvar asidoz","Metabolik asidoz","PaCO2 artışı","Respiratuvar alkaloz","Bikarbonatın ani yükselmesi"],"correct":3,"exp":"Hipoksemi periferik kemoreseptörleri uyarır, hiperventilasyon PaCO2'yi düşürerek respiratuvar alkaloz yapar."},{"id":4795,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Dokularda oluşan karbondioksitin büyük kısmı akciğere hangi formda taşınır?","options":["Plazmada çözünmüş CO2 olarak","Karbaminohemoglobin olarak","Karbonik asit olarak değişmeden","Serbest karbon monoksit olarak","Bikarbonat olarak"],"correct":4,"exp":"CO2 eritrositte karbonik anhidrazla bikarbonata çevrilir; klor kaymasıyla plazmada bikarbonat halinde taşınır."},{"id":4796,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Pnömonili bir hastada bazı alveoller iyi perfüze olduğu hâlde yetersiz ventile olmaktadır. Bu düşük ventilasyon/perfüzyon (V/Q) birimlerinin oluşturduğu gaz değişikliği bozukluğu için en doğru ifade hangisidir?","options":["Hipoksemi ve artmış alveoloarteriyel oksijen gradyanı oluşturur; ek oksijenle genellikle düzelir","Hipoksemi oluşturur ve ek oksijene gerçek sağdan sola şanttan daha kötü yanıt verir","Arteriyel oksijen basıncını artırır","Alveoloarteriyel oksijen gradyanını azaltır","Yalnız fizyolojik ölü boşluğu artırır"],"correct":0,"exp":"Düşük V/Q birimleri venöz karışım etkisiyle hipoksemiye ve alveoloarteriyel oksijen gradyanında artışa yol açar. Bu bozukluk ek oksijenle genellikle belirgin düzelirken gerçek sağdan sola şantta yanıt sınırlıdır."},{"id":4797,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Prematüre yenidoğanda surfaktan eksikliği nedeniyle alveoller kolay kollabe oluyor. Surfaktanın temel fizyolojik etkisi hangisidir?","options":["Alveol duvarını kalınlaştırmak","Yüzey gerilimini azaltarak küçük alveolleri stabilize etmek","Pulmoner damar direncini sürekli artırmak","Hemoglobinin oksijen afinitesini azaltmak","Mukosiliyer klirensi tamamen durdurmak"],"correct":1,"exp":"Surfaktan yüzey gerilimini azaltır; özellikle küçük alveollerin kollabe olmasını engeller ve kompliyansı artırır."},{"id":4798,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Fetal hemoglobinin oksijen disosiasyon eğrisi erişkin hemoglobine göre sola kaymıştır. Bu durum plasentada hangi sonucu kolaylaştırır?","options":["Fetüsten anneye oksijen geçişi","Anne hemoglobininin oksijen taşıyamaması","Fetal hemoglobinin maternal kandan oksijen alması","Fetal PaCO2'nin tamamen sıfırlanması","2,3-BPG'nin fetal hemoglobine daha güçlü bağlanması"],"correct":2,"exp":"HbF'nin oksijene afinitesi daha yüksektir; bu özellik maternal kandan fetal kana oksijen geçişini kolaylaştırır."},{"id":4799,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"KOAH alevlenmesinde PaO2 belirgin düştüğünde ventilatuvar yanıt artıyor. Düşük PaO2'ye en duyarlı reseptör grubu hangisidir?","options":["J reseptörleri","Pulmoner gerilme reseptörleri","Santral kemoreseptörler","Karotis ve aort cisimcikleri","Bronşiyal irritan reseptörler"],"correct":3,"exp":"Periferik kemoreseptörler, özellikle PaO2 60 mmHg altına düştüğünde hipoksemiye güçlü ventilatuvar yanıt verir."},{"id":4800,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Patella refleksinde kas iğciği gerilmesi kuadriseps kasılmasına yol açar. Bu refleks yayında afferent lif tipi hangisidir?","options":["C lifi","A-delta lifi","Tip II ağrı lifi","Preganglionik otonom lif","Ia afferent lifi"],"correct":4,"exp":"Kas iğciğinin primer sonlanmalarından gelen Ia afferentleri monosnaptik gerilme refleksini başlatır."},{"id":4801,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Parkinson hastalığında hareket başlatma güçlüğü dopaminerjik kayıpla ilişkilidir. Bazal ganglion direkt yolunun fizyolojik etkisi hangisidir?","options":["Talamokortikal motor aktiviteyi kolaylaştırmak","Serebellar Purkinje hücrelerini uyarmak","Spinal alfa motor nöronları doğrudan inhibe etmek","Vestibüler çekirdekleri devre dışı bırakmak","Primer görme korteksini baskılamak"],"correct":0,"exp":"Direkt yol talamus üzerindeki inhibitör çıkışı azaltır ve kortikal motor aktiviteyi kolaylaştırır."},{"id":4802,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Sağ serebellar hemisfer lezyonu olan hastada parmak-burun testinde bozulma bekleniyor. Bulgular genellikle hangi tarafta belirgindir?","options":["Sol üst ekstremitede","Sağ üst ekstremitede","Her iki alt ekstremitede simetrik","Sadece kranial sinir duyu alanında","Lezyonla ilişkisiz karşı kortekste"],"correct":1,"exp":"Serebellar lezyonlar çift çapraz bağlantılar nedeniyle çoğunlukla ipsilateral koordinasyon bozukluğu yapar."},{"id":4803,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Sempatik ganglionda preganglionik liften postganglionik nörona iletim gerçekleşiyor. Bu sinapsta kullanılan nörotransmitter ve reseptör hangisidir?","options":["Norepinefrin ve alfa-1","Dopamin ve D2","Asetilkolin ve nikotinik reseptör","GABA ve GABA-A","Serotonin ve 5-HT3"],"correct":2,"exp":"Otonom ganglionlarda preganglionik sempatik ve parasempatik lifler asetilkolin salgılar; nikotinik reseptörleri aktive eder."},{"id":4804,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Keskin ve iyi lokalize ağrı, yanıcı-künt ağrıdan daha hızlı algılanıyor. Hızlı ağrı iletiminde baskın lif tipi hangisidir?","options":["C lifi","Tip Ia lifi","Tip Ib lifi","A-delta lifi","Postganglionik sempatik lif"],"correct":3,"exp":"A-delta lifleri miyelinli olup hızlı, keskin ve iyi lokalize ağrıyı taşır; C lifleri daha yavaş ve künt ağrı taşır."},{"id":4805,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Karanlıktan ışığa çıkınca fotoreseptör membran potansiyeli değişir ve glutamat salınımı azalır. Işıkta fotoreseptörde beklenen ana olay hangisidir?","options":["cGMP artışıyla sodyum kanallarının açılması","Rodopsinin tamamen sentezlenememesi","Klor kanallarının kalıcı açılması","Asetilkolin salınımının artması","cGMP azalmasıyla kation kanallarının kapanması ve hiperpolarizasyon"],"correct":4,"exp":"Işık rodopsin-transdusin-fosfodiesteraz yolunu aktive eder; cGMP azalır, kation kanalları kapanır ve fotoreseptör hiperpolarize olur."},{"id":4806,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Strychnine zehirlenmesinde spinal inhibitör iletim bozulduğu için yaygın kas spazmları gelişir. Spinal kordda baskın inhibitör nörotransmitter hangisidir?","options":["Glisin","Glutamat","Substans P","Norepinefrin","Histamin"],"correct":0,"exp":"Glisin spinal kord ve beyin sapında önemli inhibitör nörotransmitterdir; blokajı motor aşırı uyarılabilirlik yapar."},{"id":4807,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Renal arter darlığı olan hastada jukstaglomerüler aparat aktive oluyor. Makula densaya ulaşan NaCl azalınca hangi yanıt beklenir?","options":["Renin salınımının baskılanması","Renin salınımının artması","Afferent arteriolün kalıcı yırtılması","ADH reseptörlerinin böbrekten kaybolması","Proksimal tübülde glukoz sekresyonu"],"correct":1,"exp":"Makula densada NaCl azalması düşük perfüzyon sinyali gibi algılanır ve jukstaglomerüler hücrelerden renin salınımını artırır."},{"id":4808,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Ortalama arter basıncı fizyolojik sınırlar içinde arttığında GFR büyük ölçüde sabit kalıyor. Afferent arterioldeki myojenik yanıt hangisidir?","options":["Basınç artınca afferent arteriol dilate olur","Basınç artınca efferent arteriol tamamen kapanır","Basınç artınca afferent arteriol kasılarak glomerüler basıncı sınırlar","Basınç artınca Bowman kapsülü geçirimsiz hale gelir","Basınç artınca filtrasyon bariyeri albümine seçici olur"],"correct":2,"exp":"Miyojenik otoregülasyonda damar düz kası gerilmeye kasılmayla yanıt verir; afferent direnç artışı GFR'yi korur."},{"id":4809,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Dehidratasyon sırasında ADH artışıyla medüller ozmotik gradyan daha etkili kullanılır. ADH'nin iç medüller toplayıcı kanalda artırdığı geçirgenlik hangisidir?","options":["Glukoz geçirgenliği","Albumin geçirgenliği","Kalsiyum geçirgenliği","Üre geçirgenliği","Fosfat geçirgenliği"],"correct":3,"exp":"ADH iç medüller toplayıcı kanalda üre geçirgenliğini artırır; üre geri dönüşümü medüller hiperozmolariteyi destekler."},{"id":4810,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Henle kulpunun kalın çıkan kolu hasarlanırsa idrarı konsantre etme yeteneği azalır. Bu segmentin karşı akım çoğaltıcıdaki kritik özelliği hangisidir?","options":["Suya geçirgen olup sodyumu geçirmemesi","Glukozu sekrete edip suyu emmesi","Üreyi filtre etmeden kana taşıması","Albumini aktif geri emmesi","Suya geçirimsizken NaCl geri emmesi"],"correct":4,"exp":"Kalın çıkan kol suya geçirimsizdir ve NaCl geri emer; bu özellik medüller ozmotik gradyanın oluşması için gereklidir."},{"id":4811,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Tip 2 diyabet tedavisinde kullanılan SGLT2 inhibitörü sonrası glukozüri gelişir. SGLT2'nin normalde baskın bulunduğu nefron bölgesi hangisidir?","options":["Proksimal tübül erken segmenti","İnce inen Henle kolu","Kalın çıkan Henle kolu","Distal kıvrımlı tübül","Kortikal toplayıcı kanal"],"correct":0,"exp":"Filtre edilen glukozun büyük kısmı proksimal tübül erken segmentinde SGLT2 ile sodyumla birlikte geri emilir."},{"id":4812,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Metabolik asidozda böbrek net asit atılımını artırır. Toplayıcı kanalda lümene hidrojen sekresyonundan özellikle sorumlu hücre hangisidir?","options":["Principal hücre","A tipi interkale hücre","B tipi interkale hücre","Makula densa hücresi","Mezangial hücre"],"correct":1,"exp":"A tipi interkale hücreler H+-ATPaz ve H+/K+ ATPaz ile hidrojen sekrete ederek asidozda asit atılımını artırır."},{"id":4813,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Hiperkalemi gelişen hastada aldosteron salınımı artıyor. Aldosteronun potasyum dengesine katkısı en iyi hangi etkiyle açıklanır?","options":["Proksimal tübülde potasyum filtrasyonunu durdurması","Glomerülde potasyumu albümine bağlaması","Principal hücrelerden lümene potasyum sekresyonunu artırması","Henle inen kolunda potasyum emilimini sıfırlaması","Üre geri dönüşümünü potasyuma çevirmesi"],"correct":2,"exp":"Aldosteron principal hücrelerde sodyum geri emilimini ve lümene potasyum sekresyonunu artırarak hiperkalemiyi düzeltmeye çalışır."},{"id":4814,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Birinci faringeal arkus gelişim kusuru olan bebekte mandibula ve çiğneme kasları etkilenmiştir. Bu arkusun motor innervasyonunu sağlayan sinir aşağıdakilerden hangisidir?","options":["Nervus facialis","Nervus trigeminusun mandibular dalı","Nervus glossopharyngeus","Nervus vagus","Nervus hypoglossus"],"correct":1,"exp":"Birinci faringeal arkusun kas türevleri çiğneme kasları, mylohyoid, digastrik kasın ön karnı, tensor tympani ve tensor veli palatiniyi içerir. Motor innervasyon nervus trigeminusun mandibular dalı (V3) ile sağlanır."},{"id":4815,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"İkinci faringeal arkus gelişiminden kaynaklanan kas grubunda fonksiyon kaybı olan bebekte yüz mimikleri belirgin azalıyor. Bu arkusun siniri hangisidir?","options":["Trigeminal sinir","Glossofaringeal sinir","Vagus siniri","Aksesuar sinir","Fasiyal sinir"],"correct":4,"exp":"İkinci arkus yüz mimik kasları, stapedius ve stilohyoid gibi yapıları verir; siniri fasiyal sinirdir."},{"id":4816,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"DiGeorge sendromunda timus ve paratiroid gelişimi etkilenir. İnferior paratiroid bezleri ve timus hangi faringeal poştan gelişir?","options":["Üçüncü faringeal poş","Birinci faringeal poş","İkinci faringeal poş","Dördüncü faringeal poş","Birinci faringeal yarık"],"correct":0,"exp":"Üçüncü faringeal poş inferior paratiroidleri ve timusu oluşturur; DiGeorge sendromunda bu gelişim bozulur."},{"id":4817,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Üst paratiroid bezlerinin embriyolojik kökeni sorulduğunda hangi faringeal poş doğru kabul edilir?","options":["İkinci faringeal poş","Dördüncü faringeal poş","Üçüncü faringeal poş","Birinci faringeal arkus","İkinci faringeal yarık"],"correct":1,"exp":"Superior paratiroid bezleri dördüncü faringeal poştan gelişir; inferior paratiroidler üçüncü poştan gelişir."},{"id":4818,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Nöral krest hücre migrasyonu bozulan embriyoda kraniofasiyal iskelet ve konotrunkal kalp gelişimi etkileniyor. Baş-boyun gelişiminde nöral krestin önemli katkısı hangisidir?","options":["Amniyon sıvısının tamamını üretmesi","Yolk kesesinden eritrosit oluşturması","Faringeal arkus bağ dokusu ve iskelet elemanlarına katkı sağlaması","Nöral tüp lümenini kapatması","Somitlerden miyotom oluşturması"],"correct":2,"exp":"Nöral krest hücreleri faringeal arkusların bağ dokusu, kıkırdak ve kemik bileşenlerine önemli katkı verir."},{"id":4819,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Boyun orta hattında, yutkunma ve dil çıkarma ile hareket eden kistik kitle saptanan çocukta en olası embriyolojik kalıntı hangisidir?","options":["Brankial yarık kisti","Timik kist","Dermoid kist","Tiroglossal kanal kisti","Lenfatik malformasyon"],"correct":3,"exp":"Tiroglossal kanal kisti tiroidin iniş yolu üzerinde orta hatta yer alır ve hyoid-dil bağlantısı nedeniyle yutkunma veya dil hareketiyle hareket eder."},{"id":4820,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Üst dudak yarığı olan bir bebekte primer damak ve üst dudak birleşimi etkilenmiştir. Bu malformasyon en çok hangi yapıların füzyon kusuruyla ilişkilidir?","options":["Mandibular çıkıntılar ile ikinci arkus","Maksiller çıkıntılar ile mandibular çıkıntılar","Lateral nazal çıkıntılar ile optik vezikül","Palatal raflar ile laringotrakeal oluk","Maksiller çıkıntı ile medial nazal çıkıntı"],"correct":4,"exp":"Yarık dudak genellikle maksiller çıkıntının medial nazal çıkıntıyla birleşme kusurundan kaynaklanır."},{"id":5178,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Gelişme geriliği, kaba yüz görünümü ve tekrarlayan solunum yolu enfeksiyonları olan 2 yaşındaki çocukta fibroblast lizozomlarında hidrolaz aktivitesi düşük, plazmada ise bu enzimler yüksek bulunuyor. Bu dağılımı en iyi açıklayan hücresel kusur aşağıdakilerden hangisidir?","options":["Golgi'de lizozomal enzimlere mannoz-6-fosfat işareti eklenememesi","Mitokondri iç zarında oksidatif fosforilasyonun hızlanması","Peroksizomlarda çok uzun zincirli yağ asidi yıkımının artması","Endoplazmik retikulumdan kalsiyum salınımının kalıcı azalması","Plazma membranında sodyum-glukoz kotransportunun artması"],"correct":0,"exp":"Lizozomal hidrolazların hedeflenmesi için Golgi'de mannoz-6-fosfat etiketi gerekir. Bu işaretleme bozulursa enzimler lizozoma giremez, hücre dışına salgılanır ve hücre içinde sindirilemeyen materyal birikir."},{"id":5179,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Ağır hipoksi sonrası nöronlarda hücre içi sodyum ve kalsiyum artarken hücre şişmesi gelişiyor. Bu erken değişiklikte ATP azalmasına en duyarlı basamak aşağıdakilerden hangisidir?","options":["G proteinine bağlı reseptör desensitizasyonu","Lizozomal hidrolazların ekzositozla uzaklaştırılması","Endoplazmik retikulumda ribozomal protein sentezinin artması","Plazma membranında Na/K-ATPaz pompasının yetersiz çalışması","Peroksizomal beta oksidasyonun hızlanması"],"correct":3,"exp":"Na/K-ATPaz ATP bağımlı bir pompadır. Hipoksiyle ATP azalınca iyon gradyanları korunamaz, sodyum ve su hücre içine girer; hücresel şişme ortaya çıkar."},{"id":5180,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Çocukluktan beri tekrarlayan sinüzit ve alt solunum yolu enfeksiyonları geçiren 24 yaşındaki erkekte bronşektazi, situs inversus ve infertilite saptanıyor. Semen analizinde sperm sayısı normal, hareketlilik belirgin azalmıştır. Nazal epitelin elektron mikroskobik incelemesinde 9+2 aksonem düzeni seçilmekle birlikte silyalar hareket edememektedir. Bronş biyopsisinde epitel hücre sayısı ve mukus bezleri belirgin artmamıştır. En olası ultrastrüktürel bozukluk aşağıdakilerden hangisidir?","options":["Ara filamentlerin desmozomlara bağlanamaması","Mikrovillus aktin demetlerinin kısalması","Golgi veziküllerinde klatrin kaplanmasının azalması","Kaveola aracılı endositozun artması","Aksonemal dynein kollarının eksikliği"],"correct":4,"exp":"Primer siliyer diskinezide en klasik defekt aksonemal dinein kollarının eksikliğidir. Dinein, komşu mikrotübül çiftlerinin birbiri üzerinde kaymasını ve silya hareketini sağlar. Kusuru mukosiliyer klirensi ve sperm motilitesini bozar; embriyonik nodal silya işlevi etkilenirse situs inversus gelişebilir. Mikrovilluslar ise aktin içerir ve motil silya işlevi görmez."},{"id":5181,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":5,"q":"Kaba yüz, gelişme geriliği ve çoklu iskelet anomalileri olan bir çocukta plazmada çok sayıda lizozomal hidrolaz yüksek bulunuyor; fibroblastlarda ise substrat birikimi vardır. Hangi hücresel hedefleme basamağında aksama beklenir?","options":["Mitokondriyal proteinlerin sinyal peptidazla olgunlaşması","Peroksizomal proteinlere SKL dizisinin eklenmesi","Golgi'de lizozomal enzimlere mannoz-6-fosfat etiketi eklenmesi","Sekretuar granüllerin kalsiyum bağımlı ekzositozu","Endozomların klatrin kaplı çukurlardan ayrılması"],"correct":2,"exp":"I-hücre hastalığında Golgi'de lizozomal enzimlere mannoz-6-fosfat etiketi eklenemez. Enzimler lizozoma yönlenmek yerine sekrete edilir ve hücre içinde substrat birikir."},{"id":5182,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Ailesel geçişli bir sendromda bebekte sensörinöral işitme kaybı ve kardiyak iletimde yavaşlama izleniyor; biyopside komşu hücreler arasında iyon geçişinin belirgin azaldığı gösteriliyor. Bu fizyolojik sonuç en çok hangi bağlantı yapısının işlev kaybıyla uyumludur?","options":["Zonula occludens","Hemidesmozom","Fokal adezyon","Gap junction","Adherens bağlantı"],"correct":3,"exp":"Gap junctionlar konneksinlerden oluşan kanallarla komşu hücreler arasında iyon ve küçük molekül geçişi sağlar. Koklea ve kalpte elektriksel eşleşme bozulduğunda işitme ve iletim sorunları gelişebilir."},{"id":5183,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Göbek kordonu geç düşen, nötrofil sayısı yüksek olmasına rağmen tekrarlayan bakteriyel enfeksiyonları olan 6 aylık bebekte yara yerinde irin oluşumu belirgin azdır. Lökositlerin dokuda birikememesini en iyi açıklayan bozukluk aşağıdakilerden hangisidir?","options":["Makrofajlarda MHC sınıf II sunumunun hızlanması","Selektin ligandlarının aşırı ekspresyonu","Kompleman C3b opsonizasyonunun artması","Nötrofillerde miyeloperoksidaz aktivitesinin artması","Beta-2 integrin aracılı sıkı adezyonun bozulması"],"correct":4,"exp":"Lökosit adezyon eksikliğinde CD18 beta-2 integrin kusuru sıkı adezyon ve diapedesisi bozar. Nötrofiller kanda yüksek kalır, enfeksiyon alanına yeterince geçemez."},{"id":5184,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Uzun süre taze sebze-meyve tüketmeyen 48 yaşındaki erkekte diş eti kanaması ve kolay morarma gelişiyor. Kollajen liflerinin gerilme direncindeki azalmayı hangi işlemdeki bozulma en iyi açıklar?","options":["Prokollajen zincirlerinin ribozomda translasyonu","Elastin liflerinin desmozomlara bağlanması","Kollajen fibrillerinin lizozomda yıkımı","Prolin ve lizin kalıntılarının hidroksilasyonu","Tip IV kollajenin epitel yüzeyine salgılanması"],"correct":3,"exp":"C vitamini prolin ve lizin hidroksilasyonu için gereklidir. Hidroksilasyon azalınca kollajen üçlü heliksi ve çapraz bağlanma zayıflar; kanama ve yara iyileşme kusuru görülür."},{"id":5185,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Yaşlı bir hastada gergin büller ve kaşıntı gelişiyor; immünfloresan incelemede bazal membran hattında lineer IgG birikimi saptanıyor. Epidermisin dermise tutunmasının zayıflamasını en iyi açıklayan bağlantı kompleksi aşağıdakilerden hangisidir?","options":["Zonula occludens","Gap junction","Hemidesmozom","Makula adherens","Neksus"],"correct":2,"exp":"Hemidesmozomlar bazal keratinositleri bazal laminaya bağlar. BP180/BP230 gibi hemidesmozomal yapılara karşı antikor geliştiğinde dermoepidermal ayrışma ve gergin bül oluşur."},{"id":5186,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Kolay morarma, ince yarı saydam deri ve arter rüptürü öyküsü olan genç erişkinde damar duvarı desteğinin zayıf olduğu düşünülüyor. Bu hastada özellikle hangi kollajen tipindeki kusur benzer klinik sonucu en iyi açıklar?","options":["Tip I kollajen","Tip III kollajen","Tip IV kollajen","Tip II kollajen","Tip VII kollajen"],"correct":1,"exp":"Tip III kollajen retiküler liflerin ve damar duvarı gibi esnek destek dokularının önemli bileşenidir. Vasküler Ehlers-Danlos spektrumunda tip III kollajen kusuru damar ve organ rüptürü riskini artırır."},{"id":5187,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Arı sokması sonrası dakikalar içinde ürtiker ve bronkospazm gelişen hastada bağ dokusundaki mast hücreleri hızlı degranüle oluyor. Bu erken yanıtta granüllerden salınması beklenen ana mediyatör aşağıdakilerden hangisidir?","options":["Kollajenaz","Histamin","Surfactant protein C","Osteokalsin","Eritropoietin"],"correct":1,"exp":"Mast hücreleri IgE aracılı çapraz bağlanma sonrası histamin ve heparin içeren granüllerini salar. Histamin vazodilatasyon, damar geçirgenliği artışı ve bronkokonstriksiyona katkı verir."},{"id":5188,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":5,"q":"Daha önce anestezi almamış 22 yaşındaki erkek, sevofluran ve süksinilkolin kullanılan ameliyat sırasında ani taşikardi, yaygın kas rijiditesi, hızla yükselen end-tidal CO₂ ve hipertermi geliştiriyor. Serum potasyumu ve kreatin kinazı artıyor. Ailede anestezi sırasında açıklanamayan ölüm öyküsü bulunması kalıtsal yatkınlığı destekliyor. Dantrolen hazırlanırken, iskelet kasında krizi başlatan temel hücresel olayın aşağıdakilerden hangisidir?","options":["Ryanodin reseptöründen kontrolsüz kalsiyum salınımının artması","Asetilkolinesterazın geri dönüşümsüz aktivasyon kazanması","Miyozin hafif zincir fosfataz aktivitesinin kalıcı artması","Titin elastikiyetinin sarkomer boyunca belirgin biçimde azalması","Distrofinin aktinle bağlantısının aşırı güçlenmesi"],"correct":0,"exp":"Malign hipertermi çoğunlukla RYR1 kusuru nedeniyle tetikleyici anestetiklerden sonra sarkoplazmik retikulumdaki ryanodin reseptöründen kontrolsüz kalsiyum salınmasıyla oluşur. Sürekli kasılma ve kalsiyumu geri pompalama çabası ATP tüketimini, CO₂ ve ısı üretimini artırır; rabdomiyoliz ve hiperkalemi gelişebilir. Dantrolen ryanodin reseptörü üzerinden kalsiyum salınımını azaltır."},{"id":5189,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Merdiven çıkarken zorlanan 5 yaşındaki erkek çocukta baldır hipertrofisi ve serum kreatin kinaz yüksekliği saptanıyor. Kas liflerinin kasılma sırasında zedelenmesini önleyen bağlantının kaybı hangi protein eksikliğini düşündürür?","options":["Nebulin","Troponin C","Distrofin","Miyozin hafif zincir kinaz","Kalmodulin"],"correct":2,"exp":"Distrofin aktin iskeletini sarkolemma ve hücre dışı matrikse bağlar. Eksikliğinde kasılma sırasında membran stabilitesi bozulur, lif hasarı ve CK yüksekliği gelişir."},{"id":5190,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Raynaud atağı nedeniyle kalsiyum kanal blokeri verilen hastada dijital arteriyol spazmı azalıyor. Damar düz kasında gevşemeye götüren en yakın hücresel sonuç aşağıdakilerden hangisidir?","options":["Troponin C'ye kalsiyum bağlanmasının artması","Kalmodulin-MLCK aktivasyonunun azalması","Sarkomer Z çizgileri arasındaki mesafenin kısalması","Nikotinik reseptörlerden sodyum girişinin artması","Distrofinin sarkolemmaya bağlanmasının artması"],"correct":1,"exp":"Düz kasta kontraksiyon kalsiyum-kalmodulin aracılığıyla MLCK aktivasyonuna ve miyozin hafif zincir fosforilasyonuna bağlıdır. Kalsiyum girişi azalınca MLCK aktivitesi düşer ve gevşeme kolaylaşır."},{"id":5191,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":5,"q":"Yeni başlanan bir ilaçtan sonra QT aralığı uzayan hastada ventriküler repolarizasyon gecikiyor. Kardiyak aksiyon potansiyelinde bu bulgu en çok hangi iyon akımının azalmasıyla ilişkilidir?","options":["Hızlı sodyum girişi","L tipi kalsiyum girişi","If akımıyla sodyum girişi","Gecikmiş rektifiye edici potasyum çıkışı","Klor kanalı aracılı hiperpolarizasyon"],"correct":3,"exp":"Ventrikül kasında faz 3 repolarizasyon esas olarak potasyum çıkışıyla sağlanır. Gecikmiş rektifiye edici K akımının azalması repolarizasyonu geciktirir ve QT uzamasına yol açar."},{"id":5192,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"İskelet kası lifinde izometrik kasılma gücünün sarkomer uzunluğuna göre değişmesini en iyi açıklayan ilke aşağıdakilerden hangisidir?","options":["Aktin ve miyozin filamentlerinin optimal örtüşme derecesi","Miyoglobin oksijen satürasyonunun anlık değişmesi","Motor son plakta asetilkolin salınımının uzama ile azalması","Sarkoplazmik retikulum kalsiyum deposunun ileri derecede azalması","Aksiyon potansiyeli genliğinin sarkomer uzunluğuyla artması"],"correct":0,"exp":"Uzunluk-gerilim ilişkisi çapraz köprü kurabilecek aktin-miyozin örtüşmesine bağlıdır. Çok kısa veya çok uzun sarkomerlerde etkin çapraz köprü sayısı azalır."},{"id":5193,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":5,"q":"Primer amenore nedeniyle değerlendirilen 17 yaşındaki hastanın meme gelişimi normal, pubik ve aksiller kıllanması seyrektir. Vajen kısa ve kör sonlanır; ultrasonografide uterus görülmez, inguinal kanalda testis dokusu saptanır. Karyotip 46,XY, testosteron düzeyi erkek referans aralığındadır. LH düzeyi yükselmiş, FSH ise yaşına göre normal sınırlardadır. Dış genital fenotipin kadın yönünde gelişmesini açıklayan temel hedef doku bozukluğu aşağıdakilerden hangisidir?","options":["Anti-Müllerian hormon salgısının belirgin biçimde azalması","Androjen reseptör yanıtının azalması","Sertoli hücresinde inhibin B üretiminin artması","FSH'nin granüloza aromatazını uyaramaması","Over folikül rezervinin doğuştan azalması"],"correct":1,"exp":"Komplet androjen duyarsızlığında androjen reseptörü işlevsizdir. Sertoli hücrelerinden salgılanan anti-Müllerian hormon uterus ve tüplerin gerilemesini sağlar; buna karşın hedef dokular testosteron ve dihidrotestosterona yanıt veremediği için dış genital yapı kadın fenotipinde gelişir. Testosteronun aromatizasyonu meme gelişimine katkı sağlar, terminal kıllanma ise androjen yanıtı olmadığından seyrektir."},{"id":5194,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Azospermi nedeniyle değerlendirilen erkekte Sertoli hücre fonksiyonunun hipofiz FSH salgısı üzerindeki geri bildirimi araştırılıyor. Sertoli hücrelerinden salgılanan ve FSH'yi seçici olarak azaltan hormon aşağıdakilerden hangisidir?","options":["Anti-Müllerian hormon","Testosteron","İnhibin B","Dihidrotestosteron","Estriol"],"correct":2,"exp":"Sertoli hücreleri spermatogenezin durumuna göre inhibin B salgılar. İnhibin B ön hipofizde FSH salınımını seçici biçimde baskılar."},{"id":5195,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Gebeliğin 6. haftasında sarı cisim cerrahi olarak çıkarılırsa progesteron desteği verilmediğinde gebelik kaybı riski artar. Bu dönemde sarı cismin devamlılığını hangi sinyal sağlar?","options":["Fetal adrenal bezden salgılanan DHEA-S","Plasental laktojenin desidual hücreleri uyarması","Endometriumdan salınan prostaglandin F2 alfa","Maternal FSH'nin granüloza hücresini yeniden uyarması","Trofoblast kaynaklı hCG'nin LH reseptörünü uyarması"],"correct":4,"exp":"Erken gebelikte sinsityotrofoblast hCG salgılar. hCG LH reseptörlerini uyararak korpus luteumun progesteron üretimini sürdürür; plasenta yeterli steroid üretimine geçene kadar bu destek kritiktir."},{"id":5196,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Dominant folikülü 20 mm olan 29 yaşındaki kadında serum östradiolü 48 saatten uzun süre yüksek seyrediyor ve kısa süre sonra ovulasyon gerçekleşiyor. Bu geçişi başlatan hipotalamo-hipofizer yanıt aşağıdakilerden hangisidir?","options":["Düşük östradiolün GnRH salınımını büyük ölçüde baskılaması","FSH'nin korpus luteumu tek başına sürdürmesi","Yüksek östradiolün LH dalgasını tetikleyen pozitif geri bildirimi","İnhibin B'nin prolaktin salınımını artırması","AMH'nin endometriumda sekretuar dönüşümü başlatması"],"correct":2,"exp":"Geç foliküler fazda yüksek ve sürekli östradiol negatif geri bildirimden pozitif geri bildirime geçerek LH dalgasını oluşturur. LH dalgası ovulasyon ve luteinizasyon için kritik uyarıdır."},{"id":5197,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Ovulasyon sonrasında endometriyumda bezlerin kıvrımlı hâle gelip salgı yapan yapıya dönüşmesini en iyi açıklayan hormonal ortam aşağıdakilerden hangisidir?","options":["Korpus luteumdan salgılanan progesteronun baskın duruma geçmesi","Folikül gelişimini sürdüren yüksek FSH düzeyinin korunması","Androjen düzeyinin yükselirken LH salınımının azalması","Prolaktin yüksekliğinin gonadotropin salınımını baskılaması","Hem progesteron hem östradiol düzeylerinin düşük seyretmesi"],"correct":0,"exp":"Sekretuar faz ovulasyon sonrası korpus luteumdan salgılanan progesteronla oluşur. Progesteron proliferatif endometriumu sekresyon yapan, implantasyona uygun hale getirir."},{"id":5198,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Gebelik öncesinde folik asit kullanmayan bir kadının 12. hafta ultrasonografisinde kraniyal kubbe ve serebral hemisferlerin büyük bölümünün gelişmediği, omurga kaudalinin ise kapalı olduğu görülüyor. Alfa-fetoprotein düzeyi yüksektir. Ailede benzer anomalili gebelik öyküsü bulunmamakla birlikte anne valproat kullanmaktadır. Bu ağır nöral tüp defektine yol açan embriyolojik kapanma kusuru aşağıdakilerden hangisidir?","options":["Primitif çizginin erken kaybolması","Kaudal nöroporun erken kapanması","Nöral krista hücrelerinin adrenal medullaya aşırı göçü","Somitlerin sklerotom ve dermatom ayrımının gecikmesi","Rostral nöroporun kapanma kusuru"],"correct":4,"exp":"Anensefali rostral nöroporun embriyogenezin yaklaşık 25. gününde kapanmaması sonucu gelişir; kraniyal nöroaksis ve kalvaryum ağır biçimde etkilenir. Açık nöral tüp defektlerinde amniyon sıvısı ve maternal serum alfa-fetoproteini yükselebilir. Kaudal nöropor kusuru spina bifida spektrumuna yol açar. Perikonsepsiyonel folat desteği riski azaltır."},{"id":5199,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Gebeliğinin 6. haftasında teratojen bir ilaca maruz kalan kadında fetusta majör organ anomalisi riski belirgin artıyor. Bu duyarlılığı en iyi açıklayan dönem aşağıdakilerden hangisidir?","options":["Preimplantasyon döneminde tüm hücrelerin totipotent olması","İkinci trimesterde plasental bariyerin büyük ölçüde geçirimsiz olması","Fetal dönemde yalnızca boy ve kilo artışının başlaması","Üçüncü-sekizinci haftalar arasında organogenezin yoğun olması","Doğuma yakın sürfaktan sentezinin tamamlanması"],"correct":3,"exp":"Majör yapısal anomaliler için en kritik dönem organogenezin gerçekleştiği 3-8. haftalardır. Bu dönemde teratojen maruziyet organ taslaklarını kalıcı etkileyebilir."},{"id":5200,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Monozigotik gebelikte ayrılmanın geç gerçekleştiği ve bebeklerin bazı vücut bölgelerinden birleşik doğduğu görülüyor. Bu tablo en çok hangi zamanlama ile ilişkilidir?","options":["İki hücreli evrede ayrılma","Primitif çizgi oluştuktan sonra ayrılma","Morula evresinden önce ayrılma","Blastokist implantasyonundan çok önce ayrılma","Fertilizasyondan hemen sonraki ilk mitozda ayrılma"],"correct":1,"exp":"Monozigotik ikizlerde çok geç, özellikle primitif çizgi oluştuktan sonra ayrılma yetersiz kalırsa yapışık ikizlik gelişebilir. Daha erken ayrılmalarda plasenta ve amniyon ilişkisi farklılaşır."},{"id":5201,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":5,"q":"Valproat kullanan gebelikte fetüste lumbosakral bölgede açık nöral tüp defekti saptanıyor. Bu anomalinin oluştuğu dönemde aksayan temel embriyolojik olay aşağıdakilerden hangisidir?","options":["Nöral kıvrımların birleşip yüzey ektoderminden ayrılması","Sinsityotrofoblast lakünlerinin maternal kanla dolması","Primitif çizgiden intraembriyonik mezoderm göçü","Hipoblastın ekstraembriyonik endodermi oluşturması","Somitlerin dermatom ve miyotoma geç ayrılması"],"correct":0,"exp":"Spina bifida gibi açık nöral tüp defektleri nöral kıvrımların kapanma ve yüzey ektoderminden ayrılma sürecindeki aksama ile ilişkilidir. Folat metabolizmasını etkileyen ilaçlar riski artırır."},{"id":5202,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Yardımcı üreme uygulamasında blastokistin zona pellucidadan çıkışı yetersiz kaldığında endometriyuma tutunma gerçekleşmiyor. Normal implantasyonun başlaması için öncelikle gerekli olan embriyolojik olay aşağıdakilerden hangisidir?","options":["Nöral tüpün kaudal nöropordan kapanarak kanalın tamamlanması","Primitif çizgiden notokordun oluşarak eksenel iskeletin belirlenmesi","Blastokistin zona pellucidadan çıkıp endometriyum epiteline tutunması","Hipoblastın sinsityotrofoblasta farklılaşarak invazyonu başlatması","Amniyoblastların koryon boşluğunu döşeyerek sıvı üretmesi"],"correct":2,"exp":"İmplantasyon için blastokistin zona pellucidadan ayrılması ve trofoblast yüzeyiyle endometriuma adezyonu gerekir. Zona içinde kalan blastokist uterin epitele etkin şekilde tutunamaz."},{"id":5203,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Otoimmün gastrit öyküsü olan 62 yaşındaki hastada halsizlik, parestezi ve yürüme güçlüğü gelişiyor. Hemoglobin 8,7 g/dL, MCV 116 fL, LDH belirgin yüksek, indirekt bilirubin artmış ve retikülosit yanıtı düşük. Periferik yaymada hipersegmente nötrofiller izleniyor. Bu hastada anemiden sorumlu temel mekanizma aşağıdakilerden hangisidir?","options":["DNA sentez kusuruna bağlı eritroid öncüllerin intramedüller yıkımı","Makrofajlardan aşırı demir salınımıyla eritropoezin baskılanması","Eritrosit zar iskeletindeki spektrinin kalıtsal kusuru","Globin zinciri sentezinin dengesizleşerek çökeltiler oluşturması","Plazma hacminin akut azalmasıyla göreceli hemokonsantrasyon"],"correct":0,"exp":"B12 eksikliğinde timidilat sentezi ve DNA replikasyonu aksar; çekirdek olgunlaşması sitoplazmik gelişimin gerisinde kalır. Ağır sentez kusuru bulunan eritroid öncüller dolaşıma çıkamadan kemik iliğinde parçalanır. Bu intramedüller hemoliz veya etkisiz eritropoez LDH ve indirekt bilirubini yükseltirken retikülosit yanıtını düşük bırakır. Nörolojik bulgular B12 eksikliğini folat eksikliğinden ayırmaya yardım eder."},{"id":5204,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"Romatoid artriti olan 55 yaşındaki kadında normositer anemi, düşük serum demiri ve normal-yüksek ferritin saptanıyor. Demirin eritropoeze sunulamamasını en iyi açıklayan değişiklik aşağıdakilerden hangisidir?","options":["Transferrin reseptörünün eritroblastlarda aşırı artması","İntrinsik faktör eksikliğiyle ileal demir emiliminin bozulması","Hepcidin artışıyla ferroportin aracılı demir çıkışının azalması","Alfa globin gen delesyonuyla hem sentezinin durması","Eritropoietinin akciğer epitelinden fazla salgılanması"],"correct":2,"exp":"Kronik inflamasyonda IL-6 hepcidini artırır. Hepcidin ferroportini azaltarak enterosit ve makrofajlardan demir çıkışını kısıtlar; ferritin korunurken serum demiri düşer."},{"id":5205,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Yüksek rakıma çıkan sağlıklı bir kişide birkaç gün içinde retikülosit artışı başlıyor. Hipoksiye bu yanıtı başlatan eritropoietin kaynağı hangi hücre grubudur?","options":["Karaciğer Kupffer hücreleri","Böbrek korteksindeki peritübüler interstisyel hücreler","Kemik iliği megakaryositleri","Dalak kırmızı pulpa makrofajları","Akciğer tip II pnömositleri"],"correct":1,"exp":"Erişkinde eritropoietinin ana kaynağı böbreğin peritübüler interstisyel hücreleridir. Hipoksi HIF yolunu stabilize eder ve EPO üretimi artarak eritroid öncülleri uyarır."},{"id":5206,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Siyanozlu konjenital kalp hastalığı olan çocukta hematokrit yüksek, eritropoietin düzeyi artmış ve kemik iliğinde eritroid hiperplazi izleniyor. Bu tabloya yol açan başlıca hücresel yanıt aşağıdakilerden hangisidir?","options":["Megakaryositlerde endomitozun baskılanması","B lenfositlerde immünoglobulin sınıf değişiminin artması","Granülositik seride terminal maturasyonun durması","Plazma hücrelerinden antikor sekresyonunun azalması","Eritroid öncüllerin yaşam süresi ve proliferasyonunun artması"],"correct":4,"exp":"Doku hipoksisi böbrekten eritropoietin salınımını artırır. Eritropoietin eritroid progenitörlerin sağkalımını ve çoğalmasını destekleyerek eritrosit kitlesini yükseltir."},{"id":5207,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Romatoid artriti olan hastada normositer anemi, düşük serum demiri ve normal-yüksek ferritin saptanıyor. İnflamasyonun demir kullanımını kısıtlamasını en iyi açıklayan değişiklik aşağıdakilerden hangisidir?","options":["Eritrositlerin dolaşımda çekirdeğini yeniden kazanması","Trombopoietinin eritroid seriyi seçici baskılaması","B12'nin terminal ileumdan emiliminin artması","Granülosit koloni uyarıcı faktörün azalması","Hepcidin artışıyla ferroportin aracılı demir çıkışının azalması"],"correct":4,"exp":"Kronik inflamasyonda IL-6 hepcidin üretimini artırır. Hepcidin ferroportini baskılayarak makrofaj ve enterositlerden demir çıkışını azaltır; ferritin depoları korunurken eritropoez için demir erişimi kısıtlanır."},{"id":5208,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"Yirmi yıllık tip 1 diyabeti bulunan 48 yaşındaki hasta erken doyma, postprandiyal şişkinlik ve yemekten birkaç saat sonra sindirilmemiş gıda kusmasıyla başvuruyor. Üst gastrointestinal endoskopide çıkış obstrüksiyonu yoktur; mide boşalma sintigrafisinde belirgin gecikme saptanıyor. Kan glukozu son aylarda kötü kontrollü, periferik otonom nöropati bulguları vardır. Diyabetik otonom nöropatiye bağlı bu tablonun temel fizyolojik açıklaması aşağıdakilerden hangisidir?","options":["Vagal uyarı kaybına bağlı antral peristaltizm ve pilor koordinasyonunun azalması","Sekretin fazlalığına bağlı gastrik asit sekresyonunun artması","Kolesistokinin eksikliğine bağlı safra kesesi kontraksiyonunun azalması","İleosekal sfinkter tonusunun azalmasına bağlı hızlı kolon geçişi","Mide parietal hücrelerinde intrinsik faktör üretiminin artması"],"correct":0,"exp":"Diyabetik gastroparezide vagal ve enterik sinir işlevi bozulur. Antral öğütücü kasılmalar ile pilor gevşemesi arasındaki koordinasyon azalır ve katı gıdaların mide boşalması gecikir. Mekanik tıkanıklığın dışlanması önemlidir. Sekretin veya kolesistokinin değişiklikleri bu kronik örüntünün temel nedeni değildir; intrinsik faktör artışıyla da ilişkili değildir."},{"id":5209,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Yağlı bir öğünden sonra duodenuma lipid ve aminoasit geçişi olan hastada safra kesesi kasılıyor, Oddi sfinkteri gevşiyor ve pankreatik enzim sekresyonu artıyor. Bu yanıtı başlatan hormon-etki eşleşmesi aşağıdakilerden hangisidir?","options":["Gastrin - pankreatik bikarbonat sekresyonunun baskılanması","GIP - ileal safra tuzu emiliminin durdurulması","Sekretin - mide asit sekresyonunun doğrudan artırılması","Motilin - toklukta migratuvar motor kompleksin başlatılması","Kolesistokinin - asiner enzim salınımı ve safra kesesi kontraksiyonu"],"correct":4,"exp":"Duodenal yağ ve aminoasitler I hücrelerinden kolesistokinin salınımını uyarır. Kolesistokinin safra kesesi kontraksiyonu, Oddi gevşemesi ve pankreatik asiner enzim sekresyonunu artırır."},{"id":5210,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"İnce bağırsakta glukoz emiliminin lümen tarafındaki taşıyıcı üzerinden sodyum gradyentine bağımlı olması hangi sonuçla en uyumludur?","options":["Na-K-2Cl kotransporter inhibisyonu glukoz emilimini doğrudan artırır","Fruktoz emilimi aynı taşıyıcıya bağımlı olduğu için azalır","Na-K ATPaz inhibisyonu glukoz emilimini belirgin azaltır","Apikal GLUT2 taşıyıcısı işlevini büyük ölçüde yitirir","Klor sekresyonu durduğu için su emilimi artar"],"correct":2,"exp":"SGLT1, glukozu apikal membrandan sodyumla birlikte hücre içine taşır. Bu sodyum gradyenti bazolateral Na-K ATPaz tarafından sürdürüldüğü için pompanın inhibisyonu glukoz emilimini azaltır."},{"id":5211,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Pirinç suyu görünümünde bol sulu ishalle başvuran hastada dışkıda lökosit yok, dehidratasyon belirgin ve bağırsak mukozası invazyon bulgusu göstermiyor. Bu sekresyon artışını en iyi açıklayan fizyolojik sonuç aşağıdakilerden hangisidir?","options":["Apikal sodyum-glukoz kotransportunun belirgin biçimde azalması","Villus enterositlerinde pepsinojen salınımının başlaması","Terminal ileumda safra tuzu geri emiliminin hızlanması","CAMP artışıyla CFTR üzerinden klor ve su sekresyonunun artması","Parietal hücrelerde intrinsik faktör sentezinin artması"],"correct":3,"exp":"Kolera toksini Gs-alfa aktivitesini sürdürerek enterositlerde cAMP'yi artırır. CFTR üzerinden klor sekresyonu artar; sodyum ve su lümene izleyerek invazyon olmadan masif sekretuar ishal gelişir."},{"id":5212,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Otoimmün gastriti olan hastada makrositoz, düşük B12 düzeyi ve korpus-fundus mukozasında parietal hücre kaybı saptanıyor. Bu hastadaki anemiyi en iyi açıklayan fizyolojik eksiklik aşağıdakilerden hangisidir?","options":["Antral G hücrelerinden gastrin salınımının artması","Pankreatik lipaz aktivitesinin duodenumda azalması","Kolonik kısa zincirli yağ asidi üretiminin artması","İntrinsik faktör azalmasına bağlı kobalamin emiliminin bozulması","Safra tuzlarının terminal ileumdan geri emilmesi"],"correct":3,"exp":"Parietal hücreler hem asit hem intrinsik faktör üretir. İntrinsik faktör kaybı terminal ileumdan B12 emilimini bozar ve megaloblastik anemiye yol açar."},{"id":5213,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Crohn hastalığı nedeniyle terminal ileumu geniş rezeke edilen hastada yağlı dışkılama ve yağda eriyen vitamin eksikliği bulguları gelişiyor. Bu malabsorpsiyonu en iyi açıklayan fizyolojik değişiklik aşağıdakilerden hangisidir?","options":["Gastrik parietal hücrelerden asit salınımının artması","Safra asitlerinin enterohepatik geri emiliminin azalması","Kolon kriptlerinden mukus sekresyonunun azalması","Pankreatik bikarbonatın sekretinle aşırı salınması","Duodenumda demir emiliminin seçici hızlanması"],"correct":1,"exp":"Safra asitleri terminal ileumdan geri emilerek enterohepatik dolaşıma katılır. Geniş ileal rezeksiyon safra asidi havuzunu azaltır, micel oluşumu bozulur ve steatore gelişir."},{"id":5214,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Uzun süredir aort yetersizliği bulunan 52 yaşındaki hastada sol ventrikül dilatasyonu, 170/55 mmHg kan basıncı ve hızlı yükselip sönen periferik nabızlar saptanıyor. Ekokardiyografide ileri diyastolik geri kaçış ve eksantrik hipertrofi izleniyor. Diyastolde aorttan sol ventriküle geri kaçış ve artmış toplam atım hacmi birlikte değerlendirildiğinde, geniş nabız basıncını oluşturan temel hemodinamik değişiklik aşağıdakilerden hangisidir?","options":["Diyastolik basınç düşerken atım hacmine bağlı sistolik basıncın artması","Sistolik ve diyastolik basıncın birlikte azalması","Sağ atriyum basıncının sol ventrikül basıncını aşması","Koroner perfüzyonun yalnız sistolde gerçekleşmesi","Toplam periferik direncin nabız basıncını belirgin biçimde azaltması"],"correct":0,"exp":"Aort yetersizliğinde diyastolde kanın sol ventriküle geri kaçması aort diyastolik basıncını düşürür. Artan sol ventrikül diyastol sonu hacmi ve eksantrik adaptasyon toplam atım hacmini artırarak sistolik basıncı yükseltir. Sistolik basıncın artması ile diyastolik basıncın düşmesi nabız basıncını genişletir ve sıçrayıcı nabız oluşturur."},{"id":5215,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Kronik hipertansiyonu olan 60 yaşındaki kadın hastada sol ventrikül hipertrofisi ve efor dispnesi var. Ekokardiyografide ejeksiyon fraksiyonu korunmuş, doluş basınçları artmıştır. Bu hastada diyastolik doluş bozukluğunu en iyi açıklayan değişiklik aşağıdakilerden hangisidir?","options":["Ventrikül kompliyansının artarak aynı basınçta daha fazla hacim alması","Aort kapak alanının genişleyerek atım hacmini yükseltmesi","Ventrikül sertliğinin artması ve basınç-hacim eğrisinin yukarı kayması","Venöz dönüşün azalarak ön yükü belirgin biçimde düşürmesi","Frank-Starling yanıtının güçlenerek atım hacmini artırması"],"correct":2,"exp":"Konsantrik hipertrofi ventrikül kompliansını azaltır. Aynı diyastolik hacim daha yüksek basınç oluşturur; ejeksiyon fraksiyonu korunabilir ancak doluş basıncı artar ve efor dispnesi gelişir."},{"id":5216,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"İzole olarak sistemik arteriyollerde vazokonstriksiyon oluşturan bir ilaç verildiğinde, kalp hızı sabit tutulursa sol ventrikül basınç-hacim döngüsünde hangi değişiklik beklenir?","options":["Sistol sonu hacim artar ve atım hacmi azalır","Preload azalır ve diyastol sonu hacim sıfıra yaklaşır","Kontraktilite artar ve sistol sonu basınç-hacim ilişkisi dikleşir","Afterload azalır ve sistol sonu hacim düşer","İzovolümetrik gevşeme fazı kaybolur"],"correct":0,"exp":"Arteriyoler vazokonstriksiyon afterloadu artırır. Kontraktilite değişmeden ventrikül daha yüksek basınca karşı boşalır; sistol sonu hacim artar ve atım hacmi azalır."},{"id":5217,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Ayakta uzun süre bekleyen sağlıklı bir kişide bacaklarda venöz basınç artar. Doku ödemine karşı lenfatik sistemin başlangıçta en önemli koruyucu katkısı aşağıdakilerden hangisidir?","options":["Plazma albumin sentezini dakikalar içinde artırması","Arteriyoler hidrostatik basıncı yükseltmesi","Kapiller endotelde büyük protein geçişini büyük ölçüde baskılaması","İnterstisyel sıvı ve proteini dolaşıma geri taşıması","Renin salınımını doğrudan baskılaması"],"correct":3,"exp":"Lenfatikler interstisyel sıvıyı ve sızan proteinleri venöz dolaşıma döndürür. Böylece interstisyel onkotik basıncın artması ve kalıcı ödem gelişmesi sınırlanır."},{"id":5218,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":5,"q":"Akut inferior miyokard infarktüsü geçiren hastada SA düğüm iskemisine bağlı sinüs bradikardisi gelişiyor. SA düğüm hücresinde faz 4 depolarizasyonunun yavaşlaması en çok hangi iyon akımıyla ilişkilidir?","options":["Na-K ATPazın belirgin biçimde yavaşlamasına bağlı anlık depolarizasyon","Hızlı sodyum kanallarının daha erken açılması","İçeri doğrultucu potasyum akımının ventrikül kasındaki gibi baskın hale gelmesi","Klor kanallarından masif klor çıkışı","Funny sodyum akımının ve L tipi kalsiyum girişinin azalması"],"correct":4,"exp":"SA düğümünde spontan faz 4 depolarizasyonu If akımı ve kalsiyum kanallarının katkısıyla oluşur. Bu eğimin azalması eşik potansiyeline ulaşmayı geciktirir ve kalp hızı düşer."},{"id":5219,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"Koroner kan akımının metabolik kontrolünde çalışan iskelet kasından farklı olarak kalpte oksijen ekstraksiyonu istirahatte zaten yüksektir. Egzersizde miyokard oksijen gereksinimi arttığında koroner akım nasıl artırılır?","options":["Hemoglobin oksijen afinitesinin hızla artırılmasıyla","Lokal metabolitlere bağlı koroner vazodilatasyonla","Koroner venöz basıncın sistemik arter basıncının üstüne çıkmasıyla","Aort diyastolik basıncının sıfıra düşmesiyle","Miyokard kapillerlerinin ileri derecede daralmasıyla"],"correct":1,"exp":"Miyokard istirahatte oksijeni yüksek oranda ekstrakte eder; talep artınca asıl uyum koroner kan akımının artırılmasıdır. Adenozin, CO2, H+ ve düşük O2 gibi lokal faktörler vazodilatasyon yapar."},{"id":5220,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Genç bir erişkinde inspirasyon sırasında venöz dönüş artarken sistolik kan basıncı hafif düşüyor. Normal inspirasyonda sağ ve sol kalp doluşundaki bu geçici farklılığı açıklayan bulgu aşağıdakilerden hangisidir?","options":["Pulmoner damar direncinin inspirasyonda belirgin biçimde artması","Sağ ventrikül doluşunun artması ve interventriküler etkileşimle sol doluşun kısa süre azalması","Perikard boşluğundaki negatif basıncın inspirasyonda kaybolması","Aort kapağının kapanmasının gecikerek ejeksiyon süresini uzatması","Sol atriyum basıncının venöz dönüşten bağımsız biçimde sabit kalması"],"correct":1,"exp":"İnspirasyon intratorasik basıncı düşürür ve sağ kalbe venöz dönüşü artırır. Sağ ventrikül doluşundaki artış septal etkileşim ve pulmoner geçiş gecikmesiyle sol ventrikül doluşunu kısa süre azaltabilir."},{"id":5221,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sepsisli 46 yaşındaki hastada cilt sıcak, diyastolik basınç düşük ve nabız basıncı geniştir. Erken hiperdinamik dönemde kardiyak debinin yüksek ölçülmesi en çok hangi hemodinamik değişiklikle açıklanır?","options":["Toplam periferik direncin belirgin artması","Kan viskozitesinin artmasına bağlı akımın yavaşlaması","Venöz kapasitansın azalmasıyla tüm kanın arterlere hapsolması","Sistemik vazodilatasyon ve düşük afterload","Aort kapak stenozuna bağlı sistolik basıncın düşmesi"],"correct":3,"exp":"Erken sepsiste inflamatuvar mediyatörler yaygın vazodilatasyon yapar; toplam periferik direnç ve afterload düşer. Kompansatuvar sempatik yanıtla kalp hızı artar ve kardiyak debi yüksek olabilir."},{"id":5222,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":5,"q":"Primer adrenal yetmezliği olan 32 yaşındaki kadında hiperpigmentasyon, hiponatremi ve hiperkalemi saptanıyor. Bu hastada hiperpigmentasyonu en iyi açıklayan hormonal değişiklik aşağıdakilerden hangisidir?","options":["Aldosteron artışıyla melanosit uyarısının güçlenmesi","POMC türevi ACTH ve MSH etkisinin artması","Prolaktin azalmasıyla melanin yıkımının yavaşlaması","ADH azalmasıyla epidermal su kaybının artması","İnsülin eksikliğiyle tirozinaz aktivitesinin baskılanması"],"correct":1,"exp":"Primer adrenal yetmezlikte kortizol geri bildirimi azalır ve POMC kökenli ACTH artar. ACTH/MSH aktivitesi melanokortin reseptörlerini uyararak hiperpigmentasyona yol açar."},{"id":5223,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":3,"q":"Tiroid hormonlarının hedef dokularda bazal metabolizma hızını artırması en çok hangi hücresel değişiklikle ilişkilidir?","options":["Mitokondriyal DNA'nın hedef hücrelerde ortadan kalkarak oksidatif fosforilasyonu durdurması","Hücre membranında klor kanallarının hızla kapanması","G protein aracılı cAMP üretiminin belirgin biçimde yavaşlaması","Nükleer reseptör aracılığıyla metabolik enzim ve Na-K ATPaz ekspresyonunun artması","Ribozomal protein sentezinin akut olarak bloke olması"],"correct":3,"exp":"T3 nükleer reseptörlere bağlanarak gen transkripsiyonunu düzenler. Na-K ATPaz ve oksidatif metabolizma enzimlerinin artması ısı üretimini ve bazal metabolizma hızını yükseltir."},{"id":5224,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":5,"q":"Yenidoğan kız bebekte kusma, hiponatremi, hiperkalemi ve klitoral büyüme saptanıyor; kortizol düzeyi düşük, ACTH yüksek bulunuyor. Bu bulguların birlikte görülmesini en iyi açıklayan steroidogenez sonucu aşağıdakilerden hangisidir?","options":["Overde aromataz etkinliğinin artarak östrojen üretimini yükseltmesi","ACTH artışıyla steroidogenezin adrenal androjen öncüllerine yönelmesi","Prolaktin yüksekliğinin GnRH atımlarını hızlandırarak puberteyi başlatması","TSH reseptörünün uyarılmasıyla tiroid hormon üretiminin artması","İnhibin B düzeyinin yükselerek FSH salınımını baskılaması"],"correct":1,"exp":"Klasik 21-hidroksilaz eksikliğinde kortizol ve aldosteron sentezi azalır. ACTH artışı adrenal steroid öncüllerini androjen yoluna iter; virilizasyon ve tuz kaybı birlikte görülebilir."},{"id":5225,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Uzun süredir hiperkalsemisi olan 55 yaşındaki hastada parathormon yüksek, fosfat düşük bulunuyor. Parathormonun böbrekte fosfat düzeyini düşüren başlıca etkisi aşağıdakilerden hangisidir?","options":["Distal tübülde kalsiyum atılımını artırması","Glomerüler filtrasyonu büyük ölçüde baskılaması","Henle kulpunda magnezyum geri emilimini sıfırlaması","Toplayıcı kanalda aquaporin-2 yerleşimini engellemesi","Proksimal tübülde sodyum-fosfat kotransportunu azaltması"],"correct":4,"exp":"PTH proksimal tübülde sodyum-fosfat kotransporterlerini azaltarak fosfat geri emilimini düşürür ve fosfatüri yapar. Aynı zamanda distal nefronda kalsiyum geri emilimini artırır."},{"id":5226,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Uzun süren açlıkta glukozu düşen sağlıklı kişide glukagon artışı sonrası hepatik glukoz çıkışı yükseliyor. Bu hormonal yanıtın kan glukozunu toparlamasında beklenen karaciğer etkisi aşağıdakilerden hangisidir?","options":["Kas hücresinde GLUT4 translokasyonunun artması","Glikojenoliz ve glukoneogenezin hızlanması","Pankreas beta hücresinde insülin ekzositozunun artması","Adipoz dokuda lipoprotein lipazın baskın uyarılması","Böbrek toplayıcı kanalında su geri emiliminin artması"],"correct":1,"exp":"Glukagon karaciğerde cAMP aracılığıyla glikojen yıkımını ve glukoneogenezi artırır. Bu etki özellikle açlıkta kan glukozunun korunmasını sağlar."},{"id":5227,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":5,"q":"Postpartum üçüncü günde emziren annede süt ejeksiyonu sırasında uterus krampları da belirginleşiyor. Bu iki yanıtı birlikte açıklayan hormon ve primer etki yeri aşağıdakilerden hangisidir?","options":["Prolaktin - meme alveol epitelinde laktoz sentezi","FSH - over granüloza hücresinde aromataz aktivasyonu","Oksitosin - meme miyoepitelyal hücresi ve miyometriyum kasılması","Progesteron - miyometriyum gevşemesi","Kortizol - meme yağ dokusunda lipoliz"],"correct":2,"exp":"Emme refleksi oksitosin salınımını artırır. Oksitosin meme miyoepitelyal hücrelerini kasarak süt ejeksiyonunu, miyometriyumu kasarak postpartum uterin krampları oluşturur."},{"id":5228,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Ani dispne ve plöritik göğüs ağrısıyla başvuran 42 yaşındaki hastanın BT pulmoner anjiyografisinde segmental pulmoner emboli saptanıyor. Embolinin distalindeki alveoller açık ve havalanmakta, ancak kapiller kan akımı kesilmiştir. Karşı akciğer alanlarında ventilasyon ve perfüzyon eşleşmesi büyük ölçüde normaldir. Ventilasyon/perfüzyon oranının sonsuza yaklaştığı bu bölgede alveoler gaz bileşimi zamanla hangi ortama yaklaşır?","options":["Saf karbondioksite","Miks venöz kana, yani düşük PO2 ve yüksek PCO2 değerlerine","Arter kanına, yani normal PO2 ve normal PCO2 değerlerine","Tam şant alanına, yani oksijensiz ve karbondioksitsiz ortama","İnspire edilen havaya, yani yüksek PO2 ve düşük PCO2 değerlerine"],"correct":4,"exp":"Perfüzyonu olmayan fakat ventilasyonu süren alveol fizyolojik ölü boşluk gibi davranır. Kapiller kandan CO₂ gelmediği ve oksijen uzaklaştırılmadığı için alveoler PCO₂ düşer, PO₂ yükselir; gaz bileşimi inspire edilen havaya yaklaşır. Şantta ise bunun tersi biçimde perfüzyon sürer, ventilasyon yoktur ve alveoler gaz miks venöz kana yaklaşır."},{"id":5229,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Ağır pnömonisi olan 68 yaşındaki hastada sağ alt lobda alveoller sıvıyla dolu ve ventilasyon çok azalmıştır, ancak perfüzyon sürmektedir. Bu bölgede alveoler gaz bileşimi hangi değere yaklaşır?","options":["İnspire edilen havanın PO2 ve PCO2 değerlerine","Atmosferik havadaki azot yüzdesinin sıfır olduğu duruma","Miks venöz kanın düşük PO2 ve yüksek PCO2 değerlerine","Bronşiyal ven kanındaki oksijen satürasyonunun üstüne","Saf oksijen solunan odadaki kuru gaz basıncına"],"correct":2,"exp":"Ventilasyonu azalıp perfüzyonu süren alan şant benzeri davranır. Gaz alışverişi yetersiz olduğu için alveoler gaz miks venöz kan değerlerine yaklaşır."},{"id":5230,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Tip II pnömositlerin salgıladığı sürfaktanın alveol stabilitesi üzerindeki etkisi için hangi ifade en uygundur?","options":["Küçük alveollerde yüzey gerilimini orantısal olarak daha fazla azaltır","Sadece büyük alveollerde etkili olduğu için Laplace ilişkisini değiştirmez","Alveol yüzey gerilimini artırarak küçük alveollerin kollabe olmasını kolaylaştırır","Alveoler makrofajların fagositozunu büyük ölçüde baskılar","Pulmoner kapiller hidrostatik basıncı doğrudan yükseltir"],"correct":0,"exp":"Sürfaktan yüzey gerilimini azaltır; küçük alveollerde moleküller daha yoğunlaştığı için bu etki daha belirgindir. Böylece Laplace yasasına göre kollaps eğilimi azalır ve alveoller stabilize olur."},{"id":5231,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Kronik amfizemi olan 64 yaşındaki hastada total akciğer kapasitesi artmış, elastik geri çekim azalmış ve ekspirasyon uzamıştır. Bu hastada zorlu ekspirasyon sırasında hava yolu kollapsını kolaylaştıran ana değişiklik aşağıdakilerden hangisidir?","options":["Alveol septalarının kalınlaşarak difüzyon mesafesini uzatması","Bronş düz kas tonusunun azalarak hava yolu çapını genişletmesi","Plevral basıncın inspirasyonda atmosfer basıncının altına inmesi","Sürfaktan yapımının artarak alveol yüzey gerilimini düşürmesi","Elastik geri çekim kaybı nedeniyle küçük hava yollarını açık tutan radyal traksiyonun azalması"],"correct":4,"exp":"Amfizemde alveoler duvar yıkımı elastik geri çekimi ve radial traksiyonu azaltır. Zorlu ekspirasyonda intratorasik basınç artınca desteklenmeyen küçük hava yolları erken kapanır."},{"id":5232,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Lober pnömonisi olan hastada oksijen verilmesine rağmen hipoksemi beklenenden az düzeliyor; etkilenen alveoller perfüze fakat hava ile dolmuyor. Bu gaz değişim bozukluğunu en iyi açıklayan durum aşağıdakilerden hangisidir?","options":["Ölü boşluk ventilasyonunun tek başına artması","Alveoler PCO2'nin sıfıra yaklaşması","Ventile olmayan alveollerden venöz karışımın artması","Difüzyon kapasitesinin egzersizde seçici artması","Hemoglobinin oksijene afinitesinin belirgin biçimde azalması"],"correct":2,"exp":"Pnömonide bazı alveoller perfüze olduğu halde ventile olmaz; fizyolojik şant oluşur. Şant kanı oksijenlenmiş kanla karıştığı için hipoksemi yüksek oksijene sınırlı yanıt verebilir."},{"id":5233,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Kapalı garajda bulunan hastada baş ağrısı, konfüzyon ve laktik asidoz vardır; arteriyel PaO2 normal sınıra yakın ölçülürken dokular oksijen kullanamıyor. Karbonmonoksit maruziyetinde beklenen temel oksijen taşıma değişikliği aşağıdakilerden hangisidir?","options":["Alveoler oksijen parsiyel basıncının belirgin artması","Hemoglobine bağlı oksijen içeriğinin azalması ve eğrinin sola kayması","2,3-BPG artışına bağlı oksijen salınımının kolaylaşması","Plazmada çözünmüş oksijenin hemoglobinden bağımsız çoğalması","Pulmoner kapiller transit süresinin uzaması"],"correct":1,"exp":"Karbonmonoksit hemoglobine yüksek afiniteyle bağlanır, oksijen taşıma kapasitesini azaltır ve kalan bağlanma bölgelerinin oksijeni daha sıkı tutmasına neden olur. PaO2 normal olabilir çünkü çözünmüş oksijeni yansıtır."},{"id":5234,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Opioid intoksikasyonu olan 30 yaşındaki hastada solunum sayısı belirgin azalmış, PaCO2 yükselmiş ve pH düşmüştür. Bu tabloda merkezi kemoreseptörleri en güçlü uyaran değişiklik aşağıdakilerden hangisidir?","options":["Arteriyel kandaki oksijen içeriğinin hafif azalması","Karotis cisimciğinde glukoz oksidasyonunun artması","Plazma bikarbonatının eritrosite girememesi","CO2'nin beyin omurilik sıvısında H+ artışına yol açması","Akciğer J reseptörlerinin belirgin biçimde baskılanması"],"correct":3,"exp":"CO2 kan-beyin bariyerini kolay geçer ve BOS'ta karbonik asit üzerinden H+ oluşturur. Merkezi kemoreseptörler bu H+ artışına duyarlıdır; hiperkapni normalde ventilasyonu güçlü uyarır."},{"id":5235,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"İnterstisyel akciğer hastalığı olan 58 yaşındaki kadında akciğer kompliansı azalmış ve hızlı-yüzeyel solunum paterni gelişmiştir. Bu paternin solunum işi açısından en uygun açıklaması aşağıdakilerden hangisidir?","options":["Sert akciğerde tidal hacmi küçültmek elastik işi sınırlar","Hava yolu direnci çok arttığı için ekspirasyon büyük ölçüde pasifleşir","Elastik iş azaldığı için derin ve yavaş solunum tercih edilir","Ölü boşluk ventilasyonu sıfıra indiği için solunum sayısı önemsizleşir","Diyafram kasılması ortadan kalktığı için apne gelişir"],"correct":0,"exp":"Restriktif hastalıkta komplians düşer ve hacim artırmanın elastik maliyeti yükselir. Bu nedenle hasta daha küçük tidal hacimlerle ve daha yüksek frekansta soluyarak toplam işi azaltmaya çalışır."},{"id":5236,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Periferik sinir kesisi sonrası akson distalinde dejenerasyon gelişen hastada, rejenerasyonun başarılı olabilmesi için Schwann hücrelerinin hangi katkısı en önemlidir?","options":["Bazal lamina tüpleri ve büyüme faktörleriyle akson tomurcuklarına yol göstermesi","Merkezi sinir sistemindeki oligodendrositleri çoğaltması","Sinaptik aralıktaki asetilkolini kalıcı olarak artırması","Nöron gövdesinde aksiyon potansiyelini büyük ölçüde baskılaması","Miyelin kılıfının ortadan kalkmasıyla akson çapının küçülüp iletim hızının düşmesi"],"correct":0,"exp":"Periferik sinirde Schwann hücreleri ve bazal lamina, distal yolda akson büyümesini yönlendiren bir kılavuz oluşturur. Bu özellik periferik sinir rejenerasyonunun merkezi sinir sistemine göre daha başarılı olmasını sağlar."},{"id":5237,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Ev yapımı konserve sonrası diplopi, ağız kuruluğu ve simetrik inen paralizi gelişen hastada duyu muayenesi korunmuştur. Nöromüsküler iletimde beklenen temel presinaptik bozukluk aşağıdakilerden hangisidir?","options":["Miyelin internodlarının kısalması","Postsinaptik nikotinik reseptör sayısının artması","SNARE aracılı asetilkolin vezikül salınımının engellenmesi","Asetilkolinesterazın sinaptik aralıkta çoğalması","Kas iğciği afferent deşarjının artması"],"correct":2,"exp":"Botulinum toksini presinaptik SNARE proteinlerini hedefleyerek asetilkolin veziküllerinin ekzositozunu engeller. Motor ve otonom kolinerjik sinapslarda iletim azalır."},{"id":5238,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşındaki erkek hasta birkaç haftadır sağ elde ince işlerde zorlanma ve kas seğirmeleri tarif ediyor. Muayenede tenar kaslarda hafif atrofi, derin tendon reflekslerinde artış ve Babinski pozitifliği saptanıyor. Bu bulguları birlikte açıklayan nöronal etkilenme modeli hangi seçenekte en olasıdır?","options":["Primer duysal ganglion nöronlarının dejenerasyonu","Sadece dorsal kolon liflerinin demiyelinizasyonu","Nöromüsküler kavşakta asetilkolin reseptör blokajı","Saf serebellar Purkinje hücre kaybı","Üst ve alt motor nöronların birlikte etkilenmesi"],"correct":4,"exp":"Atrofi ve fasikülasyon alt motor nöron, hiperrefleksi ve Babinski üst motor nöron etkilenmesini düşündürür. Aynı hastada bu iki bulgu grubunun birlikteliği motor nöron havuzlarının beraber tutulmasıyla açıklanır."},{"id":5239,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Optik nörit ve internükleer oftalmopleji atakları olan genç kadında santral sinir sistemi plakları saptanıyor. Etkilenen aksonlarda iletim hızının azalmasını en iyi açıklayan fizyolojik değişiklik aşağıdakilerden hangisidir?","options":["Akson çapının ani olarak iki katına çıkması","Sinaptik veziküllerde asetilkolin sentezinin artması","Miyelin kaybıyla saltatuvar iletimin bozulması","Astrositlerden glutamat geri alımının hızlanması","Dorsal kök ganglion hücrelerinin apoptozu"],"correct":2,"exp":"Miyelin internodlar boyunca membran direncini artırır ve impulsun Ranvier düğümleri arasında sıçrayarak ilerlemesini sağlar. Demiyelinizasyon kaçak akımı artırır, iletimi yavaşlatır veya bloke eder."},{"id":5240,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"68 yaşındaki kadın hasta istirahat tremoru ve hareket başlatmada yavaşlama nedeniyle değerlendiriliyor. Striatumda dopamin azalmasına bağlı indirekt yol aktivitesi baskın hale gelirse talamokortikal uyarıda hangi değişiklik beklenir?","options":["Subtalamik çekirdek aktivitesinin azalmasıyla talamusun disinhibe olması","Globus pallidus internusun talamusa inhibitör çıkışının artması","Globus pallidus internusun inhibisyonunun azalmasıyla talamusun aşırı uyarılması","Serebellar derin çekirdeklerden talamusa uyarıcı çıkışın kaybolması","Kortikospinal traktusta alfa motor nöron inhibisyonunun azalması"],"correct":1,"exp":"Dopamin azalınca indirekt yol kolaylaşır; subtalamik çekirdek GPi'yi daha fazla uyarır. GPi'nin talamusa GABAerjik inhibitör çıkışı artar ve kortikal motor aktivasyon azalır."},{"id":5241,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":5,"q":"Parkinson hastasında bradikinezi ve rijidite dopaminerjik nöron kaybıyla belirginleşiyor. Bazal gangliyon devrelerinde hareketin azalmasına en çok hangi işlevsel sonuç eşlik eder?","options":["Serebellar Purkinje hücrelerinden glutamat salınımının artması","Ön boynuz hücrelerinde asetilkolin sentezinin durması","Hipokampusta uzun süreli potansiyasyonun artması","Talamokortikal motor uyarının dolaylı yol baskınlığıyla azalması","Arka kolon liflerinde çaprazlaşmanın kaybolması"],"correct":3,"exp":"Nigrostriatal dopamin kaybı direkt yolu zayıflatır, dolaylı yolu görece güçlendirir. Globus pallidus internus çıkışı artar, talamus daha fazla inhibe olur ve kortikal motor aktivasyon azalır."},{"id":5242,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Epileptik nöbet nedeniyle benzodiazepin verilen 20 yaşındaki hastada kortikal internöronların hızlı inhibitör postsinaptik yanıtı güçleniyor. Bu yanıt en çok hangi reseptör-kanal ilişkisiyle açıklanır?","options":["NMDA reseptörü üzerinden kalsiyum girişi","AMPA reseptörü üzerinden sodyum girişi","Nikotinik reseptör üzerinden katyon girişi","GABA-A reseptörü üzerinden klorür iletkenliğinin artması","Metabotropik glutamat reseptörü üzerinden G protein aktivasyonu"],"correct":3,"exp":"GABA-A ligand kapılı klorür kanalıdır. Klorür iletkenliğinin artması membranı hiperpolarize eder veya şant inhibisyonu oluşturur; bu hızlı inhibitör postsinaptik yanıttır."},{"id":5243,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"19 yaşındaki kadın hasta bir sınav sırasında panik hissi, terleme ve çarpıntı yaşıyor. Aynı anda barsak hareketlerinin azalması ve pupillerin genişlemesi hangi otonom çıkış örüntüsüyle en iyi açıklanır?","options":["Enterik sinir sisteminin merkezi bağlantıdan büyük ölçüde bağımsız çalışması","Kraniyosakral parasempatik aktivitenin yaygın artması","Vagal efferentlerin kalbe seçici olarak artması","Somatik alfa motor nöron aktivitesinin azalması","Torakolomber sempatik aktivitenin artması"],"correct":4,"exp":"Stres yanıtında torakolomber sempatik sistem baskındır. Kalp hızı ve terleme artarken gastrointestinal motilite azalır, radial iris kası aktivasyonu ile midriyazis gelişir."},{"id":5244,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Diyabetik nöropatisi olan 58 yaşındaki erkekte ayak tabanında vibrasyon duyusu belirgin azalmış, ağrı duyusu görece korunmuştur. En çok etkilenen duysal lif tipi hangi seçenekte verilmiştir?","options":["Kalın miyelinli A-beta lifleri","İnce miyelinsiz C lifleri","Preganglionik sempatik B lifleri","İnce miyelinli A-delta lifleri","Gamma motor efferent lifleri"],"correct":0,"exp":"Vibrasyon ve ince dokunma büyük çaplı, kalın miyelinli A-beta lifleriyle taşınır. Ağrı ise A-delta ve C lifleriyle iletildiğinden seçici vibrasyon kaybı A-beta tutulumunu düşündürür."},{"id":5245,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Benign prostat hiperplazisine bağlı uzun süreli mesane çıkım obstrüksiyonu olan 70 yaşındaki hastada bilateral hidronefroz ve kreatinin artışı gelişiyor. Üreter ve pelviste biriken basınç Bowman boşluğuna kadar iletilirken renal plazma akımında başlangıçta belirgin değişiklik olmadığı varsayılıyor. Ultrasonografide kortikal kalınlık korunmuş, akut tam obstrüksiyon düşünülmüştür. Bu durumda glomerüler filtrasyon hızındaki değişikliği en doğrudan açıklayan mekanizma aşağıdakilerden hangisidir?","options":["Artar; çünkü efferent arteriyol direnci refleks olarak düşer","Değişmez; çünkü filtrasyon fraksiyonu sabit kalır","Artar; çünkü plazma onkotik basıncı azalır","Azalır; çünkü net filtrasyon basıncı düşer","Azalır; çünkü proksimal tübülde sodyum geri emilimi durur"],"correct":3,"exp":"Bowman boşluğundaki hidrostatik basınç glomerüler kapillerden filtrasyona karşı koyan kuvvetlerden biridir. Postrenal obstrüksiyonda bu basınç yükselir, net filtrasyon basıncı azalır ve GFR düşer. Değişiklik proksimal tübül sodyum geri emiliminin tamamen durmasından kaynaklanmaz. Uzamış obstrüksiyonda renal kan akımı ve parankim de ikincil olarak bozulabilir."},{"id":5246,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Diyabetik nefropatisi olan hastada hafif böbrek yetmezliğiyle orantısız hiperkalemi ve normal anyon açıklı metabolik asidoz gelişiyor; renin ve aldosteron yanıtı düşüktür. Bu tabloyu en iyi açıklayan nefron düzeyi sonuç aşağıdakilerden hangisidir?","options":["Proksimal tübülde bikarbonat geri emiliminin aşırı artması","İnen Henle kolunda su geçirgenliğinin belirgin biçimde azalması","Makula densada sodyum algısının kalıcı artması","Glomerüler filtrasyon bariyerinde albümin geçişinin azalması","Kortikal toplayıcı kanalda potasyum ve hidrojen sekresyonunun azalması"],"correct":4,"exp":"Hiporeninemik hipoaldosteronizmde aldosteron etkisi azalır. Kortikal toplayıcı kanalda sodyum geri emilimiyle ilişkili potasyum ve hidrojen sekresyonu düşer; hiperkalemi ve tip 4 RTA gelişir."},{"id":5247,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Makula densanın distal tübül sıvısında sodyum klorür artışını algılaması sonrasında glomerüle iletilen geri bildirim yanıtında hangi olay beklenir?","options":["Efferent arteriyolde prostaglandin aracılı vazodilatasyon","Afferent arteriyolde adenozin aracılı vazokonstriksiyon","Proksimal tübülde glukoz geri emiliminin azalması","Mezangial hücrelerden eritropoietin salınımı","Juxtaglomerüler hücrelerden renin salınımında artış"],"correct":1,"exp":"Distal tübüle fazla NaCl ulaşması GFR'nin göreli yüksek olduğunu gösterir. Makula densa adenozin/ATP sinyaliyle afferent arteriyolü daraltır ve GFR'yi düşürür; renin baskılanır."},{"id":5248,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Tip 2 diyabetli 56 yaşındaki hastaya SGLT2 inhibitörü başlanıyor. Tedavinin ilk günlerinde glukozüriyle birlikte hafif natriürez gelişmesi hangi nefron segmentindeki taşımanın azalmasına bağlıdır?","options":["Distal kıvrımlı tübülde sodyum-klor kotransportu","Henle kulpu çıkan kalın kolunda sodyum-potasyum-klor kotransportu","Proksimal tübül erken segmentinde sodyum-glukoz kotransportu","Toplayıcı kanalda epiteliyal sodyum kanalı","İnce inen kolda pasif sodyum difüzyonu"],"correct":2,"exp":"SGLT2 proksimal tübül erken segmentinde sodyumla birlikte glukoz geri emilimini sağlar. İnhibisyon glukozüri ve eşlik eden sodyum kaybı oluşturur."},{"id":5249,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":5,"q":"Üç gündür kusan 45 yaşındaki hastada metabolik alkaloz ve idrar klorür düzeyinde düşüklük saptanıyor. Böbrekte proksimal tübülde bikarbonat geri emilimini artıran başlıca hücresel süreç aşağıdakilerden hangisidir?","options":["Distal tübülde kalsiyum kanallarının kapanarak emilimin azalması","Henle kulbunun ince kolunda aktif bikarbonat sekresyonu yapılması","Toplayıcı kanal esas hücrelerinde akuaporin-2 yıkımının hızlanması","Na-H değiştirici etkinliğinin artması ve lümende karbonik anhidrazla CO2 oluşması","Makula densadan renin salınımının azalarak aldosteronun düşmesi"],"correct":3,"exp":"Proksimal tübülde H sekresyonu Na-H değiştiriciyle olur; lümende HCO3 ile birleşen H, karbonik anhidraz aracılığıyla CO2 oluşturur. CO2 hücreye girer ve bikarbonat yeniden kana taşınır."},{"id":5250,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Yeni tanı tip 1 diyabetli hastada erken dönemde glomerüler hiperfiltrasyon ve mikroalbüminüri gelişiyor. Bu hemodinamik değişikliği en iyi açıklayan intraglomerüler sonuç aşağıdakilerden hangisidir?","options":["Efferent arteriyol tonusunun artmasıyla glomerüler kapiller basıncın yükselmesi","Mezangiyal hücrelerden renin salgılanarak sistemik basıncın artması","Bowman kapsülü içi basıncın düşerek filtrasyonu kolaylaştırması","Toplayıcı kanalda üre geçirgenliğinin azalarak konsantrasyonun bozulması","Distal tübülde sodyum-klor kotransportunun azalarak tuz kaybı yapması"],"correct":0,"exp":"Diyabetin erken döneminde tubuloglomerüler geri bildirim ve renin-anjiyotensin sistemi değişiklikleri intraglomerüler basıncı artırabilir. Efferent arteriyol tonusu glomerüler kapiller basıncı yükselterek hiperfiltrasyona katkı sağlar."},{"id":5251,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Primer hiperaldosteronizmi olan 42 yaşındaki kadında hipertansiyon ve hipokalemi saptanıyor. Toplayıcı kanal esas hücresinde aldosteron etkisiyle hangi taşıyıcı değişikliği bu tabloya en çok katkı sağlar?","options":["Na-K-2Cl kotransporterinin lümene taşınması","ENaC ve Na-K ATPaz aktivitesinin artması","Na-HCO3 kotransporterinin inhibisyonu","Aquaporin-1 ekspresyonunun artması","ROMK kanallarının ileri derecede daralması"],"correct":1,"exp":"Aldosteron esas hücrede ENaC ve bazolateral Na-K ATPaz aktivitesini artırır. Sodyum geri emilimi lümeni daha negatif yapar ve potasyum sekresyonu artar."},{"id":5252,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"Açlıkta protein yıkımı artan bir hastada böbrek medullasında üre geri dönüşümünün artması idrarın yoğunlaştırılmasına hangi yolla katkı sağlar?","options":["Kortikal toplayıcı kanalda sodyum geri emilimini durdurarak","Afferent arteriyolde vazodilatasyon yaparak","Proksimal tübülde glukoz taşınmasını artırarak","İç medullada ozmotik gradyanı güçlendirerek","Distal tübülde kalsiyum atılımını artırarak"],"correct":3,"exp":"Üre iç medüller toplayıcı kanaldan interstisyuma geçip Henle kulpuna geri döner. Bu döngü iç medullanın hipertonisitesini artırarak su geri emilimini ve idrar yoğunlaşmasını destekler."},{"id":5253,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Yarık dudaklı bir bebekte filtrumun yanında üst dudak sürekliliği bozulmuş ve primer damak etkilenmiştir. Normal gelişimde bu bölgenin oluşması için hangi embriyolojik kaynaşma gereklidir?","options":["Tiroid taslağının foramen cecumdan göç etmesi","İkinci faringeal arkın üçüncü ark üzerine büyümesi","Nöral tüpün kaudal nöropordan kapanması","Dördüncü poştan ultimobrankiyal cismin ayrılması","Maksiller çıkıntıların medial nazal çıkıntılarla kaynaşması"],"correct":4,"exp":"Üst dudak ve primer damak, maksiller çıkıntıların medial nazal çıkıntılarla kaynaşmasına bağlıdır. Bu birleşme aksadığında yarık dudak ve primer damak defektleri ortaya çıkar."},{"id":5254,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Kronik otitis media nedeniyle cerrahi geçiren çocukta dil ön iki üçte birinde tat azalması ve submandibular salgıda azalma gelişiyor. Bu bulgular en çok hangi ark-sinir ilişkisiyle uyumludur?","options":["Birinci ark ve mandibular trigeminal dal","Dördüncü ark ve superior laringeal sinir","Üçüncü ark ve glossofaringeal sinir","İkinci ark ve fasiyal sinirin korda timpani dalı","Altıncı ark ve rekürren laringeal sinir"],"correct":3,"exp":"Dil ön iki üçte birinin tat duyusu ve submandibular-sublingual parasempatik lifler fasiyal sinirin korda timpani dalıyla taşınır. Fasiyal sinir ikinci arkla ilişkilidir."},{"id":5255,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":5,"q":"Bebekte orta hatta, hyoid kemik düzeyinde, yutkunmakla hareket eden kistik kitle izleniyor. Bu lezyonun oluşumunda embriyolojik kalıntı hangi göç yolu üzerinde kalmıştır?","options":["Foramen caecumdan boyun ön orta hatta inen tiroglossal kanal","Dördüncü poştan üst paratiroide uzanan hat","Birinci faringeal yarıktan dış kulak yoluna uzanan hat","Nöral krestten maksiller prominense uzanan hat","İkinci arkın servikal sinüsü örttüğü lateral boyun hattı"],"correct":0,"exp":"Tiroid primordiyumu dil kökündeki foramen caecumdan aşağı iner. Tiroglossal kanal kalıntısı orta hatta, yutkunmakla hareket eden kist oluşturur."},{"id":5256,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Yenidoğanda beslenme sırasında siyanoz gelişiyor, ağlayınca solunumu rahatlıyor ve nazal sondanın koanadan geçmediği görülüyor. Bu tabloyu en iyi açıklayan embriyolojik olay aşağıdakilerden hangisidir?","options":["Oronazal membranın persiste ederek arka nazal açıklığı kapatması","İkinci faringeal poşun timusa dönüşmesi","Tiroid divertikülünün boyunda kalması","Maksiller çıkıntıların lateral nazal çıkıntıyla fazla birleşmesi","Optik vezikülün lens plakodunu uyaramaması"],"correct":0,"exp":"Koanal atrezi, nazal boşluk ile nazofarenks arasındaki membranöz/kemik açıklığın oluşmamasıyla ilişkilidir. Yenidoğan zorunlu nazal solunum yaptığı için beslenmede siyanoz belirginleşir, ağlayınca ağızdan hava alabilir."},{"id":5257,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Boyun orta hattında, yutkunma ve dil çıkarma ile hareket eden kistik kitle saptanan çocukta enfeksiyon atakları oluyor. Bu lezyonun kökenini en iyi açıklayan gelişimsel kalıntı aşağıdakilerden hangisidir?","options":["Tiroidin foramen cecumdan iniş yolu üzerinde kanal kalıntısı bırakması","Üçüncü poşun timusa göç edememesi","Maksiller çıkıntının medial nazal çıkıntıyla birleşmemesi","Ultimobrankiyal cismin tiroid içine katılamaması","İkinci ark yarığının kapanmaması"],"correct":0,"exp":"Tiroglossal kanal kisti, tiroid taslağının foramen cecumdan boyuna göçü sırasında geride kalan kanal artıklarından gelişir. Hyoid ve dil köküyle ilişkisi nedeniyle yutkunma ve dil hareketiyle yer değiştirir."},{"id":5258,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Fonokardiyogramda ikinci kalp sesinden hemen sonra sol ventrikül basıncı hızla düşerken ventrikül hacminin değişmediği kısa bir dönem izleniyor. Bu dönem kardiyak siklusun hangi fazına karşılık gelir?","options":["Azalmış ejeksiyon","Hızlı ventrikül doluşu","Atriyal sistol","İzovolümetrik kontraksiyon","İzovolümetrik relaksasyon"],"correct":4,"exp":"Aort kapağı kapandıktan sonra mitral kapak açılana kadar tüm kapaklar kapalıdır. Ventrikül basıncı düşer fakat hacim değişmez; bu dönem izovolümetrik relaksasyondur."},{"id":5259,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"Ventrikül miyositinde aksiyon potansiyelinin plato fazını oluşturan iyon akımı dengesi hangi seçenekte en doğru verilmiştir?","options":["Hızlı sodyum girişi ile klorür çıkışı","HCN kanallarından sodyum girişi","Sodyum-potasyum pompasının belirgin biçimde yavaşlaması","L tipi kalsiyum girişi ile potasyum çıkışının dengelenmesi","T tipi kalsiyum kanallarının tek başına aktivasyonu"],"correct":3,"exp":"Ventrikül aksiyon potansiyelinin faz 2 plato döneminde L tipi kalsiyum kanallarından içe akım, potasyum kanallarından dışa akımla dengelenir. Bu denge kasılma için kalsiyum girişini sürdürür."},{"id":5260,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Prematüre doğan bir bebekte doğumdan kısa süre sonra solunum sıkıntısı, düşük akciğer kompliyansı ve yaygın atelektazi gelişiyor. Tip II pnömosit işlevindeki yetersizlik hangi fiziksel sonucu doğurur?","options":["Alveol yüzey geriliminin azalmasıyla alveollerin aşırı genişlemesi","Alveol-kapiller membranda oksijen difüzyon mesafesinin kısalması","Sürfaktan azalmasına bağlı yüzey geriliminin artması ve kollaps eğilimi","Bronş düz kasında beta-2 yanıtının artması","Pulmoner kapiller hidrostatik basıncın düşmesi"],"correct":2,"exp":"Tip II pnömositler sürfaktan üretir. Sürfaktan azalınca alveol yüzey gerilimi artar, özellikle küçük alveoller kollabe olur ve akciğer kompliyansı düşer."},{"id":5261,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Prematüre yenidoğanda ekspirasyon sonunda alveollerin kollabe olduğu, akciğer kompliyansının düşük ve solunum işinin yüksek olduğu görülüyor. Bu bulguları en iyi açıklayan yüzey kuvveti değişikliği aşağıdakilerden hangisidir?","options":["Alveoler makrofajların fagositozunun artması","Pulmoner arteriyollerde oksijene bağlı vazodilatasyon","Hava yolu direncinin büyük bronşlarda sıfırlanması","Tip I pnömositlerden mukus sekresyonunun artması","Sürfaktan eksikliğiyle alveol yüzey geriliminin artması"],"correct":4,"exp":"Sürfaktan alveol yüzey gerilimini azaltır ve özellikle küçük alveollerin kollapsını önler. Eksikliğinde kompliyans düşer, atelektazi gelişir ve solunum işi artar."},{"id":5262,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Duodenal ülser nedeniyle değerlendirilen 48 yaşındaki erkekte gastrin düzeyi yüksek bulunuyor. Gastrinin parietal hücre asit sekresyonunu artırmasında en önemli ara hücresel aracı hangi seçenektir?","options":["Enterokromaffin benzeri hücreden histamin salınımının artması","I hücresinden kolesistokinin salınımının azalması","D hücresinden somatostatin salınımının artması","S hücresinden sekretin salınımının azalması","Goblet hücresinden müsin salınımının baskılanması"],"correct":0,"exp":"Gastrin parietal hücreyi doğrudan uyarır, ancak önemli etkilerinden biri ECL hücresinden histamin salınımını artırmasıdır. Histamin H2 reseptörüyle asit sekresyonunu güçlendirir."},{"id":5263,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Yemekten sonra terminal ileum kontraksiyonları artıyor ve çekuma içerik geçişi hızlanıyor; açlık dönemindeki düzenli temizlik dalgaları ise baskılanıyor. Bu postprandiyal yanıtı en iyi açıklayan refleks aşağıdakilerden hangisidir?","options":["Defekasyon refleksinin baskılanarak rektal doluşun artması","Mide distansiyonu ve gastrinin gastroileal refleksi uyarması","Vagal uyarının azalarak mide boşalmasının yavaşlaması","Kolonda haustral segmentasyonun azalarak geçişin hızlanması","Sekretinin ileal düz kasta doğrudan gevşeme oluşturması"],"correct":1,"exp":"Gastroileal refleks, mide distansiyonu ve gastrin etkisiyle ileal motiliteyi artırarak içerik geçişini kolaylaştırır. Migratuvar motor kompleks ise açlık döneminde belirgindir ve yemekle baskılanır."},{"id":5264,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Kilo kaybı, demir eksikliği ve kronik ishalle başvuran hastada anti-doku transglutaminaz pozitifliği ve duodenal biyopside villus atrofisi saptanıyor. Malabsorpsiyonu en iyi açıklayan primer fizyolojik sonuç aşağıdakilerden hangisidir?","options":["Kolonik motilitenin belirgin biçimde yavaşlaması","Pankreatik bikarbonat sekresyonunun artması","Emilim yüzey alanının azalması","Safra tuzlarının midede yıkılması","Parietal hücrelerden gastrin salınımı"],"correct":2,"exp":"Çölyak hastalığında villus atrofisi ve kript hiperplazisi ince bağırsak emilim yüzeyini azaltır. Demir gibi proksimal ince bağırsaktan emilen maddelerin eksikliği bu nedenle gelişebilir."},{"id":5265,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Primer hipotiroidisi olan 46 yaşındaki kadında TSH yüksek, serbest T4 düşüktür. TRH uyarısının tirotroplarda TSH sentezini artırması hangi hücre içi yolakla en iyi açıklanır?","options":["Gq aracılığıyla fosfolipaz C, IP3 ve kalsiyum artışı","Gs aracılığıyla adenilat siklaz aktivasyonu","Tirozin kinaz reseptörü üzerinden MAPK aktivasyonu","JAK-STAT üzerinden tiroglobulin proteolizi","Nükleer reseptör üzerinden TSH depolanmasının baskılanması"],"correct":0,"exp":"TRH reseptörü Gq ile eşleşir; fosfolipaz C aktivasyonu IP3 ve DAG üretir, hücre içi kalsiyum artar. Bu yolak tirotroplarda TSH salınımını destekler."},{"id":5266,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Çarpıntı, kilo kaybı ve tremoru olan hastada TSH baskılı, serbest T4 yüksek ve TSH reseptör antikoru pozitiftir. Tiroid bezinde beklenen fizyolojik yanıt aşağıdakilerden hangisidir?","options":["TSH reseptör uyarısıyla hormon sentezi ve salınımının artması","Tiroglobulin sentezinin baskılanması","Parafoliküler C hücrelerinden parathormon salınımı","İyot organifikasyonunun belirgin biçimde yavaşlaması","Deiyodinaz aktivitesinin tüm dokularda kaybolması"],"correct":0,"exp":"Graves hastalığında antikorlar TSH reseptörünü uyarır. Bu uyarı iyot alımı, organifikasyon, tiroglobulin işlenmesi ve tiroid hormon salınımını artırır; hipofizer TSH negatif geri bildirimle baskılanır."},{"id":5267,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Uzun süredir sistemik glukokortikoid kullanan 55 yaşındaki hastada tedavi aniden kesiliyor ve halsizlik, hipotansiyon, hiponatremi gelişiyor. Bu tabloda hangi fizyolojik uyumun baskılanmış olması en olasıdır?","options":["Tiroid follikül hücresinde iyot organifikasyonu","Pankreas beta hücresinde glukozla uyarılan insülin salınımı","Paratiroid bezde kalsiyuma duyarlı reseptör aktivitesi","Leydig hücresinde LH yanıtı","Hipotalamus-hipofiz-adrenal aksın CRH ve ACTH üretimi"],"correct":4,"exp":"Ekzojen glukokortikoidler CRH ve ACTH salınımını negatif geri bildirimle baskılar. Ani kesilme sonrası adrenal korteks yeterli kortizol yanıtı veremeyebilir ve sekonder adrenal yetmezlik gelişir."},{"id":5268,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Altı aydır tekrarlayan akciğer enfeksiyonu olan 7 yaşındaki erkek çocukta ter klorürü yüksek bulunuyor. Solunum yolu epitelinde dehidrate mukusun birikmesine en doğrudan yol açan hücresel olay aşağıdakilerden hangisidir?","options":["Primer lizozomların fagozomla birleşememesi ve bakteri temizliğinin bozulması","Bazolateral Na-K-ATPaz etkinliğinin azalarak iyon gradyanının bozulması","Apikal zardaki cAMP bağımlı klor kanalından klor sekresyonunun azalması","Oluklu bağlantılar üzerinden kalsiyum geçişinin artarak silya hareketini bozması","Endoplazmik retikuluma ribozom bağlanmasının artarak mukus yapımını çoğaltması"],"correct":2,"exp":"Kistik fibroziste CFTR işlev kaybı apikal klor sekresyonunu azaltır; sodyum ve su lümenden geri emilir, mukus koyulaşır. Bu bilgi yalnız kanal adını değil, epitel su hareketinin yönünü anlamayı gerektirir."},{"id":5269,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Kemoterapi sonrası periferik nöropati gelişen 54 yaşındaki kadında aksonal taşınmanın bozulduğu düşünülüyor. Veziküllerin akson terminalinden hücre gövdesine geri taşınmasında hangi motor protein beklenir?","options":["Kinezin","Dinein","Miyozin II","Spektrin","Aktinin"],"correct":1,"exp":"Retrograd aksonal taşınma mikrotübüller üzerinde dinein ile gerçekleşir. Kinezin çoğunlukla anterograd taşınmada rol alır; aktin ilişkili motor miyozindir."},{"id":5270,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Bir hücrede reseptör aracılı endositozla alınan LDL partiküllerinin kolesterolünün sitozole ulaşabilmesi için hangi organel basamağı önceliklidir?","options":["Peroksizomda beta oksidasyon","Golgi sisternasında O-glikozilasyon","Mitokondri matriksinde pirüvat oksidasyonu","Nükleolusta rRNA transkripsiyonu","Endozom asidifikasyonu ve lizozomal hidroliz"],"correct":4,"exp":"LDL reseptör aracılı endositozla alınır, endozom asidifikasyonu reseptör-ligand ayrılmasını sağlar ve lizozomal hidrolizle kolesterol esterleri serbestleşir."},{"id":5271,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":5,"q":"Uzun süre aç kalan bir hastada hepatositlerde otofajinin arttığı saptanıyor. Bu yanıtta mTOR baskılandığında hücre içinde hangi sonuç beklenir?","options":["Ribozomal protein sentezinin seçici olarak artması","Proteazomun büyük ölçüde inaktive olması","Otofagozom oluşumunun kolaylaşması","Peroksizom membranının kaybolması","DNA polimeraz aktivitesinin hızlanması"],"correct":2,"exp":"Besin azalması ve enerji stresi mTOR aktivitesini düşürür; bu durum otofaji başlatıcı kompleksleri serbestleştirerek otofagozom oluşumunu artırır."},{"id":5272,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Ağır yanık sonrası sıvı kaybı gelişen hastada dermisteki temel ara madde bileşenlerinin su tutma kapasitesi klinik açıdan önem kazanır. Bu özellik en çok hangi molekül grubuyla ilişkilidir?","options":["Sülfatlanmış glikozaminoglikanlar","Elastin lamelleri","Fibronektin dimerleri","Laminin ağları","Tip I kollajen fibrilleri"],"correct":0,"exp":"Glikozaminoglikanlar yüksek negatif yükleriyle su ve katyon bağlar; bağ dokusunun turgoru ve difüzyon özelliklerinde belirleyicidir."},{"id":5273,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Septik şokta kapiller kaçak artan hastanın endotelinde VE-kadherin bağlantılarının zayıfladığı gösteriliyor. Hücreler arası sıvı geçişindeki artışı en iyi açıklayan doku düzeyi değişiklik aşağıdakilerden hangisidir?","options":["Adherens bağlantıların zayıflamasıyla paraselüler geçirgenliğin artması","Desmozomların ara filamentleri daha sıkı bağlaması","Hemidesmozomların bazal laminaya tutunmasının artması","Gap junction kanallarından protein geçişinin hızlanması","Fokal adezyonların kollajen IV sentezini durdurması"],"correct":0,"exp":"Endotel bariyerinde kadherin temelli adherens bağlantılar hücreler arası aralığı sınırlar. Bu bağlantıların zayıflaması paraselüler sıvı ve protein geçişini artırarak kapiller kaçak oluşturur."},{"id":5274,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Ehlers-Danlos sendromu olan 22 yaşındaki kadında yara iyileşmesi gecikiyor ve eklem hipermobilitesi belirgin. Ekstrasellüler matrikste çekme dayanıklılığının azalması en çok hangi süreçteki bozulmayla açıklanır?","options":["Elastin üzerine fibrillin dizilimi","Proteoglikan çekirdek proteinlerinin sülfatlanması","Lamininin bazal laminaya tutunması","Hyaluronanın su bağlaması","Kollajen fibrillerinin çapraz bağlanması ve olgunlaşması"],"correct":4,"exp":"Kollajenin posttranslasyonel işlenmesi, fibril organizasyonu ve çapraz bağlanması bağ dokusunun çekme dayanıklılığı için kritiktir; bozulduğunda hipermobilite ve yara sorunları görülür."},{"id":5275,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Kronik gastritte yüzey epitelinin lümene bakan yüzünde mukus tabakasının korunması için hangi hücresel farklılaşma özelliği beklenir?","options":["Çok katlı yassı keratinizasyon","Yoğun desmin ara filamentleri","Sarkomer düzeninde aktin-miyozin dizilimi","Apikal salgı granülleri ve polarize ekzositoz","Miyelin kılıf sentezi"],"correct":3,"exp":"Mukus salgılayan epitellerde apikal granüller ve polarize ekzositoz lümene yönelik koruyucu salgıyı sağlar. Bu özellik epitel polaritesinin fonksiyonel sonucudur."},{"id":5276,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Malign hipertermi öyküsü olan hastaya genel anestezi verildikten sonra rijidite, hiperkapni ve hızlı ısı artışı gelişiyor. İskelet kasında kalsiyumun sitozolde aşırı birikmesine yol açan olay aşağıdakilerden hangisidir?","options":["Asetilkolinesteraz etkinliğinin artarak uyarı süresini kısaltması","Miyozin hafif zincir fosfatazının aşırı çalışarak gevşemeyi hızlandırması","T-tübüllerdeki voltaj kapılı sodyum kanallarının kalıcı kapanması","Sarkoplazmik retikuluma kalsiyum geri alımının hızlanması","Ryanodin reseptörü aracılığıyla sarkoplazmik retikulumdan kalsiyum salınımının kontrolsüz artması"],"correct":4,"exp":"Malign hipertermide RYR1 ilişkili kalsiyum salınımı kontrolsüz artar; kas kontraksiyonu ve ATP tüketimi belirginleşir. SERCA geri alımı bu yükü karşılayamaz."},{"id":5277,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Uzun mesafe koşucusunda kas biyopsisinde yorgunluğa dirençli, bol kapillerli ve miyoglobinden zengin liflerin baskın olduğu görülüyor. Bu liflerin dayanıklılığını en iyi açıklayan metabolik özellik aşağıdakilerden hangisidir?","options":["Miyozin hafif zincir fosfatazının inhibe olarak kasılmayı sürdürmesi","Enerjinin yalnızca anaerobik glikolizden sağlanarak laktat üretmesi","Sarkoplazmik retikulum kalsiyum pompasının yavaşlayarak gevşemeyi geciktirmesi","Nikotinik reseptörlerin uzun süre açık kalarak uyarıyı sürdürmesi","Oksidatif fosforilasyon kapasitesinin ve mitokondri yoğunluğunun yüksek olması"],"correct":4,"exp":"Tip I lifler mitokondri, miyoglobin ve kapiller yoğunluğu yüksek liflerdir. Aerobik metabolizmaya dayandıkları için yavaş kasılır fakat yorgunluğa dirençlidir."},{"id":5278,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Aşırı dilate ventrikülde sarkomerler optimal uzunluğun üzerine gerildiğinde kasılma gücünün düştüğü izleniyor. Bu azalmayı en iyi açıklayan sarkomer düzeyi değişiklik aşağıdakilerden hangisidir?","options":["Presinaptik asetilkolin salınımının artması","Z çizgilerinin birbirine birbirine yaklaşması","Troponin C'nin kalsiyuma afinitesinin aşırı derecede artması","Aktin-miyozin örtüşmesinin azalması","Düz kasta latch köprülerinin çoğalması"],"correct":3,"exp":"Kas uzunluğu optimal aralıkta olduğunda aktin ve miyozin örtüşmesi etkin çapraz köprü oluşumunu sağlar. Aşırı gerilmede örtüşme azalır ve geliştirilen aktif gerilim düşer."},{"id":5279,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Dayanıklılık antrenmanı yapan bir sporcunun kas biyopsisinde mitokondri ve kapiller yoğunluğu artmış lifler baskın bulunuyor. Bu liflerin kasılma ve metabolizma özellikleri için hangisi beklenir?","options":["Yavaş kasılma, yüksek oksidatif kapasite ve yorgunluğa direnç","Düşük oksidatif kapasite ve geniş çaplı lifler","Yüksek miyozin ATPaz aktivitesi ve hızlı yorulma","Hızlı glikolitik yorgunluk ve düşük miyoglobin","Sadece anaerobik glikolize bağımlı enerji üretimi"],"correct":0,"exp":"Tip I lifler yavaş kasılır, oksidatif metabolizmaya dayanır, miyoglobin ve mitokondri içerikleri fazladır; uzun süreli aktivitede yorgunluğa dirençlidir."},{"id":5280,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Düzenli siklusları olan 28 yaşındaki kadında ovulasyondan yaklaşık bir hafta sonra endometrium biyopsisi alınıyor. Bu dönemde implantasyona hazırlığı en iyi gösteren histolojik bulgu aşağıdakilerden hangisidir?","options":["Kıvrımlı bezlerde sekresyon ve stromal ödem","Prostatik bezlerde korpora amilasea","Miyometriumda yoğun sarkomer çizgilenmesi","Spermatogonyumlarda mayoz II tamamlanması","Çok katlı yassı epitelde keratin incileri"],"correct":0,"exp":"Luteal fazda progesteron etkisiyle endometrial bezler kıvrımlı ve sekretuar hale gelir, stroma ödemlenir; implantasyon penceresi bu hazırlığa bağlıdır."},{"id":5281,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Sertoli hücresinin lümene geçmek üzere olan germ hücrelerine destek verirken aynı zamanda kan-testis bariyerini oluşturması hangi bağlantı özelliğine dayanır?","options":["Bazal lamina ile hemidesmozom ilişkisi","Spermatid akrozomunda lizozomal enzim birikimi","Leydig hücreleri arasında gap junction artışı","Miyoid hücrelerde aktin-miyozin çapraz köprüleri","Komşu Sertoli hücreleri arasındaki sıkı bağlantılar"],"correct":4,"exp":"Kan-testis bariyeri komşu Sertoli hücreleri arasındaki sıkı bağlantılarla kurulur; gelişen germ hücreleri immün sistemden ve zararlı maddelerden korunur."},{"id":5282,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Polikistik over sendromu olan 24 yaşındaki kadında folikül gelişimi düzensiz ve hiperandrojenemi vardır. Granüloza hücrelerinin aromataz aktivitesini fizyolojik olarak en çok artıran gonadotropin aşağıdakilerden hangisidir?","options":["LH","FSH","HCG","Prolaktin","GnRH"],"correct":1,"exp":"İki hücre-iki gonadotropin modelinde LH teka hücresinde androjen sentezini, FSH ise granüloza hücresinde aromatazı artırarak östrojen üretimini destekler."},{"id":5283,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Folikül gelişimi izlenen kadında FSH artışı sonrası dominant folikülde östradiol üretimi belirginleşiyor. Granüloza hücresinde bu hormonal yanıtı en iyi açıklayan değişiklik aşağıdakilerden hangisidir?","options":["Leydig hücresinde testosteron sentezinin artması","Korpus luteumda hCG reseptörünün kaybolması","Prolaktinin hipotalamik GnRH pulslarını hızlandırması","Aromataz aktivitesinin artarak androjenleri östradiole çevirmesi","AMH'nin ovulasyon sonrası progesteronu yıkması"],"correct":3,"exp":"İki hücre-iki gonadotropin modelinde LH teka hücresinde androjen üretimini destekler; FSH ise granüloza hücresinde aromatazı artırarak androjenlerin östradiole dönüşmesini sağlar."},{"id":5284,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":5,"q":"Primer siliyer diskinezi nedeniyle yenidoğanda situs inversus totalis ve tekrarlayan solunum yolu enfeksiyonları saptanıyor. İç organ yerleşimindeki değişikliği en iyi açıklayan erken embriyonik olay aşağıdakilerden hangisidir?","options":["Trofoblast lakünlerinin maternal kanla dolarak uteroplasental dolaşımı başlatması","Hipoblast hücrelerinin göç ederek primer yolk kesesini döşemesi","Primitif çizginin kaudalden kraniyale doğru gerileyerek kaybolması","Nöral krest hücrelerinin faringeal arklara göç ederek mezenkim oluşturması","Nodal siliya akımının bozulmasıyla sol-sağ asimetrisinin hatalı kurulması"],"correct":4,"exp":"Embriyonik noddaki siliyer akım sol-sağ eksen sinyalinin kurulmasına katkı sağlar. Siliyer işlev bozukluğu laterality kusurlarına ve situs inversus gibi organ yerleşim değişikliklerine yol açabilir."},{"id":5285,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Ultrasonografide tek plasenta ve tek amniyon kesesini paylaşan monozigotik ikiz gebelik saptanıyor. Bu plasental-amniyotik düzen en çok hangi ayrılma zamanlamasıyla uyumludur?","options":["Döllenmeden hemen sonra iki ayrı zigot oluşması","Bilaminar disk oluştuktan sonra embriyonik diskin geç ayrılması","Morula döneminde zona pellucida içindeyken ayrılma","Blastokistte trofoblasttan önce sitotrofoblastın kaybolması","Gastrulasyon tamamlandıktan sonra notokordun ikiye ayrılması"],"correct":1,"exp":"Monokoryonik-monoamniyotik ikizlik genellikle amniyon oluştuktan sonra, embriyonik diskin geç ayrılmasıyla ilişkilidir. Daha erken ayrılmalar amniyon ve/veya koryon sayısını farklılaştırır."},{"id":5286,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Folik asit kullanmayan gebede nöral tüp kapanma defekti saptanıyor. Kraniokaudal katlanma ve nörülasyonun aksaması en çok hangi dönemde kritik sonuç doğurur?","options":["Fetal dönemin son trimesterinde","Puberte başlangıcında","Doğumdan hemen sonraki neonatal dönemde","Organogenez döneminin erken haftalarında","İmplantasyondan önceki morula evresinde"],"correct":3,"exp":"Nöral tüp kapanması erken organogenez döneminde gerçekleşir. Bu nedenle folat yetersizliği gebeliğin ilk haftalarında belirgin malformasyon riski oluşturur."},{"id":5287,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Monozigotik ikiz gebelikte iki amniyon ve tek koryon saptanıyor. Bu bulgu bölünmenin hangi zamanlamada gerçekleştiğini düşündürür?","options":["Zigotun ilk mitoz bölünmesinden önce ikiye ayrılması","İç hücre kitlesi ayrıldıktan sonra ancak amniyon oluşmadan önce bölünme olması","Morula evresinde kompaktasyon tamamlanmadan bölünme gerçekleşmesi","Primitif çizgi oluştuktan sonra geç dönemde bölünme olması","Plasentanın olgunlaşmasının ardından ikincil bölünme gelişmesi"],"correct":1,"exp":"Monokoryonik diamniyotik ikizlik, blastokist döneminde iç hücre kitlesinin ayrılmasıyla ilişkilidir; amniyon oluşmadan önce ayrıldığı için iki amniyon gelişir."},{"id":5288,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"Kronik böbrek hastalığı olan 62 yaşındaki erkekte normositer anemi gelişiyor. Kemik iliğinde eritroid serinin uyarılamamasında hangi sinyal azalması en olasıdır?","options":["Trombopoietin aracılı megakaryosit uyarısı","Eritropoietin aracılı eritroid progenitör sağkalımı","G-BOS aracılı nötrofil farklılaşması","IL-5 aracılı eozinofil maturasyonu","M-BOS aracılı monosit farklılaşması"],"correct":1,"exp":"Böbrek kaynaklı eritropoietin eritroid progenitörlerin sağkalım ve çoğalmasını destekler. Kronik böbrek hastalığında azalması normositer anemiye yol açar."},{"id":5289,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Akut hemolitik atak sonrası hastada birkaç gün içinde retikülosit sayısı belirgin artıyor. Kemik iliğinin bu yanıtını en iyi açıklayan hormonal-hücresel değişiklik aşağıdakilerden hangisidir?","options":["Trombopoietin azalmasıyla megakaryositlerin küçülmesi","G-BOS artışıyla yalnız nötrofil serisinin çoğalması","Eritropoietin artışıyla eritroid progenitör proliferasyonunun hızlanması","Timusta eritroid öncüllerin olgunlaşması","Hepcidin artışıyla retikülosit salınımının doğrudan artması"],"correct":2,"exp":"Hemoliz doku oksijenlenmesini azaltır ve böbrekten eritropoietin salınımını artırır. EPO eritroid progenitörleri destekler; birkaç gün içinde retikülositoz gelişir."},{"id":5290,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":5,"q":"Akut kan kaybından birkaç gün sonra retikülositoz gelişen hastada periferik kana çıkan hücrelerde hangi özellik beklenir?","options":["Çok loblu çekirdek ve azurofil granül","Yüzey immünoglobulini ve germinal merkez yanıtı","Ribozomal RNA kalıntıları nedeniyle supravital boyayla ağsı görünüm","Trombositlere parçalanan poliploid sitoplazma","Hemoglobin içermeyen çekirdekli eritroblast görünümü"],"correct":2,"exp":"Retikülositler çekirdeksizdir ancak ribozomal RNA kalıntısı taşır; supravital boyalarla ağsı görünüm verir ve artışı kemik iliği eritropoetik yanıtını gösterir."},{"id":5291,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":5,"q":"Tekrarlayan bakteriyel enfeksiyonları olan çocukta nötrofil sayısı normaldir; ancak lökositlerin endotele sıkı tutunamadığı ve dokuya geçemediği gösteriliyor. Bu migrasyon kusurunu en iyi açıklayan adezyon basamağı aşağıdakilerden hangisidir?","options":["Eritrositlerde hemoglobin oksijen bağlanmasının azalması","B hücresinde immünoglobulin sınıf değişiminin hızlanması","Megakaryositlerde endomitozun artması","İntegrin aracılı sıkı adezyonun bozulması","Eozinofillerde histamin yıkımının artması"],"correct":3,"exp":"Lökosit adezyon defektinde özellikle beta-2 integrin işlevi bozulursa nötrofiller endotele sıkı tutunamaz ve dokuya göç edemez. Nötrofil sayısı kanda yüksek olsa da enfeksiyon bölgesine ulaşım yetersizdir."},{"id":5292,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Doğum sonrası stridoru olan bebekte vokal kord abdüksiyonunda zayıflık ve larenks kıkırdaklarında gelişimsel anomali düşünülüyor. Bu bulgular en çok hangi ark-sinir türev ilişkisiyle uyumludur?","options":["İkinci ark ve trigeminal sinirle ilişkili çiğneme kasları","Birinci ark ve fasiyal sinirle ilişkili mimik kasları","Altıncı faringeal ark ve rekürren laringeal sinirle ilişkili intrinsik larenks kasları","Üçüncü poş ve hipoglossal sinirle ilişkili dil kasları","Dördüncü yarık ve vestibülokoklear sinirle ilişkili stapes"],"correct":2,"exp":"Altıncı faringeal ark larenksin intrinsik kaslarının büyük kısmı ve rekürren laringeal sinirle ilişkilidir. Vokal kord abdüksiyon kusuru bu ark-sinir eksenini düşündürür."},{"id":5293,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Nöral krest hücre göçü bozulduğunda baş-boyun bölgesinde hangi doku grubu özellikle etkilenir?","options":["Farinks endoderminden gelişen tiroid follikül hücreleri","Somit miyotomundan gelişen dil kasları","Yüzey ektoderminden gelişen lens plağı","Kraniofasiyal kemik ve bağ dokusu bileşenleri","Kardiyojenik mezodermden gelişen miyokard"],"correct":3,"exp":"Kranial nöral krest hücreleri yüz iskeleti, bağ dokusu ve birçok ark türevine katkı verir; göç bozukluğu kraniofasiyal anomalilerle sonuçlanır."},{"id":5294,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Mandibulofasiyal disostozlu bebekte hipoplastik mandibula, malleus-incus anomalisi ve çiğneme kaslarında gelişim kusuru bekleniyor. Bu yapıların ortak embriyolojik kökeni aşağıdakilerden hangisidir?","options":["İkinci faringeal ark","Birinci faringeal ark","Üçüncü faringeal poş","Dördüncü faringeal poş","Altıncı faringeal ark"],"correct":1,"exp":"Birinci faringeal ark mandibula-maksilla bölgesi, malleus-incus ve çiğneme kaslarıyla ilişkilidir; motor innervasyonu trigeminal sinirin mandibular dalıdır."},{"id":5295,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Konjenital katarakt ve mikroftalmi saptanan fetüste optik vezikülün yüzey ektodermini yeterince indükleyemediği düşünülüyor. Normalde bu indüksiyon hangi yapının gelişimini başlatır?","options":["Nazolakrimal kanalın kanalizasyonu","Stapes suprastrüktürünün oluşumu","Lens plakodunun oluşumu","Dil arka üçte bir mukozasının gelişimi","Tiroid divertikülünün kaudale göçü"],"correct":2,"exp":"Göz gelişiminde optik vezikül yüzey ektodermini indükleyerek lens plakodunun oluşmasını sağlar. Bu etkileşimin aksaması lens ve göz küresi gelişim bozukluklarına katkıda bulunabilir."},{"id":5296,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Tip 2 diyabeti ve kalp yetersizliği olan hastaya empagliflozin başlanıyor. İzlemde açlık glukozu düşerken glukozüri, hafif natriürez ve başlangıçta küçük bir GFR azalması görülüyor. Serum ketonu normal ve hasta yeterli sıvı alımını sürdürüyor. İlaç, glomerülden filtre edilen glukozun büyük bölümünün geri emildiği normal nefron segmentindeki hangi taşıma basamağını doğrudan inhibe eder?","options":["Henle inen kolunda üre sekresyonu","Proksimal tübülde sodyum-glukoz kotransportunun azalması","Toplayıcı kanalda aquaporin-2'nin bazolateral membrana taşınması","Podosit slit diyaframında albümin geri emilimi","Distal tübülde kalsiyumun parathormondan bağımsız atılması"],"correct":1,"exp":"SGLT2 proksimal tübülün erken bölümünün apikal membranında sodyumla birlikte glukoz geri emilimini sağlar. İnhibisyonu glukozüri ve natriüreze, makula densaya sodyum sunumunun artması da tubuloglomerüler geri bildirime yol açar. Aquaporin-2 toplayıcı kanalın apikal membranına ADH ile taşınır; podositler albümini fizyolojik olarak geri emen tübüler hücreler değildir."},{"id":5297,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Sağlıklı kişide ortalama arter basıncı kısa süreli yükseldiğinde renal kan akımı geniş bir aralıkta belirgin değişmeden kalıyor. Bu otoregülasyonu sağlayan afferent arteriyol yanıtı aşağıdakilerden hangisidir?","options":["Efferent arteriyolde glukoz kotransportunun başlaması","Makula densadan ADH salınımının artması","Basınç artışına miyojenik konstriksiyonla yanıt vermesi","Toplayıcı kanalda bikarbonat filtrasyonunun artması","Podosit ayaksı çıkıntılarının aktif kasılması"],"correct":2,"exp":"Afferent arteriyol düz kası basınç artışında gerilmeye miyojenik konstriksiyonla yanıt verir. Böylece glomerüler kapiller basınç ve renal kan akımı geniş bir basınç aralığında dengelenir."},{"id":5827,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, merdiven çıkarken her iki bacağında güçsüzlük ve sabahları eklem sertliği şikayetiyle başvuruyor. Yapılan elektromiyografide motor ünite aksiyon potansiyellerinin amplitüdünde belirgin artış saptanıyor. EMG bulgusunu açıklayan temel mekanizma ile en uyumlu histolojik değişiklik aşağıdakilerden hangisidir?","options":["Tip 2 liflerde seçici atrofi ve miyofibriller arası mitokondri artışı","Kolateral reinervasyon sonucu büyümüş motor ünitelerde lif tipi gruplama paterni","Endomizyal fibrozis ile birlikte santral nükleus oranında artış","Sarkoplazmik retikulum T-tübül bağlantısında triad sayısının azalması","Miyozin ağır zincir izoformlarında tip 1 lif lehine yeniden düzenlenme"],"correct":1,"exp":"Yaşlı hastada EMG'de yüksek amplitüdlü motor ünite potansiyelleri, bir motor nörona bağlı lif sayısının arttığını gösterir. Bu tablo nörojenik hasarda görülen kolateral reinervasyon ile açıklanır; sağlam aksonların komşu denerve liflere bud uzatması sonucu motor ünite büyür. Histolojik karşılığı 'lif tipi gruplama' paternidir; normalde checker-board görünümündeki tip 1 ve tip 2 lifler, reinervasyon sonucu aynı motor nörona bağlandığından küme halinde aynı histokimyasal boyamayı verir."},{"id":5828,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Ezilme yaralanması sonrası kreatin kinazı çok yükselen ve miyoglobinürisi gelişen hastada kas lifi nekrozuna götüren ortak hücresel olay aşağıdakilerden hangisidir?","options":["Miyoglobinin çekirdeğe taşınması","Troponin C'nin kalsiyuma afinitesinin belirgin biçimde azalması","Yalnız asetilkolin reseptörlerinin otoimmün yıkımı","Sarkomer sayısının fizyolojik azalması","ATP tükenmesiyle iyon pompalarının bozulması ve sitozolik Ca2+ artışı"],"correct":4,"exp":"Travma, iskemi, toksin veya metabolik nedenler farklı olsa da rabdomiyolizde enerji yetersizliği ve membran hasarı sitozolik kalsiyumu artırır; proteaz ve fosfolipazlar aktive olur, miyosit nekrozu gelişir."},{"id":5829,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Kas biyopsisinde PAS boyamasında soluk görünüm, NADH-TR boyamasında ise merkezi çekirdek içermeyen ancak lif çapında belirgin azalma saptanıyor. Bu histokimyasal tablo hangi durumla en uyumludur?","options":["Dermatomiyozitte perifasiküler atrofi","Duchenne musküler distrofisinde distrofin kaybı","Mitokondriyal miyopatide ragged-red lif paterni","Miyotonik distrofide santral nükleus birikimi","Uzun süreli hareketsizliğe bağlı disuse atrofisi"],"correct":4,"exp":"PAS boyamasında soluk görünüm glikojen içeriğinin azaldığını, NADH-TR boyamasında lif çapı küçüklüğü ile santral nükleus yokluğu ise miyopatik değil atrofik bir süreci işaret eder. Disuse atrofisinde inaktivite nedeniyle önce tip 2 lifler etkilenir, metabolik aktivite düşer (PAS solukluğu), lif çapı azalır ancak internal mimari korunur; santral nükleus görülmez. Duchenne distrofisinde distrofin eksikliği sarkolemma kırılganlığına, nekroz-rejenerasyon döngüsüne ve dolayısıyla santral nükleuslara neden olur. Mitokondriyal miyopatide Gomori trikromda ragged-red lifler karakteristiktir. Miyotonik distrofide santral nükleus ön plandadır."},{"id":5830,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Statin kullanan hastada progresif proksimal güçsüzlük ve çok yüksek kreatin kinaz vardır. Statin kesildikten haftalar sonra bulgular sürüyor; biyopside az inflamasyonla nekrotik ve rejeneratif lifler görülüyor. En olası antikor aşağıdakilerden hangisidir?","options":["Anti-Jo-1","Anti-asetilkolin reseptörü","Anti-HMGCR","Anti-Mi-2","Anti-GAD65"],"correct":2,"exp":"Statinle ilişkili immün aracılı nekrotizan miyopatide anti-HMGCR antikorları görülebilir ve yalnız ilacı kesmek yeterli olmayabilir. Basit toksik miyaljiden kalıcı güçsüzlük, yüksek CK ve nekrotizan biyopsiyle ayrılır."},{"id":5831,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"23 yaşında kadın hasta, egzersiz sonrası tekrarlayan kas krampları ve miyoglobinüri atakları nedeniyle araştırılıyor. Egzersiz öncesi iskemik ön kol testinde laktat yükselmesi gözlenmiyor ancak amonyak normal şekilde artıyor. Glukoz yüklenmesiyle semptomların kısmen gerilediği öğreniliyor. Bu hastada kas liflerinde hangi yapısal ve fonksiyonel değişiklik beklenir?","options":["Glikojen fosforilaz enziminin yokluğuna bağlı glikojen birikimi ve glikolizin başlatılamaması","Karnitin palmitoyltransferaz eksikliğine bağlı uzun zincirli yağ asitlerinin mitokondri içine taşınamaması","Miyoadenilat deaminaz eksikliğine bağlı AMP birikimi ve enerji tamponlamasının bozulması","Fosfofruktokinaz eksikliğine bağlı fruktoz 6 fosfat birikimi ve glikolizin orta basamakta durması","Piruvat kinaz eksikliğine bağlı ATP üretiminin son basamakta bozulması"],"correct":0,"exp":"Klinik tablo McArdle hastalığı yani tip 5 glikojen depo hastalığıyla uyumludur. Glikojen fosforilaz enziminin yokluğunda kas, glikojen rezervlerini yıkamaz. İskemik ön kol testinde laktat yükselmemesi glikolizin başlatılamamasını gösterirken amonyakın artması kas adenilat metabolizmasının çalıştığını ortaya koyar. Egzersiz öncesi glukoz yüklenmesiyle kan glukozunun sağlanması semptomları hafifletir çünkü glukoz, fosforilaz devresi atlanarak glikolize giriş yapabilir. Kas biyopsisinde sarkolemmaya yakın subsarkolemmal glikojen birikimi karakteristiktir."},{"id":5832,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Nöromüsküler kavşakta asetilkolin salındıktan sonra kas lifinde aksiyon potansiyeli oluştuğu halde kasılma gerçekleşmiyorsa, hangi yapının işlev kaybı bu tabloyu açıklar?","options":["Troponin I üzerindeki fosforilenme bölgesinin bloke edilmesi","Motor son plakta nikotinik reseptör sayısının azalması","T tübülü ile sarkoplazmik retikulum arasındaki triyadda dihidropiridin reseptörünün ryanodin reseptörünü aktive edememesi","Sarkoplazmik retikulumda kalsiyum ATPaz pompasının aşırı çalışarak sitozolik kalsiyumu hızla tüketmesi","Miyozin hafif zincir kinazının inhibisyonu"],"correct":2,"exp":"Eksitasyon-kontraksiyon eşleşmesinin kritik basamağı T tübülündeki dihidropiridin reseptörünün sarkoplazmik retikulumdaki ryanodin reseptörünü mekanik olarak aktive etmesidir. Aksiyon potansiyeli T tübülü boyunca iletilir, dihidropiridin reseptörü voltaj sensörü olarak konformasyonel değişime uğrar ve bu değişim ryanodin reseptörünü açarak kalsiyumun sarkoplazmik retikulumdan sitozole salınmasını sağlar. Bu halkada bir bozukluk olduğunda aksiyon potansiyeli normal olsa da kalsiyum salınamaz, troponin-tropomiyozin sistemi aktive edilemez ve aktin-miyozin etkileşimi başlamaz. Diğer seçenekler ya presinaptik ya da kontraktil protein düzeyindeki bozuklukları yansıtır ve sorulan tabloya uymaz."},{"id":5833,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, merdiven çıkarken bacaklarında güçsüzlük ve kolay yorulma şikayetiyle başvuruyor. Öyküsünde küçük hücreli akciğer kanseri tanısı mevcut. Elektromiyografide tekrarlayan sinir uyarılarıyla artan kas yanıtı saptanıyor. Bu tabloda hangi mekanizma birincil olarak sorumludur?","options":["Postsinaptik asetilkolin reseptörlerine karşı gelişen otoantikorlar","Troponin I fosforilasyonunu engelleyen tümör kaynaklı kinaz inhibisyonu","Miyozin ağır zinciri sentezini bozan paraneoplastik mutasyon","Presinaptik voltaj kapılı kalsiyum kanallarına karşı gelişen otoantikorlar","Riyanodin reseptörü disfonksiyonu nedeniyle SR kalsiyum salınımının azalması"],"correct":3,"exp":"Lambert-Eaton miyastenik sendromu, presinaptik terminal membranındaki voltaj kapılı kalsiyum kanallarına (VGCC) karşı oluşan otoantikorlarla karakterizedir. Aksiyon potansiyeli geldiğinde VGCC blokajı nedeniyle presinaptik terminale yeterli Ca2+ girişi olmaz ve asetilkolin vezikül ekzositozu azalır. Tekrarlayan uyarıda ise presinaptik terminalde kalsiyum birikimi artar ve yanıt güçlenir; bu EMG bulgusunu açıklar. Myastenia graviste ise postsinaptik AChR antikorları mevcuttur ve tekrarlayan uyarıyla yanıt azalır. Paraneoplastik sendrom olarak küçük hücreli akciğer kanseriyle sık birliktelik gösterir."},{"id":5834,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Çocukluktan beri egzersizle kas krampları olan hastada iskemik ön kol testinde laktat artmıyor. Ayrıca kronik hemoliz bulguları vardır ve 'ikinci rüzgâr' fenomeni izlenmez. En olası enzim eksikliği aşağıdakilerden hangisidir?","options":["Kas glikojen fosforilazı","Karnitin palmitoiltransferaz II","Asit alfa-glukozidaz","Fosfofruktokinaz-1","Miyoadenilat deaminaz"],"correct":3,"exp":"Kas PFK-1 eksikliği Tarui hastalığıdır. Glikoliz hem kas hem eritrositte bozulduğu için egzersiz intoleransı ve hemoliz birlikte görülür; McArdle'dan bu yönüyle ayrılır."},{"id":5835,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Bir araştırmacı, izole düz kas hücresini kalsiyumsuz ortamda tutarak dışarıdan IP3 uyguladığında kasılmanın yine de gerçekleştiğini gözlemliyor. Bu kasılmayı mümkün kılan birincil yapı aşağıdakilerden hangisidir?","options":["Sarkoplazik retikulumun IP3 reseptörü","Sarkolemmal L-tipi kalsiyum kanalı","Riyanodin reseptörü tip 1","Plazma membranı Na-Ca değiştirici","Kalmodulin bağımlı miyozin kinaz otofosforilasyon bölgesi"],"correct":0,"exp":"Düz kasta kasılma ağırlıklı olarak kalsiyum-kalmodulin-miyozin hafif zincir kinaz (MLCK) yolağıyla gerçekleşir. Dış ortamda kalsiyum olmasa da IP3, sarkoplazik retikulumun IP3 reseptörü (IP3R) aracılığıyla depo kalsiyumunun sitozole salınmasını sağlar; bu sitozolük Ca2+ artışı kalmodulini aktive ederek MLCK üzerinden miyozin hafif zincirini fosforile eder ve kasılma başlar. İskelet kasında ise riyanodin reseptörü (RYR1) mekanik eşleşme ile L-tipi kanal aracılığıyla aktive olur ve dış kalsiyuma bağımlılık daha azdır. Düz kas SR'ı hem IP3R hem RyR2 içerir; ancak bu spesifik IP3 uygulaması senaryosunda IP3R birincil yapıdır."},{"id":5836,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, merdiven çıkarken her seferinde baldır ağrısı olduğunu ve biraz dinlenince geçtiğini belirtiyor. Yapılan tetkiklerde alt ekstremite arterlerinde ciddi darlık saptanıyor. Bu hastada egzersiz sırasında iskelet kasında enerji üretiminin büyük bölümünü üstlenen yapı aşağıdakilerden hangisidir?","options":["Miyozin başları","Mitokondri","Sarkoplazmik retikulum","T tübülleri","Troponin kompleksi"],"correct":1,"exp":"İskelet kasında aerobik egzersiz sırasında ATP üretiminin temel kaynağı mitokondrilerdir. Miyozin başları ATPaz aktivitesiyle ATP kullanır, sarkoplazmik retikulum kalsiyum deposudur, T tübülleri aksiyon potansiyelini iletir, troponin ise kalsiyuma duyarlı düzenleyici proteindir. Arteriyel darlıkta dokuya oksijen taşınması azaldığından mitokondriyal aerobik metabolizma bozulur ve klodikasyo ağrısı ortaya çıkar."},{"id":5837,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"28 yaşında kadın sporcu, yoğun antrenman döneminin ardından bacaklarında aşırı yorgunluk ve kasılma hissi tarif ediyor. Kan laktat düzeyi yüksek bulunuyor. Bu tabloda laktatın birikimine yol açan temel süreç hangisini doğrudan yansıtır?","options":["Tip 2B liflerinde glikolizin oksidatif kapasiteyi aşması","Tip 1 liflerde oksidatif fosforilasyonun baskılanması","Sarkoplazmik retikulumdan kalsiyum salınımının artması","Troponin I fosforilasyonunun azalması","Miyozin ağır zincir izoformlarının değişmesi"],"correct":0,"exp":"Tip 2B (hızlı glikolitik) lifler yüksek yoğunluklu egzersizde devreye girer ve oksidatif kapasitelerinin çok üzerinde glikoliz yaparlar. Oluşan piruvat mitokondriye yetişemeyip laktata dönüştürülür. Tip 1 lifler zaten yüksek oksidatif kapasiteye sahipken Tip 2B lifler bu kapasiteden yoksundur. Diğer seçenekler kalsiyum sinyalizasyonu veya miyozin izoform değişikliğini içerdiğinden laktat birikimiyle doğrudan ilişkili değildir."},{"id":5838,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Elektron mikroskobu preparatında bir iskelet kası lifine ait kesitte yalnızca aktin filamentlerinin bulunduğu, miyozin filamentlerinin yer almadığı bölge aşağıdakilerden hangisidir?","options":["A bandı","H zonu","M çizgisi","I bandı","Z diski"],"correct":3,"exp":"I bandı yalnızca aktin (ince) filamentlerinden oluşur ve sarkomerin en açık renkli bölgesidir. A bandı hem aktin hem miyozin içerir ve karanlık görünür. H zonu yalnızca miyozin içerirken Z diski aktin filamentlerinin tutunduğu çizgidir ve M çizgisi miyozin filamentlerini ortada birbirine bağlar. Bu nedenle sadece aktin bulunan bölge I bandıdır."},{"id":5839,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, merdiven çıkarken bacaklarında güçsüzlük ve yorgunluk yakınmasıyla başvuruyor. Muayenede proksimal kas güçsüzlüğü saptanıyor. Elektromiyografide motor ünite potansiyellerinde amplitüd azalması ve erken rekrütman görülüyor. Kas biyopsisinde tip 2 liflerinde atrofi ve iç nükleer migrasyon saptanıyor. Bu hastada tip 2 kas liflerinin tip 1 liflere kıyasla yorgunluğa neden daha duyarlı olduğunu açıklayan temel mekanizma aşağıdakilerden hangisidir?","options":["Tip 2 liflerde miyozin ATPaz aktivitesinin düşük olması nedeniyle ATP tüketiminin yavaş gerçekleşmesi","Tip 2 liflerde sarkoplazmik retikulumun kalsiyumu geri alım hızının azalmış olması","Tip 2 liflerde troponin C affinitesinin kalsiyuma karşı düşük olması nedeniyle aktin-miyozin köprülerinin erken ayrılması","Tip 2 liflerde oksidatif fosforilasyon kapasitesinin sınırlı olması ve glikolize bağımlılığın laktat birikimine yol açması","Tip 2 liflerde mitokondri yoğunluğunun yüksek ancak sitrat sentaz aktivitesinin düşük olması"],"correct":3,"exp":"Tip 2 (hızlı kasılan) lifler, yüksek miyozin ATPaz aktivitesi sayesinde hızlı ve güçlü kasılma üretir; ancak enerji metabolizmaları ağırlıklı olarak anaerobik glikolize dayanır. Bu durum laktat ve H+ birikimi ile sarkoplazma pH düşüşüne yol açar. Düşük pH; troponin I ile aktin bağını güçlendirerek aktif alanları bloke eder, miyozin ATPaz aktivitesini inhibe eder ve sarkoplazmik retikulumdan kalsiyum salınımını azaltır. Sonuçta kasılma kuvveti hızla düşer. Mitokondri yoğunluğu tip 2 liflerde düşüktür; oksidatif kapasite kısıtlıdır."},{"id":5840,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, tekrarlayan kas sertliği ve ağrı yakınmasıyla geliyor. Özellikle soğuk ortamda el sıktıktan sonra elini açmakta güçlük çektiğini belirtiyor. Genetik incelemede CLCN1 geninde mutasyon saptanıyor. Bu kanalın normal fizyolojik işlevi göz önünde bulundurulduğunda, mutasyonun neden miyotoni tablosuna yol açtığını en iyi açıklayan mekanizma aşağıdakilerden hangisidir?","options":["Klor kanalı kaybı, sarkoplazmik retikulumdan kalsiyum salınımını artırarak sürekli aktin-miyozin köprü oluşumuna yol açar","Klor kanalı kaybıyla sarkolemmal klorür iletkenliğinin azalması, aksiyon potansiyeli sonrası tübüler sistemde kalan K+ birikimini dengeleyemez ve tekrarlayan deşarjlara neden olur","Klor kanalı işlev bozukluğunun voltaj bağımlı sodyum kanallarını kalıcı biçimde inaktive ederek lifin uyarılabilirliğini ortadan kaldırması","Klor kanalı kaybıyla repolarizasyon hızlanır, art arda gelen aksiyon potansiyellerinin refrakter dönemini kısaltır","Klor kanalı mutasyonu troponin kompleksinin kalsiyuma duyarlılığını artırarak relaksasyonu geciktirir"],"correct":1,"exp":"Normal iskelet kasında klor kanalları (ClC-1), sarkolemmal klorür iletkenliğinin büyük bölümünü sağlar ve aksiyon potansiyeli sonrası repolarizasyona katkıda bulunur. Tekrarlayan aksiyon potansiyelleri sırasında transvers tübül sisteminde potasyum birikmesi olur; bu birikme normalde klor iletkenliği tarafından dengelenerek membranın depolarize kalması engellenir. CLCN1 mutasyonu klor iletkenliğini azalttığında, tübüler K+ birikimi membranı eşik değer civarında tutmaya devam eder ve anormal tekrarlayan aksiyon potansiyelleri üretilir. Klinik olarak bu durum istemli kasılma sonrası relaksasyon gecikimi yani miyotoni olarak kendini gösterir."},{"id":5841,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta yoğun bakıma crush sendromu tanısıyla yatırılıyor. Laboratuvar incelemesinde miyoglobinüri saptanıyor ve serum CK düzeyi normalin 40 katı buluyor. Kas biyopsisinde sarkoplazmik retikulumun hasar gördüğü, mitokondrilerin şiştiği ve Z disklerinin parçalandığı bildiriliyor. Bu tabloda hücre içi kalsiyum yükünün artmasına yol açan birincil mekanizma aşağıdakilerden hangisidir?","options":["SERCA pompasının ATP yetersizliği nedeniyle kalsiyumu SR içine geri alamaması","Hücre dışı kalsiyumun voltaj kapılı L tipi kanallar aracılığıyla sürekli içeri girmesi","SR membran bütünlüğünün bozulmasıyla kalsiyumun pasif difüzyonla sitozole geçmesi","Na-K ATPaz inhibisyonuna bağlı membran depolarizasyonunun sürmesi","Sarkoplazmik retikulum membranındaki RYR1 kanallarının kalıcı açık kalması"],"correct":0,"exp":"Crush sendromunda kas hücrelerinde mekanik hasar ve iskemi nedeniyle ATP üretimi ciddi ölçüde azalır. SERCA (sarkoendoplazmik retikulum kalsiyum ATPaz) pompası, sitozoldeki Ca2+ iyonlarını sarkoplazmik retikuluma geri almak için ATP gerektirir. ATP yetersizliğinde SERCA işlev göremez ve sitozolde kalsiyum birikmeye başlar. Aynı zamanda SR membran hasarı da pasif sızıntıya katkıda bulunsa da, birincil ve sürdürülebilir mekanizma enerji yetersizliğine bağlı aktif taşıma bozukluğudur. Yüksek sitozolик kalsiyum; miyofibril hiperaktivasyonu, mitokondri şişmesi ve proteaz aktivasyonu üzerinden hücre ölümüne yol açar."},{"id":5842,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"24 yaşında kadın sporcu, kısa süreli patlayıcı sprint koşularından sonra kas gücünün hızla azaldığını fark etmiyor; ancak uzun süreli yürüyüşlerde hiç sorun yaşamıyor. Egzersiz fizyolojisi laboratuvarında yapılan kas biyopsisinde tip 2X lif oranının beklenenden yüksek olduğu, tip 1 lif oranının ise düşük kaldığı saptanıyor. Bu lifler arasındaki fonksiyonel farkın temelinde yatan histokimyasal özellik aşağıdakilerden hangisidir?","options":["Tip 1 liflerde troponin I izoformunun kalsiyuma duyarlılığının daha düşük olması","Tip 2X liflerde miyozin ağır zincir izoformunun ATPaz aktivitesinin daha yüksek olması","Tip 2X liflerde T tübül yoğunluğunun tip 1 liflerden daha az olması","Tip 1 liflerde sarkoplazmik retikulum hacminin tip 2X liflerden daha geniş olması","Tip 2X liflerde mitokondri yoğunluğunun daha fazla olması ve oksidatif kapasiteyi artırması"],"correct":1,"exp":"Kas lifi tipleri arasındaki hız ve yorgunluk farklılıklarının en temel belirleyicisi miyozin ağır zincir (MyHC) izoformudur. Tip 2X liflerinde eksprese edilen MyHC-IIx izoformu, yüksek ATPaz aktivitesine sahiptir; bu sayede çapraz köprüler hızla döngüye girer ve kasılma hızı ile güç çıkışı yüksek olur. Ancak bu yüksek ATP tüketim hızı, anaerobik metabolizmayla sürdürülemeyince yorgunluk çabuk gelişir. Tip 1 liflerinde ise MyHC-I izoformu daha yavaş ATPaz aktivitesi gösterir; mitokondri yoğunluğu ve oksidatif kapasite yüksektir, bu nedenle uzun süreli aktiviteye uygundur. Histokimyasal mATPaz boyaması (pH 9."},{"id":5843,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, merdiven çıkarken bacaklarında güçsüzlük ve yorgunluk hissi başladığını, birkaç aydır giderek arttığını söylüyor. Nörolojik muayenede proksimal kas güçsüzlüğü saptanıyor. EMG incelemesinde motor ünite aksiyon potansiyellerinin amplitüdü düşük, süresi kısa bulunuyor. Biyopside tip 2 liflerde belirgin atrofi, tip 1 liflerde ise görece korunma izleniyor. Bu tabloda öncelikle hangi yapısal-işlevsel bağlantı bozulmuştur?","options":["Motor nöron ile kas lifi arasındaki nöromüsküler kavşakta asetilkolin reseptör yoğunluğunun azalması","Hızlı kasılan glikolitik liflerin mitokondri yoğunluğu ve oksidatif kapasitelerinin düşmesi","Tip 2 liflerde miyozin ağır zincir izoformunun tip 2X den tip 2A ya geçişiyle kasılma hızının azalması","T tübülü ile sarkoplazmik retikulum arasındaki triyad yapısında kalsiyum salınım kanalı işlev kaybı","Alfa motor nöron kaybına bağlı denervasyon atrofisi ve kolateral reinervasyon yetersizliği"],"correct":4,"exp":"EMG bulguları ve biyopsi paterni primer nörojenik atrofiyi işaret eder. Tip 2 lif atrofisi disüz ya da nörojenik süreçlerde belirgindir. Alfa motor nöron kaybı olduğunda innerve ettiği tüm motor ünite lifleri atrofiye uğrar; sağlam komşu nöronların kolateral reinnervasyonu yetersiz kalırsa bu atrofi kalıcılaşır. Düşük amplitüdlü kısa süreli polifazik potansiyeller miyojenik tutulumu değil, küçük ve parçalanmış motor üniteleri yansıtır. Diğer seçeneklerdeki mekanizmalar bu tablonun birincil patolojisini açıklamaz."},{"id":5844,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"24 yaşında kadın sporcu, ani başlayan baldır ağrısı ve şişliği nedeniyle geliyor. Koşu sırasında ani bir his sonrası yürüyemez hale gelmiş. Muayenede baldırda palpasyonla hassasiyet ve ekimoz var. Biyopsi yapılıyor ve nekrotik liflerin kenarında satellit hücre aktivasyonu ile çok çekirdekli miyotüp oluşumu izleniyor. Bu süreçte satellit hücrelerin aktive olmasını tetikleyen birincil sinyal mekanizması aşağıdakilerden hangisidir?","options":["Hasar gören miyofibrillerin salıverdiği miyostatinin parakrin etkisiyle Smad2 ve Smad3 yolağının baskılanması","Nötrofil infiltrasyonuyla salınan IL-6 nın JAK-STAT yolağı üzerinden miyogenin ekspresyonunu baskılaması","Sarkomer hasarı sonucu açığa çıkan IGF-1 izoformunun PI3K-Akt-mTOR yolağını aktive ederek miyoblast füzyonunu doğrudan uyarması","Satellit hücre yüzeyindeki Notch reseptörünün Delta-like ligandlarla uyarılması sonucu asimetrik bölünmeyi engelleyerek hücre havuzunu azaltması","Lamina propriadan salınan hepatosit büyüme faktörünün c-Met reseptörüne bağlanarak satellit hücre döngüsünü başlatması"],"correct":4,"exp":"Satellit hücreler normalde G0 evresinde quiescent durumda bekler. Kas hasarı sonrasında bazal laminadan salınan hepatosit büyüme faktörü (HGF), satellit hücre yüzeyindeki c-Met tirozin kinaz reseptörüne bağlanarak bu hücreleri G0 dan çıkarır ve proliferasyonu başlatır. Miyostatin normalde satellit hücre aktivasyonunu baskılayan bir faktördür; hasarda miyostatin düşer bu da aktivasyona katkı sağlar ancak birincil tetikleyici değildir. IGF-1 miyoblast farklılaşmaunu ve protein sentezini destekler ama satellit hücre aktivasyonunu başlatan birincil sinyal değildir. Notch sinyali ise satellit hücre havuzunu koruyarak erken farklılaşmau önler."},{"id":5845,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Eksitasyon-kontraksiyon çiftlenimi sırasında T tübüllerindeki voltaja duyarlı L tipi kalsiyum kanallarının (dihidropiridin reseptörü) birincil işlevi iskelet kasında aşağıdakilerden hangisidir?","options":["Ekstrasellüler kalsiyumun sarkoplazmaya doğrudan girişini sağlayarak miyofilaman aktivasyonunu başlatmak","Aksiyon potansiyeli sırasında sodyum kanallarının inaktivasyonunu geciktirerek plato fazını uzatmak","Sarkoplazmik retikulumdaki ryanodin reseptörlerine mekanik olarak bağlanarak kalsiyum salınımını tetiklemek","Troponin I üzerindeki fosfat gruplarını uzaklaştırarak tropomiyozinin aktif konformasyona geçişini kolaylaştırmak","Miyozin hafif zincir kinazı fosforile ederek çapraz köprü döngüsünü başlatmak"],"correct":2,"exp":"İskelet kasında eksitasyon-kontraksiyon çiftlenimi kalp kasından farklı olarak ekstrasellüler kalsiyuma bağımlı değildir. T tübülü membranındaki DHPR (L tipi kanal), aksiyon potansiyeli geldiğinde voltaj değişimini algılar ve konformasyon değiştirerek sarkoplazmik retikulum membranındaki ryanodin reseptörü tip 1 ile doğrudan fiziksel temas yoluyla etkileşir. Bu mekanik eşleşme, SR den sitoplazmaya kalsiyum salınımını tetikler. Kalp kasında DHPR ise iyon kanalı olarak çalışır ve kalsiyum girişiyle kalsiyum uyarılı kalsiyum salınımı mekanizmasını başlatır. Diğer seçenekler kas fizyolojisinde gerçek mekanizmalar içerse de bu sorunun odağı olan DHPR işlevini tanımlamamaktadır."},{"id":5846,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"42 yaşında erkek hasta, son 6 aydır bacaklarda ilerleyici güçsüzlük ve egzersiz toleransında belirgin azalma yakınmasıyla başvuruyor. Muayenede proksimal kas güçsüzlüğü saptanıyor. EMG incelemesinde miyopatik patern izleniyor. Kas biyopsisinde tip II kas liflerinde seçici atrofi ve Z disk malign tutulumu görülüyor. Bu hastada tip II liflerin enerji metabolizması ile ilgili hangi özellik doğrudan bozulmuş olacaktır?","options":["Yüksek mitokondri yoğunluğu sayesinde sürdürülen aerobik fosforilasyon kapasitesi","Miyoglobin depoları aracılığıyla sağlanan oksijen tampon kapasitesi","Kreatin kinaz ve glikoliz enzimlerine bağımlı hızlı ATP üretim mekanizması","Yavaş miyozin ATPaz aktivitesine dayalı uzun süreli kasılma kapasitesi","Tip I liflerle ortak kullandığı kapiller ağ yoğunluğu"],"correct":2,"exp":"Tip II kas lifleri hızlı kasılan, glikolize bağımlı liflerdir. Yüksek miyozin ATPaz aktivitesi, kreatin kinaz depoları ve anaerobik glikoliz kapasitesi ile hızlı ve güçlü kasılma sağlarlar. Mitokondri yoğunluğu düşük olup aerobik kapasiteleri sınırlıdır. Tip I lifler ise yüksek mitokondri içeriği ve miyoglobin ile aerobik metabolizmaya uygundur. Bu hastada tip II lif atrofisi, özellikle patlayıcı kuvvet gerektiren hızlı kasılmaları bozmaktadır."},{"id":5847,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, doğumdan sonra bebeğinde sarkık yüz ifadesi, emme güçlüğü ve hipotoni fark ediyor. Bebeğin kas biyopsisinde normal lif sayısı mevcut ancak liflerin çok küçük çaplı olduğu, nükleuslerin merkezi konumda yerleştiği ve miyofibril organizasyonunun bozuk olduğu izleniyor. Bu tabloya yol açan gelişimsel süreçte hangi mekanizmanın yetersiz çalışması en olası nedendir?","options":["Miyoblastların terminal farklılaşmau sırasında miyozin ağır zincir izoformlarının yanlış ekspresyonu","Nöromüsküler kavşakta asetilkolin reseptörlerinin yetersiz kümelenmesi","Satellit hücrelerin proliferasyon kapasitesinin doğuştan azalmış olması","Miyoblast füzyonunun yetersiz gerçekleşmesi sonucu miyotüp olgunlaşmasının tamamlanamaması","T tübül sisteminin gelişimi sırasında diyad oluşumunun tamamlanamaması"],"correct":3,"exp":"Merkezi nükleus varlığı ve küçük çaplı lifler, miyotüp olgunlaşma bozukluğunu işaret eder. Normal kas gelişiminde miyoblastlar füzyon geçirerek miyotüp oluşturur; nükleuslerin perifere göçü ve miyofibril organizasyonunun oturması olgunlaşma süreçleridir. Sentronükleer miyopati olarak bilinen bu tabloda füzyon gerçekleşmiş ancak sonraki olgunlaşma adımları tamamlanamamıştır. Satellit hücre eksikliği postnatal büyümeyi etkiler, doğumda lifleri etkilemez. T tübül bozukluğu eksitasyon-kasılma çiftleşmesini etkiler, morfolojiyi bu şekilde bozmaz."},{"id":5848,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Bir fizyoloji pratiğinde kasılma mekanizması incelenirken izometrik kasılma koşullarında bir iskelet kası uyarılıyor. Kasılma sırasında I bandının kısaldığı, A bandının sabit kaldığı, H bölgesinin daraldığı gözlemleniyor. Bu değişiklikler incelendiğinde kasılmanın hangi yapısal mekanizmayı kesin olarak kanıtladığı söylenebilir?","options":["Miyozin filamentlerinin kısalması","Z disklerinin erimesi ve yeniden oluşumu","Aktin filamentlerinin depolimerizasyonu","Troponin-tropomiyozin kompleksinin kalıcı konformasyon değişimiyle bağlanma bölgelerini açık tutması","Aktin ve miyozin filamentlerinin birbirine geçmesi ile sarkomerin boyunun azalması"],"correct":4,"exp":"Kayan filaman teorisine göre kasılma sırasında filaman boyları değişmez; aktin ve miyozin birbirine kayar. I bandı yalnızca aktin içerdiğinden kısalması aktinin miyozin üzerine kaydığını gösterir. A bandı tüm miyozin uzunluğunu kapsadığından sabit kalır. H bölgesi yalnızca miyozini kapsar; aktinin içeri kaymasıyla daralır. Bu üç bulgu birlikte filaman boylarının sabit kaldığını, sadece örtüşmenin arttığını kanıtlar."},{"id":5849,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 8 aydır giderek artan çiğneme güçlüğü ve yutma zorluğu şikayetiyle başvuruyor. Muayenede masseter ve temporal kaslarda belirgin atrofi saptanıyor. Elektromiyografide motor ünite potansiyellerinde amplitüd artışı ve duration uzaması dikkat çekiyor. Bu hastada kas liflerinin yeniden innervasyon sürecinde komşu sağlıklı aksonların terminal dallanarak denerve lifleri devralması hangi histolojik bulguya yol açar?","options":["Tip 1 ve Tip 2 lif mozaik paterninin korunması","Lif tipi gruplama ile tek tip lif adacıklarının oluşması","Santral nükleus oranında belirgin artış","Sarkomer sayısında seri azalmayla lif kısalması","Endomisyumda kollajen birikimi ile lif hipertrofisi"],"correct":1,"exp":"Nörojenik atrofilerde denervasyon sonrası komşu sağlıklı motor nöronların sprouting yaparak denerve lifleri devralması, normalde rastgele dağılmış mozaik lif tipini bozar. Tek bir motor nöron aynı tip metabolik profile sahip lifleri kontrol ettiğinden, histokimyasal boyamalarda aynı tip lifler bir arada kümelenir ve 'lif tipi gruplama' adı verilen patern ortaya çıkar. Bu bulgu nörojenik patolojinin patolognomik göstergesidir. Santral nükleus artışı miyojenik hastalıkların bulgusudur. Kollajen birikimi geç dönem fibrozisi yansıtır ancak erken yeniden innervasyon sürecini tanımlamaz."},{"id":5850,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 6 aydır sabahları el parmaklarında tutukluk ve proksimal kas güçsüzlüğü bildiriyor. Kreatin kinaz düzeyi 3200 IU/L olarak saptanıyor. Kas biyopsisinde perimizyum boyunca inflamatuar infiltrasyon ve perifasiküler atrofi izleniyor. Bu histolojik tabloda perifasiküler bölgedeki kas liflerinin selektif hasarını açıklayan temel mekanizma aşağıdakilerden hangisidir?","options":["Kas iğciği proprioseptörlerinin otoimmün hedef alınması","Miyozin ağır zincir izoformuna karşı gelişen antikor birikimi","Kas fasyasına yakın bölgedeki kapiller yatağın kompleman aracılı hasarıyla iskemi gelişmesi","Sarkoplazmik retikulum kalsiyum kanallarının immün kompleks ile blokajı","T-tübül sisteminin endomisyal inflamasyon tarafından mekanik olarak bozulması"],"correct":2,"exp":"Dermatomiyozitte karakteristik perifasiküler atrofi, kas fasyasına komşu bölgede kan damarlarına yönelik immün hasarın sonucudur. Perimizyum ve fasyaya yakın kapillerler kompleman sisteminin aktivasyonu sonucu oluşan membran atak kompleksi tarafından hasar görür. Bu vaskülopatik süreç fasyaya yakın liflerin kronik iskemiye maruz kalmasına ve selektif atrofisine yol açar. Fasyadan uzak, merkezi konumdaki lifler görece korunur. Bu tablo dermatomiyoziti polimiyozit gibi diğer inflamatuvar miyopatilerden ayırt eden en önemli histopatolojik bulgudur."},{"id":5851,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Bir fizyoloji pratiğinde öğrencilere hızlı kasılan ile yavaş kasılan kas lifi tipleri arasındaki fark sorulmaktadır. Tip 2B liflerinin Tip 1 liflerine kıyasla yorgunluğa daha duyarlı olmasının temel nedeni aşağıdakilerden hangisidir?","options":["Mitokondri sayısının az ve oksidatif fosforilasyon kapasitesinin yetersiz olması","Miyoglobin içeriğinin düşük olması nedeniyle oksijen depolama kapasitesinin azalmış olması","Sarkomer boyunun daha kısa olması nedeniyle kasılma hızının artmış olması","Motor nöron çapının büyük olması nedeniyle aksiyon potansiyelinin daha hızlı iletilmesi","Troponin izoformlarının kalsiyuma duyarlılığının düşük olması nedeniyle eşik değerinin yükselmesi"],"correct":0,"exp":"Tip 2B (hızlı glikolitik) lifler mitokondri açısından fakirdir ve ATP üretimini esas olarak anaerobik glikolize dayandırır. Bu yol hızlı ATP sağlasa da laktat birikimi ve pH düşüşüne yol açarak kısa sürede yorgunluğu tetikler. Tip 1 (yavaş oksidatif) lifler ise yoğun mitokondri içeriği, yüksek miyoglobin konsantrasyonu ve kapiller dansite sayesinde oksidatif fosforilasyonla sürekli ATP üretebilir ve yorulmaya karşı dirençlidir. Miyoglobin düşüklüğü sonucu destekler ancak yorgunluğun birincil mekanizması mitokondri yetersizliğine bağlı anaerobik enerji bağımlılığıdır."},{"id":5852,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, merdiven çıkarken bacaklarında güçsüzlük ve yorgunluk şikayetiyle başvuruyor. Muayenede proksimal kas güçsüzlüğü saptanıyor. EMG incelemesinde motor ünite potansiyellerinin amplitüdünün azaldığı ve polifazik potansiyellerin arttığı görülüyor. Bu hastada iskelet kasındaki satellite hücrelerin aktivasyonuyla başlayan rejenerasyon sürecinde, olgun miyotübün oluşumundan hemen önce hangi moleküler olay belirleyici rol oynar?","options":["Distrofin-ilişkili protein kompleksinin hücre dışı matriks ile yeniden bütünleşmesi","Titin proteininin sarkomer içinde mekanik sensör olarak RyR2 kanallarını aktive etmesi","M-band bölgesindeki miyomesin proteininin miyozin filamentlerini çapraz bağlaması","Troponin I fosforilasyonunun kalsiyum duyarlılığını artırarak kasılmayı sürdürmesi","MyoD ve myogenin transkripsiyon faktörlerinin sıralı aktivasyonuyla miyoblastların terminal farklılaşmaa girmesi"],"correct":4,"exp":"Satellite hücreler hasar sonrası aktive olarak önce MyoD eksprese eden miyoblastlara dönüşür. Bu miyoblastlar prolifere olup ardından myogenin ekspresyonu ile terminal farklılaşmaa girer ve birbirleriyle füzyon yaparak miyotübleri oluşturur. MyoD-myogenin eksenindeki bu sıralı aktivasyon, miyojenik programın vazgeçilmez anahtarıdır. Titin mekanosensörlüğü sarkomer homeostazıyla, miyomesin M-band yapısıyla, troponin I fosforilasyonu kasılma regülasyonuyla, distrofin kompleksi ise yapısal bütünlükle ilgilidir; bunların hiçbiri olgun miyotüb oluşumundan hemen önceki kritik adımı tanımlamaz."},{"id":5853,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Uzun süreli açlık ve dayanıklılık egzersizi sonrası tekrarlayan miyoglobinürisi olan erişkinde kısa süreli yüksek yoğunluklu egzersiz genellikle tolere ediliyor. Ataklar arasında kreatin kinaz normaldir. En olası tanı aşağıdakilerden hangisidir?","options":["McArdle hastalığı","Miyastenia gravis","Duchenne musküler distrofi","Malign hipertermi","CPT II eksikliğinin miyopatik formu"],"correct":4,"exp":"CPT II eksikliğinde uzamış egzersiz, açlık, soğuk veya enfeksiyon uzun zincirli yağ asidi kullanımını artırarak rabdomiyolizi tetikler. McArdle'da kısa yoğun egzersiz ve glikojenoliz daha belirleyicidir."},{"id":5854,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Bir kasın izometrik kasılması sırasında sarkomer uzunluğu sabit kalmasına karşın kasa uygulanan gerilim artmaktadır. Bu durumda hangi yapısal protein hem pasif elastik enerjiyi depolayarak hem de Z-diski ile miyozin başını mekanik olarak bağlayarak bu gerilim artışına en doğrudan katkı sağlar?","options":["Nebülin","Tropomodülin","Titin","Alfa-aktinin","Miyomesin"],"correct":2,"exp":"Titin, Z-diskinden M-bandına uzanan dev bir elastik protein olup sarkomer içinde yay görevi görür. İzometrik koşullarda aktin-miyozin köprüleri çapraz bağ yaparken titinin PEVK ve immünoglobulin benzeri bölgeleri gerilir ve pasif elastik enerji depolar. Aynı zamanda miyozin filamentlerini Z-diskiyle hizalamaya yardımcı olarak mekanik iletimi sağlar. Nebülin aktin filament uzunluğunu ölçer, tropomodülin aktin filamentinin uç regülasyonunu yapar, alfa-aktinin Z-disk çapraz bağlarını oluşturur, miyomesin ise M-bandında miyozin filamentlerini düzenler. Bu işlevlerin hiçbiri titin kadar bütüncül bir pasif gerilim ve mekanik iletim rolü üstlenmez."},{"id":5855,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Uzun süre immobil kalan hastanın kas biyopsisinde seçici tip II lif atrofisi görülüyor. Maksimal kas kuvvetindeki azalmanın en doğrudan yapısal nedeni aşağıdakilerden hangisidir?","options":["Tip I liflerde mitokondri sayısının artarak oksidatif kapasiteyi yükseltmesi","Kasın fizyolojik kesit alanının ve paralel çapraz köprü sayısının azalması","Troponin C miktarının azalarak kalsiyum duyarlılığının düşmesi","Sarkomerlerin seri yönde çoğalarak kasılma hızını değiştirmesi","Motor son plak sayısının artarak uyarı iletimini hızlandırması"],"correct":1,"exp":"Maksimal izometrik kuvvet, kasın fizyolojik kesit alanı ve paralel çalışan kontraktil eleman sayısıyla ilişkilidir. Lif atrofisi kesitsel alanı azaltarak kuvvet kaybına yol açar."},{"id":5856,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"23 yaşında kadın sporcu, antrenman sırasında tekrarlayan kasık ağrısı ve ardından birkaç dakika süren lokal kasılma-gevşeme bozukluğu tanımlıyor. İstirahatle tamamen düzeliyor. Serum kreatin kinaz değeri hafif yüksek bulunuyor. Egzersiz sırasında sarkoplazma retikulumundan salınan kalsiyumun yeterince geri alınamamasına bağlı uzamış kasılma durumu söz konusuysa, bu durumdan doğrudan sorumlu olan pompa hangisidir ve hangi koşulda işlev kaybeder?","options":["SERCA2a pompası, miyokard iskemisinde ATP tükenmesiyle","RYR1 kanalı, Mg2+ konsantrasyonu düştüğünde aşırı açık kalarak","SERCA1 pompası, yoğun egzersizde intrasellüler asidoz ve ATP azalmasıyla","Plazma membranı Ca2+-ATPaz, ekstrasellüler kalsiyum yükselmesiyle","NCX taşıyıcısı, sodyum gradyanının tersine dönmesiyle"],"correct":2,"exp":"İskelet kasında sarkoplazma retikulumundan sitozole salınan kalsiyum, ağırlıklı olarak SERCA1 pompası aracılığıyla geri alınır. Yoğun egzersizde ortaya çıkan intrasellüler laktat birikimi ve pH düşüşü SERCA1 aktivitesini doğrudan baskılar; eş zamanlı ATP tükenmesi de pompanın enerji gereksinimini karşılayamaz hale getirir. Sonuçta kalsiyum sitozolde kalır ve uzamış kasılma gerçekleşir. SERCA2a kardiyak ve düz kasta baskındır. RYR1 kanalı kalsiyum salınımından sorumludur, geri alımdan değil."},{"id":5857,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Bir histoloji preparatında enine çizgili kasın ultrayapısı inceleniyor. Kasın tam olarak dinlenme uzunluğunda olduğu bildirilmektedir. Bu preparatta A bandının tam ortasında yer alan ve yalnızca miyozin filaman içerdiği bilinen bölge hangisidir ve bu bölge kasılma sırasında nasıl değişir?","options":["Z diski, kasılma sırasında A bandı sınırlarına doğru yer değiştirir","I bandı, kasılmayla birlikte uzar çünkü aktin filaman dışarı çekilir","M çizgisi, kasılmayla birlikte kaybolur ve yalnızca istirahat halinde görülür","H zonu, kasılmayla birlikte daralır ve tam kasılmada kaybolabilir","A bandı, kasılma sırasında kısalır çünkü miyozin filaman toplanır"],"correct":3,"exp":"H zonu, A bandının tam ortasında yer alan ve yalnızca miyozin filaman içeren bölgedir; bu bölgede aktin filamanları bulunmaz. Kayan filaman mekanizmasına göre kasılma sırasında aktin filamanları miyozin üzerinde içe doğru kayar, böylece H zonu daralır ve maksimum kasılmada tamamen kaybolabilir. I bandı da kasılmayla daralır çünkü aktin filamanlarının sarkomer merkezine yaklaşmasıyla yalnızca aktin içeren bölge kısalır. A bandının uzunluğu ise sabit kalır çünkü miyozin filaman boyu değişmez. M çizgisi miyozin filamanlarını merkezden bağlayan yapısal bir çizgidir ve kasılmayla kaybolmaz."},{"id":5858,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Progresif güçsüzlüğü olan hastada EMG'de yüksek amplitüdlü, uzun süreli motor ünite potansiyelleri ve azalmış katılım görülüyor. Kas biyopsisinde grup atrofisi ve lif tipi gruplaşması vardır. En olası süreç aşağıdakilerden hangisidir?","options":["Akut inflamatuvar tutulumla seyreden polimiyozit","Hareketsizliğe bağlı gelişen primer kullanmama atrofisi","Kronik denervasyon ve kollateral yeniden innervasyon süreci","Solunum zinciri kusuruyla seyreden mitokondriyal miyopati","Kas glikojen fosforilaz eksikliğine bağlı depo hastalığı"],"correct":2,"exp":"Kronik nörojenik süreçte sağ kalan motor aksonlar kollateral filizlenmeyle denervasyonlu lifleri yeniden innerve eder; büyük motor üniteler yüksek amplitüdlü uzun süreli potansiyeller ve lif tipi gruplaşması oluşturur."},{"id":5859,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, sabahları ellerinde tutma güçlüğü ve yorgunluk yakınmasıyla başvuruyor. Yapılan tekrarlayan sinir uyarım testinde 3 Hz uyarıda bileşik kas aksiyon potansiyelinde yüzde onbeş düzeyinde amplitüd azalması saptanıyor. Tensilon testi pozitif bulunan hastada bu klinik tablonun altında yatan birincil histofizyolojik değişiklik aşağıdakilerden hangisidir?","options":["Postsinaptik membrandaki nikotinik asetilkolin reseptörlerine karşı oluşan antikorların nöromüsküler kavşakta fonksiyonel reseptör sayısını azaltması","Asetilkolin sentezini sağlayan kolin asetiltransferaz enziminin motor sinir terminalinde yokluğu","Presinaptik voltaj kapılı kalsiyum kanallarına karşı gelişen antikorların asetilkolin vezikül ekzositozunu bozması","Motor nöron gövdesinde kronik inflamasyona bağlı aksiyon potansiyeli iletim hızının yavaşlaması","Miyozin ve aktin filamentlerinin sarkomerde orantısız birikmesiyle çapraz köprü döngüsünün bozulması"],"correct":0,"exp":"Myasthenia gravis, postsinaptik nikotinik asetilkolin reseptörlerine (AChR) karşı gelişen IgG antikorların nöromüsküler kavşakta reseptör sayısını azaltması ve nöromüsküler iletimi bozmasıyla ortaya çıkar. Antikorlar reseptör kapanımını, kompleman aracılı lizi ve endositozu artırarak işlevsel reseptör yoğunluğunu düşürür; bu durum postsinaptik membranın katlanmalarında da kayba yol açar. Tekrarlayan uyarımda amplitüd azalması bu mekanizmanın doğrudan yansımasıdır ve antikolinesteraz inhibitörü olan edrofonyumun (Tensilon) bulguları düzeltmesi, sinaptik aralıkta asetilkolin birikimi sağlamasıyla açıklanır."},{"id":5860,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, 20 yıllık sigara içme öyküsüyle birlikte son 3 yıldır giderek artan efor dispnesi ve sabah saatlerinde belirginleşen üretken öksürük yakınmasıyla başvuruyor. Fizik muayenede fıçı göğüs, uzamış ekspiryum ve diffüz ronküsler saptanıyor. Hastanın akciğer dokusunda kronik sigara maruziyetine bağlı olarak goblet hücresi hiperplazisi geliştiği düşünülüyor. Bu patolojik tabloda en doğrudan hangi mekanizma rol oynamaktadır?","options":["Tip 2 pnömositlerde sürfaktan sentezinin artması","Bronşiyal mukozada Clara hücrelerinin goblet hücrelerine transdifferansiyasyonu","Alveolar makrofajlardaki lizozomal enzim aktivitesinin azalması","Paryetal plevradaki mezotel hücrelerinin hiperplazisi","Kıkırdaklı bronşlarda psödostratifiye epitelin yassı epitele dönüşmesi"],"correct":1,"exp":"Kronik sigara dumanı ve irritan maruziyetinde bronşiyal mukozada normalde sero-müköz sekresyon yapan Clara hücreleri (Club hücreleri) goblet hücrelerine transdifferansiye olur. Bu süreç epitelyal plastisite mekanizmasıyla gerçekleşir ve mukus hipersekresyonuna yol açarak kronik bronşitin temel histopatolojik bulgusunu oluşturur. Tip 2 pnömositler sürfaktan üretir ve alveolar onarımda rol alır ancak goblet hiperplazisiyle ilişkisi yoktur. Alveolar makrofaj disfonksiyonu amfizem patogenezinde yer alır. Paryetal plevra mezoteli bu tabloda etkilenmez."},{"id":5861,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"32 yaşında kadın hasta, doğumdan bu yana tekrarlayan akciğer enfeksiyonları ve bronşektazi tanısıyla izlenmektedir. Genetik incelemede otozomal resesif geçişli bir mutasyon saptanmış olup respiratuar epiteldeki siliyer yapının ultrastrüktürel incelemesinde dış dynein kollarının yokluğu gösterilmiştir. Bu hastada solunum yolu savunmasının bozulmasından sorumlu temel fizyolojik mekanizma aşağıdakilerden hangisidir?","options":["Mukosilier klirens için gerekli sil vuruş frekansının ve koordinasyonunun ortadan kalkması","Sürfaktan tabakasının hipofosfatidilkolin içeriğinin azalması","Submuköz bezlerdeki seröz hücrelerin defensin sekresyonunun durması","Tip 1 pnömositlerde gaz difüzyonu için gerekli alveoler yüzey alanının belirgin biçimde daralması","Bronşiyal düz kas hücrelerinde beta-2 reseptör duyarsızlaşması"],"correct":0,"exp":"Dış dynein kollarının yokluğu Primer Silier Diskinezi tanısına işaret eder. Dynein ATP-bağımlı motor proteinidir ve sililerin '9+2' aksoneme yapısında dış çift mikrotübülleri birbirine kaydırarak vuruş hareketini sağlar. Dış dynein kolları olmadığında sil vuruş frekansı belirgin biçimde düşer, koordineli dalga hareketi kaybolur ve mukosilier klirens ortadan kalkar. Böylece bakteriler ve partiküller alt solunum yollarında birikir, tekrarlayan enfeksiyonlar ve bronşektazi gelişir. sürfaktan bileşimi alveolar yüzey gerilimi ve atelektazi ile ilgilidir."},{"id":5862,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Akut solunum sıkıntısı sendromu tanısıyla yoğun bakımda izlenen 45 yaşında bir erkek hastada akciğer kompliyansı belirgin biçimde azalmıştır. Bu tabloda alveolar yüzey gerilimini düşürerek kollapsı önleyen maddenin hangi hücre tarafından sentezlendiği sorulduğunda doğru yanıt aşağıdakilerden hangisidir?","options":["Tip 2 pnömosit","Tip 1 pnömosit","Alveolar makrofaj","Clara hücresi","Küçük bronşiyal müköz hücre"],"correct":0,"exp":"sürfaktan başlıca dipalmitoilfosfatidilkolin içeren ve alveolar yüzey gerilimini azaltarak ekspiryumda alveol kollapsını önleyen lipoprotein yapılı bir maddedir. Tip 2 pnömositler alveolar epitelin yaklaşık yüzde onunu oluşturmasına karşın tüm sürfaktanı sentezler, lamellar cisimciklerde depolar ve alveol yüzeyine salgılar. ARDS gibi tablolarda Tip 2 pnömositler hasar görür, sürfaktan sentezi bozulur ve kompliyans düşer. Tip 1 pnömositler gaz değişimini sağlar ancak sürfaktan üretmez. Alveolar makrofajlar fagositik savunma görevini üstlenir."},{"id":5863,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Terminal bronşiol epitelinde bulunan, siliyasız kubbe biçimli hücrelerin toksik maddeleri metabolize eden enzimler ve sekretuar proteinler ürettiği görülüyor. Bu hücre aşağıdakilerden hangisidir?","options":["Tip I pnömosit","Alveoler makrofaj","Goblet hücresi","Club hücresi","Pulmoner nöroendokrin hücre"],"correct":3,"exp":"Club hücreleri bronşiollerde bulunan siliyasız sekretuar hücrelerdir; detoksifikasyon, epitel korunması ve progenitör işlevlere katkı sağlar. 'Clara hücresi' yerine güncel olarak club hücresi terimi kullanılır."},{"id":5864,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"32 yaşında kadın hasta, ani başlayan plöritik göğüs ağrısı ve hemoptizi ile acile getiriliyor. Uzun süreli yatak istirahati öyküsü olan hastada pulmoner emboli tanısı konuluyor. Etkilenen bölgede 48-72 saat içinde gerçekleşen alveoler hasara karşı ilk yanıtı başlatan ve yüzey aktif madde bütünlüğünü korumaya çalışan hücre tipi aşağıdakilerden hangisidir?","options":["Tip 1 pnömosit","Tip 2 pnömosit","Alveoler makrofaj","Endotel hücresi","Kültür hücresi"],"correct":1,"exp":"Tip 2 pnömositler, alveoler epitel hasarına karşı ilk savunma ve yeniden yapılanma sürecini yöneten hücrelerdir. Bu hücreler lamellar cisimciklerinde sentezledikleri sürfaktanı (fosfatidilkolin ağırlıklı) salgılayarak alveoler yüzey gerilimini düşürür ve kollapsı önler. Hasar durumunda Tip 2 hücreler prolifere olarak hem kendilerini yeniler hem de yassı Tip 1 pnömositlerini yeniden oluşturur. Pulmoner embolide etkilenen bölgede sürfaktan üretimi bozulunca atelektazi ve ödem gelişir. Alveoler makrofajlar fagositoz ve immün düzenlemede rol alır, doğrudan sürfaktan üretimine katkıda bulunmaz."},{"id":5865,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Yenidoğan yoğun bakım ünitesinde, 28. gestasyon haftasında doğan bir bebekte doğumdan kısa süre sonra siyanoz ve inspiratuar çekilmeler gelişiyor. Solunum sıkıntısı sendromu ön tanısıyla yüzey aktif madde tedavisi planlanıyor. Bu bebeğin patolojisinde hangi histolojik bulgu beklenir?","options":["İnterstisyel fibrozis","Goblet hücre hiperplazisi","Bronşiyal düz kas hipertrofisi","Tip 1 pnömosit proliferasyonu","Alveoler duvarlarda hyalin membran oluşumu"],"correct":4,"exp":"Prematüre bebeklerde Tip 2 pnömositler henüz yeterince olgunlaşmadığından sürfaktan sentezi yetersiz kalır. Sürfaktan eksikliğinde alveoller her ekspirasyonda kollabe olur ve protein açısından zengin sıvı alveol içine sızarak fibrin ile hücre artıklarıyla birleşerek hyalin membranları oluşturur. Bu membranlar alveoler duvarlara yapışık eozinofilik tabakalar şeklinde patolojik olarak görülür ve gaz değişimini ciddi ölçüde bozar. Gestasyon yaşı ilerledikçe kortizol etkisiyle Tip 2 pnömosit olgunlaşması ve sürfaktan üretimi artar. Bu nedenle erken doğum riski olan durumlarda anneye prenatal kortikosteroid uygulanması standart yaklaşımdır."},{"id":5866,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Kronik bronşit nedeniyle akciğer rezeksiyonu yapılan hastada bronş submukozal bezlerinde belirgin genişleme görülüyor. Reid indeksi hangi iki kalınlığın oranıdır?","options":["Plevra / akciğer parankimi","Epitel / tüm bronş çapı","Kıkırdak / düz kas tabakası","Alveol septum kalınlığının kapiller çapına oranı ve difüzyon mesafesindeki değişiklik","Mukus bezi tabakası / epitel ile kıkırdak arasındaki bronş duvarı"],"correct":4,"exp":"Reid indeksi, bazal membrandan kıkırdağın iç sınırına kadar bronş duvarı kalınlığı içinde submukozal mukus bezlerinin kapladığı orandır. Kronik bronşitte artar."},{"id":5867,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Bronşiektazi, kronik sinüzit ve situs inversusu olan hastada sol-sağ eksenin rastlantısal belirlenmesine yol açan embriyonik bozukluk aşağıdakilerden hangisidir?","options":["Septum transversumun gelişmeyerek diyaframı oluşturamaması","Nöral krest hücrelerinin hedef dokuya göç edememesi","Paramezonefrik kanalların gerilemeden kalıcı olması","Primitif nodda hareketli siliyaların yönlü akım oluşturamaması","Dorsal mezenterin gerilemeyerek kalıcı hâle gelmesi"],"correct":3,"exp":"Primitif nod siliyalarının oluşturduğu sol yönlü akım lateralizasyon sinyallerini düzenler. Siliyer hareket bozukluğunda situs inversus veya heterotaksi gelişebilir."},{"id":5868,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Pulmoner fibrozis nedeniyle takip edilen bir hastanın akciğer biyopsisinde alveolar septanın belirgin şekilde kalınlaştığı ve Tip I pnömosit kaybının olduğu görülüyor. Bu histolojik tablonun solunum gazları üzerine beklenen etkisi aşağıdakilerden hangisidir?","options":["Yalnızca karbondioksit difüzyonu bozulur, oksijen korunur","Hem oksijen hem karbondioksit difüzyonu eşit oranda bozulur","Oksijen difüzyonu bozulur, karbondioksit difüzyonu korunur","Difüzyon kapasitesi artar çünkü alveoler yüzey alanı genişler","Ventilasyon-perfüzyon oranı yükselerek difüzyon kolaylaşır"],"correct":2,"exp":"Alveolar membran kalınlaşmasında Fick yasasına göre difüzyon mesafesi artar. Oksijen karbondiokside göre çok daha düşük çözünürlüğe sahiptir; karbondioksitin suda çözünürlüğü oksijenin yaklaşık 20 katıdır. Bu nedenle membran kalınlaşması önce ve ağırlıklı olarak oksijen transferini bozar, karbondioksit yüksek çözünürlüğü sayesinde diffüzyonunu daha uzun süre sürdürebilir. Tip I pnömositler alveolün yüzde 95 ini örter; kaybı yüzey alanını azaltır, artırmaz. Fibroziste ventilasyon-perfüzyon uyumsuzluğu difüzyonu daha da kötüleştirir."},{"id":5869,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 20 yıldır sigara içmekte olup son 3 yıldır artan nefes darlığı ve sabah saatlerinde bol mukuslu öksürük yakınmasıyla başvuruyor. Spirometride FEV1/FVC oranı yüzde 58 olarak saptanıyor. Bu hastada hava yolu direncinin artmasına yol açan temel histolojik değişiklik aşağıdakilerden hangisidir?","options":["Tip II pnömosit hiperplazisi ve sürfaktan artışı","Goblet hücresi hiperplazisi ve submukozal bez hipertrofisi","Klar hücresi kaybı ve silyalı epitel metaplazisi","Alveoler makrofaj birikimi ve fibrozis","Tip I pnömosit nekrozu ve hyalin membran oluşumu"],"correct":1,"exp":"KOAH ve kronik bronşitte hava yolu direncini artıran temel histopatolojik değişiklik, goblet hücresi hiperplazisi ile submukozal seromuköz bez hipertrofisidir. Reid indeksi yani bez kalınlığının duvar kalınlığına oranı normalin üzerine çıkar. Bu durum aşırı müküs üretimine, silyar klirensin bozulmasına ve lümen daralmasına yol açar. Tip II pnömosit hiperplazisi hasarda onarım sürecini, Klar hücresi kaybı bronşiol hasarını, alveoler makrofaj birikimi ise pnömokonyozu daha çok çağrıştırır. Hyalin membran oluşumu ARDS ile ilişkilidir."},{"id":5870,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, doğumundan itibaren tekrarlayan akciğer enfeksiyonları ve erkek kardeşinin infertilite sorunu yaşadığı öğreniliyor. Hastanın göğüs tomografisinde bronşiektazi saptanıyor ve nazal nitrik oksit düzeyi belirgin düşük bulunuyor. Bu hastada altta yatan temel yapısal bozukluk hangi soruyu en iyi yanıtlar?","options":["Sürfaktan proteini B eksikliği nedeniyle alveoler yüzey gerilimi artmıştır","Elastin yıkımı sonucu bronş duvarı bütünlüğü bozulmuştur","CFTR kanal mutasyonu nedeniyle klorür transportu bozulmuştur","Aksonemi yapısındaki dynein kolu defekti silyar hareketi işlevsiz kılmaktadır","Goblet hücre hiperplazisi mukus birikimini tetiklemektedir"],"correct":3,"exp":"Primer silier diskinezi, aksonemi yapısındaki dış dynein kollarının eksikliği ya da işlev bozukluğu sonucu gelişir. Normal sil aksoneması 9 çift çevre mikrotübül artı 2 merkezi mikrotübül şeklinde yani 9 artı 2 düzenindedir ve dynein kolları ATP hidrolizi ile güç üreterek vurum hareketini sağlar. Dynein defektinde siller hareket edemez, mukosiliyer klirens bozulur ve tekrarlayan enfeksiyonlar gelişir. Situs inversus eşlik ederse Kartagener sendromu adını alır. Düşük nazal nitrik oksit bu tanı için önemli bir tarama bulgusudur."},{"id":5871,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Sürfaktan eksikliği olan prematüre yenidoğanda iki alveol aynı yüzey gerilimine sahipken küçük alveolün kollapsa daha yatkın olması hangi ilişkiyle açıklanır?","options":["Oksijen çözünürlüğünün basınçtan bağımsız olması","Akciğer kompliyansının hacimden bağımsız olarak tüm solunum döngüsü boyunca sabit kalması","Difüzyon hızının yüzey alanıyla ters orantılı olması","Hava yolu direncinin yarıçapla doğru orantılı olması","Alveol basıncının yüzey gerilimiyle doğru, yarıçapla ters orantılı olması"],"correct":4,"exp":"Laplace ilişkisine göre küresel yapıda P=2T/r'dir. Yüzey gerilimi eşitse yarıçap küçüldükçe gerekli basınç artar; sürfaktan küçük alveollerde yüzey gerilimini daha çok azaltarak stabilite sağlar."},{"id":5872,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, 20 yıldır günde bir paket sigara içtiğini belirtiyor. Son 3 yıldır sabahları öksürük ve balgam çıkarma şikayeti mevcut. Spirometride FEV1/FVC oranı 0.62 olarak ölçülüyor. Bu hastada hava yolu direncindeki artıştan birincil olarak sorumlu tutulan yapısal değişiklik hangi hücre tipini etkiliyor?","options":["Tip II pnömosit hiperplazisi ve sürfaktan üretiminde artış","Tip I pnömositlerde incelme ve diffüzyon kapasitesinin artması","Klar hücrelerinin artmış sekresyonu ile alveoler yüzey geriliminin düşmesi","Goblet hücre hiperplazisi ve mukus bezi hipertrofisi nedeniyle lümen daralması","Alveoler makrofajlarda fagositik aktivite azalması ile gaz değişiminin bozulması"],"correct":3,"exp":"Kronik bronşitte hava yolu direncindeki artışın temel mekanizması goblet hücre hiperplazisi ve submukozal mukus bezlerinin hipertrofisidir. Reid indeksi artışı bu durumu yansıtır. Goblet hücreleri normalde bronşiollerde bulunmazken sigara gibi kronik irritanlarla birlikte bronşiollere kadar uzanır ve aşırı mukus üretimi gerçekleşir. Bu durum lümen çapını daraltarak hava yolu direncini artırır. FEV1/FVC oranının 0."},{"id":5873,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Bilateral hiler lenfadenopati, kuru öksürük ve eritema nodozumu olan hastada BAL'da lenfositoz ve artmış CD4/CD8 oranı saptanıyor. Bu bulgunun en doğru yorumu aşağıdakilerden hangisidir?","options":["Sarkoidozu destekler ancak tek başına tanı koydurmaz","Sarkoidozu kesin dışlar","Tüberküloz için karakteristiktir","Yalnız bakteriyel pnömonide görülür","Akciğer biyopsisini her durumda gereksiz kılar"],"correct":0,"exp":"BAL lenfositozu ve yüksek CD4/CD8 oranı sarkoidozu destekleyebilir ancak duyarlılık ve özgüllükleri tanı koyduracak düzeyde değildir. Klinik, radyoloji, alternatiflerin dışlanması ve gerektiğinde nonkazeifiye granülom birlikte değerlendirilir."},{"id":5874,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Yeni doğan bir bebek, doğumdan hemen sonra siyanoz ve solunum sıkıntısı ile yoğun bakıma alınıyor. Akciğer grafisinde diffüz buzlu cam görünümü saptanıyor. Eksik olan maddenin hangi hücre tarafından üretildiği ve bu maddenin temel fizyolojik etkisi hangi seçenekte doğru olarak verilmiştir?","options":["Tip I pnömosit tarafından üretilen kollajen, alveoler duvar sertliğini korur","Goblet hücresi tarafından üretilen müsin, hava yolunu nemli tutarak mukosiliyer klirensi artırır","Klar hücresi tarafından üretilen lizozim, alveoler enfeksiyona karşı koruma sağlar","Tip II pnömosit tarafından üretilen sürfaktan, alveoler yüzey gerilimini azaltarak kollaps önler","Alveoler makrofaj tarafından üretilen TNF-alfa, inflamatuvar yanıtı düzenler"],"correct":3,"exp":"Yenidoğanın respiratuvar distres sendromunda eksik olan madde surfaktandır. sürfaktan başta fosfatidilkolin olmak üzere fosfolipidler ve spesifik proteinlerden oluşur ve Tip II pnömositler tarafından sentezlenip alveol boşluğuna salınır. sürfaktanın temel işlevi alveollerdeki yüzey gerilimini azaltmaktır. La Place yasasına göre küçük alveollerin büyüklerden daha yüksek iç basınca sahip olması gerekir; sürfaktan bu farkı dengeleyerek küçük alveollerin büyüklere boşalmasını yani atelektaziyi engeller. 34."},{"id":5875,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yetmiş yaşındaki hastada belirti vermeyen başlangıçlı efor dispnesi, kuru öksürük, bibaziler ince ralller ve çomak parmak vardır. Mesleksel/çevresel maruziyet, ilaç öyküsü ve bağ dokusu hastalığı bulgusu yoktur. YRBT'de bazal-subplevral bal peteği ve traksiyon bronşiektazisi saptanıyor. En olası tanı aşağıdakilerden hangisidir?","options":["İdiyopatik pulmoner fibrozis","Hipersensitivite pnömonisi","Sarkoidoz","Eozinofilik pnömoni","Pnömosistoz"],"correct":0,"exp":"Nedeni açıklanamayan, uygun klinik bağlamda tipik UIP görüntüleme paterni IPF'yi destekler. 'İdiyopatik' tanıdan önce mesleksel/çevresel maruziyetler, ilaçlar ve bağ dokusu hastalıkları dışlanmalıdır."},{"id":5876,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"29 yaşında kadın hasta, tekrarlayan bronşit atakları ve egzersiz toleransında azalma nedeniyle araştırılıyor. Spirometride FEV1/FVC oranı yüzde 58 olarak ölçülüyor, bronkodilatatör yanıt negatif. Nazal polip öyküsü ve erkek kardeşinde benzer solunum şikayetleri mevcut. Nazal fırça biyopsisinde elektron mikroskopide silia aksonemasında dış dynein kolunun yokluğu saptanıyor. Bu bulguda en çok etkilenen silia fonksiyonu aşağıdakilerden hangisidir?","options":["Hücre yüzeyinde reseptör kümelenmesi","Sitoplazma içinde veziküler taşıma","Silianın belirli bir yönde koordineli vuruş yapabilmesi","Aksonema içinde mikrotübül polimerizasyonu","Silianın bazal cisimciğe tutunması"],"correct":2,"exp":"Silia aksonemasının '9+2' mikrotübül yapısı, dış dynein kolları aracılığıyla ATP hidrolizi ile hareket üretir. Dynein kolları komşu dış çift mikrotübüller arasında kayma hareketi sağlayarak silyaya koordineli ve yönlü vuruş özelliği kazandırır. Primer siliyer diskinezi (PCD) tanısını düşündüren bu olguda dış dynein kolunun yokluğu, gücün üretilememesi anlamına gelir; silia hareketi tamamen ya da büyük ölçüde ortadan kalkar ve mukosiliyer klirens bozulur. Veziküler taşıma Golgi ve ER kaynaklı süreçlere bağlıdır, dynein ile ilişkili olmakla birlikte sitozolik dynein farklı bir izoformdur. Mikrotübül polimerizasyonu tubulin dinamiğiyle ilgilidir, dynein koludaki eksiklikten etkilenmez."},{"id":5877,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Bir histoloji preparatında terminal bronşiolden alveollere geçiş bölgesinde, hem hava yolu fonksiyonu hem de gaz değişimine katılan yapılar izlenmektedir. Bu geçiş bölgesinde bulunan ve hem solunum hem de iletim epitelinin özelliklerini taşıyan yapı aşağıdakilerden hangisidir?","options":["Alveoler kanal","Respiratuar bronşiol","Terminal bronşiol","Alveolar kese","Plevral mezotelyum"],"correct":1,"exp":"Respiratuvar bronşiol, terminal bronşiolden alveoler kanallara geçişi sağlayan yapıdır. Duvarında yer yer küboidal epitel bulunurken alveoller doğrudan lümene açılır; böylece iletim ve gaz değişimi özellikleri bir aradadır. Terminal bronşiol duvarında alveol bulunmaz."},{"id":5878,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, 3 yıldır kötüleşen efor dispnesi ve kuru öksürük şikayetiyle başvuruyor. Sigara içmemiş, mesleki toz maruziyeti yok. HRCT'de bilateral bazal retiküler opasiteler ve bal peteği görünümü mevcut. Solunum fonksiyon testlerinde FEV1/FVC oranı normal, TLC belirgin azalmış. Akciğer biyopsisinde tip II pnömosit hiperplazisi ve fibröz bant oluşumu saptanıyor. Bu tabloda en çok hangi hücre tipinin fonksiyon bozukluğu primer olarak belirleyici rol oynamaktadır?","options":["Tip I pnömosit","Tip II pnömosit","Klara hücresi","Alveolar makrofaj","Endotel hücresi"],"correct":1,"exp":"İdiyopatik pulmoner fibrozis (IPF) tablosunda primer hasar tip I pnömositlerde başlar; ancak biyopside görülen tip II pnömosit hiperplazisi bu hücrelerin onarım yanıtını temsil eder ve durumu daha da kötüleştirir. Tip II pnömositler normalde sürfaktan sentezi, sekresyonu ve geri dönüşümünü sağlar, tip I pnömosit hasarında yenileme hücresi olarak işlev görür. IPF'de tekrarlayan epitel hasarı sonucu tip II pnömositlerde anormal aktivasyon gelişir; bu hücreler TGF-beta başta olmak üzere profibrotik mediyatörler salgılayarak mezenkimal geçişi tetikler ve subepitelyal fibrozisi sürdürür. Klara hücreleri (Club hücreleri) terminal bronşiyollerde bulunur, alveolar düzeyde rol oynamaz."},{"id":5879,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"32 yaşında kadın hasta, doğumdan 6 saat sonra yenidoğanında hızlı solunum, inleme ve burun kanadı solunumu geliştiğini ifade ediyor. Bebek 34. gebelik haftasında prematüre olarak doğmuş. Akciğer grafisinde yaygın granüler görünüm ve hava bronkogramları izleniyor. Bu tablonun patofizyolojisinde hangi yapının yetersizliği temel rol oynamaktadır?","options":["Tip I pnömosit bariyer fonksiyonu","Mukosilier transport sistemi","Sürfaktan tabakası","Alveolar makrofaj fagositoz kapasitesi","Pulmoner kapiller endotel"],"correct":2,"exp":"Respiratuvar distres sendromu (RDS), prematüre yenidoğanlarda tip II pnömosit olgunlaşmasının tamamlanamaması nedeniyle sürfaktan yetersizliğiyle ortaya çıkar. sürfaktan başlıca dipalmitoilfosfatidilkolin (DPPC) içerir; alveoler yüzey gerilimini azaltarak ekspiryum sonunda alveollerin kollabe olmasını önler. Gebeliğin 24-28. haftalarında tip II pnömositler sürfaktan salgılamaya başlar, tam olgunluk 35. haftadan sonra sağlanır."},{"id":5880,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 3 aydır ilerleyici bacak güçsüzlüğü ve yürüme güçlüğü şikayetiyle başvuruyor. Nörolojik muayenede alt ekstremitelerde kas güçsüzlüğü, hiperrefleksi ve Babinski pozitifliği saptanıyor. Üst ekstremitelerde ise fasikülasyon ve atrofi dikkat çekiyor. Bu tabloda hem üst hem alt motor nöron bulgularının bir arada görülmesinin histofizyolojik temeli incelendiğinde, spinal kordun hangi yapısının selektif olarak etkilendiği anlaşılır?","options":["Arka boynuz internöronları","Renshaw hücreleri ve glia sınırı","Dorsal kolon projeksiyon nöronları ve medial lemniskus yolağının birlikte tutulması","Lateral horn sempatik nöronları","Ön boynuz alfa motor nöronları ve kortikospinal traktus"],"correct":4,"exp":"ALS tablosunu tanımlayan bu vakada temel lezyon, spinal kordun ön boynuzundaki alfa motor nöronlar ile korteksten inen kortikospinal traktustur. Ön boynuz alpha motor nöronlarının kaybı alt motor nöron bulguları olan fasikülasyon, atrofi ve hiporefleksi yaratırken, kortikospinal traktusun dejenerasyonu üst motor nöron bulgularına yani hiperrefleksi, spastisite ve Babinski pozitifliğine neden olur. Renshaw hücreleri ön boynuzda yer alan inhibitör internöronlardır ancak bu tablonun açıklayıcı yapısı değildir. Dorsal kolonlar ise vibrasyon ve propriosepsiyon taşıdığından bu klinik tabloyu açıklamaz."},{"id":5881,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, akut başlangıçlı çift görme, sağ el parmaklarında uyuşma ve aşırı yorgunluk şikayetiyle nöroloji polikliniğine başvuruyor. Semptomların sıcak banyodan sonra belirgin biçimde arttığını ifade ediyor. MR görüntülemede periventriküler beyaz cevherde multifokal demiyelinizasyon odakları saptanıyor. Bu hastada sıcağın semptomları kötüleştirme mekanizması, miyelinin hangi fizyolojik işlevini doğrudan yansıtır?","options":["Akson çapını büyüterek iletim hızını artırması","Aksiyal silindir içindeki nörofilaman yoğunluğunu artırması","Schwann hücrelerinin miyelin bazal laminasını yeniden şekillendirmesi","Nodlar arasındaki saltatorik iletimi sağlayarak iletim güvenilirliğini ve hızını optimize etmesi","Ranvier boğumlarındaki K kanallarını bloke ederek hiperpolarizasyonu önlemesi"],"correct":3,"exp":"MS tanısını düşündüren bu vakada Uhthoff fenomeni, yani sıcakla semptom artışı, miyelin kaybının saltatorik iletimdeki rolünü ortaya koyar. Sağlıklı miyelinli aksonlarda aksiyon potansiyeli yalnızca Ranvier boğumlarından boğuma atlayarak iletilir, bu da hem hızı hem enerji verimliliğini artırır. Demiyelinize segmentlerde iletim zaten kırılgan bir dengede sürmektedir. Sıcaklık artışı Na kanallarının açık kalma süresini kısaltır ve bu kırılgan dengeyi bozarak iletim bloğuna yol açar. Seçeneklerdeki diğer mekanizmalar miyelin fizyolojisiyle örtüşmez veya yanlış süreçleri tanımlar."},{"id":5882,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Omurilik kesiti histolojik olarak incelendiğinde gri cevherin ön boynuzunda büyük, çok kutuplu hücreler gözlemleniyor. Bu hücrelerin aksonlarının hedef dokuya ulaştığında serbest bıraktığı nörotransmitter ve oluşturduğu kavşak tipi aşağıdakilerden hangisidir?","options":["Norepinefrin, adrenerjik sinaps","Glutamat, eksitatör sinaps","GABA, inhibitör sinaps","Asetilkolin, nöromüsküler kavşak","Substans P, nosiseptif sinaps"],"correct":3,"exp":"Spinal kordun ön boynuzundaki büyük, çok kutuplu hücreler alfa motor nöronlardır. Bu nöronlar iskelet kasına uzanan alt motor nöron yolunu oluşturur ve akson sonlanmaları iskelet kası liflerinde nöromüsküler kavşakları oluşturur. Bu kavşaklarda serbest bırakılan nörotransmitter asetilkolindir ve postsinaptik membranda nikotinik kolinerjik reseptörlere bağlanarak motor son plak potansiyelini oluşturur. Norepinefrin sempatik postganglionik nöronlara, GABA inhibitör internöronlara, glutamat eksitatör projeksiyon nöronlarına, Substans P ise birincil afferent nosiseptörlere aittir."},{"id":5883,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 8 aydır ilerleyici yürüme güçlüğü ve ellerde titreme şikayetiyle başvuruyor. Nörolojik muayenede dişli çark rijidite ve istirahat tremoru saptanıyor. Beyin görüntülemesinde substantia nigra pars compacta'da nöron kaybı izleniyor. Bu bölgedeki dopaminerjik nöronların akson terminallerinde veziküler dopamin depolanmasından sorumlu olan ve bu hastalıkta işlev bozukluğuna uğrayan taşıyıcı aşağıdakilerden hangisidir?","options":["Dopamin taşıyıcısı","Vezikül monoamin taşıyıcısı tip 2","Norepinefrin taşıyıcısı","Serotonin taşıyıcısı","L-DOPA taşıyıcısı"],"correct":1,"exp":"VMAT2 (vezikül monoamin taşıyıcısı tip 2), dopaminerjik nöronlarda sitozolden sinaptik veziküllere dopamin yükleyen taşıyıcıdır. Parkinson hastalığında alfa-sinüklein birikimi (Lewy cisimciği) VMAT2 fonksiyonunu bozarak sitozolde serbest kalan dopaminin MAO aracılığıyla oksidatif metabolizmasına yol açar; bu da reaktif oksijen türleri üretimi ile nöronal hasarı hızlandırır. DAT ise membran düzeyinde sinapstan geri alımı sağlar, depolama ile ilgili değildir."},{"id":5884,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"45 yaşında kadın hasta, ani başlayan şiddetli baş ağrısı ve ense sertliği ile acile getiriliyor. Lomber ponksiyon yapılıyor ve BOS basıncı yüksek bulunuyor. Hasta stabilize edildikten sonra BBB bütünlüğü araştırılıyor. Kan-beyin bariyerinin yapısal temelini oluşturan ve perivasküler astrositlerden gelen sinyallerle sıkı bağlantı proteinleri olan oklüdin ve klaudinleri düzenleyerek bariyer sızdırmazlığını sağlayan hücre tipi aşağıdakilerden hangisidir?","options":["Serebral kapiller endotel hücresi","Perivasküler mikroglia","Oligodendrosit","Epandim hücresi","Nöronal akson terminali"],"correct":0,"exp":"Kan-beyin bariyeri esas olarak serebral kapiller endotel hücrelerindeki sıkı bağlantılardan (tight junction) oluşur. Bu hücreler, perisitler ve astrositik son ayakçıklarla birlikte nörovasküler birimi oluşturur. Astrositler Wnt ve angiopoetin-1 gibi sinyaller aracılığıyla endotel hücrelerindeki klaudin-5 ve oklüdin ekspresyonunu artırarak bariyeri güçlendirir. Menenjitte inflamasyon bu sinyalizasyonu bozar, sıkı bağlantılar gevşer ve BOS ile plazma arasındaki basınç dengesi bozulur."},{"id":5885,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir fizyoloji pratiğinde aksiyon potansiyeli iletimi inceleniyor. Miyelinli sinir liflerinde iletim hızının miyelinsiz liflere göre çok daha yüksek olduğu gözlemleniyor. Bu hız farkının temel nedeni olan, miyelinli liflerde uyarının atladığı özelleşmiş akson bölgeleri hangi yapılardır?","options":["Dendrit dallanma noktaları","Akson hilloğu","Sinaptik buton","Schwann hücresi gövdesi","Ranvier boğumları"],"correct":4,"exp":"Miyelinli liflerde aksiyon potansiyeli tüm membran boyunca değil yalnızca Ranvier boğumlarında oluşur; bu iletim biçimine saltatorik iletim denir. Boğumlar arasındaki mesafe yaklaşık 1-2 mm olup bu bölgelerde voltaj kapılı Na+ kanalları yoğun olarak bulunur. Miyelin kılıf kapasitansı düşürüp direnci artırarak lokal akımların boğumdan boğuma sıçramasını sağlar. Böylece iletim hızı 70-120 m/s'ye ulaşabilirken miyelinsiz C liflerinde bu hız 0,5-2 m/s düzeyinde kalır."},{"id":5886,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"42 yaşında erkek hasta, 6 aydır ellerde titreme ve yürüme güçlüğü şikayetiyle başvuruyor. Nörolojik muayenede dişli çark belirtisi saptanıyor ve dopaminerjik nöron kaybı düşünülüyor. Bu hastada substantia nigra pars compacta nöronlarının kaybıyla birlikte striatum üzerindeki net etki hangi mekanizmayla açıklanır?","options":["Striatal GABAerjik nöronların doğrudan hasar görerek kortikal çıkışı artırması","Direkt yolda D1 uyarısının artıp indirekt yolda D2 inhibisyonunun sürmesiyle talamik çıkışın artması","Yalnızca indirekt yolun etkilenerek globus pallidus internus etkinliğini azaltması","Direkt yolda D1 uyarısının azalması ve indirekt yolda D2 inhibisyonunun kalkmasıyla talamik inhibisyonun artması","Nigrostriatal yol etkilenirken mezolimbik yolun korunmasıyla motor bulgunun oluşmaması"],"correct":3,"exp":"Bazal ganglia devre fizyolojisi açısından değerlendirildiğinde; dopamin direkt yolda D1 reseptörleri aracılığıyla eksitatör, indirekt yolda D2 reseptörleri aracılığıyla inhibitör etki gösterir. Dopamin kaybıyla direkt yolun aktivasyonu azalır (talamus üzerindeki inhibitör baskı azalmak yerine artar çünkü GPi freni kalkar), indirekt yolda ise D2 inhibisyonu ortadan kalkarak GPe inhibisyonu azalır, STN aşırı aktif hale gelir ve GPi aktivitesi artar. Her iki değişiklik de talamik nöronların daha fazla inhibe edilmesine yol açar, kortekse motor çıkış azalır; bu da bradikinezi ve rijiditeyi açıklar. Parkinson hastalığının temel patofizyolojik mekanizması budur."},{"id":5887,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Diyabetli hastada ani pitoz, gözün dışa-aşağı deviasyonu ve diplopi gelişiyor; pupilla ışık refleksi korunmuştur. Bu pupilla-koruyucu üçüncü sinir felcini en iyi açıklayan mekanizma aşağıdakilerden hangisidir?","options":["Sinirin merkezindeki somatik motor liflerin mikroiskemiyle etkilenip periferik parasempatik liflerin korunması","Yüzeyel yerleşimli parasempatik liflerin dıştan basıyla seçici olarak etkilenmesi","Optik sinirde demiyelinizasyon gelişerek afferent yolun bozulması","Servikal sempatik zincirin kesintiye uğrayarak pupil çapını değiştirmesi","Edinger-Westphal çekirdeğinin tek başına uyarılarak miyozis yapması"],"correct":0,"exp":"Mikrovasküler üçüncü sinir nöropatisinde santral somatik lifler daha çok etkilenirken yüzeyel parasempatik lifler korunabilir. Kompresif anevrizmal lezyonlar ise yüzeyel pupiller lifleri erken etkileyebilir."},{"id":5888,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"42 yaşında erkek hasta, 6 aydır ilerleyici yürüme güçlüğü ve ellerde ince motor kayıp yakınmasıyla başvuruyor. Nörolojik muayenede üst ekstremitede spastisite, hiperrefleksi ve Babinski pozitifliği saptanıyor; alt motor nöron bulgusu yok. Sinir iletim çalışması normal. Bu tabloda hasarlanan yapının miyelin kılıfını oluşturan hücreler hangi mekanizmayla işlev görür?","options":["Akson boyunca K+ kanallarını kapayarak depolarizasyonu sürekli hale getirirler","Ranvier boğumlarında Na+ kanalı yoğunluğunu artırarak aksiyon potansiyelinin sıçramalı iletimini sağlarlar","Miyelin proteinleri aracılığıyla akson çapını daraltarak iletim hızını düşürürler","Schwann hücreleriyle birlikte çalışarak santral sinir sisteminde remyelinizasyon kapasitesini artırırlar","Gap junction bağlantıları aracılığıyla komşu aksonlar arası elektriksel sinyali eşitlerler"],"correct":1,"exp":"Klinik tablo santral motor nöron (üst motor nöron) lezyonunu işaret etmekte olup santral sinir sisteminde miyelin kılıfını oligodendrositler oluşturur. Oligodendrositler, miyelin segmentleri arasında açıkta kalan Ranvier boğumlarında Na+ kanalı yoğunluğunu yüksek tutarak aksiyon potansiyelinin boğumdan boğuma sıçramalı iletimini (saltatory conduction) sağlar; bu mekanizma iletim hızını ve enerji verimliliğini artırır. Schwann hücreleri ise periferik sinir sistemine özgüdür ve her biri yalnızca tek bir akson segmentini sarar; bu nedenle sinir iletim çalışması normaldir. Oligodendrositlerin remyelinizasyon kapasitesi oldukça sınırlıdır, bu da MS gibi hastalıklarda kalıcı defisitlerin nedenidir."},{"id":5889,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Demyelinizan periferik nöropatide iletim hızının azalması ve iletim bloğunun temel biyofiziksel nedeni aşağıdakilerden hangisidir?","options":["Aksiyon potansiyelinin oluşumu için enerji gerekmemesi","Akson çapının ani biçimde artarak direnci düşürmesi","Ranvier düğümlerinde sodyum kanalı sayısının artması","Miyelin kaybıyla zaman sabitinin kısalarak iletimi hızlandırması","İnternodal zar direncinin azalması ve kapasitansın artmasıyla yerel akımın sızması"],"correct":4,"exp":"Miyelin membran direncini artırır ve kapasitansı azaltır. Kaybında akım internodal bölgede sızar, komşu düğüm eşik değere ulaşamayabilir; iletim yavaşlar veya blok gelişir."},{"id":5890,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir nörobilim pratik sınavında öğrencilere büyük çaplı miyelinli bir periferik sinirde aksiyon potansiyeli iletim hızını belirleyen en önemli yapısal faktör sorulmaktadır. Bu sorunun doğru yanıtı hangi seçenekte yer almaktadır?","options":["Ranvier boğumlarının sayısı tek başına belirleyicidir; boğum sayısı azaldıkça hız artar","Akson çapının büyüklüğü ve miyelin kılıfının kalınlığı; çap arttıkça ve miyelin kalınlaştıkça iletim hızı artar","Mitokondri yoğunluğu belirleyicidir; daha fazla ATP üretimi doğrudan iletim hızını artırır","Akson terminal dallanma sayısı arttıkça iletim hızı orantılı biçimde yükselir","Nörotransmitter vezikül büyüklüğü iletim hızını doğrudan belirler"],"correct":1,"exp":"Periferik sinirde aksiyon potansiyeli iletim hızını belirleyen başlıca yapısal faktörler akson çapı ve miyelin kılıfı kalınlığıdır. Geniş çaplı aksonlarda iç direnç (aksiyel direnç) daha düşüktür, bu da depolarizasyon dalgasının daha hızlı ilerlemesini sağlar. Miyelin ise membranlara kapasitans yükü bindiren iyon sızıntısını engelleyerek aksiyon potansiyelinin Ranvier boğumları arasında pasif olarak hızla yayılmasına (saltatory conduction) olanak tanır. Bu iki faktörün birlikteliği iletim hızını en iyi açıklar. Ranvier boğum sayısı, mitokondri yoğunluğu, dallanma sayısı veya vezikül büyüklüğü tek başına iletim hızını belirleyen yapısal faktörler değildir."},{"id":5891,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 8 aydır giderek ilerleyen yürüme güçlüğü ve ellerde titreme şikayetiyle başvuruyor. Muayenede rijidite, bradikinezi ve istirahat tremoru saptanıyor. Beyin görüntülemesinde substantia nigra pars compacta nöronlarında belirgin kayıp izleniyor. Bu nöronlarda biriken ve hastalığın patolojik belirteçi olan protein agregatları hangi yapıda depolanır?","options":["Nörofibriler yumak","Bunina cisimciği","Hirano cisimciği","Pick cisimciği","Lewy cisimciği"],"correct":4,"exp":"Parkinson hastalığında substantia nigra dopaminerjik nöronlarında alfa-sinüklein proteini anormal şekilde katlanarak Lewy cisimciklerini oluşturur. Lewy cisimcikleri sitoplazmik, yuvarlak, eozinofilik inklüzyon cisimcikleridir ve merkezi yoğun bir çekirdek ile çevresinde soluk bir hale içerir. Nörofibriler yumaklar Alzheimer hastalığında hiperfosforile tau proteini birikimini, Hirano cisimcikleri aktin agregatlarını, Pick cisimcikleri frontotemporal demansı, Bunina cisimcikleri ise ALS hastalığını temsil eder."},{"id":5892,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 3 haftadır sağ elinde güç kaybı ve iki gün önce başlayan sol gözde görme bulanıklığı nedeniyle değerlendiriliyor. Özgeçmişinde 1 yıl önce bacak uyuşması geçirdiği öğreniliyor. MR'de periventriküler beyaz cevherde multipl demiyelinizasyon plakaları saptanıyor. Bu hastalıkta akson iletiminin bozulmasından sorumlu temel mekanizma aşağıdakilerden hangisidir?","options":["Akson zarında voltaj kapılı sodyum kanallarının kalıcı inaktivasyonu","Schwann hücre apoptozuna bağlı aksiyal dejenerasyon","Miyelin kılıfının kaybıyla Ranvier boğumları arasındaki tuzlayıcı iletimin ortadan kalkması","Oligodendrosit nükleuslarında DNA hasarı sonucu enerji yetersizliği","Nöroglial skar dokusunun akson zarını dıştan sıkıştırarak iletimi mekanik olarak engellemesi"],"correct":2,"exp":"Multipl skleroz merkezi sinir sisteminde oligodendrositlerden kaynaklanan miyelin kılıfının otoimmün yıkımıyla karakterizedir. Sağlıklı miyelinli aksonlarda impuls iletimi Ranvier boğumları arasında tuzlayıcı iletim ile gerçekleşir ve bu mekanizma hem hızlı hem de enerji verimli iletim sağlar. Miyelin kaybıyla birlikte bu tuzlayıcı iletim ortadan kalkar, akson boyunca sürekli ve çok daha yavaş elektrotenik iletim gereklir. Bu durum iletim hızında belirgin düşüşe ve işlevsel bloka yol açar. Voltaj kapılı sodyum kanallarının kalıcı inaktivasyonu akut depolarizasyon sonrası geçici bir durumdur, hastalığın temel mekanizması değildir."},{"id":5893,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir fizyoloji pratik sınavında öğrencilere periferik sinirde hasar sonrası gözlemlenen Wallerian dejenerasyon süreci soruluyor. Aksotomez yaralanmadan sonra hasarın distalinde akson ve miyelin kılıfında gözlemlenen ilk yapısal değişiklik hangi mekanizmayla başlar?","options":["Mitokondri disfonksiyonuna bağlı ATP sentez durması","Schwann hücrelerinin apoptozunu tetikleyen retrograd sinyal kaskadı","Aksonun nöronal hücre gövdesinden kopmasıyla anterograd aksonal transportun kesilmesi ve sitoiskelet bütünlüğünün bozulması","Bölgesel inflamatuvar hücrelerden salınan proteazların miyelin kılıfını ve bazal laminayı yıkması","Distal akson segmentindeki sodyum-potasyum ATPaz pompasının çalışmasının durması"],"correct":2,"exp":"Wallerian dejenerasyonda hasarın distalinde kalan akson segmenti, nöronal hücre gövdesinden gelen trofik destek ve anterograd aksonal transporttan yoksun kalır. Bu ayrılmayla birlikte sitoplazma içi kalsiyum konsantrasyonu yükselir, kalpain gibi kalsiyuma bağımlı proteazlar aktive olur ve nörofilaman ile mikrotübül ağı parçalanır. Akson önce granüler görünüm kazanır, ardından fragmanlara ayrılır. Miyelin kılıfı da akson kaybına ikincil olarak parçalanır. Schwann hücreleri bu süreçte miyelini fagosite ederek temizlik görevi üstlenir ve ilerleyen evrede sinir rejenerasyonuna rehberlik eden Büngner bantlarını oluşturur."},{"id":5894,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek kötüleşen yürüme güçlüğü ve alt ekstremitede his kaybı yakınmasıyla başvuruyor. Muayenede derin tendon refleksleri artmış, Babinski pozitif, vibrasyon ve pozisyon duyusu bozuk. MR incelemesinde servikal bölgede spinal kord basısı saptanıyor. Bu hastada derin tendon reflekslerinin artmış olmasından sorumlu olan en temel mekanizma aşağıdakilerden hangisidir?","options":["Üst motor nöron hasarı sonucu inhibitör internöron aktivitesinin azalması","Üst motor nöron hasarı sonucu gama motor nöron devre dışı kalması","Alfa motor nöron kaybına bağlı kas atrofisi","Dorsal kök ganglion nöronlarının direkt hasarı","Renshaw hücresi hiperplazisi"],"correct":0,"exp":"Kortikal ve subkortikal inen yollar, spinal kord düzeyindeki inhibitör internöronlar aracılığıyla alfa motor nöronlar üzerinde sürekli bir baskılayıcı etki oluşturur. Üst motor nöron lezyonlarında bu inhibitör internöron aktivitesi ortadan kalkar; sonuçta alfa motor nöronlar daha kolay ateşlenir, derin tendon refleksleri artar ve spastisite gelişir. Gama motor nöron devre dışı kalması tam tersine refleksleri azaltır. Dorsal kök ganglion hasarı afferent kolu bozarak refleksi düşürür. Renshaw hücreleri ise rekürrent inhibisyon sağlayan internöronlardır ve hiperplazisi tanımlanmış bir mekanizma değildir."},{"id":5895,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, 3 haftadır sağ el bileğinde düşme ve parmak ekstansiyonunda kayıp yakınmasıyla geliyor. Öyküsünde koltuk değneği uzun süreli kullanımı mevcut. Elektrofizyolojik incelemede etkilenen sinirde aksonal dejenerasyon saptanıyor. Sinir biyopsisinde aksonun proksimal kesiminde balonlaşma, distal kesiminde ise miyelin ve aksonal yapıların yıkımı gözlemleniyor. Bu tabloda histopatolojik değişikliklerin temel mekanizması aşağıdakilerden hangisidir?","options":["Schwann hücrelerinin birincil olarak hasar görmesiyle segmental demiyelinizasyon gelişmesi","Aksonal transportun bozulması sonucu proksimalde akümülasyon ve distal Wallerian dejenerasyon","Endonöryal fibrozis nedeniyle sinir iletim hızının azalması","Nörotrofin reseptörü eksikliğine bağlı apoptoz","Miyelin temel proteinine karşı otoimmün yanıt"],"correct":1,"exp":"Sinir kompresyon hasarlarında aksonun mekanik olarak ezildiği noktada aksonal transport bozulur. Anterograd ve retrograd transport durduğundan akson proksimalinde sitoplazmik organeller ve veziküller birikir; bu balonlaşma görüntüsünü oluşturur. Hasarın distalinde ise akson beslenme desteğini yitirir, Wallerian dejenerasyon başlar: önce aksoplazma parçalanır, ardından miyelin makrofajlar tarafından fagosite edilir. Bu tablo Wallerian dejenerasyon ile uyumludur. Segmental demiyelinizasyon elektrofizyolojide iletim bloğu ve iletim hızı yavaşlaması şeklinde görülür, aksonal balonlaşmayı açıklamaz."},{"id":5896,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Kas iğciğinin primer anulospiral sonlanmasından gelen, en kalın miyelinli ve en hızlı ileten afferent lif aşağıdakilerden hangisidir?","options":["B lifi","A-delta lif","Ia afferent lif","C lifi","Grup IV afferent lif"],"correct":2,"exp":"Kas iğciği primer sonlanmasının Ia lifleri kalın miyelinli A-alfa sınıfındadır ve çok hızlı iletir. C ve grup IV lifler miyelinsiz, A-delta lifler ince miyelinlidir."},{"id":5897,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Fasikülasyon ve kas atrofisine hiperrefleksi, spastisite ve Babinski bulgusunun eşlik ettiği; duyunun korunduğu hastada en olası patolojik süreç aşağıdakilerden hangisidir?","options":["Yalnızca periferik sinirlerde miyelin kaybı gelişmesi","Yalnızca dorsal kök ganglionu nöronlarının kaybolması","Sinir-kas kavşağında asetilkolin reseptörlerinin bloke edilmesi","Kortikospinal üst motor nöronlarla ön boynuz alt motor nöronlarının birlikte dejenerasyonu","Serebellar Purkinje hücrelerinin seçici olarak kaybolması"],"correct":3,"exp":"Üst ve alt motor nöron bulgularının birlikte, duyusal bulgu olmadan görülmesi ALS'yi düşündürür. Patoloji motor korteks/kortikospinal yol ve anterior boynuz motor nöronlarını birlikte etkiler."},{"id":5898,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Periferik sinir hasarı sonrası aksonal rejenerasyonun gerçekleşebilmesi için hangi yapının sağlam kalması zorunludur?","options":["Endonöryum","Perinöryum","Epinöryum","Miyelin üreten oligodendrosit","Ranvier boğumu"],"correct":0,"exp":"Periferik sinirde akson kesildiğinde distal segmentte Wallerian dejenerasyon gelişir. Rejenerasyonun yönlenebilmesi için aksonun tüpünü oluşturan endonöryum kılıfının bütünlüğünün korunması şarttır. Schwann hücreleri bu tüp içinde prolifere olarak büyüme faktörü salgılar ve aksonun proksimalden distale ilerlemesine rehberlik eder. Perinöryum fasikülleri bir arada tutar ancak tek tek akson rejenerasyonunu yönlendirmez. Epinöryum sinirin dış bağ dokusu kılıfıdır."},{"id":5957,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Altmış iki yaşında erkek hasta, 8 aydır giderek artan yorgunluk ve egzersiz intoleransı şikayetiyle başvuruyor. Yapılan kas biyopsisinde mitokondrilerin iç membranında krista sayısında belirgin azalma saptanıyor. Bu hastada en çok hangi süreç bozulmuş olmalıdır?","options":["Oksidatif fosforilasyon kapasitesi","Glikoliz ile ATP üretimi","Yağ asidi sentezi","Ribozomal protein üretimi","Lizozomal enzim aktivasyonu"],"correct":0,"exp":"Mitokondri iç membranındaki kristalar, elektron transport zinciri ve ATP sentaz komplekslerinin yerleştiği yapılardır. Krista sayısının azalması, bu komplekslerin yüzey alanını ve dolayısıyla oksidatif fosforilasyon kapasitesini doğrudan düşürür. Glikoliz sitozolde gerçekleştiğinden mitokondri iç membran yapısından bağımsızdır. Yağ asidi sentezi de ağırlıklı olarak sitozolde ATP bağımlı değil NADPH bağımlı bir süreçtir. Klinik tabloda uzun süreli yorgunluk ve egzersiz intoleransı, yüksek ATP gereksinimi olan iskelet kaslarında oksidatif kapasite yetersizliğini yansıtır."},{"id":5958,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Yirmi sekiz yaşında kadın hasta, tekrarlayan pnömoni atakları ve erkek kardeşinde azoospermi öyküsü nedeniyle değerlendiriliyor. Elektron mikroskobisinde silia aksoneminde dış dynein kollarının eksik olduğu görülüyor. Bu bulguda bozulan temel mekanizma aşağıdakilerden hangisidir?","options":["Mikrotübül polimerizasyonu","Mikrotübül çiftleri arasındaki motor protein kaynaklı kayma hareketi","Aktin filaman ağının yeniden düzenlenmesi","Sentrozomdan mikrotübül nükleasyon kapasitesinin azalarak iğcik oluşumunu bozması","Ara filaman çapraz bağlanması"],"correct":1,"exp":"Silia ve flagella hareketinde aksonem içindeki 9 çift çevresel mikrotübül, dynein motor proteinleri aracılığıyla birbirine göre kayarak eğilme hareketi oluşturur. Dış dynein kolları bu kayma hareketinin birincil motorudur; ATP hidrolizi ile komşu mikrotübül çiftlerini birbirine göre kaydırır. Dynein kollarının yokluğunda mikrotübüller polimerize olabilir ve yapısal olarak bütündür; ancak aktif kayma gerçekleşemez, dolayısıyla silia hareketi tamamen durur. Bu tablo, Primer Silier Diskinezi ile uyumludur. Erkek kardeşinde azoospermi, flagellar dynein yetersizliğine bağlıdır ve aynı genetik defekti düşündürür."},{"id":5959,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Kısa ömürlü veya yanlış katlanmış sitozolik proteinler poliubikuitin zinciriyle işaretlendikten sonra başlıca hangi yapı tarafından ATP bağımlı olarak yıkılır?","options":["Peroksizom","Lizozom","Düz endoplazmik retikulum","Golgi aygıtı","26S proteazom"],"correct":4,"exp":"26S proteazom, poliubikuitinle işaretlenen sitozolik ve nükleer proteinleri ATP bağımlı olarak peptitlere parçalar. Zar ile çevrili bir organel değildir."},{"id":5960,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Yirmi iki yaşında kadın hasta, kas güçsüzlüğü ve göz kapağında düşme şikayetiyle başvuruyor. Özellikle gün içinde ilerleyen yorgunluk tanımladığı öğreniliyor. Yapılan elektrofizyolojik incelemede tekrarlayan sinir uyarımıyla kas yanıtının azaldığı saptanıyor. Bu hastada nöromüsküler kavşaktaki primer patolojinin yol açtığı sonuç aşağıdakilerden hangisidir?","options":["Voltaj kapılı sodyum kanallarının kalıcı inaktivasyonu","Asetilkolin veziküllerin ekzositozunun bozulması","Nikotinik reseptör sayısının azalmasına bağlı end-plate potansiyelinin eşik altında kalması","Miyelin kılıfının hasar görmesiyle ileti hızının düşmesi","Troponin-tropomiyozin kompleksinin kalsiyuma yanıt vermeyerek aktin bağlanma bölgelerini açamaması"],"correct":2,"exp":"Bu tablo miyastenia gravis ile uyumludur. Hastalıkta otoimmün antikorlar nöromüsküler kavşaktaki nikotinik asetilkolin reseptörlerine karşı oluşur. Reseptör sayısı ve işlevi azalır; bu nedenle asetilkolin salınımı normal olmasına karşın oluşan end-plate potansiyeli eşik değerine ulaşamaz ve aksiyon potansiyeli tetiklenemez. Tekrarlayan uyarımda veziküller azaldıkça yanıt da kümülatif olarak düşer. Voltaj kapılı sodyum kanalları, miyelin ve troponin sistemi bu hastalığın birincil hedefleri değildir."},{"id":5961,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Kırk beş yaşında erkek hasta, soğuk ortamda şiddetlenen kas sertliği ve kavrama sonrası eli açamama yakınmasıyla başvuruyor. Dört yıldır bu şikayetleri olduğunu, baldır kası hipertrofisinin de eşlik ettiğini ifade ediyor. EMG incelemesinde miyotonik deşarjlar saptanıyor. Bu hastanın semptomlarına yol açan temel iyon kanalı bozukluğu hangi mekanizma üzerinden işlev görür?","options":["Sarkoplazmik retikulumdan kalsiyum salınımının artmasıyla miyosin aktivitesinin uzaması","Voltaj kapılı klorür kanallarının işlev kaybı","T-tübül sisteminde dihidropiridin reseptörünün ryanodin reseptörle eşleşememesi","Sodyum-potasyum ATPaz pompasının inhibisyonuyla istirahat membran potansiyelinin pozitifleşmesi","Miyozin ağır zincir mutasyonuna bağlı çapraz köprü döngüsünün uzaması"],"correct":1,"exp":"Miyotonia konjenita, CLCN1 genindeki mutasyon sonucu iskelet kası voltaj kapılı klorür kanallarının işlev kaybıyla ortaya çıkar. Normalde klorür kanalları, tekrarlayan aksiyon potansiyeli sonrası membranı repolarize etmede ve aşırı uyarılabilirliği frenlemede kritik rol oynar. Klorür iletiminin bozulduğu durumda membran hiperpolarizasyona gidemez; küçük depolarizasyonlar bile sodyum kanallarını yeniden aktive ederek istemsiz aksiyon potansiyeli dizisi oluşturur. Bu da klinik olarak miyotoni olarak gözlemlenir. Sarkoplazmik retikulum, T-tübül eşleşmesi veya miyozin patolojisi bu tablonun birincil mekanizması değildir."},{"id":5962,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Hücre zarından gerçekleşen transport mekanizmalarını araştıran bir fizyoloji deneyinde, intrasellüler sodyum konsantrasyonu artırılmış bir hücreye ATP sentezi tamamen bloke ediliyor. Bu koşulda glikoz alımının nasıl etkileneceği sorulmaktadır. Gözlemlenen değişiklik hangi mekanizmayla açıklanır?","options":["Glikozun GLUT2 kanalları aracılığıyla kolaylaştırılmış difüzyonla alınımı durur çünkü GLUT2 ATP bağımlıdır","Sekonder aktif transport bozulur çünkü sodyum-glikoz ko-transportörünün çalışması için gereken sodyum gradyanı ortadan kalkar","Primer aktif transport bozulur çünkü sodyum-glikoz ko-transportörü doğrudan ATP kullanır","Sodyum konsantrasyonu arttığında osmotik basınç değişimi glikozun hücre dışına çıkmasına neden olur","Glikoz transportu etkilenmez çünkü pasif difüzyon ATP gerektirmez"],"correct":1,"exp":"Bağırsakta ve böbrek proksimal tübülünde glikoz alımı SGLT1 veya SGLT2 gibi sodyum-glikoz ko-transportörleri aracılığıyla gerçekleşir. Bu mekanizma sekonder aktif transporttur; glikozu konsantrasyon gradyanına karşı taşımak için sodyumun hücre içine girişindeki elektrokimyasal gradyanı enerji kaynağı olarak kullanır. ATP bloke edildiğinde Na-K-ATPaz pompası çalışamaz, hücre içi sodyum birikir ve hücre dışı ile içi arasındaki sodyum gradyanı ortadan kalkar. Gradyan olmadan ko-transportör işlev göremez ve glikoz alımı durur. Bu durum ATP'nin dolaylı olarak sekonder aktif transportu desteklediğini açıkça gösterir."},{"id":5963,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"65 yaşında erkek hasta, son 3 aydır giderek artan yorgunluk ve egzersiz intoleransı şikayetiyle başvuruyor. Yapılan tetkiklerinde iskelet kası biyopsisinde mitokondri sayısının belirgin şekilde azaldığı ve mevcut mitokondrilerden bazılarının anormal iç membran katlantılarına sahip olduğu görülüyor. Bu hastada oksidatif fosforilasyonun bozulmasının temel mekanizması hangi yapısal değişiklikle en doğrudan ilişkilidir?","options":["Dış mitokondri membranındaki porin kanallarının tıkanması","Sitoplazmik ribozomlarda sentez hatasına bağlı içe aktarım defekti","Mitokondri matriksindeki DNA replikasyonunun durması","Kristaların yüzey alanının azalması","Mitokondri zarları arasındaki aralıkta sitokrom c birikmesi"],"correct":3,"exp":"Mitokondri iç membranının kristalar adı verilen katlantıları, ATP sentaz ve elektron transport zinciri komplekslerinin yerleştiği yapısal platformlardır. Krista yüzey alanının azalması bu komplekslerin fonksiyonel yoğunluğunu doğrudan düşürür ve proton gradyanının oluşturulmasını bozar. Dış membranda porinin tıkanması madde girişini etkiler ancak elektron zincirini doğrudan bozmaz. Mitokondri DNA replikasyonu ayrı bir süreçtir ve akut krista değişikliğini açıklamaz. İçe aktarım defekti sitoplazmik sentezle ilgilidir."},{"id":5964,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Okülokutanöz hipopigmentasyon, tekrarlayan piyojenik enfeksiyonlar ve lökositlerde dev granüller bulunan çocukta LYST geninde mutasyon saptanıyor. Bu hastadaki temel hücresel bozukluk aşağıdakilerden hangisidir?","options":["Lizozom ilişkili organellerin veziküler trafiğinin ve füzyonunun bozulması","Reseptör aracılı endositozun klatrin kusuruyla engellenmesi","Nükleer por kompleksinden protein taşınmasının bozulması","Ribozomda translokasyon basamağının aksayarak sentezi durdurması","Mitokondriyal DNA replikasyonunun duraklayarak enerji üretimini azaltması"],"correct":0,"exp":"Chediak-Higashi sendromunda LYST kusuru lizozom ilişkili organellerin boyut ve trafik düzenini bozar. Fagozom-lizozom işlevi ve sitotoksik granül salınımı etkilenir; dev granüller oluşur."},{"id":5965,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":3,"q":"Bir hücrede sodyum-potasyum ATPaz pompasının tamamen inhibe edildiği düşünüldüğünde, zamanla hücre hacminde ne beklenir ve bunun temel nedeni aşağıdakilerden hangisidir?","options":["Hücre büzülür çünkü içerideki sodyum dışarı çıkmaya devam eder","Hücre şişer çünkü ATP yokluğunda hücre zarı geçirgenliği sıfıra düşer","Hücre hacmi değişmez çünkü potasyum kanalları dengeleyici rol üstlenir","Hücre önce şişer sonra büzülür çünkü kompansatuar klor atılımı devreye girer","Hücre şişer çünkü intraselüler sodyum birikimi ozmotik su girişini artırır"],"correct":4,"exp":"Sodyum-potasyum ATPaz her döngüde 3 sodyumu dışarı atarken 2 potasyumu içeri alır ve böylece intraselüler sodyum konsantrasyonunu düşük tutar. Pompa inhibe edildiğinde sodyum hücre içinde birikir, bu ozmotik basınç artışı su girişine neden olur ve hücre şişer. Potasyum kanalları bu dengesizliği tam olarak telafi edemez çünkü sodyumun birikimi dominant ozmotik etkiyi yaratır. Hücre zarı geçirgenliği ATP yokluğuyla doğrudan sıfırlanmaz. Kompansatuar klor atılımı kısmi bir etki yaratabilir ancak net sonuç yine de şişmedir."},{"id":5966,"ders":"Fizyoloji","konu":"Hücre Histolojisi ve Fizyolojisi","diff":4,"q":"Kırk iki yaşında erkek hasta, son altı aydır giderek artan kas güçsüzlüğü ve egzersiz intoleransı yakınmasıyla başvuruyor. Yapılan tetkiklerinde serum laktat düzeyi yüksek, biyopsi örneğinde elektron mikroskopisinde mitokondrilerde kristae yapılarında belirgin bozulma saptanıyor. Bu hastada enerji üretiminin bozulmasından birincil olarak sorumlu tutulan mekanizma aşağıdakilerden hangisidir?","options":["Sitozolik glikoliz enzimlerinin aktivite kaybı","Endoplazmik retikulumdan kalsiyum salınımının engellenmesi","Glikoz taşıyıcı proteinlerin ekspresyonunun azalması","Lizozomal membran geçirgenliğinin artması","İç mitokondriyal membranda proton gradyanının oluşturulamaması"],"correct":4,"exp":"Mitokondriyal kristae yapıları iç mitokondriyal membranın kıvrımlarından oluşur ve bu membran üzerinde elektron transport zinciri kompleksleri ile ATP sentaz yerleşir. Kristae bütünlüğünün bozulması, iç mitokondriyal membranda H+ iyonlarının intermembran aralığına pompalanmasını ve bu sayede oluşması gereken elektrokimyasal proton gradyanını doğrudan engeller. ATP sentaz, intermembran aralığından matrikse akan proton akışını kullanarak ADP'yi fosforile eder; gradyan olmadığında oksidatif fosforilasyon durur. Sonuçta hücre enerji ihtiyacını karşılamak için anaerobik glikolize yönelir ve laktat birikimi ortaya çıkar; bu da klinik tablodaki yüksek serum laktat bulgusunu açıklar."},{"id":5967,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Altmış iki yaşında erkek hasta, son altı aydır artan yorgunluk ve egzersiz intoleransı şikayetiyle başvuruyor. Yapılan biyopside iskelet kası liflerinde tip II liflerin belirgin atrofiye uğradığı, tip I liflerin ise korunduğu saptanıyor. Bu hastada mitokondri yoğunluğu, oksidatif enzim kapasitesi ve yorulmaya direnç açısından hangi lif tipinin özellikleri baskın olarak korunmuştur?","options":["Tüm lif tipleri eşit oranda etkilenmiştir; bu nedenle klinik tablo nonspesifiktir","Tip IIa hızlı kasılan lifler; orta düzey mitokondri içeriği ve hem oksidatif hem glikolitik metabolizma kullanımıyla öne çıkar","Tip IIb hızlı kasılan lifler; düşük mitokondri yoğunluğu, yüksek glikolitik enzim aktivitesi ve hızlı yorulma eğilimiyle tanımlanır","Tip I yavaş kasılan lifler; yüksek mitokondri yoğunluğu, yüksek oksidatif kapasite ve düşük yorulma hızı ile karakterizedir","Tip II lifler daha fazla mitokondri içerdiğinden korunan lifler daha fazla enerji üretir"],"correct":3,"exp":"İskelet kasında tip I lifler (yavaş kasılan, kırmızı lifler) yüksek mitokondri yoğunluğu, miyoglobin içeriği ve oksidatif fosforilasyon kapasitesi ile kronik aktiviteye ve yorulmaya karşı dirençlidir. Tip II lifler ise özellikle tip IIb hızlı kasılan beyaz lifler glikolitike bağımlı olup mitokondri yoğunluğu düşüktür ve hızla yorulur. Disuse atrofi, yaşlanma ve sistemik hastalıklarda önce tip II lifler etkilendiğinden korunan lifler tip I özellikleri taşıyan liflerdir. Bu soru özellikle disuse/yaşlanmaya bağlı selektif tip II atrofisinde hangi fiz­yolojik özelliklerin korunduğunu sorgulamaktadır."},{"id":5968,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"Yirmi sekiz yaşında kadın hasta, travma sonrası deri defekti nedeniyle izlenmektedir. Yara iyileşmesi sürecinde yapılan biyopside granülasyon dokusunda bol miktarda miyofibroblast saptanıyor. Bu hücrelerin yara kontraksiyonundaki temel işlevsel özelliği, hangi iki yapısal proteinin birlikte ekspresyonuyla açıklanır?","options":["Alfa-düz kas aktin ve vimentin; bu kombinasyon miyofibroblastların hem kontraktil hem mezenkimal özellik taşıdığını gösterir","Miyozin ağır zinciri ve troponin I; çizgili kas tipi kontraksiyon mekanizmasının devreye girdiğini yansıtır","Desmin ve titin; miyofibroblastların sarkomer benzeri yapı oluşturduğunu ve pasif gerilime katkı sağladığını gösterir","Kollajen tip IV ve laminin; bazal membran sentezinin kontraksiyon kapasitesini doğrudan belirlediğini ortaya koyar","Fibronektin ve elastin; hücre dışı matriks yeniden şekillenmesinin tek başına yara kontraksiyonunu sağladığını ifade eder"],"correct":0,"exp":"Miyofibroblastlar, fibroblast ile düz kas hücresi arasında hibrit özellik gösteren hücrelerdir. Alfa-düz kas aktinin (alfa-SMA) ekspresyonu kontraktil kapasiteyi sağlarken vimentin ekspresyonu mezenkimal kökenlerini yansıtır. Bu iki proteinin bir arada bulunması miyofibroblastın tanımlayıcı immünohistokimyasal özelliğidir. Troponin ve desmin çizgili/kardiyak kas belirteçleridir; kollajen ve fibronektin matriks bileşenleridir ve kontraktil fonksiyonu doğrudan açıklamaz. Yara kontraksiyonunda TGF-beta uyarısıyla fibroblastlardan dönüşen miyofibroblastlar kritik rol oynar."},{"id":5969,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Kronik gastrit nedeniyle izlenen elli yaşında erkek hastanın mide biyopsisinde goblet hücreleri saptanıyor. Bu bulgu hangi doku dönüşümünün göstergesidir ve altta yatan temel mekanizma aşağıdakilerden hangisidir?","options":["Displazi; hücre farklılaşmasının bozulmasına bağlı nükleer atipi, artmış mitoz ve mimari düzensizlik ortaya çıkması","Metaplazi; mide bezlerindeki prizmatik müsin salgılayan hücrelerin yerini barsak tipi goblet hücrelerinin almasıdır ve kronik irritasyona bağlı kök hücre yeniden programlanmasını yansıtır","Hiperplazi; mide mukozasındaki hücre sayısının artışıyla birlikte goblet hücresi sayısı da paralel olarak yükselir","Atrofi; parietal hücre kaybıyla birlikte boşalan niş alanlara goblet hücreleri göç eder","Neoplazi; goblet hücreleri erken evre mide adenokarsinomunun en güvenilir erken belirtecidir"],"correct":1,"exp":"Intestinal metaplazi, mide mukozasında kronik H. pylori enfeksiyonu veya tekrarlayan hasara yanıt olarak kök hücrelerin barsak epiteli yönünde yeniden programlanmasıyla gerçekleşir. Goblet hücreleri barsak epitelinin karakteristik elemanıdır ve normal mide mukozasında bulunmaz. Bu dönüşüm displazi değil metaplazidir; displazide nükleer atipi ve mimari düzensizlik ön plandadır. Hiperplazi hücre sayısı artışı, atrofi hücre kaybı, neoplazi ise klonal tümör gelişimidir."},{"id":5970,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"65 yaşında erkek hasta, son 3 aydır giderek artan yorgunluk ve efor dispnesi yakınmasıyla başvuruyor. Özgeçmişinde kronik böbrek yetmezliği mevcut. Hemoglobin 7.2 g/dL, retikülosit sayısı düşük bulunuyor. Kemik iliği biyopsisinde eritroid öncül hücrelerde belirgin azalma saptanıyor. Bu hastada eritropoietin düzeyi ölçülse en büyük olasılıkla hangi sonuç beklenir ve bunun nedeni aşağıdakilerden hangisidir?","options":["Eritropoietin düzeyi yüksek bulunur, çünkü böbrek yetmezliğinde kompansatuar artış gelişir","Eritropoietin düzeyi normal bulunur, çünkü karaciğer eksikliği tam olarak kompanse eder","Eritropoietin düzeyi düşük bulunur, çünkü peritübüler fibroblastlar yeterli sentez yapamamaktadır","Eritropoietin düzeyi yüksek bulunur, çünkü hipoksi duyarlı elementler maksimal uyarılmıştır","Eritropoietin düzeyi düşük bulunur, çünkü glomerüler filtrasyon hızındaki düşüş hormonu parçalar"],"correct":2,"exp":"Eritropoietin ağırlıklı olarak böbreğin kortikomeduller bileşke bölgesindeki peritübüler interstisyel fibroblastlar tarafından sentezlenir. Kronik böbrek yetmezliğinde bu hücreler fibrozis ve hasar nedeniyle işlevini yitirir; hipoksiye rağmen yeterli EPO üretilemez. Bu durum normositin ya da mikrositik olmayan, hiporejeneratif anemiye yol açar. Karaciğer yalnızca EPO üretiminin yüzde 10 ile 15 gibi küçük bir bölümünü karşıladığından kompansasyon yetersiz kalır. Anemi derinleşmesine karşın EPO düzeyi beklenenin altında ya da düşük seyretmesi tanıyı doğrular."},{"id":5971,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"28 yaşında kadın hasta, kronik güneş hasarına bağlı cilt değişiklikleri nedeniyle dermatoloji polikliniğine başvuruyor. Dermoskopide elastik liflerde belirgin yıkım ve deri elastikiyetinde kayıp saptanıyor. Bu tabloda hangi doku bileşeninin yapısal bütünlüğü öncelikli olarak bozulmuştur?","options":["Tip I kollajen lifleri","Retiküler lifler","Fibronektin köprüleri","Elastin içeren elastik lifler","Proteoglikan matrisi"],"correct":3,"exp":"Elastik lifler, elastin proteini çevresine oksisilin ve fibrillinle sarılmış mikrofibrillerden oluşur. Cilt elastikiyetini ve gerilme sonrası geri dönüşü sağlarlar. Kronik UV maruziyeti matriks metalloproteinazları aktive ederek elastini parçalar; solar elastozis adı verilen bu tabloda elastik lif ağı bozulur ve deri sarkık bir görünüm alır. Tip I kollajen deri gerilme direncinden sorumludur ancak elastikiyet kaybında primer hedef değildir. Retiküler lifler ince organlarda destek işlevi görür."},{"id":5972,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"42 yaşında erkek hasta, 6 aydır tekrarlayan mide yanması ve yutma güçlüğü nedeniyle gastroenteroloji birimine yönlendiriliyor. Üst GIS endoskopisinde özofagusun alt ucunda silindirik epitel metaplazisi izleniyor ve Barrett özofagusu tanısı konuluyor. Bu değişikliğin gerçekleşebilmesi için hangi hücre topluluğunun yeniden programlanması zorunludur?","options":["Özofagus yüzeyindeki yassı epitel hücrelerinin doğrudan dönüşüm geçirerek silindirik fenotip kazanması","Submukozal Brunner bezlerinin duktal hücreleri yüzeye göç eder","Özofageal müköz bez hücreleri skuamöz tabakayı iterek yüzeye yerleşir","Lamina propriadaki miyofibroblastlar epitel hücrelerine transdifferansiye olur","Pluripotent bazal/kök hücreler tekrarlayan asit hasarı altında silindirik diferansiyasyon yönünde yeniden programlanır"],"correct":4,"exp":"Barrett özofagusu, çok katlı yassı epitelin intestinal tipte kolumnar epitel ile yer değiştirdiği bir metaplazi örneğidir. Güncel kanıtlar bu değişimin olgun skuamöz hücrelerin direkt dönüşümüyle değil, özofageal bazal kök hücrelerinin ve özofagogastrik bileşkedeki progenitör hücre havuzunun kronik asit-safra maruziyeti altında yeniden programlanmasıyla gerçekleştiğini ortaya koymaktadır. Wnt, Notch ve BMP sinyal yollarındaki değişimler bu hücreleri intestinal diferansiyasyon yönünde yönlendirir. Submukozal bezler ve miyofibroblastlar metaplastik epitelin kaynağı değildir. Bu mekanizmanın anlaşılması Barrett epitelinin neden skuamöz hücrelerden farklı bir genetik profile sahip olduğunu açıklar."},{"id":5973,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"67 yaşında erkek hasta, bacaklarında progresif güçsüzlük ve his kaybı şikayetiyle başvuruyor. Nörolojik muayenede derin tendon refleksleri artmış, Babinski pozitif bulunuyor. Sinir biyopsisinde miyelin kılıfında yaygın hasar saptanıyor. Bu hastada aksiyon potansiyelinin iletim hızındaki yavaşlamanın temel nedeni hangi mekanizmaya bağlıdır?","options":["Ranvier nodları arasındaki kapasitif yükün artmasına","Saltatorik iletimin bozularak sürekli iletiye dönüşmesine","Voltaj kapılı sodyum kanallarının inaktivasyonuna","Aksonun çapının azalmasına","Potasyum kanallarının erken aktivasyonuna"],"correct":1,"exp":"Miyelin kılıfı, akson boyunca elektrik yalıtımı sağlayarak aksiyon potansiyelinin Ranvier nodlarından nodlara atlayarak ilerlemesine olanak tanır; buna saltatorik iletim denir. Miyelin hasarında bu atlama mekanizması bozulur ve impuls tüm membran boyunca yavaş ve sürekli biçimde iletilmek zorunda kalır. Bu durum iletim hızını belirgin biçimde düşürür. Voltaj kapılı sodyum kanalları yalnızca Ranvier nodlarında yoğunlaştığından, miyelin yıkımı bu kanalları işlevsiz bırakır ve membran kapasitansı belirgin biçimde artar. Saltatorik iletimin sürekliye dönüşmesi, MS ve Guillain-Barre gibi demiyelinizan hastalıklarda temel elektrofizyolojik bulgudur."},{"id":5974,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"45 yaşında kadın hasta, 8 aydır devam eden sabah tutukluğu, el eklemlerinde şişlik ve simetrik artralji yakınmalarıyla romatoloji polikliniğine başvuruyor. Eklem sıvısı incelemesinde sinovyosit proliferasyonu ve pannus oluşumu saptanıyor. Sinovyal dokudaki Tip A sinovyositlerin kıkırdak tahribatındaki rolünü açıklayan hangi özellik bu hücreleri diğer doku makrofajlarından ayırt eder?","options":["Fagosite ettikleri artık maddeleri sinovyal sıvıya salmaları","Hematopoetik kök hücreden değil mezenşimal kök hücreden köken almaları","Kollajen sentezi yaparak matriks oluşturmaları","Sinovyal sıvıya hyalüronik asit salgılamaları","Proliferasyon kapasitelerinin diğer makrofajlara göre belirgin biçimde düşük olması"],"correct":0,"exp":"Sinovyal zar iki tip hücreden oluşur: Tip A sinovyositler makrofaj soyundan gelir ve monosit kökenlidir, Tip B sinovyositler ise fibroblast benzeri hücrelerdir ve hyalüronik asit ile sinovyal sıvı komponentlerini sentezler. Tip A sinovyositler fagositoz yaparak eklem içindeki artıkları temizler; ancak fagosite ettikleri maddeleri lizozomal enzimlerle birlikte sinovyal sıvıya geri salmaları eklem içi inflamasyonu sürdürür ve kıkırdak matriksini parçalar. Bu özellik onları karaciğer Kupffer hücreleri gibi klasik doku makrofajlarından işlevsel olarak ayırır."},{"id":5975,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":3,"q":"Bir fizyoloji laboratuvarında iskelet kası ve kalp kası karşılaştırılıyor. Kalp kasının tetanik kasılma yapamamasının temel nedeni hangi yapısal ya da elektrofizyolojik özelliğe bağlıdır?","options":["Kalp kasının sarkomerleri arasındaki Z disklerinin daha kalın olmasına","Kalp kasında T tübüllerinin bulunmamasına","Aksiyon potansiyeli süresinin uzun olması nedeniyle refrakter dönemin kasılma süresiyle örtüşmesine","Kalp kasındaki troponin izoformunun kalsiyuma daha yavaş bağlanmasına","Kalp kasında miyozin ATPaz aktivitesinin iskelet kasına göre düşük olmasına"],"correct":2,"exp":"İskelet kasında aksiyon potansiyeli birkaç milisaniye sürerken mekanik kasılma çok daha uzun sürer; bu nedenle yeni uyarılar eklenerek tetanos oluşabilir. Kalp kasında ise aksiyon potansiyeli plateausu (Faz 2) nedeniyle 200-300 ms sürer ve bu süre mekanik sistol süresiyle neredeyse çakışır. Aksiyon potansiyeli devam ederken hücre mutlak refrakter dönemde olduğundan yeni bir uyarı alınamaz; kasılma bitmeden yeni bir kasılma başlatılamaz. Bu özellik kalbin pompa işlevini koruması açısından zorunludur; tetanos oluşsaydı diyastol gerçekleşemez ve kalp dolum yapamaz hale gelirdi. Platau fazındaki yavaş kalsiyum kanallarının açık kalması hem uzun aksiyon potansiyelinin hem de bu koruyucu mekanizmanın temelidir."},{"id":5976,"ders":"Fizyoloji","konu":"Doku Histolojisi ve Fizyolojisi","diff":4,"q":"55 yaşında erkek hasta, uzun süredir devam eden kalp yetmezliği nedeniyle takip edilmektedir. Hastanın ekokardiyografisinde sol ventrikül ejeksiyon fraksiyonunun ciddi ölçüde düştüğü ve miyokard duvar kalınlığının arttığı görülmektedir. Biyopsi örneğinde kardiyomiyosit çapının belirgin biçimde genişlediği, ancak hücre sayısının değişmediği saptanmaktadır. Bu süreçte miyokard kütlesindeki artıştan sorumlu olan temel hücresel mekanizma aşağıdakilerden hangisidir?","options":["Kardiyomiyositlerin mitoz bölünmesiyle hücre sayısının artması","Sarkomer sayısının seri olarak eklenmesiyle hücre uzunluğunun artması","Sarkomer sayısının paralel olarak eklenmesiyle hücre çapının artması","Fibroblastların miyosit prekürsörlerine dönüşerek hiperplazi oluşturması","Miyozin ağır zincir izoformunun hızlı tipten yavaş tipe geçişiyle kontraktilite artması"],"correct":2,"exp":"Basınç yüküne bağlı gelişen konsantrik hipertrofide kardiyomiyositler bölünemez; bunun yerine yeni sarkomerler mevcut sarkomerlere paralel olarak eklenir. Bu ekleme hücre çapını artırır ve duvar kalınlaşmasına yol açar. Hacim yüküne bağlı eksentrik hipertrofide ise sarkomerler seri olarak eklenerek hücre uzunluğunu ve boşluk çapını artırır. Soruda hücre sayısının değişmediği ve çapın arttığı belirtildiğinden, bu tablo basınç yüküne bağlı konsantrik hipertrofiyle uyumludur ve sorumlu mekanizma paralel sarkomer eklenmesidir. Kardiyomiyositler terminal diferansiye hücreler olduğundan mitoz bölünme kapasitelerini kaybetmişlerdir; bu nedenle hiperplazi değil, hipertrofi söz konusudur."},{"id":5977,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, 8 aydır giderek kötüleşen proksimal kas güçsüzlüğü ve egzersiz intoleransı şikayetiyle başvuruyor. Elektromiyografide miyopatik patern saptanıyor. Kas biyopsisinde tip 2 liflerde belirgin atrofi ve mitokondri sayısında azalma dikkat çekiyor. Bu hastada egzersiz sırasında kas yorgunluğunun temel biyokimyasal mekanizması hangi seçenekte doğru açıklanmıştır?","options":["Troponin I fosforilasyonunun artmasına bağlı aktin-miyozin etkileşiminin inhibisyonu","Oksidatif fosforilasyon kapasitesinin azalması nedeniyle ATP yenilenmesinin bozulması ve miyozin ATPaz aktivitesinin sürdürülememesi","Sarkoplazmik retikulumdan Ca2+ salınımının yetersizliği sonucu miyozin başlarının aktin filamentlerine bağlanamaması","T tübül sistemindeki aksiyon potansiyeli iletiminin yavaşlaması sonucu eksitatör-kontraktil birleşmenin gecikmesi","Kreatin kinaz rezervlerinin tükenmesiyle fosfokreatinden ATP üretiminin durması ve aktin polimerizasyonunun bozulması"],"correct":1,"exp":"Bu olguda biyopside mitokondri sayısındaki azalma, oksidatif metabolizmanın yetersizliğine işaret etmektedir. Tip 2 lifler normalde hızlı glikolitik lifler olmakla birlikte, mitokondriyal patolojilerde tüm lif tiplerinde ATP yenilenmesi bozulur. Miyozin ATPaz, aktin-miyozin çapraz köprü döngüsünü sürdürmek için sürekli ATP gerektirir; mitokondri disfonksiyonunda oksidatif fosforilasyon yoluyla ATP üretimi yetersiz kalır ve bu durum çapraz köprü ayrılmasını engeller, rigor benzeri bir yorgunluk tablosu oluşturur. Troponin I fosforilasyonu sempatik uyarıyla ilişkili bir modülatör mekanizmadır ve primer yorgunluk nedeni değildir."},{"id":5978,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, aniden başlayan ve 3 saattir devam eden boyun ve çene kaslarında şiddetli spazmla acile getiriliyor. Özgeçmişinde psikiyatrik hastalık nedeniyle başlanan bir ilaç tedavisi mevcut. Muayenede opistotonus ve okülojirik kriz saptanıyor. Bu tablonun tetiklendiği nöromüsküler bileşkedeki mekanizma en çok hangi seçenekle uyumludur?","options":["Asetilkolin esterazın geri dönüşümsüz inhibisyonu sonucu motor son plakta aşırı depolarizasyon ve sürekli kas kontraksiyonu","Presinaptik terminalde Ca2+ bağımlı asetilkolin vezikül ekzositozunun artması sonucu postsinaptik nikotinik reseptörlerin sürekli uyarılması","Motor son plakta nikotinik reseptör sayısının artmasına bağlı eşik altı uyaranlarla spontan aksiyon potansiyeli oluşumu","Postsinaptik kas membranındaki voltaj kapılı Na+ kanallarının sürekli açık kalmasıyla sarkolemmada kalıcı depolarizasyon oluşması","Ekstrapiramidal sistemdeki dopamin D2 reseptör blokajının spinal alfa motor nöronlarını disinhibisyona uğratması ve kas iğciği duyarlılığının artması"],"correct":4,"exp":"Klinik tablodaki opistotonus, okülojirik kriz ve tortikolis, antipsikotik kullanımına bağlı akut distoni ile uyumludur. Mekanizma doğrudan nöromüsküler bileşkede değil, ekstrapiramidal düzeyde işler; ancak nihai etki kas kontraksiyonu üzerinedir. Antipsikotikler dopamin D2 reseptörlerini bloke ederek bazal ganglia-spinal entegrasyonunu bozar, spinal internöron inhibisyonunu azaltır ve alfa motor nöron deşarjlarını artırır. Kas iğciğindeki Ia afferent duyarlılığı artar, bu da monosinaptik gerim refleksini güçlendirir ve karşı kaslar arasındaki koordinasyonu bozarak distonik postürü oluşturur. Asetilkolin esteraz inhibisyonu organofosfat zehirlenmesinin tablosudur ve kolinerjik kriz bulguları eşlik eder."},{"id":5979,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, merdiven çıkarken her iki bacağında ağrı ve güçsüzlük yakınmasıyla başvuruyor. Nörolojik muayenede derin tendon refleksleri artmış, patolojik refleksler pozitif bulunuyor. EMG incelemesinde motor ünite aksiyon potansiyeli amplitüdleri artmış, polifazik potansiyeller görülüyor. Kasın biyopsisinde tip 2 liflerin çapında belirgin azalma saptanırken tip 1 liflerde grupsal atrofi ve fiber tip gruplandırması dikkat çekiyor. Bu hastada gözlemlenen fiber tip gruplandırmasının altta yatan temel mekanizması aşağıdakilerden hangisidir?","options":["Tip 2 liflerin selektif apoptoza girmesi sonucu tip 1 lif oranının görece artması","Kas satellit hücrelerinin aktivasyonuyla yeni miyofibril oluşumu","Miyozin ağır zincir izoform ekspresyonunun motor nöron tarafından yeniden programlanması","T tübül sisteminin yeniden düzenlenmesiyle uyarı iletiminin değişmesi","Troponin C izoformunun kalsiyum duyarlılığını artırarak kasılma eşiğini düşürmesi"],"correct":2,"exp":"Fiber tip gruplandırması, denervasyon-reinnervasyonun klasik bulgusudur. Normalde motor üniteler kasın içine mozaik şekilde dağılmıştır. Denervasyon sonrası komşu sağlıklı motor nöronların kollateral sprouting ile bu lifleri yeniden innerve etmesiyle birlikte, motor nöron hangi fiber tipini innerve ederse o fiber tipini belirleyen trofik sinyalleri (özellikle aksiyon potansiyeli sıklığı ve nörotrofik faktörler) gönderir. Yavaş ateşlenen motor nöronlar liflerde tip 1 izoform ekspresyonunu, hızlı ateşlenenler ise tip 2 izoform ekspresyonunu indükler. Böylece aynı motor nörondan innerve olan lifler aynı tip özellik kazanır ve gruplandırma ortaya çıkar."},{"id":5980,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"23 yaşında kadın sporcu, yoğun antrenman sonrası her iki baldırında şiddetli krampa benzer ağrı ve kahverengi renk idrar yakınmasıyla acil servise geliyor. Serum kreatin kinaz düzeyi 45000 U/L, miyoglobin pozitif, serum kalsiyum düzeyi normalin alt sınırında saptanıyor. Hastanın semptomları tekrarlayan rabdomiyoliz atakları şeklinde seyrediyorsa ve egzersiz sırasında laktat yanıtı bozuksa bu tabloya en çok uyan miyopatinin patolojik mekanizması aşağıdakilerden hangisidir?","options":["Sarkoplazma retikulumundan kalsiyum salınımının riyanodin reseptör mutasyonu nedeniyle aşırı artması","T tübül membranının kolesterol içeriğinin artmasıyla aksiyon potansiyeli iletiminin yavaşlaması","Miyosin başının aktin filamentine bağlanma afinitesinin artmasıyla gevşeme fazının uzaması","Dihidropiridin reseptörü ile riyanodin reseptörü eşleşmesinin bozulmasıyla uyarı-kasılma çiftlenmesinin aksaması","Glikojen veya yağ asidi metabolizmasındaki enzim eksikliği nedeniyle ATP üretiminin egzersizde yetersiz kalması"],"correct":4,"exp":"Egzersiz sırasında laktat yanıtının bozuk olması, iskemik egzersiz testinde laktat artışının gözlenmemesi glikogenoliz veya glikoliz enzim eksikliklerinin (McArdle hastalığı gibi glikojen depo miyopatileri ya da karnitin palmitoyltransferaz eksikliği gibi yağ asidi oksidasyon bozuklukları) temel bulgusudur. Bu hastalarda egzersizle artan enerji talebini karşılayacak substrat sağlanamaz, ATP yetersizliği membran bütünlüğünü bozar ve miyoglobin serbestleşir. Riyanodin reseptör mutasyonu malign hipertermi ve santral kor hastalığıyla, tetikleyici ajan maruziyetiyle ilişkilidir, tekrarlayan egzersizle rabdomiyolize yol açmaz. Miyosin-aktin afinitesi ve gevşeme bozukluğu miyotoni tablolarını açıklar."},{"id":5981,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, son 6 aydır merdiven çıkarken bacaklarında yorgunluk ve güçsüzlük yakınmasıyla başvuruyor. Muayenede proksimal kas güçsüzlüğü saptanıyor. Kas biyopsisinde tip 2B liflerinde belirgin atrofi, tip 1 liflerde ise görece korunma dikkat çekiyor. Bu bulguda rol oynayan temel mekanizma aşağıdakilerden hangisidir?","options":["Mitokondriyal oksidatif fosforilasyon kapasitesinin azalması","Troponin I izoform değişikliğine bağlı kalsiyum duyarlılığının bozulması","Hızlı glikolotik liflerin denervasyon atrofisine daha yatkın olması","Satellit hücre aktivasyonunun tip 1 liflerde baskın olması","Miyozin ağır zincir izoformlarının tip 1 lif yönünde yeniden programlanması"],"correct":2,"exp":"Tip 2B lifleri (hızlı glikolotik, miyozin ağır zincir IIx/IIb), tip 1 liflerine kıyasla nörotrofik desteğe çok daha bağımlıdır. Yaşlanmayla birlikte motor ünite yitimi ve inkomplet reinnervasyona bağlı denervasyon atrofisi öncelikle bu lifleri etkiler. Tip 1 lifler ise oksidatif kapasiteleri ve daha zengin kapillarizasyonu sayesinde görece korunur. Mitokondriyal kapasitedeki azalma genel bir bulgu olmakla birlikte, selektif tip 2B atrofisinin mekanizmasını açıklamaz. Satellit hücre aktivasyonu yenilenmeyle ilgilidir, primer atrofi mekanizması değildir."},{"id":5982,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"Egzersizin ilk dakikalarında kramp ve miyoglobinüri gelişen hastada iskemik ön kol testinde laktat artmıyor. Kronik hemoliz vardır ve kısa dinlenme sonrası egzersiz toleransında belirgin düzelme olmaz. En olası tanı aşağıdakilerden hangisidir?","options":["McArdle hastalığı","CPT II eksikliği","Pompe hastalığı","Tarui hastalığı","Malign hipertermi"],"correct":3,"exp":"Kas fosfofruktokinaz eksikliği Tarui hastalığıdır. Eritrosit glikolizi de etkilendiği için hemoliz görülür; McArdle'daki tipik ikinci rüzgâr fenomeni beklenmez."},{"id":5983,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"Bir iskelet kası lifi istirahat halindeyken sarkoplazmik retikulumdan sitozole kalsiyum salınımı başladığında kasılmanın tetiklenmesi için kalsiyumun öncelikle hangi moleküle bağlanması gerekir?","options":["Troponin C alt birimine","Aktin filamentine","Miyozin ağır zincirine","Tropomiyozin molekülüne","Titin proteinine"],"correct":0,"exp":"İstirahat halinde tropomiyozin aktin üzerindeki miyozin bağlanma bölgelerini kapatmaktadır. Aksiyon potansiyeliyle başlayan depolarizasyon T-tübülleri aracılığıyla sarkoplazmik retikuluma iletilir ve ryanodin reseptörleri (RYR1) üzerinden kalsiyum sitozole salınır. Sitozoldeki kalsiyum troponin kompleksinin kalsiyum bağlayıcı alt birimi olan troponin C'ye bağlanır. Bu bağlanma troponin I'ın aktin üzerindeki inhibitör etkisini kaldırır, troponin T aracılığıyla tropomiyozin kayar ve miyozin bağlanma bölgeleri açılır. Aktin miyozinin bağlama bölgesi değil, kalsiyumun bağlandığı ilk hedef de değildir; troponin C bu süreçteki birincil alıcıdır."},{"id":5984,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"İnsan iskelet kasındaki hızlı glikolitik tip IIx lifler için aşağıdaki özelliklerden hangisi beklenir?","options":["Yüksek miyoglobin ve yoğun kapiller ağ","Düşük mitokondri yoğunluğu ve hızlı yorulma","Yavaş miyozin ATPaz aktivitesi","Başlıca yağ asidi oksidasyonuna bağımlılık","Uzun süreli postüral aktivitede baskın kullanım"],"correct":1,"exp":"Tip IIx lifler hızlı kasılır, glikolitik kapasitesi yüksektir; mitokondri, miyoglobin ve kapiller yoğunluğu düşüktür ve hızlı yorulur. İnsan kasında 'tip IIb' yerine tip IIx terminolojisi daha uygundur."},{"id":5985,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, düzensiz adet görmesi ve son 6 aydır devam eden infertilite şikayetiyle başvuruyor. Yapılan biyopside endometrial bezlerin proliferasyon fazına uygun görünüm sergilediği, ancak stromal hücrelerin predesidualizasyon değişikliklerini göstermediği saptanıyor. Bu tabloda en olası bozukluk hangi yapıyı doğrudan etkileyen bir yetersizlikten kaynaklanmaktadır?","options":["Granüloza hücrelerinden sentezlenen östrojen yetersizliği","Teka hücrelerinden kaynaklanan androjen fazlalığı","Hipofiz ön lobundan salgılanan FSH fazlalığı","Endometrial reseptörlerdeki östrojen duyarsızlığı","Korpus luteumdan salgılanan progesteron yetersizliği"],"correct":4,"exp":"Predesidualizasyon, endometrial stromal hücrelerin luteal fazda progesteron etkisiyle desidual hücrelere dönüşümünü ifade eder. Korpus luteum yetersizliğinde progesteron düzeyi düşük kalır; bu durumda bezler proliferasyona devam ederken stroma desidual dönüşümü gerçekleştiremez. Östrojen eksikliğinde zaten proliferasyon fazı gerçekleşemeyeceğinden bu seçenek uygun değildir. FSH fazlalığı foliküler gelişimi artırır ancak luteal faz yetersizliğini açıklamaz. Androjen fazlalığı anovülasyona yol açabilirse de tablodaki spesifik histolojik bulgunun mekanizması korpus luteum kaynaklı progesteron eksikliğidir."},{"id":5986,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"45 yaşında erkek hasta, bilateral testis atrofisi ve jinekomasti ile başvuruyor. Laboratuvarda FSH ve LH yüksek, testosteron düşük saptanıyor. Testis biyopsisinde seminifer tübüllerde hiyalinizasyon ve Leydig hücre hiperplazisi göze çarpıyor. Bu histolojik tabloda Leydig hücre hiperplazisinin ortaya çıkmasından sorumlu temel mekanizma aşağıdakilerden hangisidir?","options":["Yüksek FSH düzeyinin Leydig hücrelerini direkt uyarması","Düşük inhibin B düzeyine bağlı negatif geri bildirimin bozulması","Testosteron eksikliğinin Sertoli hücreleri üzerinden Leydig hücrelerini aktive etmesi","Yüksek LH düzeyinin Leydig hücrelerini sürekli uyarması","Seminifer tübül hasarına bağlı lokal androjen ortamının değişmesi"],"correct":3,"exp":"Leydig hücreleri, LH reseptörü taşır ve LH uyarısıyla testosteron sentezler. Primer testis hasarında testosteron düzeyinin düşmesiyle hipofizden LH salgısı negatif geri bildirim kaybı nedeniyle artar. Bu kronik yüksek LH uyarısı, fonksiyonel testosteron üretimi yapamasalar da Leydig hücrelerinin hiperplazisine yol açar. FSH ise primer olarak Sertoli hücrelerini hedef alır, Leydig hücrelerini direkt uyarmaz. İnhibin B Sertoli hücre kökenlidir ve FSH eksenini etkiler."},{"id":5987,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Menstrüel siklusun luteal fazında endometrium biyopsisinde izlenen 'testere dişi' görünümlü bezler ve spiral arterlerin gelişimi hangi hormonun etkisiyle gerçekleşir?","options":["Östradiol","LH","Prolaktin","Progesteron","FSH"],"correct":3,"exp":"Luteal fazda korpus luteumdan salgılanan progesteron, endometriumda sekretuar dönüşümü başlatır. Bu dönüşüm; bezlerde glikojen birikimine bağlı 'testere dişi' veya 'kıvrımlı' görünüm, stromal ödem ve spiral arterlerin gelişimi ile karakterizedir. Östradiol proliferasyon fazından sorumludur ve bez sayısını artırır ancak sekretuar değişiklikleri progesteron yönlendirir. Prolaktin laktasyonla ilgilidir, LH ovülasyonu tetikler, FSH foliküler gelişimi sağlar; ancak söz konusu histolojik tablonun temel düzenleyicisi progesterondur."},{"id":5988,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Oligomenore ve obezitesi olan 32 yaşındaki hastada kronik anovülasyon saptanıyor. Endometriyum biyopsisinde düzensiz proliferatif bezler var, sekretuar dönüşüm yoktur. Hiperplazi riskini artıran temel mekanizma aşağıdakilerden hangisidir?","options":["Düşük östrojenle bez atrofisi","Luteal fazda aşırı progesteron","FSH'nin endometriyumu doğrudan uyarması","Prolaktinin spiral arterleri yıkması","Progesteronla karşılanmamış sürekli östrojen etkisi"],"correct":4,"exp":"Anovülasyonda korpus luteum ve siklik progesteron etkisi oluşmaz. Sürekli östrojen uyarısı sekretuar dönüşüm olmadan proliferasyona, düzensiz kanamaya ve hiperplazi riskine yol açar."},{"id":5989,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"47 yaşında erkek hasta, 2 yıldır giderek kötüleşen erektil disfonksiyon ve libido azalması şikayetiyle başvurmaktadır. Testis biyopsisinde seminifer tübül bazal membranında kalınlaşma, Sertoli hücre sayısında azalma ve Leydig hücrelerinde vakuolizasyon saptanmıştır. Hormon panelinde total testosteron düşük, LH ve FSH belirgin şekilde yüksek bulunmuştur. Bu tabloda Sertoli hücresi disfonksiyonunun sperm üretimine etkisi en çok hangi mekanizma üzerinden gerçekleşir?","options":["Sertoli hücrelerinden salgılanan inhibin B azalması sonucu FSH artışı ile negatif geri bildirimin bozulması","Sertoli hücrelerinin androgen binding protein üretimini artırması sonucu luminal testosteron konsantrasyonunun toksik düzeye ulaşması","Kan-testis bariyerinin bütünlüğünün bozulması ve luminal sıvı kompozisyonunun değişmesi ile spermatositlerin besin ve parakrin desteğinden yoksun kalması","Sertoli hücrelerinin Leydig hücrelerine doğrudan inhibitör parakrin sinyal göndermesiyle testosteron sentezinin azaltılması","Bazal membran kalınlaşmasına yanıt olarak Sertoli hücrelerinin apoptoza girmesi ve spermatogonyum proliferasyonunun durması"],"correct":2,"exp":"Sertoli hücreleri seminifer tübülde 'hemşire hücre' işlevi görür ve spermatogenez için kritik birçok görevi üstlenir: kan-testis bariyerini oluşturur, spermatositleri fiziksel olarak destekler, gerekli büyüme faktörlerini ve besleyici molekülleri salgılar. Kan-testis bariyerinin bozulması spermatositlerin immün ayrıcalıklı ortamdan çıkmasına, otoimmün yanıt gelişmesine ve luminal sıvı osmolaritesi ile protein içeriğinin değişmesine yol açar. Bu durum spermatositlerin maturasyon sürecini tamamlayamamasına neden olur. İnhibin B azalması FSH yüksekliğini açıklayabilir ancak bu nedenin değil sonucun göstergesidir."},{"id":5990,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"Yirmi sekiz günlük düzenli siklusta endometriyumun implantasyona en alıcı olduğu pencere yaklaşık hangi döneme karşılık gelir?","options":["Menstrüasyonun ilk iki günü","Erken proliferatif faz","Ovülasyon günü","Geç sekretuar fazın son günü","Orta sekretuar faz, yaklaşık 20-24. günler"],"correct":4,"exp":"İmplantasyon penceresi ovülasyondan yaklaşık 6-10 gün sonra, orta sekretuar fazdadır. Progesteron etkisiyle bez sekresyonu, stromal değişiklikler ve adezyon molekülleri alıcılığı artırır."},{"id":5991,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"32 yaşında kadın hasta, son 6 aydır düzensiz menstruasyon ve sık alevlenen pelvik ağrı şikayetiyle başvuruyor. Yapılan laparoskopide uterin tüp mukozasında bol miktarda kinosilyalı hücre kaybı ve sekretuar hücre hipertrofisi saptanıyor. Bu tabloda hangi hormonun etkisinin baskın olduğu düşünülmelidir?","options":["Progesteron","LH","FSH","Östrojen","Prolaktin"],"correct":3,"exp":"Uterin tüp mukozasındaki kinosilyalı hücreler östrojen etkisiyle gelişir ve sayısı artar; progesteron ise sekretuar hücreleri uyarır. Kinosilyalı hücre kaybı ile birlikte sekretuar hücre hipertrofisinin birarada görülmesi, östrojen eksikliği zemininde progesteron etkisinin baskın hale geçtiğini düşündürür. Bu denge bozukluğu tuba uterinanın normal peristaltik ve silier taşıma işlevini bozarak pelvik tabloya yol açabilir."},{"id":5992,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"Sertoli hücrelerine özgü androjen reseptörü işlev kaybı bulunan deneysel modelde intratestiküler testosteron yüksek olmasına karşın spermiyasyon bozuluyor. Bu bulgu en iyi hangi sonucu destekler?","options":["Sertoli hücresindeki androjen sinyalinin spermatid olgunlaşması ve salınımı için gerekli olması","FSH'nin yalnızca Leydig hücrelerini uyararak testosteron üretimini artırması","Androjen bağlayıcı proteinin spermatidler üzerinde toksik etki göstermesi","Kan-testis bariyerinin Leydig hücreleri arasındaki bağlantılarla kurulması","Spermatogenezin testosteron etkisinden bağımsız biçimde sürdürülmesi"],"correct":0,"exp":"Testosteronun spermatogenez üzerindeki temel etkileri Sertoli hücresi androjen reseptörü aracılığıyla iletilir. ABP lümende yüksek androjen düzeyini destekler ancak tek başına spermiyasyonun özgül moleküler düğmesi değildir."},{"id":5993,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":3,"q":"45 yaşında kadın hasta, son 3 aydır menstruasyonunun normalden çok daha uzun sürdüğünü ve kanamanın azalmak yerine artarak devam ettiğini belirtiyor. Endometrial biyopside bez epitelinin düzensiz proliferasyon gösterdiği, stromal hücrelerde ise desidual dönüşümün hiç gerçekleşmediği izleniyor. Bu bulgular birlikte değerlendirildiğinde hangi fizyolojik sürecin aksaması bu tabloyu açıklar?","options":["Folliküler fazda LH pikinin erken ortaya çıkması","Ovulasyonun gerçekleşmemesi nedeniyle korpus luteum oluşmaması","Östrojen reseptörlerinin endometriyumda aşırı ekspresyonu","Prolaktin düzeyinin yükselmesiyle FSH baskılanması","Endometriyumdaki PGF2a sentezinin artması"],"correct":1,"exp":"Desidual dönüşüm, endometrial stromal hücrelerin progesteron etkisiyle farklılaşmasını ifade eder ve yalnızca ovulasyon sonrası oluşan korpus luteumdan salgılanan progesteron aracılığıyla gerçekleşir. Ovulasyon olmaması durumunda korpus luteum oluşmaz, progesteron yetersiz kalır ve endometriyum sürekli östrojen uyarısı altında düzensiz prolifere olmaya devam eder. Stromal desidual dönüşümün yokluğu ve uzamış düzensiz kanama bu anovulatuar tablonun klasik histofizyolojik yansımasıdır."},{"id":5994,"ders":"Fizyoloji","konu":"Genital Sistem HistoFizyolojisi","diff":4,"q":"35 yaşında kadın hasta, son 6 aydır düzensiz menstrüasyon ve orta hat pelvik ağrı şikayetiyle başvuruyor. Yapılan laparoskopide endometrial bezlerin ve stromal dokunun over yüzeyinde implante olduğu görülüyor. Bu lezyonlardaki ektopik endometrial dokunun siklik kanamasının temel nedeni hangi mekanizmaya bağlıdır?","options":["Overlerde aromataz enzim aktivitesinin artmasıyla lokal östrojen sentezinin yükselmesi ve bu dokunun östrojene bağımlı proliferasyon-sekresyon döngüsünü sürdürmesi","Hipofiz kaynaklı FSH düzeyinin normalden yüksek seyretmesi ve ektopik dokunun FSH reseptörü aracılığıyla progesteron sentezini artırması","Ektopik dokunun over stromasından bağımsız olarak kendi prolaktin reseptörlerini eksprese etmesi ve bu yolla glandüler aktivite kazanması","Peritoneal kavitedeki makrofajların PGE2 salgılayarak ektopik endometrial stroma hücrelerini östrojenden bağımsız biçimde uyarması","Uterin kavitedeki normal endometriumdan lökotrienler aracılığıyla gelen parakrin sinyallerin portal dolaşım dışı yollarla ektopik odaklara ulaşması"],"correct":0,"exp":"Endometrioziste ektopik endometrial implantlar, over stromasındaki granüloza ve teka benzeri hücrelerden salgılanan östrojene yanıt vermenin yanı sıra kendi aromataz aktiviteleri sayesinde androjenlerden lokal östrojen üretebilir. Bu durum 'lokal östrojen amplifikasyonu' olarak adlandırılır: ektopik doku hem sistemik östrojene hem de kendi ürettiği östrojene bağımlı olarak proliferasyon ve sekresyon evrelerini tamamlar, ardından progesteron geri çekilmesiyle siklik kanama gerçekleşir. Normal eutopik endometriumda aromataz aktivitesi son derece düşükken endometriozis odaklarında belirgin biçimde artar; bu nedenle aromataz inhibitörleri tedavide hedef alınan mekanizmalardan biridir."},{"id":5995,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Yirmi dört yaşında kadın hasta, evlendikten sonra gebelik planlamak amacıyla jinekologa başvuruyor. Son adet tarihine göre ovulasyonun gerçekleştiği gün belirleniyor ve o gün ilişkiye giriliyor. Fertilizasyon gerçekleştiğinde oluşan zigot, uterusa ulaşana kadar hangi gelişim basamağından geçer ve bu süreçte zona pellusidanın varlığı hangi açıdan kritik önem taşır?","options":["Zigotun bölünerek morula ve blastosist evrelerine ulaşması; zona pellusidanın bu süreçte erken implantasyonu ve tuba tutulumunu engellemesi","Zigotun morula evresini atlayarak doğrudan blastosist oluşturması ve zonanın trofoblast invazyonunu engellemesi","Zigotun morula evresine geçmesi ve zona pellusidanın implantasyonu kolaylaştırması","Zigotun yalnızca morula evresinde kalması ve zonanın trofoblast farklılaşmasını başlatması","Zona pellusida kaybolmadan blastosiste ulaşılamaması ve iç hücre kitlesinin oluşamaması"],"correct":0,"exp":"Fertilizasyonun ardından zigot, tuba uterinadayken mitotik bölünmelerle 2, 4, 8 hücreli evreleri geçer ve hücreler kompaksiyon ile morulayı oluşturur. Morula uterusa girerken içine sıvı dolarak blastosist oluşur. Zona pellusida bu süreçte son derece kritiktir: blastomerleri bir arada tutarak erken implantasyonu önler ve zigotun tuba uterinanın epitelyumuna yapışmasını engelleyerek ektopik gebeliği önler. Uterusa ulaşan blastosist, zona pellusidayı kaybederek trofoblast aracılığıyla implante olabilir hale gelir."},{"id":5996,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Yenidoğanın göbek kordonunda bir ven ve yalnız bir arter saptanıyor. Bu bulgunun en olası gelişimsel açıklaması aşağıdakilerden hangisidir?","options":["Umblikal venlerin ikisinin de persiste etmesi","Allantoisin iki kez kanalize olması","Vitellin arterlerin büyük bölümünın kaybolması","Umblikal arterlerden birinin agenezisi veya erken atrofisi","Duktus venozusun erken kapanması"],"correct":3,"exp":"Normal kordon iki umblikal arter ve bir umblikal ven içerir. Tek umblikal arter bir arterin agenezisi ya da atrofisiyle oluşabilir ve özellikle renal/kardiyak anomaliler ile anöploidi açısından ayrıntılı değerlendirme gerektirir."},{"id":5997,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Gastrulasyonda primitif noddan kraniyale göç eden hücrelerin oluşturduğu notokordun erişkindeki başlıca kalıntısı aşağıdakilerden hangisidir?","options":["Nucleus pulposus","Annulus fibrosus","Vertebra korpusu","Dura mater","Ligamentum flavum"],"correct":0,"exp":"Notokord nöral plak ve aksiyel iskelet gelişimini indükler; erişkinde nucleus pulposus içinde kalıntıları bulunur. Chordoma notokord kalıntılarından, sakrokoksigeal teratom ise primitif çizgi kalıntılarından gelişebilir."},{"id":5998,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Primer amenoreli 18 yaşındaki hastada 46, XX karyotip, normal meme gelişimi ve normal overler vardır. Vajina kısa ve kör sonlanmakta, uterus yok veya rudimenterdir. En olası gelişim kusuru aşağıdakilerden hangisidir?","options":["Gonadal çizginin gelişmemesi","Androjen reseptör işlev kaybı","Paramezonefrik kanal gelişim kusuru","5-alfa-redüktaz eksikliği","Persistan Müller kanal sendromu"],"correct":2,"exp":"MRKH sendromu paramezonefrik kanal gelişim kusuruna bağlı uterovajinal agenezidir. Overler farklı embriyolojik kökenden geldiği için işlevleri ve ikincil cinsiyet özellikleri normaldir; tüp ve uterus anomalilerinin derecesi değişebilir."},{"id":5999,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Otopsi bulgularına göre: 38 haftalık erkek yenidoğanda sol akciğer hipoplazik, bağırsak ansları sol hemitoraksta izleniyor ve mediyasten sağa kaymış. Kalp sağ tarafta yer alıyor fakat kardiyak yapılar normaldir. Bu tabloyu ortaya çıkaran embriyolojik süreçte hangi mekanizma belirleyici rol oynamıştır?","options":["Plevroperikardiyal membranın kapanmaması sonucu kalbin toraksa herniye olması","Sol akciğer tomurcuğunun primordiyumunun yokluğuna bağlı primer pulmoner agenezi","Plevroperitoneal kanalın kapanmamasına bağlı diyafram defekti ve sekonder akciğer gelişim baskılanması","Trakeoözofageal fistül yoluyla mide içeriğinin toraksa geçmesi ve baskı oluşturması","Situs inversus totalis zemininde gelişen ve izole kardiyak transpozisyon ile birlikte olan bir tablodur"],"correct":2,"exp":"Konjenital diyafragma hernisi, plevroperitoneal kanalın gestasyonun 8-10. haftalarında kapanmamasından kaynaklanır. Kanal kapanmazsa batın organları toraksa girer ve bu dönemde hızlı büyümekte olan akciğer üzerinde baskı oluşturarak ipsilateral hipoplaziye yol açar. Sol taraf çok daha sık tutulur çünkü sol plevroperitoneal kanal daha geç kapanır. Mediyasten sağa kayar ve kalp sağda görünür; bu durum gerçek dekstrokardi değil, baskıya bağlı yer değişimidir."},{"id":6000,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Nöral tüp kapanması servikal bölgede başlayıp kraniyal ve kaudal yönlere ilerler. Kaudal nöroporun kapanmaması en çok hangi malformasyon spektrumuna yol açar?","options":["Anensefali","Dandy-Walker malformasyonu","Holoprozensefali","Spina bifida ve miyelomeningosel","Agenesis corporis callosi"],"correct":3,"exp":"Kaudal nöropor yaklaşık 27. günde kapanır; kapanmaması lumbosakral nöral tüp defektlerine yol açar. Kranial nöropor kusuru anensefaliyle ilişkilidir."},{"id":6001,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"İmplantasyonun erken döneminde maternal endometriyal bez salgılarının embriyoya aktarılmasında başlıca rol oynayan trofoblast tabakası hangisidir?","options":["Sitotrofoblast","Amniyoblast","Ekstraembriyonik mezoderm","Hipoblast","Sinsityotrofoblast"],"correct":4,"exp":"Sinsityotrofoblast endometriyuma invaze olur, maternal bez ve kapillerlerle temas ederek erken histiyotrofik beslenmeyi sağlar. Sitotrofoblast proliferatif iç tabakadır."},{"id":6002,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"Otuz iki yaşında bir erkek hasta, kısırlık nedeniyle üroloji polikliniğine başvuruyor. Yapılan tetkiklerde testislerin skrotumda palpe edilemediği ve inguinal kanalda bilateral kriptorşidizm saptanıyor. Testislerin skrotuma inişini sağlayan süreçte hangi yapı doğrudan mekanik kılavuz görevi üstlenir?","options":["Kremasterik kas lifleri","Processus vaginalis","Gubernakulum testis","Wolff kanalı distal segmenti","Mezonefrik tübüller"],"correct":2,"exp":"Gubernakulum testis, alt kutuptan skrotuma uzanan mezenkim kökenli bir ligament benzeri yapıdır ve testis inişinde doğrudan mekanik kılavuz görevi görür. Androjenlerin etkisiyle gubernakulum kısalarak testisi inguinal kanaldan skrotuma çeker. Processus vaginalis ise peritonun skrotuma uzanan bir çıkıntısıdır ve testisin inmesi için tünel oluşturur ancak kendisi kılavuz değil tünel yapısıdır. Kremasterik kaslar testisi ısı düzenlemesi amacıyla hareket ettirir fakat embriyonik inişi sağlamaz. Wolff kanalı epididim ve vas deferensin öncülüdür, mekanik bir kılavuz işlevi yoktur. Mezonefrik tübüller efferent duktullara dönüşür, testis inişinde rolü bulunmaz."},{"id":6003,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":3,"q":"Embriyoloji pratiğinde nörülasyon sürecini anlatan bir kaynakta, nöral krest hücrelerinin 'dördüncü germ tabakası' olarak nitelendirildiği belirtiliyor. Bu hücrelerin en belirgin özelliği olan epitelyomezenkimal dönüşüm hangi aşamada gerçekleşir?","options":["Nöral tüpün kapanması sırasında dorsal bölgeden göç başladığında","Primitif çizginin oluşumundan hemen önce epiblastta","Notokordun indüksiyon sinyali vermesinin ardından lateral plak mezoderminde","Amniyonun embriyoyu çevrelemeye başladığı dönemde","Trofoblastın sitotrofoblast ve sinsityotrofoblast tabakalarına ayrıştığı sırada"],"correct":0,"exp":"Nöral krest hücreleri, nöral tüpün kapanması sırasında nöral kıvrımların dorsal birleşim noktasından ayrılarak epitelyomezenkimal dönüşüm geçirir. Bu dönüşümde hücreler apikal sıkı bağlantılarını kaybeder, N-kadherin ekspresyonunu azaltır ve mezenkimal hareketlilik kazanarak çeşitli dokulara göç eder. Primitif çizgi oluşumu gastrülasyon sürecinde mezodermi ve endodermi oluşturur, nöral krest göçüyle doğrudan ilgisi yoktur. Notokord lateral plak mezodermini değil, yüzey ektodermi üzerindeki nöral plağı indükler. Amniyon oluşumu dışa hücre göçünü değil embriyoyu saran kaviteyi ifade eder. Trofoblast farklılaşması implantasyonla ilgili bir süreçtir ve nöral krestle bağlantısı yoktur."},{"id":6004,"ders":"Fizyoloji","konu":"Genel Embriyoloji","diff":4,"q":"İmplantasyonun ilk haftalarında uteroplasental dolaşım tam olarak kurulmadan önce embriyonun başlıca besin kaynağı aşağıdakilerden hangisidir?","options":["Umbilikal ven kanı","Vitellus kesesindeki eritrositler","Uterin bezlerin glikojen ve glikoproteinden zengin salgıları","Amniyon sıvısındaki proteinler","Fetal karaciğer glikojeni"],"correct":2,"exp":"Erken implantasyon döneminde uterin bez salgıları sinsityotrofoblast aracılığıyla alınır; bu dönem histiyotrofik beslenme olarak adlandırılır. Maternal kanla belirgin hemotrofik beslenme daha sonra gelişir."},{"id":6005,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta; yorgunluk, gece terlemesi, kilo kaybı ve splenomegaliyle başvuruyor. Lökosit 85.000/mm³, trombosit 650.000/mm³ ve hemoglobin 9,2 g/dL bulunuyor. Kemik iliği biyopsisinde atipik megakaryosit kümeleri ile retikülin artışı izleniyor. Bu tabloda kemik iliği fibrozisini başlatan fibrojenik sitokinlerin başlıca kaynağı hangi hematopoetik seridir?","options":["Eritroid seri","Granülositik seri","Megakaryositik seri","Lenfoid seri","Monositik seri"],"correct":2,"exp":"Primer miyelofibroziste atipik megakaryositler TGF-β ve PDGF gibi fibrojenik mediyatörler salgılayarak kemik iliği stromal fibroblastlarını uyarır. Retikülin ve kollajeni doğrudan fibroblastlar üretir; megakaryositler ise bu birikimi tetikleyen başlıca neoplastik hücre grubudur. Bu nedenle doğru cevap megakaryositik seridir."},{"id":6006,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Enfeksiyöz mononükleozda Epstein–Barr virüsünün başlıca hedefi olan B lenfositlerin antijenle karşılaşmadan önce olgunlaştığı primer lenfoid organ aşağıdakilerden hangisidir?","options":["Timus korteksi","Lenf nodu parakortikal bölgesi","Kemik iliği (bursa eşdeğeri)","Dalak kırmızı pulpası","Timus medullası"],"correct":2,"exp":"İnsanda B lenfositlerin antijenden bağımsız gelişimi ve immünoglobulin gen yeniden düzenlenmesi kemik iliğinde gerçekleşir; bu alan kuşlardaki Fabricius bursasının işlevsel eşdeğeridir. Enfeksiyöz mononükleozda EBV, B lenfositleri enfekte eder; periferik yaymadaki atipik lenfositlerin çoğu ise bu hücrelere yanıt veren CD8+ T lenfositlerdir."},{"id":6007,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"Kemik iliği biyopsisinde sinüzoid duvarlarına yapışık, bol soluk sitoplazmalı, lobüle çekirdekli dev hücreler saptanıyor. Bu hücrelerin sitoplazmasından demarcation membran sistemi aracılığıyla kopan parçacıklar dolaşıma geçiyor. Bu süreci tanımlayan hangi kavram doğrudur?","options":["Eritropoez sırasında retikülosit olgunlaşması","Megakaryositten trombosit salınımı","Monositin makrofaja dönüşümü","Nötrofil granül ekzositozu","Pro-B hücresinin ön-B hücresine geçişi"],"correct":1,"exp":"Kemik iliğindeki megakaryositler, demarcation membran sistemi adı verilen iç membran ağının parçalanmasıyla sitoplazma uzantılarını proplatellet adı verilen uzun kollar biçiminde sinüzoid lümenine uzatır ve bu uzantılardan trombositler kopar. Trombositler çekirdeksizdir ve megakaryosit sitoplazmalarından türer. Bir megakaryosit 1000 ila 3000 trombosit üretebilir. EPO eritropoezi, M-CSF ise monositopoezi düzenler; bu süreçlerin hiçbiri demarcation membran sistemiyle ilişkili değildir."},{"id":6008,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, son 6 aydır giderek artan yorgunluk, gece terlemeleri ve sol hipokondriyumda dolgunluk hissi şikayetiyle başvuruyor. Fizik muayenede dalak kosta altı 8 cm palpe ediliyor. Periferik yaymada lökosit 85.000 ve tüm olgunluk evrelerinden granülositler görülüyor. Kemik iliği biyopsisinde retikülin artışı ve megakaryosit proliferasyonu saptanıyor. Bu hastada hastalığın temel patofizyolojik mekanizmasında hangi hücresel süreç ön planda yer alır?","options":["Pluripotent kök hücrede BCR-ABL füzyon geni kaynaklı kontrolsüz miyeloid proliferasyon","T lenfosit aracılı kemik iliği supresyonu sonucu klonal genişleme","JAK2 V617F mutasyonu ile eritroid öncül hücrelerin apopitozdan kaçışı","Eritropoietin reseptör duyarlılığında artış ile reaktif lökoertroblastik yanıt","B lenfosit klonal ekspansiyonu ile sekonder miyeloid metaplazi"],"correct":0,"exp":"Bu klinik tablo kronik miyeloid lösemi ile uyumludur. KML'de t(9;22) translokasyonu sonucu oluşan Philadelphia kromozomunun ürünü olan BCR-ABL füzyon proteini, tirozin kinaz aktivitesini sürekli açık konumda tutar. Bu durum pluripotent kök hücre düzeyinde apopitozun baskılanması ve kontrolsüz miyeloid proliferasyonu tetikler. Kemik iliğinde tüm olgunluk evrelerinden miyeloid hücre birikimi ve ekstramedüller hematopoez nedeniyle masif splenomegali gelişir. JAK2 mutasyonu ise miyeloproliferatif hastalıklar arasında polisitemia vera, esansiyel trombositemi ve miyelofibroziste sorumlu tutulur; KML'de rol oynamaz."},{"id":6009,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 3 haftadır ateş, boğaz ağrısı ve boyunda şişlik nedeniyle başvuruyor. Fizik muayenede posterior servikal lenfadenopati ve hafif splenomegali saptanıyor. Periferik yaymada lenfositoz ve atipik lenfositler dikkati çekiyor. Monospot testi pozitif bulunan hastanın kemik iliği biyopsisinde reaktif lenfoid hiperplazi görülüyor. Bu tablodaki atipik lenfositlerin kökeni ve temel işlevi hangi seçenekte doğru verilmiştir?","options":["Epstein-Barr virüsüne karşı aktive olan sitotoksik T lenfositleri olup enfekte B hücrelerini hedef alır","NK hücrelerinin viral antijene bağımlı olarak diferansiye olmuş efektör formlarıdır","EBV tarafından enfekte edilen T lenfositlerin poliklonal aktivasyonunu yansıtır","Kemik iliği kaynaklı plazma hücrelerinin periferik kana salınımından oluşur","Virüs antijeni sunan dendritik hücrelerin lenfoid dönüşümünü gösterir"],"correct":0,"exp":"Enfeksiyöz mononükleozda EBV öncelikle B lenfositlere yüzeyindeki CD21 reseptörü aracılığıyla bağlanır ve bu hücreleri enfekte eder. Periferik yaymada görülen atipik lenfositler ise enfekte B hücrelerini tanıyıp ortadan kaldırmaya çalışan aktive sitotoksik CD8 pozitif T lenfositleridir. Bu hücreler büyük, bol soluk sitoplazmalı ve lobüle çekirdekli görünümleriyle Downey hücresi olarak da adlandırılır. NK hücreleri bu tabloda destekleyici rol üstlenir ancak atipik lenfositlerin asıl kaynağı değildir. Monospot testindeki heterofil antikorlar ise enfekte B lenfositlerden kaynaklanır."},{"id":6010,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"Karaciğer sinüzoidlerinin madde ve hücre geçişini kolaylaştıran temel yapısal özelliği aşağıdakilerden hangisidir?","options":["Sürekli endotel ve kalın bazal membran","Çok katlı yassı epitel","Sıkı bağlantılarla kapalı endotel","Fenestralı endotel ve kesintili bazal lamina","Miyelinli endotel hücreleri"],"correct":3,"exp":"Karaciğer sinüzoidleri fenestralı, kesintili endotel ve belirgin olmayan bazal lamina içerir. Bu yapı plazma bileşenlerinin Disse aralığına geçişini kolaylaştırır."},{"id":6011,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, son 6 aydır giderek artan yorgunluk ve efor dispnesi şikayetiyle başvuruyor. Fizik muayenede splenomegali saptanıyor. Periferik yaymada teardrops eritrositler ve lökositlerin nükleuslarında sola kayma izleniyor. Kemik iliği biyopsisinde retikülin artışı ve fibroz ile birlikte megakaryosit kümelenmesi görülüyor. Bu hastada eritrositlerin teardrop şeklini almasından birincil olarak sorumlu olan yapısal ve fonksiyonel mekanizma hangisidir?","options":["Periferik kanda artmış osmotik strese bağlı membran lipid kaybi","Artmış eritropoetin düzeyine bağlı immatür eritrosit salınımı","Diseritropoeze bağlı olarak membran spektrin ekspresyonunun azalması","Fibrotik kemik iliğinden geçişte uygulanan mekanik distorsiyonun ardından dalak sinüzoidlerinde tam geri dönüşün sağlanamaması","Dalak içi sekestrasyon sırasında membran proteinlerinin proteolitik yıkımı"],"correct":3,"exp":"Primer miyelofibroziste fibrotik kemik iliğinden geçen eritrositler mekanik deformasyona uğrar. Normalde esnek olan eritrositler dalak sinüzoidlerinden geçerken bu şekli geri kazanabilir; ancak fibrotik ortamdan geçen hücreler viskoelastik özelliklerini yitirdiğinden teardrop (dakriyosit) morfolojisi kalıcı hale gelir. Bu süreçte dalağın sinüzoidal endotelinden geçişte tam şekil restorasyonunun sağlanamaması kilit mekanizmadır. Diğer seçenekler teardrop oluşumunun birincil mekanizmasını açıklamaz."},{"id":6012,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan derin ven trombozu ve iki kez gebelik kaybı öyküsüyle hematoloji polikliniğine başvuruyor. Akım sitometri incelemesinde CD55 ve CD59 yüzey proteinlerinde belirgin azalma saptanıyor. Gece sabahları koyu renkli idrar tariflediğini de ifade ediyor. Bu hastalığın patofizyolojisinde kemik iliği düzeyinde hangi moleküler mekanizmanın bozulması tromboza yatkınlığı doğrudan açıklar?","options":["Trombopoietin reseptör duyarsızlaşması sonucu immatür trombosit salınımı","Faktör V Leiden mutasyonuna bağlı aktive protein C direnci","GPI çıpasını kodlayan PIG-A genindeki somatik mutasyon nedeniyle trombosit yüzeyinde CD59 kaybı ve kompleman C5b-9 aracılı trombosit aktivasyonu","Megakaryosit apoptozisinin bozulmasına bağlı aşırı trombosit üretimi","Eritrosit hemolizine ikincil serbest hemoglobinin nitrik oksidi tüketmesi ve trombositoz gelişmesi"],"correct":2,"exp":"Paroksismal nokturnal hemoglobinüride PIG-A genindeki somatik mutasyon GPI biyosentezini bozar. GPI çıpalı proteinler arasında trombosit yüzeyindeki CD59 ve CD55 kritik öneme sahiptir. CD59 kaybı trombosit zarında membran atak kompleksi oluşumuna izin verir; kompleman aktivasyonu trombositleri direkt aktive ederek tromboz riskini artırır. Serbest hemoglobinin NO tüketimi de tromboza katkıda bulunsa da birincil ve doğrudan mekanizma GPI eksikliğine bağlı trombosit yüzeyindeki kompleman kontrolünün kaybolmasıdır."},{"id":6013,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"Kemik iliğinde hematopoietik kök hücrelerin niş içinde tutulmasında CXCL12 salgılayarak temel rol oynayan stromal hücre hangisidir?","options":["Megakaryosit","Plazma hücresi","Olgun nötrofil","Osteoklast","CXCL12-abundant reticular (CAR) hücresi"],"correct":4,"exp":"CAR hücreleri yüksek düzeyde CXCL12 ve kök hücre faktörü salgılar; CXCR4-CXCL12 ekseni hematopoietik kök hücrelerin kemik iliği nişinde tutulmasını destekler."},{"id":6014,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Hematopoietik kök hücre nakli sonrasında kök hücrelerin kemik iliğine yönelmesinde en önemli kemokin-reseptör çifti aşağıdakilerden hangisidir?","options":["CCL2-CCR2","CCL5-CCR5","IL-8-CXCR1","CXCL12-CXCR4","CX3CL1-CX3CR1"],"correct":3,"exp":"Kemik iliği stromasından salgılanan CXCL12, kök hücrelerdeki CXCR4'e bağlanarak homing ve retansiyonu sağlar."},{"id":6015,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, uzun süredir devam eden epigastrik ağrı ve kilo kaybı şikayetiyle başvuruyor. Endoskopide mide antrum mukozasında yaygın atrofi saptanıyor. Biyopside parietal hücre kaybı olmaksızın yalnızca müköz bez hücrelerinde azalma ve intestinal metaplazi izleniyor. Bu hastada intrensek faktör sekresyonunun korunmuş olması, hangi hücre tipinin işlevselliğini sürdürdüğünü gösterir?","options":["Parietal hücreler","Baş hücreleri","Müköz boyun hücreleri","G hücreleri","Enteroendokrin hücreler"],"correct":0,"exp":"İntrensek faktör, midede yalnızca parietal hücreler tarafından salgılanır. Parietal hücreler aynı zamanda HCl üretiminden de sorumludur ve gastrik gland korpus ile fundus bölgesinde yoğunlaşmıştır. Antrum ağırlıklı atrofide parietal hücre kaybı olmaksızın intrensek faktör korunabilir. Baş hücreleri pepsinojen, G hücreleri gastrin, müköz boyun hücreleri müsin salgılar; hiçbiri intrensek faktör üretmez. Bu ayrım B12 malabsorpsiyonu riskini değerlendirmede klinik olarak kritiktir."},{"id":6016,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, kronik ishal ve steatore yakınmasıyla gastroenteroloji polikliniğine başvuruyor. İnce barsak biyopsisinde villus yüksekliğinde belirgin azalma ve kript derinliğinde artış saptanıyor. Hastalığın hangi hücresel mekanizması, besin emilimindeki bozukluğu en doğrudan açıklar?","options":["Kript tabanındaki Lieberkühn bezi aktivitesinin artması","Goblet hücrelerinden müsin salınımının artması","Paneth hücrelerinden defensin sekresyonunun azalması","Villus yüzeyindeki absorptif enterosite özgü fırçamsı kenar enzimlerinin kaybı","Enteroendokrin hücrelerin GIP sekresyonunu azaltması"],"correct":3,"exp":"İnce barsak mukozasında villus atrofisi, fırçamsı kenardaki disakkaridaz ve peptidaz gibi absorptif enzimlerin kaybına yol açar. Bu durum hem emici yüzey alanını hem de lüminal sindirim kapasitesini azaltarak steatoreye neden olur. Goblet hücreleri müsin üretimiyle mukozal bariyer sağlar, absorpsiyon işlevini doğrudan etkilemez. Paneth hücreleri antimikrobiyal savunmaya katkı sağlar. Kript derinleşmesi, hücre rejenerasyonunu yansıtır ancak emilimi restore edemez. GIP insülin salınımını uyarır; primer emilim bozukluğunu açıklamaz."},{"id":6017,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"İnce bağırsak enterositlerinde glukoz ve galaktozun lümenden hücre içine alınmasını sağlayan taşıyıcı hangisidir?","options":["GLUT2","SGLT1","GLUT4","Na+/K+ ATPaz","CFTR"],"correct":1,"exp":"SGLT1, apikal membranda sodyum gradyanını kullanarak glukoz ve galaktozu hücre içine taşır. Na+/K+ ATPaz bazolateral sodyum gradyanını sürdürür; GLUT2 monosakkaritlerin kana çıkışını sağlar."},{"id":6018,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Sekretinin safra yollarındaki başlıca etkisi aşağıdakilerden hangisidir?","options":["Hepatositlerde kolesterol sentezini baskılamak","Safra asidi sentezini durdurmak","Oddi sfinkterini kasmak","Safra kesesini doğrudan boşaltmak","Kolanjiyositlerden bikarbonattan zengin sıvı sekresyonunu artırmak"],"correct":4,"exp":"Sekretin kolanjiyositlerde cAMP aracılığıyla bikarbonattan zengin sıvı sekresyonunu artırır. Safra kesesi kontraksiyonunda esas hormon kolesistokinindir."},{"id":6019,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, Helicobacter pylori eradikasyon tedavisi tamamlandıktan 6 ay sonra hâlâ epigastrik ağrı ve hazımsızlık yakınmalarını sürdürüyor. Endoskopide antrumda atrofi saptanıyor ve biyopside 'antrum mukozasında G hücre kaybı' raporlanıyor. Bu bulguda ortaya çıkması beklenen fizyolojik değişiklik aşağıdakilerden hangisidir?","options":["Sekretin düzeyinin artması","Gastrik asit sekresyonunun artması","Mide boşalmasının hızlanması","Gastrin salınımının azalması ile asit sekresyonunun azalması","Kolesistokinin salınımının artması"],"correct":3,"exp":"G hücreleri antrum ve duodenumda bulunan enteroendokrin hücrelerdir ve gastrin salgılarlar. Gastrin; parietal hücreleri uyararak HCl, ECL hücrelerini uyararak histamin salgılatır ve böylece asit sekresyonunu güçlü biçimde artırır. G hücre kaybı olan atrofik antrumda gastrin salınımı düşer, dolayısıyla parietal hücre uyarımı azalır ve bazal asit sekresyonu belirgin şekilde düşer. Sekretin duodenumdan, CCK ise ince bağırsaktan salgılanır; G hücre kaybıyla doğrudan ilişkili değildir."},{"id":6020,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"İnce bağırsak mukozasının hangi hücre tipi, lipid emiliminin ardından şilomikron oluşturarak lenf sistemine taşıma görevini üstlenir?","options":["M hücreleri","Goblet hücreleri","Enterositler","Paneth hücreleri","Enteroendokrin hücreler"],"correct":2,"exp":"Enterositler ince bağırsak villüslerini kaplayan emici epitel hücreleridir. Apikallerinde mikrovilli yapısı olan fırçamsı kenar bulundururlar. Diyetle alınan trigliseridler lümende pankreas lipazı ile yağ asidi ve monogliseride parçalanır, enterositler tarafından emilir ve hücre içinde yeniden trigliseride dönüştürülür. Apolipoprotein B-48 ile birleşerek şilomikron oluşturulur ve bazolateral taraftan ekzositozla serbest bırakılarak lakteallerle lenf sistemine katılır. M hücreleri antijen örnekleme, goblet hücreleri mukus salgısı, Paneth hücreleri antimikrobiyal peptit üretimiyle ilişkilidir."},{"id":6021,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Midenin korpus ve fundus bezlerinde birlikte bulunan iki temel hücre çifti aşağıdakilerden hangisidir?","options":["G hücresi ve mukus boyun hücresi","Enteroendokrin hücre ve goblet hücresi","D hücresi ve Paneth hücresi","Pariyetal hücre ve baş hücre","M hücresi ve foveolar hücre"],"correct":3,"exp":"Korpus ve fundus bezlerinde pariyetal hücreler hidroklorik asit ve intrinsik faktör; baş hücreler pepsinojen salgılar. G hücreleri esas olarak antrumda bulunur."},{"id":6022,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta kronik ishal ve kilo kaybı nedeniyle araştırılıyor. Yapılan ince bağırsak biyopsisinde villus yüksekliğinin belirgin azaldığı, kript derinliğinin arttığı ve intraepitelyal lenfosit sayısının yükseldiği görülüyor. Bu histolojik değişiklikler emilim yüzeyini nasıl etkiler ve hangi hücre topluluğunun işlev kaybı bu durumun merkezindedir?","options":["Villus atrofisi emilim yüzeyini azaltır ve brush border enzimleri taşıyan enterositler işlevsizleşir","Kript hiperplazisi sekresyonu artırır ve Paneth hücre granülleri tükenir","Goblet hücre kaybı mukus tabakasını inceltir ve pasif difüzyon bozulur","M hücreleri atrofiye uğrar ve antijen örnekleme kapasitesi düşer","Enteroendokrin hücreler kaybolur ve kolesistokinin salgısı durur"],"correct":0,"exp":"Villus atrofisi ile kript hiperplazisinin birlikteliği çölyak hastalığının klasik histolojik görünümüdür. Villus yüksekliğinin azalması toplam emilim yüzeyini dramatik biçimde düşürür çünkü villüs yüzeyi düz mukozaya kıyasla yaklaşık 30 kat daha büyük alan sağlar. Villusların apikal yüzeyini kaplayan enterositler hem taşıyıcı proteinleri hem de disakkaridaz ve peptidaz gibi brush border enzimlerini barındırır. Bu hücrelerin kaybı karbonhidrat, protein ve yağ emilimini eş zamanlı bozar. Kript derinliğinin artması olgunlaşmamış hücrelerin yüzeye çıktığına işaret eder ve fonksiyonel emilim kapasitesini daha da azaltır."},{"id":6023,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"Kolesistokinin salınımından sorumlu olan hücreler ince bağırsağın hangi tabakasında yerleşir ve bu hormonun salınımını tetikleyen başlıca uyaran hangisidir?","options":["Duodenum Brunner bezlerindeki enteroendokrin hücreler, asit yükü","Mide antrum mukozasındaki G hücreleri, lümendeki protein parçacıkları","İleum kriptlerindeki L hücreleri, lümendeki kısa zincirli yağ asitleri","Pankreas adacıklarındaki delta hücreleri, portal kan glukoz düzeyi","Duodenum ve jejunum mukozasındaki I hücreleri, lümendeki yağ asitleri ve amino asitler"],"correct":4,"exp":"Kolesistokinin duodenum ve proksimal jejunumun mukoza epitelinde dağılmış I hücreleri tarafından salgılanır. Bu hücreler lümende yağ asitleri ve amino asit varlığını algılayarak kolesistokinin salgılar. Kolesistokinin safra kesesini kasarak safra akışını sağlar, pankreatik enzim sekresyonunu uyarır ve mide boşalmasını yavaşlatır. G hücreleri gastrini, L hücreleri GLP-1 ve peptid YY'yi salgılar. Brunner bezleri enteroendokrin değil müköz salgı yapar ve duodenum yüzeyini aside karşı korur."},{"id":6024,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"İntrinsik faktör eksikliğine bağlı klasik pernisiyöz aneminin temel patogenezi aşağıdakilerden hangisidir?","options":["Helicobacter pylori'nin intrinsik faktörü doğrudan tüketmesi","Pariyetal hücrelere ve intrinsik faktöre karşı otoimmün yanıt","Terminal ileumda akut enfeksiyon","Pankreatik lipaz eksikliği","Jejunumda folat taşıyıcı defekti"],"correct":1,"exp":"Pernisiyöz anemi, otoimmün gastrit sonucu pariyetal hücre kaybı ve intrinsik faktör eksikliğiyle gelişir. H. pylori atrofik gastritle ilişkili olabilir ancak klasik pernisiyöz aneminin tanımlayıcı nedeni otoimmünitedir."},{"id":6025,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı şikayetiyle başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu yüzde 35 olarak ölçülüyor. Hastanın miyokard biyopsisinde interstisyel alanda artmış kollajen birikimi ve miyosit hipertrofisi saptanıyor. Bu tabloda fonksiyon bozukluğuna en çok katkıda bulunan hücresel mekanizma hangisidir?","options":["Perikardiyal mezotel hücrelerinin epitelyal geçişi","Miyositlerde sarkomerik titin proteininin aşırı ekspresyonu","Endotel hücrelerinde eNOS aktivitesinin artması","Kardiyak progenitör hücrelerin farklılaşma kapasitesinin artışı","Kardiyak fibroblastların miyofibroblasta dönüşümü ile TGF-beta aracılı matriks yeniden şekillenmesi"],"correct":4,"exp":"Kalp yetersizliğinde kardiyak fibroblastlar, TGF-beta başta olmak üzere profibrotiik sitokinlerin etkisiyle miyofibroblasta dönüşür. Bu dönüşüm, alfa-düz kas aktin ekspresyonu ve artmış kollajen tip I ile tip III sentezi ile karakterizedir. Oluşan fibrozis miyokardın kompliyansını azaltır, iletim homojenliğini bozar ve ventrikül duvar stresini artırarak sistolik disfonksiyona zemin hazırlar. Titin, diyastolik sertlikle ilişkilidir ancak burada tanımlanan tablo sistemik fibrozis ağırlıklıdır. eNOS artışı koruyucu bir mekanizmadır, patolojiyi açıklamaz."},{"id":6026,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, ani başlayan çarpıntı ve baş dönmesiyle acile getiriliyor. EKG'de PR intervalinin belirgin şekilde kısaldığı ve delta dalgasının izlendiği görülüyor. Aksesuar yolun histolojik temeli sorgulandığında hangi yapısal özellik bu tabloyu açıklar?","options":["Anulus fibrozusun tam oluşmaması sonucu atriyal miyokard kökenli kas hücrelerinin ventriküler miyokarda köprü oluşturması","Purkinje hücrelerinin his demeti boyunca anormal dallanma göstermesi","AV düğümde gap junction proteinlerinin aşırı ekspresyonu","Sinoatriyal düğümde otomasite gösteren hücre sayısının artması","Kardiyak iskelet dokusunun kollajen içeriğinin azalması"],"correct":0,"exp":"Wolff-Parkinson-White sendromunda aksesuar yol olan Kent demeti, embriyolojik süreçte anulus fibrozusun miyokardiyal sürekliliği tam olarak kesmemesi sonucu oluşur. Normalde anulus fibrozus, atriyal ve ventriküler miyokardı elektriksel olarak birbirinden ayıran izole edici fibröz doku işlevi görür. Bu ayrımın tamamlanamaması durumunda atriyal miyosit kökenli hücreler ventriküler miyokarda doğrudan bağlantı kurar. Bu aksesuar iletim, AV düğümü atlayarak ventriküllerin erken uyarılmasına yol açar ve delta dalgasını oluşturur."},{"id":6027,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"Kronik basınç yüküne maruz kalan kardiyomiyositlerde gelişen konsantrik hipertrofinin temel hücresel mekanizması hangisidir?","options":["Sarkomerlerin seri hâlinde eklenmesi","Sarkomerlerin paralel hâlde eklenmesi","Miyosit sayısının mitozla artması","Hücre içi glikojenin azalması","Apoptozun tamamen durması"],"correct":1,"exp":"Basınç yükünde sarkomerler paralel eklenir ve duvar kalınlığı artar. Hacim yükünde sarkomerlerin seri eklenmesi eksantrik hipertrofiye yol açar."},{"id":6028,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kronik sistemik hipertansiyonda sol ventrikül duvar kalınlığının artmasına yol açan sarkomer düzenlenmesi aşağıdakilerden hangisidir?","options":["Sarkomerlerin seri hâlde eklenmesi","İnterkale disklerin tamamen kaybolması","Kardiyomiyosit sayısının mitozla artması","Miyofibrillerin lizozomal yıkımla azalması","Sarkomerlerin paralel hâlde eklenmesi"],"correct":4,"exp":"Basınç yükünde kardiyomiyositler sarkomerleri paralel olarak ekler; hücre genişliği ve duvar kalınlığı artarak konsantrik hipertrofi gelişir. Hacim yükünde ise sarkomerlerin seri eklenmesi eksantrik hipertrofiye katkıda bulunur."},{"id":6029,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta ani başlayan çarpıntı şikayetiyle acile getiriliyor. EKG'de dar QRS taşikardi saptanıyor ve adenozin uygulanıyor. Adenozinin AV düğüm iletimini yavaşlatmasında hangi iyon kanalı mekanizması belirleyici rol oynar?","options":["L tipi kalsiyum kanallarının doğrudan blokajı ile aksiyon potansiyeli platosunun kısalması","G proteini aracılığıyla IKACh kanallarının açılması ve hücre içi cAMP azalması","Voltaj kapılı sodyum kanallarının inaktivasyonu ile faz sıfır depolarizasyon hızının düşmesi","Hücre dışı potasyum konsantrasyonunu artırarak istirahat membran potansiyelinin pozitifleşmesi","If akımının doğrudan inhibisyonu ile otomatisitenin sinoatriyal düğümde baskılanması"],"correct":1,"exp":"Adenozin A1 reseptörlerine bağlanarak Gi proteini üzerinden iki eş zamanlı etki gösterir. Birincisi, Gi'nin betagama alt birimi IKACh (asetilkoline duyarlı içe doğrulayıcı potasyum akımı) kanallarını doğrudan açar; artan potasyum iletkenliği hücreyi hiperpolarize ederek AV düğüm iletimini yavaşlatır. İkincisi, Gi alfa alt birimi adenilil siklazı inhibe ederek cAMP düzeyini düşürür; bu da PKA aracılı L tipi kalsiyum kanalı fosforilasyonunu azaltır. L tipi kalsiyum kanallarının doğrudan blokajı adenozin mekanizması değil, verapamilin etki biçimidir. Voltaj kapılı sodyum kanalları AV düğümde baskın kanal değildir; bu düğümün faz sıfır depolarizasyonu kalsiyum akımına bağlıdır. If akımı esas olarak sinoatrial düğüm otomatisitesiyle ilgilidir ve adenozinin birincil AV düğüm etkisini açıklamaz."},{"id":6030,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"Kapiller düzeyde madde alışverişi incelendiğinde, sürekli kapillerlerde vesikül aracılı taşımanın en yoğun olduğu hücre tipi hangisidir ve bu yapı hangi doku tipinde baskın olarak bulunur?","options":["Perisite ait pinositik veziküller, iskelet kası kapillerlerinde","Endotel hücrelerine ait kaveoller, kan beyin bariyerinde","Endotel hücrelerine ait kaveoller, iskelet kası ve akciğer kapillerlerinde","Mezangiyal hücrelere ait fagositik veziküller, renal glomerülde","Düz kas hücrelerine ait endositik cepler, büyük arterlerde"],"correct":2,"exp":"Sürekli kapillerlerde transkitoz, endotel hücrelerinin plazma membranından oluşan kaveoller (kaveolae) aracılığıyla gerçekleştirilir. Kaveoller kolesterol ve sfingolipidden zengin lipid sal mikrodomainleridir ve kaveolin proteini içerirler. Bu yapılar iskelet kası, kalp kası ve akciğer kapillerlerinde çok sayıda bulunur; buralarda sıvı ve makromoleküllerin transendotelyal geçişini sağlar. Kan beyin bariyerini oluşturan beyin kapillerlerinde ise kaveoller çok azdır ve transkitoz minimal düzeyde tutulur; sıkı bağlantılar (tight junction) paraselüler geçişi engeller ve seçici geçirgenliği sağlar. Perisite destek hücresi işlevi görür ancak birincil veziküler taşımayı gerçekleştirmez. Mezangiyal ve düz kas hücreleri kapiller taşımada bu rolü üstlenmez."},{"id":6031,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve çabuk yorulma şikayetiyle başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu yüzde 35 olarak ölçülüyor. Biyopsi örneğinde kardiomiyositlerin sarkoplazmik retikulumundaki ryanodine reseptör-2 işlevinin bozulduğu saptanıyor. Bu bulgunun miyokard kontraksiyonuna etkisi en çok hangi mekanizma üzerinden gerçekleşir?","options":["Aksiyon potansiyeli sırasında L-tipi kalsiyum kanallarından hücre içine kalsiyum girişinin azalması","Miyozin ağır zincir izoformunun beta formundan alfa formuna geçişinin bozulması","Troponin C üzerindeki kalsiyum bağlanma kapasitesinin kalıcı olarak düşmesi","Sistol sırasında sarkoplazmik retikulumdan sitozole kalsiyum salınımının yetersiz kalması","Titin proteininin miyofilament gerilme tepkisini iletememesi"],"correct":3,"exp":"Ryanodine reseptör-2 (RyR2), kardiyak eksitasyon-kontraksiyon eşleşmesinin merkezinde yer alır. L-tipi kalsiyum kanalları aracılığıyla hücreye giren küçük miktarda kalsiyum, RyR2 kanallarını tetikleyerek sarkoplazmik retikulumdan çok daha büyük miktarda kalsiyumun sitozole salınmasını sağlar; bu olaya kalsiyumun kalsiyumu uyarması denir. RyR2 işlev kaybı bu amplifikasyon adımını bozar ve sistolde sitozolün kalsiyum konsantrasyonu yeterince artmaz, dolayısıyla aktin-miyozin çapraz köprü oluşumu yetersiz kalır. L-tipi kanal işlevi birincil etkilenmez, troponin C kapasitesi değişmez, miyozin izoform geçişi kronik remodeling süreciyle ilgili ayrı bir mekanizmadır, titin ise diastolik gerilimi algılar."},{"id":6032,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında kadın hasta, ani başlayan çarpıntı ve senkop atağı nedeniyle acile getiriliyor. EKG'de ventriküler fibrilasyon saptanıyor ve defibrilasyon uygulanıyor. Genetik incelemede gap junction proteini proteini olan connexin-43 ekspresyonunun ciddi ölçüde azaldığı belirleniyor. Bu tablonun elektrofizyolojik zemini hangi yapısal değişiklikle en doğrudan ilişkilidir?","options":["Kardiomiyositlerde T-tübül yoğunluğunun artmasıyla aksiyon potansiyelinin süresinin uzaması","Interkalate disklerdeki gap junction bölgelerinin azalmasıyla impuls iletiminin yavaşlaması ve heterojen olması","Purkinje liflerinde otomatisitenin artarak ektopik odak oluşturması","Sinoatriyal düğüm hücrelerinde If akımının yükselmesiyle atım hızının artması","Von Willebrand faktörü salınımının bozulmasıyla endotel bütünlüğünün kaybolması"],"correct":1,"exp":"Connexin-43, kalpteki gap junction kanallarının temel yapı birimidir ve interkalate disklerin nexus bölgelerinde yoğun olarak bulunur. Bu kanallar, komşu kardiomiyositler arasında iyon ve küçük molekül geçişine izin vererek aksiyon potansiyelinin miyokard boyunca koordineli biçimde yayılmasını sağlar. Connexin-43 azaldığında hücreler arası elektriksel eşleşme zayıflar, impuls iletimi bölgeden bölgeye farklılık gösterir ve yeniden giriş aritmilerine zemin hazırlar; ventriküler fibrilasyon bu mekanizmanın klinik sonucudur. T-tübüller kalsiyum eşleşmesiyle, Purkinje otomatisitesi pace-maker akımlarıyla, If akımı sinoatriyal işlevle, von Willebrand faktörü ise koagülasyon fizyolojisiyle ilgilidir."},{"id":6033,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"42 yaşında erkek hasta rutin kardiyoloji kontrolünde, istirahat halinde normal görünen kan basıncının egzersiz sırasında beklenenin çok üzerinde yükseldiği saptanıyor. Arteriyel duvarın histolojik incelemesinde tunika mediada elastin liflerinin azaldığı ve kollajen oranının arttığı görülüyor. Bu yapısal değişiklik hipertansif yanıtı hangi mekanizmayla açıklar?","options":["Damar düz kas hücrelerinde kalsiyum duyarlılığının artmasıyla bazal vazokonstriksiyon oluşması","Tunika intimada endotel hücrelerinin azalmasıyla nitrik oksit üretiminin düşmesi","Arteriyel duvarın gerginlik tamponlama kapasitesinin azalmasıyla nabız dalgasının daha az sönümlenmesi","Tunika adventisyada vasa vasorumun daralmasıyla medial iskeminin tetiklenmesi","Trombosit adezyon moleküllerinin subendotelyal alana maruz kalmasıyla kronik inflamasyon başlaması"],"correct":2,"exp":"Büyük elastik arterlerin tunika mediasındaki elastin lifleri, sistolde biriken basınç enerjisini depolayarak diastolik akışı sürdürür; bu özellik windkessel işlevi olarak adlandırılır. Elastin azalıp kollajen arttığında damar duvarı sertleşir ve esnekliğini yitirir. Bu durumda sistolde basıncı tamponlayan mekanizma zayıfladığından nabız dalgası daha az sönümlenerek perifere ve proksimal yapılara olduğundan büyük bir basınç dalgası iletir; egzersizde kardiyak debi artınca bu fark belirginleşir. Düz kas kalsiyum duyarlılığı ayrı bir regülasyon mekanizmasıdır, endotel kaybı ve nitrik oksit azalması farklı bir patolojik süreçtir, vasa vasorum iskemisi ileri aterosklerozla ilişkilidir, trombosit aktivasyonu ise akut trombotik olaylarla bağlantılıdır."},{"id":6034,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, efor sırasında nefes darlığı ve alt ekstremitelerde ödem şikayetiyle başvuruyor. Fizik muayenede boyun venöz dolgunluğu ve hepatomegali saptanıyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu yüzde 35 olarak ölçülüyor. Bu hastada kardiyak kontraktilitenin azalmasına yol açan temel hücresel mekanizma incelendiğinde, miyokard hücrelerinde hangi yapısal ve fonksiyonel değişiklik ön plana çıkmaktadır?","options":["Sarkoplazmaik retikulumdan kalsiyum salınımının azalması ve SERCA2a aktivitesinin düşmesi sonucu sitozolik kalsiyum transientinin bozulması","Troponin I fosforilasyonunun artması ve aktin-miyozin çapraz köprü oluşumunun hızlanması","Mitokondriyal ATP üretiminin geçici olarak artması nedeniyle Na-K ATPaz pompasının aşırı aktivasyonu","T tübül sisteminin genişlemesi ve buna bağlı aksiyon potansiyeli süresinin kısalması","Miyozin ağır zincir izoformlarının beta formdan alfa forma geçişiyle kontraktil hızın artması"],"correct":0,"exp":"Kalp yetersizliğinde miyokard kontraktilitesinin azalmasının temel mekanizması, intrasellüler kalsiyum döngüsünün bozulmasıdır. Sarkoplazmaik retikulum üzerinde bulunan SERCA2a pompası, sistol sonrasında sitozoldeki serbest kalsiyumu aktif taşımayla geri alarak diyastolik gevşemeyi sağlar. Kronik kalp yetersizliğinde SERCA2a ekspresyonu ve aktivitesi belirgin şekilde azalır; buna ek olarak riyanodin reseptörü 2 fosforilasyonu bozularak diyastolik kalsiyum sızıntısı artar. Sonuçta her aksiyon potansiyeli ile salınan kalsiyum miktarı düşer, troponin C üzerindeki kalsiyum bağlanması yetersiz kalır ve aktin-miyozin etkileşimi zayıflar. Diğer seçenekler yanlıştır: kalp yetersizliğinde troponin I fosforilasyonu azalır, ATP üretimi bozulur, T tübüller deformasyona uğrar ancak bu birincil mekanizma değildir ve miyozin izoform değişimi alfa formdan daha yavaş olan beta forma kayış şeklindedir, tersi değil."},{"id":6035,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Overde östrojen sentezinin iki hücre-iki gonadotropin modeline göre doğru eşleştirilmesi hangisidir?","options":["LH granüloza hücresinde androjen sentezini, FSH teka hücresinde aromatazı uyarır","FSH teka hücresinde kolesterol taşınmasını durdurur","FSH yalnızca korpus luteumu uyarır","LH granüloza hücresinde progesteronu tamamen baskılar","LH teka hücresinde androjen sentezini, FSH granüloza hücresinde aromatazı uyarır"],"correct":4,"exp":"LH teka interna hücrelerinde androjen sentezini uyarır. Androjenler granüloza hücrelerine geçer ve FSH ile indüklenen aromataz aracılığıyla östrojene çevrilir."},{"id":6036,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Epididimisin principal hücrelerinin erkek üreme sistemindeki temel işlevi aşağıdakilerden hangisidir?","options":["Testosteron sentezlemek","Spermatozoonların olgunlaşmasını sağlayan lümen ortamını düzenlemek","Spermatogonyum mitozunu başlatmak","Kan-testis bariyerini oluşturmak","Seminal vezikül sıvısını üretmek"],"correct":1,"exp":"Epididimis principal hücreleri sıvı ve protein sekresyonu/absorpsiyonuyla sperm motilitesi ve fertilizasyon yeteneğinin kazanıldığı lümen ortamını düzenler. Kan-testis bariyerini Sertoli hücreleri oluşturur."},{"id":6037,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, son 8 aydır adet düzensizliği, sıcak basması ve gece terlemesi şikayetiyle başvuruyor. FSH düzeyi belirgin yüksek, östrojen düzeyi düşük saptanıyor. Bu hastada hipofiz gonadotrop hücrelerinin boyutunun artmasının temel nedeni hangi mekanizmadır?","options":["Östrojenin negatif geri bildirim etkisinin ortadan kalkmasıyla gonadotrop hücrelerde hipertrofi ve hiperplazi gelişmesi","GnRH reseptörlerinin downregülasyonu sonucu gonadotrop hücre kitlesinin artması","Prolaktin düzeyindeki artışın gonadotrop hücreleri uyarması","İnhibin B düzeyindeki artışın FSH sentezini kronik olarak stimüle etmesi","LH atım frekansının azalması nedeniyle kompansatuar gonadotrop hücre büyümesi"],"correct":0,"exp":"Over yetmezliğinde östrojen salgısı düştüğünde hipofiz üzerindeki negatif geri bildirim ortadan kalkar. Bu durumda gonadotrop hücreler sürekli GnRH uyarısına maruz kalır ve hipertrofi ile hiperplazi gelişir; bu hücreler histolojik olarak 'kastrasyona bağlı değişim' olarak adlandırılan vakuolizasyon gösterir. İnhibin B ise FSH üzerinde negatif geri bildirim yapar, dolayısıyla düzeyinin düşmesi FSH artışına katkıda bulunur ancak hücre büyümesinin primer mekanizması östrojen eksikliğidir. GnRH reseptör downregülasyonu ise tam tersi bir etki yaratır."},{"id":6038,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"İnhibin B düzeyinin belirgin düşük olması erkek infertilitesinde en çok hangi hücresel işlev bozukluğunu düşündürür?","options":["Leydig hücrelerinde testosteron sentezi","Seminal vezikülde fruktoz sentezi","Prostat bezinde sitrat sekresyonu","Epididimiste sıvı emilimi","Sertoli hücre fonksiyonu ve spermatogenez"],"correct":4,"exp":"İnhibin B başlıca Sertoli hücrelerinden salgılanır ve spermatogenetik aktiviteyi yansıtır. Düşüklüğü Sertoli hücre işlev bozukluğu veya germ hücre kaybıyla ilişkilidir; yalnızca Sertoli hücre sayısının azalması anlamına gelmez."},{"id":6039,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":3,"q":"Erkek bebeklerde yaşamın ilk aylarında LH, FSH ve testosteron düzeylerinin geçici olarak yükseldiği fizyolojik dönem aşağıdakilerden hangisidir?","options":["Adrenarş","Mini puberte","Telarş","Menarş","Gonadarş"],"correct":1,"exp":"Doğumdan sonra plasental steroid baskısının kalkmasıyla hipotalamo-hipofizer-gonadal eksen geçici olarak aktive olur. Bu fizyolojik dönem mini puberte olarak adlandırılır."},{"id":6040,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Yirmi sekiz yaşında kadın hasta, son 8 aydır düzensiz adet görmekte, hafif galaktore ve baş ağrısından yakınmaktadır. Serum prolaktin düzeyi belirgin yüksek bulunmuş, MRG görüntülemede hipofiz bezi büyümüş saptanmıştır. Bu hastada prolaktinin salgılanmasını kısıtlayan normal fizyolojik mekanizma işlevini yitirmiştir. Söz konusu baskılayıcı kontrolü sağlayan yapı hangisidir?","options":["Hipotalamustan salgılanan dopamin","Hipotalamustan salgılanan somatostatin","Ön hipofizden salgılanan FSH","Posterior hipofizden salınan oksitosin","Pineal bezden salgılanan melatonin"],"correct":0,"exp":"Prolaktin, ön hipofizin laktotrop hücrelerinden salgılanan ve hipotalamusun tonik inhibitör etkisi altında tutulan tek hipofiz hormonudur. Bu inhibisyon, hipotalamusun tuberoinfundibuler yolağından portal dolaşıma salgılanan dopamin aracılığıyla gerçekleşir. Dopamin, laktotrop hücrelerdeki D2 reseptörlerine bağlanarak prolaktin sentez ve sekresyonunu baskılar. Hipofiz sapının kesilmesi ya da tüm hipotalamik bağlantıların kesilmesi durumunda diğer hipofiz hormonlarının salgısı azalırken prolaktin paradoksal biçimde artar; bu durum dopaminin tonik baskılayıcı etkisinin en güçlü kanıtıdır. Somatostatin ise büyüme hormonu ve TSH üzerinde inhibitör etki gösterir, prolaktin üzerinde birincil baskılayıcı rolü yoktur."},{"id":6041,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Kırk iki yaşında erkek hasta, 2 yıldır devam eden libido azalması, yorgunluk ve kas kütlesinde azalma şikayetiyle başvurmuştur. Yapılan testlerde serum testosteron düşük, LH ve FSH ise beklenmedik biçimde düşük bulunmuştur. Bu hormonal tablonun oluşmasında sorumlu olan primer patolojik nokta hangisidir?","options":["Sertoli hücrelerinde androjen bağlayıcı protein eksikliği","Leydig hücrelerinde testosteron sentez enzim defekti","Hipotalamus ya da hipofiz düzeyinde yetersiz gonadotropin salgısı","Testiküler seminifer tübüllerde germinal epitel hasarı","Periferik dokularda 5-alfa redüktaz enzim yetersizliği"],"correct":2,"exp":"Normal fizyolojide düşük testosteron düzeyi, negatif geri besleme baskısının kalkmasıyla LH ve FSH artışına yol açar; bu tablo primer hipogonadizmi gösterir. Ancak bu hastada hem testosteron hem de gonadotropinler düşüktür. Bu durum, hipotalamik GnRH yetersizliği ya da hipofizer gonadotrop hücre disfonksiyonu kaynaklı sekonder hipogonadizmi işaret eder. Hipotalamus, GnRH'yi pulsatil biçimde salgılayarak ön hipofizi uyarır; bu pulsatilite kaybolduğunda LH ve FSH salgısı azalır, dolayısıyla testosteron sentezi için Leydig hücreleri yeterince uyarılamaz. Leydig hücre defekti ya da 5-alfa redüktaz eksikliğinde ise LH yüksek seyretmelidir; germinal epitel hasarında ise öncelikle FSH yükseler. Tüm gonadotropinlerin eş zamanlı düşüklüğü merkezi kaynaklı patolojiyi doğrular."},{"id":6042,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":3,"q":"Otuz beş yaşında kadın hasta, 6 aydır adet düzensizliği ve kilo artışı nedeniyle araştırılmaktadır. Tiroid bezi ultrasonografide normal, ancak serum TSH yüksek ve serbest T4 düşük saptanmıştır. Bu hastada tiroid hormon eksikliğinin, TSH yüksekliğine yol açan mekanizması hangi ilkeye dayanmaktadır?","options":["Posterior hipofizden TSH salgısının artması","Pozitif geri besleme ile ön hipofizin aşırı uyarılması","Tiroid bezi hipertrofisinin direkt olarak TSH'yi uyarması","Hipofiz portal dolaşımında TRH konsantrasyonunun azalması","Negatif geri besleme döngüsünün baskısının kalkması"],"correct":4,"exp":"Hipotalamo-hipofizer-tiroid ekseni klasik bir negatif geri besleme döngüsüyle çalışır. Normalde dolaşımdaki serbest T3 ve T4, hipofizin tirotroplarına etki ederek TSH salgısını baskılar; aynı zamanda hipotalamik TRH salgısını da inhibe eder. Primer hipotiroidide tiroid bezi yeterli hormon üretemediğinden bu negatif geri besleme baskısı ortadan kalkar. Sonuç olarak hem hipotalamik TRH hem de hipofizer TSH salgısı artar; yüksek TSH düzeyi, tiroid bezini daha fazla hormon üretmesi için uyarmaya çalışır. Bu mekanizma, TSH ölçümünü primer hipotiroidi taramasında son derece duyarlı bir belirteç haline getirir. Pozitif geri besleme ise reprodüktif sistemde yalnızca LH dalgası gibi özgün durumlarda söz konusudur ve TSH fizyolojisinde geçerli değildir."},{"id":6043,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"Kan-testis bariyerinin yapısal temelini aşağıdakilerden hangisi oluşturur?","options":["Leydig hücreleri arasındaki desmozomlar","Peritübüler miyoid hücrelerin bazal laminası","Spermatidler arasındaki gap junctionlar","Sertoli hücreleri arasındaki sıkı bağlantılar","Epididimis epitelindeki silyalar"],"correct":3,"exp":"Kan-testis bariyeri Sertoli hücreleri arasındaki sıkı bağlantılarla oluşur ve seminifer tübülü bazal ile adluminal kompartmanlara ayırır."},{"id":6044,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Solunum yolu epitelinde hasar sonrası silyalı hücreler ve goblet hücrelerinin yenilenmesinde başlıca progenitör hücre hangisidir?","options":["Tip I pnömosit","Bazal hücre","Alveoler makrofaj","Club hücresi","Endotel hücresi"],"correct":1,"exp":"Trakea ve büyük bronşlardaki bazal hücreler epitelin progenitör hücreleridir; silyalı ve sekretuvar hücrelere farklılaşabilir."},{"id":6045,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Pulmoner alveoler proteinozda alveol içinde surfaktan birikiminin temel nedeni aşağıdakilerden hangisidir?","options":["Tip I pnömositlerin aşırı kollajen üretmesi","Endotel hücrelerinin lenfatik drenajı durdurması","Club hücrelerinin müsin üretiminin artması","Alveoler makrofajların GM-CSF sinyal bozukluğuna bağlı surfaktan temizleyememesi","Silyalı epitelin primer diskinezisi"],"correct":3,"exp":"En sık görülen otoimmün pulmoner alveoler proteinozda anti-GM-CSF antikorları alveoler makrofaj işlevini bozar; surfaktan klirensi azalır ve PAS-pozitif lipoproteinöz materyal birikir."},{"id":6046,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Bir histoloji preparatında terminal bronşiollerin epitelini inceleyen araştırmacı, siliyer olmayan, sitoplazmalarında bol miktarda düz endoplazmik retikulum ve sekretuar granül içeren hücreler tespit ediyor. Bu hücreler hangi işlevi yerine getirir?","options":["Mukus sekresyonu yaparak havayolu nemini korur","Yabancı partikülleri fagosite ederek temizler","Detoksifikasyon enzimleri ve surfaktan benzeri maddeler salgılar","IgA sekresyonu ile lokal immüniteyi sağlar","Karbondioksit difüzyonunu hızlandırır"],"correct":2,"exp":"Tanımlanan hücreler Klara hücreleridir (Club cells). Terminal ve respiratuar bronşiollerde bulunurlar; siliyer yapıları yoktur ve sitoplazmalarında bol düz endoplazmik retikulum ile sekretuar granüller taşırlar. Sitokrom P450 enzimleri aracılığıyla inhale toksik maddeleri detoksifiye eder ve surfaktan benzeri fosfolipit içeren sekresyon üretirler. Ayrıca bronşiol epitelinin kök hücresi işlevi de görürler. Mukus sekresyonu goblet hücrelerinin görevidir; fagositoz alveolar makrofajların işlevidir. IgA sekresyonu plazma hücrelerinin salgıladığı sekretuar bileşenle sağlanır."},{"id":6047,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Tip II pnömositlerin başlıca işlevi aşağıdakilerden hangisidir?","options":["Alfa-1 antitripsin sentezlemek","İmmünglobulin A salgılamak","Mukosiliyer temizliği yürütmek","Pulmoner damar tonusunu doğrudan düzenlemek","Surfaktan sentezlemek ve alveol epitelinin yenilenmesine katkı sağlamak"],"correct":4,"exp":"Tip II pnömositler surfaktan üretir ve alveol hasarı sonrasında tip I ve tip II hücrelere farklılaşabilen progenitör hücrelerdir. Alfa-1 antitripsin esas olarak karaciğerde sentezlenir."},{"id":6048,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, doğumdan 6 saat önce 28. gebelik haftasında sezaryenle doğan bebeğinin yoğun bakımda takip edildiğini öğreniyor. Yenidoğanda inspiryumda belirgin interkostal çekilmeler, ekspiryumda inleme sesi ve siyanoz gözlemleniyor. Akciğer grafisinde yaygın buzlu cam görünümü mevcut. Bebeğe uygulanan ekzojen sürfaktan tedavisinin temel etki mekanizması olan alveolar yüzey geriliminin azaltılması hangi hücresel yapı tarafından üretilerek alveoler yüzeye sekrete edilir?","options":["Tip II pnömosit lameller cisimcikleri","Tip I pnömosit apikal vezikülü","Clara hücresi sekretuar granülleri","Alveolar makrofaj lizozomal içeriği","Endotel hücresi Weibel-Palade cisimcikleri"],"correct":0,"exp":"Sürfaktan, tip II pnömositlerde 'lameller cisimcikler' adı verilen özelleşmiş lizozomal yapılarda depolanır ve ekzositozla alveoler yüzeye salınır. Gestasyonel yaş 34. haftanın altında olan bebeklerde tip II hücre olgunlaşması tamamlanmadığından sürfaktan sentezi yetersiz kalır; bu durum respiratuvar distres sendromuna (RDS) yol açar. Tip I pnömositler alveolar yüzeyin yaklaşık yüzde 95 ini kaplar, gaz değişiminden sorumludur ancak sürfaktan üretmez. Clara hücreleri (şimdiki adıyla Club hücreleri) bronşiyollerde bulunur ve yüzey aktif proteinler ile antioksidanlar salgılar fakat lameller cisimcik içermez. Weibel-Palade cisimcikleri endotel hücrelerine özgü olup von Willebrand faktörü ve P-selektin depolar."},{"id":6049,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Akciğerin alveolokapiller zarı boyunca gerçekleşen gaz difüzyonu incelendiğinde, oksijenin eritrosit içindeki hemoglobine bağlanmadan önce geçtiği katmanlar sırayla değerlendirilmektedir. Buna göre oksijenin alveoler yüzeyden eritrosit membranına ulaşana kadar hangi yapıyı geçmesi gerekmez?","options":["Tip I pnömosit bazal membranı","Füzyone bazal membran","Endotel hücre sitoplazması","Bronşiyal bez asinus epiteli","Alveoler sürfaktan tabakası"],"correct":3,"exp":"Oksijen alveolokapiller zarı geçerken sırasıyla sürfaktan tabakası, tip I pnömosit sitoplazması, tip I pnömosit bazal membranı, füzyone bazal membran (ince bölgelerde tip I pnömosit ve kapiller endotel bazal membranları birleşir), kapiller endotel sitoplazması ve eritrosit membranından geçer. Bronşiyal bez asinus epiteli ise hava iletim yollarında mukus ve seröz salgı üreten bez yapılarıdır; alveolokapiller difüzyon yolunun herhangi bir basamağında yer almaz. Bu soru alveoler difüzyon bariyerinin histolojik katmanlarını bilip bilmediğini doğrudan değil, hangi yapının bu yolun dışında kaldığını sorgulayarak daha analitik düzeyde test etmektedir."},{"id":6050,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"İdiyopatik pulmoner fibrozisin güncel patogenez modelinde başlatıcı olay olarak en çok hangi süreç kabul edilir?","options":["Tekrarlayan alveol epitel hasarı ve anormal onarım yanıtı","İzole nötrofil eksikliği","Bronş düz kas hipertrofisi","Pulmoner arter trombozu","Mukus bezlerinin hiperplazisi"],"correct":0,"exp":"İdiyopatik pulmoner fibroziste tekrarlayan alveoler epitel hasarı, anormal yara iyileşmesi ve fibroblast aktivasyonu temel kabul edilir. Hastalık yalnızca makrofaj kaynaklı inflamasyonla açıklanamaz."},{"id":6051,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, doğumdan 6 saat önce amniyon sıvısında mekonyum boyaması saptanıyor. Bebeği doğumdan hemen sonra solunum sıkıntısına giriyor ve mekanik ventilatöre bağlanıyor. Lavaj materyalinde yüzey gerilimini ölçen surfaktometre değerleri belirgin biçimde yüksek çıkıyor. Surfaktan sistemindeki bu işlev bozukluğunun histolojik ve biyokimyasal temelini en doğru açıklayan seçenek hangisidir?","options":["Mekonyumun safra asitleri içermesi nedeniyle tip II pnömositlerin mitokondrisini doğrudan hasara uğratarak ATP bağımlı lamellar cisimcik ekzositozunu durdurması","Mekonyumun Clara hücrelerini inhibe ederek lesitin-sfingomiyelin oranını düşürmesi ve akciğer matürasyon göstergelerini yanlış yorumlatması","Mekonyumun alveoler makrofajları aktive ederek surfaktan fosfolipidlerini fagosite etmesi ve geri dönüşüm havuzunu tükenmesi","Mekonyumun tip I pnömositleri hasara uğratarak gaz difüzyonunu bozması ve dolaylı olarak tip II pnömosit oksijen bağımlı surfaktan sentezini azaltması","Mekonyumun serbest yağ asitleri ve proteazlar içermesi nedeniyle fosfatidilkolini parçalaması ve surfaktan proteinleri SP-B ile SP-C yi inaktive etmesi"],"correct":4,"exp":"Mekonyum aspirasyon sendromunda surfaktan disfonksiyonunun temel mekanizması çift yönlüdür. Mekonyumun içerdiği serbest yağ asitleri (özellikle palmitat) fosfatidilkolin molekülleriyle yarışarak alveoler yüzey filmini bozar. Bunun yanı sıra mekonyumdaki proteazlar, surfaktan proteinleri SP-B ve SP-C yi proteolitik olarak parçalar. SP-B adsorpsiyon kinetiğini, SP-C ise fosfolipid tabakasının kararlılığını sağlar; her ikisinin kaybı yüzey gerilimini dramatik biçimde yükseltir. Mitokondriyal hasar ikincil süreçtir. Tip I pnömositler surfaktan sentezlemez, bu nedenle onların hasarı dolaylı etki yaratır. Clara hücreleri lesitin sentezinde değil bronşiyol sekresyonunda rol oynar."},{"id":6052,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 20 paket-yıl sigara öyküsüyle birlikte son 3 yıldır giderek artan egzersiz dispnesi ve kronik öksürük yakınmasıyla başvuruyor. Solunum fonksiyon testlerinde FEV1/FVC oranı 0.58 olarak saptanıyor. Yüksek çözünürlüklü toraks BT incelemesinde alt loblarda baskın olmak üzere yaygın amfizematöz değişiklikler izleniyor. Bu hastada alveol duvarı yıkımına zemin hazırlayan temel histofizyolojik mekanizmayı en doğru biçimde açıklayan seçenek hangisidir?","options":["Goblet hücre hiperplazisine bağlı mukus tıkacı oluşumu bronşiolleri oblitere ederek alveol kollapsına yol açar","Tip II pnömositlerde sürfaktan sentezinin azalması alveolar yüzey gerilimini artırarak difüz alveolar kollaps ve fibrozise zemin hazırlar","Nötrofil ve makrofajlardan salınan elastaz ve matriks metalloproteinazların alfa-1 antitripsin ile oluşturduğu proteaz-antiproteaz dengesinin proteaz lehine bozulması alveolar septaların kalıcı yıkımına neden olur","Klaura hücrelerinden salınan sitokinlerin bronşiyal düz kası hipertrofiye uğratması hava yolu direncini artırır","Kapiller endotel hasarına bağlı gelişen pulmoner hipertansiyon alveolar kan akımını azaltarak V/Q dengesizliği ve sekonder alveol atrofisine neden olur"],"correct":2,"exp":"Amfizem patogenezinin merkezinde proteaz-antiproteaz dengesi yer alır. Sigara dumanı hem nötrofil ve alveolar makrofajları aktive ederek elastaz, MMP-2 ve MMP-9 gibi proteazların salınımını artırır hem de alfa-1 antitripsin başta olmak üzere endojen antiproteazları oksidatif hasar yoluyla inaktive eder. Bu çift yönlü bozukluk, alveolar septaları oluşturan elastin ve kollajen yapının geri dönüşümsüz olarak parçalanmasına yol açar; sonuçta alveol duvarları yıkılır, komşu alveollerin birleşmesiyle anormal hava boşlukları oluşur ve akciğer elastik geri dönüş gücü kalıcı biçimde azalır. Goblet hücre hiperplazisi kronik bronşitin özelliğidir, amfizem mekanizması değildir. Tip II pnömosit hasarı respiratuvar distres sendromunda ön plandadır. Klara hücreleri bronşiyal düz kas hipertrofisinden sorumlu değildir. Pulmoner hipertansiyon amfizemin bir komplikasyonu olup primer mekanizma değildir."},{"id":6053,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"42 yaşında bir erkek hasta, 3 aydır giderek kötüleşen bacak güçsüzlüğü ve yürüme güçlüğü yakınmasıyla başvuruyor. Muayenede alt ekstremitelerde kas atrofisi, fasikülasyonlar ve hiperrefleksi birlikte saptanıyor. Elektromiyografide hem alt hem de üst motor nöron tutulumu gösteriliyor. Bu hastada patolojik sürecin başladığı hücre tipinde, normal koşullarda aksiyon potansiyelinin oluşabilmesi için hangi özellik zorunludur?","options":["Hücre gövdesinde voltaja duyarlı sodyum kanallarının yoğun birikimi","Akson başlangıç segmentinde eşik potansiyelinin en düşük olması","Miyelin kılıfı oluşturan Schwann hücrelerinin sürekli uyarımı","Ranvier boğumlarında potasyum kanalı yoğunluğunun sodyum kanalından fazla olması","Dendritik membranda voltaja duyarlı kanal yoğunluğunun aksondan yüksek olması"],"correct":1,"exp":"Motor nöronlarda aksiyon potansiyeli akson tepecisinde (initial segment) başlar. Buradaki voltaja duyarlı Na+ kanalı yoğunluğu vücuttaki en yüksek değerdedir ve eşik potansiyeli bu bölgede en düşüktür. Dendritler ve hücre gövdesi ağırlıklı olarak ligand kapılı kanallar içerir; bu bölgelerdeki uyarılar toplanarak initial segmentte değerlendirilir. ALS gibi hem alt hem üst motor nöronun tutulduğu tabloda patoloji motor nöronun kendisinde başlar. Ranvier boğumlarında Na+ kanalları K+ kanallarından çok daha yoğundur, bu da saltatory iletimi sağlar."},{"id":6054,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Diyabetik distal simetrik polinöropatide en sık görülen temel sinir hasarı paterni hangisidir?","options":["Primer segmental demiyelinizasyon","İzole nöromüsküler kavşak bozukluğu","Uzunluğa bağımlı aksonal dejenerasyon","Ön boynuz hücresi kaybı","Dorsal kök ganglionunda granülom"],"correct":2,"exp":"Diyabetik polinöropati çoğunlukla uzunluğa bağımlı aksonal nöropatidir; en uzun sinir lifleri önce etkilenir. Demiyelinizasyon ikincil olabilir ancak primer patern değildir."},{"id":6055,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir nöronda aksiyon potansiyeli sırasında mutlak refrakter dönemde tekrar uyarım yapılamaz. Bu durumun doğrudan sorumlusu olan iyon kanalı özelliği hangisidir?","options":["Voltaja duyarlı K+ kanallarının kalıcı açık kalması","Voltaja duyarlı Na+ kanallarının inaktivasyon kapısının kapalı olması","Na+/K+ ATPaz pompasının iyonları yerine koyamaması","Klorür kanallarının açılarak hiperpolarizasyon oluşturması","Ligand kapılı kanalların tüm reseptörlerinin dolu olması"],"correct":1,"exp":"Aksiyon potansiyelinin zirve ve iniş fazında voltaja duyarlı Na+ kanalları inaktive konumdadır; aktivasyon kapısı açık, inaktivasyon kapısı ise kapalıdır. Bu konformasyonda kanal ne uyarıya yanıt verebilir ne de iyon geçirebilir. İnaktivasyon kapısının tekrar açılabilmesi için membranın repolarize olması ve kanalın istirahat konumuna dönmesi gerekir. Bu süre tamamlanmadan gelen hiçbir uyarı yeni bir aksiyon potansiyeli oluşturamaz; bu da mutlak refrakter dönemi tanımlar. Na+/K+ ATPaz pompası yavaş çalışır ve refrakter dönemle doğrudan ilişkisi yoktur. Rölatif refrakter dönemde ise K+ kanallarının hâlâ kısmen açık olması eşiği yükseltir fakat bu mutlak değil göreceli bir kısıtlamadır."},{"id":6056,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 8 aydır yavaş ilerleyen yürüme güçlüğü ve konuşma bozukluğu yakınmasıyla nöroloji polikliniğine başvuruyor. Muayenede serebellar ataksi, dizartri ve derin tendon reflekslerinde azalma saptanıyor. Sinir iletim çalışmasında motor iletim hızı normal ancak aksiyon potansiyeli amplitüdü belirgin şekilde düşük bulunuyor. Bu hastada sorumlu tutulan patolojik süreçte hangi yapı öncelikli olarak etkilenmektedir?","options":["Ranvier boğumları","Schwann hücresi miyelin kılıfı","Akson silindirleri","Oligodendrosit uzantıları","Astrosit ara filamentleri"],"correct":2,"exp":"Motor iletim hızı normal kalırken aksiyon potansiyeli amplitüdünün düşmesi, miyelin kılıfının değil akson silindirinin (aksonal hasar) etkilendiğine işaret eder. Miyelin hasarında (demiyelinizasyon) iletim hızı düşer ancak amplitüd görece korunur. Aksonal dejenerasyonda ise miyelin sağlam olduğu için iletim hızı korunur, fakat fonksiyonel akson sayısı azaldığından amplitüd düşer. Ranvier boğumları demiyelinizan patolojilerde önem kazanır. Oligodendrosit uzantıları SSS miyelinini oluşturur, periferik sinirde görev almaz."},{"id":6057,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, sabahları her iki elinde uyuşukluk ve karıncalanma yakınmasıyla başvuruyor. Şikayetler gece uykuda artıyor, bilek fleksiyonuyla tetikleniyor. EMG incelemesinde median sinirde iletim gecikmesi saptanıyor. Bu hastada etkilenen yapıda impulsu ileten iyon kanallarının yoğunlaştığı bölge hangisidir?","options":["Akson tepesi","Ranvier boğumu","Miyelin lamelleri arası","Schwann hücre nukleusunun çevresi","Terminal bouton"],"correct":1,"exp":"Karpal tünel sendromuna bağlı bu tabloda miyelin kılıfı baskı altında kalmaktadır. Miyelinli sinirlerde voltaj kapılı sodyum kanalları miyelin altında değil, Ranvier boğumlarında yoğunlaşmıştır. Impuls iletimi bu boğumdan boğuma sıçrayarak gerçekleşir ve buna saltatorik iletim denir. Miyelin kılıfı bölgelerinde sodyum kanalı yoğunluğu son derece düşüktür. Akson tepesi, aksiyon potansiyelinin başladığı bölgedir ancak iletim sırasında iyon kanallarının odağı Ranvier boğumlarıdır. Terminal bouton ise nörotransmiter salınımıyla ilgili presinaptik yapıdır."},{"id":6058,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Periferik sinir kesisi sonrasında distal segmentte gelişen Waller dejenerasyonunda akson kalıntılarının temizlenmesi ve rejenerasyon yolunun hazırlanmasında hangi iki hücre birlikte rol oynar?","options":["Oligodendrosit ve mikroglia","Fibroblast ve mast hücresi","Astrosit ve ependim hücresi","Nöron ve plazma hücresi","Schwann hücresi ve makrofaj"],"correct":4,"exp":"Distal akson ve miyelin kalıntıları Schwann hücreleri ile makrofajlar tarafından temizlenir. Schwann hücreleri Büngner bantları oluşturarak rejenerasyonu yönlendirir."},{"id":6059,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Aksonun kesilmesinden sonra nöron gövdesinde görülen kromatoliz için aşağıdakilerden hangisi doğrudur?","options":["Nissl cisimcikleri yoğunlaşır ve çekirdek merkeze çekilir","Miyelin sentezi hızlanır","Nissl cisimcikleri dağılır, hücre gövdesi şişer ve çekirdek perifere yer değiştirir","Akson terminali mitozla çoğalır","Nöron gövdesinde kazeifikasyon gelişir"],"correct":2,"exp":"Kromatolizde protein sentezi için hücre gövdesi büyür, Nissl maddesi dağılır ve çekirdek perifere kayar. Bu, akson hasarına verilen rejeneratif yanıttır."},{"id":6060,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Miyelin kılıfın aksonal iletim hızını artırmasında hangi elektriksel değişiklikler birlikte rol oynar?","options":["Membran direncinin artması ve kapasitansın azalması","Membran direncinin azalması ve kapasitansın artması","Membran direnci ile kapasitansın birlikte artması","Sodyum kanallarının internod boyunca eşit dağılması","Akson çapının azalması"],"correct":0,"exp":"Miyelin, akım kaçağını azaltarak membran direncini artırır ve membran kapasitansını azaltır. Böylece depolarizasyon Ranvier düğümleri arasında sıçrayıcı iletilir."},{"id":6061,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir nörobilim pratiğinde araştırmacılar, periferik sinir hasarı sonrasında aksonal rejenerasyonun santral sinir sistemine kıyasla çok daha başarılı gerçekleştiğini gözlemliyor. Bu farkın temelinde yatan temel hücresel mekanizma nedir?","options":["Schwann hücrelerinin hasarlı akson çevresinde büyüme destekleyici tüp oluşturarak rehberlik etmesi","Periferik nöronların hücre gövdesinin spinal kordda bulunması nedeniyle daha kısa mesafe yenilenmesi","Oligodendrositlerin periferik sistemde de görev yaparak remyelinizasyonu kolaylaştırması","Periferik aksonlardaki aktin iskeletinin santral aksonlara göre daha hızlı yeniden yapılanması","Nörotrofik faktörlerin santral sinir sisteminde sentezlenmemesi nedeniyle rejenerasyonun durması"],"correct":0,"exp":"Periferik sinir hasarında Wallerian dejenerasyon sonrasında Schwann hücreleri kritik bir rol üstlenir. Schwann hücreleri kollajen ve laminin açısından zengin bazal membranlarını koruyarak Büngner bantlarını oluşturur; bu yapılar rejenerasyona çalışan büyüme konisi için fiziksel bir rehber kanal işlevi görür. Aynı zamanda Schwann hücreleri NGF ve BDNF gibi nörotrofik faktörler salgılayarak aksonal uzamayı destekler. Santral sinir sisteminde ise oligodendrositler ve reaktif astrositler büyümeyi inhibe eden moleküller (Nogo, MAG, CSPG) üretir; biyolojik olarak destekleyici bir rehber yapı yoktur. Dolayısıyla Schwann hücresi kaynaklı rehber tüp sistemi periferik rejenerasyonun santral rejenerasyona göre çok daha başarılı olmasının temel nedenidir."},{"id":6062,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Üst motor nöron lezyonlarında spastisite gelişmesinin temel mekanizması aşağıdakilerden hangisidir?","options":["Alfa motor nöronların doğrudan dejenerasyonu","Kas iğciğinin tamamen kaybolması","İnhibitör inen yolların kaybıyla spinal gerilme reflekslerinin aşırı uyarılabilir hâle gelmesi","Nöromüsküler kavşakta asetilkolin eksikliği","Periferik sinirde segmental demiyelinizasyon"],"correct":2,"exp":"Kortikospinal ve özellikle retikülospinal düzenleyici etkilerin kaybı spinal gerilme reflekslerini disinhibe eder; hız bağımlı tonus artışı yani spastisite gelişir."},{"id":6063,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, 3 yıldır devam eden hipertansiyon ve tip 2 diyabet öyküsüyle nefroloji polikliniğine başvuruyor. Son 6 ayda proteinüri ve serum kreatinin yüksekliği saptanmış. Böbrek biyopsisinde mezangial matriks artışı ve bazal membran kalınlaşması izleniyor. Bu hastada glomerüler filtrasyon hızının azalmasına yol açan temel histofizyolojik mekanizma hangisidir?","options":["Podosit hipertrofisi sonucu filtrasyon yarıklarının genişlemesi","Bowman kapsülü pariyetal epitel hücrelerinin proliferasyonuyla ultrafiltratın geri emiliminin artması","Jukstaglomerüler hücrelerin renin salınımını artırarak afferent arteriyolde vazodilatasyon oluşturması","Maküla densa hücrelerinin tübüloglomerüler geri beslemeyi baskılayarak filtrasyon basıncını düşürmesi","Mezangial hücre proliferasyonu ve matriks birikimi nedeniyle kapiller lümenin daralması ve filtre edilebilir yüzeyin azalması"],"correct":4,"exp":"Diyabetik nefropatide kronik hiperglisemi, mezangial hücreleri uyararak matriks protein sentezini artırır. Tip IV kollajen ve fibronektin birikimi, hem glomerüler kapiller lümenini daraltır hem de glomerüler bazal membranı kalınlaştırır. Bu iki değişiklik filtre edilebilir yüzeyi ve hidrolik geçirgenliği azaltarak GFR düşüşüne neden olur. Podositler ise ayak çıkıntılarını kaybederek filtrasyon yarıklarını daraltır; bu durum proteinüriye katkıda bulunsa da GFR azalmasının birincil mekanizması değildir. JGA ve maküla densa değişiklikleri ise sekonder adaptif yanıtlardır."},{"id":6064,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Antidiüretik hormonun böbrek toplayıcı kanalındaki doğrudan etkisi aşağıdakilerden hangisidir?","options":["AQP2'nin bazolateral membrana yerleştirilmesi","NKCC2'nin inhibe edilmesi","AQP3 sentezinin tamamen durması","AQP2 içeren veziküllerin apikal membrana eklenmesi","ENaC'nin geri dönüşümsüz kapatılması"],"correct":3,"exp":"ADH, V2 reseptörü-cAMP-PKA yolu üzerinden AQP2 içeren vezikülleri principal hücrenin apikal membranına taşır. AQP3 ve AQP4 bazolateral su çıkışına katkı sağlar."},{"id":6065,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"Böbreğin hangi tübüler segmentinde fırçamsı kenar yapısı en belirgin olup bu yapının temel fizyolojik işlevi nedir?","options":["Henle kulpunun ince inen kolunda; pasif su geçirgenliğini artırarak medüller gradyan oluşturmak","Proksimal kıvrımlı tübülde; apikal yüzeyi genişleterek geri emilim kapasitesini artırmak ve NHE3 ile NaPi taşıyıcılarının yoğunlaşmasını sağlamak","Toplayıcı kanalın principal hücrelerinde; ADH reseptörlerini lüminal yüzeye yerleştirerek su geri emilimini hızlandırmak","Distal kıvrımlı tübülün maküla densa segmentinde; NaCl konsantrasyonunu algılamak ve renin salınımını düzenlemek","Korteksteki Bowman kapsülü visseral epitelde; glomerüler filtrasyon yarıklarını oluşturmak"],"correct":1,"exp":"Fırçamsı kenar (mikrovillus), proksimal kıvrımlı tübül hücrelerinin apikal yüzeyinde en belirgin biçimde gelişmiştir. Bu yapı yüzey alanını yaklaşık 36 kata kadar artırır; böylece günlük filtrattan geri emilen glikoz, aminoasit, fosfat ve bikarbonatın büyük çoğunluğu bu segment üzerinden geri kazanılır. Mikrovilluslar aynı zamanda NHE3 sodyum-hidrojen değiştiricisinin ve Na-Pi kotransporterların yoğunlaştığı bölgedir. Henle ince inen kolu aquaporin-1 içerir fakat fırçamsı kenar barındırmaz. Maküla densa hücreleri silindirik ve kompakt olup NKCC2 taşır, mikrovillus açısından zengin değildir. Toplayıcı kanal principal hücreleri AQP2 vezikülleri içerir ancak belirgin fırçamsı kenar yapısından yoksundur."},{"id":6066,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Primer membranöz nefropatide proteinürinin gelişmesinde temel podosit hasar mekanizması hangisidir?","options":["Glomerüler bazal membranın yalnızca negatif yükünü kaybetmesi","Endotel altında fibrin trombüsleri","Mezangiyal hücrelerde IgA birikimi","Subepitelyal immün komplekslere bağlı kompleman aracılı podosit hasarı","Proksimal tübül nekrozu"],"correct":3,"exp":"Membranöz nefropatide subepitelyal immün kompleksler komplemanı aktive eder; C5b-9 aracılı podosit hasarı ve slit diyafram bozukluğu proteinüriye yol açar."},{"id":6067,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Kırk sekiz yaşında kadın hasta, hipertansiyon nedeniyle takip edilirken rutin tetkiklerinde serum kreatinin 3.2 mg/dL, idrar dansitesi 1.010 olarak saptanıyor. Renal sintigrafide bilateral küçük, granüler yüzeyli böbrekler izleniyor. Biyopside afferent arteriyollerde hiyalinizasyon ve tubulointerstitiyel fibrozis göze çarpıyor. Bu hastada idrar dansitesinin 1.010 düzeyinde sabit kalmasının temel açıklaması hangi yapısal değişiklikle bağlantılıdır?","options":["Glomerüler bazal membran kalınlaşmasına bağlı filtrasyon hızı artışı","Distal tübül ve toplayıcı kanal hasarı nedeniyle konsantrasyon-dilüsyon yeteneğinin kaybı","Henle kulpunun inen kolundaki aquaporin-1 ekspresyonunun artması","Proksimal tübülde Na-K-ATPaz aktivitesinin kompansatuar yükselmesi","Jukstamedüller nefronların hipertrofisiyle ozmotik gradyanın güçlenmesi"],"correct":1,"exp":"İdrarı konsantre etme yeteneği esas olarak medüller hipertonisitenin korunmasına ve toplayıcı kanalların ADH yanıtına bağlıdır. Kronik hipertansif nefrosklerozu olan bu hastada tubulointerstitiyel fibrozis medüller yapıyı tahrip ederek ozmotik gradyanı bozar; aynı zamanda distal tübül ve toplayıcı kanal epitelinin hasarı ADH'a yanıtsızlığa yol açar. Sonuçta böbrek ne konsantre ne de dilüe idrar yapabilir ve dansite plazma ozmolalitesiyle eşdeğer olan 1.010 civarında sabit kalır; buna izosthenüri denir."},{"id":6068,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"Yirmi dört yaşında erkek, tarama tetkiklerinde idrarda eritrosit silendirleri ve hafif proteinüri saptanıyor. Hasta asemptomatik olup kan basıncı normal sınırlarda. Renal biyopside mezangial IgA depolanması görülüyor. Bu hastada eritrosit silendrinin oluşabilmesi için hangi anatomik yapının bütünlüğünün bozulmuş olması gerekmektedir?","options":["Proksimal tübül fırçamsı kenarı","Toplayıcı kanal ana hücreleri","Henle kulpu ince segment epiteli","Distal tübül maküla densa hücreleri","Glomerüler filtrasyon bariyeri"],"correct":4,"exp":"Eritrosit silendirleri, glomerülden geçen eritrositlerin tübül lümeninde Tamm-Horsfall proteinine tutunarak kalıplaşmasıyla oluşur. Eritrositlerin tübüler lümene geçebilmesi için glomerüler filtrasyon bariyerinin yani endotelyal pencereler, bazal membran ve podosit yarık diyaframlarından oluşan üç katmanlı yapının hasarlı olması zorunludur. IgA nefropatisinde mezangial inflamasyon kapiller duvar bütünlüğünü bozarak eritrosit geçişine izin verir. Eritrosit silendrinin varlığı her zaman glomerüler kaynaklı hematuriye işaret eder ve böbrek kaynaklı patoloji için glomerüler kanamayı güçlü biçimde düşündürür."},{"id":6069,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Proksimal tübül hücrelerinde yaygın mitokondriyal işlev bozukluğu geliştiğinde aşağıdaki klinik tablolardan hangisi beklenir?","options":["İzole su retansiyonu","Nefrojenik diabetes insipidus","Fanconi sendromu","İzole hiperkalemi","Distal renal tübüler asidoz"],"correct":2,"exp":"Proksimal tübüldeki enerji bağımlı geri emilim bozulursa glukoz, fosfat, aminoasit, bikarbonat ve ürik asit kaybıyla Fanconi sendromu gelişir."},{"id":6070,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, tekrarlayan böbrek taşı öyküsü nedeniyle inceleniyor. İdrar pH'sı sürekli 6.8 ile 7.2 arasında seyrediyor, serum klor düzeyi yüksek, bikarbonat düzeyi düşük bulunuyor. Genetik incelemede alfa-interkale hücre fonksiyonunu etkileyen bir mutasyon saptanıyor. Bu hücre tipinin normalde gerçekleştirdiği ve hastada bozulmuş olan temel fizyolojik işlev hangisidir?","options":["Toplayıcı kanalda AQP2 aracılı su reabsorpsiyonunu ADH yönlendirmesiyle sağlamak","Kortikotoplayıcı kanaldaki ana hücre aracılığıyla potasyum sekresyonunu artırmak","Apikal H-ATPaz ve bazolateral AE1 aracılığıyla proton sekresyonu ve bikarbonat reabsorpsiyonu yapmak","Henle kulpunun kalın çıkan kolunda NKCC2 taşıyıcısı üzerinden Na-K-2Cl kotransportunu sağlamak","Proksimal tübülde karbonik anhidraz IV aracılığıyla lüminal bikarbonatı suya ve CO2'e dönüştürmek"],"correct":2,"exp":"Alfa-interkale hücreler, korteks ve medüller toplayıcı kanalda asit-baz dengesinde kritik rol üstlenir. Apikal yüzeyde H-ATPaz ve H-K-ATPaz aracılığıyla lümene proton pompalarlar; bazolateral yüzeyde ise AE1 (anyon değiştirici 1) aracılığıyla hücre içindeki bikarbonatı kana taşırlar. Bu mekanizma bozulduğunda idrar asidifikasyonu yapılamaz, idrar pH'sı yüksek seyreder ve sistemik metabolik asidoz gelişir. Yüksek idrar pH'sı kalsiyum fosfat taşlarına zemin hazırlar. Serum hiperklüoremik metabolik asidoz tablosu distal renal tübüler asidoz tip 1 ile tam örtüşür. Diğer seçenekler sırasıyla ana hücre, NKCC2 (TAL), ve proksimal tübül karbonik anhidraz fonksiyonlarını tanımlar; bu hastanın tablosunu açıklamaz."},{"id":6071,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Minimal değişiklik hastalığında proteinüriye yol açan temel ultrastrüktürel değişiklik hangisidir?","options":["Subendotelyal immün kompleks birikimi","Mezangiyal nodül oluşumu","Glomerüler kapillerde fibrin trombüsü","Podosit ayaksı çıkıntılarında yaygın silinme","Bazal membranda çift kontur"],"correct":3,"exp":"Minimal değişiklik hastalığında elektron mikroskobunda podosit ayaksı çıkıntılarının yaygın silinmesi görülür. Slit diyafram işlev bozukluğu seçici albuminüriye yol açar."},{"id":6072,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Konjenital lateral boyun kistlerinin en sık köken aldığı brankiyal yarık hangisidir?","options":["İkinci","Birinci","Üçüncü","Dördüncü","Altıncı"],"correct":0,"exp":"Lateral servikal brankiyal kistlerin büyük çoğunluğu ikinci brankiyal yarık kalıntısından gelişir ve tipik olarak sternokleidomastoid kasın ön kenarında yer alır."},{"id":6073,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Dört yaşında bir erkek çocukta doğumdan beri fark edilen, boyun orta hattında hyoid kemik düzeyinde yerleşik, yumuşak, ağrısız bir kitle mevcut. Kitle dil çıkarıldığında yukarı doğru hareket ediyor. Bu kitlenin oluşumundan sorumlu yapının embriyolojik olarak hangi yapıdan göç ettiği sorgulandığında doğru yanıt hangisidir?","options":["Foramen sekumdan dil köküne kadar uzanan tiroglossal kanaldan","İkinci faringeal çıkıntıdan","Rathke kesesi artığından","Birinci brankiyal yarık artığından","Medial tiroid primordiumu hariç lateral tiroid primordiumu artığından"],"correct":0,"exp":"Tiroid bezi, dördüncü gestasyonel haftada dil tabanındaki foramen sekumdan aşağı doğru göç eder ve bu göç sırasında tiroglossal kanal geçici olarak açık kalır. Normalde bu kanal kapanır; kapanmazsa tiroglossal kist oluşur. Hyoid kemiğin hemen önünden ya da arkasından geçtiği için hyoid düzeyinde orta hatta yerleşir. Dil ile fibroz band aracılığıyla bağlı olduğundan dil çıkarıldığında yukarı hareket eder. Bu ayırt edici klinik bulgu tanı için kritik öneme sahiptir."},{"id":6074,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":3,"q":"Yenidoğan muayenesinde damağın arkasında uvulanın ikiye bölünmüş olduğu saptanıyor. Bu malformasyondan hangi yapının füzyonundaki bozukluk sorumludur?","options":["Lateral palatin çıkıntıların birbirleriyle ve nazal septumla füzyonundan","Medyan nasal çıkıntıyla maksiller çıkıntı füzyonundan","Rathke kesesinin kapanma yetersizliğinden","Mandibular çıkıntıların orta hatta birleşme hatasından","Frontonazal çıkıntının gelişim duraklamasından"],"correct":0,"exp":"Sekonder damak, her iki taraftan gelen lateral palatin çıkıntıların birbirleriyle ve önde primer damakla, yukarıda ise nazal septumla füzyonuyla oluşur. Bu füzyon geriden öne doğru ilerler; en son uvula kapanır. Bu nedenle en hafif füzyon bozukluğu izole bifid uvula olarak kendini gösterir ve submuköz veya tam yarık damağın en hafif uç noktasını temsil eder. Medyan nasal çıkıntı ve maksiller çıkıntı füzyonu ise üst dudak ve primer damağı etkiler, uvulayı değil."},{"id":6075,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Yirmi iki yaşında bir erkek hasta kulak arkasında kistik şişlik şikayetiyle başvuruyor. Şişlik boyun lateralinde, sternokleidomastoid kasın ön kenarı boyunca uzanıyor ve üst solunum yolu enfeksiyonlarıyla birlikte büyüdüğü öğreniliyor. Ameliyat sırasında kistin internal ve eksternal karotid arterler arasından geçtiği görülüyor. Bu kistin embriyolojik kökeninde hangi yapının kalıntısı sorumludur?","options":["Birinci farengeal yarık","Tiroglossal kanal","Üçüncü farengeal kese","Dördüncü farengeal yarık","İkinci farengeal yarık"],"correct":4,"exp":"İkinci farengeal yarık kökenli brankial kist, boyun lateralinde sternokleidomastoid kasın ön kenarı boyunca yerleşir. Karotid arterlerin arasından geçmesi ikinci yay kökenini doğrular çünkü ikinci yarık artığı bu anatomik ilişkiyi korur. Birinci yarık kisitleri dış kulak yoluna yakın yerleşir. Üçüncü ve dördüncü kese artıkları daha alt boyun bölgesinde görülür ve tiroid veya paratiroide yakın seyir gösterir. Tiroglossal kist ise midhat hatta dil kökünden tiroid bezi düzeyine kadar uzanır, hyoid kemikle ilişkilidir."},{"id":6076,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Otuz beş yaşında bir kadın hasta boyun orta hattında ağrısız kistik kitle nedeniyle değerlendiriliyor. Kistin dil çıkarıldığında yukarı doğru hareket ettiği gözlemleniyor. Biyopsi sonucunda kist duvarında tiroide özgü epitel dokusu saptanıyor. Bu lezyonun gelişiminden sorumlu olan embriyolojik yapı hangi arkın hangi bölgesinden köken alır?","options":["Birinci faringeal arkın dorsal yüzeyinden","İkinci faringeal arkın mezoderminden","Birinci ve ikinci arklar arasındaki endodermden","Foramen sekumdan itibaren tiroglossal kanalın kapanmamasından","Üçüncü faringeal kesenin ventral uzantısından"],"correct":3,"exp":"Tiroid bezi embriyolojik olarak dil kökündeki foramen sekumdan başlayarak tiroglossal kanal aracılığıyla aşağı göç eder ve normal konumuna yerleşir. Kanal normalin de kapanır; kapanmaması durumunda tiroglossal kist oluşur. Hyoid kemiğe yakın seyrettiğinden dil çıkarıldığında yukarı hareket eder; bu hareket diagnostik değer taşır. Kist duvarında tiroid dokusu bulunabilir ve nadiren malign transformasyon gösterebilir. Faringeal ark mezodermi kas ve iskelet yapılarını oluşturur, tiroid dokusunun kaynağı değildir."},{"id":6077,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":3,"q":"Konjenital musküler tortikolliste en sık tutulan kas ve temel patolojik değişiklik hangisidir?","options":["Trapezius - denervasyon atrofisi","Sternokleidomastoid - fibrozis ve kısalma","Skalen anterior - hipertrofi","Levator skapula - yağ nekrozu","Platysma - granülomatöz inflamasyon"],"correct":1,"exp":"Konjenital musküler tortikolliste sternokleidomastoid kasta fibrozis ve kısalma görülür. İntrauterin pozisyon ve perinatal kas hasarı olası etkenlerdir; tek bir kesin neden gösterilemez."},{"id":6078,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"İkinci brankiyal yarık fistülünün dış açıklığı en sık nerede bulunur?","options":["Sternokleidomastoid kasın ön kenarının alt bölümünde","Mandibula angulusu arkasında","Submental orta hatta","Tragus önünde","Klavikula üzerinde orta hatta"],"correct":0,"exp":"İkinci brankiyal fistülün dış ağzı çoğunlukla sternokleidomastoid kasın ön kenarının alt bölümündedir; traktus internalde tonsiller fossaya kadar uzanabilir."},{"id":6079,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Otuz beş yaşında bir erkek hasta boyun ön orta hatta yerleşik, yutkunmayla yukarı hareket eden kistik bir kitle nedeniyle değerlendiriliyor. Ultrasonografide kitle tiroid kıkırdağın hemen altında, hyoid kemikle ilişkili izleniyor. Cerrahi patoloji raporunda kistin iç yüzeyinin sözde stratifiye silindrik epitelle döşeli olduğu belirtiliyor. Bu kistin gelişiminde hangi embriyonik yapının kalıntısı rol oynamaktadır?","options":["Tüberkulum impar","Tiroglossal duktus","Kopula","Foramen sekum","Ultimobrankiyal cisim"],"correct":1,"exp":"Tiroglossal dukt kistleri, tiroid bezinin foramen sekumdan aşağıya göçü sırasında kullandığı tiroglossal duktusun tam oblitere olmamasından kaynaklanır. Foramen sekum dil kökünde yer alır ve tiroid göçünün başlangıç noktasıdır. Duktus kalıntısı hioid kemiğe yakın bölgede kist oluşturur; bu nedenle kist yutkunmayla ve dil çıkarmayla yukarı hareket eder. Epiteli sözde stratifiye silindrik ya da skuamöz olabilir. Kopula birinci ve ikinci faringeal arkların birleşimiyle oluşan dil arka bölümüyle ilgilidir. Ultimobrankiyal cisim beşinci faringeal keseden köken alarak tiroidin parafolliküler C hücrelerini oluşturur."},{"id":6080,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":3,"q":"Pierre Robin sekansında yarık damak gelişimine yol açan başlangıç anomalisi hangisidir?","options":["Makroglossi","Maksiller hiperplazi","Koanal atrezi","Dil agenezisi","Mikrognati"],"correct":4,"exp":"Mikrognati dilin geriye ve yukarı yer değiştirmesine (glossoptozis) yol açar; palatal rafların birleşmesi mekanik olarak engellenir. Bu nedenle tablo bir sekans olarak adlandırılır."},{"id":6081,"ders":"Fizyoloji","konu":"Baş Boyun Embriyolojisi","diff":4,"q":"Kistik higromanın embriyolojik temelinde en sık hangi gelişim kusuru bulunur?","options":["Juguler lenf keselerinin venöz sistemle bağlantı kuramaması","Vitellin venin persiste etmesi","Umbilikal arterin kapanmaması","Duktus arteriozusun erken kapanması","Dorsal aortların birleşmemesi"],"correct":0,"exp":"Kistik higroma, özellikle juguler lenf keselerinin venöz dolaşımla uygun bağlantı kuramaması sonucu gelişen lenfatik malformasyondur."},{"id":8170,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, 6 aydır giderek artan bacak güçsüzlüğü ve yürüme güçlüğü yakınmasıyla başvuruyor. Nörolojik muayenede proksimal kas güçsüzlüğü saptanıyor, derin tendon refleksleri korunmuş. EMG incelemesinde miyopatik patern izleniyor. Kas biyopsisinde tip II muscle fiber atrofisi, tip I fiber hipertrofisi ve internal çekirdek göçü saptanıyor. Bu hastaya en uygun tanıyı destekleyen ek bulgu aşağıdakilerden hangisidir?","options":["Serumda anti-Jo-1 antikoru pozitifliği ve interstisyel akciğer hastalığı","Kreatin kinaz düzeyinin belirgin yüksekliği ve inflamatuvar infiltrasyon","CPK normalliği eşliğinde kardiyak tutulum ve lens opasitesi","Tekrarlayan uyarımlarda miyopatik potansiyellerin artması ve myotonia","Kas biyopsisinde nemalin cisimcikleri ve konjenital başlangıç"],"correct":2,"exp":"Klinik tabloda proksimal kas güçsüzlüğü, korunmuş refleksler, tip II fiber atrofisi ve internal çekirdek göçü miyotonik distrofi tip 2 (PROMM) ile uyumludur. Miyotonik distrofilerde kardiyak iletim defektleri ve lens opasitesi (katarakt) karakteristik ekstramisküler bulgulardır; CPK hafif yüksek ya da normal olabilir. Anti-Jo-1 pozitifliği inflamatuvar miyopati (polimiyozit), belirgin CPK yüksekliği ile inflamasyon Duchenne/polimiyoziti, nemalin cisimcikleri konjenital miyopatiyi, tekrarlayan uyarımda artma ise miyasteniform tabloyu düşündürür."},{"id":8171,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, efor dispnesi ve alt ekstremite ödemi şikayetiyle kardiyoloji polikliniğine başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %30, sol ventrikül diyastol sonu basıncı artmış olarak saptanıyor. Hastaya başlanan sakubitril/valsartan tedavisinin primer hedefi olan peptid ve bu peptid üzerindeki temel etkiyi gösteren biyokimyasal değişiklik aşağıdakilerden hangisidir?","options":["Natriüretik peptidlerin yıkımının inhibisyonu → plazma cGMP düzeyinde artış","ANP yıkımının inhibisyonu → plazma BNP düzeyinde belirgin düşüş","Renin salınımının doğrudan baskılanması → plazma aldosteron düzeyinde artış","BNP yıkımının inhibisyonu → idrar ANP atılımında azalma","Anjiyotensin II reseptör blokajı → AT1 reseptör aktivasyonunda artış"],"correct":0,"exp":"Sakubitril, neprilizin enzimini inhibe ederek natriüretik peptidlerin (ANP, BNP, CNP) yıkımını engeller. Bu peptidler guanilat siklazı aktive ederek hücre içi cGMP düzeyini artırır; sonuç olarak vazodilatasyon, natriürez ve kardiyak remodelingin baskılanması sağlanır. Plazma BNP düzeyi yıkım azaldığı için yükselir, düşmez. Renin sakubitril tarafından doğrudan baskılanmaz; AT1 blokajı valsartanın görevidir ve bu blokaj AT1 aktivasyonunu azaltır, artırmaz."},{"id":8172,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında erkek hasta, rutin check-up sırasında istenen tetkiklerinde serum kreatinin 1,8 mg/dL, 24 saatlik idrarda protein 3,5 g ve hematüri saptanıyor. Renal biyopside ışık mikroskobisinde mezangial proliferasyon ve segmental skleroz, immünfloresan incelemede IgA ve C3 birikimi görülüyor. Hastalığın patogenezinde rol oynayan, karaciğerde üretilen ve mukozal IgA homeostazını bozan molekül açısından aşağıdaki öncüller değerlendirilmektedir:\nI. Bu molekül, glikozilasyonu yetersiz polimerik IgA1 için mezangiyumda biriken antikorların oluşumunu tetikler.\nII. Hastaların serum düzeyleri sağlıklı bireylerle karşılaştırıldığında belirgin biçimde düşük seyretmektedir.\nIII. Tonsillektominin bazı vakalarda proteinüriyi azaltması, bu molekülün tonsil kökenli üretiminin patogenezdeki rolünü desteklemektedir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II ve III","I, II ve III","I ve III","Yalnız I","I ve II"],"correct":2,"exp":"IgA nefropatisinde (Berger hastalığı) patogenezde galaktoz-eksik IgA1 (Gd-IgA1) merkezi role sahiptir. Öncül I doğrudur: glikozilasyonu yetersiz (galaktoz-eksik) polimerik IgA1 'antigenik' özellik kazanarak anti-glikoprotein antikorlarla immün kompleks oluşturur ve mezangiyuma birikir. Öncül II yanlıştır: serum Gd-IgA1 düzeyleri IgA nefropatisi hastalarında sağlıklı bireylerden yüksektir, düşük değil. Öncül III doğrudur: tonsillektomi bazı hastalarda hastalık aktivitesini azaltmaktadır; bu bulgu tonsil dokusundaki plazma hücrelerinin anormal IgA1 üretimine katkısını desteklemektedir."},{"id":8173,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"27 yaşında kadın hasta, ani başlayan çift görme, sağ göz kapağında düşüklük ve öğleden sonrası belirginleşen kas yorgunluğu yakınmalarıyla başvuruyor. Tensilon (edrofonyum) testinde belirtilerinin geçici olarak düzeldiği görülüyor. Hastalığın ilişkili olduğu yapı ve bu yapıyla ilgili aşağıdaki öncüller değerlendirilmektedir:\nI. Bu yapı, T lenfosit olgunlaşmasını ve otoimmün toleransı yöneten bir organdır.\nII. Hastalığın erken başlangıçlı formunda bu yapıda hiperplazi, ileri yaş formunda ise timoma sıklıkla gözlemlenir.\nIII. Bu yapıda bulunan miyoid hücreler, asetilkolin reseptörlerine karşı oluşan otoimmün yanıtın başlangıç basamağında rol oynar.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["2","3","1","Belirlenemiyor","0"],"correct":1,"exp":"Klinik tablo miyastenia gravisi (MG) düşündürmektedir; edrofonyum ile düzelme tanıyı destekler. MG'de hedef organ timüs bezidir. Öncül I doğrudur: timüs, T lenfosit olgunlaşmasında ve santral toleransın (negatif seleksiyon) oluşturulmasında temel organdır. Öncül II doğrudur: erken başlangıçlı MG (özellikle genç kadınlar) timüs hiperplazisiyle, geç başlangıçlı form ise timoma ile daha sık ilişkilidir. Öncül III doğrudur: timüsteki miyoid hücreler yüzeylerinde asetilkolin reseptörü (AChR) taşır ve bu reseptörlere karşı oluşan otoimmün yanıtı başlatabilir. Dolayısıyla üç öncülün tamamı doğrudur."},{"id":8174,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Tip II pnömositler hakkında aşağıdakilerden hangisi yanlıştır?","options":["Yüzey aktif madde olarak başlıca dipalmitilfosfatidilkolin (DPPC) içerirler.","Osmiyumla boyamada lamellar cisimcikler karakteristik ultrastrüktürel bulgudur.","Alveol yüzeyinin büyük bölümünü döşeyen hücrelerdir.","Surfaktan sentez ederek alveollerin kollapsını önlerler.","Hasarlı tip I pnömositlerin yerine geçebilen kök hücre özelliği taşırlar."],"correct":2,"exp":"Alveol yüzeyinin yaklaşık %95'ini tip I pnömositler kaplar; tip II pnömositler ise alveoler yüzeyin yalnızca %5'ini oluşturmakla birlikte hücre sayısı bakımından daha fazladır. Bu nedenle “Alveol yüzeyinin büyük bölümünü döşeyen hücrelerdir.” ifadesi yanlıştır ve doğru yanıttır. Diğer şıklar doğrudur: tip II pnömositler surfaktan (başlıca DPPC) sentezler; lamellar cisimcikler bu hücrelerin karakteristik ultrastrüktürel bulgusudur; hasar sonrası tip I pnömositler için progenitör hücre görevi üstlenirler."},{"id":8175,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 4 aydır süren kanlı ishal, karın ağrısı ve 8 kg kilo kaybı yakınmalarıyla gastroenteroloji polikliniğine başvuruyor. Kolonoskopide çekumdan başlayan, sürekli tutulum gösteren mukozal hiperemi ve ülserasyonlar izleniyor; biyopside goblet hücre kaybı, kript absesi ve lamina propriada yoğun nötrofil infiltrasyonu saptanıyor. Bu hastanın tanısı doğrultusunda uzun dönem izlemde en sık gelişmesi beklenen komplikasyon hangisidir?","options":["Granülom oluşumu ve transmural inflamasyon zemininde karsinoid tümör","İnce bağırsak adenokarsinomu ve malabsorpsiyon sendromu","Taş safra kesesi ve primer sklerozan kolanjit","Kolorektal karsinom ve primer sklerozan kolanjit","Fistül, fissür ve perianal hastalık"],"correct":3,"exp":"Klinik ve histopatolojik bulgular ülseratif kolit (ÜK) ile uyumludur: çekumdan başlayan sürekli tutulum, goblet hücre kaybı, kript absesi ve yüzeyel mukozal tutulum. ÜK'nin en önemli uzun dönem komplikasyonları kolorektal karsinom (özellikle pankolit ve uzun hastalık süresinde risk artar) ve primer sklerozan kolanjittir (PSK); PSK, ÜK ile güçlü şekilde ilişkilidir ve hastaların %5 kadarında görülür. Fistül ve transmural tutulum Crohn hastalığına özgüdür. İnce bağırsak adenokarsinomu ve granülom da Crohn'u düşündürür. Taş safra kesesi Crohn'da terminal ileum tutulumuna bağlı gelişir."},{"id":8176,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 4 aydır devam eden çift görme, göz kapağı düşüklüğü ve çiğneme sırasında yorgunluk yakınmalarıyla başvuruyor. Nörolojik muayenede tekrarlayan kas hareketleriyle güçsüzlüğün arttığı saptanıyor. Asetilkolinesteraz inhibitörü tedavisi başlandıktan sonra hastanın bulgularında belirgin düzelme gözleniyor. Bu hastada asetilkolinesteraz inhibitörünün terapötik etkisini açıklayan nöromüsküler kavşak fizyolojisiyle ilgili aşağıdaki öncüllerden hangileri doğrudur?\nI. Motor son plakta nikotinik reseptörlerin aktivasyon süresi uzar.\nII. Postsinaptik membranda oluşan uç plak potansiyeli amplitüdü artar.\nIII. Sinaptik yarıktaki asetilkolin konsantrasyonu düşer.\nIV. Aksiyon potansiyeli eşiğine ulaşma olasılığı azalır.","options":["Yalnız I ve II","I ve III","I, II ve III","II ve IV","I, II ve IV"],"correct":0,"exp":"Asetilkolinesteraz inhibitörleri, sinaptik yarıktaki asetilkolini parçalayan enzimi bloke ederek ACh konsantrasyonunu yükseltir ve kalış süresini uzatır. Bu sayede nikotinik reseptörler daha uzun süre aktif kalır (I doğru), uç plak potansiyelinin amplitüdü artar (II doğru). Öncül III yanlıştır; ACh konsantrasyonu düşmez, aksine artar. Öncül IV de yanlıştır; eşiğe ulaşma olasılığı azalmaz, artar. Myastenia gravis patogenezinde otoimmün IgG antikorları AChR'yi hedef alır; ilaç bu açığı fonksiyonel olarak telafi eder."},{"id":8177,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, kardiyoloji polikliniğine egzersiz intoleransı ve efor dispnesi yakınmalarıyla başvuruyor. Ekokardiyografide mitral kapak yaprakçıklarında kalınlaşma ve mitral darlık saptanıyor. Gradient ölçümünde ortalama transmitral basınç farkı 14 mmHg olarak bulunuyor. Bu hastada kapak patolojisinin hemodinamik sonuçlarıyla ilgili aşağıdakilerden hangisi beklenmez?","options":["Sol atriyal basınçta artış","Sol ventrikül diyastol sonu hacminde artış","Atriyal fibrilasyon riski artışı","Pulmoner venöz hipertansiyon gelişimi","Sol atriyal dilatasyon"],"correct":1,"exp":"Mitral darlıkta sol atriyumdan sol ventriküle geçiş engellenir. Bu nedenle sol atriyal basınç artar, pulmoner venöz basınç yükselir, sol atrium genişler ve atriyal fibrilasyon riski belirgin biçimde artar. Kritik nokta şudur: mitral darlıkta sol ventriküle yeterli kan dolumu olmadığından sol ventrikül diyastol sonu hacmi artar değil, azalır ya da normal-düşük kalır. Dolayısıyla 'Sol ventrikül diyastol sonu hacminde artış' beklenen bir bulgu değildir ve doğru yanıttır."},{"id":8178,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 20 paket-yıl sigara öyküsüyle polikliniğe başvuruyor. Solunum fonksiyon testinde FEV1/FVC: %58, TLC artmış, RV/TLC oranı yükselmiş bulunuyor. Yüksek çözünürlüklü akciğer BT'de hava hapsi ve amfizematöz değişiklikler saptanıyor. Bu hastada azalmış difüzyon kapasitesinin (DLCO) temel nedeni aşağıdakilerden hangisidir?","options":["Alveoler ventilasyonun azalması","Havayolu rezistansının artması","Alveolokapiller membran yüzey alanının kaybı","İnspiratuvar kas güçsüzlüğü","Pulmoner kapiller basıncın artması"],"correct":2,"exp":"Amfizemde alveol duvarları yıkılır; bu durum gaz değişim yüzey alanını dramatik biçimde azaltır. DLCO doğrudan bu yüzey alanıyla orantılıdır. Alveoler ventilasyon azalabilir; ancak DLCO düşüklüğünün birincil açıklaması membran yüzey kaybıdır. Kapiller basınç artışı interstisyel ödem durumunda difüzyon mesafesini artırır, ancak amfizemin primer mekanizması değildir. Havayolu rezistansı FEV1/FVC'yi açıklar, DLCO'yu değil."},{"id":8179,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 3 gündür süren bulantı, kusma ve oligüri yakınmalarıyla acil servise başvuruyor. Laboratuvar sonuçlarında serum kreatinin: 4.2 mg/dL, BUN: 68 mg/dL, idrar özgül ağırlığı: 1.010, idrar sodyumu: 65 mEq/L, fraksiyonel sodyum atılımı (FENa): %3.2 bulunuyor. Bu hastada böbrek yetmezliğinin prerenal mi yoksa intrinsik renal mi olduğunu ayırt etmede en belirleyici parametre aşağıdakilerden hangisidir?","options":["Serum kreatinin düzeyi","BUN/kreatinin oranı","Serum ürik asit düzeyi","İdrar sodyum konsantrasyonu ve FENa birlikte","Günlük idrar miktarı"],"correct":3,"exp":"Prerenal azotemide tübüler fonksiyon korunur; böbrek sodyumu geri emer, bu nedenle idrar Na < 20 mEq/L ve FENa < %1 beklenir. İntrinsik renal hasarda (örn. ATN) tübüler hasar nedeniyle sodyum geri emilimi bozulur: idrar Na > 40 mEq/L ve FENa > %2. Bu hastada idrar Na: 65 mEq/L ve FENa: %3.2 intrinsik renal hasarı işaret eder. İdrar sodyumu tek başına yeterlidir; ancak FENa ile birlikte değerlendirilmesi daha güvenilir bilgi verir. BUN/kreatinin oranı prerenal lehine yükselir, ancak tek başına yetersizdir."},{"id":8180,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Merkezi sinir sisteminde miyelin kılıf oluşumundan sorumlu hücre tipi ve periferik sinir sisteminde aynı görevi üstlenen hücre tipi eşleştirmesi aşağıdakilerden hangisinde doğru verilmiştir?","options":["Mikroglia - Schwann hücresi","Astrosit - satellit hücre","Astrosit - Schwann hücresi","Oligodendrosit - satellit hücre","Oligodendrosit - Schwann hücresi"],"correct":4,"exp":"MSS'de miyelin, oligodendrositlerin uzantılarının akson çevresine sarılmasıyla oluşur; bir oligodendrosit birden fazla aksonu miyelinleyebilir. PSS'de bu görevi Schwann hücreleri üstlenir ve her Schwann hücresi yalnızca tek bir akson segmentini sarar. Satellit hücreler PSS'deki gangliyon nöronlarını destekler, miyelin yapmaz. Mikroglia MSS'nin bağışıklık hücreleridir. Astrositin miyelin üretimindeki rolü yoktur."},{"id":8181,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"45 yaşında erkek hasta, 6 aydır devam eden halsizlik, tekrarlayan enfeksiyonlar ve ciltte peteşi-purpura ile başvuruyor. Tam kan sayımında pansitopeni saptanıyor. Kemik iliği biyopsisinde hücreselliğin %10'un altında olduğu görülüyor. Siklosporin ve antitimosit globulin (ATG) tedavisi planlanıyor. Bu tedavinin hedef aldığı patofizyolojik mekanizma aşağıdaki öncüllerin hangisinde doğru özetlenmiştir?\nI. CD8+ sitotoksik T lenfositler hematopoetik kök hücreleri apoptoza götürür.\nII. Kemik iliği stromal yapısı primer olarak hasar görmüştür.\nIII. IFN-γ ve TNF-α salınımı kök hücre supresyonuna katkıda bulunur.\nIV. Siklosporin, T lenfosit aktivasyonunu kalsinörin inhibisyonu yoluyla baskılar.","options":["Yalnız II ve III","I ve IV","II, III ve IV","I, III ve IV","I, II ve IV"],"correct":3,"exp":"Edinsel aplastik anemide kemik iliği yetmezliği ağırlıklı olarak otoimmün kökenlidir: aktive CD8+ sitotoksik T hücreleri ve bunların salgıladığı IFN-γ ile TNF-α, hematopoetik kök hücreleri Fas/FasL yoluyla apoptoza iter (I ve III doğru). Siklosporin, T hücrelerinde IL-2 transkripsiyonunu engelleyen kalsinörin inhibitörüdür; ATG ise T hücrelerini tüketir (IV doğru). Öncül II yanlıştır; stromal hasar aplastik aneminin primer mekanizması değildir, kök hücreye yönelik immün saldırı esastır. Dolayısıyla I, III ve IV doğrudur."},{"id":8182,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, 6 aydır giderek artan nefes darlığı ve bacaklarında güçsüzlük yakınmasıyla başvuruyor. Özgeçmişinde 20 yıldır tip 2 diyabetes mellitus ve hipertansiyon mevcut; metformin ve amlodipin kullanıyor. Kas biyopsisinde Tip I liflerde belirgin atrofi saptanıyor. Bu hastada beklenen kas fizyolojisi bulgularına ilişkin aşağıdaki öncülleri değerlendirin:\nI. Etkilenen kas liflerinde mitokondri yoğunluğu azalmıştır.\nII. Kas kasılma hızı göreceli olarak korunmuş, ancak yorulmaya direnç belirgin biçimde azalmıştır.\nIII. Kas lifinin istirahat membran potansiyeli Na⁺/K⁺-ATPaz aktivitesinin azalmasına bağlı olarak daha az negatif değere kayabilir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II ve III","I, II ve III","Yalnız III","I ve III","Yalnız I"],"correct":3,"exp":"Tip I kas lifleri (yavaş, yorulmaya dirençli, kırmızı lifler) yüksek mitokondri yoğunluğu ve oksidatif kapasite ile karakterizedir; atrofide bu lifler mitokondri içeriğini kaybeder, bu nedenle öncül I doğrudur. Tip I lif atrofisinde kasılma hızı değil yorulmaya direnç korunur, zira hız özelliği miyozin ağır zincir izoformuna bağlıdır; ancak yorulmaya direnç mitokondriye bağlı olduğundan azalır; dolayısıyla öncül II yanlıştır. Diyabetik nöropati ve kronik hastalık sürecinde Na⁺/K⁺-ATPaz aktivitesi baskılanabilir; bu durum hücre dışına K⁺ pompalamasını azaltarak istirahat membran potansiyelini depolarize yönde kaydırır (daha az negatif yapar), bu nedenle öncül III doğrudur. Doğru öncüller I ve III'tür."},{"id":8183,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, efor sırasında ortaya çıkan göğüs ağrısı ve çarpıntı yakınmalarıyla kardiyoloji polikliniğine başvuruyor. EKG'de PR mesafesinin uzadığı ve QRS kompleksinin genişlediği saptanıyor. Yapılan ileri tetkikler sonucunda hastaya bir iyon kanal blokörü başlanıyor. İlaç tedavisinin ardından yapılan kontrol EKG'sinde QT mesafesinin uzadığı görülüyor. Bu hastada kullanılan ilacın etki mekanizmasına göre aşağıdaki öncülleri değerlendirin:\nI. İlaç, kardiyomiyositlerde hızlı depolarizasyon fazını (faz 0) yavaşlatmaktadır.\nII. İlaç, aksiyon potansiyelinin plato fazında (faz 2) kalsiyum akımını artırmaktadır.\nIII. QT uzaması, ventriküler repolarizasyonun geciktiğine işaret etmektedir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Yalnız biri","Hiçbiri","Üçü de","Yalnız I ve III","Yalnız ikisi"],"correct":4,"exp":"QRS genişlemesi iletim hızının yavaşladığını gösterir ve bu Sınıf I antiaritmiklerin (Na⁺ kanal blokörü) karakteristik bulgusudur; dolayısıyla faz 0'ı yavaşlatan Na⁺ kanalı blokajı söz konusudur, öncül I doğrudur. QT uzaması repolarizasyonun geciktiğini gösterir ve bu Sınıf III antiaritmiklere (K⁺ kanal blokörü) özgüdür; repolarizasyon gecikince aksiyon potansiyeli süresi uzar ve QT uzar; öncül III doğrudur. QT uzatacak şekilde etki eden bu ilaç Ca²⁺ akımını artırmaz; aksine hem Sınıf I hem de Sınıf III etkiler Na⁺ ve K⁺ kanalları üzerinden gerçekleşir; öncül II yanlıştır. Doğru öncül sayısı ikidir (I ve III)."},{"id":8184,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında erkek hasta, 2 yıldır devam eden öksürük, balgam ve tekrarlayan akciğer enfeksiyonu yakınmalarıyla başvuruyor. Toraks BT'de bronşiektazi saptanıyor. Solunum fonksiyon testlerinde FEV1/FVC oranı düşük bulunuyor. Nazal polip öyküsü olan hastanın spermiogramında da ağır motilite bozukluğu tespit ediliyor. Bronş biyopsisinde siliyaların ultrastrüktürel incelemesinde iç dynein kollarının yokluğu gösteriliyor. Bu hastanın klinik tablosuyla en doğrudan ilişkili olan hücresel yapı ve işlev bozukluğu hangisidir?","options":["Siliyalı epitel hücrelerinde ATP bağımlı aksonemal hareketin bozulması","Bronş düz kas hücrelerinde beta-2 reseptör duyarsızlaşması","Clara hücrelerinin sekretuar işlev kaybı","Tip II pnömosit yüzey aktif madde sentezinin azalması","Goblet hücrelerinde mukus sekresyonunun artması"],"correct":0,"exp":"Bu klinik tablo, Primer Silier Diskinezi (PSD) ile uyumludur; bronşiektazi, nazal polip ve erkek infertilitesi (spermlerde motilite bozukluğu) birlikteliği tanı için klasik üçlüdür. PSD'de dynein kollarının yapısal defekti sonucunda siliyaların '9+2' mikrotübül çifti düzenli olsa da ATP bağımlı aksonemal motor aktivitesi işlevini yerine getiremez; mukosiliyer klerens durur ve tekrarlayan enfeksiyonlar gelişir. Goblet hücresi hiperplazisi sekonder bir bulgu olup primer patoloji değildir. Tip II pnömosit defekti RDS tablosunu açıklar. Beta-2 duyarsızlaşması astım ve KOAH patofizyolojisine girer. Clara hücre defekti bu tabloya uymaz."},{"id":8185,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"58 yaşında erkek hasta, 3 aydır devam eden ödem ve idrar miktarında azalma yakınmasıyla nefroloji polikliniğine başvuruyor. 24 saatlik idrarda protein atılımı 6,8 g/gün olarak ölçülüyor; serum albümin düzeyi 2,1 g/dL, serum kolesterol düzeyi 380 mg/dL olarak saptanıyor. Renal biyopside glomerüler bazal membranda diffüz kalınlaşma ve subepitelyal çivi başı görünümü (spike and dome pattern) izleniyor. Bu hastada GFR'yi koruma çabası kapsamında afferent arteriol düzeyinde aktive olan fizyolojik mekanizma aşağıdakilerden hangisidir?","options":["Sempatik sinir aktivasyonu ile afferent arteriolin dilatasyonu","Anjiyotensin II aracılığıyla efferent arteriolin dilatasyonu","Tübüloglomerüler geri bildirim ile afferent arteriolin dilatasyonu","Atriyal natriüretik peptid ile glomerüler kapiller basıncın düşürülmesi","Miyojenik refleks ile afferent arteriolin konstriksiyonu"],"correct":2,"exp":"Bu hasta nefrotik sendrom (membranöz nefropati) tablosundadır. Proteinüri ve hipoalbuminemi sonucunda efektif dolaşım hacmi azalır; bu durum maküla densa seviyesinde NaCl konsantrasyonunun düşmesine yol açar. Tübüloglomerüler geri bildirim mekanizması gereği maküla densa hücreleri bu düşüşü afferent arteriole iletir ve afferent arteriol dilate olarak GFR'yi korumaya çalışır. Miyojenik refleks arteriyel basınç yükselince afferent konstriksiyona yol açar, burada söz konusu değildir. Anjiyotensin II ağırlıklı olarak efferent arterioli daraltır. ANP glomerüler filtrasyonu artırırken afferent arteriole etkisi farklıdır. Sempatik aktivasyon afferent arterioli daraltır, dilate etmez."},{"id":8186,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"29 yaşında kadın hasta, sabahları ellerde belirginleşen güçsüzlük ve çift görme yakınmalarıyla nöroloji polikliniğine başvuruyor. Fizik muayenede tekrarlayan hareketlerle güçsüzlüğün arttığı gözlemleniyor. Tensilyum (edrofonium) testi pozitif saptanıyor ve hastaya bir kolinesteraz inhibitörü başlanıyor. Tedavinin başlanmasının ardından hastada aşırı tükürük salgısı, bağırsak krampi ve bronkospazm gelişiyor. Bu durumda tedavide yapılması gereken farmakolojik düzenleme ve bunu gerektiren fizyolojik arka plan aşağıdakilerden hangisidir?","options":["Atropin eklenmesi; muskarinik reseptörlerde aşırı kolinerjik uyarının yan etkilerini gidermek için","İlacın kesilmesi; nöromusküler kavşakta asetilkolin birikimiyle nikotinik reseptör desensitizasyonu","Doz azaltımı; monoaminoksidaz inhibisyonuyla katekolamin toksisitesi gelişmesi","Propranolol eklenmesi; beta-adrenerjik hiperaktivite sonucu bronkospazmın kötüleşmesi","İlaca magnezyum eklenmesi; presinaptik asetilkolin salınımının artırılması"],"correct":0,"exp":"Myasthenia gravis tedavisinde kullanılan kolinesteraz inhibitörleri asetilkolinin yıkımını engeller; nöromusküler kavşakta nikotinik reseptör uyarısı artarak kas gücü düzelir. Ancak aynı zamanda otonom sinir sisteminin parasempatik (muskarinik) reseptörleri de aşırı uyarılır; bu durum tükürük artışı, bağırsak krampı, bronkospazm ve bradikardi gibi 'SLUDGE' bulgularına yol açar. Bu muskarinik yan etkileri gidermek için atropin (muskarinik antagonist) eklenir; atropinin nikotinik reseptörlere etkisi yoktur, dolayısıyla kas gücüne müdahale etmez. İlacın kesilmesi gerekli değildir. Katekolamin toksisitesi veya adrenerjik mekanizma bu tabloda söz konusu değildir. Magnezyum presinaptik asetilkolin salınımını azaltır, artırmaz."},{"id":8187,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor sırasında ortaya çıkan nefes darlığı ve alt extremitelerde ödem yakınmasıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30 olarak ölçülüyor. Hastaya tedavi olarak bir ilaç başlanıyor; bu ilacın etkisiyle preload ve afterload azalmakta, semptomlar gerilemiş olsa da hastada hiperkalemi gelişiyor. Başlanan ilaç aşağıdakilerden hangisidir?","options":["Metoprolol","Hidralazin","Furosemid","Digoksin","Enalapril"],"correct":4,"exp":"ACE inhibitörleri (enalapril), anjiyotensin II oluşumunu engelleyerek hem venöz (preload) hem arteriyel (afterload) direnci azaltır; aynı zamanda aldosteron salınımını baskılayarak potasyum atılımını kısıtlar ve hiperkalemiye yol açar. Furosemid hipokalemi yapar, metoprolol kalp hızını yavaşlatır ama hiperkalemi yapmaz, hidralazin yalnızca afterload azaltır ve hiperkalemi yapmaz, digoksin pozitif inotroptur."},{"id":8188,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında erkek hasta, ani başlayan nefes darlığı ve sağ taraflı plöretik göğüs ağrısıyla acil servise getiriliyor. Hastanın boyunun uzun ve zayıf yapılı olduğu görülüyor. Solunum seslerinin sağda alınmadığı tespit ediliyor. Göğüs tüpü takılarak tedavi ediliyor. Bu hastada pnömotoraksa bağlı olarak beklenen solunum fizyolojisi değişikliği aşağıdakilerin hangisidir?","options":["Toplam akciğer kapasitesinin artması","Etkilenen tarafta difüzyon kapasitesinin korunması","Etkilenen akciğerde kompliyansın artması","Soldan sağa şant gelişmesi","Etkilenen tarafta V/Q oranının sıfıra yaklaşması"],"correct":4,"exp":"Pnömotoraks durumunda etkilenen akciğer kollabe olur; bu bölgede ventilasyon (V) sıfıra yaklaşırken perfüzyon (Q) bir süre devam edebilir. Bu durum V/Q oranının sıfıra yaklaşmasına yani intrapulmoner şanta (sağdan sola şant) yol açar, hipoksemi gelişir. Kompliyans kollabe akciğerde azalır, TLC azalır, difüzyon kapasitesi bozulur."},{"id":8189,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında kadın hasta, 10 yıldır tip 2 diyabetes mellitus tanısıyla oral antidiyabetik kullanmaktadır. Rutin kontrolde proteinürisi olduğu saptanıyor; GFR 48 mL/dak olarak hesaplanıyor. Hastanın nefroloji polikliniğine yönlendirilmesiyle başlatılan SGLT-2 inhibitörü tedavisinin renal düzeydeki temel hemodinamik etkisi aşağıdakilerden hangisidir?","options":["Proksimal tübülde sodyum-glukoz kotransportunu bloke ederek tübüloglomerüler geri bildirimi restore etmek","Distal tübülde sodyum reabsorbsiyonunu artırarak GFR'yi korumak","Afferent arteriyolde vazokonstrüksiyon yaparak glomerüler basıncı azaltmak","Efferent arteriyolde vazodilatasyon yaparak GFR'yi artırmak","Mezangial hücreler üzerine doğrudan etki ederek proteinüriyi azaltmak"],"correct":0,"exp":"Diyabetik nefropatide proksimal tübülde SGLT-2 aracılı aşırı sodyum-glukoz geri emilimi, makula densaya ulaşan sodyum miktarını azaltır ve tübüloglomerüler geri bildirim (TGF) mekanizması bozulur; afferent arteriyol genişler, glomerüler hipertansiyon gelişir. SGLT-2 inhibitörleri bu aşırı reabsorbsiyonu bloke ederek makula densaya sodyum akışını normale döndürür, TGF'yi restore eder, afferent arteriyolde vazokonstrüksiyon sağlar ve glomerüler basıncı düşürür; böylece nefropati progresyonu yavaşlar."},{"id":8190,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Bir sinir lifinde aksiyon potansiyeli oluşumu sırasında aşağıdaki öncülleri değerlendiriniz:\nI. Depolarizasyon fazında hücre dışına sodyum iyonu akışı gerçekleşir.\nII. Repolarizasyon fazında potasyum kanalları açılarak potasyum iyonu hücre dışına çıkar.\nIII. Mutlak refrakter dönemde sodyum kanalları inaktif konumdadır.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, II ve III","II ve III","Yalnız II","I ve III","Yalnız I"],"correct":1,"exp":"Depolarizasyon fazında voltaj kapılı sodyum kanalları açılır ve sodyum hücre İÇİNE girer (I yanlış). Repolarizasyon fazında sodyum kanalları inaktive olurken potasyum kanalları açılır ve potasyum hücre dışına çıkar (II doğru). Mutlak refrakter dönemde sodyum kanallarının inaktivasyon kapısı kapalıdır, hiçbir uyaran yeni aksiyon potansiyeli oluşturamazçünkü kanallar inaktif konumdadır (III doğru). Dolayısıyla II ve III doğrudur."},{"id":8191,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"45 yaşında erkek hasta, yağlı yemek yedikten sonra sağ üst kadrana vuran ve sırta yayılan karın ağrısı yakınmasıyla başvuruyor. Ultrasonografide safra kesesinde taş saptanıyor, koledok genişlemesi izlenmiyor. Hastada safra salgısı ve sindirim fizyolojisi açısından değerlendirildiğinde, yağlı öğün sonrasında safra kesesinin kasılmasını primer olarak uyaran hormon hangisidir ve bu hormon hangi hücrelerden salgılanır?","options":["VIP; ince bağırsak enterik nöronlar","Sekretin; duodenum S hücreleri","Kolesistokinin; duodenum ve jejunum I hücreleri","Gastrin; mide antrum G hücreleri","Motilin; duodenum Mo hücreleri"],"correct":2,"exp":"Yağ ve protein içerikli besinlerin duodenuma ulaşmasıyla duodenum ve jejunumun I hücrelerinden kolesistokinin (CCK) salgılanır. CCK safra kesesini kasarak safra akışını artırır, Oddi sfinkterini gevşetir ve pankreatik enzim salgısını uyarır. Sekretin ise S hücrelerinden salgılanır ve pankreatik bikarbonattan zengin sıvı salgısını uyarır; safra kesesini kasma etkisi yoktur. Gastrin, gastrik asit salgısını; motilin, interdigestif motor aktiviteyi düzenler."},{"id":8192,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, tekrarlayan kemik ağrıları, sarılık ve dalak büyüklüğü yakınmalarıyla hematoloji polikliniğine başvuruyor. Periferik yaymada orak hücreler görülüyor; hemoglobin elektroforezinde HbS oranı %85 olarak saptanıyor. Hastada defalarca akut göğüs sendromu atağı geçirdiği öğreniliyor. Hidroksiüre tedavisi başlanıyor. Bu tedavinin orak hücre hastalığındaki faydalı etkisinin temel biyokimyasal dayanağı aşağıdakilerden hangisidir?","options":["HbS polimerleşmesini doğrudan inhibe eden antioksidan etki","Retiküloendotelyal sistemde dalak sekestrasyon hızını yavaşlatma","Kemik iliğinde eritropoezi baskılayarak anormal eritrosit üretimini azaltma","Eritrosit membranındaki spektrin proteinini stabilize ederek hemolizi önleme","HbF sentezini artırarak HbS konsantrasyonunu ve polimerleşme eğilimini azaltma"],"correct":4,"exp":"Hidroksiüre, ribonükleotid redüktazı inhibe ederek DNA sentezini baskılar; bu etki gamma-globin gen ekspresyonunu artırır ve fetal hemoglobin (HbF, alfa2-gamma2) üretimini yükseltir. HbF, HbS ile hibrit tetramerlerde yer alarak HbS'nin oksi-desoksi dönüşümünde polimerleşmesini engeller; orak hücre oluşumu ve buna bağlı vasooklüzif krizler azalır. Diğer seçenekler hidroksiürenin bilinen etki mekanizmasıyla uyuşmamaktadır."},{"id":8193,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, efor dispnesi ve bacaklarda şişlik yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya başlanan sakubitril/valsartan tedavisinin etki mekanizması değerlendirildiğinde aşağıdaki öncüllerden hangileri doğrudur?\nI. Natriüretik peptid yıkımı azalarak tübüler sodyum reabsorbsiyonu baskılanır.\nII. Anjiyotensin II düzeyi artarak efferent arteriyol vazodilatasyon sağlanır.\nIII. cGMP aracılı vasküler düz kas gevşemesi preload azalmasına katkıda bulunur.","options":["II ve III","I, II ve III","Yalnız I","I ve III","Yalnız II"],"correct":3,"exp":"Sakubitril, nöral endopeptidaz (neprilizin) inhibisyonu yoluyla ANP ve BNP yıkımını azaltır. Bu peptidler böbrekte toplayıcı kanallarda sodyum reabsorbsiyonunu baskılar (Öncül I doğru). Artmış natriüretik peptidler guanilat siklaz reseptörleri aracılığıyla cGMP sentezini artırarak düz kas gevşemesine ve preload azalmasına yol açar (Öncül III doğru). Öncül II yanlıştır: valsartan AT1 reseptörünü bloke eder, anjiyotensin II düzeyi reaktif olarak yükselse de efferent arteriyol vazodilatasyon değil, vazokonstrüksiyon baskılanmış olur; mekanizma preglomerüler direnç azalması şeklinde değil, postglomerüler AT1 blokajı şeklinde işler. Doğru öncüller I ve III'tür."},{"id":8194,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, tekrarlayan idrar yolu enfeksiyonları nedeniyle araştırılırken idrar osmolalitesi sürekli 290 mOsm/kg olarak ölçülüyor. Su kısıtlama testinde idrar osmolalitesi artmıyor; dezmopressin uygulaması sonrasında da yanıt alınamıyor. Bu tablonun patofizyolojisini açıklayan yapı veya mekanizm hangisidir?","options":["Proksimal tübül Na-K-ATPaz aktivitesinin primer kaybı","V2 reseptör gen mutasyonu nedeniyle adenilat siklaz aktivasyonu bozukluğu","Henle kulpunun ince çıkan kolunda aktif NaCl transportu yokluğu","Toplayıcı kanal prensipyal hücrelerinde AQP2 ekspresyonu yokluğu","Vasa rekta hipertonisitesinin korunamaması"],"correct":3,"exp":"Dezmopressin (sentetik ADH) uygulamasına rağmen idrar yoğunlaştırılamıyorsa defekt ADH reseptörünün distalinde, yani toplayıcı kanal epitelindedir. Bu durum nefrojenik diabetes insipidusun en sık nedeni olan AQP2 (aquaporin-2) kanal yokluğu veya işlev bozukluğunu gösterir. V2 reseptör mutasyonu da nefrojenik DI yapar ancak bu durumda dezmopressine yanıtsızlık cAMP üretim basamağında olur; AQP2 ekspresyon kaybı ise daha distalde, cAMP-PKA-AQP2 fosforilasyon kaskadının sonucunu etkiler. Vaka, reseptör ve kaskad bütünüyle işlevsiz olduğunda veya AQP2 proteinin kendisi yoksa ortaya çıkar; seçenekler arasında bu tabloyu en doğru açıklayan AQP2 ekspresyon yokluğudur."},{"id":8195,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır süren progresif nefes darlığı yakınmasıyla başvuruyor. Toraks BT'de buzlu cam görünümü ve bal peteği fibrozisi saptanıyor. Bronkoalveoler lavajda lenfosit oranı %60 bulunuyor. Spirometride FVC %58, FEV1/FVC %88 ölçülüyor. Bu hastanın patolojisinde birincil olarak etkilenen hücre tipi ve bu hücrenin temel fizyolojik işlevi ile ilgili aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Etkilenen hücre tip II pnömositlerdir ve surfaktan sentezleyerek alveoler yüzey gerilimini düşürür.\nII. Etkilenen hücre tip I pnömositlerdir ve alveoler kapiller membranın yaklaşık %95'ini örter.\nIII. Surfaktan bileşimindeki dipalmitoilfosfatidilkolin (DPPC) ekspirasyonda alveoler kollabsı önler.\nIV. Tip II pnömositler hasar sonrası tip I pnömosit rejenerasyonunu sağlayan progenitör hücrelerdir.","options":["2","Hiçbiri","3","1","4"],"correct":2,"exp":"İdiyopatik pulmoner fibroziste (İPF) öncelikle alveoler epitel hasara uğrar. Öncül I doğrudur: tip II pnömositler surfaktan sentezler ve yüzey gerilimini azaltır. Öncül II doğrudur: tip I pnömositler ince ve yassı yapılarıyla gaz değişiminin gerçekleştiği alveoler-kapiller yüzeyin yaklaşık %95'ini kaplar. Öncül III doğrudur: DPPC ekspirasyonda alveoler yarıçap küçüldükçe moleküllerin sıkışması ile yüzey gerilimini daha da azaltarak kollabsı önler. Öncül IV doğrudur: tip II pnömositler kök hücre niteliğinde olup hasar sonrası prolifere olarak tip I pnömosit farklılaşmasını sağlar. Dört öncülün tamamı doğrudur."},{"id":8196,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"23 yaşında kadın hasta, 2 haftadır çift görme ve sağ göz kapağında düşüklük yakınmasıyla başvuruyor. Muayenede sağ ptozis ve öğleden sonraya doğru belirginleşen proksimal kas güçsüzlüğü saptanıyor. Edrofonyum testi pozitif bulunan hastaya pridostigmin başlanıyor. Bu ilacın etki gösterdiği yapı hangisidir?","options":["Kas iğciği Ia afferentlerinin nöronal ateşleme eşiği","Nöromüsküler kavşaktaki asetilkolin esteraz enzimi","Postsinaptik membrandaki nikotinik asetilkolin reseptörü","Motor nöron presinaptik terminalindeki voltaj kapılı kalsiyum kanalları","Motor korteks inhibitör internöronları"],"correct":1,"exp":"Myastenia gravis'te postsinaptik nikotinik asetilkolin reseptörlerine karşı antikorlar gelişir ve nöromüsküler iletim bozulur. Pridostigmin, asetilkolin esteraz enzimini geri dönüşümlü olarak inhibe ederek sinaptik yarıktaki asetilkolin yoğunluğunu artırır; bu sayede kalan reseptörler daha uzun süre uyarılır ve kas kasılması güçlenir. Edrofonyum da aynı mekanizmayla çalışan kısa etkili bir asetilkolin esteraz inhibitörüdür ve tanısal amaçla kullanılır."},{"id":8197,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 3 haftadır süren halsizlik, peteşi ve burun kanaması yakınmasıyla başvuruyor. Tam kan sayımında trombosit 8.000/µL, hemoglobin 11.2 g/dL, beyaz küre 7.400/µL saptanıyor. Periferik yaymada dev trombositler ve megakaryosit fragmanları görülüyor. Kemik iliği biyopsisinde megakaryositler artmış. Bu hastada aşağıdaki öncüllerden hangileri doğrudur?\nI. Patoloji trombopoetin eksikliğine bağlı yetersiz megakaryosit olgunlaşmasından kaynaklanmaktadır.\nII. Megakaryositler endomitoz yoluyla ploidi artırarak sitoplazmik olgunlaşma sağlar ve trombosit tomurcuklanmasına izin verir.\nIII. Tedavide kullanılan eltrombopag c-Mpl (trombopoetin) reseptörünü aktive ederek trombosit üretimini artırır.\nIV. İmmün trombositopeninin temel nedeni GPIb-IX-V kompleksinin kalıtsal olarak bulunmamasıdır.","options":["II ve III","III ve IV","I ve II","I ve IV","I, II ve III"],"correct":0,"exp":"İmmün trombositopenide periferik immün yıkım artar ve kemik iliğinde megakaryositler genellikle artmıştır; trombopoetin eksikliği temel mekanizma değildir. Megakaryositler endomitozla ploidi kazanır. Eltrombopag, c-Mpl reseptörünü aktive ederek trombosit üretimini artırır. GPIb-IX-V kompleksinin kalıtsal yokluğu ise Bernard-Soulier sendromunun özelliğidir. Doğru öncüller II ve III'tür."},{"id":8198,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Mide fundusunda paryetal hücrelerin yoğun olduğu bilinmektedir. Bu hücrelerin ürettiği faktörlerin eksikliğinde ortaya çıkabilecek klinik tablolar değerlendirildiğinde aşağıdaki öncüllerden hangileri doğrudur?\nI. İntrinsik faktör eksikliği, terminal ileumda B12 vitamini emilimini bozarak megaloblastik anemiye yol açar.\nII. HCl eksikliğinde pepsinojenden pepsin aktivasyonu gerçekleşemez.\nIII. Paryetal hücre hasarı, hipergastrinemi ve mide fundusunda enterokromafin benzeri (ECL) hücre hiperplazisine neden olur.\nIV. Paryetal hücreler aynı zamanda gastrin salgılayarak mide asit sekresyonunu otoregüle eder.","options":["II ve IV","I ve II","I, II, III ve IV","I, II ve III","I, III ve IV"],"correct":3,"exp":"Paryetal hücreler HCl ve intrinsik faktör üretir. Öncül I doğrudur: intrinsik faktör B12 vitamini ile ileumda cubilin reseptörü aracılığıyla emilim için zorunludur; eksikliğinde pernisiyöz anemi (megaloblastik anemi) gelişir. Öncül II doğrudur: pepsinojen, asidik ortamda (pH<4) otokatalitik olarak aktif pepsin formuna dönüşür; HCl eksikliğinde bu aktivasyon gerçekleşemez. Öncül III doğrudur: paryetal hücre kaybıyla asit sekresyonu azalır, antrumdaki G hücreleri baskılanmaz ve gastrin salınımı artar (hipergastrinemi); gastrin ECL hücrelerini uyardığından ECL hiperplazisi izlenir. Öncül IV yanlıştır: gastrin salgılamak paryetal hücrelerin değil, antrum ve duodenum G hücrelerinin görevidir; paryetal hücreler gastrine yanıt veren hücrelerdir, gastrini üretenler değil. Doğru öncüller I, II ve III'tür."},{"id":8199,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor sırasında ortaya çıkan çarpıntı ve presenkop yakınmasıyla başvuruyor. EKG'de dar QRS kompleksli, düzensiz ritim saptanıyor. Transtorasik ekokardiyografide sol atriyum boyutu 5,2 cm olarak ölçülüyor. Hasta atriyal fibrilasyon tanısıyla hız kontrolü amacıyla digoksin tedavisine başlanıyor. Digoksinin bu hastadaki hız kontrolünü sağlayan temel etki noktası hangisidir? A) Sinoatriyal düğümde otomatisite artışı B) AV düğümde vagal tonusu artırarak ileti hızını yavaşlatma C) His-Purkinje sisteminde refrakter periyodu uzatma D) Sol ventrikül kontraktilitesini azaltarak kalp hızını düşürme E) Sempatik sinir uçlarından norepinefrin salınımını inhibe etme","options":["AV düğümde vagal tonusu artırarak ileti hızını yavaşlatma","Sinoatriyal düğümde otomatisite artışı","His-Purkinje sisteminde refrakter periyodu uzatma","Sol ventrikül kontraktilitesini azaltarak kalp hızını düşürme","Sempatik sinir uçlarından norepinefrin salınımını inhibe etme"],"correct":0,"exp":"Digoksin, Na+/K+-ATPaz pompasını inhibe ederek hücre içi Na+ konsantrasyonunu artırır; bu durum Na+/Ca2+ değiştiricisini (NCX) ters yönde çalıştırarak hücre içi Ca2+ birikimini sağlar ve pozitif inotropik etkiye yol açar. Hız kontrolündeki asıl etkisi ise parasempatik (vagal) tonusu artırması yoluyla AV düğüm iletim hızını yavaşlatmasıdır. Bu nedenle atriyal fibrilasyonda ventriküler hız kontrolü için kullanılır. Digoksinin SA düğüm üzerinde otomatisiteyi artırdığı ya da His-Purkinje üzerinden primer etki ettiği şeklindeki ifadeler yanlıştır. Sempatik inhibisyon ise digoksinin primer mekanizması değildir."},{"id":8200,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 4 aydır süren progresif dispne ve kuru öksürük şikayetiyle başvuruyor. Sigara kullanım öyküsü bulunmuyor. Solunum fonksiyon testlerinde FVC: %58 (beklenenin), FEV1: %60, FEV1/FVC: %103 olarak saptanıyor. DLCO belirgin şekilde düşük bulunuyor. Yüksek rezolüsyonlu BT'de bilateral bazal predominant, subplevral, retiküler opasiteler ve bal peteği görünümü mevcut. Bu hastanın patolojik sürecinde tip II pnömositlerin rolüne ilişkin aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Tip II pnömositler, hasar sonrası alveoler epiteli yeniden döşemek üzere tip I pnösite diferansiye olabilir.\nII. Tip II pnömositler, surfaktan sentezleyerek alveolar yüzey gerilimini artırır.\nIII. İdiyopatik pulmoner fibrozisde tip II pnömositlerde hiperplazi gelişmesi, alveolar hasarın göstergesidir.\nIV. Tip II pnömositler, lamellar cisimcikler aracılığıyla surfaktanı ekzositozla salgılar.","options":["4 tanesi","2 tanesi","3 tanesi","Hiçbiri","Yalnız 1 tanesi"],"correct":2,"exp":"SFT bulguları (düşük FVC, normal/yüksek FEV1/FVC, düşük DLCO) ve YRBT görünümü idiyopatik pulmoner fibrozu (IPF) düşündürmektedir. Öncüllerin değerlendirilmesi: I. DOĞRU - Tip II pnömositler, alveolar epitel kök hücresi işlevi görür ve alveolar hasar sonrası tip I pnösite farklılaşabilir. II. YANLIŞ - Tip II pnömositler surfaktan sentezler, ancak surfaktan yüzey gerilimini AZALTIR, artırmaz. III. DOĞRU - IPF'de tip II pnömositlerde hiperplazi, akut alveolar hasarı ve devam eden yeniden yapılanmayı yansıtır. IV. DOĞRU - Surfaktan, tip II pnömositlerde lamellar cisimciklerde depolanır ve ekzositozla alveolar lümene salgılanır. Dolayısıyla I, III ve IV doğru, II yanlıştır; 3 öncül doğrudur."},{"id":8201,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, tip 2 diabetes mellitus ve hipertansiyon tanılarıyla 12 yıldır takip edilmektedir. Son kontrolünde idrar tahlilinde mikroalbüminüri saptanan hastanın eGFR değerinin 42 mL/dak/1,73 m2 olduğu görülüyor. Nefroloji tarafından değerlendirilen hastaya SGLT-2 inhibitörü başlanıyor. Bu ilacın renal koruyucu etkisini açıklamak için böbrek histofizyolojisi açısından aşağıdaki öncüllerin doğruluğu değerlendirildiğinde kaç tanesi yanlıştır?\nI. SGLT-2 transporteri proksimal tübülün S1 ve S2 segmentlerinin apikal yüzeyinde eksprese edilir.\nII. SGLT-2 inhibisyonu, tübüloglomerüler geri besleme aracılığıyla glomerüler kapiller basıncı düşürür.\nIII. Proksimal tübülde glikoz geri emiliminin inhibisyonu, maküla densaya iletilen NaCl miktarını artırır.\nIV. SGLT-2 inhibisyonu afferent arteriyolde vazodilatasyon ve efferent arteriyolde vazokonstrüksiyon yaparak hiperfiltrasyonu azaltır.","options":["2 tanesi","Hiçbiri","4 tanesi","3 tanesi","Yalnız 1 tanesi"],"correct":4,"exp":"SGLT-2 inhibitörleri diyabetik nefropatide hiperfiltrasyonu azaltarak renal koruma sağlar. Öncüllerin değerlendirilmesi: I. DOĞRU - SGLT-2, proksimal tübülün S1-S2 segmentlerinin apikal (lüminal) membranında yoğun olarak eksprese edilir, düşük afinite-yüksek kapasite özelliğindedir. II. DOĞRU - SGLT-2 inhibisyonu proksimal tübülde glikoz ve sodyum geri emilimini azaltır; maküla densaya daha fazla NaCl ulaşır, tübüloglomerüler geri besleme aktive olur ve afferent arteriyol daralarak intraglomerüler basınç düşer. III. DOĞRU - Glikoz geri emiliminin azalmasıyla proksimal tübülden geçen NaCl oranı artar ve maküla densaya ulaşan miktarı yükselir. IV. YANLIŞ - SGLT-2 inhibisyonu afferent arteriyolde VAZOKONSTRİKSİYON yaparak (efferent değil) intraglomerüler basıncı düşürür. Efferent arteriyolde dilatasyon değil, afferent arteriyolde daralma söz konusudur. Dolayısıyla yalnızca IV yanlıştır; 1 öncül yanlıştır."},{"id":8202,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"19 yaşında kadın hasta, 2 gündür süren sağ el bileği ve el sırtında his kaybı ve uyuşma şikayetiyle başvuruyor. Nörolojik muayenede sağ ön kolun dorsal yüzeyinde ve el sırtı radyal yarısında duyu kaybı saptanıyor, motor muayene normal. Yapılan tetkiklerde sinir ileti hızının ilgili sinirde belirgin şekilde düştüğü görülüyor. Sinirin miyelin kılıfını oluşturan hücreler hasara uğramış olup remyelinizasyon süreci başlamıştır. Periferik sinir sisteminde miyelin kılıfını oluşturan hücrelere ilişkin aşağıdakilerden hangisi doğrudur?","options":["Santral sinir sistemindeki muadilleriyle aynı embriyonik kökenden gelişir.","Her bir hücre, birden fazla aksonun miyelin kılıfını oluşturabilir.","Akson çevresini saran miyelin kılıfı Ranvier boğumlarında kesintisiz devam eder.","Her bir hücre, tek bir akson boyunca yalnızca bir internodal segmenti sarar.","Akson hasarı sonrasında Wallerian dejenerasyonu başlatma görevini üstlenir."],"correct":3,"exp":"Periferik sinir sisteminde miyelin kılıfını Schwann hücreleri oluşturur. Temel özellikleri: Her bir Schwann hücresi, tek bir akson üzerinde yalnızca bir internodal segmenti (iki Ranvier boğumu arasındaki bölgeyi) sarar. Bu, santral sinir sistemindeki oligodendrositlerin birden fazla akson üzerinde miyelin oluşturmasından farklıdır. Ranvier boğumlarında miyelin kılıfı yoktur, kesintisiz değildir. Schwann hücreleri nöral krest kökenlidir; oligodendrositlerin kökeni ise nörektoderm (nöral tüp). Wallerian dejenerasyonu, akson hasarı sonrası uzak segment ve miyelin kılıfının bozulması sürecidir; Schwann hücreleri bu süreçte miyelin kalıntılarını fagosite eder ancak süreci 'başlatan' hücreler değildir."},{"id":8203,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"24 yaşında erkek hasta, polikliniğe rutin kontrol amacıyla başvurmuştur. Tam kan sayımında eritrosit morfolojisi değerlendirilirken periferik yaymada, hemoglobin içermeyen santral soluk alanı eritrosit çapının üçte birinden fazlasını kaplayan hücreler dikkat çekmektedir. Laboratuvar bulgularında serum demiri düşük, TDBK yüksek ve ferritin düşük saptanmaktadır. Bu periferik yayma bulgusunun açıklamasında en doğru ifade hangisidir?","options":["Bu hücreler hipokromik eritrositler olup yetersiz hemoglobin sentezini yansıtır.","Santral soluk alan genişlemesi, hücre içi B12 vitamini yetersizliğinin göstergesidir.","Santral soluk alan genişlemesi, eritrosit membranındaki spektrin eksikliğine bağlıdır.","Bu bulgular demir yüklenme durumlarında ortaya çıkar.","Periferik yaymadaki bu hücreler, kemik iliğinde erken salınan immatür eritrositlerdir."],"correct":0,"exp":"Periferik yaymada santral soluk alanının eritrosit çapının 1/3'ünden fazlasını kaplaması hipokromiyi tanımlar. Hipokromik eritrositler, yetersiz hemoglobin sentezi sonucunda oluşur. Serum demiri düşük, TDBK yüksek ve ferritin düşük olması demir eksikliği anemisinin karakteristik laboratuvar profilidir. Demir eksikliğinde hem sentezi bozulur; bu da hemoglobin miktarının azalmasına ve hücre içinin boş görünmesine yol açar. Spektrin eksikliği herediter sferositoza neden olur ve santral soluk alan kaybıyla seyreder. B12 eksikliği megaloblastik anemi ile sonuçlanır ve hiperkromik makrositoz yapar. Demir yüklenme durumları hiperkromi ile ilişkilidir. Polikromatofilik eritrositler immatür hücreleri tanımlar, ancak soruda tanımlanan bulgu hipokromidir."},{"id":8204,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan egzersiz intoleransı ve proksimal kas güçsüzlüğü yakınmasıyla başvuruyor. Fizik muayenede baldır kaslarında psödohipertrofi saptanıyor. EMG'de miyopatik patern mevcut. Kas biyopsisinde tip II kas lifi atrofisi ve glikojen birikimi görülüyor. Hastaya enzim replasman tedavisi başlanıyor. Bu tedavinin kas hücrelerindeki birincil etkisi hangi organelde gerçekleşir?","options":["Mitokondri","Peroksizom","Lizozom","Golgi aygıtı","Sarkoplazmik retikulum"],"correct":2,"exp":"Glikojen depo hastalığı tip II (Pompe hastalığı) lizozomal asit maltaz (alfa-glukozidaz) eksikliğine bağlıdır. Glikojen lizozomlar içinde birikir. Enzim replasman tedavisinde verilen rekombinant alfa-glukozidaz mannoz-6-fosfat reseptörleri aracılığıyla lizozomlara hedeflenir ve buradaki glikojen birikimini çözer. Tedavinin birincil etkisi lizozomda gerçekleşir."},{"id":8205,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında kadın hasta, ani başlayan nefes darlığı ve bacak ödemi ile başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %65 olarak ölçülüyor, ancak E/e' oranı 15 bulunuyor. Hastaya diüretik tedavi başlanıyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Bu tabloda kapiller hidrostatik basınç artmıştır.\nII. Kardiyomiyositlerde titin proteininin sertliği artmış olabilir.\nIII. Natriüretik peptid düzeyleri normal sınırlar içinde beklenir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve II","I ve III","Yalnız I","II ve III","I, II ve III"],"correct":0,"exp":"EF korunmuş kalp yetmezliğinde (HFpEF) diyastolik disfonksiyon mevcuttur. E/e' oranının >14 olması sol ventrikül dolum basınçlarının arttığını gösterir; bu da pulmoner venöz ve kapiller hidrostatik basıncı yükseltir (I doğru). Diyastolik sertliğin önemli bir nedeni sarkomerde titin izoformlarının ve fosforilasyon durumunun değişmesidir (II doğru). BNP/NT-proBNP bu hastalarda çoğunlukla yüksektir, normal sınırlarda değildir (III yanlış). Doğru öncüller I ve II'dir."},{"id":8206,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 haftadır süren çift görme ve sağ göz kapağında düşüklük yakınmasıyla başvuruyor. Muayenede öğleden sonra semptomların belirginleştiği, tekrarlayan konuşmayla seste yorulma olduğu saptanıyor. Tensilonum (edrofonyum) testiyle semptomlar geçici olarak düzeliyor. Timoma şüphesiyle görüntüleme planlanıyor. Bu hastalıkta nöromüsküler kavşakta hangi yapı hedef alınmaktadır?","options":["Motor sinir terminalindeki asetilkolin vezikülü proteinleri","Postsinaptik nikotinik asetilkolin reseptörleri","Kas membranındaki voltaj kapılı sodyum kanalları","Presinaptik voltaj kapılı kalsiyum kanalları","Presinaptik voltaj kapılı potasyum kanalları"],"correct":1,"exp":"Myastenia gravis'te otoantikor hedefi postsinaptik nöromüsküler kavşaktaki nikotinik asetilkolin reseptörleridir (anti-AChR antikoru). Reseptörlerin yıkımı ve blokajı nedeniyle nöromüsküler iletim bozulur, tekrarlayan kullanımla yorulma ortaya çıkar. Edrofonyum asetilkolinesterazı inhibe ederek sinaptik aralıktaki ACh konsantrasyonunu artırır ve semptomları geçici olarak düzeltir. Presinaptik kalsiyum kanalı antikoru Lambert-Eaton sendromunda görülür."},{"id":8207,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbrek tübüluslarına ait aşağıdaki öncülleri değerlendiriniz:\nI. Proksimal tübülüs epitel hücrelerinin apikal yüzeyinde fırçamsı kenar (brush border) bulunur.\nII. Henle kulpunun ince çıkan kolu suya geçirgen, tuz transportuna kapalıdır.\nIII. Distal tübülüste aldosteron etkisiyle sodyum geri emilimi artar.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Yalnız biri","Üçü de","Tamamı yanlış değerlendirme sorusudur","Hiçbiri","Yalnız ikisi"],"correct":4,"exp":"I. Doğru: Proksimal tübülüs hücrelerinin apikal yüzeyinde mikroviluslardan oluşan fırçamsı kenar (brush border) vardır; bu yapı emilim yüzeyini artırır. II. Yanlış: Henle kulpunun ince çıkan kolu suya geçirgen ancak tuz transportuna görece kapalıdır; ince ÇIKAN kol ise suya geçirgensiz fakat tuz geçişine açıktır. Bu nedenle II. öncüldeki 'ince çıkan kol' ifadesi ile verilen özellik ince inen kola aittir, dolayısıyla II yanlıştır. III. Doğru: Aldosteron distal tübülüs ve toplayıcı kanal hücrelerinde basolateral mineralokortikoid reseptörlere bağlanarak ENaC ve Na/K-ATPaz ekspresyonunu artırır. Doğru öncül sayısı: I ve III olmak üzere 2'dir."},{"id":8208,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 3 aydır süren yorgunluk, tekrarlayan ağız içi ülserleri ve deri döküntüsü yakınmalarıyla başvuruyor. Tam kan sayımında pansitopeni saptanıyor. Periferik yaymada hipersegmente nötrofiller görülüyor. Kemik iliği aspirasyonunda megaloblastik değişiklikler mevcut. Serum B12 düzeyi çok düşük, folik asit normal. Bu hastaya B12 tedavisi başlandıktan sonra en erken hangi bulguda düzelme beklenir?","options":["Retikülositozun ortaya çıkması","Hemoglobin değerinin normale dönmesi","Periferik yaymadaki hipersegmente nötrofillerin kaybolması","Trombosit sayısının normale dönmesi","Megaloblastik kemik iliği bulgularının kaybolması"],"correct":0,"exp":"B12 tedavisine yanıt sıralaması önemlidir. Tedavinin 2-3. günlerinde en erken belirti kemik iliğinde eritroid hiperplaziye geçiş ve ardından periferik kanda retikülositozdur (5-7. günlerde zirve yapar). Hipersegmente nötrofillerin kaybolması 1-2 hafta alır. Hemoglobin ve trombosit sayısındaki düzelme ise haftalar-aylar içinde gerçekleşir. Bu nedenle en erken beliren bulgu retikülositozdur."},{"id":8209,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, tekrarlayan pnömoni atakları, kronik sinüzit ve yıllardır süren kronik öksürük yakınmalarıyla başvuruyor. Ailede benzer şikayetleri olan bireyler olduğu öğreniliyor. Göğüs radyografisinde situs inversus totalis saptanıyor. Bronş biyopsisinde yapısal sil anomalisi görülüyor. Bu hastada beklenen spermatogenez bozukluğunun temel nedeni aşağıdakilerden hangisidir?","options":["Testiküler venöz drenaj bozukluğu","Germinal epitel hücrelerinde apoptoz artışı","Sperm hücresinin aksonema yapısındaki dynein kol defekti","Leydig hücresinden testosteron sekresyonunun azalması","Testiküler Sertoli hücre disfonksiyonu"],"correct":2,"exp":"Primer silier diskinezi (Kartagener sendromu: sinüzit + bronşektazi + situs inversus) aksonemal dynein ağır zincir mutasyonlarına bağlıdır. Sillerin '9+2' mikrotübül yapısındaki iç ve dış dynein kolları, mikrotübüller arası kayan hareketi sağlar. Bu defekt bronş epiteli ve tuba uterina epitelindeki sillerin yanı sıra sperm flagellasını da etkiler çünkü flagella aksoneması sil aksonemasıyla aynı yapısal düzeni paylaşır. Sonuçta sperm motilitesi bozulur ve infertilite gelişir. Sertoli, Leydig veya vasküler patoloji bu tablonun açıklaması değildir."},{"id":8210,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan proksimal kas güçsüzlüğü ve egzersiz intoleransı yakınmasıyla başvuruyor. Aile öyküsünde özellik yok. Elektromiyografide miyopatik patern saptanıyor; kas biyopsisinde PAS boyamasıyla glikojen birikimine rastlanıyor. Hastaya enzim replasman tedavisi başlanması planlanıyor. Bu tedavide kullanılan rekombinan enzimin eksikliğine bağlı olarak, iskelet kası hücrelerinde hangi organel işlev bozukluğu birincil olarak meydana gelir?","options":["Mitokondri","Golgi aygıtı","Peroksizom","Sarkoplazmatik retikulum","Lizozom"],"correct":4,"exp":"Bu tablo Pompe hastalığını (tip II glikojenoz) tanımlamaktadır. Hastalık, lizozomal asit alfa-glukozidaz (GAA) enziminin eksikliğinden kaynaklanır. Enzim replasman tedavisinde kullanılan alglukozidaz alfa da bu enzimin rekombinan formudur. Glikojen lizozomlarda birikir; dolayısıyla birincil organel işlev bozukluğu lizozomaldır. Sarkoplazmatik retikulum kalsiyum depolanmasından, mitokondri enerji üretiminden, peroksizom yağ asidi oksidasyonundan sorumludur; Golgi aygıtı ise bu süreçle doğrudan ilişkili değildir."},{"id":8211,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, ani başlangıçlı göğüs ağrısı ve nefes darlığıyla acil servise getiriliyor. EKG'de ST elevasyonu saptanarak primer perkütan koroner girişim uygulanıyor. Girişimden 4 gün sonra yapılan ekokardiyografide sol ventrikül serbest duvarında psödoanevrizma geliştiği görülüyor. Bu komplikasyonun altta yatan histolojik sürecini en iyi açıklayan kardiyak hücre özelliği hangisidir?","options":["Kardiyomiyositlerin T tübüllerinin aksiyel iletimi yavaşlatması","İnterkalar disklerin gap junction bölgelerinin elektriksel sürekliliği bozması","Kardiyomiyositlerin terminal diferansiyasyon nedeniyle proliferasyon kapasitesinin son derece kısıtlı olması","Miyokardın zengin kapiller ağı nedeniyle kollateral dolaşım kuramaması","Kardiyak fibroblastların ilk 24 saatte miyokite dönüşmesi"],"correct":2,"exp":"Akut miyokard enfarktüsü sonrası serbest duvar rüptürü ve psödoanevrizma gelişiminin temelinde kardiyomiyositlerin terminal diferansiasyona uğramış olması yatar. Bu hücreler fizyolojik koşullarda mitotik kapasitelerini yitirdiğinden, nekroz bölgesini onarabilecek yeni kardiyomiyosit üretemezler. Sonuçta nekrotik doku yerini fibröz dokuya bırakır; bu doku mekanik stresi karşılayamazsa rüptür gelişir. İnterkalar diskler elektriksel iletimi kolaylaştırır, bozamaz. T tübülleri kalsiyum salınımını hızlandırır. Zengin kapiller ağ enfarktüs riskini azaltmaz, enfarktüs oluştuktan sonra rüptürü engellemez."},{"id":8212,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 haftadır sol elinde uyuşma ve 3. ile 4. parmaklarda güçsüzlük yakınmasıyla başvuruyor. Nörolojik muayenede 'pençe el' deformitesi ve hipotenar atrofi saptanıyor. Sinir iletim çalışmalarında ulnar sinirde ileti hızında belirgin yavaşlama ve distal motor latansta uzama tespit ediliyor. Bu bulgular ışığında hastada en çok hangi yapının hasarlanmış olduğu düşünülür?","options":["Endonöryum","Myelin kılıfı","Ranvier boğumları","Akson silindiri","Nöromüsküler kavşak"],"correct":1,"exp":"İletim hızında yavaşlama ve motor latansta uzama, demiyelinizasyon yani myelin kılıfı hasarının klasik elektrofizyolojik bulgularıdır. Aksonal hasarda ise iletim hızı görece korunur, ancak aksiyon potansiyel amplitüdü düşer ve kas atrofisi ön plandadır. Bu hastada hem ileti yavaşlaması hem de latans uzaması myelin patolojisine işaret etmektedir. Ranvier boğumları demiyelinizasyondan ikincil olarak etkilenebilir; ancak primer hasarlanan yapı myelin kılıfıdır. Nöromüsküler kavşak patolojilerinde ileti hızı etkilenmez; tekrarlayan uyarım testinde dekrement beklenir."},{"id":8213,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 1 aydır süren yorgunluk ve çarpıntı yakınmasıyla başvuruyor. Tam kan sayımında Hb: 8,2 g/dL, MCV: 110 fL, periferik yaymada hipersegmente nötrofil saptanıyor. Serum B12 düzeyi düşük bulunarak B12 replasman tedavisi başlanıyor. Tedavinin 5-7. günlerinde beklenen hematolojik yanıtı en iyi gösteren parametre hangisidir?","options":["MCV'nin hızla normale gerilemesi","Hemoglobin düzeyinin normale dönmesi","Serum demir düzeyinin artması","Retikülosit sayısında belirgin artış","Hipersegmente nötrofillerin kaybolması"],"correct":3,"exp":"B12 replasman tedavisinde en erken belirgin hematolojik yanıt, 5-10. günlerde görülen retikülosit artışıdır (retikülosit krizi). Kemik iliğindeki ineffektif eritropoez düzeldikçe olgun eritrositler dolaşıma çıkmaya başlar. Hemoglobin düzeyi haftalar içinde normale döner; MCV'nin düzelmesi ise aylar alır çünkü dolaşımdaki makrositler eritrosit ömrü boyunca (120 gün) kanda kalmaya devam eder. Hipersegmente nötrofiller tedaviden sonra kaybolur, ancak bu retikülosit krizinden daha geç olur. Serum demir düzeyi bu tedaviyle doğrudan ilişkili değildir."},{"id":8214,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, 2 haftadır süren periorbital ödem, hematüri ve azalmış idrar çıkışı yakınmasıyla başvuruyor. 10 gün önce boğaz ağrısı geçirdiği öğreniliyor. Laboratuvarda BUN ve kreatinin yüksek, idrar sedimentinde eritrosit silendirleri saptanıyor. Hastaya uygun tedavi başlanıyor. Bu hastada glomerüler hasarın birincil olarak hangi yapıyı etkilediği düşünülür?","options":["Mezangiyel hücreler","Proksimal tübül hücreleri","Glomerüler bazal membran ve endotel","Podosit ayaksı çıkıntılar (pediküller)","Pariyetal epitel (Bowman kapsülü)"],"correct":2,"exp":"Boğaz enfeksiyonu sonrası gelişen nefritik sendrom tablosu (hematüri, ödem, hipertansiyon, azalmış GFR, eritrosit silendirleri) poststreptokoksik glomerülonefriti düşündürür. Bu hastalıkta immün kompleks birikimi ağırlıklı olarak glomerüler bazal membran ve endotel düzeyinde gerçekleşir; elektron mikroskobisinde subepitelyal 'humplar' görülür, nötrofil infiltrasyonu eşlik eder. Podosit ayaksı çıkıntı kaybı nefrotik sendromun (özellikle minimal değişiklik hastalığı) bulgusudur ve proteinüri ön plandadır. Mezangiyel birikim IgA nefropatisinde tipiktir. Pariyetal epitel proliferasyonu ise hızlı ilerleyen glomerülonefritte yarım ay (crescent) oluşumuna yol açar."},{"id":8215,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Solunum yollarının histolojik yapısı incelendiğinde, trakea ve bronşlarda bulunan psödostratifiye silli kolumnar epitel hakkında aşağıdaki öncüllerden hangileri doğrudur?\nI. Tüm hücreler bazal laminaya temas eder.\nII. Tüm hücreler yüzey lümenine uzanır.\nIII. Goblet hücreleri bu epitelin bileşenlerindendir.\nIV. Siliaların temel görevi mukusu alt solunum yollarına taşımaktır.","options":["II, III ve IV","I, II ve III","I, III ve IV","Yalnız III","I ve III"],"correct":4,"exp":"Psödostratifiye epitelde tüm hücreler bazal laminaya temas eder; bu yüzden 'gerçek' katmanlı epitel değildir (I doğru). Ancak tüm hücreler lumene ulaşmaz; kısa bazal hücreler yüzeye çıkamaz (II yanlış). Goblet hücreleri bu epitelin önemli bir bileşenidir ve müsin salgılar (III doğru). Siliaların görevi ise üretilen mukusü alt değil, üst solunum yollarına (farinkse) doğru taşımaktır; bu mukosiliyer klirensin yönüdür (IV yanlış). Dolayısıyla yalnızca I ve III doğrudur."},{"id":8216,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor sırasında nefes darlığı ve bacaklarda şişlik yakınmasıyla başvuruyor. Özgeçmişinde 10 yıldır hipertansiyon ve tip 2 diabetes mellitus tanısı mevcut. Fizik muayenede juguler venöz distansiyon, bilateral bazal raller ve pretibial ödem saptanıyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %65 olarak ölçülüyor. Bu hastaya sakubitril/valsartan başlanması durumunda temel etki mekanizmasından beklenen hemodinamik değişiklik aşağıdakilerden hangisidir?","options":["Renin-anjiyotensin sistemini uyararak afterload'u azaltır","Beta-1 reseptör blokajı yoluyla kalp hızını düşürür","Natriüretik peptid yıkımını engelleyerek venöz dönüşü azaltır ve dolum basıncını düşürür","Miyokard kontraktilitesini artırarak kardiyak debiyi yükseltir","Aldosteron antagonizması yoluyla potasyum tutucu etki gösterir"],"correct":2,"exp":"Sakubitril, neprilizin enzimini inhibe ederek ANP ve BNP gibi natriüretik peptidlerin yıkımını engeller. Bu peptidler natriürez, diürez ve vazodilatasyon sağlayarak venöz dönüşü ve dolum basıncını (preload) düşürür. Valsartan ise anjiyotensin II tip 1 reseptörünü bloke ederek afterload'u azaltır. Hastanın EF'si korunmuş olduğundan (HFpEF tablosu) kontraktilite artışı hedef değildir; asıl amaç diyastolik dolum basıncını ve semptom yükünü azaltmaktır. Diğer seçenekler sakubitril/valsartan'ın mekanizmasını yanlış tanımlamaktadır."},{"id":8217,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Sinir sistemi hücre biyolojisine ilişkin aşağıdaki öncüller değerlendirilmektedir:\nI. Aksiyon potansiyeli sırasında Na⁺ kanalları inaktive olduktan sonra mutlak refrakter dönemde hiçbir uyaran yeni bir aksiyon potansiyeli oluşturamaz.\nII. Miyelin kılıfı, akson membranı kapasitansını artırarak iletim hızını düşürür.\nIII. Akson terminalinde Ca²⁺ girişi, sinaptik veziküllerin aktif bölgeye docking ve füzyonunu SNARE protein kompleksi aracılığıyla tetikler.\nIV. Oligodendrositlerin hasarında periferik sinir iletim hızı azalırken santral sinir sistemi iletimi korunur.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I, II ve IV","Yalnız I ve III","I, III ve IV","I, II ve III","II, III ve IV"],"correct":1,"exp":"Öncül I doğrudur: mutlak refrakter dönemde Na⁺ kanalları inaktif konumdadır ve hiçbir uyaran yeni aksiyon potansiyeli oluşturamaz. Öncül II yanlıştır: miyelin kılıfı membran kapasitansını AZALTIR (yalıtkan etki), bu sayede saltatory iletimle hız artar; kapasitans artışı hızı düşürürdü. Öncül III doğrudur: Ca²⁺ girişi, sinaptobrevin-SNAP25-sentaksin üçlüsünden oluşan SNARE kompleksini aktive ederek veziküllerin presinaptik membranda ekzositozunu sağlar. Öncül IV yanlıştır: oligodendrosit hasarı SSS miyelinini etkiler (multipl skleroz gibi), periferik sinir miyelinini oluşturan Schwann hücreleridir; dolayısıyla periferik iletim başlangıçta korunabilir."},{"id":8218,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"34 yaşında erkek hasta, 2 yıldır giderek artan efor dispnesi ve tekrarlayan pnömoni atakları yakınmasıyla başvuruyor. Sigara içme öyküsü yok. Yüksek çözünürlüklü akciğer tomografisinde diffüz buzlu cam görünümü ve periferik retiküler opasiteler izleniyor. Bronkoalveolar lavajda PAS pozitif, proteinöz materyal saptanıyor. Serum anti-GM-CSF antikorları pozitif bulunuyor. Bu hastada alveolar makrofaj disfonksiyonunun temel nedeni olan patofizyolojik süreç aşağıdakilerden hangisidir?","options":["GM-CSF sinyalinin baskılanmasıyla alveolar makrofajların sürfaktanı fagosite edip yıkma kapasitesinin bozulması","Surfaktan protein C gen mutasyonu nedeniyle Tip II pnömosit apopitozu","Tip I pnömosit hipertrofisi ile alveoler-kapiller diffüzyon mesafesinin artması","Nötrofil elastaz artışı ile alveoler septum yıkımı","Clara hücresi metaplazisi sonucu surfaktan kompozisyonunun değişmesi"],"correct":0,"exp":"Tabloda tanımlanan hastalık otoimm pulmoner alveoler proteinozistir (PAP). Anti-GM-CSF (granülosit-makrofaj koloni uyarıcı faktör) antikorları, GM-CSF sinyalini nötralize eder. GM-CSF, alveolar makrofajların matürasyonu ve sürfaktanı fagosite edip katabolize etme kapasitesi için zorunludur. Bu sinyal bloke olduğunda alveollerde surfaktan lipoprotein birikimi gerçekleşir, BAS'ta PAS pozitif proteinöz materyal izlenir. Tedavide tam kan lavajı ve rekombinant GM-CSF uygulaması kullanılır. Diğer seçenekler farklı patolojik süreçleri tanımlamaktadır."},{"id":8219,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Hematopoetik sistem histofizyolojisine ilişkin aşağıdaki öncüller değerlendirilmektedir:\nI. Eritropoietin, böbrek peritübüler interstisyel hücrelerinden hipoksi uyarısıyla salgılanır ve kemik iliğinde BFU-E ve CFU-E kolonilerini uyarır.\nII. Trombosit aktivasyonu sırasında alfa granüllerinden fibrinojen, vWF ve P-selektin salınırken yoğun granüllerden ADP ve serotonin salınır.\nIII. Nötrofil olgunlaşmasında miyeloblast → promyelosit → miyelosit aşamasından sonra hücre artık bölünme kapasitesini kaybeder.\nIV. Doğal öldürücü (NK) hücreler CD3 eksprese ederek MHC-I bağımlı mekanizmayla hedef hücreleri öldürür.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["2","1","3","4","Hiçbiri"],"correct":2,"exp":"Öncül I doğrudur: EPO peritübüler interstisyel fibroblast benzeri hücrelerden HIF-1α/HIF-2α aracılığıyla salgılanır; BFU-E ve CFU-E üzerindeki EPOR'u uyarır. Öncül II doğrudur: Trombosit alfa granülleri fibrinojen, vWF, faktör V, P-selektin içerirken yoğun (delta) granüller ADP, ATP, serotonin ve kalsiyum içerir. Öncül III doğrudur: miyelosit aşaması son mitotik bölünmenin gerçekleştiği evredir; metamiyelosit ve sonrası artık bölünmez. Öncül IV yanlıştır: NK hücreler CD3 eksprese etmez (T hücre belirtecidir), MHC-I eksikliğini tanıyarak 'missing self' mekanizmasıyla hedef hücreleri öldürür; bu TCR bağımsız bir süreçtir. Dolayısıyla 3 öncül doğrudur."},{"id":8220,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak ölçülüyor, sol ventrikül end-diastolik basıncı yüksek bulunuyor. Hastaya tedavi olarak bir ilaç başlanıyor; bu ilacın etkisiyle venöz kapasitans damarlarda dilatasyon oluştuğu ve kardiyak preloadun belirgin düştüğü gözlemleniyor. Bu hastaya başlanan ilaç hangisidir?","options":["Karvedilol","Spironolakton","Digoksin","Dopamin","İzosorbid dinitrat"],"correct":4,"exp":"İzosorbid dinitrat bir organik nitrat olup venöz kapasitans damarları dilate ederek venöz dönüşü (preload) azaltır. Bu etki sol ventrikül dolum basıncını düşürür ve kalp yetmezliğinde semptomatik rahatlama sağlar. Digoksin pozitif inotropiktir, karvedilol alfa ve beta blokerdir, spironolakton aldosteron antagonistidir, dopamin ise katekolaminerjik ajandır; hiçbiri birincil mekanizması olarak venöz kapasitans damar dilatasyonuyla preload azaltmaz."},{"id":8221,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, uzun süredir devam eden kuru öksürük ve egzersizle ortaya çıkan nefes darlığı yakınmasıyla başvuruyor. Solunum fonksiyon testlerinde FEV1/FVC oranı normal, TLC artmış, DLCO belirgin azalmış bulunuyor. Yüksek çözünürlüklü toraks BT'de difüz buzlu cam görünümü ve septal kalınlaşma saptanıyor. Bu hastanın akciğer patolojisinde birincil olarak etkilenen yapı hangisidir?","options":["Tip I pnömosit ve alveolo-kapiller membran","Goblet hücreleri","Kıkırdak destekli bronş duvarı","Plevral mezotel","Bronş düz kası"],"correct":0,"exp":"Azalmış DLCO, normal FEV1/FVC oranı ile birlikte TLC artışı ve buzlu cam görünümü; gaz difüzyonunun bozulduğuna işaret eder. Difüzyon kapasitesi alveolo-kapiller membranın kalınlığı ve yüzey alanıyla doğrudan ilişkilidir. Tip I pnömositler bu membranın alveoler yüzeyini oluşturur; interstisyel akciğer hastalıklarında bu hücreler ve alveolo-kapiller membran hasar görür. Goblet hücreleri ve bronş düz kası obstrüktif patolojilerle ilişkilidir, plevral mezotel ise bu tabloya uymaz."},{"id":8222,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında erkek hasta, tip 2 diyabet tanısıyla 10 yıldır takip edilmektedir. Son kontrolünde idrarda albumin/kreatinin oranı 380 mg/g, GFR 42 mL/dk/1,73 m² olarak ölçülüyor. Nefroloji konsültasyonu sonucunda hastaya SGLT-2 inhibitörü başlanıyor. Bu ilacın nefroprotektif etkisini açıklayan birincil mekanizma aşağıdakilerden hangisiyle ilişkilidir?","options":["Proksimal tübülde glikoz ve sodyum reabsorbsiyonunu azaltarak tübüloglomerüler geri beslemeyi yeniden aktive etmesi","Podosit apoptozunu engelleyerek glomerüler bazal membranı güçlendirmesi","Mezangiyel hücre proliferasyonunu doğrudan inhibe etmesi","Henle kulpunda klor reabsorbsiyonunu artırarak medüller hipertonisiteyi düzenlemesi","Toplayıcı tübülde ADH reseptörlerini bloke etmesi"],"correct":0,"exp":"Diyabetik nefropatide hiperglisemi proksimal tübülde sodyum-glikoz ko-transportunu (SGLT-2) aşırı aktive eder; aşırı sodyum reabsorbsiyonu macula densaya ulaşan sodyum miktarını azaltır ve tübüloglomerüler geri besleme mekanizması baskılanır, bu da afferent arteriyol dilatasyonuna ve glomerüler hiperfiltrasyona yol açar. SGLT-2 inhibitörleri bu süreci tersine çevirerek afferent arteriyol tonusunu artırır ve intraglomerüler basıncı düşürür. Diğer seçenekler SGLT-2 inhibitörlerinin primer mekanizmasını yansıtmaz."},{"id":8223,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Sinir sistemindeki miyelinizasyon süreci ve miyelin kılıfını oluşturan hücrelerle ilgili aşağıdaki öncüller değerlendirildiğinde hangileri doğrudur?\nI. Merkezi sinir sisteminde miyelin kılıfı oligodendrositler tarafından oluşturulur ve bir oligodendrosit birden fazla aksonun miyelin kılıfına katkıda bulunabilir.\nII. Periferik sinir sisteminde her Schwann hücresi yalnızca tek bir akson segmentini sarar.\nIII. Ranvier nodları, miyelin kılıfının kesintiye uğradığı bölgeler olup aksiyon potansiyelinin saltatorik iletimini sağlar.\nIV. Miyelinsiz periferik sinir liflerinde Schwann hücreleri tamamen işlevsizdir ve aksonla herhangi bir ilişki kurmaz.","options":["I, II, III ve IV","Yalnız II ve IV","I, II ve III","II, III ve IV","Yalnız I ve III"],"correct":2,"exp":"I. Doğru: Oligodendrositler MSS'de miyelini oluşturur ve her biri birden fazla aksona miyelin sağlayabilir. II. Doğru: PSS'de her Schwann hücresi tek bir internodal aksonu sarar. III. Doğru: Ranvier nodlarında iyon kanalları yoğunlaşmıştır ve aksiyon potansiyeli bu nodlar arasında sıçrayarak saltatorik iletim gerçekleşir. IV. Yanlış: Miyelinsiz periferik sinirlerde Schwann hücreleri aksonları çepeçevre sarmaya devam eder ve Remak bantları oluşturur; tamamen işlevsiz değildir. Dolayısıyla I, II ve III doğru, IV yanlıştır."},{"id":8224,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Mide korpusunda bulunan parietal hücreler ve bu hücrelerin salgı ürünleriyle ilgili aşağıdaki öncüller değerlendirildiğinde kaç tanesi doğrudur?\nI. Parietal hücreler HCl ve intrinsik faktör salgılar.\nII. İntrinsik faktör, B12 vitaminin terminal ileumda emilimi için zorunludur.\nIII. Otoimmün gastritte parietal hücrelere karşı oluşan antikorlar akorhidri ve megaloblastik anemiye yol açabilir.\nIV. HCl salgısı H+/K+-ATPaz pompası aracılığıyla gerçekleşir ve bu pompa proton pompa inhibitörlerinin hedefidir.","options":["1","2","3","0","4"],"correct":4,"exp":"I. Doğru: Parietal hücreler hem HCl hem de intrinsik faktör salgılar. II. Doğru: İntrinsik faktör, besinlerden serbest kalan B12'ye bağlanır ve terminal ileumda reseptör aracılı emilimi sağlar. III. Doğru: Otoimmün gastritte parietal hücre antikorları ve/veya intrinsik faktör antikorları hem asit salgısını hem de B12 emilimini bozar; bu durum akorhlori ve pernisiyöz anemi (megaloblastik anemi) ile sonuçlanır. IV. Doğru: H+/K+-ATPaz (proton pompası) HCl salgısının son basamağını oluşturur ve omeprazol gibi proton pompa inhibitörleri bu pompayı geri dönüşümsüz olarak inhibe eder. Tüm dört öncül doğrudur."},{"id":8225,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, son 2 aydır artan yorgunluk, tekrarlayan enfeksiyonlar ve bacaklarında kendiliğinden oluşan morluklar yakınmasıyla hematoloji polikliniğine başvuruyor. Tam kan sayımında pansitopeni saptanıyor; periferik yaymada blast oranı %2, eritrositler normokrom normositer. Kemik iliği biyopsisinde hücresellik belirgin azalmış, yağ dokusu artmış olarak raporlanıyor. Hastaya antitimosit globulin ve siklosporin kombinasyonu başlanıyor. Bu tedavi rejiminin hastalığın patogenezindeki hangi mekanizmayı hedef aldığını en iyi gösteren ifade aşağıdakilerden hangisidir?","options":["Malign blast klonunun sitotoksik ajanlarla elimine edilmesi","Demir eksikliğinin düzeltilerek yetersiz eritroid öncüllerinin desteklenmesi","Eritropoetin reseptörlerinin duyarlılığının artırılarak eritropoezin uyarılması","Otoreaktif T lenfositlerin hematopoetik kök hücrelere verdiği immün hasarın baskılanması","Megakaryosit olgunlaşmasını engelleyen trombopoetin antagonizminin giderilmesi"],"correct":3,"exp":"Edinsel aplastik anemide CD8+ sitotoksik T lenfositler hematopoetik kök hücrelere saldırır; perforin ve granzimlerin salınması ve Fas-FasL etkileşimi yoluyla kök hücre apoptozunu tetikler. Bu süreç kemik iliğinde hücreselliğin kaybıyla sonuçlanır. Antitimosit globulin (ATG) T lenfositleri elimine ederken siklosporin kalsinörin inhibisyonu yoluyla T hücre aktivasyonunu ve IL-2 üretimini baskılar. Tedavinin hedefi malign bir klon değil, otoimmün T hücre aktivasyonudur; bu nedenle aplastik anemi ile miyelodisplastik sendrom ya da lösemi birbirine karıştırılmamalıdır."},{"id":8226,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, efor sırasında nefes darlığı ve bacaklarda ödem yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya başlanan sakubitril/valsartan tedavisinin etki mekanizması değerlendirildiğinde aşağıdaki öncüller göz önüne alınıyor:\nI. Natriüretik peptid degradasyonunu inhibe ederek natriürez artırır.\nII. Anjiyotensin II reseptörünü bloke ederek afterload'u azaltır.\nIII. Aldosteron sentezini doğrudan inhibe eder.\nYukarıdaki öncüllerden hangileri bu ilacın etkisini doğru açıklar?","options":["I, II ve III","I ve II","II ve III","Yalnız II","Yalnız I"],"correct":1,"exp":"Sakubitril/valsartan, neprilizin inhibisyonu yoluyla BNP ve ANP gibi natriüretik peptidlerin yıkımını azaltır (Öncül I doğru); valsartan bileşeni AT1 reseptörünü bloke ederek afterload azaltır (Öncül II doğru). Aldosteron sentezinin doğrudan inhibisyonu bu ilacın mekanizmasında yer almaz, dolaylı olarak aldosteron düzeyi düşebilir ancak doğrudan sentez inhibisyonu söz konusu değildir (Öncül III yanlış). Dolayısıyla I ve II doğrudur."},{"id":8227,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, 20 paket-yıl sigara öyküsüyle birlikte kronik öksürük ve progresif dispne yakınmasıyla başvuruyor. Spirometride FEV1/FVC: 0,58, FEV1: %48 (beklenenin) saptanıyor. Hastaya uzun etkili muskarinik antagonist (LAMA) başlanıyor. Bu tedavi altında beklenen fizyolojik değişiklikler için aşağıdaki öncüller değerlendirilmektedir:\nI. Bronş düz kasındaki M3 reseptörlerinin blokajıyla hava yolu direnci azalır.\nII. Fonksiyonel rezidüel kapasite ve total akciğer kapasitesi artar.\nIII. Hava yolu hiperreaktivitesini tamamen ortadan kaldırır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["II ve III","I ve III","I, II ve III","I ve II","Yalnız I"],"correct":4,"exp":"LAMA tedavisi M3 reseptörlerini bloke ederek bronkodilatasyon sağlar ve hava yolu direncini azaltır. Hiperinflasyonun azalmasıyla fonksiyonel rezidüel kapasite düşebilir; total akciğer kapasitesinin artması beklenmez. Tedavi hava yolu hiperreaktivitesini tamamen ortadan kaldırmaz. Yalnız I doğrudur."},{"id":8228,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan idrar yolu enfeksiyonu öyküsünün ardından böbrek biyopsisi yapılıyor. Biyopside proksimal tübül hücrelerinin apikal yüzeyinde yoğun mikrovillus yapısı ve bazolateral membranda Na⁺/K⁺-ATPaz ekspresyonunun belirgin olduğu bildiriliyor. Bu yapısal özellikleri taşıyan proksimal tübül hücresinden gerçekleşen taşıma işlemleri düşünüldüğünde, filtre edilen glukozun büyük çoğunluğunun hangi taşıyıcı aracılığıyla geri emildiği ve bu taşıyıcının hangi mekanizmayla çalıştığı sorulduğunda, doğru yanıt hangisidir?","options":["SGLT1 - primer aktif taşıma","SGLT2 - sekonder aktif taşıma (Na⁺ ile birlikte)","GLUT2 - kolaylaştırılmış difüzyon","SGLT2 - primer aktif taşıma","GLUT1 - basit difüzyon"],"correct":1,"exp":"Proksimal tübülde filtre edilen glukozun yaklaşık %90'ı SGLT2 (sodyum-glukoz ko-transporter 2) aracılığıyla geri emilir. SGLT2, Na⁺ gradyanını kullanan sekonder aktif taşıma mekanizmasıyla çalışır; Na⁺ bazolateral membranda Na⁺/K⁺-ATPaz tarafından hücre dışına pompalandığı için oluşan elektrokimyasal gradyan, Na⁺ ile birlikte glukozun lümenden hücre içine taşınmasını sağlar. SGLT2 inhibitörleri (örn. empagliflozin) bu mekanizmayı bloke ederek tip 2 diyabet tedavisinde kullanılır."},{"id":8229,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"28 yaşında erkek hasta, ani başlayan sağ el bilek ekstansiyonu kaybı ve bilek düşüklüğü yakınmasıyla acil servise başvuruyor. Öyküsünden geçirdiği kış gecesi koltukta uyku sonrasında şikayetlerin başladığı öğreniliyor. Nörolojik muayenede bilek ekstansiyonu ve parmak ekstansiyonu kaybı saptanırken el bileği fleksiyonu korunmuş. Bu tabloda etkilen sinir ve hasarın gerçekleştiği düzeyi en doğru tanımlayan seçenek hangisidir?","options":["Radial sinir - spiral kanal düzeyi","Ulnar sinir - kübital tünel düzeyi","Median sinir - karpal tünel düzeyi","Radial sinir - aksilla düzeyi","Median sinir - dirsek düzeyi"],"correct":0,"exp":"Bilek ekstansiyonu (ekstansör karpi radialis) ve parmak ekstansiyonu kaybı, el fleksiyonunun korunması ile birlikte radial sinirin spiral kanal (humerus arka yüzü) düzeyindeki basısına işaret eder. Bu klasik 'Saturday night palsy' tablosudur. Aksilla düzeyinde hasar olsaydı triseps de etkilenerek dirsek ekstansiyonu da kaybedilirdi. Median ve ulnar sinir hasarı bu tabloya uymaz."},{"id":8230,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"22 yaşında kadın hasta, rutin hemogram tetkikinde eritrosit indeksleri inceleniyor. MCV: 72 fL, MCH: 24 pg, MCHC: 31 g/dL, RDW: %18 saptanıyor. Periferik yaymada hipokromik mikrositik eritrositler ve kalem hücreleri (pencil cell) görülüyor. Serum ferritin düzeyi düşük, serum demiri düşük, TDBK yüksek olarak raporlanıyor. Bu hastanın en olası tanısı ve bu durumda kemik iliğinde eritropoez için gerekli olan hangi yapının yetersiz kaldığı sorulduğunda doğru seçenek hangisidir?","options":["Demir eksikliği anemisi - hem sentezi için demir","Kronik hastalık anemisi - transferrin reseptör artışı","Talasemi minör - globin zincir sentezi bozukluğu","Megaloblastik anemi - B12 vitamini eksikliği","Sideroblastik anemi - ALA sentaz enzimi"],"correct":0,"exp":"Hipokromi, mikrositoz, yüksek RDW, düşük ferritin, düşük serum demiri ve yüksek TDBK kombinasyonu demir eksikliği anemisinin klasik bulgularıdır. Kemik iliğinde normoblastların hemoglobin sentezi için gerekli olan hem yapısında demir şarttır; demir yetersizliğinde hem sentezi bozulur, hemoglobin içeriği azalır ve hipokromik mikrositik eritrositler ortaya çıkar. Talasemi minörde RDW genellikle normaldir ve ferritin düşük olmaz."},{"id":8231,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"45 yaşında erkek hasta, uzun süreli alkol kullanım öyküsüyle birlikte kronik karın ağrısı, steatore ve 8 kg kilo kaybı yakınmasıyla başvuruyor. Fekal elastaz düzeyi düşük saptanıyor, görüntülemede pankreas kanalında genişleme ve parankimde kalsifikasyon izleniyor. Hastaya pankreas enzim replasman tedavisi başlanıyor. Bu tedavinin etkili olabilmesi için hangi ortam koşulunun sağlanması kritik öneme sahiptir ve bu koşul sağlanamazsa ne olur?","options":["Mide asidinin tamamen baskılanması gerekir; aksi halde enzimler mide lümeninde parçalanır ve hiç aktif hale gelemez","Mide pH'sının 7'nin üzerinde tutulması gerekir; aksi halde enzimler ince barsakta aktive olamaz","Duodenum pH'sının yaklaşık 6-7 olması gerekir; asidik ortamda lipaz inaktive olur ve yağ sindirimi bozulmaya devam eder","Duodenum pH'sının 5-6 arasında olması gerekir; aksi halde lipaz inaktive olur ve steatore devam eder","Biliyer pH'nın 8'in üzerinde olması gerekir; aksi halde kolipaz aktive olamaz"],"correct":2,"exp":"Pankreatik lipaz, pH 4'ün altında hızla inaktive olur. Kronik pankreatit hastalarında bikarbonat sekresyonu da yetersiz olduğundan duodenuma asidik mide içeriği gelir ve pH yeterince yükselemez. Bu nedenle enzim replasman tedavisinin etkinliği için duodenum pH'sının yaklaşık 6-7 düzeyine ulaşması gerekmektedir; gerektiğinde proton pompa inhibitörü eklenerek mide asidi baskılanır ve lipazın aktif kalacağı ortam sağlanır. Aksi halde steatore ve malnütrisyon devam eder."},{"id":8232,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, efor sırasında ortaya çıkan göğüs ağrısı ve nefes darlığı yakınmasıyla başvuruyor. Yapılan koroner anjiyografide sol ön inen arterde %80 darlık saptanıyor. Hastaya perkütan koroner girişim planlanıyor; işlem öncesinde klopidogrel başlanıyor. Klopidogrelin etki mekanizması düşünüldüğünde bu ilaç aşağıdaki trombosit aktivasyon yolağını inhibe ederek etki gösterir. Buna göre klopidogrel kullanımında hangi laboratuvar bulgusu en doğrudan etkilenir?","options":["Protrombin zamanı uzaması","Fibrinojen düzeyinin düşmesi","Trombin zamanı uzaması","ADP ile indüklenen trombosit agregasyonunun azalması","Kollajen ile indüklenen trombosit agregasyonunun artması"],"correct":3,"exp":"Klopidogrel, P2Y12 reseptörünü irreversibl olarak bloke eden bir tiyenopiridin türevidir. Bu reseptör ADP'nin trombositler üzerindeki birincil hedefidir; blokaj sonucu ADP ile indüklenen trombosit agregasyonu belirgin şekilde azalır. Protrombin zamanı ve trombin zamanı koagülasyon kaskadını yansıtır, klopidogrel bunları doğrudan etkilemez. Fibrinojen düzeyi farklı bir mekanizmayla regüle edilir. Kollajen ile indüklenen agregasyon ise başka yolaklar aracılığıyla gerçekleşir ve klopidogrel tarafından doğrudan inhibe edilmez."},{"id":8233,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 yıldır süregelen progresif dispne ve kuru öksürük yakınmasıyla göğüs hastalıkları polikliniğine başvuruyor. Solunum fonksiyon testlerinde FEV1/FVC oranı %84 (normal), TLC değeri beklenenin %62'si olarak ölçülüyor. Yüksek rezolüsyonlu bilgisayarlı tomografide bilateral bazal retiküler opasiteler ve balpeteği görünümü saptanıyor. Bu hastada patolojik süreçten birincil olarak hangi hücre tipi ve yapı etkilenmektedir?","options":["Tip I pnömositler ve pulmoner kapiller endotel","Goblet hücreleri ve bronşiyal mukoza","Clara (Club) hücreleri ve terminal bronşioller","Tip I pnömositler ve alveolar makrofajlar","Tip II pnömositler ve bazal membran bütünlüğü"],"correct":4,"exp":"İdiyopatik pulmoner fibrozis (IPF) tablosu ile uyumlu olan bu hastada kısıtlayıcı patern (azalmış TLC, korunmuş FEV1/FVC) ve HRCT'deki balpeteği görünümü tanıyı desteklemektedir. IPF'de alveolar epitel hasarı öncelikle Tip II pnömositleri etkiler; bu hücreler surfaktan üretiminden sorumlu olup alveolar epitelin rejenerasyonunu sağlar. Kronik hasar sonucu Tip II pnömosit disfonksiyonu ve bazal membran bütünlüğünün bozulması fibrozis sürecini başlatır. Goblet hücreleri ve Clara hücreleri hava yolu patolojilerinde ön plana çıkar; IPF'nin primer lezyonu hava yolları değil alveoler epitel ve interstisyumdur."},{"id":8234,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 6 aydır ilerleyici yürüyüş bozukluğu, denge kaybı ve ellerde titreme yakınmasıyla nöroloji polikliniğine başvuruyor. Nörolojik muayenede istirahat tremoru, rijidite ve bradikinezi saptanıyor; postüral refleksler bozulmuş. Beyin MR normal olarak değerlendiriliyor. Hastaya levodopa/karbidopa tedavisi başlanıyor ve karbidopa bu kombinasyona ekleniyor. Karbidopa ilavesinin birincil amacı aşağıdakilerden hangisidir?","options":["Levodopanın karaciğerde MAO enzimi tarafından yıkılmasını engellemek","Striatal dopamin reseptörlerinin duyarlılığını artırmak","Kan-beyin bariyerini geçerek striatumda dopamin sentezini artırmak","Periferik DOPA dekarboksilazı inhibe ederek daha fazla levodopanın beyne ulaşmasını sağlamak","Santral sinir sisteminde levodopanın katekolamine dönüşümünü hızlandırmak"],"correct":3,"exp":"Karbidopa periferik L-DOPA dekarboksilaz (aromatik aminoasit dekarboksilaz) enzimini inhibe eden ve kan-beyin bariyerini geçemeyen bir bileşiktir. Levodopa tek başına verildiğinde periferden büyük oranda dopamine dönüştürülür; bu durum hem santrale ulaşan levodopa miktarını azaltır hem de periferik dopamin kaynaklı yan etkilere (bulantı, kardiyak aritmiler) yol açar. Karbidopa bu periferik dönüşümü bloke ederek levodopanın beyne ulaşan oranını artırır ve periferik yan etkileri azaltır. Karbidopa MAO inhibitörü değildir; striatal reseptör duyarlılığını da doğrudan etkilemez."},{"id":8235,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"58 yaşında diyabetik kadın hasta, rutin kontrol için nefroloji polikliniğine başvuruyor. Spot idrarda albümin/kreatinin oranı 380 mg/g olarak saptanıyor; serum kreatinin 1,6 mg/dL, GFR 45 mL/dak. Böbrek biyopsisinde mezangial matriks artışı, bazal membran kalınlaşması ve nodüler glomerüloskleroz (Kimmelstiel-Wilson nodülleri) görülüyor. Bu hastada proteinürinin birincil patogenetik mekanizmasını yansıtan histolojik değişiklik aşağıdakilerden hangisidir?","options":["Parietal epitel hücrelerinin proliferasyonu","Glomerüler bazal membranın anyon yük bariyerinin kaybı ve podosit hasarı","Mezangial hücrelerde lipid birikimine bağlı köpük hücre formasyonu","Afferent arteriyolde fibrinoid nekroz","Tübüler epitel hücrelerinde vakuoler dejenerasyon"],"correct":1,"exp":"Diyabetik nefropatide kronik hiperglisemiye bağlı ileri glikasyon son ürünleri (AGE) ve hemodinamik stres glomerüler bazal membranın yapısal değişikliğine yol açar. Normalde negatif yüklü olan GBM'nin anyon bariyeri bozulur ve podositler hasar görür; podosit kaybı ile filtrasyon yarıklarının bozulması albüminin idrarla kaybedilmesine neden olur. Kimmelstiel-Wilson nodülleri diyabetik nefropatinin karakteristik bulgusudur ancak proteinürinin doğrudan patogenetik substratı GBM yük bariyeri hasarı ve podosit disfonksiyonudur. Diğer seçenekler farklı glomerülonefrit veya vasküler patoloji tablolarını yansıtır."},{"id":8236,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 3 haftadır süren ateş, gece terlemesi ve boyun ile aksillada ele gelen ağrısız kitleler nedeniyle hematoloji polikliniğine başvuruyor. Lenfoma ön tanısıyla alınan lenf nodu biyopsisinde Reed-Sternberg hücreleri ve çevreleyen reaktif hücre infiltrasyonu görülüyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Reed-Sternberg hücreleri CD15 ve CD30 eksprese eder.\nII. Bu tümör hücreleri B lenfosit kökenlidir.\nIII. Klasik Hodgkin lenfomada tümör hücreleri genellikle CD45 (lökosit ortak antijeni) pozitiftir.\nIV. EBV enfeksiyonu, Hodgkin lenfoma gelişiminde rol oynayan bir etiyolojik faktördür.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["4","1","Hiçbiri","3","2"],"correct":3,"exp":"Öncül I doğrudur: Reed-Sternberg hücreleri klasik olarak CD15 ve CD30 eksprese eder; bu belirteçler tanıda kullanılır. Öncül II doğrudur: Klasik Hodgkin lenfomadaki Reed-Sternberg hücreleri germinal merkez B lenfosit kökenlidir; ancak BCR ekspresyonu kaybedilmiştir. Öncül III yanlıştır: Reed-Sternberg hücreleri CD45 negatiftir; bu durum reaktif lenfositlerden ayırt edilmelerinde önemli bir özelliktir. Öncül IV doğrudur: EBV, özellikle mikst selülarite alt tipinde Reed-Sternberg hücrelerinde saptanır ve etiyolojide rol oynayan başlıca viral faktördür. Buna göre doğru öncüller I, II ve IV olup 3 tanesi doğrudur."},{"id":8237,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Midenin korpus ve fundus bölgesindeki oksintik bezlerde yer alan parietal hücreler, proton pompası inhibitörleri (PPI) ile inhibe edilmektedir. Buna göre parietal hücrelerin fizyolojik işlevi ve PPI kullanımına bağlı gelişmesi beklenen durum hangisidir?","options":["Mukus ve bikarbonat salgılayarak mide epitelini korur; PPI kullanımında ülser riski artar","Pepsinojen salgılayarak proteolitik aktivasyon sağlar; PPI kullanımında mide boşalması hızlanır","HCl ve intrinsik faktör salgılar; PPI kullanımında B12 vitamini emilimi bozulabilir","Somatostatin salgılayarak asit sekresyonunu inhibe eder; PPI kullanımında gastrin düzeyi düşer","Gastrin salgılayarak parietal hücre aktivasyonunu uyarır; PPI kullanımında hipergastrinemi gelişir"],"correct":2,"exp":"Parietal hücreler iki temel ürün salgılar: H+/K+-ATPaz aracılığıyla mide lümenine HCl ve B12 vitamini emilimi için gerekli olan intrinsik faktör. PPI'lar H+/K+-ATPaz enzimini irreversibl bloke ederek asit sekresyonunu baskılar; bu etki HCl üretimini azaltırken intrinsik faktör sekresyonunu da olumsuz etkileyebilir. Uzun süreli PPI kullanımında mide pH'ının yükselmesi B12 vitaminin protein bağından ayrılmasını zorlaştırır ve intrinsik faktör sekresyonunun azalmasıyla birlikte B12 emilimi bozulabilir. Pepsinojen ise parietal hücreler tarafından değil, ağırlıklı olarak baş (chief) hücreleri tarafından salgılanır."},{"id":8238,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve son 2 haftadır artan nefes darlığı yakınmasıyla başvuruyor. Özgeçmişinde 15 yıllık hipertansiyon ve tip 2 diyabet öyküsü mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35, sol ventrikül duvar kalınlığı artmış ve diyastolik disfonksiyon tespit ediliyor. Hastaya ivabradine başlanıyor. Bu ilacın bu hastadaki birincil etkisi hangisidir?","options":["L-tipi kalsiyum kanallarını bloke ederek miyokardiyal kontraktiliteyi düşürmek","Sinoatriyal düğümde If akımını inhibe ederek kalp hızını azaltmak","HCN kanallarını aktive ederek diyastolik depolarizasyonu hızlandırmak","Renin sekresyonunu baskılayarak afterloadu azaltmak","Beta-1 reseptörlerini antagonize ederek sempatik tonusu kırmak"],"correct":1,"exp":"İvabradine, sinoatriyal düğümdeki funny akım kanallarını (If / HCN kanalları) inhibe ederek spontan diyastolik depolarizasyonu yavaşlatır ve böylece kalp hızını düşürür. Ejeksiyon fraksiyonu düşük olan bu hastada hız kontrolü diastolik dolum süresini uzatarak kardiyak outputu destekler. İvabradine miyokard kontraktilitesini, iletim sisteminin diğer bölümlerini ve periferik vasküler direnci etkilemez; bu yönüyle beta blokerlerden ayrışır. Seçenek E tersini tanımladığından yanlıştır."},{"id":8239,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 6 aydır süren kuru öksürük, egzersiz dispnesi ve tekrarlayan pnömotoraks atakları yakınmasıyla başvuruyor. Bilinen herhangi bir sistemik hastalığı yok, sigara kullanmıyor. Yüksek çözünürlüklü bilgisayarlı tomografide her iki akciğerde ince duvarlı, diffüz kistik lezyonlar saptanıyor. Serum VEGF-D düzeyi belirgin yüksek. Kesin tanı için yapılan akciğer biyopsisinde HMB-45 pozitif iğsi hücreler görülüyor. Bu hastanın hastalığının patogenezinde işlev kazanımı (gain-of-function) mutasyonu olan gen hangisidir?","options":["KRAS","TSC1 / TSC2","BRAF","NF1","EGFR"],"correct":1,"exp":"Lenfanjiyoleiomiyomatozis (LAM), TSC1 (hamartin) veya TSC2 (tüberin) genlerindeki inaktive edici mutasyonlar sonucu mTOR yolağının kontrolsüz aktivasyonuyla ortaya çıkar. Normalde hamartin-tüberin kompleksi mTOR'u inhibe eder; bu genlerin kaybı mTOR'u sürekli aktif kılar (mTOR yolağı açısından fonksiyon kaybı mutasyonu, ancak proliferatif sinyal açısından etkili fonksiyon kazanımı). HMB-45 pozitifliği, serum VEGF-D yüksekliği ve genç kadında diffüz akciğer kistleri LAM için tanı koydurucu üçlüdür. mTOR inhibitörü sirolimus bu hastalığın tedavisinde kullanılmaktadır."},{"id":8240,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 3 aydır süren ilerleyici yürüme güçlüğü, sık düşme ve çift görme yakınmasıyla başvuruyor. Nörolojik muayenede sakkadik göz hareketleri, başı geriye doğru düşme eğilimi (retroflexi) ve aksiyel rijidite saptanıyor. MR'da mezensefalon atrofisi ve 'penguen silueti' görünümü izleniyor. DAT-SPECT normalin altında tespit ediliyor. Bu hastaya levodopa/karbidopa başlanmasına karşın belirtiler belirgin düzelmiyor. Bu tedaviye yanıtsızlığın en olası açıklaması hangisidir?","options":["Levodopanın kan-beyin bariyerini geçememesi","Substantia nigra'daki dopaminerjik nöronların henüz yeterince hasar görmemiş olması","Dopamin reseptörlerinin aşırı duyarlılık gelişmesi sonucu downregüle olması","Striatonigrayal yolun yanı sıra striatofrontal ve striatopallidal yolların da etkilenmesi nedeniyle postsinaptik dopaminerjik reseptörlerin işlevsiz olması","Kolin esteraz enzim aktivitesinin artarak dopaminin metabolizmasını hızlandırması"],"correct":3,"exp":"Progresif supranükleer palsi (PSP), mezensefalon atrofisi, aksiyel rijidite, retroflexi ve sakkadik göz hareketleriyle karakterize bir 4-tekrarlı tau (4R-tau) tauopatisidir. Levodopa yanıtsızlığı, patolojinin yalnızca substantia nigra ile sınırlı olmamasından kaynaklanır: bazal gangliyonların çıkış yolları (globus pallidus interna, striatum) ve frontal kortikal projeksiyonlar da etkilendiğinden postsinaptik D1/D2 reseptörler işlevsizdir. Dolayısıyla öncü madde ne kadar artırılırsa artırılsın anlamlı klinik yanıt alınamaz."},{"id":8241,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbreğin proksimal tüpünde gerçekleşen aşağıdaki taşıma olaylarına ilişkin;\nI. Glukoz geri emilimi SGLT2 taşıyıcısı aracılığıyla sodyuma bağımlı olarak gerçekleşir.\nII. Bikarbonat geri emilimi lümende karbonik anhidraz aracılı CO2 üretimiyle başlar.\nIII. Amino asit geri emilimi pasif diffüzyon yoluyla sağlanır.\nIV. Fosfor geri emilimi parathormon tarafından artırılır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","3","4","1","2"],"correct":4,"exp":"I. Doğru: Proksimal tübülde glukoz, apikal membranda Na+-glukoz kotransportörü SGLT2 aracılığıyla lümenden hücre içine, bazolateral membranda GLUT2 ile interstisyuma geçer. II. Doğru: Lümene salgılanan H+ iyonu HCO3- ile birleşerek H2CO3 oluşturur; lüminal karbonik anhidraz (tip IV) bunu CO2 ve H2O'ya çevirir, CO2 hücreye diffüze olur ve intraselüler karbonik anhidraz (tip II) ile tekrar HCO3- üretilir. III. Yanlış: Amino asitler, Na+'a bağımlı sekonder aktif taşıyıcılar (çeşitli SLC aileleri) aracılığıyla aktif olarak geri emilir. IV. Yanlış: PTH, proksimal tübülde NaPi-IIa taşıyıcısını içselleştirerek fosfor geri emilimini AZALTIR ve fosfatüriyi artırır. Doğru öncül sayısı: I ve II → 2."},{"id":8242,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 2 haftadır süren halsizlik, ciltte peteşi ve diş eti kanaması yakınmasıyla başvuruyor. Tam kan sayımında hemoglobin 9,2 g/dL, lökosit 3.400/mm³, trombosit 18.000/mm³ saptanıyor. Periferik yaymada blast hücre görülmüyor, eritrositler normokrom normositer. Retikülosit sayısı beklentinin altında. Kemik iliği biyopsisinde hiposellüler ilik, yağ dokusu artışı ve hematopoetik öncü hücrelerde belirgin azalma görülüyor. Bu hastada aşağıdaki tedavilerden hangisi uygulanırsa kemik iliğinde CD34+ hücre havuzunun uzun vadede en kalıcı biçimde yenilenmesi beklenir?","options":["HLA-uyumlu kardeşten allojenik kök hücre transplantasyonu","Yüksek doz metilprednizolon","Rekombinant eritropoetin ve G-CSF kombinasyonu","Eltrombopag monoterapisi","Antitimosit globulin ve siklosporin kombinasyonu"],"correct":0,"exp":"Aplastik anemi tanısı konan bu hastada kemik iliğindeki CD34+ hematopoetik kök hücre havuzunu kalıcı olarak yenileyebilecek tek tedavi allojenik hematopoetik kök hücre transplantasyonudur. HLA-uyumlu kardeş donörden yapılan transplantasyon, genç hastalarda uzun dönem hastalıksız sağkalım açısından altın standarttır ve yeni bir kök hücre havuzu sağladığından hastalık kürlenebilir. Antitimosit globulin + siklosporin immünsupresif tedavisi otoimmün bileşeni baskılar ve kalıcı yanıt verebilir ancak transplantasyon kadar güçlü kök hücre yenilenmesi sağlamaz. G-CSF ve eritropoetin mevcut progenitörleri uyarır fakat hiposellüler ilikte yeterli progenitör olmadığından etkisi sınırlıdır. Eltrombopag trombopoietin reseptörü agonistidir ve plastisite üzerinden kısmi yanıt verebilir ancak uzun vadeli kür sağlamaz."},{"id":8243,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"61 yaşında erkek hasta, 4 aydır süren ishal, yüz kızarması (flushing) ve nefes darlığı yakınmasıyla başvuruyor. Fizik muayenede triküspid kapakta regürjitasyon üfürümü ve hepatomegali saptanıyor. 24 saatlik idrarda 5-hidroksiindolasetik asit (5-HIAA) düzeyi belirgin yüksek. Oklüzif bir lezyonun hangi anatomik konumda olduğu bu klinik tablonun ortaya çıkmasında kritik önem taşır?","options":["Akciğer","İnce barsak mezenterik lenf nodları","Pankreas","Karaciğer","Adrenal medulla"],"correct":3,"exp":"Karsinoid sendrom, serotonin ve diğer vazoaktif maddelerin sistemik dolaşıma geçmesiyle ortaya çıkar. Barsak kaynaklı karsinoid tümörlerden salgılanan serotonin, portal dolaşım yoluyla karaciğere ulaştığında büyük ölçüde metabolize edilir ve sistemik belirtiler görülmez. Ancak karaciğerde okluzyona yol açan metastazlar varlığında (tıkayıcı hepatik metastazlar) serotonin sistemik dolaşıma direkt geçer ve klasik karsinoid sendrom tablosu (flushing, ishal, sağ kalp valvülopati) belirginleşir. Sağ kalp tutulumu ise pulmoner dolaşımda serotoninin akciğerlerde inaktive edilmesi nedeniyle sol kalbi genellikle koruduğunu gösterir. Bu nedenle kritik anatomik konum karaciğerdir."},{"id":8244,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, ağır egzersiz sonrası gelişen koyu renkli idrar ve kas ağrısı yakınmasıyla acile başvuruyor. Serum kreatin kinaz düzeyi 18.000 U/L, miyoglobin pozitif, idrar çıkışı 25 mL/saat olarak saptanıyor. Hastaya agresif IV hidrasyon başlanıyor. Bu hastada akut böbrek hasarına yol açan temel patolojik süreçte, miyoglobinin hangi bölgede birikimi proksimal tübül nekrozunu tetikler?","options":["Toplayıcı kanalda AQP-2 ekspresyonunu baskılayarak osmotik dengeyi bozarak","Jukstaglomerüler aparatta renin salınımını artırarak vazokonstriksiyon oluşturarak","Henle kulpunun ince çıkan kolunda tübüler tıkaç oluşturarak","Proksimal tübül hücrelerinde demir aracılı oksidatif hasar ve vakuolar dejenerasyon yaparak","Glomerüler bazal membrana çökerek filtrasyon bariyerini doğrudan tahrip ederek"],"correct":3,"exp":"Rabdomiyoliz tablosunda serbest miyoglobin, proksimal tübül hücrelerine girerek hem grubundan açığa çıkan serbest demir aracılığıyla Fenton reaksiyonu üzerinden reaktif oksijen türleri üretir. Bu oksidatif hasar mitokondriyal membran potansiyelini çökerterek proksimal tübül hücrelerinde vakuolar dejenerasyon ve nekroza yol açar. Ayrıca miyoglobin, asidik idrarda Tamm-Horsfall proteini ile presipite olarak distal tübülde tıkaç oluşturur; ancak oksidatif hasar mekanizması proksimal tübül nekrozunun asıl nedenidir. Diğer seçenekler miyoglobin toksisitesinin anatomik ve moleküler hedefini yanlış tanımlamaktadır."},{"id":8245,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, anjina pektoris nedeniyle kardiyoloji kliniğine yatırılıyor. Koroner anjiyografide LAD'da %85 darlık saptanıyor. Hastaya ivabradin başlanarak kalp hızı 58/dk'ya düşürülüyor. İvabradinin etki mekanizması göz önünde bulundurulduğunda, sinüs düğümü hücrelerinde hangi iyon akımı üzerinden kalp hızı azalması sağlanmaktadır?","options":["Geç Na+ akımını (INaL) bloke ederek aksiyon potansiyeli süresini uzatır","Funny akımını (If) bloke ederek diastolik depolarizasyon eğimini azaltır","Hızlı Na+ kanallarını bloke ederek 0. faz yükselmesini yavaşlatır","IKr kanallarını inhibe ederek repolarizasyon fazını uzatır","L-tipi Ca²+ kanallarını bloke ederek eşik potansiyeline ulaşmayı geciktirir"],"correct":1,"exp":"İvabradin, sinüs düğümü hücrelerinde HCN (hyperpolarization-activated cyclic nucleotide-gated) kanalları aracılığıyla taşınan funny akımını (If) seçici olarak bloke eder. If akımı, 4. fazda spontan diastolik depolarizasyonu sağlayan karma katyon akımıdır; bu akımın baskılanması eğimi azaltarak bir sonraki aksiyon potansiyeline ulaşma süresini uzatır ve kalp hızını düşürür. İvabradin negatif kronotropik etki gösterirken inotrop etki yapmaz, kan basıncını ve iletim sisteminin diğer bölgelerini etkilemez. Diğer seçenekler ivabradinin hedef kanalını yanlış tanımlamaktadır."},{"id":8246,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 20 yıldır süregelen KOAH tanısıyla takip edilmektedir. Son 2 haftadır artan nefes darlığı ve bacak ödemi nedeniyle başvuruyor. Fizik muayenede JVD (+), hepatojugüler reflü (+), bilateral alt ekstremite ödemi, siyanoz ve parmaklarda çomaklaşma saptanıyor. EKG'de sağ aks deviasyonu ve P pulmonale görülüyor. Bu hastada gelişen patofizyolojik süreçte aşağıdaki öncülleri değerlendiriniz:\nI. Kronik hipoksemi, pulmoner vasküler düz kas hücrelerinde Kv kanallarını baskılayarak depolarizasyona ve vazokonstriksiyona yol açar.\nII. Hipoksik pulmoner vazokonstriksiyon başlangıçta reversibldır; ancak kalıcı yapısal remodeling ile irreversibla dönüşür.\nIII. Pulmoner hipertansiyon gelişiminde endotelin-1 azalır, nitrik oksit artar.\nIV. Sağ ventrikül hipertrofisi, artan afterload'a karşı kompansatuar bir yanıttır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["4","2","1","3","Hiçbiri"],"correct":3,"exp":"I. DOĞRU: Kronik hipoksemide pulmoner vasküler düz kas hücrelerinde voltaj kapılı potasyum kanalları (Kv) baskılanır, bu durum hücre içi K+ azalmasına, membran depolarizasyonuna ve L-tipi Ca²+ kanallarının açılmasına yol açarak vazokonstriksiyon oluşturur. II. DOĞRU: Akut hipoksik pulmoner vazokonstriksiyon başta reversibldir; kronik süreçte düz kas hipertrofisi, intimada fibroblast proliferasyonu ve ekstrasellüler matriks birikimi ile irreversible yapısal remodeling gelişir. III. YANLIŞ: Pulmoner hipertansiyon gelişiminde endotelin-1 artar (vazokonstriktör ve mitojenik etki), nitrik oksit (vazodilatör) ise azalır. IV. DOĞRU: Artan pulmoner vasküler rezistans, sağ ventrikül afterload'unu artırır; sağ ventrikül buna karşı önce hipertrofi, ardından dilatasyon ile yanıt verir. Dolayısıyla I, II ve IV doğru; III yanlış olduğundan 3 öncül doğrudur."},{"id":8247,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbrekte proksimal tübül hücreleri, glomerüler filtrattan glukozu reabsorbe ederken SGLT-2 taşıyıcısını kullanır. Tip 2 diyabetes mellitus tedavisinde kullanılan SGLT-2 inhibitörleri (örneğin empagliflozin) bu taşıyıcıyı bloke ettiğinde aşağıdakilerden hangisi beklenmez?","options":["Toplayıcı kanalda AQP-2 ekspresyonunun artması","Hafif ozmotik diürez gelişmesi","Serum glukoz düzeyinin düşmesi","İdrarda glukoz atılımının artması","Proksimal tübülde Na+ reabsorbsiyonunun azalması"],"correct":0,"exp":"SGLT-2, proksimal tübülün S1-S2 segmentlerinde Na+ ile birlikte glukozu reabsorbe eden sodyum-glukoz ko-taşıyıcısıdır. SGLT-2 inhibisyonu ile glukoz ve Na+ reabsorbsiyonu azalır; tübüler sıvıda kalan glukoz ozmotik diüreze yol açar ve idrarda glukoz atılımı artar, dolayısıyla kan şekeri düşer. Proksimal tübülde Na+ reabsorbsiyonu azaldığından tübülogomerüler geri bildirim aktive olur ve afferent arteriol daralır. Bu süreçte toplayıcı kanalda AQP-2 ekspresyonunun artması beklenmez; aksine ozmotik diürez nedeniyle ADH-bağımlı su geri alımı azalır ve AQP-2 ekspresyonu azalır ya da değişmez. Dolayısıyla 'toplayıcı kanalda AQP-2 ekspresyonunun artması' beklenen bir etki değildir."},{"id":8248,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, ani gelişen çift görme, sağ el bileğinde güçsüzlük ve denge bozukluğu yakınmalarıyla nöroloji polikliniğine başvuruyor. Öyküsünde 8 ay önce geçici görme kaybı atağı geçirdiği ve kendiliğinden düzeldiği öğreniliyor. MRG'de periventriküler ve juxtakortikal beyaz cevher alanlarında T2/FLAIR hiperintens lezyonlar izleniyor. BOS analizinde oligoklonal bant pozitif, IgG indeksi yüksek bulunuyor. Bu hastalığın patogenezinde santral sinir sistemindeki hasara yol açan birincil hedef yapı hangisidir?","options":["Akson membranında voltaj kapılı Na+ kanalları","Ranvier nodları arasındaki paranodal bölge proteinleri","Nöronal hücre gövdeleri (perikaryon)","Schwann hücreleri ve periferik miyelin","Miyelin kılıfı ve oligodendrosit hücreleri"],"correct":4,"exp":"çok sayıda skleroz (MS), santral sinir sisteminde miyelin kılıfını ve miyelin üreten oligodendrositleri hedef alan otoimmün inflamatuvar bir demiyelinizan hastalıktır. T hücre aracılı immün yanıt, kan-beyin bariyerini geçerek oligodendrositlere ve miyelin bileşenlerine (MBP, MOG, PLP) karşı oluşur. Demiyelinizasyon, aksiyon potansiyelinin saltatory iletimini bozarak ileti hızının azalmasına veya tamamen kesilmesine yol açar. Schwann hücreleri periferik sinir sistemine ait olup MS'de birincil hedef değildir. Nöronal hücre gövdesine hasar hastalığın ilerleyen dönemlerinde ortaya çıkar ve ikincildir. MS tanısında McDonald kriterleri (zamanda ve mekânda yaygınlık) kullanılır; bu vakada iki farklı atak ve multifokal lezyon dağılımı bu kriterleri karşılamaktadır."},{"id":8249,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"52 yaşında erkek hasta, 6 aydır süregelen halsizlik, gece terlemesi ve kilo kaybı yakınmalarıyla başvuruyor. Fizik muayenede dalak 4 cm palpabl, karaciğer 2 cm palpabl. Tam kan sayımında lökosit 85.000/mm³ (granülositik seri ağırlıklı), trombosit 620.000/mm³, Hb 10,2 g/dL saptanıyor. Periferik yaymada tüm olgunlaşma evrelerinde granülositler izleniyor. Kemik iliği biyopsisinde hiperselülarite mevcut. BCR-ABL1 füzyon geni pozitif bulunuyor. Bu hastada BCR-ABL1 onkoproteininin artırdığı tirozin kinaz aktivitesi sonucunda hangi sinyal yolağı sürekli aktif kalarak apoptozun baskılanmasına yol açar?","options":["MAPK/ERK yolağı üzerinden hücre proliferasyonunu azaltır","PI3K/AKT/mTOR yolağını aktive ederek BAD'ı fosforile eder ve Bcl-2 aracılı apoptozu baskılar","NF-κB yolağını baskılayarak inflamatuvar sinyali azaltır","JAK/STAT3 yolağını inhibe ederek sitokin bağımsız büyümeyi engeller","Wnt/β-katenin yolağını kapatarak farklılaşmayı durdurur"],"correct":1,"exp":"Kronik miyeloid lösemi (KML), t(9;22) translokasyonu sonucu oluşan Philadelphia kromozomunda BCR-ABL1 füzyon onkogeninin ürünü olan BCR-ABL1 tirozin kinazı ile karakterizedir. Bu tirozin kinazın sürekli aktif kalması, PI3K/AKT/mTOR sinyal yolağını aktive eder. AKT, pro-apoptotik protein BAD'ı fosforile ederek 14-3-3 proteinine bağlanmasını sağlar; böylece BAD, Bcl-2 ve Bcl-xL'yi serbest bırakır ve bu anti-apoptotik proteinler mitokondriyal apoptozu baskılar. Aynı zamanda MAPK/ERK ve JAK/STAT5 yolakları da BCR-ABL1 tarafından aktive edilir (STAT3 değil, STAT5 primer hedef). İmatinib gibi tirozin kinaz inhibitörleri BCR-ABL1'i bloke ederek bu yolakları inhibe eder ve apoptozu yeniden aktive eder."},{"id":8250,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, progresif proksimal kas güçsüzlüğü ve egzersiz intoleransı şikayetiyle başvuruyor. Aile öyküsünde babasının 40'lı yaşlarda 'kalp yetmezliği'nden öldüğü öğreniliyor. EMG'de miyopatik patern saptanıyor, kas biyopsisinde PAS pozitif granüller ve lizozomal şişme izleniyor. Enzim replasman tedavisi başlanan hastada tedavinin hangi yapıyı hedef aldığı düşünüldüğünde, bu yapının aynı zamanda hangi işlev için de kritik öneme sahip olduğu söylenebilir?","options":["Miyozin başlarının aktine bağlanma döngüsü","Miyofibril içi ATP üretimi","Sarkomerik yapının protein sentezi ile yenilenmesi","Glikojen yıkımı ile glikoz-1-fosfat sağlanması","Kas kontraksiyonu için gerekli kalsiyum depolaması"],"correct":3,"exp":"Bu hastada Pompe hastalığı (glikojen depo hastalığı tip II) söz konusudur. Kas biyopsisinde PAS pozitif lizozomal granüller ve enzim replasman tedavisine (alglukozidaz alfa) yanıt, lizozomal asit alfa-glukozidaz (GAA) enzim eksikliğini işaret eder. GAA, lizozomlar içinde glikojeni glikoz-1-fosfata değil, doğrudan glikoza yıkan enzimdir; ancak kritik olan nokta, iskelet ve kardiyak kasta lizozomal glikojen birikiminin hem miyofibril bütünlüğünü hem de hücre içi enerji dengesini bozmasıdır. Soru 'hangi yapıyı hedef alıyor' derken lizozomları kastetmekte, bu yapının kritik işlevi ise hücre içi glikojen katabolizmasıdır. Diğer şıklar sarkoplazmatik retikulum, mitokondri veya miyofibrille ilgili olup bu hastalığın patogenezinde merkezi rol oynamaz."},{"id":8251,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 6 aydır devam eden efor dispnesi ve bacaklarda ödem yakınmasıyla kardiyoloji polikliniğine başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30 olarak ölçülüyor, biventriküler dilatasyon ve mitral yetersizliği saptanıyor. Hastaya nörohormonal blokaj amacıyla bir ilaç grubu ekleniyor; bu ilaçların kullanımıyla birlikte miyokard biyopsisinde kardiyomiyosit hipertrofisinin gerilediği ve ekstraselüler matriks yeniden yapılanmasının normalize olduğu gösterilmiştir. Bu hastada başlanan tedavinin etkisini en iyi açıklayan kardiyomiyosit özelliği hangisidir?","options":["Kardiyomiyositlerin mitokondriyal oksidatif fosforilasyonu azaltarak glikolize geçmesi","Kardiyomiyositlerin T-tübül sistemi ile sarkoplazmatik retikulumdan kalsiyum salınımını artırması","Kardiyomiyositlerin terminal diferansiye hücreler olarak hipertrofi ile iş yüküne yanıt vermesi","Kardiyomiyositlerin gap junction proteinleri olan konneksinleri aşırı eksprese etmesi","Kardiyomiyositlerin interkale diskler aracılığıyla elektriksel senkronizasyon sağlaması"],"correct":2,"exp":"Dilate kardiyomiyopatide kalp, artan duvar stresi ve nörohormonal aktivasyona (renin-anjiyotensin-aldosteron, sempatik sistem) yanıt olarak kardiyomiyosit hipertrofisi ve patolojik yeniden yapılanma (remodeling) geliştirir. Kardiyomiyositler terminal diferansiye hücreler olduğundan prolifere olamaz; iş yükü artışına yalnızca hipertrofi ile yanıt verebilir. Beta blokerler ve ACE inhibitörleri/ARB'ler bu nörohormonal aktivasyonu baskılayarak patolojik hipertrofiyi ve fibrozisi geriletir; buna 'reverse remodeling' denir. Diğer şıklar kardiyomiyosit fizyolojisinin gerçek yönlerini içerse de sorulan tedavi etkisiyle en doğrudan ilişkili olan seçenek B'dir."},{"id":8252,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında diyabetik kadın hastada nefrotik düzeyde proteinüri ve pretibial ödem saptanıyor. Renal biyopside glomerüler bazal membranda diffüz kalınlaşma ve mezangial matriks artışı izleniyor. Diyabetik nefropatide görülen bu mezangial matriks artışından birincil olarak sorumlu mediyatör aşağıdakilerden hangisidir?","options":["TGF-β aşırı ekspresyonu","İnterlökin-2 salınımı","Eritropoetin eksikliği","Paratiroid hormon artışı","Endotelyal nitrik oksit sentaz aktivasyonu"],"correct":0,"exp":"Diyabetik nefropatide kronik hiperglisemi mezangial hücrelerde TGF-β ekspresyonunu artırır; TGF-β, kollajen ve fibronektin gibi ekstrasellüler matriks proteinlerinin aşırı üretimine yol açarak mezangial matriks genişlemesi ve bazal membran kalınlaşmasına neden olur. Bu süreç Kimmelstiel-Wilson nodüllerinin de temelini oluşturur."},{"id":8253,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"24 yaşında kadın hasta, 2 haftadır devam eden sağ gözde ağrılı görme kaybı ve renk ayrımında bozulma şikayetiyle başvuruyor. Nörolojik muayenede afferent pupiller defekt saptanıyor. MR'da optik sinirde T2 hiperintensitesi izleniyor, BOS analizinde oligoklonal bant pozitif bulunuyor. Yüksek doz IV kortikosteroid tedavisi başlanan hastanın şikayetlerinin hızla düzeldiği gözlemleniyor. Bu klinik tabloda kortikosteroidlerin primer etkisini açıklayan yapısal özellik hangisidir?","options":["Akson boyunca sodyum kanalı yeniden dağılımını kortikosteroidlerin düzenleyerek iletimi restore etmesi","Merkezi sinir sistemindeki inflamasyon ve ödemi baskılayarak iletim bloğunu geçici olarak çözmesi, ancak miyelin rejenerasyonunu doğrudan uyarmaması","Schwann hücrelerinin periferik sinirlerde miyelin oluşturması ve steroidlerin bu hücreleri uyarması","Oligodendrositlerin her biri çok sayıda aksonu sarması nedeniyle steroid tedavisiyle hızla yeniden myelinizasyon sağlanması","Merkezi sinir sisteminde miyelin kılıfının oligodendrosit uzantılarından oluşması ve bu hücrelerin steroid tedavisine bağlı proliferasyonu"],"correct":1,"exp":"Bu hastada multipl skleroz (MS) atağı, optik nörit ile prezente olmaktadır. MS'de SSS'de oligodendrositlerin oluşturduğu miyelin kılıfı, inflamatuvar T hücre aracılı saldırıya uğrar. Yüksek doz IV metilprednizolon, miyelin rejenerasyonunu sağlamaz; temel etkisi kan-beyin bariyerini stabilize etmek, T lenfosit geçişini azaltmak ve lokal ödemi ve inflamasyonu baskılamaktır. Bu sayede iletim bloğu geçici olarak çözülür ve semptomlar hızla düzelir, ancak hastalığın uzun dönem seyrini değiştirmez. Oligodendrositlerin aksonu sardıkları doğrudur (bir oligodendrosit 20-30 akson segmentini sarabilir), ancak steroidlerin yeniden myelinizasyon sağladığı kanıtlanmamıştır. Periferik sinirde miyelin Schwann hücrelerinden kaynaklanır; optik sinir SSS uzantısı olduğundan Schwann hücresi içermez."},{"id":8254,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Tip II pnömositlere ilişkin aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Tip II pnömositler alveoler yüzeyin büyük bölümünü kaplar ve gaz değişiminin gerçekleştiği birincil hücrelerdir.\nII. Tip II pnömositler hasara uğrayan Tip I pnömositlerin yerine geçebilecek progenitör hücre özelliği taşır.\nIII. Tip II pnömositler, sürfaktan üretip lamellar cisimcikler aracılığıyla alveoler lümene salgılar.\nIV. Sürfaktanın başlıca bileşeni olan dipalmitoilfosfatidilkolin (DPPC), yüzey gerilimini düşürerek alveoler kollabsı önler.","options":["1 tanesi","Hiçbiri","3 tanesi","2 tanesi","4 tanesi"],"correct":2,"exp":"I. YANLIŞ: Alveoler yüzeyin büyük bölümünü (%95) kaplayan Tip I pnömositlerdir; gaz değişimi bu ince, yassı hücreler aracılığıyla gerçekleşir. Tip II pnömositler sayıca fazla olmakla birlikte yüzey alanı bakımından azınlıktadır. II. DOĞRU: Tip II pnömositler alveoler epitel için progenitör (öncül) hücre olarak kabul edilir; hasar sonrasında prolifere olarak hem Tip II hem de Tip I pnömositlere farklılaşabilirler. III. DOĞRU: Tip II pnömositler endoplazmik retikulum ve Golgi aracılığıyla sürfaktan sentezler; sürfaktanı lamellar cisimcikler (lamellar bodies) içinde depolar ve ekzositozla alveoler yüzeye salgılar. IV. DOĞRU: Sürfaktanın ana fosfolipid bileşeni DPPC, hava-sıvı arayüzündeki yüzey gerilimini azaltarak küçük alveollerin ekspirasyon sırasında çökmesini (atelektazi) önler. Öncüllerin 3 tanesi (II, III, IV) doğrudur."},{"id":8255,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor dispnesi ve bacaklarında şişlik yakınmasıyla başvuruyor. Özgeçmişinde 10 yıldır hipertansiyon ve tip 2 diyabet tanısı mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya ACE inhibitörü, beta bloker ve spironolakton başlanıyor. Tedavinin başlanmasından 3 ay sonra kontrol ekokardiyografisinde sol ventrikül diyastol sonu çapında azalma izleniyor. Bu hastada spironolaktonun tedaviye eklenmesindeki temel katkı aşağıdakilerden hangisiyle açıklanır?","options":["Vazodilatasyon yaparak afterload'ı doğrudan azaltması","Renin-anjiyotensin sistemini baskılayarak preload'ı azaltması","Distal tübülde sodyum geri emilimini artırarak diürez sağlaması","Sempatik sinir sistemi aktivasyonunu azaltarak kalp hızını düşürmesi","Kardiyak fibroblastların aldosteron aracılı aktivasyonunu engelleyerek miyokardiyal yeniden şekillenmeyi yavaşlatması"],"correct":4,"exp":"Spironolakton, mineralokortikoid reseptörlerini bloke ederek aldosteronun kardiyak fibroblastlar üzerindeki etkisini engeller. Aldosteron; kardiyak fibroblastları aktive ederek kollajen sentezini artırır ve miyokardiyal fibrozise yol açar. Bu fibrozis, ventrikül sertleşmesine ve dilate kardiyomiyopatinin ilerlemesine katkıda bulunur. Spironolakton bu süreci keserek miyokardiyal yeniden şekillenmeyi (remodeling) yavaşlatır; ejeksiyon fraksiyonunun düşük olduğu kalp yetmezliğinde mortaliteyi azalttığı randomize çalışmalarla gösterilmiştir. Preload azalması diüretik etkiye bağlıdır ancak bu, spironolaktonun kalp yetmezliğindeki temel katkısını açıklamaz. ACE inhibitörü renin-anjiyotensin sistemini baskılar; beta bloker sempatik aktivasyonu ve kalp hızını düşürür."},{"id":8256,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hastada 2 yıldır sinsi ilerleyen nefes darlığı ve kuru öksürük var. Solunum fonksiyon testinde FVC beklenenin %58'i, FEV1/FVC %88 bulunuyor. Yüksek rezolüsyonlu BT'de alt loblarda yaygın bal peteği görünümü izleniyor. Bu hastanın solunum fonksiyon paterni aşağıdakilerden hangisiyle en iyi açıklanır?","options":["Restriktif patern","Obstrüktif patern","Obstrüksiyonun baskın olduğu mikst patern","Normal solunum fonksiyonu","Ekstratorasik üst hava yolu obstrüksiyonu"],"correct":0,"exp":"FVC'nin belirgin düşük (%58), FEV1/FVC oranının ise korunmuş/yüksek (%88) olması restriktif patternin tipik bulgusudur. Alt lob predominant bal peteği görünümü idiyopatik pulmoner fibroz (UIP) ile uyumludur ve akciğer kompliyansındaki azalma restriksiyona yol açar. Obstrüktif hastalıkta FEV1/FVC oranı düşer."},{"id":8257,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 6 aydır yavaş ilerleyen yürüme güçlüğü, ellerde titreme ve yüz ifadesinde azalma şikayetiyle nöroloji polikliniğine başvuruyor. Nörolojik muayenede dinlenme tremoru, rijidite, bradikinezi ve postural instabilite saptanıyor. Beyin MR'ı normal olarak değerlendiriliyor. Substantia nigra pars compacta nöronlarında dopaminerjik kayıp düşünülen hastaya levodopa/karbidopa tedavisi başlanıyor ve semptomlar belirgin olarak düzeliyor. Bu hastada uzun süreli levodopa tedavisinde görülebilecek 'wearing-off' fenomeninin temel nedeni aşağıdakilerden hangisidir?","options":["Kan-beyin bariyerindeki taşıyıcı proteinlerin levodopaya karşı oluşturduğu immün tolerans","Karbidopanın periferik DOPA dekarboksilaz inhibisyonunun zamanla azalması","Substantia nigra nöronlarının azalmasına bağlı olarak levodopayı depolayıp dönüşümlü salabilen presinaptik tampon kapasitesinin daralması","Striatumdaki dopamin D2 reseptörlerinin aşırı uyarılmaya bağlı kalıcı downregülasyonu","Levodopanın hepatik ilk geçiş metabolizmasının tedavi süresince artması"],"correct":2,"exp":"Sağlıklı bir striatumda dopaminerjik presinaptik terminaller, levodopayla sentezlenen dopamini depolayarak pulsatil değil, sürekli bir dopamin salınımı sağlar. Parkinson hastalığının ilerlemesiyle birlikte substantia nigra nöronları ve onların striatal terminalleri giderek azalır. Bu durumda levodopayı dopaminine çevirip depolayabilecek ve gerektiğinde salabilecek presinaptik terminal kapasitesi daralır. Sonuç olarak striataldaki dopamin konsantrasyonu, plazma levodopa düzeyini doğrudan yansıtmaya başlar. İlaç dozunun tükenmesiyle plazma düzeyi düştüğünde striatal dopamin hızla azalır ve 'wearing-off' (dozun bitmesiyle semptomların geri dönmesi) ortaya çıkar. Karbidopa periferik inhibisyon sağlar ancak bu etki tedavi boyunca devam eder, azalmaz. D2 reseptör downregülasyonu diskinezilerle daha çok ilişkilidir. Kan-beyin bariyerinde immün tolerans gelişimi tanımlanan bir mekanizma değildir."},{"id":8258,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 3 gündür olan yanmalı idrar yapma, sık idrara çıkma ve suprapubik ağrı şikayetiyle başvuruyor. Ateş ve yan ağrısı bulunmuyor. İdrar analizinde lökosit esteraz pozitif, nitrit pozitif, mikroskopide bol lökosit görülüyor. Komplike olmayan alt üriner sistem enfeksiyonu tanısıyla antibiyotik başlanıyor. Bu hastada idrar yolu enfeksiyonuna karşı mesane duvarının ilk savunma hattını oluşturan yapı aşağıdakilerden hangisidir?","options":["Mesane lümenine salgılanan sekretuar IgA","Detrusör düz kas tabakası","Adventisyadaki lenfatik damarlar","Transisyonel epitel (ürotelium) yüzeyindeki umbrella hücrelerinin glikoprotein tabakası","Subüroteliyal bağ dokusundaki mast hücreleri"],"correct":3,"exp":"Mesane iç yüzeyi transisyonel epitel (ürotelium) ile döşelidir. Bu epitelin en yüzeysel tabakasını oluşturan umbrella (şemsiye) hücreleri, apikal yüzeylerinde uroplakin proteinlerinden oluşan kalın bir asimetrik birim membranı ve üzerinde GAG (glikozaminoglikan) / müsin içeren yoğun bir glikoprotein tabakası taşır. Bu tabaka; bakterilerin ürotelyal hücrelere tutunmasını fiziksel olarak engeller ve idrar içeriğinin epitel hücreleriyle doğrudan temasını önler, böylece mesanenin ilk mekanik ve kimyasal savunma hattını oluşturur. Sekretuar IgA önemli bir immün faktördür ancak glikoprotein tabakası kadar erken ve doğrudan bir mekanik bariyer değildir. Mast hücreleri inflamatuvar yanıta katılır. Detrusör kas ve adventisya, epitel bariyerinin gerisinde yer alan yapılardır."},{"id":8259,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Gastrointestinal sistemin farklı bölgelerindeki epitelle ilgili aşağıdaki öncüllerden hangileri doğrudur?\nI. Mide fundusundaki parietal hücreler hem HCl hem de intrinsik faktör salgılar.\nII. İnce barsak villi yüzeyindeki goblet hücreleri, mukus salgılayarak emilimi artırır.\nIII. Brunner bezleri duodenumda submukozada yer alır ve alkalin sekresyon salgılar.\nIV. Kolon epiteli, villus yapısına sahip olmakla birlikte kript derinliği ince barsaktan fazladır.","options":["I, II ve III","II ve IV","Yalnız III","I, III ve IV","I ve III"],"correct":4,"exp":"I. DOĞRU: Mide fundus ve korpusundaki parietal (oksintik) hücreler, H+/K+-ATPaz pompaları aracılığıyla HCl salgılar; aynı zamanda B12 vitaminin emilimi için zorunlu olan intrinsik faktörü de üretir. II. YANLIŞ: Goblet hücreleri mukus salgılayarak epiteli korur; ancak bu mukus tabakası emilimi artırmaz, aksine epiteli mekanik ve kimyasal hasara karşı korur. Emilim; mikrovilli (fırça kenar) taşıyan enterositler tarafından gerçekleştirilir. III. DOĞRU: Brunner bezleri duodenuma özgüdür ve submukozada bulunur (diğer barsak bezlerinin aksine). Alkalin, müsinöz sekresyon salgılayarak mide asidine karşı duodenal mukozayı korur ve pankreatik enzimlerin optimal pH'ı olan alkalin ortamı sağlar. IV. YANLIŞ: Kolonda villus yapısı bulunmaz; yalnızca Lieberkühn kriptleri mevcuttur. Doğru öncüller I ve III'tür."},{"id":8260,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve çabuk yorulma şikayetiyle kardiyoloji polikliniğine başvuruyor. Özgeçmişinde tip 2 diyabet ve hipertansiyon mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya ACE inhibitörü ve beta bloker başlanıyor. Beta blokerin bu hastadaki primer hemodinamik etkisi aşağıdakilerden hangisidir?","options":["Renin salınımını artırarak anjiyotensin II düzeyini yükseltir","Sinoatriyal düğümde otomasisiteyi baskılayarak kalp hızını düşürür ve miyokard oksijen tüketimini azaltır","Periferik vasküler direnci azaltarak afterload'u düşürür","Miyokard kontraktilitesini artırarak ejeksiyon fraksiyonunu akut olarak yükseltir","Aldosteron salınımını inhibe ederek diürez sağlar"],"correct":1,"exp":"Beta blokerler, sinoatriyal düğümdeki beta-1 reseptörlerini bloke ederek kalp hızını düşürür; aynı zamanda miyokardın kontraktilitesini ve iletim hızını azaltır. Bu üç etki birlikte miyokard oksijen tüketimini belirgin şekilde düşürür. Kronik kalp yetmezliğinde sempatik aktivasyon zararlı olduğundan, beta blokaj uzun vadede ventriküler remodellingi yavaşlatır ve mortaliteyi azaltır. Renin salınımını ise artırmaz, aksine jukstaglomerüler hücrelerden renin sekresyonunu inhibe eder."},{"id":8261,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, 2 yıldır giderek artan nefes darlığı ve kuru öksürük nedeniyle göğüs hastalıkları polikliniğine başvuruyor. Sigara kullanmıyor. Akciğer grafisinde bilateral bazal retiküler opasiteler saptanıyor. Yüksek rezolüsyonlu BT'de bal peteği görünümü ve traksiyon bronşiektazisi izleniyor. Solunum fonksiyon testlerinde FVC: %58 (beklenenin), FEV1/FVC: 0,88 saptanıyor. Aşağıdaki öncüllerden kaç tanesi bu hastanın fizyopatolojisi ile uyumludur?\nI. Akciğer kompliyansının azalması\nII. Difüzyon kapasitesinin (DLCO) azalması\nIII. Rezidüel volümün orantısız biçimde artması\nIV. Alveoloarteriyel oksijen gradyanının artması","options":["2","1","4","3","Hiçbiri"],"correct":3,"exp":"Bu tablo idiyopatik pulmoner fibrozis (IPF) ile uyumludur ve restriktif patern gösterir. I. Fibrozis alveoler duvarları sertleştirir, kompliyans belirgin azalır - DOĞRU. II. Alveolokapiller membranın kalınlaşması ve yüzey alanının azalması DLCO'yu düşürür - DOĞRU. III. Restriktif hastalıkta tüm akciğer volümleri (TLC, FVC, RV) orantılı olarak azalır; obstrüktif hastalığın aksine rezidüel volüm orantısız artmaz - YANLIŞ. IV. Fibröz alveoler duvar difüzyon bariyeri oluşturduğundan ve V/Q uyumsuzluğu nedeniyle A-a gradyanı artar - DOĞRU. Dolayısıyla I, II ve IV doğrudur: 3 öncül uyumludur."},{"id":8262,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında erkek hasta, rutin kontrol amacıyla başvuruyor. Laboratuvar tetkiklerinde serum kreatinin: 1,1 mg/dL, BUN: 14 mg/dL saptanıyor. Renal arteriyografi sırasında sağ renal artere gadolinyum bazlı kontrast madde veriliyor ve sağ böbreğin afferent arteriolünde %70 darlık tespit ediliyor. Bu hastada darlık tarafındaki böbrekte renin salınımının artmasının temel nedeni aşağıdakilerden hangisidir?","options":["Makula densa hücrelerine ulaşan tübüler sodyum yükünün azalması","Afferent arteriol duvarındaki baroreseptörlerin düşük basınca yanıt vermesi","Angiyotensin II'nin jukstaglomerüler hücrelere direkt pozitif geri bildirimi","Sempatik sinir uçlarından norepinefrin salınmasının artması","Prostaglandin E2'nin jukstaglomerüler hücrelerden renin salınımını inhibe etmesi"],"correct":1,"exp":"Renal arteri stenozu varlığında afferent arteriol içindeki perfüzyon basıncı düşer. Jukstaglomerüler (JG) hücreler, afferent arteriol duvarında yerleşik modifiye düz kas hücreleridir ve intrarenal baroreseptör görevi görür. Azalan gerilmeye yanıt olarak JG hücrelerinden renin salınımı artar. Bu, renin salınımını düzenleyen üç mekanizmadan biridir (diğerleri: makula densanın azalan NaCl algılaması ve sempatik beta-1 stimülasyonu). Makula densa mekanizması da katkıda bulunur ancak birincil tetikleyici baroreseptör yanıtıdır. Anjiyotensin II ise JG hücrelerine negatif geri bildirim yapar."},{"id":8263,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"27 yaşında kadın hasta, sağ gözde çift görme ve sağ göz kapağında düşüklük şikayetiyle nöroloji polikliniğine başvuruyor. Muayenede sağ pupilde midriyazis ve medial yönde gözün hareketi kısıtlı olarak saptanıyor. Beyin MRG'de sağ arka kommunikan arterde anevrizma tespit ediliyor. Aşağıdaki öncüllerin hangisi ya da hangileri bu klinik tablo ile uyumludur?\nI. Etkilenen sinirin parasempatik lifleri en dışta seyreder\nII. Ptoz, levator palpebra superiorisin sempatik denervasyonuna bağlıdır\nIII. Pupil dilatasyonu, sfinkter pupilla kasının paralizisiyle açıklanır","options":["Yalnız I","I ve III","Yalnız III","I, II ve III","II ve III"],"correct":1,"exp":"Bu tablo N. okulomotorius (III. kraniyal sinir) basısıyla uyumludur. I. N. III'ün parasempatik lifleri sinirin en dış katmanında seyreder; bu nedenle anevrizma gibi kompresif lezyonlar önce pupil dilatasyonuna yol açar - DOĞRU. II. Ptoz, levator palpebra superiorisin somatik motor (N. III) denervasyonundan kaynaklanır; sempatik denervasyonda ise parsiyel ptoz (Müller kası paralizisi) görülür, bu tablodaki tam ptoz ile uyuşmaz - YANLIŞ. III. Sfinkter pupilla kası N. III'ün parasempatik lifleriyle innerve edilir; bu liflerin baskılanması sfinkter paralizisine ve dolayısıyla midriyazise yol açar - DOĞRU. Bu nedenle I ve III doğrudur."},{"id":8264,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, 3 haftadır süren ateş, gece terlemesi ve 6 kg kilo kaybı şikayetiyle hematoloji polikliniğine başvuruyor. Boyun sağ tarafında ağrısız, lastik kıvamında 3×4 cm lenfadenopati saptanıyor. Yapılan lenf nodu biyopsisinde Reed-Sternberg hücreleri görülüyor. Hodgkin lenfoma tanısıyla ABVD (Adriamisin, Bleomisin, Vinblastin, Dakarbazin) kemoterapisi planlanıyor. Bleomisinin bu şemadaki etki hedefi aşağıdakilerden hangisidir?","options":["Topoizomeraz II'yi inhibe ederek DNA replikasyonunu bozar","Alkilleyici ajan olarak DNA çapraz bağları oluşturur","Pürin sentezini inhibe ederek S fazını engeller","Tübülin polimerizasyonunu bozarak mitotik iğ oluşumunu engeller","DNA çift zincir kırıklarına yol açarak hücre döngüsünü G2/M fazında durdurur"],"correct":4,"exp":"Bleomisin, serbest radikaller aracılığıyla DNA tek ve çift zincir kırıklarına yol açan bir glikoprotein antibiyotiktir. Hücre döngüsünü ağırlıklı olarak G2 ve M fazında durdurur. Şemadaki diğer ajanlara bakılırsa: Vinblastin tübülin polimerizasyonunu bozar (“Tübülin polimerizasyonunu bozarak mitotik iğ oluşumunu engeller” ifadesi), Adriamisin (doksorubisin) topoizomeraz II'yi inhibe eder ve DNA interkalasyonu yapar (“Topoizomeraz II'yi inhibe ederek DNA replikasyonunu bozar” ifadesi), Dakarbazin alkilleyici ajandır (“Alkilleyici ajan olarak DNA çapraz bağları oluşturur” ifadesi). Bleomisinin en önemli yan etkisi pulmoner fibrozdir; bu nedenle ABVD uygulanan hastalarda kümülatif doz ve akciğer fonksiyonları yakından izlenir."},{"id":8265,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"42 yaşında erkek hasta, 6 aydır süren epigastrik ağrı, gece ağrısıyla uyanma ve yemekten birkaç saat sonra artan yanma şikayetiyle dahiliye polikliniğine başvuruyor. Üst gastrointestinal endoskopide duodenum birinci kıtasında 1,5 cm çaplı ülser saptanıyor. Hızlı üreaz testi pozitif. Hastaya klaritromisin, amoksisilin ve omeprazol içeren üçlü eradikasyon tedavisi başlanıyor. Omeprazolün bu tedavideki primer etki mekanizması aşağıdakilerden hangisidir?","options":["Antrum G hücrelerinden gastrin salınımını azaltır","Parietal hücrelerde H2 reseptörlerini bloke ederek histamin etkisini önler","Asetilkolin reseptörlerini bloke ederek vagal uyarıyı keser","Parietal hücrelerde H+/K+-ATPaz enzimini irreversibl olarak inhibe ederek asit sekresyonunu baskılar","Mide mukozasında prostaglandin sentezini artırarak mukus sekresyonunu uyarır"],"correct":3,"exp":"Omeprazol bir proton pompa inhibitörüdür (PPI). Asit ortamında aktif forma (sülfenamid) dönüşerek parietal hücrelerin apikal membranında bulunan H+/K+-ATPaz enzimini (proton pompası) irreversibl olarak kovalent bağla inhibe eder. Bu, mide asit sekresyonunun son ortak basamağını bloke ettiğinden en güçlü asit suppresyon yöntemini sağlar. H2 reseptör blokajı ranitidin gibi ilaçların mekanizmasıdır. Prostaglandin artışı misoprostol gibi sitoprotektif ajanlara özgüdür. PPI'lar eradikasyon tedavisinde antibiyotiklerin etkinliğini artırmak ve semptom kontrolü sağlamak amacıyla kullanılır."},{"id":8266,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya tedavi başlandıktan sonra yapılan kontrol muayenesinde periferik ödemin azaldığı ve egzersiz toleransının arttığı gözlemleniyor. Hastanın kullandığı ilaç aşağıdakilerden hangisi olamaz?","options":["Nifedipin","Spironolakton","Karvedilol","Sakubitril/valsartan","Digoksin"],"correct":0,"exp":"Kalsiyum kanal blokerleri, özellikle dihidropiridin grubu (nifedipin), sistolik kalp yetersizliğinde negatif inotropik etkileri ve refleks sempatik aktivasyon riski nedeniyle kontrendikedir. Spironolakton (aldosteron antagonisti), karvedilol (beta-blokör), sakubitril/valsartan (ARNI) ve digoksin düşük EF'li kalp yetersizliğinde kullanım endikasyonu taşır. Nifedipin miyokard kontraktilitesini daha da baskılayarak klinik tabloyu ağırlaştırabilir."},{"id":8267,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 20 yıldır sigara içmekte olup son 2 yıldır giderek artan nefes darlığı yakınmasıyla başvuruyor. Solunum fonksiyon testinde FEV1/FVC oranı %58, TLC artmış, DLCO belirgin düşük saptanıyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Bu hastada tip II pnömositlerde hipertrofi beklenir.\nII. Alveoler makrofaj sayısının artması beklenir.\nIII. Alveoler duvar yıkımı nedeniyle difüzyon mesafesi azalmış, bu durum DLCO düşüklüğüne yol açmıştır.\nIV. Bronş bezi hipertrofisi bu hastada FEV1/FVC düşüklüğünün tek nedenidir.\nYukarıdaki öncüllerden kaç tanesi yanlıştır?","options":["4","1","3","5","2"],"correct":4,"exp":"I. Yanlış: Amfizemde tip II pnömositler kompansatuar olarak hiperplazi gösterebilir ancak 'hipertrofi' temel beklenti değildir; aksine alveoler yüzey alanı azalır. II. Doğru: Sigara dumanına yanıt olarak alveoler makrofaj sayısı artar ve bunlar elastaz salgılayarak alveoler duvar yıkımına katkıda bulunur. III. Yanlış: Alveoler duvar yıkımı difüzyon yüzey alanını azaltır; bu nedenle difüzyon mesafesi azalmaz, difüzyon kapasitesi (DLCO) düşer. Mekanizma doğru ifade edilmemiştir. IV. Yanlış: Bronş bezi hipertrofisi kronik bronşitin özelliğidir; FEV1/FVC düşüklüğü hem amfizem hem kronik bronşit bileşeninden kaynaklanır ve tek neden değildir. Dolayısıyla I, III ve IV yanlıştır; yanlış öncül sayısı 3'tür."},{"id":8268,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan idrar yolu enfeksiyonu nedeniyle üroloji polikliniğine başvuruyor. Sistoskopide mesane mukozasında geçici epitel (ürotelyal epitel) ile döşeli yüzeyin normalden farklı göründüğü izleniyor. Bu epitele ait özellikleri sorgulayan asistan, aşağıdaki öncülleri değerlendiriyor:\nI. Geçici epitel, mesane dolgunluğuna göre hücre sayısını değiştirmeden yüzey alanını düzenleyebilir.\nII. Yüzey hücreleri (şemsiye hücreler) apikal membranında asimetrik birim membran yapıları içerir.\nIII. Geçici epitel hem pelvis renalis hem de üreter hem de mesanede bulunur.\nIV. Bu epitel tipinde hücreler arası bağlantılar gevşek olduğundan idrara karşı geçirgenliği yüksektir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","I, II, III ve IV","II, III ve IV","I, II ve III","II ve III"],"correct":3,"exp":"Ürotelyum, mesane dolarken hücre sayısını değiştirmeden hücrelerin yassılaşması ve apikal membran rezervlerinin açılmasıyla yüzey alanını artırır. Şemsiye hücrelerin apikal membranında üroplakinlerden zengin asimetrik birim membran bulunur. Ürotelyum renal pelvis, üreter ve mesaneyi döşer. Sıkı bağlantılar nedeniyle idrara geçirgenliği düşüktür. I, II ve III doğrudur."},{"id":8269,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, yorgunluk ve çarpıntı yakınmasıyla başvuruyor. Laboratuvar incelemesinde hemoglobin 8,2 g/dL, MCV 112 fL, periferik yaymada hipersegmente nötrofiller saptanıyor. Hastaya uygun tedavi başlandıktan sonra retikülosit sayısının belirgin yükseldiği görülüyor. Bu retikülositozun beklenmesinin temel nedeni aşağıdakilerden hangisidir?","options":["Kemik iliğinde önceden birikmiş eritrositlerin dolaşıma verilmesi","Eritropoietin salgısının akut artışı","Periferik eritrosit yıkımının azalmasına bağlı kompansatuar üretim artışı","Tedaviyle düzelen inefektif eritropoiezin yerine etkili eritropoiezin başlaması","Trombosit prekürsörlerinin eritroid seriye dönüşümü"],"correct":3,"exp":"Megaloblastik anemide (B12 veya folat eksikliği) temel sorun, kemik iliğinde DNA sentezinin bozulmasına bağlı inefektif eritropoiezdir; immatür eritroid prekürsörler olgunlaşamadan intramedullar olarak yıkılır. Tedavi (B12 veya folat replasmanı) başlandığında DNA sentezi normale döner, inefektif eritropoiez yerini etkili eritropoieze bırakır ve periferik kana retikülosit dalgası şeklinde yansır. Bu durum tedaviye yanıtın en erken göstergesidir ve genellikle 5-7. günlerde doruk yapar."},{"id":8270,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Santral sinir sisteminde miyelinizasyonu sağlayan hücreyi ve bu hücrenin tek bir aksonu mu yoksa birden fazla aksonu mu sardığını sorgulayan bir tıp öğrencisi, aşağıdaki ifadelerden hangisini söylerse doğru olur?","options":["Mikroglia hücreleri MSS'de miyelin oluşturur; her hücre yalnızca bir aksonu sarar.","Schwann hücreleri MSS'de miyelin oluşturur; her hücre birden fazla aksonu sarabilir.","Schwann hücreleri SNS ve MSS'de miyelini oluşturur; her hücre yalnızca bir aksonu sarar.","Oligodendrosit hücreleri MSS'de miyelin oluşturur; her hücre yalnızca bir akson segmentini sarar.","Oligodendrosit hücreleri MSS'de miyelin oluşturur; her hücre birden fazla akson segmentini sarabilir."],"correct":4,"exp":"Merkezi sinir sisteminde miyelin, oligodendrosit hücreleri tarafından üretilir. Oligodendrositler, her biri farklı aksonlara ait olmak üzere birden fazla (ortalama 15-30) akson segmentini sarabilir; bu özelliğiyle periferik sinir sisteminde yalnızca tek bir aksonu saran Schwann hücrelerinden ayrılır. Schwann hücreleri yalnızca periferik sinir sisteminde işlev görür."},{"id":8271,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"45 yaşında erkek hasta, uzun süreli proton pompası inhibitörü (PPI) kullanımı nedeniyle gastroenteroloji polikliniğine yönlendiriliyor. Endoskopide mide gövdesinde enterokromafin benzeri (ECL) hücre hiperplazisi saptanıyor. Aşağıdaki öncülleri değerlendiriniz:\nI. PPI kullanımı antrum G hücrelerini uyararak gastrin salgısını artırır.\nII. Artan gastrin, ECL hücreleri üzerindeki reseptörlerine bağlanarak histamin salgılatır.\nIII. ECL hücre hiperplazisi doğrudan PPI'nın ECL hücreleri üzerindeki direkt trofik etkisinden kaynaklanır.\nIV. Bu mekanizma, uzun süreli PPI kullanımında asit baskılanmasına rağmen serum gastrin düzeyinin neden yüksek seyredebileceğini açıklar.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II ve III","I ve II","I, II ve IV","I, III ve IV","I, II, III ve IV"],"correct":2,"exp":"I. Doğru: PPI ile asit baskılanınca antrumdaki asit-duyarlı D hücreleri somatostatin salgısını azaltır; bu durum G hücrelerinin inhibisyonunu ortadan kaldırarak gastrin salgısının artmasına (hipergastrinemi) yol açar. II. Doğru: Gastrin, ECL hücreleri üzerindeki kolesistokinin-2 (CCK-2) reseptörlerine bağlanarak histamin salgılatır; histamin ise parietal hücrelerden asit sekresyonunu uyarır. III. Yanlış: ECL hücre hiperplazisi PPI'nın direkt trofik etkisinden değil, hipergastrinemiye bağlı gastrin aracılı trofik etkiden kaynaklanır. IV. Doğru: Asit baskılandığında oluşan negatif geri beslemenin kaldırılmasıyla gastrin düzeyi yükselir; bu uzun süreli PPI kullanımında beklenen bir bulgudur. Doğru öncüller I, II ve IV'tür."},{"id":8272,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, efor sırasında ortaya çıkan göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Özgeçmişinde 12 yıldır tip 2 diyabet ve hipertansiyon tanıları mevcut. Ekokardiyografik değerlendirmede sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor; N-terminal pro-BNP düzeyi belirgin şekilde yüksek bulunuyor. Hastaya tedavi protokolü kapsamında sakubitril/valsartan başlanıyor. Bu ilacın etki mekanizmasına göre, tedavinin başlanmasının ardından dolaşımdaki hangi peptidin düzeyi yükselir?","options":["Bradikinin","Atriyal natriüretik peptid (ANP)","Endotelin-1","Aldosteron","Anjiyotensin II"],"correct":1,"exp":"Sakubitril, nörilysin (neprilizin) enzimini inhibe ederek natriüretik peptidlerin (ANP, BNP) yıkımını engeller; böylece dolaşımdaki ANP ve BNP düzeyleri yükselir. Bu peptigler natriürez, diürez ve vazodilatasyon sağlayarak kalp üzerindeki yükü azaltır. Anjiyotensin II ve aldosteron ise valsartan bileşeni sayesinde bloke edilir. Bradikinin artışı ACE inhibitörlerine özgü bir etkidir, sakubitril/valsartan için birincil mekanizma ANP yükselmesidir."},{"id":8273,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 8 aydır süren kuru öksürük, giderek artan efor dispnesi ve ajitasyon yakınmalarıyla göğüs hastalıkları kliniğine yönlendiriliyor. Sigara içmediği öğrenilen hastanın solunum fonksiyon testlerinde FEV1/FVC oranı normal sınırda iken TLC ve RV değerlerinde belirgin azalma saptanıyor. DLCO değeri beklenenin %42'si olarak ölçülüyor. Bronkoalveoler lavaj örneğinde CD4/CD8 oranı artmış, non-kazeifiye granülomlar tespit ediliyor. Bu hastanın akciğer patolojisinde alveoler gaz difüzyonunu birincil olarak bozan yapısal değişiklik hangisidir?","options":["Pulmoner kapiller endotel hasarı","Tip I pnömosit hiperplazisi","İnterstisyel fibrozis ve alveoler duvar kalınlaşması","Müköz bez hipertrofisi","Alveoler makrofaj birikimi"],"correct":2,"exp":"Klinik tablo, solunum fonksiyon testleri ve BAL bulguları sarkoidozu düşündürmektedir. Sarkoidozda non-kazeifiye granülomlar interstisyumda yerleşerek alveoler duvar kalınlaşmasına ve ilerleyen süreçte interstisyel fibrozise yol açar. Bu değişiklikler alveolokapiller membranın diffüzyon mesafesini artırır, DLCO değerini düşürür. Restriktif patern (TLC ve RV azalması) da interstisyel tutulumu yansıtır. Müköz bez hipertrofisi kronik bronşite, pulmoner kapiller endotel hasarı ARDS'ye özgüdür."},{"id":8274,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 3 yıldır süren ve giderek ilerleyen denge bozukluğu, sık düşme ve yutma güçlüğü yakınmalarıyla nöroloji kliniğine başvuruyor. Nörolojik muayenede simetrik rijidite, aksiyel instabilite ve supranükleer bakış felci saptanıyor; levodopa tedavisine yanıt son derece sınırlı. Beyin MRG'de mezensefalon atrofisi ve 'penguen silueti' görünümü izleniyor. Hastalığın patogenezinde sorumlu tutulan anormal protein birikiminin ağırlıklı olarak hangi hücre tipinde gerçekleştiği ve bu proteinin adı aşağıdakilerden hangisinde doğru olarak birlikte verilmiştir?","options":["Schwann hücresi - prion proteini","Oligodendrosit - alfa-sinüklein","Nöron - tau proteini (4R izoformu)","Mikroglia - TDP-43","Astrosit - beta-amiloid"],"correct":2,"exp":"Klinik tablo progresif supranükleer palsiyi (PSP) işaret etmektedir. PSP, primer tauopatiler grubunda yer alan ve 4R tau izoformunun nöronlarda, astrositlerin 'çalı demeti' görünümünde biriktiği bir nörodejeneratif hastalıktır. Mezensefalon atrofisi MRG'de 'penguen silueti' ya da 'hummingbird sign' olarak izlenir. Levodopaya yanıtsızlık ve supranükleer bakış felci ayırt edici bulgulardır. Alfa-sinüklein Parkinson ve MSA'da, TDP-43 ALS/FTLD'de, beta-amiloid Alzheimer hastalığında sorumlu tutulan proteinlerdir."},{"id":8275,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"42 yaşında kadın hasta, 6 haftadır süren periorbital ödem, köpüklü idrar ve yorgunluk yakınmalarıyla nefroloji polikliniğine başvuruyor. Laboratuvar incelemelerinde serum albumin 1,9 g/dL, 24 saatlik idrarda protein atılımı 6,8 g, serum kreatinin 0,9 mg/dL olarak saptanıyor. Böbrek biyopsisinde elektron mikroskopide podosit ayak süreçlerinde yaygın silinme (effacement) görülürken ışık mikroskopide glomerüller normal izleniyor, immünfloresan inceleme negatif bulunuyor. Aşağıdaki ifadeler değerlendirildiğinde hangisi yanlıştır?\nI. Bu hastalıkta glomerüler filtrasyon bariyerinin birincil hasarı podositte gerçekleşmektedir.\nII. Masif proteinüri, onkotik basıncın artması sonucu ödeme yol açar.\nIII. Immünfloresan negatifliği, immün kompleks birikimi olmadığını gösterir.\nIV. Serum kreatininin normal olması, GFR'nin korunduğuna işaret eder.\nYukarıdaki öncüllerden kaç tanesi yanlıştır?","options":["Yalnız II","Yalnız I","III ve IV","II ve IV","I ve III"],"correct":0,"exp":"Klinik ve histopatolojik bulgular minimal değişiklik hastalığını (MCD) düşündürmektedir. Öncüller tek tek değerlendirildiğinde: I. Doğrudur; MCD'de podosit ayak süreçlerinin silinmesi birincil yapısal bozukluktur. II. Yanlıştır; masif proteinüri sonucu albumin kaybı onkotik basıncı DÜŞÜRÜR, bu da interstisyuma sıvı geçişine ve ödeme neden olur. III. Doğrudur; MCD'de immün kompleks birikimi olmadığı için immünfloresan negatiftir. IV. Doğrudur; GFR, serum kreatinin ile ters orantılı bir ilişki içindedir ve normal kreatinin GFR'nin korunduğunu destekler. Dolayısıyla yalnızca II. öncül yanlıştır."},{"id":8276,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Kemik iliği biyopsisinde normoblast (eritroblast) serisi incelendiğinde, hangi olgunlaşma evresinde çekirdeğin hücreden atıldığı ve retikülosit aşamasına geçildiği gözlemlenir?","options":["Polikromatofilik eritroblast","Proeritroblast","Eritrosit","Bazofilik eritroblast","Ortokromatik eritroblast"],"correct":4,"exp":"Eritroid olgunlaşma sırası şu şekildedir: proeritroblast → bazofilik eritroblast → polikromatofilik eritroblast → ortokromatik eritroblast → retikülosit → eritrosit. Çekirdek atımı (enükleasyon) ortokromatik eritroblast evresinde gerçekleşir; bu aşamada çekirdek piknotik ve yoğundur. Enükleasyonun ardından hücre retikülosit adını alır ve hâlâ ribozom kalıntıları içerdiği için supravital boyama ile ağ görünümü verir. Polikromatofilik eritroblast ise henüz çekirdeğini korumaktadır ve hemoglobin sentezinin başladığı evredir."},{"id":8277,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"29 yaşında erkek hasta, 14 aydır süren tekrarlayan karın ağrısı, kanlı ishal ve kilo kaybı yakınmalarıyla gastroenteroloji kliniğine başvuruyor. Kolonoskopide rektumdan başlayarak proksimale uzanan sürekli mukozal tutulum ve granülasyon dokusu izleniyor; biyopsi örneklerinde kript absesi ve goblet hücresi kaybı saptanıyor. Anti-TNF tedavisine yanıt alınamayan hastaya vedolizumab başlanıyor. Bu ilacın etki mekanizması düşünüldüğünde, vedolizumabın bağlandığı ve bloke ettiği molekül hangisidir?","options":["MAdCAM-1","IL-12/IL-23 ortak p40 alt birimi","Integrin alfa4-beta7","TNF-alfa reseptörü","JAK1/JAK3 kinaz"],"correct":2,"exp":"Vedolizumab, bağırsak dokusuna spesifik olan integrin alfa4-beta7'yi hedef alan monoklonal bir antikordur. Bu integrin, bağırsak mukoza adresin hücre adezyon molekülü-1 (MAdCAM-1) ile etkileşerek T lenfositlerinin bağırsak dokusuna göçünü sağlar. Vedolizumab bu etkileşimi bloke ederek bağırsak özgül immün hücre infiltrasyonunu azaltır; sistemik immün baskılama yapmaz. Anti-TNF ilaçlar TNF-alfa'yı, ustekinumab IL-12/IL-23 p40 alt birimini, tofasitinib JAK1/JAK3'ü hedef alır. MAdCAM-1 ise ilacın bağlandığı değil, integrin alfa4-beta7'nin doğal ligandıdır."},{"id":8278,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Hastanın öyküsünde 15 yıldır hipertansiyon tanısı mevcut olup anjiyotensin dönüştürücü enzim (ACE) inhibitörü kullanmaktadır. Ekokardiyografik incelemede sol ventrikül duvar kalınlığında artış, diyastolik disfonksiyon ve doldurma basıncında yükselme saptanıyor. Bu tabloya yol açan yapısal değişiklikte en çok hangi hücre tipi sorumludur?","options":["Periositler","Kardiyak fibroblastlar","Düz kas hücreleri","Kardiyomiyositler","Endotel hücreleri"],"correct":1,"exp":"Hipertansif kalp hastalığında sol ventrikül hipertrofisi oluşurken kardiyomiyositler büyüse de interstisyel fibrozis ve patolojik yeniden yapılanmanın (remodeling) asıl sorumlusu kardiyak fibroblastlardır. Fibroblastlar miyofibroblastlara dönüşerek aşırı kollajen I ve III sentezler; bu durum miyokard sertliğini artırarak diyastolik disfonksiyona zemin hazırlar. ACE inhibitörleri anjiyotensin II'nin fibroblast aktivasyonunu azaltarak bu süreci yavaşlatır."},{"id":8279,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, 6 aydır süren kuru öksürük ve egzersiz dispnesi yakınmasıyla göğüs hastalıkları kliniğine yönlendiriliyor. Hastanın 30 paket-yıl sigara içme öyküsü bulunmakta, spirometride FVC'de azalma, FEV1/FVC > 0,7 saptanmakta ve DLCO belirgin şekilde düşük bulunmaktadır. Yüksek çözünürlüklü toraks BT'de her iki akciğer alt loblarında balpeteği görünümü ve traksiyon bronşiektazisi izleniyor. Bu hastada bozulan gaz değişiminin histolojik temeli olan yapı aşağıdakilerden hangisidir?","options":["Tip I pnömositler","Alveolar makrofajlar","Tip II pnömositler","Küçük havayolu düz kas hücreleri","Clara (Club) hücreleri"],"correct":0,"exp":"İdiyopatik pulmoner fibrozis (IPF) ya da sigara ilişkili interstisyel akciğer hastalığında gaz değişimi esas olarak Tip I pnömositler aracılığıyla gerçekleşir; bu hücreler alveol yüzeyinin yaklaşık %95'ini kaplar ve gaz difüzyonu için ince bir bariyer oluştururlar. Fibrozis sürecinde Tip I pnömositler hasar görür ve yerini kollajen birikmesine bırakır; bu durum DLCO'nun düşmesini açıklar. Tip II pnömositler sürfaktan üretir ve Tip I hücrelerin progenitörüdür, ancak primer gaz değişim birimi değildir."},{"id":8280,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında erkek hasta, 3 haftadır devam eden göz kapağı ödemi ve ayak bileklerinde şişlik yakınmasıyla nefroloji polikliniğine başvuruyor. İdrar analizinde 3+ proteinüri, mikroskopide lipid yüklü hücreler (oval yağ cisimcikleri) saptanıyor. Serum albumin düzeyi 1,8 g/dL, total kolesterol 420 mg/dL olarak ölçülüyor. Renal biyopside elektron mikroskopisi ile podosit ayakçık (ayaksı çıkıntı) obliterasyonu görülüyor, ışık mikroskopisinde ise glomerüller normal görünmektedir. Bu tabloda birincil olarak hasara uğrayan yapı ve bu yapının koruduğu elektrostatik bariyer için hangi molekül kritik öneme sahiptir?","options":["Podosinin - GBM yük bariyeri","Endotelyal glikokaliks - hidrostatik bariyer","Zonula okludens - glomerüler filtrasyon bariyeri","Heparan sülfat proteoglikanlar - GBM anyonik bariyeri","Nefrin - podosit slite diyafram bariyeri"],"correct":3,"exp":"Minimal değişiklik hastalığında ışık mikroskobu normalken elektron mikroskobunda podosit ayakçık obliterasyonu görülür. Bu tabloda glomerüler bazal membranda (GBM) bulunan heparan sülfat proteoglikanlar (özellikle agrin ve perlekan) kaybı kritik öneme sahiptir; bu anyonik moleküller negatif yüklü albuminin filtrasyonunu engeller. Nefrin ve podosinin slite diyafram bariyerinin yapısal proteinleridir; ancak MCD'de primer hasar elektrostatik bariyerdedir. Heparan sülfat kaybı albuminin GBM'yi geçmesine izin vererek masif proteinüriye yol açar."},{"id":8281,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir nörobilim laboratuvarında Schwann hücrelerine özgü bir toksinin etkisi araştırılmaktadır. Bu toksin Schwann hücrelerinin miyelinizasyon işlevini tamamen ortadan kaldırdığında, periferik sinir iletiminde aşağıdakilerden hangisi beklenir?\nI. Aksiyon potansiyeli iletim hızı azalır.\nII. Ranvier boğumları arasındaki saltatorik iletim durur.\nIII. Akson membranının kapasitans değeri düşer.\nIV. Mutlak refrakter dönem uzar.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["3 tanesi","4 tanesi","2 tanesi","Hiçbiri","Yalnız 1 tanesi"],"correct":2,"exp":"Miyelinin iki temel işlevi vardır: iletiyi hızlandırmak (saltatorik iletim) ve akson membranının elektriksel kapasitansını düşürerek aksiyon potansiyeli oluşumunu kolaylaştırmak. Miyelin kaybında I. öncül doğrudur (iletim hızı azalır) ve II. öncül doğrudur (saltatorik iletim durur). III. öncül yanlıştır; miyelin kapasitansı düşürür, dolayısıyla miyelin kaybında kapasitans ARTAR. IV. öncül yanlıştır; mutlak refrakter dönem miyelin durumundan değil, voltaj kapılı Na+ kanallarının inaktivasyonundan belirlenir ve miyelinizasyonla doğrudan ilişkisi yoktur. Doğru öncül sayısı 2'dir."},{"id":8282,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"25 yaşında kadın hasta, rutin kan sayımında trombosit değeri 820.000/mm³ olarak saptanması üzerine hematoloji polikliniğine yönlendiriliyor. Hastanın herhangi bir yakınması bulunmuyor; öyküsünde 3 ay önce geçirilmiş demir eksikliği anemisi tedavisi mevcut. Periferik yaymada trombositler morfolojik olarak normal görünmekte, lökosit ve eritrositlerde patoloji saptanmamaktadır. Trombosit üretimini artıran ve megakaryosit olgunlaşmasını uyaran hormon aşağıdakilerden hangisidir?","options":["İnterlökin-5","Granülosit koloni uyarıcı faktör (G-CSF)","Stem cell factor (SCF)","Trombopoietin","Eritropoietin"],"correct":3,"exp":"Trombopoietin (TPO), karaciğer ve böbrek tarafından sentezlenen ve megakaryosit öncüllerinin proliferasyonu ile olgunlaşmasını düzenleyen başlıca hormondur. C-Mpl reseptörüne bağlanarak megakaryositlerin endoreduplikasyon sürecini ve trombosit tomurcuklanmasını uyarır. Bu vakada reaktif trombositoz söz konusudur (demir eksikliği veya geçirilmiş iltihabi duruma bağlı). Eritropoietin eritrosit serisini, IL-5 eozinofilleri, G-CSF nötrofilleri uyarır; SCF ise kök hücre faktörü olup genel hematopoezi destekler ancak trombosit serisine özgü değildir."},{"id":8283,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"48 yaşında erkek hasta, 5 yıldır süregelen gastroözofageal reflü hastalığı (GÖRH) nedeniyle uzun süreli proton pompa inhibitörü (PPI) kullanmaktadır. Rutin endoskopide alt özofagusta soluk pembe renkli kolumnar epitel ile çevrili adalar saptanıyor ve biyopsi alınıyor. Biyopside goblet hücreleri içeren intestinal metaplazi rapor ediliyor. Bu dönüşüm sürecinde normal özofagus mukozasının hangi epitel tipinden hangi epitel tipine geçiş gerçekleşmektedir?","options":["Çok katlı yassı epitelden intestinal tip kolumnar epitele","Psödostratifiye silyalı epitelden basit kolumnar epitele","Geçici epitelden basit prizmatik epitele","Tek katlı küboidal epitelden çok katlı yassı epitele","Basit kolumnar epitelden çok katlı yassı epitele"],"correct":0,"exp":"Özofagus normalde koruyucu çok katlı yassı epitel ile döşelidir. Kronik asit maruziyetinde bu hücreler hasar görür ve yerini intestinal tip kolumnar epitele (goblet hücreleri içeren) bırakır; bu süreç metaplazi olarak adlandırılır ve Barrett özofagusu oluşumunu temsil eder. Goblet hücreleri intestinal metaplazinin ayırt edici histolojik bulgusudur ve Alcian mavisi ile boyandığında müsin granülleri görülür. Bu tablo displazi ve özofagus adenokarsinomu için önemli bir premalign lezyon oluşturduğundan endoskopik takip zorunludur."},{"id":8284,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, egzersiz sonrası kaslarında aşırı yorgunluk ve kramplara ek olarak son 6 aydır giderek kötüleşen proksimal kas güçsüzlüğü yakınmasıyla başvuruyor. Elektromiyografide miyopatik patern saptanan hastanın kas biyopsisinde tip I kas lifi atrofisi ve mitokondriyal anormallikler görülüyor. Bu hastada sarkomerik düzeyde aşağıdaki değişikliklerden hangisi beklenir?","options":["Titinlerin elastik segment uzunluğunun kısalması ile pasif gerilme kuvvetinin azalması","Tropomiyozinin aktin filaman üzerindeki pozisyonunun değişerek sürekli aktif konumda kalması","Troponin I fosforilasyonunda artış ile miyozin ATPaz aktivitesinin yükselmesi","Z disklerinin sayısının artmasına bağlı sarkomer uzunluğunun kısalması","Nebulin miktarının azalmasına bağlı ince filaman uzunluğunun düzensizleşmesi"],"correct":4,"exp":"Miyopatik süreçlerde kas lifi yapısı bozulurken iskelet kasının ince filaman mimarisi öncelikli olarak etkilenir. Nebulin, aktin (ince) filaman uzunluğunu belirleyen dev bir sarkomeri yapısal proteinidir; hem filaman uzunluğunu sabit tutar hem de aktin polimerizasyonuna rehberlik eder. Nebulin ekspresyonundaki azalma, ince filaman uzunluğunda sarkomerden sarkomere farklılıklara yol açar ve kuvvet üretimini ciddi biçimde bozar. Titin ise kalın (miyozin) filaman çevresinde pasif elastisiteyi sağlar; titinin elastik segmenti zedelenmeden kısalmaz. Troponin I fosforilasyonu miyokartta daha belirgindir, iskelet kasında bu mekanizma primer patoloji değildir. Z disk sayısı değil Z disk yapısı bozulur. Tropomiyozin ise miyopatilerde sürekli aktif konumda kalmaz, aksinizotropik düzenleme korunmaya çalışılır."},{"id":8285,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 2 haftadır artan efor dispnesi ve bacaklarda ödem yakınmasıyla başvuruyor. Özgeçmişinde hipertansiyon ve tip 2 diyabetes mellitus mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30 olarak ölçülüyor. Hastaya ivabradine başlanıyor. Aşağıdakilerden hangisi bu ilacın etkisiyle beklenen elektrofizyolojik değişimi doğru tanımlar?","options":["Sinoatriyal düğümde IKs kanallarının aktivasyonu ile repolarizasyon süresinin kısalması","Sinoatriyal düğümde If akımının (funny current) baskılanması ile diastolik depolarizasyon eğiminin azalması","Atriyoventriküler düğümde T tipi kalsiyum kanallarının blokajı ile PR intervalinin uzaması","Hız purkinje liflerinde IK1 kanallarının inhibisyonu ile istirahat membran potansiyelinin pozitifleşmesi","Sinoatriyal düğümde L tipi kalsiyum kanallarının blokajı ile aksiyon potansiyeli plato fazının kısalması"],"correct":1,"exp":"İvabradine, sinoatriyal (SA) düğümdeki HCN (hyperpolarization-activated cyclic nucleotide-gated) kanalları aracılığıyla oluşan If akımını (funny current) selektif olarak inhibe eder. Bu akım, aksiyon potansiyelinin repolarizasyonu sonrasında hiperpolarize membranın yavaş diastolik depolarizasyonunu sağlar. If baskılandığında diastolik depolarizasyon eğimi yavaşlar, eşik potansiyeline ulaşmak daha uzun sürer ve kalp hızı azalır. İvabradine L tipi kalsiyum kanallarını etkilemez; dolayısıyla plato fazı ve AV iletisi korunur. IK1 kanalları ventriküler miyositlerin istirahat potansiyelini belirler, ivabradine bu kanallara etki etmez. T tipi kalsiyum kanalları AV düğüm iletisinde rol oynar; ivabradine bu kanalları hedef almaz, PR intervali uzamaz. IKs aktivasyonu ise tam tersi yönde repolarizasyonu hızlandırır."},{"id":8286,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, ani başlayan çift görme, sol göz kapağında düşüklük ve ışığa yanıtsız sol pupil genişlemesi ile acil servise getiriliyor. Nörolojik muayenede sol gözde aşağıya ve dışa deviasyon saptanıyor. Beyin görüntülemesinde sol posterior komünikan arterde anevrizma tespit ediliyor. Aşağıdakilerden hangileri bu hastanın bulgularını açıklar?\nI. Okulomotor sinirin parasempatik liflerinin sıkışması ile pupil sfinkter kasının paralizisi\nII. Levator palpebrae süperioris kasına giden somatik motor liflerin hasarı ile pitozis\nIII. Süperior oblik ve lateral rektus dışındaki ekstraoküler kasların paralizisi ile aşağı-dışa deviasyon\nIV. Sempatik sinir liflerinin sıkışması ile midriyazis ve ipsilateral anhidrozis\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız III","II, III ve IV","I ve IV","I, II, III ve IV","I, II ve III"],"correct":4,"exp":"N. oculomotorius (III. kranial sinir) hasarında klasik bulgular şunlardır: (1) Parasempatik lifler sinirin dış yüzeyinde seyreder ve bası ile önce bu lifler etkilenir; sfinkter pupillae felci nedeniyle ışığa yanıtsız midriyazis oluşur (öncül I doğru). (2) Levator palpebrae süperioris III. sinir tarafından inerve edilir; hasarda pitozis gelişir (öncül II doğru). (3) III. sinir; süperior, inferior ve medial rektus ile inferior oblik kasları inerve eder. Bu kaslar felç olduğunda, işlevini sürdüren IV. sinir (süperior oblik - içe ve aşağı rotasyon) ve VI. sinir (lateral rektus - dışa deviasyon) kasları hakim olur; göz aşağıya ve dışa kayar (öncül III doğru). Öncül IV yanlıştır; midriyazis parasempatik blokajdandır, sempatik lifler komprese olmaz ve anhidrozis bu tabloda beklenmez (anhidrozis Horner sendromundaki sempatik hasar ile görülür). Dolayısıyla I, II ve III doğrudur."},{"id":8287,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"45 yaşında kadın hasta, 3 haftadır süren poliüri, noktüri ve aşırı susama yakınmalarıyla başvuruyor. Günlük idrar miktarı 6 litreye ulaşmış. Serum sodyumu 150 mEq/L, serum ozmolalitesi 310 mOsm/kg, idrar ozmolalitesi 80 mOsm/kg olarak saptanıyor. Su kısıtlama testinde idrar ozmolalitesi değişmiyor; ancak desmopressin uygulamasının ardından idrar ozmolalitesi 650 mOsm/kg'a yükseliyor. Bu hastada hangi mekanizma defektif olup renal tübülde hangi değişiklik gözlenir?","options":["Toplayıcı tüp ana hücrelerinde AQP2 ekspresyonunun artması ile idrar konsantrasyonunda yükselme","Henle kulpunun inen kolunda AQP1 kanallarının yokluğu ile kortikomedullar ozmotik gradientin bozulması","Proksimal tübülde NHE3 taşıyıcısının inaktivasyonu ile izozmotik sıvı geri emiliminin durması","Toplayıcı tüp ana hücrelerinde V2 reseptörlerinin işlevsizliği nedeniyle desmopressine yanıtsızlık","Hipotalamustan ADH salınımının azalması nedeniyle toplayıcı tüplerde AQP2 ekspresyonunun düşük kalması"],"correct":4,"exp":"Klinik tablo merkezi (santral) diabetes insipidusu işaret etmektedir. Su kısıtlama testinde idrar konsantre edilememesi ADH yetersizliğini ya da ADH direncini gösterir; ancak desmopressin sonrasında idrar ozmolalitesinin belirgin artması (80'den 650 mOsm/kg'a), toplayıcı tüpteki V2 reseptörlerinin ve AQP2 mekanizmasının sağlam olduğunu ortaya koyar. Sorun hipotalamustan yetersiz ADH salınımıdır. ADH yokluğunda toplayıcı tüp ana hücrelerinde AQP2 kanalları apikal membranda eksprese edilmez; su geri emilimi gerçekleşmez ve büyük hacimde hipotonik idrar oluşur. Desmopressin verildiğinde V2 reseptörleri aktive olur, cAMP-PKA yoluyla AQP2 kanalları apikal membrana taşınır ve idrar yoğunlaşır. Nefrojenik DI'da ise V2 reseptörü veya AQP2 defekti bulunduğundan desmopressine yanıt alınamaz."},{"id":8288,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Aşağıdaki öncüllerin hangisi ya da hangileri pulmoner sürfaktan ile ilgili doğrudur?\nI. Tip II pnömositler tarafından sentezlenerek alveol yüzeyine salgılanır.\nII. Fosfatidilkolin (DPPC) başlıca bileşenidir ve yüzey gerilimini azaltır.\nIII. Eksikliğinde küçük alveoller büyük alveollere göre daha az kollapsa eğilimlidir.\nIV. Gebeliğin 28. haftasından önce doğan prematüre bebeklerde yetersiz üretim, respiratuar distres sendromuna yol açar.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","4","1","3","2"],"correct":3,"exp":"Öncül I doğrudur: Sürfaktan, alveol epitelindeki tip II pnömositler (granüler pnömositler) tarafından sentezlenip lamellar cisimcikler aracılığıyla alveol lümenine salgılanır. Öncül II doğrudur: Sürfaktanın yaklaşık %70'i dipalmitoilfosfatidilkolin (DPPC) formundaki fosfatidilkolinden oluşur; bu lipit tabakası hava-sıvı ara yüzünde yüzey gerilimini düşürerek alveollerin açık kalmasını sağlar. Öncül III yanlıştır: Laplace yasasına göre küçük yarıçaplı alveollerde iç basınç daha yüksektir (P = 2T/r); yani sürfaktan yokluğunda küçük alveoller, büyüklere kıyasla kollapsa çok daha eğilimlidir. Sürfaktan eksikliği özellikle küçük alveolleri tehdit eder. Öncül IV doğrudur: Sürfaktan üretimi gestasyonun yaklaşık 24-28. haftasında başlar ve 35. haftada olgun düzeye ulaşır. 28. haftadan önce doğan bebeklerde sürfaktan yetersizliği, tip II pnömositlerinin immatüritesine bağlı yeni doğan respiratuar distres sendromuna (NRDS/hyalen membran hastalığı) yol açar. Doğru öncüller I, II ve IV olduğundan 3 öncül doğrudur."},{"id":8289,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan egzersiz intoleransı ve proksimal kas güçsüzlüğü yakınmasıyla başvuruyor. EMG'de miyopatik patern saptanıyor, serum CK düzeyi 4 kat yüksek bulunuyor. Kas biyopsisinde tip II kas lifi atrofisi ve mitokondriyal agregasyon (ragged-red fibers) izleniyor. Hastaya mitokondriyal miyopati tanısı konuluyor. Bu hastada egzersiz sırasında venöz kanda laktat ve pirüvat düzeyleri ölçülürse beklenen bulgu aşağıdakilerden hangisidir?","options":["Laktat/pirüvat oranının normale göre belirgin artmış olması","Laktat düzeyinin düşük, pirüvat düzeyinin yüksek olması","Laktat/pirüvat oranının normale göre belirgin azalmış olması","Pirüvat yüksekliğine eşlik eden laktat normalliği","Her iki düzeyin de normal sınırlarda kalması"],"correct":0,"exp":"Mitokondriyal miyopatilerde solunum zinciri defektleri nedeniyle oksidatif fosforilasyon bozulur. Egzersiz sırasında pirüvat mitokondride işlenemez ve sitozolde laktat dehidrojenaz aracılığıyla laktata dönüştürülür. Bu nedenle hem laktat hem pirüvat artar; ancak laktat artışı orantısız biçimde fazla olduğundan laktat/pirüvat oranı belirgin yükselir (normalin 2-3 katı). Bu bulgu mitokondriyal hastalıklar için karakteristik olup pirüvat dehidrojenaz eksikliğinden (pirüvat yüksek, oran değişmez) ve diğer miyopatilerden ayırt ettirici önem taşır."},{"id":8290,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında kadın hasta, akut miyokard enfarktüsü nedeniyle yoğun bakımda izlenmektedir. Enfarktüsten 36 saat sonra çekilen ekokardiyografide EF %30 olarak ölçülmekte, pulmoner kapiller kama basıncı 22 mmHg ve kardiyak indeks 1,8 L/dk/m² saptanmaktadır. Hastaya dobutamin başlanmaktadır. Dobutaminin bu hastadaki hemodinamik etkisine ilişkin aşağıdaki öncülleri değerlendiriniz.\nI. Miyokarddaki beta-1 reseptörleri üzerinden cAMP artışına yol açarak kontraktiliteyi artırır.\nII. Periferik vasküler direnci sistemik vazokonstrüksiyon yoluyla artırır ve koroner perfüzyon basıncını yükseltir.\nIII. Normalde koronerler otoregülasyon nedeniyle dobutamine yanıt vermez, bu nedenle koroner kan akımı değişmez.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["II ve III","Yalnız I","I ve II","Yalnız III","I, II ve III"],"correct":1,"exp":"Öncül I doğrudur: Dobutamin beta-1 agonist etkiyle miyokartta adenilat siklaz aktivasyonu ve cAMP artışına yol açar; protein kinaz A aracılıklı yolakla L-tipi Ca²⁺ kanalları fosforile olur ve kontraktilite (inotropi) artar. Öncül II yanlıştır: Dobutamin hem beta-1 hem beta-2 reseptörlerine agonist etki gösterir; beta-2 aktivasyonu periferik vazodilatasyon yapar, sistemik vasküler direnci düşürür. Dopamin veya norepinefrinin aksine vazokonstrüktör değildir. Öncül III yanlıştır: Artmış kontraktilite miyokardın oksijen tüketimini artırır; bu metabolik artış koroner otoregulatuar mekanizmaları tetikler ve koroner kan akımı metabolik ihtiyaca paralel biçimde artar. Dolayısıyla doğru öncül sayısı yalnız I'dir."},{"id":8291,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 yıldır devam eden ödem, proteinüri ve hipertansiyon yakınmasıyla nefroloji polikliniğine başvuruyor. 24 saatlik idrarda protein atılımı 4,2 g, serum albümin 2,1 g/dL, total kolesterol 320 mg/dL olarak bulunuyor. Böbrek biyopsisinde podosit ayaksı çıkıntı füzyonu ve bazal membranda diffüz kalınlaşma saptanıyor. Hastada glomerüler filtrasyon bariyerinin elektriksel yük seçiciliği incelendiğinde, sağlıklı bireyle karşılaştırıldığında beklenen bulgu aşağıdakilerden hangisidir?","options":["Glikokaliks ve glomerüler bazal membranda heparan sülfat proteoglikanlarının azalmasına bağlı anyonik yük kaybı","Bowman kapsülünün iç yaprağındaki paryetal hücre hasarına bağlı protein kaçağı","Podosit kaynaklı nefrin ekspresyonunun artmasına bağlı filtrasyon bariyeri güçlenmesi","Mezangiyal hücre proliferasyonuna bağlı filtrasyon yüzey alanının artması","Tübüler geri emilim kapasitesinin aşılmasına bağlı albüminürinin ortaya çıkması"],"correct":0,"exp":"Glomerüler filtrasyon bariyeri boyut seçiciliği (GBM porları) ve yük seçiciliği (anyonik yük tabakası) olmak üzere iki bileşenden oluşur. Negatif yüklü albüminin geçişini önleyen başlıca yapı, podosit glikokaliksi ve GBM'de yoğun olarak bulunan heparan sülfat proteoglikanlarıdır. Bu vakada minimal change hastalığından çok membranöz nefropati/FSGS benzeri tabloda olduğu gibi podosit hasarı söz konusu olduğunda heparan sülfat içeriği azalır, anyonik bariyer bozulur ve albümin gibi negatif yüklü proteinler filtrasyona uğrar. Nefrin ekspresyonu ise hastalıkta azalır, artar değil. Tübüler geri emilim kapasitesi saatlik birkaç gramı aşan yükte gerçekten aşılır; ancak asıl patoloji glomerüler bariyerdedir, tübüler kapasite ikincil bozulur. Doğru şık A'dır."},{"id":8292,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"22 yaşında erkek hasta, trafik kazası sonrası sağ el bileğinden geçen kesici alet yaralanması nedeniyle acile getiriliyor. Muayenede sağ elde başparmak karşıya getirme hareketi yok, avuç içi lateral yarısında his kaybı ve tenar atrofi saptanıyor. Hastaya el cerrahisi konsültasyonu yapılıyor ve primer sinir onarımı planlanıyor. Sinir kesisi sonrasında distal güdükte gerçekleşen Wallerian dejenerasyona ait aşağıdaki öncülleri değerlendiriniz.\nI. Akson ve miyelin kılıf hasarı başlar ve Schwann hücreleri miyelin döküntülerini fagosite eder.\nII. Schwann hücreleri çoğalarak Büngner bantlarını oluşturur ve aksonal büyüme için rehberlik sağlar.\nIII. Wallerian dejenerasyon tamamlandıktan sonra proksimal güdükteki nöron hücre gövdesi de apoptoza girerek kalıcı kayba uğrar.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve II","I, II ve III","Yalnız II","Yalnız I","II ve III"],"correct":0,"exp":"Öncül I doğrudur: Sinir kesisinin ardından distal güdükte Wallerian dejenerasyon başlar; aksoplazmik transport durur, akson ve miyelin kılıf 24-48 saat içinde parçalanmaya başlar. Schwann hücreleri ve izleyen süreçte göç eden makrofajlar miyelin döküntülerini fagosite eder. Öncül II doğrudur: Schwann hücreleri prolifere olarak bazal lamina tüpleri içinde sıralanır; bu yapılara Büngner bantları denir. Proksimal güdükten uzanan yeni akson filizlerinin rejenerasyonu için fiziksel ve nörotrofik kılavuzluk sağlar. Öncül III yanlıştır: Proksimal nöron hücre gövdesi Wallerian dejenerasyona değil, merkomi (aksonal reaksiyon/kromatoliz) adı verilen geri dönüşümlü bir yanıta uğrar; Nissl cisimcikleri dağılır, çekirdek ekzantrik hale gelir. Onarım başarılı olursa hücre gövdesi toparlanır, apoptoz görülmez. Dolayısıyla yalnız I ve II doğrudur."},{"id":8293,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"28 yaşında sağlıklı erkek gönüllü, bir araştırma çalışması kapsamında pulmoner fonksiyon testine alınıyor. Spirometrik ölçümde zorlu vital kapasite (FVC), FEV1/FVC oranı ve tepe akım hızı normal bulunuyor. Araştırmacı, derin inspirasyon sırasında akciğer parankim elastisitesini sağlayan temel yapısal proteini sorguluyor. Bu özelliği sağlayan başlıca protein aşağıdakilerden hangisidir?","options":["Kollajen tip IV","Laminin","Fibronektin","Kollajen tip I","Elastin"],"correct":4,"exp":"Akciğer parankiminin geriye dönüş (elastik recoil) özelliği başta elastin olmak üzere kollajen lifler ve yüzey aktif madde tarafından sağlanır. Elastin, interstisyel bağ dokusunda fibroblastlar tarafından sentezlenir ve derin inspirasyon sonrası akciğerin pasif olarak normal hacmine dönmesine olanak tanır. Kollajen tip IV bazal membranın yapısal bileşenidir; tip I ise gerilme direncini sağlar ancak elastik geri dönüş için birincil protein değildir. Fibronektin ve laminin hücre adezyonunda görevlidir. Amfizemde elastin yıkımı ön plandadır ve elastik recoil kaybına bağlı hava hapsi gelişir; bu durum elastinin önemi açısından klinik referans noktasıdır."},{"id":8294,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"19 yaşında kadın hasta, 4 aydır süren yorgunluk, 3 haftadır artan sarılık ve koyu renkli idrar yakınmasıyla başvuruyor. Özgeçmişinde çocuklukta safra taşı operasyonu geçirdiği öğreniliyor. Fizik muayenede splenomegali saptanıyor. Periferik yaymada sferosit ve retikülositoz izleniyor. Doğrudan Coombs testi negatif bulunuyor. Bu hastada eritrosit membranı fonksiyon bozukluğuna ilişkin aşağıdaki öncülleri değerlendiriniz.\nI. Spektrin-ankyrin bağlantısının bozulması eritrositin bikonkav diskoid şeklini kaybetmesine ve sferositoze yol açar.\nII. Sferositik eritrositler, dalak sinüslerinden geçerken deformabilite yetersizliği nedeniyle seçici olarak tutulur ve yıkılır.\nIII. Doğrudan Coombs testinin negatif olması, hemolizin otoimmün değil intrinsik membran defektine bağlı olduğunu destekler.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II ve III","Yalnız I","I, II ve III","I ve III","Yalnız III"],"correct":2,"exp":"Öncül I doğrudur: Herediter sferositozda başta spektrin, ankyrin, bant 3 proteini ve protein 4.2 olmak üzere eritrosit iskelet proteinlerindeki defektler lipid çift tabakasını iç iskeletle bağlayan bağlantıları bozar. Lipid kaybı ve membran yüzey alanının azalması sonucunda eritrosit bikonkav disk şeklini yitirir ve sferositik forma döner. Öncül II doğrudur: Sferositler, sağlıklı eritrositlerin sahip olduğu fazla membran yüzey alanı ve deformabiliteyi taşımaz. Dalak kırmızı pulpasının dar sinüsoidlerini geçemeyen sferositler burada tutularak makrofajlar tarafından fagosite edilir; bu süreç ekstravaskü̈ler hemolizi açıklar. Öncül III doğrudur: Doğrudan Coombs testi eritrosit yüzeyindeki IgG veya kompleman birikimini gösterir; otoimmün hemolitik anemide pozitiftir. Negatiflik, eritrosit yıkımının dışsal bir immün mekanizmadan değil, intrinsik membran iskelet defektinden kaynaklandığını destekler. Dolayısıyla üç öncül de doğrudur."},{"id":8295,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya tedavi başlanıyor ve belirli bir süre sonra yapılan ölçümde kapiler wedge basıncının düştüğü, kardiyak outputun arttığı, sistemik vasküler direncin azaldığı gözlemleniyor. Bu hastaya verilen ilaç aşağıdakilerden hangisidir?","options":["Metoprolol","Nitrogliserin","Furosemid","Enalapril","Digoksin"],"correct":3,"exp":"Kapiler wedge basıncını düşürme (preload azalması), kardiyak outputu artırma ve sistemik vasküler direnci azaltma (afterload azalması) birlikteliği ACE inhibitörü olan enalaprilin hemodinamik profiline uymaktadır. Enalapril, anjiyotensin II sentezini azaltarak hem arteriyel dilatasyona (afterload azalır) hem de aldosteron baskılanması üzerinden sıvı atılımına (preload azalır) yol açar; bu iki etki birlikte kalp debisini artırır. Metoprolol kalp hızını ve kontraktiliteyi azaltır, digoksin kontraktiliteyi artırır ancak SVR'yi düşürmez, furosemid ağırlıklı olarak preload üzerine etkilidir ve SVR'yi belirgin düşürmez, nitrogliserin ise esas olarak venodilatatördür ve SVR'yi çok az etkiler."},{"id":8296,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 20 yıldır sigara içme öyküsü var. Son 6 ayda artan nefes darlığı ve balgam çıkarma yakınmalarıyla başvuruyor. Solunum fonksiyon testlerinde FEV1/FVC oranı %58, TLC artmış, DLCO belirgin azalmış bulunuyor. Arteriyel kan gazında PaO2: 58 mmHg, PaCO2: 48 mmHg, pH: 7.38 saptanıyor. Bu hastada aşağıdaki öncüllerden hangileri doğrudur?\nI. Kronik hiperkapni nedeniyle böbrekler bikarbonat tutarak kompansasyon yapmaktadır.\nII. DLCO düşüklüğü, alveoler yüzey alanının ve kapiler yatağın azaldığını göstermektedir.\nIII. FEV1/FVC oranının düşük olması restriktif patern lehine değerlendirilmelidir.","options":["I, II ve III","I ve II","II ve III","Yalnız II","Yalnız I"],"correct":1,"exp":"I. Doğru: PaCO2: 48 mmHg ile kronik hiperkapni mevcuttur, pH 7.38 ile kompanse durumdadır; bu kompansasyon böbreklerin HCO3- tutması (bikarbonat retansiyonu) ile sağlanmaktadır. II. Doğru: DLCO (difüzyon kapasitesi), amfizemde alveoler septaların yıkımına bağlı yüzey alanı ve pulmoner kapiler yatak kaybını yansıtır; amfizem tanısını destekleyen önemli bir parametredir. III. Yanlış: FEV1/FVC < 70 obstrüktif paterni gösterir; restriktif paterde FEV1/FVC normal ya da artmış, TLC ise azalmış olur. Bu hastada TLC artmış olması da hava hapsi ve obstrüksiyonu destekler."},{"id":8297,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 3 haftadır süren ödem, köpüklü idrar ve yorgunluk yakınmasıyla başvuruyor. İdrar tetkikinde 24 saatlik protein atılımı 4.8 g/gün, serum albumin 1.9 g/dL, total kolesterol 320 mg/dL, LDL 240 mg/dL olarak saptanıyor. Böbrek biyopsisi planlanıyor. Bu hastada görülen hiperlipideminin temel mekanizmasıyla ilgili aşağıdakilerden hangisi doğrudur?","options":["Proteinüri nedeniyle idrarla kaybedilen LDL reseptörleri dolaşımdaki LDL yıkımını engeller.","Albümin kaybına bağlı onkotik basınç düşüşü karaciğerde lipoprotein sentezini uyarır ve lipoprotein lipaz aktivitesi azalır.","Anjiyotensin II'nin artması hepatik VLDL klirensini doğrudan inhibe eder.","Kortizol düzeyinin artması adipoz dokuda lipolizi baskılayarak trigliserid birikimine yol açar.","Renal arter stenozu nedeniyle renin salınımının artması lipoprotein lipaz aktivitesini baskılar."],"correct":1,"exp":"Nefrotik sendromda (proteinüri >3.5 g/gün, hipoalbüminemi, ödem, hiperlipidemi tetrad) hiperlipidemi iki mekanizmayla açıklanır: (1) Onkotik basınç düşüşü karaciğerde kompansatuar protein sentezini uyarır; bu süreçte lipoprotein sentezi (VLDL, LDL) artar. (2) İdrarda lipoprotein lipaz kofaktörü olan apolipoprotein CII kaybı ve lipoprotein lipaz aktivitesinin azalması, lipoproteinlerin yıkımını engeller. Bu iki etki birlikte hiperkolesterolemiye yol açar. Diğer seçeneklerde açıklanan mekanizmalar nefrotik sendrom patofizyolojisiyle örtüşmez."},{"id":8298,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"28 yaşında erkek hasta, trafik kazası sonrası sol tarafta el bileği düzeyinde kesici alet yaralanması tanımlıyor. Muayenede median sinir hasarı düşünülüyor. Aşağıdaki öncüllerden kaç tanesi bu tabloya uygun bulgudur?\nI. Başparmak, işaret parmağı ve orta parmakta palmar yüzde his kaybı\nII. Tenar atrofi ve 'maymun eli' deformitesi\nIII. Başparmak abdüksiyonu ve karşı koyma hareketlerinde güçsüzlük\nIV. Yüzük parmağının ulnar tarafında ve serçe parmağında his kaybı","options":["3","2","Hiçbiri","1","4"],"correct":0,"exp":"I. Doğru: Median sinir el bileği düzeyinde el 1., 2., 3. ve 4. parmağın radyal yarısının palmar yüzünün duyusunu taşır. II. Doğru: Median sinir tenar kasları (abductor pollicis brevis, opponens pollicis, flexor pollicis brevis yüzeyel başı) innerve eder; kronik hasarda tenar atrofi ve maymun eli görülür. III. Doğru: Tenar kas grubu median sinir tarafından innerve edildiğinden abdüksiyon ve opozisyon güçsüzlüğü beklenir. IV. Yanlış: Yüzük parmağının ulnar tarafı ve serçe parmağı ulnar sinirin duyu alanıdır; median sinir hasarında etkilenmez. Dolayısıyla I, II ve III uygun bulgudur; 3 tanesi doğrudur."},{"id":8299,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Kemik iliğinde CFU-E kolonilerinden olgunlaşarak periferik kana geçen eritrositlerin son diferansiyasyon basamağında çekirdeği dışarı atması ve mitokondri ile ribozomlarını yitirmesiyle oluşan, RNA kalıntıları içerdiği için cresyl violet ile boyandığında çöp sepeti görünümü veren hücre aşağıdakilerden hangisidir?","options":["Normoblast","Makrosit","Retikülosit","Eritroblast","Sferosit"],"correct":2,"exp":"Retikülosit, ortokromatik eritroblastın çekirdeğini dışarı atmasının hemen ardından oluşur. Henüz mitokondri ve ribozom artıklarına sahiptir; bu RNA kalıntıları krezil viyole veya parlak krezil mavisi ile boyandığında çöp sepeti (basketwork) görünümü verir. Periferik kanda 1-2 gün dolaştıktan sonra olgun eritrosit haline gelir. Eritroblastlar çekirdekli öncül hücrelerdir, normoblast ortokromatik eritroblastın eş anlamlısıdır (çekirdeği henüz atmamıştır), makrositler büyük eritrositlerdir, sferositler ise küresel şekilli patolojik eritrositlerdir."},{"id":8300,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"45 yaşında erkek hasta, 8 yıldır gastroözofageal reflü hastalığı tanısıyla proton pompa inhibitörü kullanıyor. Son endoskopide distal özofagusta salmon renkli mukoza adaları saptanıyor ve biyopside goblet hücreleri içeren kolumnar epitel görülüyor. Tanı Barrett özofagusu olarak konuluyor. Bu hastada gelişen histolojik değişikliğin adı ve bu değişikliğin taşıdığı en önemli klinik risk aşağıdakilerden hangisinde doğru eşleştirilmiştir?","options":["Displazi - Barrett karsinomu","Displazi - squamöz hücreli karsinom","Metaplazi - özofageal adenokarsinom","Metaplazi - squamöz hücreli karsinom","Hiperplazi - gastrointestinal stromal tümör"],"correct":2,"exp":"Barrett özofagusunda normal özofagus squamöz epiteli, kronik asit maruziyeti sonucunda goblet hücreleri içeren intestinal tipte kolumnar epitele dönüşür; bu değişiklik metaplazidir (bir diferansiye doku tipinin başka bir diferansiye doku tipine dönüşümü). Metaplazi kendi başına kanser değildir; ancak displazi aşamasına ilerleyerek özofageal adenokarsinoma (özellikle gastroözofageal bileşke adenokarsinomu) zemin hazırlar. Squamöz hücreli karsinom Barrett özofagusuyla değil, sigara-alkol gibi risk faktörleriyle ilişkilidir. Barrett özofagusu displazisiz iken endoskopik takip, yüksek dereceli displazide ablasyon veya rezeksiyon önerilir."},{"id":8301,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı şikayetiyle kardiyoloji polikliniğine başvuruyor. Yapılan koroner anjiyografide sol ön inen arterde %85 darlık saptanıyor. Hastaya perkütan koroner girişim planlanmakla birlikte tıbbi tedavi olarak nitrogliserin başlanıyor. Nitrogliresinin etki mekanizmasına bağlı olarak aşağıdaki öncüllerin hangileri doğrudur?\nI. Nitrik oksit salınımı yoluyla venöz kapasitans damarlarında dilatasyon oluşturarak ön yükü azaltır.\nII. Koroner arterlerde düz kas hücrelerinde cGMP düzeyini artırarak vazodilatasyon sağlar.\nIII. Endotelyal nitrik oksit sentaz (eNOS) üzerinden etki ederek trombosit agregasyonunu artırır.\nIV. Sistemik arteriyel direnci azaltarak ard yükü düşürür ve miyokard oksijen tüketimini azaltır.","options":["I, II, III ve IV","I ve II","I, III ve IV","I, II ve IV","II ve III"],"correct":3,"exp":"Nitrogliserin, organik nitrat grubu bir ilaç olup biyolojik olarak nitrik okside (NO) dönüşerek etki gösterir. NO, vasküler düz kas hücrelerinde guanilil siklazı aktive ederek cGMP düzeyini artırır ve miyozin hafif zincir fosfatazı aktive edip miyoziyin defosforilasyonuna yol açar; bu da düz kas gevşemesi ve vazodilatasyon ile sonuçlanır. Düşük dozlarda ağırlıklı olarak venöz kapasitans damarlarda dilatasyon yaparak ön yükü azaltır; daha yüksek dozlarda arteriyel direnç damarlarını da etkileyerek ard yükü düşürür. Böylece miyokard oksijen tüketimi azalır. Öncül III yanlıştır; NO trombosit agregasyonunu artırmaz, aksine inhibe eder. eNOS endojen NO kaynağıdır, ancak nitrogliresinin etkisi eNOS bağımsız, eksojen NO üretimine dayanır. Dolayısıyla I, II ve IV doğru öncüllerdir."},{"id":8302,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"35 yaşında kadın hasta, 6 aydır devam eden progresif dispne ve nonprodüktif öksürük şikayetiyle göğüs hastalıkları polikliniğine başvuruyor. Solunum fonksiyon testinde FEV1/FVC: %85, TLC ve RV değerleri belirgin şekilde azalmış olup DLCO düşük saptanıyor. Yüksek çözünürlüklü bilgisayarlı tomografide bilateral alt lob ağırlıklı retiküler opasiteler ve bal peteği görünümü izleniyor. Tanısı idiyopatik pulmoner fibrozis olarak konulan hastada, alveolar düzeyde meydana gelen patolojik süreçle ilgili aşağıdakilerden hangisi en doğrudur?","options":["Makrofaj aktivasyonu yoluyla elastaz salınımı artar ve elastin yıkımı diffüzyon kapasitesini bozar.","Tip II pnömositlerden salınan TGF-β, fibroblast aktivasyonu ve aşırı kollajen birikimini tetikleyerek alveolokapiller membranı kalınlaştırır.","Alveoler septaların incelmesi nedeniyle difüzyon mesafesi kısalır ve DLCO yükselir.","Küboidal tip I pnömositlerin hasarına bağlı surfaktan eksikliği gelişerek yüzey gerilimi azalır.","Tip I pnömositlerin proliferasyonu surfaktan üretimini artırarak kompliyansı yükseltir."],"correct":1,"exp":"İdiyopatik pulmoner fibrozis (IPF), alveolar epitel hasarının ardından anormal yara iyileşmesinin tetiklediği ilerleyici bir fibrotik akciğer hastalığıdır. Hasarlı tip I pnömositler yerine çoğalan tip II pnömositler, TGF-β başta olmak üzere profibrotik sitokinler salgılar. TGF-β, fibroblastları miyofibroblastlara dönüştürür; bu hücreler aşırı kollajen ve ekstrasellüler matriks biriktirerek alveolokapiller membranı kalınlaştırır. Kalınlaşan membran difüzyon mesafesini artırır, DLCO belirgin biçimde düşer. Hastalık restriktif paterne yol açtığından FEV1/FVC korunur ya da artar, akciğer hacimleri (TLC, RV) azalır. Surfaktan tip II pnömositlerden üretilir; tip I pnömositler bu görevi üstlenmez. Seçeneklerdeki diğer ifadeler histofizyolojik açıdan yanlış ya da ters yönlüdür."},{"id":8303,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 3 yıldır ilerleyen yürüme güçlüğü, ellerde titreme ve yüz ifadesinde azalma şikayetleriyle nöroloji polikliniğine başvuruyor. Nörolojik muayenede istirahat tremoru, rijidite, bradikinezi ve postural instabilite saptanıyor. Beyin görüntülemede substantia nigra pars kompakta nöronlarında ileri düzeyde kayıp izleniyor. Hastaya dopaminerjik tedavi başlanıyor. Aşağıdaki öncüllerin hangileri bu hastalığın patofizyolojisi ve tedavisiyle uyumludur?\nI. Striatum'daki D1 reseptörlerinin aktivasyonu direkt yolağı inhibe ederek talamik inhibisyonu artırır.\nII. Dopamin eksikliği nedeniyle direkt yolak aktivitesi azalır, indirekt yolak aktivitesi artar ve talamus üzerindeki inhibisyon güçlenir.\nIII. Levodopa, kan-beyin bariyerini geçerek santral sinir sisteminde dopamine dönüşür ve semptomları hafifleter.\nIV. Karbidopa, levodopanın periferik dekarboksilasyonunu önleyerek santral biyoyararlanımını artırır.","options":["I, II, III ve IV","I ve III","Yalnız III","I, II ve IV","II, III ve IV"],"correct":4,"exp":"Parkinson hastalığında substantia nigra pars kompaktadaki dopaminerjik nöronlar kaybedilir. Bazal ganglia devre modelinde dopamin; striatum D1 reseptörleri üzerinden direkt yolağı aktive eder (talamus inhibisyonunu azaltır, motor korteks aktivasyonunu artırır), D2 reseptörleri üzerinden ise indirekt yolağı inhibe eder. Dopamin eksikliğinde direkt yolak aktivitesi düşer, indirekt yolak hiperaktif hale gelir; sonuçta globus pallidus internusun talamus üzerindeki inhibisyonu artar ve motor çıktı azalır. Bu nedenle öncül I yanlıştır: D1 aktivasyonu direkt yolağı stimüle eder, inhibe etmez. Öncüller II, III ve IV ise fizyolojik ve farmakolojik açıdan doğrudur. Levodopa kan-beyin bariyerini aşabilir; dopaminin kendisi bu bariyeri geçemez. Karbidopa, periferik aromatik L-aminoasit dekarboksilazı inhibe ederek levodopanın periferik yıkımını azaltır ve santral biyoyararlanımını artırır."},{"id":8304,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"48 yaşında diyabet ve hipertansiyon tanılı erkek hasta, rutin kontrolünde serum kreatinin: 2,4 mg/dL, GFR: 28 mL/dak/1,73 m², idrarda albumin/kreatinin oranı 450 mg/g olarak saptanıyor. Böbrek biyopsisinde mezengial matriks artışı, Kimmelstiel-Wilson nodülleri ve glomerüler bazal membran kalınlaşması izleniyor. Bu hastanın böbrek histopatolojisi ve tübüler adaptasyon mekanizmaları göz önüne alındığında aşağıdaki öncüllerin kaç tanesi yanlıştır?\nI. Glomerüler bazal membranda tip IV kollajen birikimi filtrasyon yüzey alanını azaltır.\nII. Proksimal tübülde SGLT2 ekspresyonu azaldığından glikoz geri emilimi bozulur ve glikozüri gelişir.\nIII. Tübüloglomerüler feedback baskılanması afferent arteriyol dilatasyonuna katkıda bulunarak hiperfiltrasyon oluşturur.\nIV. Podosit kaybı ve efasman, selektif filtrasyon bariyerinin bozulmasıyla non-selektif proteinüriye yol açar.","options":["Hiçbiri yanlış değil","3 tanesi","Yalnız 1 tanesi","2 tanesi","Tamamı yanlış"],"correct":2,"exp":"diyabetik nefropati sürecinde glomerüler bazal membranda tip IV kollajen ve laminin birikimi filtrasyon yüzey alanını daraltır (I doğru). Podosit kaybı ve ayaksı çıkıntıların efasmanı, elektriksel ve boyut seçiciliğini bozan non-selektif proteinüriye yol açar (IV doğru). Erken diyabetik nefropatide tübüloglomerüler feedback baskılanması; yüksek glukozun proksimal tübülde artan SGLT2 ekspresyonuna bağlı Na+ ve glikoz reabsorbsiyonunu artırmasıyla maküla densa'ya ulaşan NaCl azalır, afferent arteriyol dilate olur ve hiperfiltrasyon oluşur (III doğru). Öncül II ise yanlıştır: diyabetik nefropatinin erken döneminde proksimal tübülde SGLT2 ekspresyonu artmaktadır, azalmamaktadır; bu durum tübüloglomerüler feedbackin baskılanmasına yol açar. Normoglisemide glikozüri olmaz; ancak eşik değer aşılırsa glikozüri görülür. Dolayısıyla yalnızca öncül II yanlıştır, yanıt 'Yalnız 1 tanesi'dir."},{"id":8305,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 2 aydır süren yorgunluk, çarpıntı ve egzersiz intoleransı şikayetleriyle iç hastalıkları polikliniğine başvuruyor. Menstrüasyon döngüleri düzensiz ve kanamaları ağır seyrediyor. Tam kan sayımında Hb: 7,8 g/dL, MCV: 68 fL, MCH: 21 pg, MCHC: 28 g/dL, ferritin: 4 ng/mL olarak saptanıyor. Bu hastaya demir takviyesi başlanırken hematopoezin hangi aşamasında düzelme en erken beklenir?","options":["Kemik iliğinde eritroid hiperplazinin gerilemesi","Eritrosit indekslerinin (MCV, MCH) normalleşmesi","Serum ferritin düzeyinin normale dönmesi","Periferik kanda retikülosit sayısının artması","Hemoglobin düzeyinin normale ulaşması"],"correct":3,"exp":"Demir eksikliği anemisinde demir tedavisine yanıt belirli bir sırayla ortaya çıkar. Tedaviye başlandıktan 3-5 gün içinde kemik iliğinde eritropoez hızlanır ve periferik kanda retikülosit sayısı artmaya başlar; bu, en erken gözlemlenen yanıttır. Yaklaşık 1-2 hafta içinde retikülosit doruk düzeyine ulaşır. Hemoglobin düzeyi genellikle 4-8 haftada belirgin yükselir, tam normalleşme 2-4 ay alabilir. Eritrosit indeksleri (MCV, MCH) hemoglobinden daha geç normalize olur. Ferritin depoların yenilenmesini yansıttığından en geç düzelen parametrelerden biridir ve aylar alabilir. Kemik iliği eritroid hiperplazisinin gerilemesi de periferik yanıttan sonra değerlendirilir."},{"id":8306,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan çiğneme güçlüğü ve çene yorgunluğu yakınmasıyla başvuruyor. Nörolojik muayenede tekrarlayan çiğneme hareketleriyle kuvvet kaybının belirginleştiği saptanıyor. Elektromiyografide tekrarlayan uyarıyla azalan aksiyon potansiyeli amplitüdü gözlemleniyor. Hastaya asetilkolinesteraz inhibitörü başlanıyor. Bu tedavinin etkinliğini değerlendirmek amacıyla kasın tekrarlayan uyarıma yanıtı incelendiğinde, aşağıdakilerden hangisi beklenen primer mekanizmanın göstergesidir?","options":["Presinaptik terminalde asetilkolin sentezinin artması","Nöromüsküler kavşakta asetilkolinin yıkımının yavaşlaması sonucu reseptör aktivasyonunun uzaması","Kas lifinde ryanodine reseptörü duyarlılığının artması","Miyelin kılıfında iletim hızının yükselmesi","Motor son plakta asetilkolin reseptörü sayısında artış"],"correct":1,"exp":"Myastenia gravis'te nöromüsküler kavşaktaki nikotinik asetilkolin reseptörlerine karşı oluşan otoantikorlar reseptör sayısını azaltır. Asetilkolinesteraz inhibitörleri, sinaptik yarıktaki asetilkolinin yıkımını engelleyerek mevcut asetilkolinin reseptörlerle daha uzun süre etkileşimde kalmasını sağlar; bu sayede kas kontraksiyonu güçlenir. Ryanodine reseptörü eksitatör-kontraksiyon eşleşmesinde rol oynar ancak bu ilaç grubunun hedefi değildir. Presinaptik sentez artışı ve miyelin iletimi bu ilaçların etki mekanizmasıyla ilgisizdir."},{"id":8307,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, 2 yıldır efor dispnesi ve çabuk yorulma yakınmalarıyla kardiyoloji polikliniğine başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu yüzde 30 olarak ölçülüyor, sol ventrikül kısmen genişlemiş. Hastaya ACE inhibitörü, beta-bloker ve spironolakton tedavisi başlanıyor. Tedavinin 6. ayında kontrol ekokardiyografisinde ejeksiyon fraksiyonunun yüzde 45'e yükseldiği ve sol ventrikül çapının azaldığı görülüyor. Bu hastada gözlenen yapısal iyileşme, öncelikle hangi histofizyolojik kavramla açıklanır?","options":["Patolojik kardiyak hipertrofinin gerilemesi ve ekstraselüler matriks yeniden şekillenmesi","Miyosit nekrozu sonrası fibröz doku replasmanı","Kardiyak miyositlerde hücre siklusu yeniden aktivasyonuyla proliferasyon","Purkinje lifi ağının reorganizasyonu","İnterstisyel ödemin çözülmesiyle miyofibril yoğunluğunun artması"],"correct":0,"exp":"Dilate kardiyomiyopatide ventrikül duvarı aşırı yüklenmeye bağlı patolojik hipertrofi ve ekstraselüler matriks (kollajen) birikimi ile yeniden şekillenir. ACE inhibitörleri anjiyotensin II'yi, spironolakton aldosteronu baskılayarak kardiyak fibrozu azaltır; beta-blokerler sempatik aktivasyonun neden olduğu patolojik hipertrofi sinyallerini engeller. Bu ilaç kombinasyonunun birlikte kullandırılmasıyla 'ters yeniden şekillenme' (reverse remodeling) gerçekleşir: ventrikül çapı azalır, miyosit hipertrofisi geri döner ve matriks fibrozu kısmen çözülür. Kardiyak miyositler terminal diferansiye hücreler olup fizyolojik koşullarda proliferasyon göstermez."},{"id":8308,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, uzun süreli tip 2 diyabetes mellitus ve hipertansiyon öyküsüyle birlikte 1 yıldır giderek artan ödem ve halsizlik yakınmalarıyla başvuruyor. İdrar analizinde proteinüri 3.5 g/gün üzerinde saptanıyor, serum albümini 2.1 g/dL. Böbrek biyopsisinde glomerüler bazal membranın kalınlaştığı, mezengial matriks artışı ve Kimmelstiel-Wilson nodülleri gözlemleniyor. Bu hastada proteinüri gelişiminden birincil olarak sorumlu olan glomerüler yapısal bozukluk hangisidir?","options":["Endotelyal fenestrasyon sayısının artması","Podosit ayak çıkıntılarının (ayaksı çıkıntı) kaybı ve glomerüler filtrasyon bariyerinin bozulması","Bowman kapsülü pariyetal epitelinin proliferasyonu","Mezengial hücrelerin fagositik kapasitesinin azalması","Efferent arteriolün düz kas tabakasının atrofisi"],"correct":1,"exp":"Diyabetik nefropati sürecinde kronik hiperglisemi; ileri glikasyon son ürünleri ve TGF-β aracılığıyla podosit hasarına yol açar. Podositler glomerüler filtrasyon bariyerinin kritik bileşenlerinden olan slite diyaframı oluşturur. Podosit ayak çıkıntılarının kaybı (ayaksı çıkıntı effacement) ile nefrin, podosin gibi slit diyafram proteinlerinin bozulması, proteinlerin serbestçe filtreden geçmesine neden olur. Kimmelstiel-Wilson nodülleri mezengial matriks artışını yansıtsa da proteinürinin primer nedeni podosit disfonksiyonudur. Endotelyal fenestrasyon artışı ya da efferent arteriol atrofisi bu tablonun açıklayıcısı değildir."},{"id":8309,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Santral sinir sisteminde miyelin kılıfını oluşturan hücre tipi hangisidir?","options":["Mikroglia","Astrositler","Oligodendrosit","Schwann hücresi","Ependim hücresi"],"correct":2,"exp":"Miyelin kılıfı santral sinir sisteminde oligodendrositler, periferik sinir sisteminde ise Schwann hücreleri tarafından oluşturulur. Her bir oligodendrosit birden fazla aksonun miyelin segmentini oluşturabilirken, her Schwann hücresi yalnızca tek bir aksonun bir segmentini sarar. Mikroglia SSS'nin bağışıklık hücreleridir, astrosit kan-beyin bariyeri ve destek işlevleri görür, ependim hücreleri ventrikülleri döşeyerek beyin-omurilik sıvısı üretimine katkı sağlar."},{"id":8310,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"45 yaşında kadın hasta, yıllardır devam eden gastroözofageal reflü hastalığı nedeniyle omeprazol kullanmaktadır. Üst gastrointestinal endoskopide distal özofagusta skuamöz epitelin kolumnar epitel ile yer değiştirdiği saptanıyor; biyopsi sonucu Barrett özofagusu olarak raporlanıyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Barrett özofagusunda gözlenen metaplazi, kronik asit hasarına karşı gelişen bir adaptif yanıttır.\nII. Bu metaplazide özofagusu döşeyen epitel tipi mide kardiya epiteline benzer kolumnar yapıya dönüşür ve intestinal metaplazi eşlik edebilir.\nIII. Barrett özofagusu, özofagus skuamöz hücreli karsinomuna dönüşüm riski taşıdığından yakın izlem gerektirir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, II ve III","I ve III","I ve II","Yalnız I","II ve III"],"correct":2,"exp":"Öncül I doğrudur: Barrett özofagusunda kronik asit-safra reflüsüne bağlı tekrarlayan hasar, skuamöz epitelin asit ortamına daha dayanıklı kolumnar epitelle yer değiştirmesine (metaplazi) neden olur; bu bir adaptif yanıttır. Öncül II doğrudur: Metaplastik epitel kolumnar karakterde olup intestinal tip goblet hücreleri içeren intestinal metaplazi sıklıkla eşlik eder. Öncül III yanlıştır: Barrett özofagusu, skuamöz hücreli karsinom değil, özofageal adenokarsinom riskini artırır; endoskopik izlem bu nedenle yapılır."},{"id":8311,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 30 paket-yıl sigara öyküsüyle birlikte 4 yıldır giderek kötüleşen efor dispnesi ve kronik öksürük yakınmalarıyla başvuruyor. Solunum fonksiyon testlerinde FEV1/FVC oranı yüzde 62, DLCO belirgin düşük saptanıyor. Yüksek çözünürlüklü bilgisayarlı tomografide alt loblarda baskın, retiküler opasiteler ve bal peteği görünümü izleniyor. Transbronşiyal biyopside zamansal ve mekansal heterojenite gösteren, fibroblastik odaklar içeren olağandışı interstisyel pnömoni (UIP) paterni raporlanıyor. Bu hastada bal peteği görünümünün oluşumundan histolojik olarak birincil sorumlu olan süreç hangisidir?","options":["Alveoler makrofaj birikimi sonucu lümenin dolması","Surfaktan üretiminin artmasıyla yüzey geriliminin azalması","Tip I pnömositlerde hiperplazi ve alveoler genişleme","Alveoler duvarların yıkılarak hava alanlarının birleşmesi","Terminal ve respiratuvar bronşiyollerin peribronşiyal fibrozis ile tıkanarak distalinde kistik alanlar oluşturması"],"correct":4,"exp":"İdiyopatik pulmoner fibrozis'in (IPF) karakteristik radyolojik ve histolojik bulgusu olan bal peteği görünümü, tekrarlayan epitelyal hasara bağlı fibrogenez sürecinde terminal ve respiratuvar bronşiyollerin çevresinde gelişen yoğun fibrozis ile bu yapıların tıkanması sonucu oluşur. Tıkanan bronşiyollerin distalinde hava hapsi ve kistik genişleme meydana gelir; BT'de alt loblarda periferal dağılımlı kistik yapılar (bal peteği) olarak izlenir. Bu bulgu UIP paterninin tanımlayıcısıdır. Alveoler duvar yıkımı amfizemi, Tip I pnömosit hiperplazisi reaktif değişimi, makrofaj birikimi deskuamatif interstisyel pnömoniyi düşündürür."},{"id":8312,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, egzersiz sonrası gelişen kas güçsüzlüğü ve miyoglobinüri yakınmalarıyla başvuruyor. Yapılan incelemede iskelet kasında glikojen birikimi saptanıyor. Enzimatik analizde kas dokusunda miyofosforilaz (kas glikojen fosforilazı) aktivitesinin tamamen yokluğu gösteriliyor. Bu hastada egzersiz sırasında beklenen metabolik bulgular aşağıdakilerden hangisidir?","options":["Venöz laktat düzeyinde artış olmaması, venöz amonyak düzeyinde artış olması","Venöz laktat düzeyinde artış olması, venöz amonyak düzeyinde artış olmaması","Hem venöz laktat hem de amonyak düzeylerinde artış olması","Venöz laktat düzeyinde artış olması, venöz amonyak düzeyinde azalma olması","Hem venöz laktat hem de amonyak düzeylerinde artış olmaması"],"correct":0,"exp":"McArdle hastalığı (tip V glikojenoz), kas miyofosforilaz eksikliğiyle karakterizedir. Bu enzim kas glikojeninin yıkılmasını sağlar; yokluğunda kas glikolizi işleyemez ve egzersizde laktat üretilemez. Bu nedenle iskemik egzersiz testinde venöz laktat artmaz. Ancak AMP deaminaz yolu ve pürin nükleotid döngüsü işlevseldir; dolayısıyla amonyak salınımı normaldir veya artmıştır. Laktatın artmaması, amonyağın artması bu hastalığın klasik bulgusudur ve doğru cevap A şıkkıdır."},{"id":8313,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Miyelin kılıfının yapısı ve işlevi ile ilgili olarak aşağıda verilen öncüller değerlendirilmektedir:\nI. Merkezi sinir sisteminde miyelin, Schwann hücreleri tarafından oluşturulur.\nII. Ranvier boğumları, aksiyon potansiyelinin saltatory iletimini sağlayan K⁺ kanalları bakımından zengindir.\nIII. Miyelin kılıfı, akson membranının kapasitansını azaltarak iletim hızını artırır.\nIV. Paranodal bölgede K⁺ kanalları yoğunlaşırken nodal bölgede Na⁺ kanalları yoğundur.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["1","2","3","4","0"],"correct":1,"exp":"Öncülleri tek tek değerlendirelim: I. Yanlış; merkezi sinir sisteminde miyelini oligodendrosit hücreleri, periferik sinir sisteminde ise Schwann hücreleri oluşturur. II. Yanlış; Ranvier boğumları Na⁺ kanalları bakımından zengindir ve aksiyon potansiyeli burada yenilenir; K⁺ kanalları ağırlıklı olarak paranodal ve juxtaparanodal bölgelerde bulunur. III. Doğru; miyelin kılıfı membran kapasitansını azaltır ve rezistansı artırarak elektrotonikal iletimi hızlandırır, bu da saltatory iletimin temel fizyolojik altyapısıdır. IV. Doğru; nodal bölgede yoğun Nav1.6 kanalları bulunurken, paranodal ve juxtaparanodal bölgelerde Kv1 tipi K⁺ kanalları yoğunlaşır. Böylece öncüllerin yalnızca 2 tanesi (III ve IV) doğrudur."},{"id":8314,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, efor dispnesi ve bacaklarda ödem yakınmalarıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30 olarak saptanıyor. Hastaya digoksin başlanıyor. Digoksinin bu hastadaki pozitif inotropik etkisine aracılık eden hücresel mekanizmanın sonucunda miyokardiyal hücrede hangi iyon düzeyinde artış beklenir?","options":["Ekstraselüler Ca²⁺","İntraselüler Mg²⁺","İntraselüler Ca²⁺","İntraselüler Na⁺","İntraselüler K⁺"],"correct":2,"exp":"Digoksin, Na⁺/K⁺-ATPaz pompasını inhibe eder; bu inhibisyon sonucunda hücre içinde Na⁺ birikir. Artan intraselüler Na⁺, Na⁺/Ca²⁺ değiştiricisinin (NCX) ters çalışmasına ya da ileri modda daha az Ca²⁺ dışarı atmasına yol açar; sonuçta intraselüler Ca²⁺ düzeyi artar. Bu Ca²⁺ artışı sarkoplazmatik retikulumdan daha fazla Ca²⁺ salınımını (Ca²⁺-induced Ca²⁺ release) tetikler ve miyokardiyal kontraktiliteyi artırır. Dolayısıyla digoksinin pozitif inotropik etkisinin nihai hücresel sonucu intraselüler Ca²⁺ artışıdır."},{"id":8315,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"55 yaşında kadın hasta, uzun süredir devam eden poliüri ve polidipsi yakınmalarıyla başvuruyor. Su kısıtlama testinde idrar osmolalitesi yükselmezken, eksojen desmopressin uygulamasının ardından idrar osmolalitesinin belirgin biçimde arttığı gözlemleniyor. Bu hastada en olası tanı hangisidir?","options":["Santral diabetes insipidus","Tip 2 diabetes mellitus","Primer aldosteronizm","Psikojenik polidipsi","Nefrojenik diabetes insipidus"],"correct":0,"exp":"Su kısıtlama testinde idrar osmolalitesinin artmaması, ADH salınımı ya da renal ADH yanıtının yetersiz olduğuna işaret eder. Desmopressin (sentetik ADH) uygulaması sonrasında idrar osmolalitesinin belirgin artması, böbrek tübüllerinin ADH'ya duyarlı olduğunu gösterir; yani sorun renal düzeyde değil, hipofizer ADH salınımındadır. Bu tablo santral diabetes insipidus ile uyumludur. Nefrojenik DI'da desmopressin uygulamasına rağmen idrar osmolalitesi artmaz. Psikojenik polidipside ise su kısıtlama testiyle osmolalite yükselir."},{"id":8316,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, tekrarlayan derin ven trombozu atakları nedeniyle araştırılıyor. Laboratuvar incelemesinde aPTT uzamış olarak saptanıyor; ancak 1:1 karıştırma testi aPTT'yi düzeltmiyor. Anti-kardiyolipin antikoru ve anti-β2 glikoprotein-1 antikoru pozitif bulunuyor. Aşağıdaki öncüller bu hastanın koagülasyon fizyolojisi açısından değerlendirilmektedir:\nI. Lupus antikoagülanı, in vitro ortamda fosfolipide bağlanarak protrombinaz kompleksini inhibe eder, bu nedenle aPTT uzar.\nII. Bu hastada in vivo ortamda da antikoagülan etki mevcuttur; dolayısıyla tromboz değil kanama beklenir.\nIII. Karıştırma testinin aPTT'yi düzeltmemesi, inhibitör varlığına işaret eder.\nIV. Bu hastalarda warfarin tedavisi sırasında INR takibi güvenilir olmayabilir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, III ve IV","Yalnız III","I, II, III ve IV","I ve III","II ve IV"],"correct":0,"exp":"Öncüller değerlendirildiğinde: I. Doğru; lupus antikoagülanı (LA) fosfolipide bağlanan antikordur ve in vitro'da protrombinaz kompleksinin kurulmasını engeller, aPTT uzar. II. Yanlış; bu durum in vitro bir eserdir. In vivo'da LA ve antifosfolipid antikorlar paradoksal olarak tromboza yol açar; endotel hücreleri, trombositler ve protein C yolunu etkileyen protrombotik mekanizmalar devreye girer. III. Doğru; karıştırma testinde normal plazma eklenmesi faktör eksikliğini düzeltir ancak inhibitörü nötralize edemez; bu nedenle aPTT düzelmez ve bu inhibitör varlığının klasik göstergesidir. IV. Doğru; fosfolipide bağımlı PT testi de LA tarafından etkilenebileceğinden warfarin izleminde kullanılan INR yanıltıcı olabilir; bu hastalarda anti-Xa düzeyi veya alternatif yöntemler tercih edilebilir. Dolayısıyla doğru öncüller I, III ve IV'tür."},{"id":8317,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Tip II pnömosit hücreleriyle ilgili aşağıdaki ifadelerden hangisi doğrudur?","options":["Müköz sekresyon üreterek solunum yollarını nemli tutarlar.","Surfaktan sentezleyerek alveol yüzey gerilimini azaltırlar ve hasarın ardından Tip I pnömosit öncülü olarak görev yaparlar.","Alveoler yüzeyin büyük bölümünü kaplayan, gaz değişiminden sorumlu hücrelerdir.","Karbondioksit difüzyonunu kolaylaştırmak amacıyla ince ve geniş sitoplazmaları ile yaygın biçimde uzanırlar.","Makrofaj işlevi görerek alveoler yabancı partikülleri fagosite ederler."],"correct":1,"exp":"Tip II pnömositler, alveol köşelerinde kümelenmiş, küboidal yapıda hücrelerdir. Temel işlevleri, lameller cisimcikler aracılığıyla surfaktan (ağırlıklı olarak dipalmitoilfosfatidilkolin) sentezleyip salgılamaktır; surfaktan alveol yüzey gerilimini azaltarak alveollerin ekspiryumda kollabe olmasını önler. Ayrıca Tip II pnömositler, alveoler hasarın ardından prolifere olarak hem kendi yenilenimini hem de Tip I pnömosit yenilenimini sağlayan öncül hücrelerdir. Alveol yüzeyinin büyük bölümünü kaplayan ve gaz değişiminden sorumlu olan hücreler ise Tip I pnömositlerdir. Alveoler makrofajlar fagosite görevini üstlenirken, müköz sekresyon bronşiyal goblet hücrelerine aittir."},{"id":8318,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, 2 yıldır devam eden efor dispnesi ve alt ekstremite ödemi yakınmalarıyla başvuruyor. Özgeçmişinde 15 yıldır hipertansiyon ve tip 2 diyabet tanıları mevcut. Ekokardiyografide ejeksiyon fraksiyonu %35, sol ventrikül diyastol sonu çapı 68 mm olarak ölçülüyor. Tedaviye sakubitril/valsartan eklenmesi planlanıyor. Bu ilacın etki mekanizmasına bağlı olarak hastada beklenen en önemli hemodinamik değişiklik hangisidir?","options":["Natriüretik peptid yıkımının azalmasıyla venöz dönüşün ve preloadun düşmesi","Periferik vasküler direncin artışına bağlı afterload yüklenmesi","Renin salınımının doğrudan uyarılmasıyla aldosteron düzeyinin artması","Sempatik sinir sistemi aktivasyonuyla kalp hızının refleks olarak yükselmesi","Anjiyotensin II reseptör blokajıyla böbrek perfüzyon basıncının artması"],"correct":0,"exp":"Sakubitril, neprilizin enzimini inhibe ederek natriüretik peptidlerin (ANP, BNP) yıkımını engeller. Yükselen natriüretik peptid düzeyleri natriürez ve diürez sağlayarak preloadı azaltır, aynı zamanda vazodilatasyon yaparak afterloadı da düşürür. Bu ikili etki, kronik kalp yetersizliğinde semptom yükünü ve yeniden hastaneye yatış riskini belirgin şekilde azaltır."},{"id":8319,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 6 aydır süren öksürük, hafif hemoptizi ve egzersiz dispnesi yakınmalarıyla başvuruyor. Toraks BT'de bilateral hiler lenfadenopati ve diffüz parankimal infiltrasyon saptanıyor. Bronkoalveoler lavaj örneğinde CD4/CD8 oranı 3,5 olarak bulunuyor. Serum anjiyotensin dönüştürücü enzim düzeyi yüksek. Bronş biyopsisinde nekroz içermeyen granülomlar izleniyor. Kortikosteroid tedavisi başlanıyor. Bu hastanın akciğer fonksiyon testlerinde en sık hangi patern beklenir?","options":["Azalmış TLC, azalmış DLCO ve korunmuş FEV1/FVC oranıyla restriktif patern","Artmış TLC ve RV ile birlikte obstrüktif patern","Artmış FEV1/FVC oranı ile birlikte restriktif ve obstrüktif karma patern","Normal spirometri ile birlikte izole azalmış DLCO","İzole artmış RV ile küçük hava yolu hastalığı paterni"],"correct":0,"exp":"Sarkoidoz, interstisyel akciğer hastalıklarının klasik bir örneğidir. Granülomatöz infiltrasyon ve fibrozis akciğer kompliyansını azaltarak restriktif bir fizyoloji oluşturur: TLC, FVC ve TLC'nin tümü azalır; ancak FEV1/FVC oranı korunur ya da artar. DLCO da alveolar-kapiller membran kalınlaşması nedeniyle azalır. CD4/CD8 oranının 3,5'in üzerinde olması sarkoidozu destekleyen önemli bir BAL bulgusudur."},{"id":8320,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında erkek hasta, 3 haftadır devam eden yüz ve bacaklarda şişlik yakınmasıyla nefroloji polikliniğine başvuruyor. Fizik muayenede periorbital ödem ve bilateral pretibyal çukur bırakan ödem saptanıyor. İdrar tetkikinde protein 3+ ve idrar proteinürisi 24 saatte 5,2 g olarak ölçülüyor. Serum albümin 1,8 g/dL, total kolesterol 380 mg/dL, LDL 290 mg/dL. Böbrek biyopsisinde ışık mikroskobisinde glomerüller normal görünüyor; elektron mikroskobisinde podosit ayak çıkıntı füzyonu (ayaksı çıkıntı effacement) izleniyor. Bu hastanın hiperlipidemisi için aşağıdaki açıklamalardan hangisi doğrudur?","options":["Böbrekten lipoprotein kaybının artmasına bağlı dolaşımda birikimi","Lipoprotein lipaz aktivitesinin artmasına bağlı VLDL klirensinin hızlanması","Karaciğerde apolipoprotein B sentezinin baskılanması sonucu gelişen sekonder hiperkolesterolemi","Albümin düşüklüğüne bağlı safra asidi enterohepatik döngüsünün bozulması","Onkotik basınç düşüklüğüne bağlı karaciğerde lipoprotein sentezinin kompansatuar artışı"],"correct":4,"exp":"Nefrotik sendromda (burada minimal change disease tablosu) hipoalbüminemi sonucu plazma onkotik basıncı düşer. Karaciğer bu düşüşe kompansatuar yanıt olarak lipoprotein sentezini (özellikle VLDL ve LDL) artırır. Aynı zamanda lipoprotein lipaz aktivitesi azaldığından trigliseridlerin klirensi de bozulur. İkili mekanizma nefrotik sendromun karakteristik hiperlipidemisini oluşturur."},{"id":8321,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"19 yaşında erkek hasta, trafik kazası sonrası acil servise getiriliyor. Yapılan nörolojik değerlendirmede T10 düzeyinde komplet spinal kord kesisi saptanıyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Lezyon seviyesinin altında derin tendon refleksleri kalıcı olarak kaybolur.\nII. Akut dönemde lezyon altında flask paralizi ve arefleksi görülmesi beklenir.\nIII. Mesane, başlangıçta atonik olup zamanla spastik (otomatik) mesaneye dönüşür.\nIV. Lezyon seviyesinin üzerindeki duyu ve motor işlevler tamamen korunur.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["2 tanesi","3 tanesi","Hiçbiri","Yalnız 1 tanesi","4 tanesi"],"correct":1,"exp":"Öncül II doğrudur: Akut spinal kord kesisinde 'spinal şok' fazı gelişir; bu dönemde lezyon altında geçici flask paralizi ve arefleksi görülür. Öncül III doğrudur: Atonik olan mesane, spinal şok fazının geçmesiyle birlikte üst motor nöron lezyonuna bağlı olarak spastik mesaneye dönüşür. Öncül IV doğrudur: T10 komplet kesisinde üst düzey duyu ve motor işlevler korunur. Öncül I yanlıştır; çünkü spinal şok döneminde geçici olarak kaybolan tendon refleksleri, haftalarca-aylarca içinde geri döner ve hiper-refleksiye dönüşür. Dolayısıyla 3 öncül doğrudur."},{"id":8322,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Aşağıdaki öncülleri değerlendiriniz:\nI. Demir eksikliği anemisinde serum ferritin düzeyi düşer, TIBC artar.\nII. Megaloblastik anemide B12 ya da folat eksikliğine bağlı DNA sentezi bozulur ve hipersegmente nötrofiller görülür.\nIII. Orak hücre anemisinde hemoglobin S, oksijenlenince polimerizasyon eğilimi gösterir.\nIV. Kronik hastalık anemisinde hem serum demiri hem de TIBC düşer, ferritin ise artar ya da normaldir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","4 tanesi","3 tanesi","1 tanesi","2 tanesi"],"correct":2,"exp":"Öncül I doğrudur: Demir eksikliğinde demir depolarını yansıtan ferritin düşer, bağlanmaya hazır transferrin kapasitesi olan TIBC artar. Öncül II doğrudur: B12/folat eksikliğinde timidilat sentezi bozulur, nükleer olgunlaşma gecikir; hipersegmente nötrofil karakteristik bulgudur. Öncül III yanlıştır: HbS, deoksijenize (oksijensiz) ortamda polimerizasyon gösterir; oksijenlenince polimerizasyon geri döner. Öncül IV doğrudur: Kronik hastalık anemisinde hepsidin artışına bağlı demir mobilizasyonu kısıtlanır; serum demiri ve TIBC düşer, ferritin (akut faz proteini olarak) artar ya da normal kalır. Dolayısıyla 3 öncül doğrudur."},{"id":8323,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında erkek hasta, 8 aydır devam eden epigastrik ağrı, erken doygunluk ve istem dışı 9 kg kilo kaybı yakınmalarıyla başvuruyor. Üst gastrointestinal endoskopide antrumda ülsere infiltratif lezyon saptanıyor. Biyopsi sonucu 'taş yüzüğü hücreli (signet ring cell) karsinom' olarak raporlanıyor. Bu histolojik tip için aşağıdaki ifadelerden hangisi doğrudur?","options":["İntestinal metaplazi zemininden gelişir ve Helicobacter pylori ile ilişkisi yoktur.","Yüksek differansiye olduğundan cerrahi rezeksiyonla tam küre ulaşılabilir.","Lauren sınıflandırmasında intestinal tipe karşılık gelir.","Mukus sekresyonunu sağlayan MUC5AC gibi müsinlerin hücre içinde birikmesiyle nükleus perifere itilir ve karakteristik görünüm oluşur.","Hematojen yayılım yerine lenfatik yayılımı tercih ettiğinden uzak metastaz nadirdir."],"correct":3,"exp":"Taş yüzüğü hücreli karsinom, diffüz tip mide kanserinin (Lauren sınıflandırması) histolojik görünümüdür. Hücre içinde müsin (ağırlıklı olarak MUC5AC ve MUC6) birikimi, nükleusu hücrenin periferine iter; bu görünüm yüzüğe taş oturtulmuş izlenimi verir. E-kadherin mutasyonu (CDH1) ile ilişkilidir ve genellikle kötü prognozludur. İntestinal tip için geçerli olan H. pylori → kronik gastrit → intestinal metaplazi → displazi → karsinom silsilesi diffüz tip için geçerli değildir; diffüz tip genetik yatkınlıkla daha yakından ilişkilidir."},{"id":8324,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, 6 aydır devam eden proksimal kas güçsüzlüğü ve efor sonrası belirginleşen yorgunluk yakınmasıyla başvuruyor. Elektromiyografide miyopatik patern saptanıyor. Kas biyopsisinde tip II liflerde atrofi, mitokondri sayısında artış ve 'ragged-red fiber' görünümü izleniyor. Serum laktat düzeyi yüksek bulunuyor. Bu hastaya uygulanan egzersiz testi sırasında venöz kanda laktat artışı gözlemlenirken beklenen artışın aksine amonyak düzeyi normal sınırlarda kalıyor. Bu bulgu, hangi metabolik patolojiyle en iyi açıklanır?","options":["Miyoadenilat deaminaz eksikliği","Miyofosforilaz enzim yetersizliği","Glikojen depo hastalığı tip III","Mitokondriyal solunum zinciri bozukluğu","Karnitin palmitiltransferaz eksikliği"],"correct":3,"exp":"Egzersiz sırasında normal koşullarda AMP deaminaz aktivasyonuyla amonyak üretimi artar; laktat ise anaerobik glikoliz ürünüdür. Mitokondriyal solunum zinciri bozukluğunda aerobik metabolizma bozulduğundan laktat artar; ancak AMP deaminaz yolağı korunduğundan amonyak yanıtı beklenen düzeyde olabilir. Öte yandan ragged-red fiber ve yüksek laktat, mitokondriyal hastalığın klasik bulgularıdır. Miyofosforilaz eksikliğinde (McArdle) laktat artışı olmaz; miyoadenilat deaminaz eksikliğinde ise amonyak yanıtı bozulur. Bu hastada laktat artışı + normal amonyak yanıtı + ragged-red fiber kombinasyonu mitokondriyal solunum zinciri bozukluğunu işaret eder."},{"id":8325,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, ani gelişen çarpıntı ve baş dönmesi yakınmasıyla acil servise başvuruyor. EKG'de QRS süresi 0,14 saniye, P dalgası QRS'ten önce görülmüyor ve ventrikül hızı 160/dk olarak ölçülüyor. Hasta, bu ataktan 3 ay önce geçirdiği geniş anterior miyokard enfarktüsü nedeniyle takip altında. Kardiyak belirteçler negatif. Bu hastaya hız kontrolü amacıyla uygulanan amiodaronun etki mekanizmasına ilişkin aşağıdaki öncüllerden hangileri doğrudur?\nI. Faz 0 depolarizasyonunu hızlandırarak iletimi kolaylaştırır.\nII. Faz 3 repolarizasyonunu uzatarak efektif refrakter periyodu artırır.\nIII. Faz 4 spontan depolarizasyonunu baskılayarak otomatisiteyi azaltır.\nIV. Beta adrenerjik reseptörleri bloke ederek sempatik etkiyi azaltır.","options":["I ve IV","Yalnız II","II ve III","I, II ve III","II, III ve IV"],"correct":4,"exp":"Amiodaron çoklu kanal ve reseptör etkisine sahip bir sınıf III antiaritmiktir. Faz 3'te K+ kanallarını bloke ederek aksiyon potansiyeli süresini ve efektif refrakter periyodu uzatır (öncül II doğru). Faz 4 spontan depolarizasyonunu inhibe ederek pacemaker otomatisitesini azaltır (öncül III doğru). Aynı zamanda kompetitif olmayan beta adrenerjik blokaj yapar (öncül IV doğru). Faz 0'ı hızlandırmaz; aksine Na+ kanallarını hafifçe bloke ederek faz 0'ı yavaşlatır, bu nedenle öncül I yanlıştır. Doğru öncüller II, III ve IV'tür."},{"id":8326,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, 3 haftadır süren ödem, köpüklü idrar ve halsizlik yakınmasıyla başvuruyor. Laboratuvar incelemesinde serum albumin 1,8 g/dL, 24 saatlik idrarda protein 6,2 g, serum kolesterol 380 mg/dL, serum kreatinin 0,8 mg/dL saptanıyor. Renal biyopside ışık mikroskobisinde glomerüller normal görünümde, elektron mikroskobisinde ise podosit çıkıntılarında yaygın silinme (ayaksı çıkıntı effacement) izleniyor. Bu hastanın tedavisine prednizolon başlandıktan 8 hafta sonra idrarda protein 0,15 g/24 saat düzeyine gerilemiş ve ödemler tamamen çözülmüştür. Bu klinik tabloyu en çok destekleyen bulgu hangisidir?","options":["Steroid yanıtlılık ile birlikte podosit hasarının izole görülmesi","Subepitelyal immün kompleks depozitleri","Serum C3 düzeyinde düşüklük","Antinükleer antikor pozitifliği","Mezengial IgA birikimi"],"correct":0,"exp":"Bu tablo minimal change disease (minimal değişiklik hastalığı) ile uyumludur. Işık mikroskobisinde normal görünüm, elektron mikroskobisinde yaygın podosit çıkıntısı silinmesi ve steroide tam yanıt bu hastalığın karakteristik üçlüsüdür. Subepitelyal depozitler membranöz nefropatiyi, mezengial IgA birikimi IgA nefropatisini, C3 düşüklüğü membranoproliferatif GN'yi, ANA pozitifliği lupus nefritini düşündürür. Minimal change disease'de immünflüoresan genellikle negatiftir; sadece podosit hasarı ve steroid yanıtlılığının birlikteliği bu tanıyı destekleyen en özgün bulgudur."},{"id":8327,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"45 yaşında erkek hasta, 2 yıldır ilerleyici hafıza kaybı, kişilik değişikliği ve 3 aydır eklenen yürüme bozukluğu ile başvuruyor. Muayenede miyoklonus ve serebellar ataksi saptanıyor. MR'da difüzyon kısıtlaması mevcut. BOS incelemesinde 14-3-3 proteini pozitif. Bu hastada patolojik süreçte rolü olan hücreye ilişkin aşağıdaki öncüllerden kaç tanesi yanlıştır?\nI. Nissl cisimcikleri içerir.\nII. Akson boyunca ortaya çıkan hasarda Wallerian dejenerasyon gerçekleşir.\nIII. Hasarlı bölgelerde prolifere olarak gliozis oluşturur.\nIV. Miyelin kılıfı bu hücre tarafından üretilir.","options":["1","0","3","2","4"],"correct":3,"exp":"Klinik tablo Creutzfeldt-Jakob hastalığını (CJH) düşündürmektedir; patolojide prion birikimi nöronlarda vakuolizasyona yol açar. Ancak soruda 'patolojik süreçte rolü olan hücre' ifadesiyle asıl hasarı gören nöronlar kastedilmektedir. Nöronlar Nissl cisimcikleri içerir (öncül I doğru). Aksonal hasar sonrası Wallerian dejenerasyon nörona özgüdür (öncül II doğru). Gliozis oluşturan hücre astrosittir, nöron değil (öncül III yanlış). MSS'de miyelin üreten hücre oligodendrosittir, nöron değil (öncül IV yanlış). Bu nedenle yanlış olan öncüller III ve IV olup cevap 2'dir."},{"id":8328,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Tip II pnömosit hücreleri ve sürfaktan üretimine ilişkin aşağıdaki öncüllerden hangileri doğrudur?\nI. Tip II pnömositler alveol yüzeyinin yaklaşık %95'ini kaplar.\nII. Sürfaktan başlıca dipalmitoilfosfatidilkolin (DPPC) içerir.\nIII. Sürfaktan, alveol yarıçapı küçüldükçe yüzey gerilimini daha fazla azaltarak alveoler kollabsı önler.\nIV. Tip II pnömositler hasarlı tip I pnömositleri yenileyebilir.","options":["I ve II","II ve III","I, II ve IV","II, III ve IV","Yalnız II"],"correct":3,"exp":"Tip I pnömositler alveol yüzeyinin yaklaşık %95'ini kaplarken tip II pnömositler yalnızca %5'ini oluşturur, bu nedenle öncül I yanlıştır. Sürfaktanın temel fosfolipid bileşeni DPPC'dir (öncül II doğru). Laplace yasası gereği alveol yarıçapı küçüldükçe yüzey geriliminin azaltılması daha kritik hale gelir; sürfaktan yoğunlaşarak bu etkiyi güçlendirir ve kollabsı önler (öncül III doğru). Tip II pnömositler kök hücre özelliği taşır ve hasar durumunda tip I pnömositleri yenileyebilir (öncül IV doğru). Doğru öncüller II, III ve IV'tür."},{"id":8329,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, 4 aydır süren epigastrik ağrı, erken doyma ve 8 kg kilo kaybı yakınmasıyla başvuruyor. Üst GI endoskopide mide antrum ve korpusunda yaygın nodülarite ve sertleşme saptanıyor; biyopside mide duvarının tüm katlarına infiltre olmuş yüzük hücreli karsinom görülüyor. BT'de over metastazı şüpheli kitleler mevcut. Tanı konulan bu hastanın hastalık sürecinde gastrik asit sekresyonu değerlendirildiğinde en olası bulgu hangisidir?","options":["Bazal asit çıkışı artmış, serum gastrin düzeyi düşük","Bazal asit çıkışı artmış, serum gastrin düzeyi normal","Bazal asit çıkışı normal, pentagastrin uyarısına maksimal yanıt artmış","Serum gastrin düzeyi çok yüksek, bazal asit çıkışı artmış, hipokalsemi eşlik ediyor","Bazal ve maksimal asit çıkışı belirgin azalmış, serum gastrin düzeyi yüksek"],"correct":4,"exp":"Yaygın mide karsinomu (linitis plastica paterni), özellikle yüzük hücreli tip, parietal hücre kitlesini ve mide bezlerini tahrip eder. Bu nedenle bazal ve maksimal asit sekresyonu belirgin biçimde azalır (hipoklorhidri veya aklorhidri). Parietal hücrelerden asit sekresyonu azaldığında, antral D hücreleri üzerindeki asit inhibisyonu ortadan kalkar; bunun sonucunda G hücrelerinden gastrin salınımı refleks olarak artar ve serum gastrin düzeyi yükselir. Bu tablo sekonder hipergastrineminin klasik örneğidir. Zollinger-Ellison sendromunda ise gastrin yüksek olmasına karşın asit çıkışı artmıştır; bu iki tablo karıştırılmamalıdır."},{"id":8330,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, 6 aydır ilerleyici proksimal kas güçsüzlüğü ve egzersiz intoleransı yakınmasıyla başvuruyor. Aile öyküsünde benzer şikayetler mevcut. Elektromiyografide miyopatik patern saptanıyor. Kas biyopsisinde tip 1 kas liflerinde atrofi ve merkezi nükleuslar dikkat çekiyor. Bu hastada gözlenen tip 1 kas lifi atarofisiyle en uyumlu ultrastrüktürel bulgu hangisidir?","options":["T tübül sisteminin dilatasyonu ve triyadların bozulması","Sarkoplazmik retikulumda kalsiyum salınım kanallarının (riyanodin reseptör) artmış yoğunluğu","Miyozin ağır zincir izoformlarında tip I'den tip IIx'e geçiş","Z disklerinde düzensizleşme ve sarkomerin M çizgisinde silinme","Mitokondri sayısı ve oksidatif enzim aktivitesinde belirgin azalma"],"correct":4,"exp":"Tip 1 (yavaş, oksidatif) kas lifleri zengin mitokondri içeriği ve yüksek oksidatif enzim aktivitesiyle tanımlanır. Bu liflerin atrofisinde ultrastrüktürel düzeyde mitokondri kaybı ve oksidatif kapasite düşüşü en karakteristik bulgudur. Riyanodin reseptör artışı tip 1 lif patolojisiyle değil, malign hipertermiye yatkınlıkla ilişkilidir. Z disk düzensizliği miyotonlarda görülür. Miyozin izoform değişimi denervasyona yanıt olarak tip 1 liflerden tip 2'ye geçiş şeklinde olur; burada tanımlanan yön tersidir. T tübül dilatasyonu ise hipokalemik periyodik paralizi gibi iyon kanal hastalıklarına özgüdür."},{"id":8331,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, akut miyokard enfarktüsü tanısıyla koroner yoğun bakıma yatırılıyor. Enfarktüsün 4. gününde ani başlayan nefes darlığı ve yeni sistolik üfürüm gelişiyor. Ekokardiyografide papiller kas rüptürü ve akut mitral yetersizliği saptanıyor. Papiller kasların bu periyotta rüptüre özellikle yatkın olmasının histolojik zeminini en doğru açıklayan ifade hangisidir?","options":["Papiller kaslar, myokardın en son vaskülarize bölgesi olup kollateral dolaşımdan yoksun uç nokta beslenmesine sahiptir","Papiller kaslardaki tip 2B lif oranının yüksekliği glikolitik kapasiteyi sınırlayarak erken nekroza yol açar","Papiller kas miyositlerinde gap junction yoğunluğunun düşük olması iskemi yayılımını hızlandırır","Papiller kaslardaki interstisyel kollajen oranının düşüklüğü iskemik yumuşamaya zemin hazırlar","İnfarkt bölgesindeki nötrofil infiltrasyonu papiller kasa özgü hücre adezyon moleküllerini hedef alır"],"correct":0,"exp":"Papiller kaslar, sol ventrikülün trabeküler yapıları içinde koroner dolaşımın en uç noktalarına yerleşmiştir; özellikle posteromediyal papiller kas çoğunlukla tek koroner arterden (sağ koroner veya sirkumfleks) beslenir ve kollateral dolaşımdan yoksundur. Bu anatomik 'uç nokta' beslenmesi, iskemiye karşı dayanıklılığı en aza indirir ve 4-7. günlerde sıvılaşma nekrozunun zirveye ulaşmasıyla rüptür riskini maksimize eder. Tip 2B lif dağılımı miyokardda belirleyici değildir. Gap junction yoğunluğu iskemi yayılımından çok elektriksel iletim için önemlidir. Nötrofil infiltrasyonu evrenseldir, papiller kasa özgü değildir."},{"id":8332,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, nefrotik sendrom tanısıyla değerlendiriliyor. İdrar proteini 6 g/gün, serum albumini 1,8 g/dL olarak ölçülüyor. Böbrek biyopsisinde ışık mikroskopisinde glomerüller normal görünürken elektron mikroskobunda podosit ayaksı çıkıntılarının (ayaksı çıkıntı) yaygın silinmesi saptanıyor. Bu hastada proteinürinin mekanizmasını en doğrudan açıklayan yapısal değişiklik aşağıdakilerden hangisidir?","options":["Glomerüler bazal membranda tip IV kollajen ekspresyonunun azalması","Mezangiyal hücrelerde fagositoz kapasitesinin artışına bağlı filtrasyon alanı daralması","Bowman kapsülü pariyetal epitelinde epitel-mezenkimal dönüşüm","Endotel hücrelerindeki glikokaliksin selektif anyonik yük kaybı","Podosit slit diyafram proteinleri olan nefrin ve podosinin işlev kaybı"],"correct":4,"exp":"Podositlerin ayaksı çıkıntıları arasındaki slit diyafram, glomerüler filtrasyon bariyerinin en seçici katmanıdır. Nefrin ve podosin bu diyaframın temel yapısal proteinleridir; nefrin mutasyonu konjenital nefrotik sendroma (Finlandiya tipi) yol açar, podosin mutasyonu ise fokal segmental glomerüloskleroza neden olur. Minimal değişiklik hastalığında ışık mikroskobu normalken elektron mikroskobu ayaksı çıkıntı silinmesini ortaya koyar; bu tablo nefrin/podosin disfonksiyonunu yansıtır. Tip IV kollajen azalması Alport sendromuyla ilişkilidir. Mezangiyal hiperplazi IgA nefropatisinde ön plandadır. Glikokaliks kaybı teorik olarak katkı sağlasa da tek başına bu tabloyu açıklamaz."},{"id":8333,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Miyelinli bir sinir lifinde lokal anestezik uygulandığında aksiyon potansiyelinin iletilememesinin temel nedeni aşağıdakilerden hangisidir?","options":["Akson boyunca K+ kanallarının kalıcı olarak açık tutulması","Ranvier boğumlarındaki voltaj kapılı Na+ kanallarının bloke edilmesi","Aksiyon potansiyelinin internodal segmentte ısıyla nötralize edilmesi","Dendritik iletimin aksondan önce kesilmesi","Schwann hücresi miyelin kılıfının kimyasal olarak bozulması"],"correct":1,"exp":"Miyelinli liflerde saltatory (sıçramalı) iletim Ranvier boğumlarındaki yüksek yoğunluklu voltaj kapılı Na+ kanalları aracılığıyla gerçekleşir. Lokal anestezikler (lidokain, bupivakain) bu kanalların iç yüzüne bağlanarak Na+ girişini bloke eder ve depolarizasyonu engeller; böylece aksiyon potansiyeli bir sonraki boğuma iletilemez. K+ kanallarının açık tutulması hiperpolarizan etki yapar ancak lokal anestezik mekanizması değildir. Miyelin kılıfının bozulması demyelinizan hastalıklara özgüdür. Isıyla nötralizasyon fizyolojik bir mekanizma değildir. Lokal anestezikler hem duyusal hem motor lifleri etkiler, yalnızca dendrite özgü etkileri yoktur."},{"id":8334,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"55 yaşında erkek hasta, uzun süreli gastroözofageal reflü hastalığı nedeniyle izlenmektedir. Endoskopik biyopside distal özofagusta skuamöz epitelin yerini kolumnar epitelin aldığı ve intestinal metaplazi odaklarının bulunduğu raporlanıyor. Bu metaplazinin klinik açıdan önemini en iyi ifade eden öncüller aşağıda verilmiştir:\nI. Kolumnar epitelin goblet hücreleri içermesi intestinal metaplazi tanısı için zorunludur.\nII. Bu lezyonun adenokarsinomaya ilerleme riski, skuamöz hücreli karsinoma riskinden daha yüksektir.\nIII. Proton pompa inhibitörü (PPI) tedavisi mevcut metaplaziyi tamamen geri döndürebilir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II ve III","I ve II","Yalnız I","I, II ve III","I ve III"],"correct":1,"exp":"Öncül I doğrudur: Barrett özofagusu tanısının histolojik kriteri, kolumnar metaplazi içinde goblet hücrelerinin varlığıyla tanımlanan intestinal metaplazidir; goblet hücreleri alcian mavisiyle (pH 2,5) boyanır. Öncül II doğrudur: Barrett özofagusu displazi-karsinom sekansı üzerinden özofagus adenokarsinomasına zemin hazırlar; bu risk skuamöz hücreli karsinoma riskinin çok üzerindedir ve özellikle düşük/yüksek dereceli displazi aşamasında belirginleşir. Öncül III yanlıştır: PPI tedavisi reflü semptomlarını kontrol eder ve ilerlemeyi yavaşlatabilir, ancak yerleşik intestinal metaplaziyi histolojik düzeyde tam olarak geri döndürdüğü kanıtlanmamıştır; bu nedenle endoskopik ablasyon (radyofrekans ablasyon) tercih edilen tedavidir."},{"id":8335,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında erkek hasta, 2 yıldır tekrarlayan sinopulmoner enfeksiyonlar, bronşiektazi ve situs inversus totalis tanılarıyla değerlendiriliyor. Nazal nitrik oksit düzeyi çok düşük saptanıyor. Bronş biyopsisinde transmisyon elektron mikroskobunda siliyaların iç dinamik kollarında (inner dynein arm) yokluk izleniyor. Bu hastada siliyer disfonksiyonun doğrudan yol açtığı patofizyolojik sonuç aşağıdakilerden hangisidir?","options":["Bronşiyal düz kas hipertrofisi sonucu reversible hava yolu obstrüksiyonu","Müküs tabakasının perisilier sıvı fazının kaybolmasına bağlı derin atelektazi","Tip II pnömosit surfaktan sekresyonunun azalması nedeniyle alveoler kollaps","Goblet hücresi hiperplazisine bağlı mukus hipersekresyonu","Siliyaların koordineli vuruş frekansının bozulmasıyla mükosilier klirensin yetersiz kalması"],"correct":4,"exp":"Primer silier diskinezi (PCD), dinein kol proteinlerini kodlayan genlerdeki mutasyonlar sonucu siliyaların hareket edemediği otozomal resesif bir hastalıktır. Siliyelerin koordineli vuruşu (yaklaşık 12-15 Hz) mükosilier taşımayı sağlar; inner dynein arm yokluğunda bu hareket tamamen ortadan kalkar ve solunum yolu sekresyonları temizlenemez. Bu birikimin kronik bakteriyel kolonizasyon, bronşiektazi ve tekrarlayan pnömoniye zemin hazırladığı gösterilmiştir. Situs inversus totalis, nodal siliyaların erken embriyonik dönemde sağ-sol asimetrinin belirlenmesinde görev yapamamasından kaynaklanır (Kartagener sendromu = PCD + situs inversus). Surfaktan sekresyonu tip II pnömositlerle ilgilidir ve PCD patogenezinde yer almaz. Perisilier sıvı kaybı kistik fibrozis mekanizmasıdır. Düz kas hipertrofisi ve goblet hücre hiperplazisi sekonder değişiklikler olabilir ancak PCD'nin doğrudan sonucu değildir."},{"id":8336,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor dispnesi ve bacaklarda şişlik yakınmasıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya tedavi planlanırken kardiyak miyositlerin yapısal özellikleri değerlendiriliyor. Bu hücrelere ait aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Kardiyak miyositler, iskelet kası hücrelerinin aksine kendi aralarında gap junction (nexus) bağlantıları içeren diskus interkalatuslar aracılığıyla elektriksel senkroni sağlar.\nII. Kardiyak miyositlerde T-tübülüs sistemi iskelet kasına kıyasla daha gelişmiş olup Z disklerinin hizasında yer alır.\nIII. Kardiyak miyositler terminal olarak diferansiye olduğundan fizyolojik koşullarda mitoz geçirmez; kalp yetmezliğindeki adaptasyon miyosit hiperplazisiyle değil, hipertrofiyle gerçekleşir.\nIV. Sarkoplazma retikulumundan kalsiyum salınımı kalbin kasılması için yeterli olup ekstrasellüler kalsiyuma bağımlılık iskelet kasına kıyasla çok daha azdır.","options":["II, III ve IV","I, II, III ve IV","I ve III","I, II ve III","Yalnız I"],"correct":3,"exp":"I. Doğru: Kardiyak miyositler diskus interkalatuslar içindeki gap junctionlar aracılığıyla senkron kasılma sağlar; bu bağlantılar elektriksel uyarıyı hücreden hücreye ileterek fonksiyonel sinsityum oluşturur. II. Doğru: Kardiyak kasta T-tübülusler Z disklerinin hizasında yer alır (iskelet kasında A-I bileşkesindeydi şeklindeki karışıklığa dikkat; karşılaştırmalı olarak kardiyak kasın T-tübülusları Z bandı hizasındadır). III. Doğru: Kardiyak miyositler terminal diferansiyasyon gösterir; yetişkinde hiperplazi değil hipertrofi söz konusudur. IV. Yanlış: Kardiyak kasılma ekstrasellüler kalsiyuma belirgin biçimde bağımlıdır. Sarkoplazma retikulumundan salınan kalsiyum tek başına yeterli değildir; L-tipi kalsiyum kanalları aracılığıyla hücre dışından giren kalsiyum kalsiyumla tetiklenen kalsiyum salınımını (CICR) başlatır. Bu nedenle doğru öncüller I, II ve III'tür."},{"id":8337,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"23 yaşında kadın hasta, tekrarlayan kas güçsüzlüğü ve çift görme yakınmasıyla nöroloji polikliniğine başvuruyor. Yapılan değerlendirmede antikorların nöromüsküler kavşakta postsinaptik nikotinik asetilkolin reseptörlerine bağlandığı tespit edilerek asetilkolinesteraz inhibitörü başlanıyor. Tedaviye yanıt olarak nöromüsküler kavşakta beklenen birincil değişiklik hangisidir?","options":["Sinaptik yarıkta asetilkolinin yıkımının yavaşlaması ve end-plate potansiyelinin uzaması","Presinaptik voltaj kapılı kalsiyum kanallarının aktivasyonunun güçlenmesi","Kas lifi membranında depolarizasyonun azalması","Postsinaptik membranda nikotinik reseptör sayısının artması","Motor nörondan asetilkolin salınımının artması"],"correct":0,"exp":"Miyastenia gravisde postsinaptik nikotinik asetilkolin reseptörleri otoantikorlar tarafından bloke edilir ve yıkıma uğratılır; bu durum end-plate potansiyelinin eşik altında kalmasına ve kas güçsüzlüğüne yol açar. Asetilkolinesteraz inhibitörleri (piridostigmin gibi) sinaptik yarıkta asetilkolinin enzimatik yıkımını engelleyerek birikimini artırır. Bu sayede azalmış reseptörlerle daha uzun ve güçlü etkileşim sağlanır, end-plate potansiyeli uzar ve eşiğe ulaşma olasılığı artar. Diğer seçenekler: presinaptik salınımın artması Lambert-Eaton sendromunun tedaviyle ilgili mekanizmasıyla daha uyumludur; reseptör sayısının artması asetilkolinesteraz inhibisyonunun doğrudan sonucu değildir; kalsiyum kanalı aktivasyonu bu ilacın hedefi değildir; depolarizasyonun azalması ise tedavi amacıyla çelişir."},{"id":8338,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 10 yıldır tip 2 diyabetes mellitus tanısıyla izlenmektedir. Son kontrollerde idrarda albumin/kreatinin oranı 380 mg/g olarak saptanıyor, GFR 52 mL/dak olarak hesaplanıyor. Böbrek biyopsisinde mezangiyel matriks artışı ve glomerüler bazal membran kalınlaşması görülüyor. Bu hastanın glomerülündeki patolojiyi anlamak için filtrasyonu kısıtlayan yapılar değerlendiriliyor. Aşağıdaki öncüllerden hangileri doğrudur?\nI. Glomerüler filtrasyon bariyerinin en seçici katmanı, podosit ayaksı uzantıları arasındaki nefrinin içerdiği yarık diyaframdır.\nII. Endotel hücrelerini kaplayan glikokaliks, negatif yükü sayesinde albumin gibi anyonik makromoleküllerin geçişini kısıtlar; diyabette bu tabaka bozulur.\nIII. Mezangiyum hücreleri, glomerüler kapillerlerden filtrasyonu doğrudan gerçekleştiren hücreler olup kontraksiyonları ile filtre edilen sıvı miktarını artırır.\nIV. Glomerüler bazal membran tip IV kollajen ve heparan sülfat proteoglikan içerir; heparan sülfatın azalması diyabetik nefropatide proteinüriye katkıda bulunur.","options":["II ve IV","I, II, III ve IV","I, II ve IV","II, III ve IV","I ve II"],"correct":2,"exp":"I. Doğru: Yarık diyafram (slit diaphragm), boyut ve yük seçiciliğinin en kritik belirleyicisidir; nefrin bu yapının temel proteinidir ve mutasyonları konjenital nefrotik sendroma yol açar. II. Doğru: Endotelyal glikokaliks negatif yüklüdür ve albumin gibi anyonların geçişini engeller; diyabette glikokaliks hasarı proteinüriye katkıda bulunur. III. Yanlış: Mezangiyum hücreleri filtrasyonu gerçekleştirmez; destek, fagositoz ve matriks düzenlemesi işlevleri görür. Kontraksiyonları filtrasyon yüzeyini azaltarak GFR'yi düşürebilir, artırmaz. IV. Doğru: GBM'deki tip IV kollajen yapısal iskelet sağlar; heparan sülfat proteoglikanlar negatif yük bariyeri oluşturur ve diyabette bu bileşenin azalması albümin geçişini kolaylaştırır. Sonuç: I, II ve IV doğrudur."},{"id":8339,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"34 yaşında kadın hasta, 6 aydır süren kronik ishal, karın ağrısı ve kilo kaybı yakınmasıyla gastroenteroloji polikliniğine başvuruyor. Yapılan ince barsak biyopsisinde villus atrofisi ve kript hiperplazisi saptanarak çölyak hastalığı tanısı konuluyor. Glutenden arındırılmış diyet başlanan hastada, ince barsak epitelinin histolojik olarak düzelmesiyle birlikte emilimi en fazla iyileşecek olan yüzey yapısı hangisidir?","options":["Enteroendokrin hücreler","Kript hücreleri","Goblet hücreleri","Enterositlerde mikrovillüs fırçamsı kenar","Paneth hücreleri"],"correct":3,"exp":"Çölyak hastalığında otoimmün hasar ağırlıklı olarak ince barsak yüzeyindeki villöz enterosite yöneliktir. Bu hücrelerin apikal yüzeyindeki mikrovillüsler (fırçamsı kenar), emilim yüzeyini yaklaşık 600 kat artıran temel yapılardır ve emilim kapasitesinin büyük bölümünü belirler. Villus atrofisinde bu yapılar kaybolur ve emilim alanı dramatik biçimde daralır. Glutensiz diyetle villuslar yeniden oluşurken mikrovillüs fırçamsı kenar da geri kazanılır ve emilim düzelir. Kript hücreleri (kök ve prekürsör hücreler), goblet hücreleri (mukus salgısı), enteroendokrin hücreler (hormon salgısı) ve Paneth hücreleri (antimikrobiyal peptid) emilim işlevinden değil, farklılaşmış sekresyon ve savunma işlevlerinden sorumludur."},{"id":8340,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Yenidoğan yoğun bakım ünitesinde 28. gebelik haftasında doğan prematüre bebekte solunum sıkıntısı gelişiyor. Akciğer grafisinde yaygın buzlu cam görünümü saptanıyor. Bu tablonun temel nedeni olan hücresel yetersizlik ve uygulanan eksojen sürfaktan tedavisinin etkisi değerlendirildiğinde, hangi hücre tipinin işlev eksikliği söz konusudur?","options":["Tip I pnömosit","Tip II pnömosit","Clara (Club) hücresi","Kültür hücresi (Goblet hücresi)","Alveolar makrofaj"],"correct":1,"exp":"Sürfaktan, alveol yüzey gerilimini azaltarak alveollerin ekspirasyon sonunda kollabe olmasını engelleyen bir madde olup ağırlıklı olarak dipalmitoilfosfatidilkolin (DPPC) içerir. Bu maddeyi sentezleyip salgılayan hücreler Tip II pnömositlerdir. Tip II pnömositler 24. gebelik haftasından itibaren farklılaşmaya başlar; ancak yeterli sürfaktan üretimi genellikle 34-36. haftada gerçekleşir. 28. haftadaki prematüre bebeklerde Tip II pnömosit olgunlaşması yetersiz kaldığından sürfaktan eksikliğine bağlı respiratuar distres sendromu (RDS/hyalin membran hastalığı) gelişir. Tip I pnömositler gaz değişimini sağlar ancak sürfaktan sentezlemez. Diğer seçenekler sürfaktan üretimiyle ilişkili değildir."},{"id":8341,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, 6 aydır giderek artan kas güçsüzlüğü ve egzersiz intoleransı şikayetiyle başvuruyor. Aile öyküsünde benzer hastalık mevcut. Elektromiyografide myotonik deşarjlar saptanıyor; kas biyopsisinde tip I lif hipertrofisi ve tip II lif atrofisi izleniyor. Hastaya membran stabilizasyonu amacıyla meksiletin başlanıyor. Bu ilacın etki mekanizması düşünüldüğünde aşağıdaki öncüllerden hangileri doğrudur?\nI. Voltaj kapılı Na⁺ kanallarını bloke ederek aksiyon potansiyeli frekansını azaltır.\nII. Miyotoni, motor nöron hipereksitabilitesinden kaynaklandığından ilacın kas membranı üzerine doğrudan etkisi yoktur.\nIII. Etki mekanizması lokal anesteziklerle benzerlik gösterir.","options":["Yalnız I","II ve III","Yalnız II","I, II ve III","I ve III"],"correct":4,"exp":"Miyotonik distrofide (Steinert hastalığı) DMPK genindeki trinükleotid tekrar ekspansiyonu, skeletal kas hücrelerinde voltaj kapılı Na⁺ kanallarının inaktivasyonunda gecikmeye yol açar; bu durum sürekli tekrarlayan aksiyon potansiyelleri (miyotoni) olarak kendini gösterir. Meksiletin, sınıf IB antiaritmik ajan olup lokal anesteziklerle (lidokain) aynı şekilde voltaj kapılı Na⁺ kanallarının iç yüzüne bağlanarak kanalı bloke eder; bu nedenle öncül I ve III doğrudur. Öncül II yanlıştır: miyotoni, kas membranının kendisindeki iyon kanal disfonksiyonundan kaynaklanır, motor nöronden değil. Bu nedenle doğru öncüller I ve III'tür."},{"id":8342,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, efor dispnesi ve bilateral pretibial ödem şikayetiyle başvuruyor. Özgeçmişinde hipertansiyon ve tip 2 diyabetes mellitus mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %65, E/e' oranı 18, sol atriyal volüm indeksi 42 mL/m² saptanıyor. Hastaya yeni başlanan bir ilaç sonrasında furosemid dozunun azaltılabildiği ve egzersiz kapasitesinin arttığı gözlemleniyor. Bu hastada başlanan ilaç aşağıdakilerden hangisidir?","options":["Sakubitril/valsartan","Digoksin","Empagliflozin","Spironolakton","İvabradın"],"correct":2,"exp":"Klinik tablo, korunmuş ejeksiyon fraksiyonlu kalp yetmezliğini (HFpEF) düşündürmektedir: EF ≥%50, yüksek E/e' oranı ve dilate sol atriyum diyastolik disfonksiyonun göstergeleridir. SGLT2 inhibitörleri (empagliflozin), EMPEROR-Preserved ve DELIVER çalışmalarıyla HFpEF'te hospitalizasyonu ve kardiyovasküler ölümü anlamlı düzeyde azaldığı gösterilen ve bu endikasyonda FDA onayı bulunan ilaçlardır. Diüretik gereksinimini azaltarak volüm yönetimine katkı sağlar ve egzersiz kapasitesini artırır. Sakubitril/valsartan HFrEF'te birincil seçenek olup HFpEF'te sınırlı kanıt mevcuttur. Digoksin ve ivabradın HFpEF için standart tedavi değildir. Spironolakton HFpEF'te kullanılabilir ancak tanımlanan klinik yanıt SGLT2 inhibitörlerine özgüdür."},{"id":8343,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, üniversite sınavı döneminde başlayan progresif nefes darlığı ve elle tutulur parmaklara yayılan parestezi şikayetiyle acil servise başvuruyor. Vital bulgularda solunum sayısı 28/dk, oksijen satürasyonu oda havasında %99, tansiyonu 110/70 mmHg. Arteriyel kan gazı analizi: pH 7.56, PaCO₂ 24 mmHg, PaO₂ 105 mmHg, HCO₃⁻ 21 mEq/L. Bu hastada aşağıdaki öncüllerden kaç tanesi yanlıştır?\nI. Hipokalsemi, semptomların fizyopatolojisinde rol oynamaktadır.\nII. Birincil bozukluk metabolik alkalozisdir.\nIII. İyonize kalsiyum düzeyi, toplam kalsiyum düzeyi değişmeksizin azalmış olabilir.\nIV. Tedavide öncelikli yaklaşım karbonhidrat yüklenmesidir.","options":["3","1","Hiçbiri","2","4"],"correct":3,"exp":"Klinik tablo, stres ilişkili hiperventilasyon sendromunu yansıtmaktadır. KAN GAZI: yüksek pH (7.56), düşük PaCO₂ (24), normal/hafif düşük HCO₃⁻ (21) → akut solunum alkalozisi. Öncüller değerlendirildiğinde: I. DOĞRU — Solunum alkalozisinde artan pH, albumine bağlı H⁺ ayrışarak albuminin Ca²⁺'a afinitesini artırır; böylece serbest (iyonize) Ca²⁺ azalır. Bu durum perioral ve distal parestezilere, karpopedal spazma yol açar. II. YANLIŞ — Birincil bozukluk solunum alkalozisidir, metabolik alkaloz değil; HCO₃⁻ düşük-normal seyretmektedir (kompansatör renal atılım). III. DOĞRU — Toplam kalsiyum değişmeksizin iyonize fraksiyon pH'ya bağlı olarak azalabilir. IV. YANLIŞ — Tedavide kapalı kese nefesi (CO₂ rebreathing) veya kontrollü solunum eğitimi önceliklidir; karbonhidrat yüklenmesi bu patolojide endike değildir. Dolayısıyla II ve IV yanlıştır: yanlış öncül sayısı 2'dir."},{"id":8344,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"67 yaşında erkek hasta, kontrolsüz diyabeti olan bir hastada serum kreatinin değerinin 6 ayda 0.9 mg/dL'den 2.1 mg/dL'ye yükseldiği saptanıyor. İdrar tetkikinde mikroalbüminüri pozitif, glukozüri mevcut. Bu hastada böbrek hasarının erken döneminde glomerüler filtrasyon hızının geçici olarak artmasının (hiperfiltrasyon) temel nedeni hangisidir?","options":["Mezangial hücre proliferasyonunun filtrasyon yüzeyini artırması","Bowman kapsülü hidrostatik basıncının azalması","Efferent arteriyol vazodilasyonu ile glomerüler kapiller basıncın düşmesi","Afferent arteriyolün vazodilasyonu ile glomerüler kapiller basıncın artması","Tübüler geri emilimin azalması ile tübüloglomerüler geri bildirimin baskılanması"],"correct":3,"exp":"Diyabetik nefropatinin erken döneminde hiperglisemi, böbrekte lokal IGF-1 ve NO salınımını artırarak afferent arteriyolde vazodilasyona yol açar. Bu durum glomerüler kapiller hidrostatik basıncı yükseltir ve GFR'yi artırır (hiperfiltrasyon). Aynı zamanda proksimal tübülde artmış glukoz-Na⁺ kotransportu nedeniyle makula densaya ulaşan NaCl miktarı azalır; bu da tübüloglomerüler geri bildirimi baskılayarak afferent arteriyol dilatasyonunu daha da pekiştirir. Seçenek B bu mekanizmayı doğru tanımlamaktadır. Efferent arteriyol dilatasyonu (seçenek C) glomerüler basıncı düşürür ve GFR'yi azaltır. Mezangial proliferasyon (seçenek D) ilerleyen dönemde filtrasyon yüzeyini azaltır. Tübüler geri emilimin azalması (seçenek E) hiperfiltrasyonun değil hipergliseminin sonucudur."},{"id":8345,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Bir nöronda aksiyon potansiyeli sırasında aşağıdaki öncüllerden hangileri doğrudur?\nI. Depolarizasyon fazında Na⁺ iyonları hücre içine girer.\nII. Repolarizasyon fazında K⁺ kanalları kapanır ve Na⁺ kanalları açılır.\nIII. Mutlak refrakter dönemde Na⁺ kanallarının çoğu inaktif konumdadır.\nIV. Hiperolarizasyon (undershoot) fazında K⁺ geçirgenliği artmış olmaya devam eder.","options":["Yalnız III","I, III ve IV","I, II ve IV","I ve II","II ve III"],"correct":1,"exp":"Aksiyon potansiyeli fazları: Depolarizasyon — eşik potansiyel aşılınca voltaj kapılı Na⁺ kanalları hızla açılır, Na⁺ içeri girer, membran potansiyeli +30–+40 mV'a ulaşır; öncül I doğrudur. Repolarizasyon — Na⁺ kanalları inaktive olur (kapanır), K⁺ kanalları açılır, K⁺ dışarı çıkar; öncül II'de Na⁺ kanallarının açıldığı ifadesi yanlıştır, bu nedenle öncül II yanlıştır. Mutlak refrakter dönem — Na⁺ kanallarının büyük çoğunluğu inaktif (kapalı-inaktif) konumdadır ve ikinci bir uyarıya yanıt verilemez; öncül III doğrudur. Hiperpolarizasyon (undershoot) — K⁺ kanallarının yavaş kapanması nedeniyle K⁺ geçirgenliği normalin üzerinde kalmaya devam eder, membran potansiyeli kısa süreliğine istirahat potansiyelinin altına iner; öncül IV doğrudur. Doğru öncüller: I, III ve IV."},{"id":8346,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 3 haftadır süren yorgunluk, sarılık ve koyu renkli idrar şikayetiyle başvuruyor. Özgeçmişinde otoimmün hastalık öyküsü mevcut ve 2 hafta önce üst solunum yolu enfeksiyonu geçirmiş. Laboratuvar tetkiklerinde hemoglobin 7.2 g/dL, MCV 105 fL, retikülosit indeksi %8, direkt Coombs testi pozitif, LDH yüksek, haptoglobin düşük saptanıyor. Periferik yaymada sferositler ve polikromazi izleniyor. Bu hastaya başlanan tedavinin birincil etki hedefi aşağıdakilerden hangisidir?","options":["Dalak ve karaciğerde antikor üreten B lenfosit klonlarının baskılanması","Kompleman sisteminin C3 konvertazının inhibisyonu","T lenfosit aktivasyonunun engellenerek antikor üretiminin azaltılması","Eritropoietin reseptörlerine bağlanarak eritropoezi stimüle etmek","Makrofaj yüzeyindeki Fc reseptörlerinin bloke edilerek IgG kaplı eritrositlerin hemolizden korunması"],"correct":4,"exp":"Klinik tablo, enfeksiyon tetikli sıcak tip otoimmün hemolitik anemiyi (AIHA) yansıtmaktadır: direkt Coombs pozitifliği, sferositler, yüksek retikülosit indeksi, LDH yüksekliği, düşük haptoglobin ve makrositoz (aktif eritropoezle ilişkili). Sıcak tip AIHA'da IgG antikorları eritrosit yüzeyine bağlanır; dalak ve karaciğer makrofajları bu eritrositleri Fc reseptörleri aracılığıyla tanıyarak fagosite eder (ekstravazküler hemoliz). Tedavide birinci basamak kortikosteroidlerdir. Kortikosteroidlerin birincil etki mekanizması, dalak ve karaciğer makrofajlarının yüzeyindeki Fc reseptör ekspresyonunu azaltarak IgG kaplı eritrositlerin klirensini baskılamaktır; bu seçenek C'ye karşılık gelir. T lenfosit supresyonu (B) ve B hücre baskılanması (E) kortikosteroidlerin ikincil etkileri olup birincil hedef değildir. Kompleman inhibisyonu (A) soğuk tip AIHA ve PNH'de ön plandadır."},{"id":8347,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, 6 aydır eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Özgeçmişinde tip 2 diyabetes mellitus ve hipertansiyon mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor; kalp hızı 88/dk, kan basıncı 145/90 mmHg. Hastaya başlanan izosorbit dinitrat tedavisinin hemodinamik etkisine ilişkin aşağıdaki öncüller değerlendirilmektedir:\nI. Venöz kapasitans damarlarını dilate ederek ön yükü azaltır.\nII. Koroner arterlerden kolateral kan akımını artırır.\nIII. Sistemik vasküler direnci belirgin düzeyde azaltarak arka yükü primer olarak etkiler.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, II ve III","Yalnız I","I ve II","II ve III","I ve III"],"correct":2,"exp":"İzosorbit dinitrat organik nitrat grubuna ait bir ilaçtır. Nitratların en belirgin etkisi venöz dilatasyon aracılığıyla venöz dönüşü (ön yükü) azaltmaktır; bu sayede sol ventrikül diyastol sonu basıncı düşer ve miyokard oksijen tüketimi azalır (Öncül I doğru). Koroner arteriyel düzeyde kolateral dolaşımı artırarak iskemik bölgelere kan akımını yeniden dağıtır (Öncül II doğru). Öncül III yanlıştır; nitratlar yüksek dozda arteriyel dilatasyon yapabilse de arka yük üzerine primer etkisi belirgin değildir, bu etki hidralazin gibi direkt arteriyel vazodilatörlere özgüdür. Dolayısıyla I ve II doğrudur."},{"id":8348,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 yıldır süren tekrarlayan wheezing, öksürük ve nefes darlığı yakınmalarıyla göğüs hastalıkları polikliniğine başvuruyor. Solunum fonksiyon testinde FEV1/FVC: %62, bronkodilatatör sonrası FEV1'de %18 artış saptanıyor. Histopatolojik açıdan bu hastalıkta beklenen doku değişikliklerine ilişkin aşağıdaki öncüller değerlendirilmektedir:\nI. Goblet hücre hiperplazisi ve mukus hipersekresyonu izlenir.\nII. Bronş duvarında eozinofil ve mast hücre infiltrasyonu beklenir.\nIII. Düz kas kitlesinde azalma (atrofi) gözlenir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["2 tanesi","Yalnız 1 tanesi","Hiçbiri","Yalnız III","3 tanesi"],"correct":0,"exp":"Klinik tablo bronşiyal astımı düşündürmektedir. Astımın histopatolojik bulguları arasında goblet hücre hiperplazisi ve artmış mukus sekresyonu yer alır (Öncül I doğru). Bronş duvarına eozinofil ve mast hücre infiltrasyonu, Tip 2 immün yanıtın yansıması olarak tipik bir bulgudur (Öncül II doğru). Öncül III yanlıştır; astımda bronş düz kasında atrofi değil, tam tersine hipertrofi ve hiperplazi gelişir; bu durum havayolu remodellinginin temel bileşenlerinden biridir. Dolayısıyla 2 öncül doğrudur."},{"id":8349,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, rutin kontrol sırasında serum kreatinin: 2.8 mg/dL, BUN: 54 mg/dL, 24 saatlik idrarda protein: 3.2 g olarak saptanıyor. Kan basıncı 162/98 mmHg. Renal biyopside mezangial matriks artışı, bazal membran kalınlaşması ve Kimmelstiel-Wilson nodülleri görülüyor. Bu hastada böbrek histolojisindeki değişikliklerin fizyopatolojik sonuçlarına ilişkin aşağıdaki öncüller değerlendirilmektedir:\nI. Glomerüler filtrasyon bariyerinin yük seçiciliğinin bozulması proteinüriye yol açar.\nII. Mezangial ekspansiyon, glomerüler filtrasyon alanını daraltarak GFR'yi azaltır.\nIII. Tübüler sekresyon kapasitesinin artması, BUN yüksekliğini önler.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","II ve III","I ve II","Yalnız II","I, II ve III"],"correct":2,"exp":"Klinik ve histopatolojik bulgular diyabetik nefropatiyle uyumludur. Glomerüler bazal membran kalınlaşması ve podosit hasarı, filtrasyon bariyerinin hem boyut hem yük seçiciliğini bozarak proteinüriye neden olur (Öncül I doğru). Mezangial matriks ekspansiyonu ve nodüler skleroz, kapiller lümen alanını daraltarak fonksiyonel glomerüler filtrasyon yüzeyini azaltır ve GFR'nin düşmesine yol açar (Öncül II doğru). Öncül III yanlıştır; kronik böbrek hastalığında tübüler sekresyon kapasitesi azalır, artan tübüler sekresyon BUN'u düşürmez; BUN yüksekliğinin temel nedeni GFR azalmasıdır. Dolayısıyla I ve II doğrudur."},{"id":8350,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"47 yaşında erkek hasta, 3 aydır ellerde uyuşma, bilekte ağrı ve gece uykuyu bölen yanma hissiyle nöroloji polikliniğine başvuruyor. Tinel ve Phalen testleri pozitif saptanıyor. Sinir iletim çalışmasında median sinirde distal motor latans uzamış, iletim hızı azalmış, ancak aksiyel amplitüdler korunmuş olarak bulunuyor. Bu sinir iletim çalışması bulgularının histopatolojik karşılığı olarak en doğru yorum hangisidir?","options":["Aksonal dejenerasyon ile birlikte Schwann hücre kaybı","Endonöryal fibrozis ile tam aksonal kayıp","Miyelinli liflerde selektif demiyelinizasyon, aksonal bütünlük korunmuş","Miyelinsiz C liflerinde selektif hasar","Ranvier boğumlarında paranodal aksonal şişme"],"correct":2,"exp":"Klinik tablo karpal tünel sendromunu düşündürmektedir. Sinir iletim çalışmasında iletim hızının azalmış olması ve distal latansın uzaması ancak amplitüdlerin korunmuş olması, aksonal kaybın değil demiyelinizasyonun göstergesidir. Miyelin kılıfı Schwann hücreleri tarafından oluşturulur ve Ranvier boğumları arasında saltatory iletimi sağlar; miyelin kaybı iletim hızını dramatik biçimde düşürür. Amplitüdlerin korunması aksonların büyük çoğunluğunun sağlam olduğunu gösterir. Aksonal dejenerasyonda amplitüdler düşerdi. Karpal tünelde kronik kompresyon öncelikle demiyelinizasyona yol açar."},{"id":8351,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 4 haftadır süren halsizlik, soluk görünüm ve egzersiz intoleransı yakınmalarıyla iç hastalıkları polikliniğine başvuruyor. Laboratuvar incelemesinde Hb: 8.2 g/dL, MCV: 72 fL, MCH: 22 pg, serum ferritin: 6 ng/mL, TDBK: 420 µg/dL saptanıyor. Bu hastada eritropoez sırasında hangi olgunlaşma basamağında en belirgin bozulma beklenir?","options":["Proeritroblastten bazofil eritroblasta geçiş","Retikülositte ribozom kaybı","Eritroid öncüllerden BFU-E oluşumu","Ortokromatik eritroblastta çekirdek atımı","Polikromatofil eritroblastten ortokromatik eritroblasta geçişte hemoglobin sentezi"],"correct":4,"exp":"Laboratuvar bulguları demir eksikliği anemisine işaret etmektedir (düşük ferritin, yüksek TDBK, mikrositik hipokromik tablo). Hemoglobin sentezi için hem yapısının oluşması demire bağımlıdır. Eritropoezde hemoglobin birikimi özellikle polikromatofil ve ortokromatik eritroblast aşamasında yoğunlaşır; demir eksikliğinde bu dönemde globin zincirleri sentezlenebilir ancak hem sentezi yetersiz kalır ve hemoglobin birikimi azalır. Sonuç olarak hücreler daha fazla bölünmeye devam ederek küçük (mikrositik) ve hemoglobinden fakir (hipokromik) eritrositler oluşur. Çekirdek atımı ve ribozom kaybı gibi diğer aşamalar demire doğrudan bağımlı değildir."},{"id":8352,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Mide fundus mukozasındaki parietal hücrelerin hem intrinsik faktör hem de hidroklorik asit salgıladığı bilinmektedir. Bu hücrelerin ultrastrüktürel özelliğini ve fonksiyonel kapasitesini en iyi açıklayan bulgu hangisidir?","options":["Apikal yüzeyde çok sayıda mikrovillüs ve bazal lamina invazyonu","Lizozom ağırlıklı sitoplazma ve otofaji vakuolleri","Granüllü endoplazmik retikulumun belirgin gelişimi ve bazolateral ekzositoz","Düz endoplazmik retikulum gelişimi ve lipid damlacıkları","Tubulovesiküler sistem ve geniş intrasellüler kanaliküller"],"correct":4,"exp":"Parietal hücreler mide fundus bezlerinin karakteristik hücreleridir. Elektron mikroskopisinde en dikkat çekici ultrastrüktürel özellik, sitoplazmanın büyük bölümünü kaplayan çok sayıda mitokondri (yüksek enerji gereksinimi için), apikal membrana bağlantılı intrasellüler kanaliküller ve bu kanaliklüllerle birleşen tubulovesiküler sistem kompleksidir. Uyarılmamış hücrede H+/K+-ATPaz pompaları tubulovesiküler membranlar içinde depolanırken, uyarı sonrasında bu veziküller kanalikiül membranıyla füzyon yaparak pompa yoğunluğunu artırır ve HCl sekresyonu gerçekleşir. Granüllü endoplazmik retikulum protein sentezinin yoğun olduğu hücrelerin (asiner hücreler gibi) özelliğidir; parietal hücrelerin baskın organeli mitokondri ve tubulovesiküler sistemdir."},{"id":8353,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, efor dispnesi ve bacaklarda ödem şikayetiyle başvuruyor. Yapılan ekokardiyografide ejeksiyon fraksiyonu %30 olarak saptanıyor. Hastaya tedavi düzenlenirken aşağıdaki ifadeler değerlendiriliyor:\nI. Digoksin, Na⁺/K⁺-ATPaz inhibisyonu yoluyla intraselüler Na⁺ birikimini artırarak Na⁺/Ca²⁺ değiştiricisini (NCX) ters yönde çalıştırır ve intraselüler Ca²⁺ konsantrasyonunu yükseltir.\nII. Spironolakton bu hastada kullanıldığında aldosteronun koroner arter düz kas hücrelerindeki fibrozis yapıcı etkisini baskılayarak mortaliteyi azaltır.\nIII. Beta bloker kullanımı akut dekompanse kalp yetmezliği atağı sırasında başlanmalıdır, çünkü sempatik aktivasyonun hızla bloke edilmesi kardiyak yeniden şekillenmeyi (remodeling) önler.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, II ve III","I ve II","II ve III","Yalnız II","Yalnız I"],"correct":1,"exp":"Öncül I doğrudur: Digoksin sarkolemmal Na⁺/K⁺-ATPaz pompasını inhibe eder; hücre içi Na⁺ artar, Na⁺/Ca²⁺ değiştiricisi (NCX) ters modda çalışmak zorunda kalır ve Ca²⁺ hücre içinde birikir, böylece pozitif inotropik etki sağlanır. Öncül II doğrudur: Spironolakton, aldosteronun kardiyak ve vasküler fibroblastlar üzerindeki mineralokortikoid reseptör aracılı pro-fibrotik etkisini bloke eder; RALES ve EMPHASIS-HF çalışmaları mortalite azalmasını göstermiştir. Öncül III yanlıştır: Beta blokerler akut dekompanse kalp yetmezliğinde kontrendikedir; negatif inotropik etkileri nedeniyle akut dönemi kötüleştirebilirler. Bu ilaçlar klinik stabilizasyon sağlandıktan sonra, genellikle taburculuk öncesinde veya sonrasında başlanır."},{"id":8354,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbrek tübül segmentleri ve taşıyıcı proteinlerle ilgili aşağıdaki öncüller değerlendiriliyor:\nI. Proksimal tübülde glukoz geri emilimi, apikal membranda SGLT2 aracılığıyla gerçekleşir ve bu taşıma Na⁺ gradyanına bağımlıdır.\nII. Henle kulpunun ince inen kolu suya geçirgen, Na⁺ ve Cl⁻ iyonlarına ise geçirgensizdir.\nIII. Toplayıcı kanallarda ADH varlığında AQP2 kanalları bazolateral membrandan lüminal membrana yerleşir ve su geri emilimi artar.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Üçü","Dördü","Hiçbiri","Yalnız biri","İkisi"],"correct":4,"exp":"Öncül I doğrudur: Proksimal tübül apikal membranında SGLT2 (sodyum-glukoz ko-taşıyıcı 2), Na⁺ gradyanını kullanarak glukozu lümenden hücre içine taşır; bu sekonder aktif taşıma mekanizmasıdır. SGLT2 inhibitörleri bu noktayı hedef alır. Öncül II doğrudur: Henle kulpunun ince inen kolu yüksek düzeyde AQP1 eksprese eder, dolayısıyla suya oldukça geçirgendir; ancak Na⁺ ve Cl⁻ için geçirgenliği düşüktür. Bu özellik medüller hipertonik ortamın oluşmasına katkıda bulunur. Öncül III kısmen doğru ifade edilmiş ancak lokalizasyon hatası içermektedir: AQP2 normalde hücre içi veziküllerde depolanır; ADH (vazopressin) V2 reseptörüne bağlandığında cAMP/PKA yolağı aktive olur ve AQP2 veziküllerinin füzyonuyla kanallar apikal (lüminal) membrana yerleşir, bazolateral değil. Bu nedenle öncül III yanlıştır. Sonuç olarak I ve II doğru, III yanlış olduğundan iki öncül doğrudur."},{"id":8355,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan egzersiz intoleransı ve yorgunluk yakınmasıyla başvuruyor. Özgeçmişinde 10 yıldır tip 2 diyabet tanısı mevcut. Elektromiyografide miyopatik patern saptanıyor; kas biyopsisinde tip II kas liflerinde belirgin atrofi ve mitokondri sayısında azalma gözleniyor. Bu hastanın kas dokusunda beklenen metabolik uyum aşağıdakilerden hangisidir?","options":["Kreatin fosfat yenileme hızında artış ve glikojen sentezinde yükselme","Oksidatif fosforilasyon kapasitesinde düşme ve yağ asidi oksidasyonuna bağımlılığın azalması","Tip I liflerin hipertrofisi ile oksidatif enzim aktivitesinin kompansatuar artışı","Glikoliz kapasitesinde artış ve laktat üretiminde azalma","Yüksek eşikli motor birimlerin tercihli kaybı ve aerobik kapasitenin korunması"],"correct":2,"exp":"Tip 2 diyabette kronik insülin direnci ve hiperglisemi, öncelikle hızlı kasılan, glikolize bağımlı tip II kas liflerini etkiler. Bu liflerde mitokondri sayısı azalır, oksidatif kapasitede gerileme olur. Kompansatuar olarak yavaş kasılan, oksidatif metabolizmaya yetkin tip I lifler hipertrofi gösterir ve oksidatif enzim aktivitesi (sitrat sentaz, sitokrom oksidaz) bu liflerde göreceli artar. Bu durum, kronik diyabetik miyopatide tipik bir kompansasyon mekanizması olarak bilinir. Diğer seçenekler yanlıştır: glikoliz kapasitesi artmaz; kreatin fosfat yenileme hızı tip I liflerde tip II liflere kıyasla daha yavaştır; yüksek eşikli (tip II) motor birimler kaybedilirken aerobik kapasite zaten bozulur."},{"id":8356,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 3 haftadır ilerleyici seyirli çift görme, yutma güçlüğü ve üst ekstremitede proksimal kas güçsüzlüğü yakınmasıyla başvuruyor. Tekrarlayan sinir uyarımı testinde yüksek frekanslı stimülasyonla amplitüdde artış saptanıyor; tensilyum testine yanıt alınamıyor. Anti-VGCC (voltaj kapılı kalsiyum kanalı) antikoru pozitif. Bu hastada nöromüsküler kavşakta birincil bozukluk hangi yapıda gerçekleşmektedir?","options":["Presinaptik terminale kalsiyum girişinin yetersizliğine bağlı kuantal içerik azalması","Presinaptik terminalde asetilkolin sentezi için kolin asetiltransferaz aktivitesinin kaybı","Postsinaptik membranda voltaj kapılı sodyum kanalı blokajı","Sinaptik yarıkta asetilkolinesteraz aktivitesinin artışına bağlı hızlı asetilkolin yıkımı","Postsinaptik membranda asetilkolin reseptörü yoğunluğunda azalma"],"correct":0,"exp":"Anti-VGCC antikorları Lambert-Eaton miyastenik sendromu (LEMS) göstergesidir. Bu sendromda otoimmün antikorlar presinaptik terminaldeki P/Q tipi voltaj kapılı kalsiyum kanallarını bloke eder. Kalsiyum girişi azaldığından sinir uyarısına bağlı asetilkolin vezikül ekzositozu (kuantal içerik) belirgin azalır. Yüksek frekanslı stimülasyonda birikimli kalsiyum girişi geçici iyileşme sağladığından amplitüd artar (fasilitasyon). Bu tablo miyastenia gravisin tam tersidir: miyasteniada postsinaptik AChR azalır ve tensilyuma yanıt pozitiftir. Kolin asetiltransferaz kaybı ve asetilkolinesteraz artışı bu tabloya uymaz."},{"id":8357,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 2 yıldır devam eden poliüri ve noktüri yakınmalarıyla nefroloji polikliniğine başvuruyor. İdrar ozmolalitesi 180 mOsm/kg, serum ozmolalitesi 298 mOsm/kg, serum sodyumu 148 mEq/L olarak ölçülüyor. Su kısıtlama testine yanıt alınamıyor, ancak desmopressin uygulaması sonrasında idrar ozmolalitesi 185 mOsm/kg düzeyinde kalıyor. Toplayıcı kanal epitelinde en olası histolojik değişiklik aşağıdakilerden hangisidir?","options":["Toplayıcı kanalın prinsip hücrelerinde V2 reseptör yoğunluğunda artış","Henle kulpunun çıkan kolunda Na-K-2Cl kotransporter aktivasyonunun artması","Prinsip hücre apikal membranında aquaporin-2 ekspresyonu ve membrana entegrasyonunun yetersizliği","Aquaporin-2 kanal ekspresyonunun artışı ve bazolateral aquaporin-3/4 kaybı","Interstisyel hipertonisitenin bozulmasına bağlı ozmotik gradyan korunması"],"correct":2,"exp":"Desmopressin (ADH analoğu) uygulamasına yanıtsız diabetes insipidus, nefrojenik tipini işaret eder. Nefrojenik DI'da sorun, toplayıcı kanal prinsip hücrelerinde V2 reseptörünün işlevsizliği veya downstream sinyal yolunun bozukluğudur. Bu durumda ADH normalde bağlanıp cAMP oluştursa bile aquaporin-2 (AQP2) içeren veziküller apikal membrana füzyon yapamaz ya da AQP2 ekspresyonu yetersiz kalır. Bunun histolojik karşılığı, apikal membranda AQP2 ekspresyonu ve membrana entegrasyonunun bozulmasıdır. AQP2 genellikle normal ya da artmış sayıda bulunur ancak membranda değil sitoplazmik vezikül havuzunda sıkışmış olarak kalır. Su kısıtlama testine yanıt alınamaması ve desmopressin sonrası idrar konsantrasyonunun artmaması bu tanıyı doğrular."},{"id":8358,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"Aşağıdaki öncülleri değerlendirin:\nI. Kapiller endotel hücreleri arasındaki sıkı bağlantılar (tight junction) beyin kapillerinde diğer dokulara kıyasla çok daha gelişmiş olup kan-beyin bariyerini oluşturur.\nII. Venüller, kapillerden daha büyük çaplıdır ve akut inflamasyonda histamin etkisiyle permeabilite artışı öncelikle venüllerde gerçekleşir.\nIII. Sinüzoidal kapillerlerin bazal membranı devamlı yapıdadır ve bu özellik karaciğerde plazma proteinlerinin geçişini kısıtlar.\nIV. Arteriyoller, damar direncinin temel belirleyicisi olup sempatik innervasyon aracılığıyla periferik vasküler direnci düzenler.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["1","2","Hepsi yanlıştır","4","3"],"correct":4,"exp":"Öncül I doğrudur: Beyin kapillerindeki sıkı bağlantılar diğer dokulara kıyasla belirgin şekilde gelişmiş olup kan-beyin bariyerini oluşturur. Öncül II doğrudur: Venüller kapillerden geniş çaplıdır; akut inflamasyonda histamin ve bradikinin etkisiyle permeabilite artışı öncelikle post-kapiller venüllerde gerçekleşir. Öncül III yanlıştır: Sinüzoidal kapillerlerin bazal membranı süreksiz (diskontinü) yapıdadır ya da hiç yoktur; bu sayede karaciğerde albümin dahil büyük proteinler serbestçe geçebilir. Öncül IV doğrudur: Arteriyoller, sempatik sinir sistemi ve lokal faktörler aracılığıyla lümen çapını değiştirerek periferik vasküler direncin ana belirleyicisidir. Dolayısıyla 3 öncül (I, II ve IV) doğrudur."},{"id":8359,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Aşağıdaki öncülleri değerlendirin:\nI. Tip II pnömositler, alveol yüzey gerilimini azaltan sürfaktanı üretir ve alveoler epitel hasarı sonrası tip I pnömositleri yenileyebilir.\nII. Clara hücreleri (Club hücreleri), bronşiyollerde mukus salgılar ve silier hareketle partikül temizliğini sağlar.\nIII. Alveoler makrofajlar, pulmoner kapiller endotel kökenlidir ve alveoler boşlukta fagositoz işlevi görür.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","II ve III","Yalnız I","I, II ve III","I ve II"],"correct":2,"exp":"Öncül I doğrudur: Tip II pnömositler (granüler pnömositler) sürfaktan sentezler ve salgılar; ayrıca tip I pnömositler hasarlandığında mitoz geçirerek alveol epitelini yeniler. Öncül II yanlıştır: Club (Clara) hücreleri silia içermez ve mukus üretmez; aksine yüzey aktif lipoprotein salgılar, yabancı maddeleri detoksifiye eder ve bronşiyol epiteli için progenitör hücre işlevi görür. Öncül III yanlıştır: Alveoler makrofajlar kemik iliği kökenli monosit serisinden gelir, pulmoner kapiller endotelden değil. Alveoler boşlukta ve pulmoner interstisyumda fagositoz yaparlar. Bu nedenle yalnızca I. öncül doğrudur."},{"id":8360,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 8 aydır devam eden kronik ishal, 12 kg kilo kaybı ve steatore yakınmasıyla başvuruyor. Duodenum biyopsisinde villöz atrofi ve kript hiperplazisi saptanıyor, intraepitelyal lenfosit sayısı artmış. Hastaya gluten içermeyen diyet başlandıktan 6 ay sonra kontrol biyopsisinde morfolojik iyileşme gözleniyor. Bu hastada emilim bozukluğunun birincil nedeni aşağıdakilerden hangisidir?","options":["İnce barsak laminasına bağlı lenfatik drenaj bozukluğu ve şilomikron taşınım yetersizliği","Kolonik mukozada sodyum-su geri emiliminin bozulması","Villöz atrofiye bağlı emilim yüzey alanının kaybı ve fırçamsı kenar enzim aktivitesinde düşme","Gastrik asit hipersekresyonuna bağlı duodenal pH'nın pankreas lipazını inaktive etmesi","Pankreatik ekzokrin yetmezliğe bağlı intralüminal sindirim enzimi eksikliği"],"correct":2,"exp":"Tanım çölyak hastalığını (gluten enteropatisi) göstermektedir: villöz atrofi, kript hiperplazisi, artmış intraepitelyal lenfositoz ve gluten içermeyen diyetle düzelme bu tanının klasik kriterleridir. Çölyakta gliadine (gluten bileşeni) karşı gelişen otoimmün yanıt, ince barsak mukozasını hasarlar. Villöz atrofi, emilim yüzey alanını dramatik biçimde azaltır. Buna ek olarak fırçamsı kenardaki disakkaridazlar, peptidazlar ve taşıyıcı proteinler kaybedildiğinden besin öğelerinin sindirim ve emilimi bozulur. Pankreatik yetmezlik, lenfatik bozukluk ve gastrik hipersekresyon bu tabloya uymaz; kolonik patoloji ise çölyakın birincil mekanizması değildir."},{"id":8361,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"72 yaşında erkek hasta, 6 aydır devam eden efor dispnesi ve bacaklarda şişlik yakınmasıyla başvuruyor. Özgeçmişinde 20 yıllık hipertansiyon ve tip 2 diyabet öyküsü mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30 olarak saptanıyor. Hastaya digoksin başlanıyor. Digoksinin etki mekanizmasıyla ilgili aşağıdaki öncülleri değerlendiriniz:\nI. Na⁺/K⁺-ATPaz pompasını inhibe eder.\nII. İntraselüler Na⁺ birikimi sonucu Na⁺/Ca²⁺ değiştirici (NCX) ters yönde çalışır.\nIII. Sitozolde artan Ca²⁺ konsantrasyonu, miyozin hafif zincir kinazı doğrudan aktive eder.\nIV. Sonuç olarak kasılma kuvveti artar (pozitif inotropi).\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["2","3","4","1","Hiçbiri"],"correct":1,"exp":"Digoksin, kardiyomiyosit zarındaki Na⁺/K⁺-ATPaz pompasını inhibe ederek hücre içinde Na⁺ birikmesine yol açar (öncül I doğru). Artan intraselüler Na⁺, Na⁺/Ca²⁺ değiştiricinin (NCX) ters yönde çalışmasına neden olarak Ca²⁺ çıkışını azaltır ve sitozolde Ca²⁺ artışı sağlar (öncül II doğru). Bu mekanizma pozitif inotropik etki ile sonuçlanır (öncül IV doğru). Ancak öncül III yanlıştır; artan Ca²⁺, miyozin hafif zincir kinazı doğrudan aktive etmez; düz kasta bu ilişki geçerlidir, kalp kasında troponin C üzerinden etki oluşur. Dolayısıyla I, II ve IV doğru olmak üzere 3 öncül doğrudur."},{"id":8362,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 yıldır tekrarlayan hışıltılı solunum ve nefes darlığı yakınmaları nedeniyle başvuruyor. Allerjik astım tanısı konulan hastaya inhale kortikosteroid ve uzun etkili beta-2 agonist (LABA) tedavisi başlanıyor. Kontrolünde zorlu vital kapasite (FVC) normal, FEV₁/FVC oranı %62 olarak saptanıyor. Bu hastada LABA'nın bronkodilatatör etkisine aracılık eden temel hücresel mekanizma hangisidir?","options":["cAMP artışı ile miyozin hafif zincir fosfatazın aktivasyonu","K⁺ kanallarının blokajı ile membran hiperpolarizasyonu","IP₃ aracılıklı endoplazmik retikulumdan Ca²⁺ salınımının inhibisyonu","Rho-kinaz yolağının aktivasyonu ile Ca²⁺ duyarlılığının artması","cGMP artışı ile protein kinaz G aktivasyonu"],"correct":0,"exp":"Beta-2 agonistler, bronş düz kasındaki Gs proteinlerine bağlı beta-2 reseptörlerini aktive eder. Bu aktivasyon adenilat siklazı uyararak cAMP düzeyini artırır. Artan cAMP, protein kinaz A'yı aktive eder; PKA hem miyozin hafif zincir kinazı (MLCK) fosforile ederek inaktive eder hem de miyozin hafif zincir fosfatazı (MLCP) aktive eder. Sonuç olarak miyozin defosforilasyonu artar, düz kas gevşer ve bronkodilatasyon gerçekleşir. cGMP yolağı nitrik oksit gibi ajanlarla ilişkilidir. IP₃ yolağı ise kasılmayı başlatan yolaktır, bronkodilatasyon ile ilişkisi yoktur."},{"id":8363,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 3 haftadır devam eden ödem ve köpüklü idrar yakınmasıyla nefroloji polikliniğine başvuruyor. İdrar tetkikinde günlük 4,5 g protein atılımı saptanıyor. Serum albumin düzeyi 2,1 g/dL, total kolesterol 320 mg/dL olarak ölçülüyor. Böbrek biyopsisinde podosit ayakçıklarında yaygın silinme ve bazal membranda değişiklik olmaksızın glomerüler hasar görülüyor. Bu hastada proteinüriye yol açan temel histolojik bozuklukla ilgili aşağıdaki öncülleri değerlendiriniz:\nI. Podositler glomerüler filtrasyon bariyerinin son katmanını oluşturur.\nII. Ayakçık silinmesi, nefrinin ve podosinin kaybına bağlı yarık diyaframı bozar.\nIII. Glomerüler bazal membranda yaygın kalınlaşma bu tablonun karakteristik bulgusudur.\nIV. Söz konusu bulgular minimal değişiklik hastalığıyla uyumludur.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve II","II ve III","Yalnız IV","I, III ve IV","I, II ve IV"],"correct":4,"exp":"Podositler, glomerüler filtrasyon bariyerinin üçüncü ve son katmanını oluşturan viseryal epitel hücreleridir (öncül I doğru). Podosit ayakçıkları arasındaki yarık diyafram, nefrin ve podosinin oluşturduğu yapısal bir süzgeçtir; bu proteinlerin kaybı ayakçık silinmesine ve proteinüriye yol açar (öncül II doğru). Öncül III yanlıştır; bazal membran kalınlaşması minimal değişiklik hastalığında görülmez, bu bulgu daha çok diyabetik nefropati veya membranöz nefropati ile ilişkilidir. Klinik tablo (nefrotik sendrom, ışık mikroskobisinde normal görünüm, sadece ayakçık silinmesi) minimal değişiklik hastalığıyla uyumludur (öncül IV doğru). Dolayısıyla I, II ve IV doğrudur."},{"id":8364,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Miyelinli sinir liflerinde aksiyon potansiyelinin düğümden düğüme atlayarak iletilmesini sağlayan yapı hangisidir?","options":["Schmidt-Lanterman çentikleri","Ranvier düğümleri","Akson tepesi","Nöroblast","Perikaryon"],"correct":1,"exp":"Miyelinli sinir liflerinde miyelin kılıf, Schwann hücreleri (periferik sinir sisteminde) veya oligodendrositlerin (merkezi sinir sisteminde) lipit bakımından zengin membran katmanlarından oluşur ve aksonun büyük bölümünü yalıtır. Miyelin kılıfın aralıklı olarak kesintiye uğradığı bölgeler Ranvier düğümleri olarak adlandırılır. Bu düğümlerde voltaj kapılı Na⁺ kanalları yoğunlaşmıştır. Aksiyon potansiyeli, miyelinli bölümden geçemeyeceğinden bir Ranvier düğümünden diğerine 'atlayarak' (saltatorik ileti) ilerler. Bu mekanizma hem iletim hızını artırır hem de enerji tüketimini azaltır. Schmidt-Lanterman çentikleri Schwann hücresi sitoplazmasının korunduğu alanlardır ve iletimde rol oynamaz."},{"id":8365,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 4 aydır devam eden halsizlik, çarpıntı ve egzersiz intoleransı yakınmaları nedeniyle başvuruyor. Tam kan sayımında hemoglobin 7,8 g/dL, MCV 72 fL, MCH düşük saptanıyor. Periferik yaymasında hipokrom mikrositer eritrositler ve kalem hücreleri görülüyor. Serum ferritin düzeyi 4 ng/mL olarak ölçülüyor. Bu hastaya demir replasmanı başlandıktan 7-10 gün sonra periferik kanda ilk belirgin artışın hangi hücre serisinde gözlemleneceği ve bunun nedeni hangisidir?","options":["Lenfosit artışı; timüste T hücre farklılaşmasının yeniden aktive olması","Nötrofil artışı; demir eksikliğinin düzeltilmesiyle granulopoezin uyarılması","Trombosit artışı; trombopoetinin demir varlığında sentezinin artması","Retikülosit artışı; kemik iliğinde eritroid öncüllerinin demir replasmanıyla hızlanan olgunlaşması","Monosit artışı; kemik iliği stromasındaki makrofajların yeniden proliferasyonu"],"correct":3,"exp":"Demir eksikliği anemisinde demir replasmanının ardından kemik iliğindeki eritroid progenitörler (özellikle eritroblastlar) hız kazanır ve olgunlaşmaya devam eder. Bu süreçte çekirdeğini atmış ancak henüz tam olgunlaşmamış retikülosit sayısı periferik kanda 7-10. günde belirgin biçimde artar; bu yanıt 'retikülosit krizi' olarak adlandırılır. Retikülosit artışı, kemik iliğinin tedaviye verdiği ilk somut eritropoetik yanıtı yansıtır ve tedavinin etkinliğini değerlendirmede kritik öneme sahiptir. Diğer serilerin (nötrofil, trombosit, lenfosit, monosit) demir replasmanına bu şekilde erken ve belirgin yanıt verdiğine dair kanıt yoktur."},{"id":8366,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 8 yıldır kullandığı proton pompa inhibitörü (PPI) tedavisinin gastroenteroloji kontrolünde sorgulanması üzerine ek tetkikler yapılıyor. Üst gastrointestinal endoskopide mide korpusunda küçük, soluk, polipoid lezyonlar saptanıyor ve biyopsi sonucu oksintik gland polipleriyle uyumlu olarak raporlanıyor. Serum gastrin düzeyi belirgin yüksek, serum B12 vitamini düşük bulunuyor. Bu hastada kronik PPI kullanımına bağlı gelişen histolojik ve fizyolojik değişikliklerle ilgili aşağıdaki öncülleri değerlendiriniz:\nI. PPI, parietal hücrelerdeki H⁺/K⁺-ATPaz pompasını geri dönüşümsüz bloke ederek mide asidini azaltır.\nII. Mide lümenindeki pH artışı, antral G hücrelerinin gastrin sekresyonunu negatif geri bildirimle baskılar.\nIII. Uzun süreli hipergastrinemi, enterokromafin benzeri (ECL) hücrelerinin hiperplazisine yol açabilir.\nIV. İntrinsik faktör, parietal hücrelerden salgılanır ve kronik parietal hücre supresyonu B12 emilimini bozabilir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, III ve IV","II ve IV","I ve III","Yalnız II","I, II, III ve IV"],"correct":0,"exp":"PPI'lar parietal hücrelerdeki H⁺/K⁺-ATPaz'ı (proton pompası) kovalent ve geri dönüşümsüz biçimde bloke eder; bu nedenle asit sekresyonu kalıcı olarak baskılanır ve yeni pompa sentezi gerekir (öncül I doğru). Öncül II yanlıştır: asit sekresyonunun azalması mide lümen pH'sını artırır; bu durum antral D hücrelerinden somatostatin sekresyonunu azaltarak G hücrelerinin üzerindeki inhibisyonu kaldırır. Sonuç olarak gastrin sekresyonu artar (hipergastrinemi gelişir), baskılanmaz. Hipergastrinemi, ECL hücrelerini trofik uyarı ile proliferasyona zorlar ve ECL hücresi hiperplazisi ile nadiren karsinoid tümöre zemin hazırlayabilir (öncül III doğru). İntrinsik faktör parietal hücrelerce salgılanır; kronik supresyon parietal hücre sayısını ve intrinsik faktör sekresyonunu azaltarak terminal ileumdan B12 emilimini bozar (öncül IV doğru). Dolayısıyla I, III ve IV doğrudur."},{"id":8367,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek kötüleşen proksimal kas güçsüzlüğü yakınmasıyla başvuruyor. Özgeçmişinde küçük hücreli akciğer kanseri tanısı mevcut. EMG'de tekrarlayan sinir uyarımıyla artan kas aksiyon potansiyeli amplitüdü saptanıyor. Bu hastada nöromüsküler kavşakta hangi yapı işlev göremez hale gelmiştir?","options":["Voltaj kapılı kalsiyum kanalı (P/Q tipi)","Voltaj kapılı sodyum kanalı","Asetilkolin reseptörü (nikotinik)","Ryanodine reseptörü","Asetilkolinesteraz enzimi"],"correct":0,"exp":"Lambert-Eaton miyastenik sendromu, presinaptik voltaj kapılı P/Q tipi kalsiyum kanallarına karşı oluşan otoantikoral nedeniyle gelişir. Presinaptik kalsiyum girişinin azalması asetilkolin vezikül salınımını bozar. Tekrarlayan uyarımda kalsiyum birikimi artar ve kas yanıtı güçlenir (fasilitasyon), bu da tanıyı miyastenia gravis'ten ayırt ettirir. Miyastenia gravis'te ise postsinaptik nikotinik reseptörler etkilenir ve tekrarlayan uyarımda dekrement gözlenir."},{"id":8368,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan böbrek taşı öyküsüyle başvuruyor. 24 saatlik idrarda hiperkalsiüri saptanıyor, serum kalsiyumu normal sınırlarda. Paratiroid hormon (PTH) düzeyi baskılanmış, 1,25-dihidroksivitamin D3 düzeyi yüksek bulunuyor. Bu hastanın proksimal tübül hücrelerinde aşırı aktive olan enzim hangisidir?","options":["11β-hidroksilaz","1α-hidroksilaz","25-hidroksilaz","24-hidroksilaz","Aromataz"],"correct":1,"exp":"1,25-dihidroksivitamin D3 (kalsitriol), proksimal tübülde 1α-hidroksilaz enzimi aracılığıyla 25-hidroksivitamin D3'ten sentezlenir. Bu hastada PTH baskılanmış olmasına karşın 1α-hidroksilaz aktivitesinin artmış olması, PTH'dan bağımsız primer bir 1α-hidroksilaz upregülasyonunu düşündürür (absorbsiyonel hiperkalsiüri tip II veya idiopatik hiperkalsiüri). Artan kalsitriol bağırsak kalsiyum emilimini artırır, hiperkalsiüri ve taş oluşumuna zemin hazırlar. 24-hidroksilaz ise kalsitriolün inaktif metabolitine dönüşümünü katalizler."},{"id":8369,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Kardiyovasküler sistem fizyolojisi ile ilgili aşağıdaki öncüller değerlendirildiğinde:\nI. Kapasitans damarlar olarak adlandırılan venler, total kan hacminin yaklaşık %64'ünü barındırır.\nII. Ventriküler miyokardda gap junction'lar interkalar disklerin yan (lateral) yüzeyinde yoğunlaşmıştır.\nIII. Starling kuvvetleri dengesinde onkotik basınç hem arteriyel hem venöz uçta reabsorbsiyonu destekler.\nIV. Baroreseptörler, karotis sinüsünde duvar gerilmesine yanıt veren düz kas hücreleridir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["2 tanesi","4 tanesi","3 tanesi","Yalnız 1 tanesi","Hiçbiri"],"correct":3,"exp":"Yalnızca I numaralı öncül doğrudur: venler sistemik dolaşımın yaklaşık %64'ünü barındıran kapasitans damarlardır. II yanlıştır: gap junction'lar (connexin 43) interkalar disklerin uç (terminal) yüzeyinde, desmosomlar ise yan yüzeyinde bulunur. III yanlıştır: Starling dengesinde onkotik basınç her iki uçta da reabsorbsiyonu destekler doğru olsa da klasik modelde arteriyel uçta filtrasyon baskın, venöz uçta reabsorpsiyon baskındır; cümle 'her iki uçta reabsorbsiyonu destekler' şeklinde kurulduğundan yanıltıcı biçimde yanlıştır. IV yanlıştır: baroreseptörler düz kas değil, adventisya ve medya arasındaki germeli sonlanmalar içeren özelleşmiş afferent sinir uçlarıdır."},{"id":8370,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Yoğun bakımda takip edilen 28 yaşında erkek hasta, aspire ettiği mide içeriği sonrasında ARDS tablosu geliştiriyor. Akciğer grafisinde bilateral infiltratlar saptanıyor, PaO2/FiO2 oranı 140 mmHg olarak hesaplanıyor. Bu hastada difüzyon bariyer hasarından birincil olarak sorumlu olan hücre tipi hangisidir?","options":["Endotel hücresi","Tip II pnömosit","Tip I pnömosit","Clara (Club) hücresi","Alveolar makrofaj"],"correct":2,"exp":"Alveolokapiller difüzyon bariyerinin %95'ini oluşturan Tip I pnömositler, gaz değişiminin gerçekleştiği ince yüzeyi sağlar. ARDS'de asit aspirasyonu ya da enflamasyon sonucu Tip I pnömositler nekroza uğrar; difüzyon mesafesi artar ve oksijen geçişi bozulur. Tip II pnömositler sürfaktan üretir, Tip I hücrelerin öncülüdür ve hasara karşı rejenerasyon başlatır. Bu nedenle ARDS'de difüzyon bariyer yıkımının birincil hedefi Tip I pnömositlerdir."},{"id":8371,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"65 yaşında erkek hasta, ani başlayan sağ taraf güçsüzlüğü ve konuşma bozukluğuyla acile getirileniyor. Görüntülemede sol orta serebral arter sulama alanında iskemik odak saptanıyor. Hasarın ilk 24 saatinde iskemik bölgede etkilenen akson miyelin kılıfını oluşturan hücre hangisidir?","options":["Oligodendrosit","Ependim hücresi","Fibröz astrositler","Schwann hücresi","Mikroglia"],"correct":0,"exp":"Santral sinir sisteminde miyelin kılıfı oligodendrositler tarafından oluşturulur; tek bir oligodendrosit birden fazla aksonu myelinize edebilir. Periferik sinir sisteminde bu görevi Schwann hücreleri üstlenir. İskemik hasarda ATP tükenmesiyle birlikte oligodendrositler özellikle glutamat eksitotoksisitesine karşı yüksek duyarlılık gösterir ve erken dönemde hasar görür, bu da demyelinizasyona yol açar. Mikroglia SSS'nin rezidan makrofajlarıdır; fibröz astrositler beyaz maddede iskelet işlevi görür; ependim hücreleri ventrikülleri döşer."},{"id":8372,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"Kemik iliği transplantasyonu planlanan 19 yaşında kadın hastada donör taraması yapılıyor. Aşağıdaki öncüller hematopoez ve kök hücre biyolojisi açısından değerlendirilmektedir:\nI. Uzun kemiklerin diyafizindeki sarı ilik, gerektiğinde kırmızı iliğe dönüşebilir.\nII. Pluripotent kök hücreler CD34 ve CD38 açısından çift pozitiftir.\nIII. Trombopoietin primer olarak karaciğer ve böbrekte sentezlenir.\nIV. Eritropoezde proeritroblast, bazofilik eritroblast, polikromatofilik eritroblast ve ortokromatik eritroblast sırasıyla nükleus kaybederek retikülosit oluşturur.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II ve IV","I, III ve IV","I ve IV","I ve III","Yalnız I"],"correct":3,"exp":"I doğrudur: sarı ilik yağ dokusundan oluşur; ağır anemi veya hipoksi gibi durumlarda aktif kırmızı iliğe dönüşebilir. II yanlıştır: pluripotent (uzun dönem) kök hücreler CD34+/CD38- fenotipindedir; CD38 pozitifliği daha olgun progenitörü gösterir. III doğrudur: trombopoietin başlıca karaciğer hepatositleri ve böbrek proksimal tübül hücreleri tarafından sentezlenir. IV yanlıştır: nükleus kaybı ortokromatik eritroblast aşamasında gerçekleşir, proeritroblastta değil; ayrıca sıralama doğru olmakla birlikte öncülde 'nükleus kaybederek' ifadesi her aşamaya atfedildiğinden kavramsal hata içerir."},{"id":8373,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla başvuruyor. Koroner anjiyografide sol ön inen arterde %85 darlık saptanıyor. Hasta perkütan koroner girişim için hazırlanırken yapılan ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30 olarak ölçülüyor. Hastaya kılavuz tedavisi başlanıyor. Aşağıdaki ilaçlardan hangisinin bu hastada kullanımı, renal perfüzyon basıncının kritik eşiğin altında olduğu bir durumda en ciddi böbrek hasarına yol açar?","options":["Beta bloker","ACE inhibitörü","Spironolakton","İvabradine","Digoksin"],"correct":1,"exp":"Düşük ejeksiyon fraksiyonlu kalp yetersizliğinde efferent arteriyol tonusu anjiyotensin II tarafından korunur. ACE inhibitörleri anjiyotensin II sentezini baskılayarak efferent arteriyol dilatasyonuna ve glomerüler filtrasyon basıncının düşmesine yol açar. Renal perfüzyon zaten kritik eşikte ise bu mekanizma akut böbrek hasarını tetikler. Beta blokerler, ivabradine ve digoksin kronik kalp yetersizliği tedavisinde semptomatik yarar sağlar ancak efferent arteriyol tonusu üzerine doğrudan etkisi yoktur. Spironolakton potasyum tutucu diüretik olup RAAS'ı farklı bir basamakta etkiler ve bu mekanizma üzerinden akut prerenal hasarı ACE inhibitörleri kadar kritik tetiklemez."},{"id":8374,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 20 yıldır sigara içiyor ve 6 aydır giderek artan eforla nefes darlığı tanımlıyor. Solunum fonksiyon testinde FEV1/FVC: 0,58, FEV1: %42 (beklenenin yüzdesi) saptanıyor. Arteriyel kan gazında pH: 7,38, PaCO2: 52 mmHg, PaO2: 55 mmHg, HCO3: 30 mEq/L bulunuyor. Bu hastaya uzun süreli oksijen tedavisi başlandığında beklenen en temel solunum fizyolojisi değişikliği hangisidir?","options":["Hipoksik ventilatuar yanıtın baskılanmasıyla PaCO2'nin akut olarak yükselmesi","Hipoksik vazokonstrüksiyonun azalmasıyla pulmoner vasküler direncin düşmesi ve sağ kalp yükünün hafiflemesi","Eritropoietin sentezinin azalmasıyla sekonder polisitemi bulgularının hızla gerilemesi","Alveoler-arteriyel oksijen gradiyentinin kapanarak diffüzyon kapasitesinin normale dönmesi","Oksihemoglobin disosiasyon eğrisinin sola kayarak doku oksijen sunumunun artması"],"correct":1,"exp":"İleri KOAH'ta kronik hiperkapni nedeniyle santral kemoreseptörler CO2'ye duyarsızlaşır ve solunum dürtüsünün önemli bir bölümü hipoksiye bağımlı hale gelir; bu nedenle yüksek akımlı O2 uygulaması PaCO2 artışına yol açabilir. Ancak sorulan 'en temel' solunum fizyolojisi değişikliği, kronik hipoksinin tetiklediği hipoksik pulmoner vazokonstrüksiyonun (Euler-Liljestrand refleksi) azalmasıdır. Bu durum pulmoner vasküler direnci düşürür, sağ ventrikül afterload'ını hafifletir ve kor pulmonale progresyonunu yavaşlatır. Bu, uzun süreli O2 tedavisinin mortaliteyi azaltmasının kanıtlanmış temel mekanizmasıdır. Hiperkapni akut değil, kronik bir bulgudur; oksihemoglobin eğrisi kronik hipoksik adaptasyonla zaten sağa kaymıştır. Polisitemi ve diffüzyon kapasitesi O2 tedavisiyle anlık normalize olmaz."},{"id":8375,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"35 yaşında kadın hasta, 2 haftadır sağ gözde çift görme ve sol bacakta güçsüzlük yakınmasıyla başvuruyor. Nörolojik muayenede internükleer oftalmopleji ve sol alt ekstremitede hiperrefleksi saptanıyor. MR'da periventriküler ve justakortikal beyaz cevher lezyonları görülüyor. Hastalığın kesin tanısı konulduktan sonra atak tedavisi için yüksek doz intravenöz metilprednizolon başlanıyor. Bu tedavinin, hastanın semptomlarını kısaltmadaki temel etkisinin histofizyolojik karşılığı aşağıdakilerden hangisidir?","options":["Oligodendrosit öncül hücrelerini aktive ederek demiyelinize aksonlarda remyelinizasyonu hızlandırması","Astrosit aktivasyonunu kalıcı olarak baskılayarak gliyozis oluşumunu önlemesi","Ranvier boğumlarındaki sodyum kanalı yoğunluğunu artırarak ileti hızını normale döndürmesi","Kan-beyin bariyerinin bütünlüğünü yeniden sağlayarak lezyon bölgesindeki iyon ve su birikimini azaltması","Miyelin bazik proteinine karşı oluşan antikorları nötralize ederek otoimmün yanıtı durdurmast"],"correct":3,"exp":"Multipl sklerozda akut atakta kan-beyin bariyeri bozulur; T lenfositler ve monosit infiltrasyonu, perivasküler ödem ve aktif demiyelinizasyon gelişir. Yüksek doz kortikosteroidler, endotelyal hücrelerdeki sıkı kavşakları stabilize ederek kan-beyin bariyerini onarır, lezyon bölgesindeki ödem ve iyon birikimini azaltır; bu, klinik semptomların hızla düzelmesini açıklar. Kortikosteroidler atak süresini kısaltır ancak uzun dönem hasarı ve özürlülük birikimini değiştirmez. Remyelinizasyon tedaviye değil spontan iyileşme kapasitesine bağlıdır; sodyum kanalı yeniden dağılımı kronik adaptif bir süreçtir. Gliyozis kronik evre bulgusudur, kortikosteroidler bunu kalıcı engellemez. Miyelin bazik proteinine spesifik antikor nötralizasyonu kortikosteroid mekanizması değildir."},{"id":8376,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 8 aydır adet düzensizliği, kilo alımı ve hirsutizm yakınmasıyla başvuruyor. Fizik muayenede aksiller bölge ve boyunda hiperpigmentasyon saptanıyor. Laboratuvarda açlık insülin düzeyi 28 mU/L, HOMA-IR: 6,8, testosteron yüksek, LH/FSH oranı: 3,2 bulunuyor. Ultrasonografide her iki overde periferik kistler görülüyor. Hastaya metformin başlanıyor. Aşağıdaki öncülleri inceleyin:\nI. Metformin, over teka hücrelerinde LH uyarımlı androjen sentezini doğrudan inhibe eder.\nII. İnsülin direncinin düzelmesi, insülinin over granüloza hücreleri üzerindeki IGF-1 benzeri etkisini azaltır ve östrojen/androjen dengesini düzeltmeye katkı sağlar.\nIII. Metforminin hipotalamo-hipofizer aks üzerindeki etkisiyle LH atım frekansı normalleşir ve bu durum LH/FSH oranının düzelmesine doğrudan katkı sağlar.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız II","I ve II","II ve III","I, II ve III","Yalnız III"],"correct":0,"exp":"Öncül I yanlıştır: Metforminin over teka hücrelerinde androjen sentezini doğrudan inhibe ettiğine dair kanıt yoktur; temel etkisi karaciğerde glukoneogenezi baskılamak ve periferik insülin duyarlılığını artırmaktır. Öncül II doğrudur: İnsülin direnci düzelince over granüloza hücreleri üzerindeki hiperinsulineminin IGF-1 benzeri (aromataz artışı, SHBG baskılanması) etkileri azalır; SHBG düzeyi yükselir, biyoyararlanabilir androjen düşer. Öncül III yanlıştır: Metforminin LH atım frekansını hipotalamo-hipofizer aks üzerinden doğrudan düzelttiğine dair kanıtlanmış bir etki mekanizması bulunmamaktadır; LH/FSH oranındaki iyileşme daha çok androjen azalmasına ve kilo kaybına sekonder olarak gelişir."},{"id":8377,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"24 yaşında kadın hasta, yorgunluk ve egzersiz toleransında azalma yakınmasıyla başvuruyor. Laboratuvar sonuçlarında Hgb: 8,2 g/dL, MCV: 68 fL, MCH düşük, serum ferritin: 4 ng/mL, transferrin saturasyonu: %8 saptanıyor. Periferik yaymasında hipokromik mikrositik eritrositler görülüyor. Oral demir tedavisi başlanan hastada tedavinin etkinliğini değerlendirmek için 10. günde bakılacak en erken ve en özgül laboratuvar göstergesi hangisidir?","options":["Serum transferrin reseptörü düzeyi","Serum ferritin düzeyi","Hemoglobin konsantrasyonu","Ortalama eritrosit hacmi (MCV)","Retikülosit sayısı"],"correct":4,"exp":"Demir tedavisine yanıt önce kemik iliğinde eritroid hiperplazi ile başlar; tedavinin 5-10. günlerinde periferik kanda retikülosit sayısı belirgin biçimde yükselir (retikülosit krizi). Bu yanıt, demir depolarının yenilenmesinden çok önce ve hemoglobin artışından (2-4 hafta) önce görülür. Serum ferritin depo demirini yansıtır ve haftalar-aylar içinde değişir. Hemoglobin düzeyi 4-8 haftada normalleşir. Transferrin reseptörü ve MCV ise daha geç dönem değişkenlerdir. Bu nedenle 10. günde tedavi etkinliğinin erken ve özgül göstergesi retikülosit sayısıdır."},{"id":8378,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbrek tübülüs fizyolojisiyle ilgili aşağıdaki öncülleri inceleyin:\nI. Proksimal tübülde glukoz reabsorpsiyonu, lüminal membranda sodyumla birlikte sekonder aktif taşıma (SGLT2) ile gerçekleşir.\nII. Henle kulpunun ince inen kolunda su geçirgenliği yüksek, sodyum geçirgenliği düşüktür.\nIII. Toplayıcı kanalda ADH varlığında aquaporin-2 kanalları apikal membrana yerleşerek su reabsorpsiyonunu artırır.\nYukarıdaki öncüllerin kaç tanesi doğrudur?","options":["Bir","Hiçbiri","Üç","Yalnız I ve III","İki"],"correct":2,"exp":"Öncül I doğrudur: Proksimal tübülün lüminal (apikal) membranında SGLT2 taşıyıcıları Na+ ile birlikte glukozı sekonder aktif olarak (Na+ gradiyentini kullanan) hücre içine taşır. Öncül II doğrudur: Henle kulpunun ince inen kolu yüksek su geçirgenliğine sahipken solütlere (özellikle sodyuma) oldukça az geçirgendir; bu özellik renal konsantrasyon mekanizmasının temelini oluşturur. Öncül III doğrudur: ADH (vazopressin) toplayıcı kanal epitel hücrelerinde V2 reseptörlerine bağlanır, cAMP yolunu aktive eder ve sitoplazmik veziküllerden aquaporin-2 kanallarının apikal membrana yerleşmesini sağlar; bu mekanizma su reabsorpsiyonunu artırır. Her üç öncül de doğru olduğundan yanıt 'Üç'tür."},{"id":8379,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor ile gelen göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Koroner anjiyografide sol ön inen arterde %80 darlık saptanıyor. Hastaya perkütan koroner girişim planlanıyor ve öncesinde ivabradin başlanıyor. Bu ilacın etkisiyle aşağıdakilerden hangisi beklenir?","options":["AV düğüm iletiminin yavaşlaması sonucu PR aralığının uzaması","Periferik vasküler dirençte artış yoluyla afterload azalması","Ventriküler diyastolik relaksasyon süresinin kısalması","Sinoatriyal düğümde funny akım inhibisyonu sonucu kalp hızında azalma","Miyokard kontraktilitesinde azalma"],"correct":3,"exp":"İvabradin, sinoatriyal düğümdeki HCN kanallarını (If - funny current) seçici olarak inhibe eder. Bu kanal, diyastol sırasında spontan depolarizasyonu sağlayan Na+/K+ mixed akımını taşır. İnhibisyon sonucunda spontan depolarizasyon yavaşlar ve kalp hızı düşer; kontraktilite ve AV iletim etkilenmez. Koroner hastalıkta kalp hızı azalması miyokardiyal oksijen tüketimini düşürürken diyastol süresini uzatarak koroner perfüzyonu artırır."},{"id":8380,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, dört haftadır süren progresif nefes darlığı ve kuru öksürük yakınmasıyla başvuruyor. Yüksek rezolüsyonlu BT'de bilateral buzlu cam opasiteleri ve interstisyel fibrozis bulguları saptanıyor. Solunum fonksiyon testinde FVC: %58 (beklenenin), FEV1/FVC: 0,89 olarak ölçülüyor. Alveolokapiller membranda yaşanan patolojik süreç değerlendirildiğinde bu hastada diffüzyon kapasitesini (DLCO) en çok etkileyen faktör hangisidir?","options":["Sürfaktan eksikliğine bağlı yüzey geriliminin artması","Alveolokapiller membran kalınlığının artması ve etkin yüzey alanının azalması","Fonksiyonel rezidüel kapasitenin azalması","Havayolu rezistansındaki artış","Pulmoner vasküler direncin düşmesine bağlı kapiller transit süresinin uzaması"],"correct":1,"exp":"Diffüzyon kapasitesi (DLCO), Fick yasasına göre membran yüzey alanı ile doğru, kalınlık ile ters orantılıdır. İnterstisyel fibroziste alveolokapiller membranda kollajen birikimi hem membranı kalınlaştırır hem de fibrotik alanların fonksiyonel gaz değişimi yapamaması nedeniyle etkin yüzey alanını azaltır. Bu iki etki birlikte DLCO'yu ciddi biçimde düşürür. Restriktif paternde (FEV1/FVC normal veya yüksek, FVC düşük) havayolu rezistansı ön planda değildir; sürfaktan eksikliği ise farklı bir klinik tablodur."},{"id":8381,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, tip 2 diyabet ve hipertansiyon tanılarıyla takip edilmektedir. Son kontrol laboratuvar sonuçlarında idrar albumin/kreatinin oranı 380 mg/g, eGFR 42 mL/dk/1,73 m², serum potasyum 5,1 mEq/L saptanıyor. Hastanın mevcut tedavisine SGLT-2 inhibitörü ekleniyor. Bu ilacın böbrek düzeyindeki etkisine ilişkin aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Proksimal tübülde Na+-glukoz ko-transportunu inhibe ederek glukozu tübüler geri emilimden uzaklaştırır.\nII. Tübüloglomerüler feedback mekanizması üzerinden afferent arteriyolde vazokonstriksiyon yaparak intraglomerüler basıncı düşürür.\nIII. Distal nefrondan sodyum atılımını azaltarak hiperkalemiye zemin hazırlar.\nIV. Proksimal tübülde Na+ reabsorpsiyonu azaldığından, maküla densaya ulaşan NaCl miktarı artar ve adenozin aracılı afferent vazokonstriksiyon tetiklenir.","options":["Yalnız 1 tanesi","2 tanesi","4 tanesi","3 tanesi","Hiçbiri doğru değil"],"correct":3,"exp":"Öncül I doğru: SGLT-2 inhibitörleri proksimal tübülde SGLT-2 kanalını bloke ederek glukoz ve Na+ geri emilimini önler. Öncül II doğru: Proksimal tübülden azalan Na+ reabsorpsiyonu maküla densaya daha fazla NaCl ulaştırır; bu, tübüloglomerüler feedback aracılığıyla afferent arteriyolde adenozin yoluyla vazokonstriksiyon yaratarak intraglomerüler hipertansiyonu düzeltir. Öncül III yanlış: SGLT-2 inhibitörleri proksimal tübülde etki eder ve distal nefron Na+ atılımını azaltmaz; aksine hafif natriürez vardır ve hiperkalemi riski minimal ya da diüretik etkiyle azalır. Öncül IV doğru: I ve II'nin mekanistik açıklamasını tamamlar; maküla densa NaCl algısı TGF'yi tetikler. Dolayısıyla I, II ve IV doğru: 3 tanesi."},{"id":8382,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Laboratuvar ortamında bir sinir lifinde aksiyon potansiyeli oluşturulduktan hemen sonra, eşiğin çok üzerinde bir uyaran uygulanmasına rağmen yeni bir aksiyon potansiyeli oluşturulamıyor. Bu durumu açıklayan fizyolojik kavram ve altta yatan iyon kanalı değişikliği hangisidir?","options":["Relatif refrakter dönem; voltaj kapılı Na+ kanallarının aktivasyon kapılarının henüz kapanmamış olması","Relatif refrakter dönem; voltaj kapılı K+ kanallarının aktivasyonu","Akkomodasyon; yavaş sodyum kanallarının kümülatif inaktivasyonu","Mutlak refrakter dönem; voltaj kapılı Na+ kanallarının inaktivasyon kapılarının kapalı olması","Hiperpolarizasyon sonrası iz potansiyeli; Na+/K+ ATPaz aktivitesinin geçici artışı"],"correct":3,"exp":"Aksiyon potansiyelinin tepe noktasından hemen sonraki mutlak refrakter dönemde voltaj kapılı Na+ kanallarının inaktivasyon kapıları (h kapısı) kapalıdır. Bu durum kanalları, aktivasyon kapısı (m kapısı) açık olsa bile Na+ geçişine izin vermez kılar. İstirahat membran potansiyeline dönüş gerçekleşip kanallar tekrar istirahat durumuna gelmedikçe hiçbir uyaran yeni aksiyon potansiyeli oluşturamazçünkü kanallar depolarizasyona yanıt veremez haldedir. Relatif refrakter dönemde ise kanalların bir kısmı recover olmuştur; eşik üstü uyaran aksiyon potansiyeli tetikleyebilir."},{"id":8383,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, yorgunluk ve kolay morarma yakınmasıyla başvuruyor. Tam kan sayımında hemoglobin 8,4 g/dL, trombosit 22.000/µL, lökosit 2.100/µL saptanıyor. Kemik iliği biyopsisinde hiposellüler (%10 sellülarite) ve yağ dokusuyla dolu alanlar izleniyor. Aplastik anemi tanısı konulan hastaya antitimosit globulin (ATG) ve siklosporin tedavisi başlanıyor. Bu tedavinin aplastik anemideki etki hedefi aşağıdaki öncüllerle değerlendirilmiştir:\nI. ATG ve siklosporin, hematopoetik kök hücreleri proliferasyona doğrudan uyararak kemik iliği sellülaritesini artırır.\nII. Aplastik aneminin büyük çoğunluğunda altta yatan mekanizma, T lenfositlerinin hematopoetik kök hücrelere yönelik otoimmün saldırısıdır.\nIII. Siklosporin, kalsinörin inhibisyonu yoluyla IL-2 sentezini baskılar ve T hücre proliferasyonunu önler.\nIV. ATG uygulaması sonrası serum hastalığı gelişmesi beklenen bir komplikasyon değildir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","II, III ve IV","II ve III","I, II ve III","Yalnız II"],"correct":2,"exp":"Öncül I yanlış: ATG ve siklosporin kök hücreleri doğrudan uyarmaz; T lenfositlerini hedef alır. Öncül II doğru: İdiyopatik aplastik aneminin büyük çoğunluğu otoimmün kökenlidir; sitotoksik T hücreleri IFN-γ ve TNF-α salgılayarak kök hücre apoptozunu tetikler. Öncül III doğru: Siklosporin, kalsinörin-NFAT yolağını bloke ederek IL-2 gen transkripsiyonunu önler ve T hücre klonal genişlemesini durdurur. Öncül IV yanlış: ATG yabancı protein içerdiğinden %50-75 oranında serum hastalığı (tip III hipersensitivite) beklenen bir komplikasyondur ve profilaktik steroid verilir. Dolayısıyla II ve III doğrudur."},{"id":8384,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Mide fundusundaki oksintik bezlerde bulunan ve proton pompası (H+/K+-ATPaz) aracılığıyla HCl salgılayan hücre tipi hangisidir?","options":["D hücresi","G hücresi","Müköz boyun hücresi","Baş hücresi (chief cell)","Parietal hücre (oksintik hücre)"],"correct":4,"exp":"Parietal hücreler (oksintik hücreler), mide fundus ve korpusundaki oksintik bezlerde bulunur ve H+/K+-ATPaz (proton pompası) aracılığıyla lumene H+ pompalayarak HCl üretir. Aynı zamanda intrinsik faktörü de salgılarlar. Baş hücreleri pepsinojen, G hücreleri gastrin, D hücreleri somatostatin, müköz boyun hücreleri ise asit ortama dayanıklı mukus salgılar."},{"id":8385,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı şikayetiyle kardiyoloji polikliniğine başvuruyor. Özgeçmişinde 10 yıldır hipertansiyon ve tip 2 diyabetes mellitus tanıları mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor, diastolik disfonksiyon saptanıyor. Tedavisine ACE inhibitörü ekleniyor. Bu ilacın hemodinamik etkilerine ilişkin aşağıdaki öncülleri değerlendiriniz:\nI. Arteriyel vazodilatasyon sonucu afterload azalır.\nII. Venöz kapasitans artışı ile preload azalır.\nIII. Aldosteron baskılanması nedeniyle volüm yüklenmesi hafifler.\nIV. Renin salınımı refleks olarak kalıcı biçimde baskılanır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["2","3","4","1","Hiçbiri"],"correct":1,"exp":"ACE inhibitörleri anjiyotensin II oluşumunu engelleyerek hem arteriyel hem venöz dilatasyon sağlar; bu nedenle hem afterload (öncül I) hem de preload (öncül II) azalır. Aldosteron sentezi anjiyotensin II'ye bağlı olduğundan baskılanır ve sodyum-su atılımı artar, volüm yüklenmesi hafifler (öncül III). Öncül IV ise yanlıştır: ACE inhibitörleri anjiyotensin II'nin renin salınımı üzerindeki negatif geri bildirimini kaldırır, dolayısıyla plazma renin aktivitesi artar, baskılanmaz. Doğru öncüller I, II ve III olmak üzere toplam 3 tanesidir."},{"id":8386,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 2 haftadır süren progresif efor dispnesi, kuru öksürük ve düşük dereceli ateş yakınmasıyla başvuruyor. Bilinen kronik hastalığı yok; ancak 4 ay önce kemoterapi aldığını belirtiyor. Arteriyel kan gazı analizinde PaO2: 58 mmHg, PaCO2: 30 mmHg, pH: 7,48 saptanıyor. Toraks BT'de bilateral buzlu cam görünümü izleniyor. Bronkoalveoler lavaj örneğinde Pneumocystis jirovecii tespit ediliyor. Bu hastada hipokseminin temel fizyopatolojik mekanizmasını en doğru yansıtan seçenek hangisidir?","options":["Yüksek irtifa","Arteriyovenöz fistül","Diffüzyon bozukluğu","Sağdan sola şant","Hipoventilasyon"],"correct":2,"exp":"Pneumocystis jirovecii pnömonisi (PCP), özellikle alveol duvarında interstisyel kalınlaşmaya ve alveol içinde köpüksü eksüda birikimine yol açar. Bu tablo, oksijen gibi difüzyon katsayısı düşük gazların alveolden kapillere geçişini engeller ve 'diffüzyon bozukluğu' ile hipoksemiye neden olur. Karakteristik bulgu: egzersizle hipokseminin belirginleşmesi ve PaCO2'nin düşük olmasıdır (hiperventilasyon kompansasyonu). Hipoventilasyonda PaCO2 yükselir; tam sağdan sola şantta oksijen tedavisine yanıt alınmaz; bu olguda ise oksijen verilmesiyle oksijen satürasyonu yükselir, bu da şantı dışlar."},{"id":8387,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, ani başlayan şiddetli baş ağrısı ve bilinç bulanıklığı nedeniyle acile getiriliyor. Özgeçmişinde özellik yok. Nörolojik muayenede ense sertliği ve ışık refleksi alınamayan bilateral midriyazis saptanıyor. Beyin BT'de subaraknoid kanama ile uyumlu görünüm mevcut. Hastada kan-beyin bariyerinin (KBB) bütünlüğü bozulduğunda aşağıdaki öncüllerden hangileri beklenir?\nI. Normalde KBB'yi oluşturan endotel hücreler arasındaki sıkı bağlantılar (tight junction) gevşer.\nII. Beyin interstisyumuna albumin geçişi artar ve vazojenik ödem gelişir.\nIII. Astrosit ayak uzantıları KBB hasarının birincil nedenidir.\nIV. İyonize ilaçlar sağlam KBB'den normalde serbestçe geçemez.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, II ve IV","I ve II","II, III ve IV","Yalnız IV","I, II ve III"],"correct":0,"exp":"KBB, beyin kapillerindeki endotel hücreleri arasındaki sıkı bağlantılar (tight junction), perisitler ve astrosit ayak uzantılarından oluşur. Öncül I doğrudur: KBB hasarında tight junction'lar gevşer. Öncül II doğrudur: protein geçişi artar, ozmotik denge bozulur ve vazojenik ödem oluşur. Öncül III yanlıştır: KBB hasarının birincil nedeni endotelyal sıkı bağlantıların bozulmasıdır; astrosit ayak uzantıları bariyer bütünlüğünü destekler ancak hasar başlatıcısı değildir. Öncül IV doğrudur: iyonize, büyük moleküllü ya da suda çözünür maddeler sağlam KBB'yi geçemez; lipofilik, küçük moleküller geçebilir. Doğru öncüller I, II ve IV'tür."},{"id":8388,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbreğin proksimal tübülüsünde gerçekleşen sodyum geri emilimi için hangisi doğrudur?","options":["Na⁺/K⁺-ATPaz, apikal membranda konumlanarak aktif taşımayı gerçekleştirir.","Proksimal tübülüste geri emilen sodyum miktarı toplam filtrasyonun yaklaşık %15'ini oluşturur.","Antidiüretik hormon, proksimal tübülüste sodyum geri emilimini doğrudan artırır.","Bazolateral membranda Na⁺/K⁺-ATPaz, sodyumu hücre içine pompalayarak lümen-hücre gradyanını oluşturur.","Sodyum, apikal membrandan pasif difüzyonla lümene geçer."],"correct":3,"exp":"Proksimal tübülüste sodyum geri emilimi iki aşamalıdır: (1) Apikal membranda Na⁺, lümenden hücre içine, Na⁺/H⁺ değiştirici (NHE3) ve çeşitli kotransporterlar (SGLT, Na⁺/amino asit) aracılığıyla sekonder aktif transport ile girer; bu pasif değil, elektrokimyasal gradyana bağlı aktif bir süreçtir. (2) Bazolateral membranda Na⁺/K⁺-ATPaz, sodyumu hücre dışına (intersitisyuma) pompalar, hücre içi Na⁺ konsantrasyonu düşük tutularak lümen-hücre gradyanı korunur. Doğru seçenek budur. Proksimal tübülüste filtrelenen sodyumun yaklaşık %65-70'i geri emilir (%15 değil). ADH, proksimal tübülüste değil, toplayıcı kanallarda su geçirgenliğini düzenler. Na⁺/K⁺-ATPaz bazolateraldedir, apikal değil."},{"id":8389,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"34 yaşında kadın hasta, yorgunluk, eklem ağrıları ve tekrarlayan enfeksiyonlar nedeniyle hematoloji polikliniğine başvuruyor. Laboratuvar incelemesinde hemoglobin: 8,2 g/dL, lökosit: 2.400/mm³, trombosit: 68.000/mm³ saptanıyor. Periferik yayma incelemesinde eritrositler normokrom normositerdir. Kemik iliği biyopsisinde hücresellik belirgin azalmıştır. Bu tabloya yol açan fizyopatolojik süreçte aşağıdaki öncüllerden hangileri beklenir?\nI. Pluripotent hematopoetik kök hücre sayısı azalmıştır.\nII. Kemik iliğinde yağ dokusu oranı artmıştır.\nIII. Eritropoietin düzeyi düşük saptanır.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız III","Yalnız I","I, II ve III","II ve III","I ve II"],"correct":4,"exp":"Bu tablo aplastik anemi ile uyumludur: pansitopeni ve hiposellüler kemik iliği bulguları tanıyı desteklemektedir. Öncül I doğrudur: aplastik anemide otoimmün veya toksik hasar sonucu pluripotent kök hücreler azalır ya da yok olur. Öncül II doğrudur: hematopoetik hücrelerin yerini yağ hücreleri alır, kemik iliği biyopsisinde yağ dokusu oranı artar (>%75). Öncül III yanlıştır: anemi nedeniyle doku hipoksisi geliştiğinden eritropoietin düzeyi reaktif olarak yükselir, düşmez. Aplastik anemide eritropoietin yüksek olmasına karşın kemik iliği bu uyarıya yanıt veremez."},{"id":8390,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, 6 aydır süren steatore, kilo kaybı ve karın ağrısı şikayetiyle gastroenteroloji polikliniğine başvuruyor. Özgeçmişinde uzun yıllar süren alkol kullanımı mevcut. Dışkıda yağ miktarı artmış, serum lipaz ve amilaz düzeyleri normalin üzerinde saptanmaktadır. Batın BT'de pankreas kanalında dilatasyon ve parankim kalsifikasyonları izleniyor. Bu hastada yağda çözünen vitaminlerin emiliminin bozulmasının temel nedeni aşağıdakilerden hangisidir?","options":["İnce barsak villus atrofisi nedeniyle emilim yüzeyinin azalması","Mide asit sekresyonunun baskılanması nedeniyle lipazın inaktivasyonu","Terminal ileum hasarına bağlı safra asitlerinin enterohepatik döngüsünün bozulması","Pankreas lipazının yetersiz salgılanması nedeniyle trigliseritlerin misel oluşturamaması","Karaciğer yetersizliği sonucu safra asidi sentezinin durması"],"correct":3,"exp":"Kronik pankreatit olgusunda egzokrin pankreas fonksiyonu bozulur ve pankreas lipazı yetersiz salgılanır. Lipaz, diyetle alınan trigliseritleri digliserid ve yağ asitlerine parçalamak için zorunludur. Bu hidroliz gerçekleşmeden, yağ asitleri ve monogliseritler safra asitleri ile birleşerek misel oluşturamaz. Misel oluşmadan yağda çözünen vitaminler (A, D, E, K) de dahil olmak üzere lipidler enterosite geçemez ve emilim bozulur. Villus atrofisi çölyak hastalığı gibi durumlarda söz konusudur. Safra asidi sentezi karaciğere bağlıdır ve bu olguda karaciğer yetmezliğine dair bulgu yoktur. Mide asidi lipazı inaktive etmez; aksine, pankreas bikarbonatı duodenumda pH'ı nötralize ederek lipazın optimal çalışma koşulunu sağlar."},{"id":8391,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor dispnesi ve bacaklarda ödem yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya başlanan sakubitril/valsartan tedavisinin etki mekanizması değerlendirildiğinde aşağıdaki öncüllerden hangileri doğrudur?\nI. Nöropeptidaz inhibisyonu ile natriüretik peptid düzeyleri yükselir.\nII. Renin-anjiyotensin sisteminin blokajı ile afterload azalır.\nIII. Aldosteron artışı sonucu sodyum retansiyonu baskılanır.\nIV. cGMP aracılı vazodilatasyon ve natriürezis artışı sağlanır.","options":["I, II ve IV","I, II, III ve IV","II, III ve IV","Yalnız I","I ve II"],"correct":0,"exp":"Sakubitril/valsartan kombinasyonunda sakubitril, nötral endopeptidaz (neprilizin) enzimini inhibe ederek ANP, BNP ve CNP gibi natriüretik peptidlerin yıkımını önler; böylece cGMP yolu üzerinden vazodilatasyon ve natriürezis artar (Öncül I ve IV doğru). Valsartan ise AT1 reseptörünü bloke ederek anjiyotensin II'nin vazokonstriksiyon ve aldosteron salınımını uyarma etkisini engeller, bu sayede afterload düşer (Öncül II doğru). Ancak aldosteron valsartan ile baskılandığından sodyum retansiyonu azalır; Öncül III'te 'aldosteron artışı sonucu sodyum retansiyonu baskılanır' ifadesi mekanizmayı yanlış tanımlamaktadır, doğrusu aldosteron azalması ile retansiyon azalır. Dolayısıyla I, II ve IV doğrudur."},{"id":8392,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, ani başlayan nefes darlığı ve plöritik göğüs ağrısı nedeniyle acil servise getiriliyor. Öyküde 6 haftadır oral kontraseptif kullandığı öğreniliyor. Arter kan gazında pH: 7.48, PaCO2: 30 mmHg, PaO2: 58 mmHg, A-a gradyanı artmış olarak saptanıyor. Hastada V/Q uyumsuzluğunu kompanse etmek amacıyla başlayan lokal pulmoner yanıt aşağıdakilerden hangisidir?","options":["Surfaktan sentezinde artış","Hipoksik bronkodilatasyon","Kollateral ventilasyon artışı","Hipoksik pulmoner vazokonstriksiyon","Alveoler makrofaj aktivasyonu"],"correct":3,"exp":"Pulmoner embolide tıkanan damara ait bölgede ventilasyon korunurken perfüzyon ortadan kalkar; bu durum yüksek V/Q bölgeleri oluşturur. Bununla birlikte embolinin yol açtığı lokal hipoksi ve hipokapni, etkilenmeyen komşu bölgelerde refleks hipoksik pulmoner vazokonstriksiyonu (HPV) tetikler. HPV, akciğerdeki temel otoregülatuar yanıttır: hipoksi, pulmoner arteriyollerde düz kas hücrelerini doğrudan depolarize ederek bu bölgelere kan akımını kısıtlar ve kanı daha iyi ventile edilen alveollere yönlendirir; böylece V/Q uyumsuzluğu minimize edilmeye çalışılır. Sistemik dolaşımın aksine pulmoner dolaşımda hipoksi vazodilatasyon değil, vazokonstriksiyon yanıtı üretir."},{"id":8393,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında erkek hasta, 3 yıldır tip 2 diyabetes mellitus tanısıyla metformin kullanmaktadır. Rutin kontrolünde idrarda albumin/kreatinin oranı 280 mg/g olarak saptanıyor; GFR 58 mL/dk/1.73 m² olarak hesaplanıyor. Hastaya SGLT2 inhibitörü eklenmesinin böbrek üzerine olan hemodinamik etkisi aşağıdakilerden hangisidir?","options":["Afferent arteriyol konstriksiyonu ile glomerüler filtrasyon basıncının azaltılması","Proksimal tübülde Na-K-ATPaz aktivitesinin artırılmasıyla tübüler geri emilimin hızlandırılması","Tubuloglomerüler geri bildirim aracılığıyla afferent arteriyol dilatasyonunun uyarılması","Mezangiyel hücre kontraksiyonunun artırılarak filtrasyon yüzeyinin daraltılması","Efferent arteriyol dilatasyonu ile glomerüler hidrostatik basıncın düşürülmesi"],"correct":0,"exp":"SGLT2 inhibitörleri proksimal tübülde sodyum-glukoz kotransportunu bloke eder; bu durum distale ulaşan Na+ miktarını artırır. Macula densa, artan tübüler NaCl yükünü algılayarak tubuloglomerüler geri bildirim (TGF) mekanizmasını aktive eder ve afferent arteriyolde adenozin aracılı konstriksiyon gelişir. Afferent arteriyolün daralması glomerüler hidrostatik basıncı (ve dolayısıyla GFR'yi) düşürür; böylece kronik hiperfiltrasyon kaynaklı glomerüler hasar azaltılır. Bu mekanizma, SGLT2 inhibitörlerinin diyabetik nefropati üzerine koruyucu etkisinin temel hemodinamik açıklamasıdır."},{"id":8394,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir nöronda aksiyon potansiyeli oluşumu değerlendirildiğinde aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Eşik potansiyeline ulaşıldığında voltaj kapılı Na+ kanalları hızla açılır.\nII. Repolarizasyon fazında K+ kanalları kapanırken Na+ kanalları inaktif konumdadır.\nIII. Hiperpolarizasyon fazında membran potansiyeli dinlenim potansiyelinin altına iner.\nIV. Mutlak refrakter dönemde uyaran şiddeti ne kadar artırılırsa artırılsın yeni aksiyon potansiyeli oluşturulamaz.","options":["1","3","Hiçbiri","4","2"],"correct":1,"exp":"Öncül I doğrudur: eşik potansiyeline (-55 mV civarı) ulaşıldığında voltaj kapılı Na+ kanalları pozitif geri beslemeyle (Hodgkin döngüsü) hızla açılır. Öncül II doğrudur: repolarizasyon sırasında K+ kanalları geç açılıp Na+ kanalları inaktivasyona uğrar, bu iki süreç eş zamanlı olarak membranı negatife çeker. Öncül III doğrudur: K+ kanallarının geç kapanması nedeniyle membran potansiyeli kısa süreliğine dinlenim değerinin altına iner (afterhiperpolarizasyon). Öncül IV doğrudur: mutlak refrakter dönemde Na+ kanalları inaktif konumdadır ve hiçbir uyaran yeni aksiyon potansiyeli oluşturamaz. Dört öncülün tamamı doğrudur."},{"id":8395,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Aşağıdaki safra bileşenlerinden hangisi, safranın bağırsakta yağ emilimini kolaylaştırdığı mekanizma açısından diğerlerinden farklı bir işlev üstlenir?","options":["Lesitin","Taurokolat","Deoksikolat","Glikokolat","Kolesterol"],"correct":4,"exp":"Safra tuzları (glikokolat, taurokolat, deoksikolat) ve lesitin (fosfatidilkolin), amfipatik yapıları sayesinde yağ damlacıklarını emülsifiye eder ve misel oluşumuna katılarak yağ asitleri ile yağda çözünen vitaminlerin enterosit yüzeyine taşınmasını sağlar; hepsi aktif emülsifikasyon/misel işlevini paylaşır. Kolesterol ise safranın bir atık/metabolik son ürünüdür; emülsifikasyon sürecine katkıda bulunmaz, aksine miktarı arttığında miksel dengeyi bozarak safra taşı oluşumuna yatkınlık yaratır. Dolayısıyla yağ emilimini kolaylaştırma açısından kolesterol diğerlerinden işlevsel olarak ayrılır."},{"id":8396,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 aydır süren yorgunluk, solukluk ve egzersiz intoleransı yakınmalarıyla başvuruyor. Tam kan sayımında Hb: 7.2 g/dL, MCV: 118 fL, lökosit ve trombosit normal sınırlarda saptanıyor. Periferik yaymada hipersegmente nötrofiller ve oval makrositler görülüyor. Hastanın B12 düzeyi normal, folik asit düzeyi düşük olarak ölçülüyor. Bu hastada folik asit eksikliğine bağlı megaloblastik anemi gelişiminde rol oynayan temel mekanizmanın en doğru yansıması aşağıdakilerden hangisidir?","options":["Globin zincir sentezinin dengesizleşmesi sonucu eritrosit membran hasarı","Demir kullanım bozukluğuna bağlı hem sentez yetersizliği","Vitamin B12 bağımlı metiyonin sentaz aktivite kaybı ile homosistein birikimi","Eritropoetin reseptör duyarsızlığı nedeniyle eritroid prekürsörlerin olgunlaşamaması","5,10-metilentetrahidrofolat azlığı nedeniyle timidilat sentezinin bozulması ve DNA replikasyonunun yavaşlaması"],"correct":4,"exp":"Folik asit, tetrahidrofolat (THF) türevleri aracılığıyla tek karbon transferi reaksiyonlarına katılır. En kritik adım, 5,10-metilenTHF'nin timidilat sentaz enzimi için metil grubu donörü olarak kullanılarak deoksiüridilat'tan (dUMP) timidilat'ın (dTMP) sentezlenmesidir. Folik asit eksikliğinde bu adım bozulur; timidilat kıtlığı nedeniyle DNA sentezi yavaşlar, RNA sentezi ise devam ettiğinden hücre büyümesi sürer. Sonuç olarak hücre bölünmesi geriden gelir ve megaloblastik değişiklikler ortaya çıkar. Seçenek E B12 eksikliğinin mekanizmasını tanımlar; B12 bağımlı metiyonin sentaz folik asit döngüsünü etkiliyor olsa da burada B12 normal saptanmıştır ve soru doğrudan folik asit eksikliğinin mekanizmasını sorgulamaktadır."},{"id":8397,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve çabuk yorulma yakınmasıyla kardiyoloji polikliniğine başvuruyor. Ekokardiyografide aort kapak alanı 0,7 cm², ortalama gradient 55 mmHg olarak saptanıyor. Hasta semptomatik ciddi aort stenozu tanısıyla aort kapak replasmanı planlanıyor. Postoperatif dönemde ventrikül duvar gerilimini (wall stress) azaltmak için kalp hızı ve afterload yönetimi yapılıyor. Laplace yasasına göre aşağıdaki değişkenlerden hangisinin artması sol ventrikül duvar gerilimini DOĞRUDAN azaltır?","options":["Ventrikül yarıçapının artması","Ventrikül duvar kalınlığının artması","İntraventriküler basıncın artması","Kalp hızının artması","Diyastol sonu hacmin artması"],"correct":1,"exp":"Laplace yasasına göre duvar gerilimi (T) = (P × r) / (2h) formülüyle ifade edilir; burada P intraventriküler basınç, r yarıçap, h duvar kalınlığıdır. Duvar kalınlığı (h) arttıkça duvar gerilimi azalır. Aort stenozu gibi kronik basınç yükü durumlarında konsantrik hipertrofi gelişir; ventrikül duvarı kalınlaşarak artan sistol içi basıncı normalize etmeye çalışır. Yarıçap artışı ve intraventriküler basınç artışı duvar gerilimini artırır. Kalp hızı duvar gerilimini doğrudan belirlememektedir."},{"id":8398,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 6 aydır süren progresif nefes darlığı, çomak parmak ve siyanoz yakınmalarıyla göğüs hastalıkları polikliniğine başvuruyor. Yüksek çözünürlüklü bilgisayarlı tomografide bilateral buzlu cam görünümü ve ağ benzeri fibrozis alanları izleniyor. Solunum fonksiyon testlerinde FVC: %52, FEV1: %55, FEV1/FVC: %88 saptanıyor. Diffüzyon kapasitesi (DLCO) belirgin şekilde azalmış. Pulmoner hipertansiyon eşlik ediyor. Bu hastanın solunum fizyolojisiyle ilgili aşağıdaki öncülleri değerlendirin:\nI. Alveolokapiller membran kalınlaşması diffüzyon kapasitesini azaltır.\nII. Akciğer kompliyansı artmıştır.\nIII. Ventilasyon-perfüzyon uyumsuzluğu hipoksemiye katkıda bulunur.\nIV. Total akciğer kapasitesi azalmıştır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["4","2","3","1","Hiçbiri"],"correct":2,"exp":"İdiyopatik pulmoner fibrozis (IPF) gibi restriktif akciğer hastalıklarında alveolokapiller membran fibrotik kalınlaşmasıyla DLCO azalır (Öncül I doğru). Fibrozis nedeniyle akciğer daha sert hale gelir, bu nedenle kompliyans AZALIR, arttığı ifadesi yanlıştır (Öncül II yanlış). Fibrotik bölgelerde ventile olmayan ancak perfüze olan alanlar V/Q uyumsuzluğu yaratarak hipoksemiye katkıda bulunur (Öncül III doğru). Restriktif paternde TLC belirgin biçimde azalmaktadır (Öncül IV doğru). Doğru öncüller I, III ve IV olup toplam 3 tanesi doğrudur."},{"id":8399,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 3 haftadır süren halsizlik, bacaklarda şişlik ve sabahları belirginleşen göz kapağı ödemi yakınmalarıyla nefroloji polikliniğine başvuruyor. İdrar tetkikinde proteinüri 7,2 g/gün, mikroskobide yağ damlacığı içeren oval yağ cisimcikleri görülüyor. Serum albümini 1,8 g/dL, total kolesterol 380 mg/dL. Böbrek biyopsisinde podosit efasman (ayaksı çıkıntı fusion) saptanıyor. Bu hastaya standart doz kortikosteroid tedavisi başlanıyor. Tedaviye yanıt olarak proteinürinin azalmasının temel mekanizmasıyla uyumlu aşağıdaki ifade hangisidir?","options":["Podosit nefrin ekspresyonunun yeniden düzenlenmesi ve filtrasyon bariyerinin onarılması","Proksimal tübül Na-K-ATPaz aktivitesinin azaltılması","Glomerüler bazal membranda kollajen sentezinin artması","Mezangial hücre proliferasyonunun baskılanması","Tübüler protein geri emiliminin artırılması"],"correct":0,"exp":"Minimal change hastalığında (MCH) yapısal glomerüler hasar olmaksızın yalnızca podosit ayaksı çıkıntı efasmanı görülür. Podositler, filtre yüzeyini düzenleyen nefrin, podosin ve CD2AP gibi proteinleri eksprese eder. Kortikosteroidler, podosit iskelet yapısını ve nefrin gen ekspresyonunu yeniden düzenleyerek yarık diyaframın (slit diaphragm) işlevini restore eder; böylece selektif filtre onarılır ve proteinüri azalır. Mezangial proliferasyon MCH'nin özelliği değildir. Tübüler geri emilim proteinürinin azalmasında primer mekanizma değildir."},{"id":8400,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"19 yaşında erkek hasta, bir trafik kazası sonrası acil servise getiriliyor. Nörolojik muayenede sağ alt ekstremitede propriosepsiyon ve vibrasyon duyusu kaybı, sol alt ekstremitede ağrı ve ısı duyusu kaybı saptanıyor. Motor kayıp izlenmiyor. Spinal MR'da T6 düzeyinde sağ hemikord lezyonu görülüyor. Bu klinik tabloda aşağıdaki öncülleri değerlendirin:\nI. Sağ taraf propriosepsiyon kaybı, spinal kordda çapraz yapmadan ipsilateral seyreden dorsal kolon hasarına bağlıdır.\nII. Sol taraf ağrı-ısı kaybı, lateral spinotalamik traktın lezyon seviyesinin hemen üstünde çapraz yapmasından kaynaklanır.\nIII. Bu tabloya Brown-Séquard sendromu adı verilir.\nIV. Lezyon düzeyinin altında ipsilateral motor kayıp beklenir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","I, III ve IV","II ve III","I, II ve III","I, II, III ve IV"],"correct":1,"exp":"Brown-Séquard sendromu (Öncül III doğru), spinal hemikord lezyonunda görülür. Dorsal kolonlar (propriosepsiyon, vibrasyon) ipsilateral seyreder ve medulla oblangatada çapraz yapar; bu nedenle lezyon tarafında kayıp oluşur (Öncül I doğru). Lateral spinotalamik traktın lifleri birkaç segment içinde spinal kordda çapraz yaptığı için kontralateral (karşı taraf) ağrı-ısı kaybı görülür, 'lezyon seviyesinin hemen üstünde çapraz yapar' ifadesi anatomik olarak yanlıştır (Öncül II yanlış). Kortikospinal traktın lifleri de medullada çapraz yapar, dolayısıyla lezyon tarafında (ipsilateral) motor kayıp beklenir (Öncül IV doğru). Doğru öncüller I, III ve IV'tür."},{"id":8401,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"28 yaşında kadın hasta, 2 aydır süren halsizlik, çarpıntı ve baş dönmesi yakınmalarıyla iç hastalıkları polikliniğine başvuruyor. Hemogram sonuçlarında Hb: 7,8 g/dL, MCV: 106 fL, periferik yaymada hipersegmente nötrofiller görülüyor. Serum B12 düzeyi belirgin şekilde düşük saptanıyor. Hastaya parenteral B12 vitamini (siyanokobalamin) tedavisi başlanıyor. Tedavinin 5-7. günlerinde hemogram kontrolünde en çok hangi parametrenin değişmesi beklenir?","options":["MCV'nin hızla normale dönmesi","Retikülosit sayısında belirgin artış (retikülosit krizi)","Serum demir düzeyinin yükselmesi","Trombosit sayısının düşmesi","Lökosit sayısının normalleşmesi"],"correct":1,"exp":"B12 eksikliğine bağlı megaloblastik anemide parenteral B12 tedavisinin başlanmasından 5-7 gün sonra kemik iliği baskılanmış eritropoezini hızla aktive eder. Bu dönemde retikülosit sayısı dramatik biçimde artar ve 'retikülosit krizi' olarak adlandırılır; bu bulgu tedavi yanıtının en erken ve en belirgin göstergesidir. Hemoglobin yükselmesi ve MCV'nin normalleşmesi haftalar-aylar içinde gerçekleşir. Serum demir düzeyi B12 tedavisine doğrudan yanıt olarak yükselmez; aksine artan eritropoez nedeniyle tüketim artışından dolayı geçici olarak düşebilir. Lökosit normalleşmesi daha geç dönemde görülür."},{"id":8402,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"61 yaşında erkek hasta, 4 aydır süren epigastrik ağrı, kilo kaybı ve erken doygunluk yakınmalarıyla gastroenteroloji polikliniğine başvuruyor. Üst endoskopide antrum yerleşimli ülsere lezyon saptanıyor, biyopsi sonucu 'diffüz tip gastrik adenokarsinom' olarak geliyor. Mide fizyolojisiyle ilgili aşağıdaki öncülleri değerlendirin:\nI. Diffüz tip gastrik karsinom, intestinal metaplazi zemininde gelişmekten ziyade E-kadherin kaybıyla ilişkilidir.\nII. Antrum bölgesindeki G hücrelerinden salgılanan gastrin, parietal hücreleri doğrudan uyararak HCl sekresyonunu artırır.\nIII. Mide boşalmasını yavaşlatan kolesistokinin (CCK), duodenumun I hücrelerinden salgılanır.\nIV. Somatostatin, antrumdaki D hücrelerinden salgılanarak gastrin salınımını inhibe eder.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, III ve IV","I, II ve IV","I, II, III ve IV","II ve III","I ve II"],"correct":2,"exp":"Diffüz tip gastrik karsinom E-kaderin kaybıyla ilişkilidir. Gastrin parietal hücreleri CCK-B reseptörü üzerinden doğrudan uyarabilir; ayrıca ECL hücrelerinden histamin salınımını artırarak güçlü bir dolaylı etki gösterir. CCK duodenum ve jejunumdaki I hücrelerinden salgılanır ve mide boşalmasını yavaşlatır. Somatostatin, D hücrelerinden salgılanarak gastrin salınımını baskılar. Dört öncül de doğrudur."},{"id":8403,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, efor sırasında nefes darlığı ve bacaklarda ödem yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya tedavi başlandıktan 2 hafta sonra yapılan kontrolde serum aldosteron düzeyinin belirgin yükseldiği görülüyor. Bu hastada aldosteron düzeyinin yükselmesine yol açan en olası tedavi ajanı hangisidir?","options":["Karvedilol","Digoksin","Enalapril","Spironolakton","Furosemid"],"correct":4,"exp":"Furosemid bir loop diüretiğidir ve tübüler sodyum kaybına yol açarak hipovolemiye ve RAS aktivasyonuna neden olur. Renin-anjiyotensin-aldosteron sisteminin aktivasyonu aldosteron sekresyonunu artırır. ACE inhibitörleri (enalapril) aldosteron düzeyini düşürür; spironolakton aldosteron reseptörünü bloke eder; digoksin ve karvedilol aldosteron üzerine bu mekanizmayla doğrudan etki etmez. Dolayısıyla aldosteron yükselmesinden sorumlu olan furosemid kaynaklı RAS aktivasyonudur."},{"id":8404,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"22 yaşında erkek hasta, trafik kazası sonrası acil servise getiriliyor. Yapılan nörolojik değerlendirmede T10 düzeyinde tam spinal kord yaralanması saptanıyor. Yaralanmadan 6 hafta sonra hastanın alt ekstremitelerinde spastisite ve derin tendon reflekslerinde artış gözlemleniyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Bu bulgular üst motor nöron lezyonuna özgüdür.\nII. Hasarda kortikospinal yolak etkilenmiştir.\nIII. Spastisite, alt motor nöron lezyonunun tipik bulgusudur.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["I ve II","Yalnız I","II ve III","Yalnız II","I, II ve III"],"correct":0,"exp":"T10 tam transeksiyon sonrası görülen spastisite ve hiperrefleksi, üst motor nöron lezyonunun klasik bulgularıdır; alt motor nöron lezyonunda ise flaksidite ve hiporefleksi beklenir. Kortikospinal yolak T10 seviyesinde kesildiği için hem motor hem de inhibitör sinyaller iletilememektedir. Bu nedenle öncül I ve II doğru, öncül III yanlıştır; doğru olan öncül sayısı 2'dir."},{"id":8405,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, 20 paket-yıl sigara içme öyküsüyle birlikte 2 yıldır süren progresif dispne ve kronik produktif öksürük yakınmasıyla başvuruyor. Solunum fonksiyon testinde FEV1/FVC: %58, FEV1: %52 (beklenenin) olarak ölçülüyor. Hastaya inhaler bronkodilatör tedaviye ek olarak uzun süreli oksijen tedavisi planlanıyor. Bu hastada uzun süreli oksijen tedavisinin primer fizyolojik hedefi hangisidir?","options":["FEV1/FVC oranını normalize etmek","Alveoler surfaktan sentezini uyarmak","Hipoksik solunum dürtüsünü artırmak","Mukosiliyer klerensı hızlandırarak enfeksiyonu önlemek","Hipoksik pulmoner vazokonstriksiyon refleksini baskılayarak pulmoner hipertansiyonu azaltmak"],"correct":4,"exp":"Kronik obstrüktif akciğer hastalığında persistan hipoksi, hipoksik pulmoner vazokonstriksiyon (HPV) refleksini kronik olarak aktive eder ve bu durum pulmoner hipertansiyon ile kor pulmonaleye yol açar. Uzun süreli oksijen tedavisinin temel fizyolojik amacı PaO2'yi ≥60 mmHg'de tutarak HPV'yi baskılamak ve pulmoner vasküler direnci düşürmektir. Bu sayede sağ kalp yükü azaltılır ve sağkalım uzatılır. Diğer seçenekler tedavinin doğrudan hedefi değildir."},{"id":8406,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 3 aydır süren poliüri ve polidipsi yakınmasıyla başvuruyor. 24 saatlik idrar miktarı 6 litre olarak ölçülüyor; idrar osmolalitesi 95 mOsm/kg, plazma osmolalitesi 298 mOsm/kg saptanıyor. Su kısıtlama testinin ardından desmopressin uygulamasıyla idrar osmolalitesi 510 mOsm/kg'a yükseliyor. Bu hastaya en uygun tedavi seçeneği hangisidir?","options":["Su kısıtlaması","Desmopressin","Tiazid diüretik","Lityum kesilmesi","İndometazin"],"correct":1,"exp":"Desmopressin (sentetik ADH analoğu) uygulamasına yanıt alınması, renal toplayıcı tübüllerin ADH'ya duyarlı olduğunu ve sorunun nörohipofizer ADH eksikliğinden kaynaklandığını gösterir; bu tablo santral diabetes insipidusla uyumludur. Santral DI'da birinci basamak tedavi desmopressindir. Nefrojenik DI'da ise tiazid ve indometazin kullanılabilir ancak bu hastada desmopressin yanıtı nefrojenik olasılığı dışlar."},{"id":8407,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 6 aydır süren yorgunluk, solukluk ve kolay kanama yakınmalarıyla başvuruyor. Hemogram incelemesinde pansitopeni saptanıyor; retikülosit sayısı belirgin düşük bulunuyor. Kemik iliği biyopsisinde hiposellüler yapı ve yağ dokusu artışı izleniyor. Bu hastada en olası tanı hangisidir?","options":["Megaloblastik anemi","Paroksismal noktürnal hemoglobinüri","Demir eksikliği anemisi","Aplastik anemi","Miyelodisplastik sendrom"],"correct":3,"exp":"Pansitopeni, düşük retikülosit sayısı ve kemik iliği biyopsisinde hiposellülarite ile yağlı değişim aplastik aneminin klasik triadını oluşturur. Hematopoetik kök hücre kaybı ya da baskılanmasıyla ortaya çıkan bu tabloda tüm hücre serilerinin üretimi azalır. Demir eksikliği yalnızca eritroid seriyi etkiler; megaloblastik anemi hiposellülarite yerine hiperselülarite gösterir; MDS'de displazi ön planda olup retikülosit normal ya da yüksek olabilir."},{"id":8408,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Gastrointestinal sistemdeki enteroendokrin hücreler tarafından salgılanan sekretin hormonu ile ilgili aşağıdaki öncülleri değerlendiriniz:\nI. Duodenum S hücrelerinden salgılanır.\nII. Asidik kimus duodenuma geçtiğinde sekresyonu uyarılır.\nIII. Pankreastan bikarbonat zengin sıvı salgısını artırır.\nYukarıdaki öncüllerin kaç tanesi doğrudur?","options":["Hiçbiri","Yalnız I ve III","Üç tanesi","Yalnız bir tanesi","İki tanesi"],"correct":2,"exp":"Sekretin, duodenum mukozasındaki S hücrelerinden (öncül I doğru) salgılanan bir hormondur. Temel uyarısı duodenuma ulaşan aside pH'dır; pH 4,5'in altına düştüğünde sekresyon belirgin artar (öncül II doğru). Sekretin, pankreas duktal hücrelerini uyararak bikarbonat açısından zengin, enzim fakiri sıvı salgısını artırır ve duodenal asidi nötralize eder (öncül III doğru). Dolayısıyla üç öncülün tamamı doğrudur."},{"id":8409,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, ağır egzersiz sonrası gelişen kas ağrısı, halsizlik ve koyu renkli idrar yakınmasıyla başvuruyor. Serum kreatinin kinaz düzeyi 12.000 U/L, idrar miyoglobin pozitif olarak saptanıyor. Hastaya yoğun IV sıvı tedavisi başlanıyor ve idrar pH'ı alkalize ediliyor. Bu hastada akut böbrek hasarının önlenmesinde idrar alkalinizasyonunun temel katkısı hangi mekanizma üzerinden gerçekleşmektedir?","options":["Miyoglobinin proksimal tübüler geri emilimini artırarak serum düzeyini düşürür","Glomerüler filtrasyon hızını artırarak miyoglobin klirensini hızlandırır","Renin-anjiyotensin sistemini baskılayarak renal vazokonstriksiyonu önler","Miyoglobinin tübüler lümende çökmesini ve tıkaç oluşturmasını engeller","Distal tübülde Na-K-ATPaz aktivitesini artırarak tübüler akımı hızlandırır"],"correct":3,"exp":"Miyoglobin asidik ortamda ferrihemat formuna dönüşerek doğrudan tübüler toksisiteye yol açar ve Tamm-Horsfall proteini ile birleşerek tübüler tıkaç oluşturur. İdrar alkalinizasyonu bu dönüşümü önleyerek miyoglobinin çözünür formda kalmasını sağlar ve tübüler tıkaç oluşumunu engeller. Sıvı yüklemesi idrar akımını artırsa da alkalinizasyonun spesifik katkısı tübüler presipitasyonu önlemektir."},{"id":8410,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya karvedilol başlanıyor ve 6 ay sonra yapılan kontrolde ejeksiyon fraksiyonu %48'e yükselmiş. Bu hastada kardiyak remodelingin tersine dönmesinden sorumlu olan başlıca hücresel değişiklik hangisidir?","options":["Kardiyomiyosit hipertrofisinin gerilemesi ve miyozin ağır zincir izoform dönüşümü","Kardiyak fibroblastlarda kollajen sentezinin akut olarak inhibe edilmesi","Sarkoplazma retikulumundaki riyanodin reseptör duyarlılığının artması","İnterkalar disk bölgesindeki gap junction yoğunluğunun azalması","Sinoatriyal düğüm hücrelerinde otomatisite artışının baskılanması"],"correct":0,"exp":"Kalp yetersizliğinde kronik sempatik aktivasyon, beta-miyozin ağır zincir (yavaş, enerji verimsiz) ekspresyonunu artırır ve kardiyomiyosit hipertrofisine yol açar. Karvedilol gibi beta-blokerler bu adrenerjik uyarıyı azaltarak alfa-miyozin ağır zincir ekspresyonunu restore eder, miyosit hipertrofisini geri döndürür ve kardiyak remodelingi tersine çevirir. Bu değişiklik ejeksiyon fraksiyonundaki iyileşmenin moleküler temelidir."},{"id":8411,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında kadın hasta, 2 yıldır giderek artan unutkanlık, kişilik değişikliği ve günlük aktivitelerde bağımsızlığını yitirme yakınmalarıyla nöroloji polikliniğine getiriliyor. Beyin MR'ında bilateral hipokampal atrofi saptanıyor. BOS analizinde beta-amiloid 42 düzeyi düşük, total tau ve fosfo-tau düzeyleri yüksek olarak raporlanıyor. Bu hastada BOS'taki beta-amiloid 42 düzeyinin düşük saptanmasının en olası nedeni nedir?","options":["Astrositlerde artmış beta-amiloid fagositozu nedeniyle BOS konsantrasyonunun düşmesi","Koroid pleksus epitel hücrelerinde beta-amiloid üretiminin azalması","Beta-amiloid 42 peptidlerinin beyin parankiminde plak olarak birikmesi nedeniyle BOS'a geçişinin azalması","Kan-beyin bariyerinin bozulmasıyla birlikte beta-amiloid 42'nin sistemik dolaşıma kaçması","Nöronal beta-sekretaz aktivitesinin azalması nedeniyle amiloid prekürsör protein yıkımının engellenmesi"],"correct":2,"exp":"Alzheimer hastalığında beta-amiloid 42 peptidleri beyin parankiminde amiloid plaklar oluşturacak biçimde çökelir. Bu çökelme nedeniyle serbest beta-amiloid 42 BOS'a geçemez ve BOS düzeyi paradoks olarak düşük ölçülür. Tau proteinleri ise hasarlı nöronlardan BOS'a salındığından yüksek bulunur. Bu BOS profili (düşük Aβ42, yüksek t-tau ve p-tau) Alzheimer hastalığının biyobelirteç tanısında kullanılır."},{"id":8412,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"24 yaşında kadın hasta, 6 aydır süren ödem, halsizlik ve köpüklü idrar yakınmasıyla başvuruyor. İdrar tetkikinde 24 saatlik protein atılımı 4,8 g olarak ölçülüyor. Serum albumin 2,1 g/dL, total kolesterol 380 mg/dL olarak saptanıyor. Renal biyopside ışık mikroskobisinde normal görünüm izlenirken elektron mikroskobisinde podosit ayaksı çıkıntılarında yaygın silinme (effacement) saptanıyor. Bu hastada hiperlipidemi gelişmesinin birincil nedeni nedir?","options":["Renal tübüllerde lipoprotein lipaz ekspresyonunun artması","Adrenal korteksten artmış kortizol salgılanması sonucunda hepatik lipolizin uyarılması","Böbrek proksimal tübüllerinde kolesterol geri emiliminin bozulması","Karaciğerde albumin ve lipoprotein sentezinin artması ile lipoprotein lipaz aktivitesinin azalması","İntestinal lenfatik kanallardan lipoprotein emiliminin artması"],"correct":3,"exp":"Nefrotik sendromda masif proteinüri sonucunda gelişen hipoalbüminemi, onkotik basıncı düşürür. Karaciğer bu duruma yanıt olarak albumin sentezini artırır; ancak bu nonspesifik bir hepatik aktivasyon olduğundan VLDL başta olmak üzere lipoprotein sentezi de artar. Eş zamanlı olarak idrarla kaybedilen lipoprotein lipaz aktivatörleri (özellikle apolipoprotein C-II) nedeniyle periferik lipoprotein yıkımı azalır. Bu ikili mekanizma nefrotik sendromda hiperlipidemiyi açıklar."},{"id":8413,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Solunum yolu epiteli ile ilgili aşağıdaki öncüller değerlendirildiğinde hangileri doğrudur?\nI. Trakea ve ana bronşlarda yalancı çok katlı siliyalı silindirik epitel bulunur.\nII. Tip I pnömositler gaz değişiminden sorumludur ve alveoler yüzeyin yaklaşık %95'ini kaplar.\nIII. Tip II pnömositler sürfaktan sentezler ve alveol hasarı sonrasında Tip I pnömositleri yenileyebilir.\nIV. Bronşiollerde kıkırdak halkalar bulunmadığından lümen sadece düz kas tonusu ile açık tutulur.","options":["II ve IV","Yalnız II","I, II, III ve IV","I ve IV","I, II ve III"],"correct":2,"exp":"I. Doğru: Trakea ve bronşların karakteristik epiteli yalancı çok katlı (psödostratifiye) siliyalı silindirik epiteldir ve goblet hücreleri içerir. II. Doğru: Tip I pnömositler (squamöz alveoler hücreler) ince yapıları sayesinde gaz difüzyonuna izin verir ve alveoler yüzeyin yaklaşık %95'ini kaplar. III. Doğru: Tip II pnömositler sürfaktan üretir, alveol basıncını düzenler ve hasar sonrası Tip I pnömositlere farklılaşarak alveoler epitel onarımını sağlar. IV. Doğru: Bronşiollerde kıkırdak bulunmaz; lümen açıklığı çevre parankimin elastik traksiyon ve düz kas tonusu ile sağlanır. Bu nedenle tüm öncüller doğrudur."},{"id":8414,"ders":"Fizyoloji","konu":"Endokrin ve Genital Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 14 haftalık gebeliğinde rutin kontrole geliyor. Tiroid fonksiyon testlerinde serbest T4 hafif düşük, TSH baskılanmış olarak saptanıyor. Hastanın bilinen Graves hastalığı öyküsü var ve gebelik öncesinde propiltiourasil (PTU) kullanmaktaydı. Gebelikte tiroid fizyolojisiyle ilgili aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. İnsan koriyonik gonadotropini (hCG), TSH reseptörlerine zayıf agonist etki göstererek tiroid bezini uyarabilir.\nII. Östrojen etkisiyle artmış tiroksin bağlayıcı globulin (TBG) düzeyi total T4'ü yükseltir ancak serbest T4 fizyolojik sınırlarda kalır.\nIII. Plasenta T4'ü anneden fetüse aktif taşıma ile iletir, bu nedenle maternal tiroid hormonu fetal gelişim açısından kritik öneme sahiptir.\nIV. PTU, metimazolün aksine plasenta bariyerini geçemez ve bu nedenle gebeliğin ilk trimesterinde tercih edilir.","options":["1 tanesi","Hiçbiri","2 tanesi","4 tanesi","3 tanesi"],"correct":4,"exp":"I. Doğru: hCG, TSH reseptörüne zayıf agonist etkisiyle bağlanır; özellikle ilk trimesterde yüksek hCG düzeyleri subklinik hipertiroidi tablosuna yol açabilir. II. Doğru: Östrojen TBG sentezini artırır, total T4 yükselir; ancak homeostaz mekanizmaları serbest T4'ü normal sınırlarda tutar (yüksek riskli gebelikler hariç). III. Doğru: Plasenta T4'ü anneden fetüse aktif transport ile iletir; fetal tiroid fetal dönemde geliştiğinden özellikle erken gebelikte maternal T4 fetal beyin gelişimi için kritiktir. IV. Yanlış: Her iki ilaç da plasentayı geçer; PTU metimazolden daha az geçtiği için ilk trimesterde tercih edilir, ancak 'geçemez' ifadesi yanlıştır. Bu nedenle doğru öncül sayısı 3'tür."},{"id":8415,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, efor sırasında ortaya çıkan nefes darlığı ve bacaklarında şişlik yakınmasıyla başvuruyor. Özgeçmişinde 15 yıldır hipertansiyon ve tip 2 diyabet mellitus tanısı mevcut. Fizik muayenede boyun venöz dolgunluğu, bilateral raller ve pretibial ödem saptanıyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya digoksin başlanıyor. Bu ilacın kardiyak etkisine aracılık eden iyon kanalı/pompa değişikliğinin bir sonucu olarak aşağıdakilerden hangisi beklenir?","options":["İntraselüler sodyum artışına ikincil sitozolde kalsiyum birikimi","Voltage-gated L-tipi kalsiyum kanallarının doğrudan aktivasyonu","Hücre içi potasyum konsantrasyonunun artması","Aksiyon potansiyeli plato fazının kısalması","Sarkoplazmik retikulumdan kalsiyum salınımının azalması"],"correct":0,"exp":"Digoksin, Na+/K+ ATPaz pompasını inhibe ederek hücre içi Na+ konsantrasyonunu artırır. Yükselen intraselüler Na+, Na+/Ca2+ değiştiricisinin (NCX) ters yönde çalışmasına neden olur; NCX artık Na+ içeri almak yerine Ca2+ dışarı atamaz hale gelir ve sitozolde Ca2+ birikir. Bu artmış intraselüler Ca2+ sarkoplazmik retikuluma depolanır; her aksiyon potansiyelinde daha fazla Ca2+ salınır ve pozitif inotrop etki ortaya çıkar. Plato fazı kısalmaz, aksine uzayabilir. Sarkoplazmik retikulum salınımı azalmaz, artar. L-tipi kanallar doğrudan aktive edilmez. İntraselüler K+ pompanın inhibisyonuyla düşer."},{"id":8416,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, 8 yıldır devam eden progresif nefes darlığı ve kuru öksürük yakınmasıyla başvuruyor. Bilinen romatolojik hastalığı bulunmuyor. Toraks BT'de bilateral bazal predominant retikülasyon ve balpeteği görünümü izleniyor. Solunum fonksiyon testlerinde FVC: %58, FEV1/FVC: 0,88 ve DLCO: %42 saptanıyor. Bronkoalveoler lavaj analizinde lenfosit oranı %8, nötrofil oranı %12 bulunuyor. Bu hastanın patolojik sürecinde en belirleyici rol oynayan hücre tipi ve onun uyardığı efektör mekanizma için aşağıdaki eşleştirmelerden hangisi doğrudur?","options":["Alveolar tip II pnömosit — matrilysin aracılı bazal membran yıkımı","Alveoler makrofaj — MMP-9 aracılı elastin yıkımı","Alveolar tip I pnömosit — surfaktan sentezinin artması","Mast hücresi — histamin salınımıyla bronkokonstrüksiyon","Miyofibroblast — TGF-β uyarımıyla aşırı kollajen birikimi"],"correct":4,"exp":"İdiyopatik pulmoner fibrozis (IPF) tanısı alan bu hastada balpeteği görünümü, restriktif patern ve düşük DLCO karakteristiktir. IPF patogenezinde tekrarlayan epitelyal hasar sonucu aktive olan alveolar tip II pnömositler, TGF-β1 salgılayarak fibrozisi başlatır. TGF-β1, fibrozün temel efektör hücresi olan miyofibroblastları aktive eder; miyofibroblastlar aşırı kollajen (özellikle tip I ve III) ve diğer matriks proteinlerini üreterek patolojik fibrozisi oluşturur. Tip I pnömositler gaz değişiminden sorumludur, surfaktan sentezi tip II pnömositlere aittir. MMP-9 amfizem patogenezinde daha belirgindir. Histamin aracılı bronkokonstrüksiyon astım ile ilişkilidir."},{"id":8418,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan idrar yolu enfeksiyonları ve 6 aydır devam eden poliüri-polidipsi yakınmasıyla başvuruyor. Kan basıncı 155/95 mmHg, serum K+: 2,9 mEq/L, serum Na+: 147 mEq/L, serum HCO3-: 31 mEq/L, idrar dansitesi: 1,005. Plazma aldosteron düzeyi yüksek, plazma renin aktivitesi baskılı olarak saptanıyor. Adrenal BT'de 1,8 cm sağ adrenal adenom görülüyor. Bu hastada böbreğin hangi tübüler segmentinde hangi iyon kanalı/taşıyıcı aşırı aktive olmaktadır ve bunun doğrudan sonucu nedir?","options":["Kortikal toplayıcı kanal — ENaC ve ROMK — Na+ tutulumu ve K+ sekresyonunun artması","Distal kıvrımlı tübül — NCC taşıyıcısı — aldosteron bağımsız Na+-Cl- geri emilimi","Henle kulpunun çıkan kalın kolu — NKCC2 taşıyıcısı — hiperkalemi gelişmesi","Medüller toplayıcı kanal — AQP2 su kanalı — ADH bağımsız serbest su geri emilimi","Proksimal tübül — Na+/H+ değiştirici (NHE3) — bikarbonat geri emiliminin azalması"],"correct":0,"exp":"Primer hiperaldosteronizm (Conn sendromu) tanısını düşündüren bu tabloda; hipertansiyon, hipokalemi, metabolik alkaloz, düşük renin ve yüksek aldosteron birlikteliği ile adrenal adenom saptanmaktadır. Aldosteron, kortikal toplayıcı kanalın baş hücrelerinde apikal ENaC (epitelyal Na+ kanalı) ve ROMK (K+ kanalı) ekspresyonunu artırır, bazolateral Na+/K+ ATPaz aktivitesini de uyarır. Sonuç olarak Na+ geri emilimi (hacim yüklenmesi → hipertansiyon) ve K+ sekresyonu (hipokalemi) artar. Metabolik alkaloz ise H+ sekresyonunun artması ve K+ kaybına bağlı hücre içine K+ girişiyle ortaya çıkar. Poliüri, kronik hipokaleminin AQP2 ekspresyonunu azaltması ve nefrojenik DI benzeri tablo oluşturmasıyla açıklanır."},{"id":8419,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında erkek hasta, 3 haftadır devam eden halsizlik, efor intoleransı ve sarılık yakınmasıyla başvuruyor. Özgeçmişinde talasemi minör tanısı bilinen hasta, son hafta antimalaryal ilaç kullanmış. Laboratuvar sonuçları: Hb: 7,2 g/dL, MCV: 78 fL, retikülositoz belirgin, periferik yaymada ısırık hücreleri (bite cell) ve Heinz cisimcikleri görülüyor, direkt Coombs testi negatif. Bu hastadaki hemolizin temel patogenezi için aşağıdaki öncüllerden hangileri doğrudur?\nI. Eritrositlerde G6PD eksikliği nedeniyle pentoz fosfat yolağı işlev göremez ve NADPH üretimi bozulur.\nII. NADPH yetersizliği sonucu glutatyon indirgenmiş (GSH) formda tutulamamakta ve oksidatif strese karşı savunma çökmektedir.\nIII. Denatüre hemoglobin Heinz cisimciklerini oluşturarak eritrositlerin dalak sinüzoidlerinde parçalanmasına yol açmaktadır.\nIV. Direkt Coombs pozitifliği bu tablonun tanısal kriterleri arasındadır.","options":["II ve IV","Yalnız III","I ve II","I, II ve III","I, II, III ve IV"],"correct":3,"exp":"G6PD eksikliğinde pentoz fosfat yolağı bozulur ve NADPH üretimi yetersiz kalır (I doğru). NADPH, glutatyon redüktaz için kofaktördür; NADPH eksikliğinde okside glutatyon (GSSG) indirgenemez, GSH azalır ve oksidatif strese karşı savunma çöker (II doğru). Okside hemoglobin denatüre olarak Heinz cisimciklerini oluşturur; Heinz cisimciği içeren eritrositler dalak makrofajları tarafından 'ısırılarak' bite cell haline getirilir veya eritrosit yıkılır (III doğru). Bu tablo oksidatif hemoliz olup otoimmün değildir; direkt Coombs testi negatiftir, pozitiflik bu tablonun kriteri değildir (IV yanlış). Dolayısıyla I, II ve III doğrudur."},{"id":8420,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"45 yaşında erkek hasta, uzun süredir kullandığı aspirin sonrası gelişen epigastrik ağrı ve mide yanması yakınmasıyla başvuruyor. Yapılan üst GIS endoskopisinde antrum yerleşimli ülser saptanıyor, biyopside Helicobacter pylori pozitif. Hastaya proton pompa inhibitörü (PPI) başlanıyor. PPI tedavisinin mide asit sekresyonunu azaltmasında hangi hücre tipi ve hangi mekanizma doğrudan hedef alınmaktadır?","options":["Parietal hücre — H+/K+ ATPaz pompasının geri dönüşümsüz inhibisyonu","G hücresi — gastrin sekresyonunun baskılanması","Müköz hücre — bikarbonat sekresyonunun artırılması","Enterokromafin benzeri (ECL) hücre — histamin salınımının azaltılması","Chief hücre — pepsinojen salınımının inhibe edilmesi"],"correct":0,"exp":"Mide asit sekresyonunun son ortak adımı parietal hücredeki H+/K+ ATPaz (proton pompası) aracılığıyla gerçekleşir. PPI'lar (omeprazol, pantoprazol vb.) prodrug yapısındadır; asidik ortamda aktif sulfenamid formuna dönüşerek proton pompasının sistein rezidülerine kovalent bağlanır ve pompayı geri dönüşümsüz olarak inhibe eder. Asit sekresyonu baskılanır ve ülserin iyileşmesi için uygun ortam oluşur. Chief hücreler pepsinojen salgılar, G hücreleri gastrin üretir, ECL hücreleri histamin salgılar; bunlar asit sekresyonunun düzenleyici basamaklarıdır, PPI'nın doğrudan hedefi değildir. Müköz hücreler mukozal bariyer sağlar."},{"id":8421,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, efor sırasında nefes darlığı ve çabuk yorulma yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya tedavi başlanıyor ve takiplerinde atım hacminin arttığı gözlemleniyor. Bu hastada atım hacmini artırmak için kullanılan ajan aşağıdaki mekanizmalardan hangisine sahip olmalıdır?\nI. Miyozin başının ATPaz aktivitesini artırmak\nII. Sarkoplazma retikulumundan Ca²⁺ salınımını artırmak\nIII. Fosfolambana bağlanarak SERCA aktivitesini inhibe etmek\nYukarıdaki öncüllerden hangileri atım hacmini artırır?","options":["Yalnız II","I ve II","II ve III","Yalnız I","I, II ve III"],"correct":1,"exp":"Kalp yetmezliğinde kontraktiliteyi artıran pozitif inotropik ajanlar; miyozin ATPaz aktivitesini artırarak (miyozin aktivatörleri, omekamtiv mekarbil) veya hücre içi Ca²⁺ konsantrasyonunu yükselterek (dijital glikozitleri, fosfodiesteraz inhibitörleri) sistol gücünü artırır. Bu nedenle öncül I ve II doğrudur. Fosfolambana bağlanarak SERCA'yı inhibe etmek ise Ca²⁺ geri alımını azaltır, miyosit gevşemesini bozar ve diyastol sonu basıncı artırarak kontraktiliteyi olumsuz etkiler; öncül III yanlıştır. Doğru yanıt I ve II'dir."},{"id":8422,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 yıldır süren progresif dispne ve öksürük yakınmasıyla solunum polikliniğine başvuruyor. Yüksek rezolüsyonlu BT'de her iki akciğerde yaygın buzlu cam opasiteleri saptanıyor. Bronkoalveolar lavajda CD4/CD8 oranının belirgin düşük olduğu görülüyor. Biopsi materyalinde granülom izlenmiyor. Akciğer fonksiyon testleri restriktif patern gösteriyor. Bu hastada en olası etkilenen hücre tipinin birincil işlevi aşağıdakilerden hangisidir?","options":["Alveol içine girmiş partikülleri fagosite etmek","Yüzey gerilimini azaltmak için sürfaktan sentezlemek","Bazal membrana yapışık olarak alveol onarımını koordine etmek","Alveol duvarında gaz değişimi için ince bariyer oluşturmak","Havayolu lümenindeki mukusu hareket ettirmek"],"correct":3,"exp":"Klinik tablo, granülomsuz interstisiyel akciğer hastalığı olan nonspesifik interstisiyel pnömoniyi (NSIP) düşündürmektedir. Bu tabloda ağırlıklı olarak Tip I pnömositler hasar görür. Tip I pnömositler, alveol yüzeyinin yaklaşık %95'ini kaplayan yassı hücrelerdir ve birincil işlevleri oksijen ile karbondioksitin difüzyon için gerekli olan ince gazlı bariyeri oluşturmaktır. Sürfaktan sentezi Tip II pnömositlere aittir. Mukus klirens siliyalı hücrelerin görevidir. Fagositoz alveolar makrofajların işlevidir. Onarım koordinasyonu Tip II pnömositler tarafından üstlenilir."},{"id":8423,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan el titremesi, yürüme güçlüğü ve konuşma bozukluğu nedeniyle nöroloji bölümüne başvuruyor. Muayenede bradikinezi, rijidite ve istirahat tremoru saptanıyor. Tedaviye levodopa başlanıyor ve semptomlar belirgin düzeyde gerilemeye başlıyor. Bu hastada levodopanın etkinliğini azaltan biyokimyasal durum aşağıdakilerden hangisidir?\nI. Periferik aromatik L-amino asit dekarboksilaz aktivitesinin artması\nII. Kan-beyin bariyerini geçen levodopa miktarının azalması\nIII. Striatal D2 reseptörlerinin upregülasyonu\nYukarıdaki öncüllerden kaç tanesi levodopa etkinliğini azaltır?","options":["II ve III","I, II ve III","I ve II","I ve III","Yalnız I"],"correct":2,"exp":"Levodopa, kan-beyin bariyerini geçerek dopamine dönüştürülmesi sayesinde etki gösterir. Periferik dekarboksilaz aktivitesinin artması (öncül I) levodopanın periferde dopamine çevrilmesini hızlandırır; merkeze ulaşan levodopa miktarı azalır, etkinlik düşer. Kan-beyin bariyerini geçen miktarın azalması (öncül II) da aynı sonucu doğurur. Bu yüzden I ve II levodopa etkinliğini azaltır. Striatal D2 reseptörlerinin upregülasyonu (öncül III) ise postsinaptik duyarlılığı artırarak levodopa etkinliğini artırır, azaltmaz. Yanıt I ve II'dir."},{"id":8424,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında erkek hasta, askerlik muayenesi sırasında idrar tetkikinde protein +3 ve eritrosit +2 saptanıyor. Hasta asemptomatik olup kan basıncı 148/94 mmHg'dır. Serum kreatinin düzeyi 1,8 mg/dL olarak ölçülüyor. Renal biopside ışık mikroskobisinde mezangial hücre proliferasyonu ve immünfloresan mikroskobide mezangiumda IgA birikimi görülüyor. Bu hastada glomerüler filtrasyon hızının azalmasında birincil rol oynayan yapısal değişiklik aşağıdakilerden hangisidir?","options":["Afferent arteriol düz kas hipertrofisi","Podosit ayaksı çıkıntıların silinmesi ve filtrasyona izin veren yüzeyin azalması","Jukstaglomerüler hücrelerin hiperplazisi","Bowman kapsül pariyetal epitel hücrelerinin hipertrofisi","Mezangial matriksin artmasıyla kapiller lümen kompresyonu"],"correct":4,"exp":"IgA nefropatisinde (Berger hastalığı) mezangiumda IgA birikimi, kompleman aktivasyonu ve sitokin salınımıyla mezangial hücre proliferasyonuna ve mezangial matriks artışına yol açar. Artan matriks glomerüler kapillerleri dışarıdan sıkıştırarak lümeni daraltır; glomerüler filtrasyon yüzeyi azalır ve GFR düşer. Podosit ayaksı çıkıntıların silinmesi nefrotik sendromlarda (özellikle minimal change) ön plandadır. Afferent arteriol hipertrofisi hipertansif nefropatiyi düşündürür. Pariyetal epitel hipertrofisi kreskentik glomerülonefrit ile ilişkilidir."},{"id":8425,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Gastrointestinal sistemde 'Cajal hücreleri' ile ilgili aşağıdaki ifadelerden hangisi doğrudur?","options":["Mide fundusunda asid sekresyonunu uyaran enterokromafin benzeri hücrelerdir","Bağırsak lümenine geçen bakterileri fagosite eden özel makrofajlardır","Villus yüzeyinde besin emilimini gerçekleştiren absorptif enterositlerdir","Bağırsak duvarında pacemaker işlevi gören, yavaş dalgaları oluşturan interstisyel hücrelerdir","Kolonik kripta tabanında epitel yenilenmesini sağlayan kök hücrelerdir"],"correct":3,"exp":"Cajal hücreleri (interstisyel Cajal hücreleri), gastrointestinal sistemde düz kas tabakası içinde yer alan özel mezenkimal hücrelerdir. Miyenterik sinir ağına yakın konumlanan bu hücreler, gastrointestinal motilitenin pacemaker'ı olarak kabul edilir ve yavaş elektriksel dalgaları (slow waves) oluşturarak düz kasın ritmik kontraksiyonlarını başlatır. Cajal hücre kaybı veya disfonksiyonu, gastroparezi ve Hirschsprung hastalığı gibi motilite bozukluklarıyla ilişkilendirilmektedir. Diğer seçenekler farklı hücre tiplerini tanımlamaktadır."},{"id":8426,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"42 yaşında kadın hasta, 3 aydır süren yorgunluk, tekrarlayan enfeksiyonlar ve ciltte peteşi şikayetiyle hematoloji bölümüne başvuruyor. Tam kan sayımında pansitopeni saptanıyor. Kemik iliği biyopsisinde hiposellüler ilik ve yağ dokusu artışı görülüyor. Akış sitometrisinde CD34+ hücre sayısının belirgin azaldığı saptanıyor. Hastaya immünsüpresif tedavi başlanıyor ve kemik iliği transplantasyonu planlanıyor. Bu hastada transplantasyon için alıcıya aktarılan hücrelerin birincil hedefi aşağıdakilerden hangisidir?\nI. Kemik iliğinin endosteal nişine yerleşmek\nII. CD34+ yüzey işaretleyicisini kaybederek farklılaşmak\nIII. Stromal hücrelerden bağımsız olarak prolifere olmak\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve II","II ve III","Yalnız II","I, II ve III","Yalnız I"],"correct":0,"exp":"Aplastik anemide hematopoetik kök hücre transplantasyonu yapılırken verici kaynaklı CD34+ hematopoetik kök hücreler alıcıya aktarılır. Bu hücreler öncelikle kemik iliğinin endosteal nişine (öncül I) göç ederek tutunur; bu niş, osteoblastlar ve CXCL12 salgılayan stromal hücreler tarafından oluşturulur. Ardından kök hücreler, aldıkları sinyaller doğrultusunda CD34+ işaretleyicisini kaybederek eritroid, miyeloid ve lenfoid serilere farklılaşır (öncül II). Ancak bu proliferasyon ve farklılaşma süreci stromal hücrelerden bağımsız değildir; SCF, TPO, Flt3L gibi stromal kaynaklı sitokinler zorunludur, bu nedenle öncül III yanlıştır. Doğru yanıt I ve II'dir."},{"id":8427,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan kas güçsüzlüğü ve efor dispnesi yakınmasıyla başvuruyor. Özgeçmişinde tip 2 diyabetes mellitus mevcut olup metformin kullanmaktadır. Yapılan elektromiyografide miyopatik patern saptanıyor; kas biyopsisinde tip 1 kas lifi atrofisi ve mitokondriyal birikimler görülüyor. Serum laktat düzeyi yüksek bulunuyor. Bu hastada gözlemlenen histopatolojik değişikliklerle en doğrudan ilişkili fizyopatolojik temel hangisidir?\nI. Tip 1 liflerin ağırlıklı olarak oksidatif fosforilasyona bağımlı olması\nII. Mitokondriyal disfonksiyonun laktat birikimiyle sonuçlanması\nIII. Tip 2 liflerin bu süreçte tip 1 liflerden daha erken etkilenmesi\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II ve III","I ve III","I ve II","Yalnız I","I, II ve III"],"correct":2,"exp":"Tip 1 (yavaş, kırmızı) kas lifleri, enerji üretiminde ağırlıklı olarak mitokondriyal oksidatif fosforilasyona dayanır; bu nedenle mitokondriyal disfonksiyonda en çok etkilenen lif tipidir (Öncül I doğru). Mitokondri işlev bozukluğunda pirüvat aerobik yoldan metabolize edilemez ve laktat birikimine yol açar (Öncül II doğru). Tip 2 (hızlı, beyaz) lifler glikolitik metabolizmaya daha fazla bağımlı olduklarından mitokondriyal hastalıklarda daha az etkilenir; bu nedenle tip 2 liflerin daha erken etkilendiğini öne süren III. öncül yanlıştır."},{"id":8428,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, 2 yıldır süren efor intoleransı ve bacaklarda ödem yakınmasıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu yüzde 30 olarak saptanıyor. Kalp yetmezliği tanısıyla furosemid ve enalapril başlanıyor. Tedaviye rağmen semptomları gerileyen hasta 6 ay sonra kontrol amaçlı başvurduğunda sistolik kan basıncının belirgin düştüğü ve serum kreatinin düzeyinin yükseldiği görülüyor. Bu hastada en olası olarak hangi mekanizma devreye girmiştir?","options":["Renin-anjiyotensin-aldosteron sisteminin ACE inhibitörü tarafından baskılanmasına bağlı glomerüler filtrasyon basıncının düşmesi","Furosemidin tübüler sekresyonu azaltarak kreatinin klirensini doğrudan inhibe etmesi","Efferent arteriyol dilatasyonunun glomerüler filtrasyon hızını artırması","Natriüretik peptid düzeylerinin yükselmesiyle tübüler reabsorbsiyonun artması","Sempatik aktivasyona bağlı afferent arteriyol vazodilatasyon gelişmesi"],"correct":0,"exp":"ACE inhibitörleri anjiyotensin II sentezini baskılar. Anjiyotensin II, böbrek glomerülünde efferent arteriyolu daraltarak intraglomerüler basıncı korur. ACE inhibisyonu bu etkiyi ortadan kaldırarak efferent arteriyol direncini düşürür ve intraglomerüler basıncın azalmasına yol açar; bu da GFR'nin düşmesine ve kreatinin yükselmesine neden olur. Özellikle düşük kardiyak debi varlığında renal perfüzyon zaten azalmış olduğundan bu etki daha belirgindir. Diğer seçenekler mekanistik açıdan hatalıdır."},{"id":8429,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 3 yıldır süren ilerleyici unutkanlık, oryantasyon bozukluğu ve kişilik değişikliği yakınmasıyla getiriliyor. Nöropsikolojik testlerde bellek ve yürütücü işlev bozukluğu saptanıyor. Beyin MR'ında hipokampal atrofi ve temporoparietal kortikal incelme görülüyor. Asetilkolinesteraz inhibitörü başlanıyor. Bu hastada kullanılan ilacın etkinliğini kısıtlayan en önemli histopatolojik değişiklik hangisidir?","options":["Astroglial skar dokusunun kolinerjik reseptör ekspresyonunu artırması","Nörofibriler yumak oluşumuna bağlı kolinerjik nöron kaybı","GABA-erjik nöronların selektif olarak tutulması","Miyelin kılıfında demiyelinizasyon gelişmesi","Sinaptik aralıkta glutamat birikimi"],"correct":1,"exp":"Alzheimer hastalığında bazal ön beyin kolinerjik nöronları (özellikle Meynert'in bazal çekirdeği) nörofibriler yumaklar ve beta-amiloid birikimi nedeniyle progresif şekilde kaybolur. Asetilkolinesteraz inhibitörleri kolinerjik sinaptik iletimi artırmaya çalışır; ancak sinaptik iletim için presinaptik nöronun varlığı zorunludur. İleri evrede kolinerjik nöron kaybı ilaca yanıtı belirgin biçimde azaltır. Glutamat veya GABA ilgisi bu ilaç sınıfının etkisiyle doğrudan ilişkili değildir; demiyelinizasyon ise bu tablonun temel patolojisi değildir."},{"id":8430,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"24 yaşında kadın hasta, 1 haftadır süren göz kapaklarında şişlik ve ayak bileklerinde ödem yakınmasıyla başvuruyor. İdrar tetkikinde günlük 4,5 g proteinüri saptanıyor, serum albumin düzeyi 1,8 g/dL olarak ölçülüyor. Böbrek biyopsisinde ışık mikroskobisinde normal glomerül morfolojisi izlenirken elektron mikroskobisinde podosit ayak çıkıntılarının yaygın kaybolduğu görülüyor. Bu hastada en olası tanı hangisidir?","options":["IgA nefropatisi","Lupus nefriti","Fokal segmental glomerüloskleroz","Membranöz nefropati","Minimal değişiklik hastalığı"],"correct":4,"exp":"Minimal değişiklik hastalığı, ışık mikroskobisinde glomerüllerin normal görünmesiyle karakterizedir; ancak elektron mikroskobisinde podosit ayak çıkıntılarının (ayaksı çıkıntı) yaygın silinmesi (effacement) patognomoniktir. Yetişkin başlangıçlı nefrotik sendromda daha az görülse de genç erişkinlerde göz önünde bulundurulmalıdır. FSGS'de sklerotik odaklar, membranöz nefropatide subepitelyal depozitler, IgA nefropatisinde mezangial IgA birikimi elektron ve immünfloresans mikroskopide izlenir."},{"id":8431,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Akciğer alveollerini döşeyen ve surfaktan üreten hücre tipi ile bu hücrenin temel histolojik özelliğine ilişkin aşağıdaki öncüller değerlendirildiğinde hangileri doğrudur?\nI. Tip II pnömosit, köşeli ve küboidal görünümlüdür.\nII. Tip II pnömosit, elektron mikroskobisinde lamellar cisimcikler içerir.\nIII. Tip I pnömosit, alveol yüzeyinin yaklaşık yüzde seksenini döşer.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız II","II ve III","I ve II","I, II ve III","Yalnız I"],"correct":3,"exp":"Tip II pnömositler köşeli ve küboidal morfolojileriyle tanınır (Öncül I doğru). Bu hücreler surfaktan bileşenlerini depolayan lamellar cisimcikler (lamellar bodies) içerir; bu yapı elektron mikroskobisinde karakteristik bulgu olarak izlenir (Öncül II doğru). Tip I pnömositler ise çok ince ve yassı yapılarıyla alveol yüzeyinin yaklaşık yüzde seksenini oluşturur; sayıca az olmalarına karşın geniş yüzey alanları nedeniyle gaz değişimini kolaylaştırır (Öncül III doğru). Her üç öncül de doğrudur."},{"id":8432,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 4 aydır süren üst karın ağrısı, kilo kaybı ve sarılık yakınmasıyla başvuruyor. Görüntülemede pankreas başında kitle ve safra kanalında dilatasyon saptanıyor. Cerrahi rezeksiyon kararı alınıyor. Patoloji sonucunda tümörün duktus epitel hücrelerinden kaynaklandığı bildiriliyor. Bu hastada tümörün köken aldığı hücre tipinin fizyolojik olarak salgıladığı başlıca ürün ve bu ürünün ortam pH'ına göre düzenlenmesiyle ilgili aşağıdakilerden hangisi doğrudur?","options":["Duktus epitel hücreleri kolesistatik enzimleri salgılar; CCK tarafından inhibe edilir.","Duktus epitel hücreleri lipaz salgılar; safra tuzlarının varlığında aktivasyonu gerçekleşir.","Duktus epitel hücreleri insülin salgılar; kan glukozu yükseldikçe salgı artar.","Duktus epitel hücreleri bikarbonat salgılar; bu salgı sekretin aracılığıyla duodenum asidifikasyonuna yanıt olarak uyarılır.","Duktus epitel hücreleri trypsinojen salgılar; enterokinaz tarafından aktive edilir."],"correct":3,"exp":"Pankreasın duktal epitel hücreleri, duodenuma asit kimus geldiğinde S hücrelerinden salgılanan sekretine yanıt olarak bikarbonat açısından zengin bir sıvı salgılar. Bu bikarbonat, mideden gelen asidi nötralize ederek pankreatik enzimlerin optimal pH'ta çalışmasını sağlar. Asiner hücreler ise sindirim enzimlerini (lipaz, tripsinojen vb.) salgılar; bu nedenle lipaz ve tripsinojen sekresyonu asiner hücre işlevidir, duktal işlev değildir. İnsülin Langerhans adacıklarındaki beta hücrelerinden salgılanır; duktal epitel ile ilişkisi yoktur."},{"id":8433,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, 2 yıldır giderek kötüleşen proksimal kas güçsüzlüğü yakınmasıyla başvuruyor. Elektromiyografide miyopatik patern saptanıyor. Kas biyopsisinde tip II lif atrofisi ve sarkolemmal nükleusların santrale göçü izleniyor. Serum kreatin kinaz düzeyi belirgin şekilde yüksek bulunuyor. Bu hastada aşağıdaki öncüllerden hangisi ya da hangileri doğrudur?\nI. Etkilenen lifler hızlı kasılan, glikolitik liflerdir.\nII. Santrale göç eden nükleuslar normalde miyofiberin periferinde, sarkolemma altında yerleşir.\nIII. Tip II lif atrofisi denervasyon hastalıklarında da görülebilir, bu nedenle tek başına tanı koydurucudur.","options":["Yalnız I","I ve II","II ve III","I, II ve III","Yalnız II"],"correct":1,"exp":"Tip II lifler hızlı kasılan, glikolitik (beyaz) liflerdir; yorgunluğa duyarlıdırlar ve miyopatilerde sıklıkla etkilenirler. Öncül I doğrudur. Çizgili kas liflerinde nükleuslar normalde sarkolemmanın hemen altında periferde yer alır; santrale göç, miyopatik süreci (özellikle miyotonik distrofi ve miyotübüler miyopati) gösterir. Öncül II doğrudur. Öncül III yanlıştır: tip II lif atrofisi denervasyon hastalıklarında da görülebilir, ancak bu bulgu miyopatiyle denervasyon hastalığını ayırt ettirici değil, aksine örtüşen bir bulgudur; dolayısıyla tek başına tanı koydurucu değildir. Bu nedenle doğru öncüller I ve II'dir."},{"id":8434,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, eforla gelen göğüs ağrısı nedeniyle kardiyoloji polikliniğine başvuruyor. Koroner anjiyografide sol ön inen arterde %80 darlık saptanıyor. Hasta perkütan koroner girişim sonrasında ilaç salınımlı stent ile tedavi ediliyor. Stent yerleştirildikten 6 ay sonra yapılan kontrol anjiyografide in-stent restenoz geliştiği görülüyor. Bu hastada restenoz gelişiminde birincil rol oynayan hücre tipi ve bu hücrelerin bağ dokusu içindeki normal yerleşim yeri düşünüldüğünde, aşağıdakilerden hangisi doğrudur?","options":["Perisiytler; kapiller bazal membranı çevreleyerek yerleşir","Endotel hücreleri; tunika intimada tek sıra halinde yerleşir","Fibroblastlar; tunika adventisyada yoğun bağ dokusu üretir","Makrofajlar; subendotelyal aralıkta köpük hücre formunda birikir","Düz kas hücreleri; tunika mediada sirküler tabakalar oluşturur"],"correct":4,"exp":"In-stent restenozun temel mekanizması, tunika mediada sirküler tabakalar oluşturan vasküler düz kas hücrelerinin (VDMH) intimal hiperplazisidir. Balon anjiyoplasti ve stent yerleştirme sırasında damar duvarında oluşan mekanik hasar, tunika mediadaki VDMH'leri uyarır; bu hücreler fenotipik olarak kontraktil tipten sentetik tipe geçiş yaparak prolifere olur ve intimaya göç ederek ekstrasellüler matriks üretir. VDMH'lerin normal yerleşimi tunika mediada, elastik lameller arasında sirküler düzlemde dizili tabakalardır. Endotel hücreleri (A) intimal restenozda rol oynasa da birincil hücre tipi değildir; fibroblastlar (C), perisiytler (D) ve makrofajlar (E) ise restenozun birincil effektör hücresi değildir."},{"id":8435,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, 3 aydır devam eden görme bulanıklığı, sağ kolda uyuşma ve denge bozukluğu yakınmalarıyla nöroloji polikliniğine başvuruyor. Manyetik rezonans görüntülemede periventriküler bölgede multipl demiyelinizasyon odakları saptanıyor. Lumbar ponksiyonda oligoklonal bant pozitif bulunuyor. Bu hastada demiyelinizasyondan birincil olarak etkilenen hücre tipi için aşağıdaki öncüllerden hangisi ya da hangileri doğrudur?\nI. Bu hücreler santral sinir sistemindeki en kalabalık gliya hücre grubudur.\nII. Her bir hücre, tek bir aksonun birden fazla Ranvier boğumunu kapatan kılıfı oluşturabilir.\nIII. Bu hücrelerin hasar görmesi iletim hızında azalmaya yol açar, çünkü saltatorik iletim bozulur.","options":["I ve III","Yalnız III","I, II ve III","II ve III","I ve II"],"correct":1,"exp":"Tanım MS (Multipl Skleroz) ile uyumludur; demiyelinizasyondan birincil etkilenen hücreler oligodendrosittir. Öncül I yanlıştır: santral sinir sistemindeki en kalabalık gliya hücresi oligodendrosit değil, astrositlerdir. Öncül II yanlıştır: bir oligodendrosit birden fazla aksonun miyelin kılıfını oluşturabilir, ancak Ranvier boğumlarını 'kapatan' değil, iki boğum arasındaki internodal segmenti saran hücredir; Ranvier boğumları miyelin kılıfından yoksun, açık bölgelerdir. Öncül III doğrudur: miyelin kılıfı saltatorik (zıplayarak) iletimi sağlar; oligodendrositlerin hasarıyla bu kılıf bozulunca aksiyon potansiyeli Ranvier boğumundan boğuma atlayamaz, iletim yavaşlar veya tamamen durur. Dolayısıyla yalnızca III doğrudur."},{"id":8436,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"67 yaşında erkek hasta, 6 aydır giderek artan halsizlik, iştahsızlık ve bacaklarda ödem yakınmalarıyla dahiliye polikliniğine başvuruyor. Özgeçmişinde 15 yıldır tip 2 diyabetes mellitus tanısı mevcut. Laboratuvar incelemesinde GFR: 22 mL/dak/1,73 m², 24 saatlik idrarda protein: 4,8 g bulunuyor. Renal biyopside Kimmelstiel-Wilson nodülleri izleniyor. Bu hastada böbrek biyopsisinde en erken ve karakteristik histolojik değişikliklerin görüldüğü yapı hangisidir?","options":["Proksimal tübül epiteli","Bowman kapsülü pariyetal epiteli","Afferent arteriyol duvarı","Distal tübül epiteli","Glomerüler bazal membran"],"correct":4,"exp":"Diyabetik nefropatide en erken ve en karakteristik histolojik değişiklikler glomerüler bazal membranda (GBM) görülür. Hipergliseminin yol açtığı ileri glikasyon son ürünleri (AGE) birikimi ve hemodinamik stres GBM'yi kalınlaştırır; ardından mezangial matriks genişlemesi ve hiyalinizasyon gelişir. Kimmelstiel-Wilson nodülleri mezangial alanda oluşan nodüler glomerüloskleroz odaklarıdır ve bu sürecin ileri evresidir. Afferent ve efferent arteriyollerde hiyalinizasyon da görülür; ancak ilk ve en tanımlayıcı değişiklik GBM kalınlaşmasıdır. Proksimal tübül, Bowman kapsülü ve distal tübül bu hastalıkta ikincil olarak etkilenir."},{"id":8437,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Periferik yayma incelemesinde eritrositler hipokromik ve mikrositik görünümde olup merkezi soluk alanı genişlemiş olarak izlenmektedir. Serum ferritin düzeyi düşük, total demir bağlama kapasitesi yüksek bulunmaktadır. Bu bulgularla demir eksikliği anemisi tanısı konulan hastada, eritrositlerde hipokromi ve mikrositoz gelişmesinin temel nedeni aşağıdakilerden hangisidir?","options":["Hem sentezi için gerekli demirin yetersizliği nedeniyle hemoglobin üretiminin azalması","Eritropoetine duyarlılığın azalması nedeniyle eritroid farklılaşmanın durması","Kemik iliğinde eritroid öncülerin apopitozunun artması","Demir taşıyıcı protein transferrinin sentezinin baskılanması","Retiküloendotelyal sistemde eritrosit yıkımının hızlanması"],"correct":0,"exp":"Demir eksikliğinde hem sentezi için gerekli olan Fe²⁺ yetersiz kalır; bu durum hemoglobin üretimini kısıtlar. Hemoglobin yetersiz olduğunda eritroblastlar daha fazla bölünmeye devam ederek (hücre küçülür, mikrositoz) ve içlerinde yeterli hemoglobin birikemediğinden sitoplazmalarında hemoglobin konsantrasyonu düşer (hipokromi). Merkezi soluk alan genişlemesi de aynı mekanizmanın yansımasıdır. Transferrin sentezi demir eksikliğinde artış gösterir (TDBK yükselir), baskılanmaz; eritropoetin duyarlılığı ve eritroid apopitozis bu tablonun birincil mekanizması değildir."},{"id":8438,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, 10 yıldır devam eden kuru öksürük ve giderek kötüleşen efor dispnesi yakınmalarıyla göğüs hastalıkları polikliniğine başvuruyor. Özgeçmişinde 30 paket-yıl sigara içme öyküsü mevcut. Yüksek çözünürlüklü bilgisayarlı tomografide her iki akciğer bazallerinde balpeteği görünümü (honeycombing) ve traksiyon bronşiektazisi saptanıyor. Akciğer fonksiyon testlerinde restriktif patern ve DLCO'da belirgin azalma izleniyor. Bu hastada aşağıdaki öncüllerden hangisi ya da hangileri doğrudur?\nI. Balpeteği görünümü, tip I pnömositlerin yıkılıp yerini fibröz doku ile döşeli kistik boşluklara bırakmasıyla oluşur.\nII. Tip II pnömositler hasarlı alveoler epiteli onarmak için prolifere olur ve surfaktan üretimini sürdürür.\nIII. DLCO'daki azalma yalnızca difüzyon mesafesinin artmasından kaynaklanır; alveoler yüzey alanı kaybı katkıda bulunmaz.","options":["Yalnız II","I ve II","I, II ve III","Yalnız I","II ve III"],"correct":0,"exp":"Tanım İdiyopatik Pulmoner Fibrozis (IPF) ile uyumludur. Öncül I kısmen yanıltıcı biçimde ifade edilmiştir ve yanlıştır: balpeteği görünümü, geniş fibrozis alanlarında alveollerin yıkılmasıyla oluşan kistik boşlukları tanımlar; ancak bu boşluklar ağırlıklı olarak bronşiolar epitelle (solunum yolu epiteli) döşelidir, tip I pnömosit artığıyla değil. Öncül II doğrudur: tip II pnömositler (granüler pnömositler) hem surfaktan üreten hem de alveoler epitelin kök hücresi işlevi gören hücrelerdir; hasarda tip I pnömositlerin yerini doldurmak üzere prolifere olurlar. Bu IPF'nin erken döneminde koruyucu bir yanıttır. Öncül III yanlıştır: DLCO azalması hem alveoler-kapiller membranda difüzyon mesafesinin artmasından hem de fibrozisle kaybedilen alveoler yüzey alanının azalmasından kaynaklanır; her iki mekanizma birlikte katkıda bulunur. Dolayısıyla yalnızca II doğrudur."},{"id":8439,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, 6 aydır giderek kötüleşen proksimal kas güçsüzlüğü yakınmasıyla başvuruyor. Elektromiyografide miyopatik değişiklikler saptanıyor. Kas biyopsisinde tip II kas lifi atrofisi ve sarkolemma altında mitokondri birikimi izleniyor. Hastanın serum laktat düzeyi yüksek bulunuyor. Bu hastada aşağıdaki öncüllerden hangileri doğrudur?\nI. Oksidatif fosforilasyon bozukluğu sonucu ATP üretimi azalmıştır.\nII. Miyozin ağır zincir izoformlarında tip IIx'ten tip I'e geçiş beklenir.\nIII. Subsarkolemmal mitokondri birikimi, mitokondrial füzyon-fisyon dengesizliğini yansıtır.","options":["II ve III","I, II ve III","Yalnız I","I ve III","I ve II"],"correct":1,"exp":"Mitokondrial miyopatilerde oksidatif fosforilasyon zincir defekti nedeniyle ATP üretimi yetersiz kalır ve anaerobik metabolizma devreye girerek laktat birikir (Öncül I doğru). Tip II liflerin oksidatif kapasitesi daha düşük olduğundan bu lifler atrofiye uğrarken; kronik enerji yetersizliği ve kullanım değişikliği nedeniyle kalan liflerde tip I (yavaş, oksidatif) lif yönünde izoform kayması gözlenir (Öncül II doğru). Subsarkolemmal mitokondri birikimi, 'ragged red fiber' görünümüne yol açar ve mitofaji ile fisyon-füzyon dengesizliğinin histolojik karşılığıdır (Öncül III doğru). Dolayısıyla üç öncül de doğrudur."},{"id":8440,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya sakubitril/valsartan tedavisi başlanıyor. Tedavinin yürütülmesi sırasında plazma BNP düzeyi düşmeyip aksine artmaya devam etmektedir; ancak NT-proBNP düzeyleri belirgin şekilde azalmaktadır. Bu durumun en olası açıklaması hangisidir?","options":["Sakubitrilin nötral endopeptidazı inhibe ederek BNP yıkımını azaltması ve BNP'nin biyolojik olarak aktif kalmasıdır.","NT-proBNP'nin nöroendopeptidaz substratı olması nedeniyle yıkımının engellenmesidir.","BNP'nin miyokard fibrozisinin biyobelirteci olup, fibrozis gerilince yükseldiğini yansıtmasıdır.","Nörohumoral aktivasyonun baskılanamaması nedeniyle kalp yetmezliğinin ilerlediğini gösterir.","Valsartanın anjiyotensin reseptörünü bloke ederek natriüretik peptid salınımını artırmasıdır."],"correct":0,"exp":"Sakubitril, nörilysin (nötral endopeptidaz, NEP) enzimini inhibe eder. BNP, NEP'in bir substratıdır; dolayısıyla ilaç tedavisiyle BNP yıkımı azalır ve plazma BNP konsantrasyonu yükselir ya da düşmez. Buna karşın NT-proBNP, NEP substratı değildir ve dolayısıyla ilaçtan etkilenmez; NT-proBNP düzeyinin azalması, gerçek anlamda hemodinamik yükün ve miyokard duvar stresinin gerildiğini gösterir. Bu nedenle sakubitril/valsartan alan hastalarda tedavi yanıtını değerlendirmek için BNP değil NT-proBNP kullanılmalıdır."},{"id":8441,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, 2 haftadır çift görme ve sağ gözde ağrısız görme kaybı yakınmalarıyla başvuruyor. Nörolojik muayenede internükleer oftalmopleji saptanıyor. MR görüntülemede periventriküler beyaz cevherde demiyelinizasyon odakları izleniyor. Bu hastada aşağıdaki öncüllerden kaç tanesi yanlıştır?\nI. Etkilenen aksonlarda ranvier boğumları arasındaki mesafe kısalır.\nII. Saltatorik iletim bozulduğu için iletim hızı düşer.\nIII. Oligodendrosit başına düşen akson sayısı periferik sinir sistemine kıyasla daha fazladır.\nIV. Lezyon bölgesinde aksiyon potansiyeli eşiği düşer.","options":["Hiçbiri yanlış değildir","3","2","4","1"],"correct":2,"exp":"Öncül I yanlıştır: Miyelin kaybı ranvier boğumlarını ortadan kaldırmaz ya da kısaltmaz; demiyelinizasyonda internodal segment bozulur ve saltatorik iletim sürekli iletiyle ikame edilmek zorunda kalır, boğum mesafesi kısalmaz. Öncül II doğrudur: Miyelin kılıfın kaybıyla saltatorik iletim bozulur ve iletim hızı belirgin şekilde düşer. Öncül III doğrudur: SSS'de bir oligodendrosit 20-50 akson segmentini sarar; periferik sinir sisteminde Schwann hücresi birebir bir akson segmentini sarar. Öncül IV yanlıştır: Demiyelinizasyonda aksiyon potansiyeli eşiği yükselir, çünkü membran kapasitansı artar ve depolarizasyon için gerekli akım miktarı çoğalır. Yanlış öncüller I ve IV olmak üzere 2 tanedir."},{"id":8442,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"67 yaşında diyabetik erkek hasta, rutin kontrolünde idrarda mikroalbüminüri saptanması üzerine nefroloji polikliniğine yönlendiriliyor. Böbrek biyopsisinde mezangial matriks artışı ve bazal membranda kalınlaşma izleniyor. Hastaya anjiyotensin dönüştürücü enzim inhibitörü başlanıyor. Bu ilacın diyabetik nefropati seyrindeki koruyucu etkisinin temel mekanizmasını en doğru yansıtan ifade hangisidir?","options":["Afferent arteriyol tonusunu artırarak glomerüler filtrasyon hızını hızla normalleştirir.","Efferent arteriyol direncini düşürerek glomerüler kapiller basıncı azaltır ve hiperfiltrasyon hasarını yavaşlatır.","Tübüler bazal membran sentezini durdurup proteinüriyi azaltır.","Mezangial hücre proliferasyonunu doğrudan bloke ederek skleroza yol açan büyüme faktörlerini inhibe eder.","Proksimal tübül Na-glukoz ko-transporter aktivitesini azaltarak tübüler hasarı önler."],"correct":1,"exp":"Diyabetik nefropatinin erken döneminde anjiyotensin II, efferent arteriyolde baskın olarak vazokonstriksiyon yaparak glomerüler kapiller hidrostatik basıncı artırır ve hiperfiltrasyon yaratır. ACE inhibitörleri anjiyotensin II oluşumunu azaltarak efferent arteriyol direncini düşürür; bu sayede glomerüler kapiller basınç ve filtrasyon fraksiyonu düşer, hiperfiltrasyon hasarı yavaşlar ve proteinüri azalır. Bu etki, ilacın diyabetik nefropatideki koruyucu rolünün temel hemodinamik mekanizmasıdır."},{"id":8443,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Periferik kan yaymasında hedef hücre (target cell / kodosit) görünümü aşağıdaki durumların hangisinde beklenmez?","options":["Karaciğer yetmezliği","Talasemi majör","Demir eksikliği anemisi","Herediter sferositoz","Dalak çıkarılması sonrası"],"correct":3,"exp":"Hedef hücreler (kodositler), yüzey alanı/hacim oranının artmasıyla oluşur; demir eksikliği anemisinde (hipokromi ve mikrositoz), talasemide (artmış HbA2/HbF ile anormal membran), karaciğer yetmezliğinde (membrana kolesterol birikmesi) ve splenektomi sonrasında (dalak süzme işlevinin kaybolması) görülür. Herediter sferositozda ise tam tersine spektrin-ankyrin defekti nedeniyle hücre küçülüp yuvarlaklaşır ve yüzey alanı azalır; bu nedenle sferosite dönüşüm olur, hedef hücre oluşumu beklenmez."},{"id":8444,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"45 yaşında sigara içmeyen kadın hasta, 1 yıldır süren kuru öksürük ve egzersiz dispnesi yakınmasıyla başvuruyor. Yüksek rezolüsyonlu BT'de bilateral bazal baskın retiküler opasiteler ve balpeteği görünümü izleniyor. Solunum fonksiyon testinde FVC: %58, FEV1/FVC: 0,88 bulunuyor. Bronkoalveoler lavajda lenfosit oranı %8 ve nötrofil oranı %15 olarak saptanıyor. Bu hastada aşağıdaki öncüllerden hangileri doğrudur?\nI. Tip II pnömosit hiperplazisi, hasarlı tip I pnömositlerin yenilenmesine yönelik koruyucu bir yanıttır.\nII. Surfaktan üreten hücrelerin kaybı alveolar yüzey gerilimini artırır.\nIII. BAL nötrofil predominansı lenfositik alveolit ile uyumlu olup tanıyı destekler.\nIV. Restriktif patern, alveolar duvar fibrozisi nedeniyle akciğer kompliyansının azalmasını yansıtır.","options":["I ve II","II ve IV","I, II ve IV","I, III ve IV","I, II, III ve IV"],"correct":2,"exp":"Klinik tablo idiyopatik pulmoner fibrozis (IPF) ile uyumludur. Öncül I doğrudur: Tip I pnömositler alveolar gaz değişimini sağlar ve hasara karşı savunmasızdır; Tip II pnömositler rezerv hücre olarak prolifere olarak hasarlı alanları onarmaya çalışır. Öncül II doğrudur: Tip II pnömositlerden salgılanan surfaktan yüzey gerilimini düşürür; bu hücrelerin işlev kaybı yüzey gerilimini artırır ve alveolar kollaps eğilimini güçlendirir. Öncül III yanlıştır: BAL'da lenfosit predominansı hipersensitivite pnömonitisi ile uyumludur; IPF'de nötrofil ve eozinofil hakimiyeti görülür, nötrofil predominansı lenfositik alveolit tanımına girmez. Öncül IV doğrudur: Fibrozis, akciğer parankiminin sertleşmesine yol açarak kompliyansı azaltır; bu durum FVC'nin düşük, FEV1/FVC oranının normal veya yüksek olduğu restriktif bir paternle kendini gösterir. Doğru öncüller I, II ve IV'tür."},{"id":8445,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, progresif proksimal kas güçsüzlüğü ve egzersiz sonrası kasılma yakınmasıyla başvuruyor. Aile öyküsünde benzer şikayetler mevcut. Elektromiyografide miyotonik deşarjlar saptanıyor, serum kreatin kinaz düzeyi hafif yüksek bulunuyor. Kas biyopsisinde tip 1 kas liflerinde atrofi ve santral nükleusların artışı izleniyor. Bu hastanın kas biyopsisi bulgularında hangi ultrastrüktürel değişikliğin eşlik etmesi beklenir?\nI. Sarkomerlerde Z diski düzensizliği\nII. Mitokondri sayısında belirgin artış\nIII. Transvers tübül sisteminde dilatasyon\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II ve III","Yalnız II","I ve III","Yalnız I","I, II ve III"],"correct":2,"exp":"Miyotonik distrofi (Steinert hastalığı) tip 1 kas lifi atrofisi, santral nükleuslar ve miyotonik deşarjlarla karakterizedir. Ultrastrüktürel düzeyde sarkomerlerde Z diski düzensizliği (tip 1 liflerinin primer etkilenmesiyle ilişkili) ve transvers tübül sisteminde dilatasyon izlenir; bu iki bulgu miyotonik bozukluklarda kalsiyum homeostazı bozukluğunu yansıtır. Mitokondri sayısında belirgin artış ise mitokondriyal miyopati bulgusudur ve bu tabloda beklenmez. Dolayısıyla I ve III doğrudur."},{"id":8446,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında diyabetik erkek hasta, düzenli insülin kullanan, son 6 aydır giderek artan bacak ödemi ve yorgunluk yakınmasıyla başvuruyor. İdrar tetkikinde 24 saatlik protein atılımı 4,8 g, serum albumin 2,1 g/dL, serum kreatinin 1,3 mg/dL. Böbrek biyopsisinde glomerüler bazal membranda yaygın kalınlaşma ve mezangiyumda nodüler genişleme (Kimmelstiel-Wilson nodülleri) saptanıyor. Bu hastada podositlere ait aşağıdaki değişikliklerden hangisi birincil olarak proteinüriye yol açan histolojik bulgudur?","options":["Podosit proliferasyonu ve yarıkların kapanması","Podositlerin parietal epitele transformasyonu","Glomerüler filtrasyon membranında kollajen tip IV birikimi","Mezangiyum hücrelerinin podosit aralığına göçü","Podosit ayak çıkıntılarının silinmesi"],"correct":4,"exp":"Diyabetik nefropatide masif proteinürinin birincil ultrastrüktürel nedeni podosit ayak çıkıntılarının (ayaksı çıkıntı) yaygın silinmesidir. Bu silinme, yarık diyaframını oluşturan nefrin ve podosinin ekspresyonunu bozarak glomerüler filtre seçiciliğini ortadan kaldırır. Kimmelstiel-Wilson nodülleri ve bazal membran kalınlaşması önemli histolojik bulgulardır; ancak proteinürinin doğrudan nedeni podosit hasarıdır. Diğer seçeneklerdeki değişiklikler bu tablonun birincil mekanizmasını açıklamaz."},{"id":8447,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, 2 haftadır sağ gözde görme bulanıklığı, sol bacakta uyuşma ve denge bozukluğu yakınmasıyla başvuruyor. MR'da periventriküler ve jukstakortikal alanlarda T2 hiperintensite alanları saptanıyor. Beyin omurilik sıvısı incelemesinde oligoklonal bantlar pozitif. Tedavisinde yüksek doz kortikosteroid başlanıyor. Hastalığın patogenezinde rol oynayan hücre tipine ilişkin aşağıdaki öncüller değerlendirildiğinde kaç tanesi doğrudur?\nI. Santral sinir sistemindeki miyelin kılıfını oluşturan hücreler oligodendrositlerin hasarına uğrar.\nII. Periferik sinirdeki Schwann hücresi, santral sinir sisteminde oligodendrositlerin işlevsel karşılığıdır.\nIII. Her bir oligodendrosit, birden fazla aksonun miyelin kılıfını oluşturabilir.\nIV. Kortikosteroidler, bu hastalıkta remyelinizasyonu doğrudan uyararak etki eder.","options":["4","Hiçbiri","2","3","1"],"correct":3,"exp":"çok sayıda sklerozda I, II ve III numaralı öncüller doğrudur; dolayısıyla 3 tanesi doğrudur. I: MS'de santral miyelin kılıfını oluşturan oligodendrositler otoimmün hasara uğrar. II: Periferik sinirdeki Schwann hücresi SNS'deki miyelin yapımından sorumluyken, oligodendrositler MSS'de aynı işlevi görür; bu karşılaştırma doğrudur. III: Bir oligodendrosit 20-50 farklı akson segmentinin miyelinizasyonundan sorumlu olabilir; Schwann hücresinin aksine bu özellik oligodendrositlere özgüdür. IV yanlıştır: Kortikosteroidler antiinflamatuvar ve kan-beyin bariyeri stabilizasyonu mekanizmasıyla akut atağı kısaltır, remyelinizasyonu doğrudan uyarmaz."},{"id":8448,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"45 yaşında erkek hasta, 8 yıldır gastroözofageal reflü hastalığı nedeniyle proton pompası inhibitörü kullanmaktadır. Yapılan endoskopide alt özofagusta kırmızımsı kadifemsi görünüm izleniyor; biyopside yassı epitelin yerini kolumnar epitelin ve goblet hücrelerinin aldığı saptanıyor. Bu hastada izlenen dönüşüm sürecinde hangi epitel tipi oluşmuştur ve bu değişikliğin en önemli klinik önemi nedir?","options":["Psödostratifiye epitel; mukus sekresyonunu bozar","Skuamöz metaplazi; özofajit riskini artırır","İntestinal metaplazi; adenokarsinoma zemin hazırlar","Geçiş epiteli; reflü semptomlarını kötüleştirir","İntestinal metaplazi; peptik ülser riskini artırır"],"correct":2,"exp":"Barrett özofagusu, kronik gastroözofageal reflüye bağlı olarak alt özofagustaki çok katlı yassı epitelin özelleşmiş intestinal metaplazi (kolumnar + goblet hücreli epitel) ile yer değiştirmesidir. Bu dönüşümün en önemli klinik önemi, özofagus adenokarsinoması için anlamlı bir premalign zemin oluşturmasıdır. Goblet hücrelerinin varlığı tanı koydurucudur ve bu hücreler müsin sekrete ederek intestinal tipte bir mukozayı temsil eder."},{"id":8449,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, tekrarlayan pürülan enfeksiyonlar, parsiyel oküler albinizm ve gümüş renkli saçlarla başvuruyor. Periferik yaymasında granülositlerde dev azurofilik granüller dikkati çekiyor. Kemik iliği incelemesinde granülosit serisinin matürasyon bloğu izleniyor. Bu hastada aşağıdakilerden hangisi beklenen laboratuvar ve fonksiyonel bulgudur?","options":["T lenfosit yokluğu ve düşük immünglobülin düzeyleri","Nötrofil kemotaksis bozukluğu ve degranülasyon yetersizliği","Kompleman C3 düzeyinde belirgin düşüklük","Nitroblue tetrazolium testi pozitifliği ve artmış süperoksit üretimi","Trombosit fonksiyon bozukluğu ve uzamış kanama zamanı"],"correct":1,"exp":"Tanımlanan tablo Chediak-Higashi sendromudur; LYST genindeki mutasyon nedeniyle lizozomal trafik bozukluğu mevcuttur. Dev granüller, lizozomların anormal füzyonuyla oluşur. Bu hastalarda nötrofil kemotaksis belirgin olarak bozulmuş, fagolizozom oluşumu ve degranülasyon yetersizdir; bu nedenle katalaz-pozitif bakterilere karşı savunma ileri derecede azalmıştır. NBT testi Kronik Granülomatöz Hastalığa özgüdür ve burada beklenmez. T hücre yokluğu SCID tablosunu tanımlar. Kompleman düşüklüğü farklı bir defekti gösterir."},{"id":8450,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":2,"q":"Kardiyak miyositler, iskelet kası liflerinden farklı olarak fiziksel stres altında hipertrofi ile yanıt verir. Kardiyak miyositlerin bu yanıtı, iskelet kası liflerine kıyasla farklı kılan temel histolojik özellik hangisidir?","options":["Kalp kasında hücrelerin terminal diferansiye olması ve mitozla çoğalma kapasitesini yitirmiş olması","T tübül sisteminin kardiyak miyositlerde bulunmaması","Kardiyak miyositlerin tek çekirdekli olması","İnterkalar diskler aracılığıyla oluşan fonksiyonel sinsisyum yapısı","Kalp kasında troponin izoformlarının farklı olması"],"correct":0,"exp":"Kardiyak miyositler erken postnatal dönemde mitoz kapasitesini kaybeder ve terminal diferansiye hücreler haline gelir. Bu nedenle miyokard hasarına veya kronik basınç yüküne yanıt olarak hücre sayısı artışı (hiperplazi) yerine mevcut hücrelerde büyüme (hipertrofi) gerçekleşir. İnterkalar diskler (gap junction + dezmozom) elektriksel ve mekanik bütünlüğü sağlayan önemli yapılardır ancak hipertrofik yanıtı iskelet kasından ayıran birincil özellik değildir. İskelet kası da postnatal dönemde büyük ölçüde terminal diferansiyedir; ancak uydu hücre havuzu mevcuttur ve kardiyak kasta bu mekanizma yok denecek kadar azdır."},{"id":8451,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor sırasında ortaya çıkan göğüs ağrısı ve nefes darlığı yakınmasıyla başvuruyor. Yapılan ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya ACE inhibitörü ve beta bloker başlanıyor. Tedavinin 6. haftasında hastanın semptomları belirgin biçimde azalıyor. Bu hastada klinik iyileşmeye en çok katkıda bulunan hücresel süreç hangisidir?","options":["Sinüs düğümü hücrelerinde If akımının kalıcı olarak baskılanması","Kardiyomiyositlerde hipertrofik sinyal yolaklarının aktivasyonu","Koroner arteriyollerde düz kas hücrelerinin proliferasyonu","Miyokard interstisyumundaki fibroblastların kollajen sentezini artırması","Adrenerjik reseptör yoğunluğunun normalizasyonu ve ters yeniden şekillenme"],"correct":4,"exp":"Kronik kalp yetersizliğinde uzun süreli sempatik aktivasyon, kardiyomiyositlerde beta-1 adrenerjik reseptörlerin down-regülasyonuna ve ventriküler dilatasyon ile sferikal yeniden şekillenmeye (remodeling) yol açar. ACE inhibitörleri anjiotensin II'nin fibroz ve hipertrofi uyarısını keserken, beta blokerler reseptör yoğunluğunu yukarı doğru regüle ederek (up-regulation) miyokardın katekolaminlere verdiği patolojik yanıtı azaltır. Bu süreç 'ters yeniden şekillenme' (reverse remodeling) olarak adlandırılır; EF artışı ve semptom iyileşmesi bu mekanizmayla açıklanır. Kollajen sentezi artışı fibrozisi kötüleştirir, hipertrofik sinyal aktivasyonu hastalığın kendisini oluşturur, düz kas proliferasyonu bu tablonun primer belirleyicisi değildir, If baskılanması ise sinüs hızını düşürür ancak yeniden şekillenmeyi açıklamaz."},{"id":8452,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 yıldır süren egzersiz dispnesi ve tekrarlayan hemoptizi yakınmasıyla başvuruyor. Yüksek rezolüsyonlu BT'de bilateral yaygın buzlu cam görünümü ve küçük kistik lezyonlar saptanıyor. Biyopsi materyalinde HMB-45 ile boyanan düz kas benzeri hücre proliferasyonu izleniyor. Bu hastalıkta patolojik sürecin altta yatan hücresel temeli hakkında aşağıdaki öncüller değerlendiriliyor:\nI. Hastalık, interstisyumu infiltre eden anormal düz kas benzeri hücrelerin (LAM hücreleri) mTOR yolağının aşırı aktivasyonu ile çoğalmasından kaynaklanır.\nII. LAM hücreleri, tip II pnömositler ile aynı yüzey belirteçlerini taşıdığından ikisi arasında morfolojik ayrım yapmak mümkün değildir.\nIII. Östrojenin bu hücre proliferasyonunu uyardığına dair kanıt, doğurganlık çağındaki kadınlarda hastalığın daha şiddetli seyretmesi ve menopoz sonrası stabilizasyon ile desteklenmektedir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","Yalnız III","I ve II","I ve III","I, II ve III"],"correct":3,"exp":"Lenfanjiyoleiomyomatozis (LAM), TSC1/TSC2 gen mutasyonu sonucu mTOR yolağının konstitüsyonel aktivasyonuna bağlı anormal düz kas benzeri hücre proliferasyonu ile karakterizedir; bu nedenle I doğrudur. LAM hücreleri HMB-45 pozitifliği, düz kas aktin ve östrojen/progesteron reseptörleri gibi kendine özgü belirteçler taşır ve tip II pnömositlerden histolojik olarak kolaylıkla ayrılır; bu nedenle II yanlıştır. Hastalığın yalnızca doğurganlık çağındaki kadınlarda ortaya çıkması, gebelikte kötüleşmesi ve menopoz sonrası stabilize olması östrojenin LAM hücresi üzerindeki uyarıcı etkisini kanıtlar; III doğrudur. mTOR inhibitörü olan everolimus, bu mekanizma temel alınarak tedavide kullanılmaktadır."},{"id":8453,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında erkek hasta, 3 haftadır devam eden çift görme, yutma güçlüğü ve gün içinde ilerleyici yorgunluk yakınmasıyla başvuruyor. Muayenede ptoz ve proksimal kas güçsüzlüğü saptanıyor; istirahatle semptomlar kısmi olarak düzeliyor. Tensilon testi pozitif bulunuyor. Hastaya piridostigmin başlanmasına karşın yanıt yetersiz kalıyor ve timoma saptandıktan sonra timektomiye karar veriliyor. Bu klinik tabloda sinir-kas kavşağındaki histofizyolojik değişiklikler hakkında aşağıdakilerden hangisi doğrudur?","options":["Postsinaptik membranda nikotinik asetilkolin reseptörlerine karşı antikorlar reseptör yoğunluğunu azaltır ve nöromüsküler iletimi bozar","Asetilkolin vezikülleri presinaptik terminalde birikir ancak ekzositoz mekanizması geri dönüşümsüz biçimde bloke olur","Presinaptik terminal boyunca voltaj kapılı kalsiyum kanallarına karşı antikor oluşumu asetilkolin salınımını engeller","Myelinli motor sinir liflerinde demiyelinizasyon periferik iletim hızını yavaşlatarak nöromüsküler bağlantıyı keser","Kas liflerinde T-tübül sisteminin yapısal bozulması kalsiyum salınımını engeller ve gevşek felce yol açar"],"correct":0,"exp":"Myasthenia gravis'te otoimmün antikor, postsinaptik motor son plakdaki nikotinik asetilkolin reseptörlerine (AChR) bağlanarak hem reseptörü bloke eder hem de kompleman aracılı hasara ve reseptörün artmış internalizasyonuna (endositoz) yol açar. Bu durum postsinaptik reseptör yoğunluğunu azaltır, miniyal son plak potansiyellerinin amplitüdünü düşürür ve iletim yetersiz kalır. Tekrarlayan uyarımda güvenlik marjı aşılır ve yorgunluk ortaya çıkar. Piridostigmin asetilkolinesterazı inhibe ederek yarık içinde ACh yoğunluğunu artırır; azalmış reseptörler için daha fazla ligand sağlar. Voltaj kapılı kalsiyum kanalı antikorları Lambert-Eaton sendromunu tanımlar; demiyelinizasyon Guillain-Barré'yi, T-tübül bozulması malign hipertermiyı, presinaptik ekzositoz blokajı ise botulinum toksini zehirlenmesini açıklar."},{"id":8454,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"19 yaşında erkek hasta, iki gün önce üst solunum yolu enfeksiyonu geçirdikten hemen sonra başlayan makroskopik hematüri yakınmasıyla başvuruyor. İdrar sedimentinde eritrosit silendirleri saptanıyor; serum IgA düzeyi yüksek bulunuyor. Hastada en olası patolojik süreç hangi yapıyı birincil olarak etkiler?","options":["Podosit ayak çıkıntılarını ve nefrin bağlantılarını","Glomerüler bazal membran tip IV kollajenini","Mezangiyum hücrelerini ve matriks birikimini","Proksimal tübül fırçamsı kenar epitelini","Jukstaglomerüler aparatın renin salgılayan granüler hücrelerini"],"correct":2,"exp":"IgA nefropatisi (Berger hastalığı), enfeksiyon tetikleyicisinin ardından 1-2 gün içinde hematüri ile başvurması, sinüfarenjitik hematüri paterni ve yüksek serum IgA düzeyiyle tanınır. Patolojik süreçte galaktozilasyon defektli IgA1 molekülleri mezangiyumda birikerek mezangiyel hücre proliferasyonunu ve matriks genişlemesini uyarır; C3 aktivasyonu lokal inflamasyonu artırır. Eritrosit silendirleri ve dismorfik eritrositler glomerüler orijini destekler. Tip IV kollajen mutasyonu Alport sendromunu, podosit harabiyeti nefrotik sendromu (minimal change, FSGS), proksimal tübül hasarı akut tübüler nekrozu, JGA granüler hücre patolojisi ise renal hipertansiyonu düşündürür."},{"id":8455,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hastada halsizlik, tekrarlayan enfeksiyonlar ve pansitopeni saptanıyor. Periferik yaymada olgun görünümlü küçük lenfosit artışı, kemik iliğinde diffüz lenfositik infiltrasyon ve CD5+/CD19+/CD23+ immünfenotip belirleniyor. Bu hastalıkta aşağıdakilerden hangisi en kötü prognozla ilişkilidir?","options":["IGHV geninde somatik hipermutasyon bulunması","İzole 13q delesyonu","17p delesyonu (TP53 kaybı)","Trizomi 12 olmaksızın normal karyotip","ZAP-70 negatifliği"],"correct":2,"exp":"İmmünfenotip (CD5+/CD19+/CD23+, olgun küçük lenfositler) kronik lenfositik lösemi ile uyumludur. 17p delesyonu (TP53 kaybı) fludarabin bazlı tedavilere primer dirençle ilişkili olup en kötü prognostik sitogenetik belirteçtir. Buna karşılık izole 13q delesyonu ve IGHV mutasyonlu (hipermutasyon bulunan) olgular daha iyi seyreder."},{"id":8456,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Ejeksiyon fraksiyonu azalmış kalp yetersizliği olan bir hastaya sakubitril/valsartan başlanıyor. Tedavi sonrasında natriüretik peptidlerin yorumlanması ve ilacın renin-anjiyotensin-aldosteron sistemi üzerindeki etkisiyle ilgili aşağıdakilerden hangisi doğrudur?","options":["BNP azalır çünkü sakubitril neprilizin aktivitesini artırır; aldosteron salınımı yükselir.","BNP ve NT-proBNP mutlaka aynı oranda yükselir; RAAS aktive olur.","NT-proBNP neprilizin tarafından yıkıldığı için tedavi sırasında güvenilir değildir.","İlaç yalnızca diüretik etki gösterir ve RAAS üzerinde etkili değildir.","NT-proBNP azalabilirken BNP neprilizin inhibisyonu nedeniyle geçici olarak yükselebilir; valsartan AT1 reseptörünü bloke eder."],"correct":4,"exp":"Sakubitril neprilizin inhibisyonuyla natriüretik peptidlerin yıkımını azaltır; bu nedenle BNP erken dönemde yükselebilir veya yorumlanması güçleşebilir. NT-proBNP neprilizin substratı değildir ve tedavi yanıtında daha kullanışlıdır. Valsartan, AT1 reseptörünü bloke ederek renin-anjiyotensin-aldosteron sisteminin etkilerini baskılar."},{"id":8457,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan pnömotoraks atakları nedeniyle araştırılıyor. Akciğer biyopsisinde tip II pnömosit hiperplazisi ve düz kas proliferasyonu saptanıyor. Serum VEGF-D düzeyi yüksek bulunuyor. Hastanın adet döngüsüyle ilişkili semptom artışı tarif ettiği öğreniliyor. Bu hastaya başlanan tedavinin etkisini açıklayan aşağıdaki ifadelerden hangileri doğrudur?\nI. Tedavi, mTOR yolağını inhibe ederek anormal düz kas proliferasyonunu baskılar.\nII. Tedavi, östrojen reseptörü antagonizması yoluyla tümörün büyümesini durdurmaktadır.\nIII. Tedavi süresince hastalığın tamamen gerilemesi beklenir, bu nedenle ilaç kesildiğinde nüks görülmez.\nIV. Sirolimus bu hastalıkta onaylı tedavi seçenekleri arasındadır.","options":["I, III ve IV","I, II ve IV","II ve III","I ve IV","Yalnız I"],"correct":3,"exp":"Tanı lenfanjiyoleiomiyomatozis (LAM) olup sporadik ya da tüberous skleroz kompleksiyle ilişkili olabilir. LAM'da mTOR yolağı anormal biçimde aktive olur ve bu nedenle mTOR inhibitörü olan sirolimus (rapamisin) tedavide kullanılır. Öncül I doğrudur. Öncül IV doğrudur; sirolimus LAM'da FDA onaylı tek hastalık modifiye edici tedavidir. Öncül II yanlıştır; sirolimus östrojen antagonisti değildir. Öncül III yanlıştır; sirolimus hastalığı yavaşlatır ancak tam remisyon sağlamaz, ilaç kesildiğinde nüks sık görülür. Bu nedenle doğru öncüller I ve IV'tür."},{"id":8458,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında erkek hasta, 6 aydır süren hematüri ve proteinüri nedeniyle nefroloji polikliniğine başvuruyor. Böbrek biyopsisinde ışık mikroskobisinde mezangial genişleme, immünfloresan mikroskobisinde IgA birikimi ve elektron mikroskobisinde mezangial elektron dens depozitler saptanıyor. Hastanın idrar protein miktarı 1,8 g/gün olarak ölçülüyor, kan basıncı 148/92 mmHg. Bu hastaya başlanan renin-anjiyotensin sistemi blokajının böbrek üzerindeki hemodinamik etkisi aşağıdakilerden hangisidir?","options":["Podosit apoptozunu tetikleyerek proteinüriyi artırır","Efferent arteriyol vazokonstüksiyonunu azaltarak intraglomerüler basıncı düşürür","Proksimal tübülden sodyum reabsorpsiyonunu doğrudan inhibe eder","Mezangial hücre kontraksiyonunu artırarak filtrasyon yüzeyini azaltır","Afferent arteriyol vazodilatasyonu ile glomerüler filtrasyon hızını artırır"],"correct":1,"exp":"IgA nefropatisinde RAS blokajı (ACE inhibitörü veya ARB) birincil antiproteinürik tedavidir. Anjiyotensin II, efferent arteriyolde baskın vazokonstriksiyon yaparak intraglomerüler hidrostatik basıncı yükseltir. RAS blokajı bu efferent vazokonstriksiyonu azaltır; böylece intraglomerüler basınç düşer ve proteinüri azalır. Afferent arteriyol dilatasyonu RAS blokajının birincil etkisi değildir. Mezangial kontraksiyon anjiyotensin II ile artar, blokajda azalır; ancak soru hemodinamik etkiyi sormaktadır. Proksimal tübüler etki dolaylı ve ikincil düzeydedir."},{"id":8459,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"19 yaşında erkek hasta, trafik kazası sonrası sol alt ekstremitede güç kaybı ve his azalması ile acil servise getiriliyor. Yapılan incelemede spinal kord hasarı saptanıyor. Hasarın olduğu bölgede Wallerian dejenerasyon geliştiği öğreniliyor. Wallerian dejenerasyona ilişkin aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Hasar distalinde akson ve miyelin kılıfı dejenerasyona uğrar.\nII. Schwann hücreleri sinir rejenerasyonu için rehber tüp oluşturur.\nIII. Merkezi sinir sisteminde periferik sinir sistemine kıyasla rejenerasyon daha başarılıdır.\nIV. Makrofajlar dejene olmuş miyelin artıklarını fagosite eder.","options":["2","3","4","1","Hiçbiri"],"correct":1,"exp":"Öncül I doğrudur; Wallerian dejenerasyonda lezyon distalinde akson ve miyelin yıkımı gerçekleşir. Öncül II doğrudur; periferik sinirde Schwann hücreleri Büngner bantlarını oluşturarak rejenerasyon için tüp yapısı sağlar. Öncül III yanlıştır; santral sinir sisteminde rejenerasyon periferik sisteme göre çok daha sınırlıdır; inhibitör çevre faktörleri (Nogo-A, MAG, OMgp) ve oligodendrositlerin rehber tüp oluşturamaması başlıca nedenlerdir. Öncül IV doğrudur; hem periferik hem de merkezi sinir sisteminde makrofajlar ve mikroglia hücreleri miyelin kalıntılarını fagosite eder. Doğru öncül sayısı 3'tür (I, II, IV)."},{"id":8460,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Kemik iliğinde üretilen ve olgunlaştıktan sonra dolaşıma katılan megakaryositlerden köken alan hücreler, hemostazın primer fazında hangi yapıyla etkileşime girerek trombosit tıkacı oluşturmaya başlar?","options":["Doku plazminojen aktivatörü","Fibrin ağı","Endotel yüzeyindeki trombomodülin","Von Willebrand faktörün trombosit GP Ib reseptörüne bağlanmasıyla subendotelyal kollajen","Hasarlı damarda açığa çıkan subendotelyal kollajen"],"correct":3,"exp":"Primer hemostazda trombositler önce von Willebrand faktör (vWF) aracılığıyla subendotelyal kollajene tutunur; bu bağlanma yüksek kesme geriliminde GP Ib-IX-V reseptörü üzerinden gerçekleşir ve trombosit aktivasyonunu başlatır. Aktivasyon sonrası GP IIb/IIIa reseptörü fibrinojen ve vWF'ye bağlanarak trombosit agregasyonunu sağlar. Fibrin ağı sekonder hemostazda koagülasyon kaskadının sonucunda oluşur. Trombomodülin ise antikoagülan bir moleküldür. Doku plazminojen aktivatörü fibrinoliz sistemine aittir."},{"id":8461,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, uzun süredir devam eden gastroözofajeal reflü hastalığı nedeniyle takip edilmektedir. Üst gastrointestinal endoskopide özofagus alt ucunda skuamöz epitelin kolumnar epitel ile yer değiştirdiği saptanıyor ve biyopsi alınıyor. Patoloji raporunda goblet hücreleri içeren intestinal metaplazi olduğu bildiriliyor. Bu dönüşüm sürecine ilişkin aşağıdaki öncüllerden hangileri doğrudur?\nI. Bu değişim Barrett özofagusu olarak adlandırılır ve malign dönüşüm riski taşır.\nII. CDX2 transkripsiyon faktörü bu metaplastik dönüşümde belirleyici rol üstlenir.\nIII. En sık gelişen malignite skuamöz hücreli karsinomdur.\nIV. Asit supresyon tedavisi metaplaziyi tam olarak geri döndürebildiğinden cerrahi gereksizdir.","options":["I, II ve III","I, II ve IV","II ve IV","Yalnız I","I ve II"],"correct":4,"exp":"Barrett özofagusu, kronik asit hasarına yanıt olarak özofageal skuamöz epitelin goblet hücresi içeren kolumnar epitele dönüşmesidir (Öncül I doğru). CDX2, bağırsak farklılaşmasında anahtar transkripsiyon faktörüdür ve Barrett metaplazisinin gelişiminde kritik rol oynar (Öncül II doğru). Barrett özofagusunda gelişen malignite skuamöz değil adenokarsinomdur; özofagus adenokarsinomları sıklıkla Barrett zemininde ortaya çıkar (Öncül III yanlış). Asit supresyon tedavisi semptomları ve progresyonu yavaşlatabilir, ancak mevcut metaplaziyi tam olarak geri döndüremez; yüksek dereceli displazi varlığında ablasyon veya cerrahi gerekebilir (Öncül IV yanlış). Doğru öncüller I ve II'dir."},{"id":8462,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"28 yaşında erkek sporcu, ağır antrenman sonrası gelişen kas güçsüzlüğü ve koyu renkli idrar şikayetiyle acil servise başvuruyor. Serum kreatinin kinaz düzeyi belirgin yüksek, idrar miyoglobin pozitif saptanıyor. Hastaya yoğun intravenöz sıvı tedavisi başlanıyor ve idrar alkalinizasyonu planlanıyor. İdrar alkalinizasyonunun bu hastadaki temel amacı hangisidir?","options":["Miyoglobinin renal tübülüste presipitasyonunu önlemek","Tübüler sodyum reabsorpsiyonunu artırmak","Böbrekte renin salınımını baskılamak","Kas hücrelerinde glikojen yıkımını azaltmak","Serum miyoglobin klirensini artırmak"],"correct":0,"exp":"Rabdomiyolizde miyoglobin, asidik ortamda renal tübülüslerde ferrihemat kristalleri oluşturarak tıkanmaya ve direkt tübüler toksisiteye yol açar. İdrar pH'ını alkalize etmek (pH >6,5) miyoglobinin çözünürlüğünü artırır ve tübüler presipitasyonu önler. Bu mekanizma, akut tübüler nekroz gelişimini engellemede kritik rol oynar."},{"id":8463,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor dispnesi ve bacaklarda ödem şikayetiyle başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %30, sol ventrikül diyastol sonu basıncı yüksek bulunuyor. Tedaviye sakubitril/valsartan ekleniyor. Bu ilacın kardiyak yeniden yapılanma (remodeling) üzerine olan etkisinin temel fizyolojik dayanağı aşağıdakilerden hangisidir?","options":["Renin sekresyonunun artırılmasıyla koroner vazodilatasyonun uyarılması","Sempatik uyarının bloke edilmesiyle kalp hızının azaltılması","Natriüretik peptid yıkımının inhibisyonu ile kardiyomiyosit hipertrofisinin baskılanması","Anjiyotensin II sentezinin artırılarak afterload'ın düşürülmesi","Aldosteron salınımının doğrudan artırılarak sodyum atılımının sağlanması"],"correct":2,"exp":"Sakubitril, nötralisin (neprilizin) inhibitörüdür; bu enzim BNP ve ANP gibi natriüretik peptidleri yıkar. İnhibisyon sonucunda natriüretik peptid düzeyleri yükselir; bu peptidler kardiyomiyositlerde cGMP aracılı anti-hipertrofik ve antifibrotik etkiler göstererek patolojik yeniden yapılanmayı baskılar. Valsartan ise AT1 reseptörü blokajıyla sinerjistik etki sağlar."},{"id":8464,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında diyabetik kadın hasta, rutin kontrolde mikroalbüminüri saptanması üzerine değerlendiriliyor. Kan basıncı 148/92 mmHg, HbA1c %9,2 olarak ölçülüyor. Hastaya ACE inhibitörü başlanıyor. Aşağıdaki öncülleri değerlendirin:\nI. ACE inhibitörü, efferent arterioler direnci düşürerek intraglomerüler basıncı azaltır.\nII. İntraglomerüler hipertansiyon, mezangial hücre proliferasyonunu ve matriks birikimini uyarır.\nIII. Glomerüler filtrasyon bariyerindeki ilk etkilenen yapı tubuler bazal membrandır.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","II ve III","I, II ve III","Yalnız I","I ve II"],"correct":4,"exp":"ACE inhibitörleri, anjiyotensin II'nin efferent arterioler konstriksiyonunu bloke ederek intraglomerüler basıncı düşürür (I doğru). Kronik intraglomerüler hipertansiyon, mezangial hücreleri mekanik olarak uyararak proliferasyon ve ekstraselüler matriks artışına yol açar; bu da Kimmelstiel-Wilson lezyonlarının temelini oluşturur (II doğru). Glomerüler filtrasyon bariyerinde diyabette ilk etkilenen yapı glomerüler bazal membrandır, tubuler değil (III yanlış). Bu nedenle doğru öncüller I ve II'dir."},{"id":8465,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"35 yaşında kadın hasta, ani başlayan tek taraflı görme kaybı ve birkaç hafta önce geçip düzelen alt ekstremite güçsüzlüğü öyküsüyle başvuruyor. MRG'de periventriküler beyaz cevherde demiyelinizan plaklar saptanıyor. Hastalığın patogenezinde merkezi sinir sistemindeki iletim bozukluğuna yol açan başlıca histolojik değişiklik hangisidir?","options":["Oligodendrosit sayısının artmasıyla myelin overproduction gelişmesi","Miyelin kılıfının hasarı ile Ranvier boğumları arasındaki saltatory iletimin bozulması","Sinaps aralığında asetilkolin yıkımının artmasıyla nöromüsküler blok","Akson gövdesinde nörofilaman birikimi ile aksonal transport yavaşlaması","Schwann hücre proliferasyonunun neden olduğu kompresyon nöropatisi"],"correct":1,"exp":"çok sayıda skleroz, merkezi sinir sisteminde oligodendrositlerin oluşturduğu miyelin kılıfının otoimmün hasarıyla karakterizedir. Miyelin, Ranvier boğumları arasında saltatory (sıçramalı) iletimi sağlar; miyelin kaybı bu iletiyi ortadan kaldırarak aksiyon potansiyelinin yavaşlamasına veya tamamen bloke olmasına yol açar. Schwann hücreleri periferik sinir sistemine ait olup MS ile ilişkili değildir."},{"id":8466,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Aşağıdaki öncülleri değerlendirin:\nI. Tip II pnömositler, hasar gören Tip I pnömositlerin yenilenmesini sağlar.\nII. Surfaktan, yüzey gerilimini artırarak alveoler kollapsı önler.\nIII. Clara hücreleri (Club hücreleri), bronşiyollerde sekretuar işlev görür.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["3","0","2","Yalnız I ve III","1"],"correct":2,"exp":"Tip II pnömositler surfaktan sentezler ve Tip I hücrelerin hasarında prekürsör görevini üstlenerek rejenerasyonu sağlar (I doğru). Surfaktan, diopalmitoilfosfatidilkolin içeriğiyle alveol yüzeyindeki su tabakasının yüzey gerilimini DÜŞÜRÜR; bu sayede nefes verme sırasında alveollerin kollabe olmasını önler (II yanlış, 'artırır' ifadesi hatalı). Club hücreleri (eski adıyla Clara), terminal bronşiyollerde sitoplazmik sekresyon granülleri aracılığıyla proteaz inhibitörleri ve yüzey aktif maddeler salgılar (III doğru). Dolayısıyla I ve III doğru, II yanlış olduğundan 2 öncül doğrudur."},{"id":8467,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"48 yaşında erkek hasta, kronik ishal, yağlı dışkı ve kilo kaybı yakınmalarıyla başvuruyor. İnce barsak biyopsisinde villus atrofisi ve kript hiperplazisi saptanıyor. Glutensiz diyetle semptomların gerilediği görülüyor. Bu hastada malabsorbsiyonun primer fizyolojik mekanizması aşağıdakilerden hangisiyle en doğru açıklanır?","options":["Paneth hücrelerinin defensin sekresyonunun artmasıyla aktif transport inhibisyonu","Goblet hücre hiperplazisinin mukus tabakasını kalınlaştırarak diffüzyonu engellemesi","Kript derinleşmesinin enterosit transit süresini uzatarak aşırı emilime yol açması","Villus atrofisi nedeniyle emilim yüzey alanının azalması ve brush border enzim aktivitesinin kaybı","Lamina propriada plazma hücre birikiminin IgA sekresyonunu artırarak besin absorbsiyonunu azaltması"],"correct":3,"exp":"Çölyak hastalığında gliadine karşı gelişen otoimmün yanıt, enterosite zarar vererek villus atrofisine ve kompansatuar kript hiperplazisine yol açar. Villus atrofisi; emilim yüzey alanını dramatik biçimde azaltır ve brush border üzerindeki laktaz, sukraz, maltaz gibi disakkaridaz enzimlerinin kaybına neden olur. Bu çift etki, karbonhidrat, yağ ve protein emiliminde belirgin bozulmaya yol açarak malabsorbsyon tablosunu oluşturur."},{"id":8468,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan egzersiz intoleransı ve baldır kaslarında ağrı yakınmasıyla başvuruyor. Öyküsünden 3 yıldır yüksek doz statin kullandığı öğreniliyor. Kreatin kinaz düzeyi normalin 10 katı bulunuyor. Kas biyopsisinde tip I ve tip II liflerde vakuoler dejenerasyon ve mitokondriyal proliferasyon saptanıyor. Bu hastada kas hasarının temel nedeni olan mitokondriyal disfonksiyona yol açan mekanizma aşağıdaki hangi yapının fonksiyon kaybıyla açıklanır?","options":["Koenzim Q10 sentezinde azalma","T-tübül sisteminin geri dönüşümsüz depolarizasyonu","Miyozin ağır zinciri izoform değişimi","Sarkoplazmik retikulumdan Ca²⁺ salınımının artması","Titin proteinin yapısal bütünlüğünün bozulması"],"correct":0,"exp":"Statinler, HMG-CoA redüktaz inhibisyonu yoluyla kolesterol sentezini baskılarken mevalonat yolundaki ara ürün olan geranil-geranil pirofosfat ve farnesil pirofosfat sentezini de azaltır. Bu ara ürünler, koenzim Q10 (ubikinonun prekürsörü) sentezi için zorunludur. Koenzim Q10, mitokondriyal elektron transport zincirinde kompleks I ve II'den kompleks III'e elektron taşıyan lipofilik bir moleküldür. Eksikliğinde mitokondriyal solunum bozulur, ATP üretimi azalır ve reaktif oksijen türleri birikir; bu tablo kas vakuoler dejenerasyonu ve biyopside mitokondriyal proliferasyon (kompansatuar yanıt) ile kendini gösterir. Diğer seçenekler statin miyopatisinin birincil mekanizmasını açıklamaz."},{"id":8469,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 yıldır süren progresif dispne ve tekrarlayan pnömoni atakları nedeniyle tetkik ediliyor. Yüksek çözünürlüklü BT'de alt loblarda baskın, balpeteği görünümü ve bronşektazi saptanıyor. Bronkoalveolar lavajda PAS pozitif, hücresiz amorf materyal birikimi görülüyor. Serum GM-CSF antikoru pozitif çıkıyor. Bu hastada hastalığın patogenezinde birincil rolü oynayan hücresel bozukluk aşağıdakilerden hangisidir?","options":["Clara hücrelerinden CC16 sekresyonunun durması","Klatrin aracılı endositozun azalması nedeniyle Tip I pnömosit hasarı","İnterstisyel fibrozis nedeniyle alveolar kapiller membranda kalınlaşma","Tip II pnömositlerde sürfaktan katabolizmasının bozulması","Mukosiliyer klerens bozukluğuna bağlı alveolar makrofaj aktivasyonu"],"correct":3,"exp":"Pulmoner alveoler proteinozis (PAP), alveolar makrofajların sürfaktan temizleme kapasitesinin bozulmasıyla karakterizedir. Otoimmün PAP'ta GM-CSF antikorları, makrofaj maturasyon ve aktivasyonunu engeller; bu durum Tip II pnömositler tarafından normalde üretilen ve ardından makrofajlar tarafından yıkılması gereken sürfaktan fosfolipid ve proteinlerinin (SP-A, SP-D) alveollerde birikmesine yol açar. PAS pozitif amorf materyal bu birikimi yansıtır. Tip I pnömositler gaz değişiminden sorumludur, endositoz bozukluğuyla ilişkileri yoktur. Clara hücreleri ve CC16, PAP patogenezinde yer almaz. Klinik tablo interstisyel fibrozisten farklıdır."},{"id":8470,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"Bir araştırmada, böbrek tübül fizyolojisiyle ilgili aşağıdaki öncüller değerlendirilmektedir:\nI. Proksimal tübülde Na⁺-K⁺-ATPaz bazolateral membranda yerleşiktir ve lümenden Na⁺ girişi için gerekli elektrokimyasal gradyanı oluşturur.\nII. Henle kulpunun ince inen kolunda aktif klor transportu gerçekleşir ve bu segment su geçirgenliğinden yoksundur.\nIII. Toplayıcı kanalda aldosteron, ENaC kanal yoğunluğunu artırarak Na⁺ geri emilimini hızlandırır.\nIV. Maküla densa hücreleri, tübüler NaCl konsantrasyonu arttığında afferent arteriyolu dilate eden sinyal molekülleri salgılar.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["3","2","Hiçbiri","1","4"],"correct":1,"exp":"Öncül I doğrudur: Na⁺-K⁺-ATPaz bazolateral konumlanarak hücre içi Na⁺ konsantrasyonunu düşük tutar; bu gradyan apikal membrandan Na⁺ girişini (kotransportörler ve kanallar aracılığıyla) sağlar. Öncül II yanlıştır: Henle kulpunun ince inen kolu suya geçirgen (AQP1 içerir), NaCl transportuna pasif olarak geçirimlidir; aktif klor transportu ince çıkan kolda değil, kalın çıkan kolda (NKCC2 aracılıyla) gerçekleşir. Öncül III doğrudur: Aldosteron, ENaC (epitelyal sodyum kanalı) transkripsiyon ve membrana yerleşimini artırır. Öncül IV yanlıştır: Maküla densa, tübüler NaCl yüksekliğinde afferent arteriyolu KONSTRİKTE eder (tübüloglomerüler geri besleme); dilatasyon değil, GFR azaltma amaçlıdır. Doğru öncül sayısı: 2."},{"id":8471,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"67 yaşında erkek hasta, ani başlayan göğüs ağrısı ve nefes darlığıyla acile başvuruyor. EKG'de ST elevasyonu saptanıyor ve primer perkütan koroner girişim uygulanıyor. Tedavi sonrasında ekokardiyografide etkilenen bölgede 'stunned myocardium' (sersemletilmiş miyokard) tablosu izleniyor; kontraktil fonksiyon bozuk olmasına karşın doku canlılığı korunmuş. Bu tabloda kardiyomiyosit kontraktil disfonksiyonunun birincil nedeni aşağıdakilerden hangisidir?","options":["Miyozin ağır zincir izoformunun β'dan α'ya dönüşümü","Sarkoplazik retikulumda Ca²⁺ döngüsünün bozulması ve miyofibril Ca²⁺ duyarlılığının azalması","Sarkomerde titin molekülünün parçalanması","Gap junction remodeling ile interkalated disk bütünlüğünün bozulması","Mitokondriyal membranın kalıcı depolarizasyonu ve apoptozis aktivasyonu"],"correct":1,"exp":"Sersemletilmiş miyokardda iskemi-reperfüzyon hasarı sonrası hücre ölümü gerçekleşmemiştir (canlılık korunmuştur) ancak kontraktil disfonksiyon mevcuttur. Bu durumun temel mekanizması reperfüzyon sırasında sarkoplazmik retikulumun Ca²⁺ döngüsünü düzenleyemeyen SERCA2a aktivitesinin azalması ve troponin I'ın fosforilasyonuna bağlı miyofibril Ca²⁺ duyarlılığının geçici olarak bozulmasıdır. Titin parçalanması geri dönüşsüz hasarda görülür. Mitokondriyal kalıcı depolarizasyon apoptoza yol açar; stunned miyokardda apoptoz minimal düzeydedir. Miyozin izoform değişimi kronik hipertrofi/kalp yetmezliği sürecinde söz konusudur. Gap junction rimodeling de kronik bir süreçtir."},{"id":8472,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Miyelinli bir sinir lifinde aksiyon potansiyelinin iletimi ile ilgili aşağıdaki öncüller değerlendirilmektedir:\nI. Aksiyon potansiyeli Ranvier boğumlarından boğuma atlayarak ilerler; bu iletim şekline saltatorik iletim denir.\nII. Miyelin kılıfı, aksiyon potansiyelinin hızını düşürür çünkü iyon kanallarının eşik değerini yükseltir.\nIII. Ranvier boğumlarında voltaj kapılı Na⁺ kanalları yoğun olarak bulunur.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","Yalnız I","Yalnız II","I, II ve III","II ve III"],"correct":0,"exp":"Öncül I doğrudur: Miyelinli liflerde depolarizasyon miyelin kılıfından geçemez; aksiyon potansiyeli Ranvier boğumları arasında elektrostatik olarak iletilir ve yalnızca boğumlarda yeniden oluşur; buna saltatorik (sıçrayıcı) iletim denir. Öncül II yanlıştır: Miyelin kılıfı membran kapasitansını azaltır ve aksiyon potansiyelinin hızını artırır; eşik değeri üzerinde doğrudan bir etkisi yoktur. Öncül III doğrudur: Voltaj kapılı Na⁺ kanalları Ranvier boğumlarında yoğunlaşmıştır (yaklaşık 1000/µm²); bu yoğunlaşma saltatorik iletimi mümkün kılar. Doğru öncüller I ve III'tür."},{"id":8473,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hastada yorgunluk, tekrarlayan enfeksiyonlar ve peteşi ile pansitopeni saptanıyor. Kemik iliği biyopsisinde hiposelüler ilik ve yağ dokusu artışı görülüyor. Edinsel aplastik anemi tanısı konuluyor. Bu hastalığın patogenezinde ve antitimosit globulin tedavisinin hedefindeki temel mekanizma aşağıdakilerden hangisidir?","options":["Klonal megakaryosit proliferasyonu ve retiküler fibrozis","Eritropoetin reseptöründe aktive edici mutasyon","Vitamin B12 eksikliğine bağlı inefektif eritropoez","Kemik iliğinin lösemik blastlarla infiltrasyonu","Sitotoksik T lenfositlerin hematopoetik kök hücreleri perforin/granzim B ile yıkması"],"correct":4,"exp":"Edinsel aplastik anemide otoreaktif sitotoksik T lenfositler IFN-γ ve TNF-α salgılayarak, ayrıca perforin/granzim B aracılığıyla hematopoetik kök hücrelerde apoptozu tetikler. Antitimosit globulin (ATG) ve siklosporin bu otoimmün saldırıyı baskılar. Klonal proliferasyon, EPO reseptör mutasyonu veya blastik infiltrasyon aplastik aneminin mekanizması değildir."},{"id":8474,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, efor dispnesi ve alt ekstremite ödemi şikayetiyle başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya digoksin tedavisi başlanıyor. Digoksinin kardiyak kontraktiliteyi artırmasının temelinde yatan hücresel değişiklikle ilgili aşağıdaki öncülleri değerlendiriniz:\nI. Na⁺/K⁺-ATPaz inhibisyonu sonucu hücre içi Na⁺ konsantrasyonu artar.\nII. Hücre içi Na⁺ artışı, Na⁺/Ca²⁺ değiştirici (NCX) aktivitesini artırarak Ca²⁺ atılımını hızlandırır.\nIII. Sitoplazmik Ca²⁺ artışı, troponin C'ye bağlanarak aktin-miyozin etkileşimini güçlendirir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, II ve III","I ve II","Yalnız I","II ve III","I ve III"],"correct":4,"exp":"Digoksin, sarkolemmal Na⁺/K⁺-ATPaz'ı inhibe ederek hücre içi Na⁺ konsantrasyonunu artırır (Öncül I doğru). Bu durum Na⁺/Ca²⁺ değiştiricisinin (NCX) ters modda çalışmasına yol açar; yani NCX daha az Ca²⁺ dışarı atar ve hücre içi Ca²⁺ konsantrasyonu yükselir (Öncül II yanlış: NCX aktivitesi azalır, artmaz). Artan sitoplazmik Ca²⁺, sarkoplazma retikulumundan ek Ca²⁺ salınımını tetikler ve troponin C'ye bağlanarak aktin-miyozin köprü oluşumunu kolaylaştırır, kontraktiliteyi artırır (Öncül III doğru). Bu nedenle I ve III doğru, II yanlıştır."},{"id":8475,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, 8 yıldır devam eden kuru öksürük ve progresif dispne yakınmasıyla başvuruyor. Toraks BT'de bilateral bazal yerleşimli retiküler opasiteler ve bal peteği görünümü saptanıyor. Transbronşiyal biyopside alveol duvarlarında aşırı kollajen birikimi ve tip I pnömosit kaybıyla birlikte tip II pnömosit hiperplazisi izleniyor. Bu hastada tip II pnömositlerle ilgili aşağıdaki öncülleri değerlendiriniz:\nI. Tip II pnömositler, hasar sonrası alveol epitelini yenilemek üzere bölünebilen tek alveolar epitel hücreleridir.\nII. Tip II pnömositler, lameller cisimciklerden sürfaktan salgılayarak alveol yüzey gerilimini düşürür.\nIII. Bu hastalıkta tip II pnömosit hiperplazisi, işlevsel sürfaktan üretiminin arttığının göstergesidir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Yalnız 2 tanesi","Yalnız 1 tanesi","Değerlendirilemez","3 tanesi","Hiçbiri"],"correct":0,"exp":"Tip II pnömositler gerçekten alveol epitelinin rejenerasyonundan sorumlu progenitör hücrelerdir ve sürfaktanı lameller cisimciklerden salgılarlar; dolayısıyla I ve II doğrudur. Ancak Öncül III yanlıştır: İdiyopatik pulmoner fibrozis (IPF) gibi hastalıklarda tip II pnömosit hiperplazisi, reaktif/reparatif bir yanıt olup bu hücrelerin işlev görememesi ve anormal farklılaşması nedeniyle fonksiyonel sürfaktan üretiminin artmadığını, aksine bozulduğunu yansıtır. Bu nedenle doğru öncül sayısı 2'dir."},{"id":8476,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 aydır devam eden çift görme, sol kolda güçsüzlük ve yorgunlukla başvuruyor. Nörolojik muayenede tekrarlayan kas kasılmalarıyla birlikte giderek artan yorgunluk (patolojik yorgunluk) saptanıyor. Edrofonyum uygulanması sonrasında semptomların geçici olarak düzeldiği gözlemleniyor. Bu hastanın tedavisinde kullanılan piridastigminin nöromüsküler kavşakta primer olarak etkilediği yapı ve bu etkinin sonucu olarak beklenen elektrofizyolojik değişiklik hangisidir?","options":["Presinaptik voltaj kapılı Ca²⁺ kanalı; tekrarlayan uyarımda amplitüd azalması","Postsinaptik nikotinik asetilkolin reseptörü; end-plate potansiyelinin amplitüdü değişmez","Asetilkolinesteraz enzimi; end-plate potansiyelinin süresi ve amplitüdü artar","Kas voltaj kapılı Na⁺ kanalı; eşik potansiyeli düşer","Asetilkolin vezikülleri; kuantal içerik artar"],"correct":2,"exp":"Hastada tanımlanan tablo miyastenia gravistir; edrofonyum (kısa etkili asetilkolinesteraz inhibitörü) ile semptomların geçici düzelmesi tanıyı destekler. Piridastigmin de bir asetilkolinesteraz inhibitörüdür. Bu ilaç nöromüsküler kavşakta asetilkolinesteraz enzimini inhibe ederek asetilkolinin sinaptik aralıkta yıkımını yavaşlatır. Sonuç olarak asetilkolin daha uzun süre reseptörle temas eder, end-plate potansiyelinin hem süresi hem de amplitüdü artar ve nöromüsküler iletim güçlenir. Diğer şıklarda belirtilen yapılar miyastenia gravis patogenezinde veya piridastigminin etki mekanizmasında primer hedef değildir."},{"id":8477,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında erkek hasta, 1 haftadır devam eden periorbital ödem, koyu renkli idrar ve azalmış idrar miktarı yakınmasıyla başvuruyor. Özgeçmişinde 3 hafta önce farenjit öyküsü mevcut. İdrar analizinde eritrosit silendirleri ve proteinüri saptanıyor. Serum kompleman C3 düzeyi düşük bulunuyor. Renal biyopside glomerüllerde mezengial ve subendotelyal elektron-yoğun depozitler izleniyor. Bu hastada böbrek biyopsisindeki ışık mikroskopisi bulgularında en sık görülmesi beklenen değişiklik hangisidir?","options":["Mezengial matrikste artış ve Kimmelstiel-Wilson nodülleri","Visseral epitel hücre (podosit) ayaksı çıkıntılarında yaygın silinme","Glomerüler skleroz ve tübüler atrofi","Glomerüllerde nötrofil infiltrasyonu ile hiperselülerite","Glomerüler bazal membranda yaygın kalınlaşma ve çivi başı görünümü"],"correct":3,"exp":"Klinik tablo, geçirilmiş farenjit sonrası gelişen nefritik sendrom ve düşük C3 ile akut poststreptokoksik glomerülonefriti (APSGN) düşündürmektedir. Bu hastalığın patolojik korelasyonu, immün kompleks birikiminin tetiklediği kompleman aktivasyonu sonucu glomerüllere nötrofil göçü ve buna bağlı glomerüler hiperselülaritedir; ışık mikroskopide en belirgin bulgu budur. Subendotelyal ve mezengial depozitler elektron mikroskopisiyle görülür. Çivi başı görünümü membranöz nefropatiye, Kimmelstiel-Wilson nodülleri diyabetik nefropatiye, yaygın podosit ayaksı silinmesi minimal değişiklik hastalığına, glomerüler skleroz kronik böbrek hasarına işaret eder."},{"id":8478,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Dalakla ilgili aşağıdaki öncülleri değerlendiriniz:\nI. Kırmızı pulpa, sinüzoidler ve bunlar arasındaki splenik kordonlardan oluşur; yaşlı eritrositlerin yıkımı burada gerçekleşir.\nII. Beyaz pulpa, T lenfositlerin periarteriolar lenfoid kılıfında (PALS) ve germinal merkezlerin mantle zonunda B lenfositlerin yoğunlaştığı lenfoid dokulardan oluşur.\nIII. Marjinal zon, kırmızı ve beyaz pulpa arasında konumlanan, kan kaynaklı antijenleri örnekleyen özelleşmiş B hücrelerini içerir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve II","I, II ve III","II ve III","I ve III","Yalnız I"],"correct":1,"exp":"Tüm öncüller doğrudur. Kırmızı pulpa gerçekten venöz sinüzoidler ve Billroth kordonlarından oluşur; esnek olmayan veya opsonize yaşlı eritrositler bu kordonları geçemez ve makrofajlar tarafından fagosite edilir (I doğru). Beyaz pulpa, santral arteriolu çevreleyen PALS'ta çoğunlukla T lenfositler, germinal merkezler ve mantle zonunda ise çoğunlukla B lenfositler barındırır (II doğru). Marjinal zon, kırmızı ve beyaz pulpa arasında yer alır ve buradaki özelleşmiş B hücreleri (marjinal zon B hücreleri) kan yoluyla gelen kapsüllü bakterilerin polisakkarit antijenlerine yanıt üretmede kritik rol oynar (III doğru)."},{"id":8479,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"61 yaşında erkek hasta, 6 aydır devam eden epigastrik ağrı, kilo kaybı ve iştahsızlık yakınmasıyla başvuruyor. Üst gastrointestinal endoskopide antrum yerleşimli ülsere lezyon saptanıyor. Biyopside Helicobacter pylori ile ilişkili kronik aktif gastrit ve intestinal metaplazi görülüyor. Kronik H. pylori gastriti olan bu hastada mide korpusunda parietal hücre kaybının ilerlemesiyle birlikte gelişmesi en olası laboratuvar bulgusu hangisidir?","options":["Serum pepsinojen I/pepsinojen II oranında artma","Serum kolesistokinin düzeyinde artma","Serum kobalamin (B12) düzeyinde azalma","Serum somatostatin düzeyinde azalma","Serum gastrin düzeyinde azalma"],"correct":2,"exp":"Mide korpusundaki parietal hücreler hem hidroklorik asit hem de intrinsik faktör salgılar. Uzun süren H. pylori gastriti korpusa yayılarak otoimmün benzeri bir atrofik gastrite zemin hazırlayabilir; parietal hücre kaybıyla birlikte intrinsik faktör sekresyonu azalır. İntrinsik faktör yokluğunda terminal ileumda kobalamin (B12) emilimi bozulur ve zamanla B12 eksikliği gelişir. Bunun yanı sıra parietal hücre kaybıyla asit sekresyonu azalacağından antral D hücrelerinin somatostatin inhibisyonu ortadan kalkar ve G hücrelerinden gastrin salınımı artar (hipergastrinemi beklenir, azalma değil). Pepsinojen I/II oranı atrofide azalır, artan değil. Bu nedenle doğru yanıt serum B12 düzeyinde azalmadır."},{"id":8480,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, ağır egzersiz sonrası gelişen kas güçsüzlüğü ve koyu renkli idrar yakınmasıyla başvuruyor. Serum kreatin kinaz düzeyi belirgin yüksek, miyoglobinüri saptanıyor. Hastada rabdomiyoliz tanısı konuluyor. Bu süreçte iskelet kası hücrelerinde önce hangi iyon birikimi tetikleyici rol oynar?\nI. Hücre içi Na⁺ artışı\nII. Hücre içi Ca²⁺ artışı\nIII. Hücre içi K⁺ azalması\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve II","II ve III","Yalnız I","Yalnız II","I ve III"],"correct":0,"exp":"Rabdomiyolizde iskelet kası hasarı sırasında Na⁺/K⁺-ATPaz pompasının yetersiz kalmasıyla hücre içi Na⁺ birikir (Öncül I doğru). Artan hücre içi Na⁺, Na⁺/Ca²⁺ değiştiriciyi (NCX) ters yönde çalıştırarak hücre içi Ca²⁺'nin kritik düzeylerde artmasına yol açar (Öncül II doğru). Hücre içi K⁺ ise depolarizasyon sırasında dışarı çıkar ancak birincil tetikleyici değil, eşlik eden bir bulgudur; K⁺ azalması tek başına miyolizi başlatmaz (Öncül III yanlış). Bu nedenle I ve II doğrudur."},{"id":8481,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"27 yaşında kadın hasta, 2 yıldır tekrarlayan pnömoni atakları, kronik ıslak öksürük ve balgam yakınmasıyla göğüs hastalıkları polikliniğine başvuruyor. Yüksek çözünürlüklü BT'de bronşiektazi saptanıyor. Nazal nitrik oksit ölçümü belirgin düşük bulunuyor. Yapılan genetik analizde DNAI1 geninde mutasyon tespit ediliyor.\nI. Solunum epiteli silialarının iç dineyn kolları işlevsizdir.\nII. Mukosilier klirens bozulmuştur.\nIII. Spermlerin motilitesi etkilenmemiştir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Üçü","İkisi","Tamamı yanlış, doğru öncül sayısı dörttür","Yalnız biri","Hiçbiri"],"correct":1,"exp":"DNAI1 mutasyonu primer silier diskinezi (PCD) tablosuna yol açar. PCD'de silia aksonemasındaki dış veya iç dineyn kolları işlevsiz hale gelir; DNAI1 mutasyonlarında özellikle iç dineyn kolu bozukluğu görülür (Öncül I doğru). Silier işlev kaybı mukosilier klirensi bozarak tekrarlayan enfeksiyonlara zemin hazırlar (Öncül II doğru). Spermlerin kuyruk yapısı da silier aksonem ile benzer yapıya sahiptir; bu nedenle PCD'li erkeklerde infertilite sıktır, sperm motilitesi etkilenir (Öncül III yanlış). Doğru öncül sayısı ikidir."},{"id":8482,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"45 yaşında kadın hasta, uzun süreli NSAID kullanımı öyküsüyle birlikte poliüri, noktüri ve hipostatik idrar yakınmasıyla başvuruyor. Serum elektrolitleri normal, serum osmolalitesi normal, idrar osmolalitesi ise belirgin düşük saptanıyor. Susuzluk testi yapılıyor; egzojen desmopressin verilmesine rağmen idrar osmolalitesi artmıyor. Bu hastada toplayıcı tüp epitelinde hangi yapısal değişiklik beklenir?","options":["Maküla densa hücrelerinde renin salınımı artışı","Interkale hücrelerde H⁺-ATPaz upregülasyonu","Principal hücrelerde apikal AQP2 ekspresyonunun artması","Principal hücrelerde AQP2 ekspresyonunun azalması ya da tübüler AQP2 yanıtsızlığı","Proksimal tübül fırçamsı kenar kaybı"],"correct":3,"exp":"Kronik NSAID kullanımı renal prostaglandin sentezini inhibe ederek toplayıcı tüpün ADH (AVP) yanıtını bozar. Susuzluk testi ve desmopressin uygulamasına rağmen idrar osmolalitesinin artmaması nefrojenik diabetes insipidus (NDI) lehinedir. NDI'de ADH düzeyi yeterli olmasına karşın toplayıcı tüp principal hücreleri yanıt veremez; bu tabloda AQP2 ekspresyonu azalmış ya da hücre yüzeyine taşınması bozulmuştur. Santral DI'den farklı olarak desmopressine yanıt yoktur."},{"id":8483,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Bir nörobilim araştırmasında, büyük miyelinli aksonların miyelinsiz ince aksonlara kıyasla iletim hızının çok daha yüksek olduğu gösterilmektedir. Saltatorik iletimin gerçekleştiği yapısal birim ve bu yapıdaki en yüksek iyon kanalı yoğunluğunun bulunduğu bölge sırasıyla hangileridir?","options":["Schmidt-Lanterman yarıkları - Ranvier boğumu","İnternode - aksonal tepecik (axon hillock)","Ranvier boğumu - internodal segment","Perikaryon - dendrit","Ranvier boğumu - Ranvier boğumu"],"correct":4,"exp":"Saltatorik iletimde aksiyon potansiyeli bir Ranvier boğumundan diğerine 'atlayarak' ilerler; bu sayede iletim hızı ve enerji verimliliği artar. Ranvier boğumları, voltaj kapılı Na⁺ kanallarının (özellikle Nav1.6) en yüksek yoğunlukta bulunduğu bölgelerdir. İnternodal segment miyelin ile kaplı olduğundan kanal yoğunluğu çok düşüktür. Bu nedenle saltatorik iletimin yapısal birimi ve en yüksek Na⁺ kanalı yoğunluğunun bulunduğu bölge her ikisi de Ranvier boğumudur."},{"id":8484,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, tekrarlayan bakteriyel ve fungal enfeksiyonlar, parsiyel oküloskütan albinizm ve kanama eğilimi yakınmalarıyla başvuruyor. Periferik kan yaymasında nötrofillerde dev sitoplazmik granüller görülüyor. Fonksiyon testlerinde NK hücresi sitotoksisitesinin ileri derecede azaldığı saptanıyor.\nI. Lizozom işlev bozukluğu mevcuttur.\nII. LYST geninde mutasyon vardır.\nIII. Trombosit yoğun granül sayısı artmıştır.\nIV. Kemik iliği nakli küratif tedavi seçeneğidir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["İkisi","Yalnız biri","Üçü","Dördü","Hiçbiri"],"correct":2,"exp":"Bu tablo Chediak-Higashi sendromunu tanımlamaktadır. LYST (CHS1) genindeki mutasyon lizozomal trafik düzenleyici proteini bozar (Öncül II doğru). Lizozomların diğer vezikülerle anormal füzyonu dev granül oluşumuna, fagositoz ve NK sitotoksisitesinde bozulmaya yol açar (Öncül I doğru). Trombositlerde yoğun granüller azalmıştır, artmaz; bu azalma kanama eğilimini açıklar (Öncül III yanlış). Kemik iliği nakli hastalığın hematolojik ve immünolojik komponentini düzeltebilen tek küratif tedavidir (Öncül IV doğru). Doğru öncül sayısı üçtür."},{"id":8485,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 6 aydır eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla başvuruyor. Koroner anjiyografide sol ön inen arterde %85 darlık saptanıyor. Hastaya perkütan koroner girişim planlanıyor ancak reperfüzyon öncesinde miyokard dokusunun iskemik koşullanma protokolüne alındığı bildiriliyor. Bu süreçte kısa süreli iskemi-reperfüzyon siklüslerinin kardiyomiyositleri koruduğu düşünülmektedir. Aşağıdaki öncülleri değerlendiriniz:\nI. Mitokondriyal K-ATP kanallarının aktivasyonu bu koruyucu mekanizmada rol oynar.\nII. Adenozin salınımının artması iskemik koşullanmanın başlatıcı ajanlarından biridir.\nIII. Bu mekanizma, mitokondriyal geçirgenlik geçiş porunu (mPTP) açarak hücreyi korur.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız II","I ve II","I, II ve III","Yalnız I","II ve III"],"correct":1,"exp":"İskemik ön koşullanmada (preconditioning) adenozin, bradikinin ve opioidler başlatıcı ajan olarak görev yapar (öncül II doğru). Bu ajanlar G protein bağlantılı reseptörler aracılığıyla protein kinaz C'yi aktive eder; bunun sonucunda mitokondriyal K-ATP kanalları açılır ve membran potansiyeli korunarak kardiyomiyosit ölümü engellenir (öncül I doğru). Öncül III yanlıştır: mPTP'nin AÇILMASI iskemi-reperfüzyon hasarının temel mekanizmasıdır ve hücre ölümüne yol açar; iskemik koşullanma ise mPTP'nin KAPALI kalmasını sağlayarak koruma sağlar."},{"id":8486,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 yıldır tekrarlayan görme bulanıklığı, denge bozukluğu ve üst ekstremitelerde güçsüzlük atakları nedeniyle nöroloji kliniğine başvuruyor. MRG'de periventriküler ve corpus callosum'da T2 hiperintens lezyonlar izleniyor. Beyin omurilik sıvısı incelemesinde oligoklonal bantlar pozitif bulunuyor. Hastaya yüksek doz metilprednizolon başlanıyor. Bu tedavinin akut atakları kısaltmasındaki temel histofizyolojik gerekçeyi en iyi açıklayan ifade hangisidir?","options":["Remyelinizasyonu doğrudan uyararak iletim hızını yeniden normale döndürür.","Oligodendrosit proliferasyonunu artırarak demiyelinize aksonları yeniden kaplar.","Astrosit aktivasyonunu kalıcı olarak baskılayarak gliyozisi önler.","Akson boyunca sodyum kanalı dağılımını yeniden düzenleyerek nodal iletimi restore eder.","Kan-beyin bariyeri geçirgenliğini azaltarak aktive T lenfositlerinin CNS'e girişini kısıtlar."],"correct":4,"exp":"Multipl skleroz akut atak tedavisinde kullanılan yüksek doz kortikosteroidler, kan-beyin bariyerinin geçirgenliğini azaltarak aktive T lenfositleri ve inflamatuvar mediatörlerin MSS'ye geçişini kısıtlar; bu sayede inflamatuvar ödem ve demiyelinizan hasarın ilerlemesi engellenir ve atağın süresi kısalır. Kortikosteroidler remyelinizasyonu doğrudan uyarmaz, oligodendrosit proliferasyonunu artırmaz ve sodyum kanalı dağılımını reorganize etmez. Astrosit aktivasyonunu baskılamaları da kalıcı değildir ve bu etki atakları kısaltmanın temel mekanizması değildir."},{"id":8487,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 10 yıldır tip 2 diyabetes mellitus tanısıyla takip edilmektedir. Son 1 yılda ayak bileklerinde şişlik ve idrarda köpürme yakınması eklenmesi üzerine yapılan tetkiklerinde spot idrarda albumin/kreatinin oranı 420 mg/g, GFR 38 mL/dak/1,73 m² olarak saptanıyor. Renal biyopside mezangiyumda genişleme ve Kimmelstiel-Wilson nodülleri izleniyor. Hastada aşağıdaki öncülleri değerlendiriniz:\nI. Glomerüler bazal membran kalınlaşması podosit kayıplarını kolaylaştırarak proteinüriye zemin hazırlar.\nII. Mezangiyum genişlemesinin temel nedeni ileri glikasyon son ürünleri (AGE) birikimi ve TGF-β aracılı matriks artışıdır.\nIII. Bu hastada GFR'nin erken dönemde artmış olması, eferent arteriyol dilatasyonuna bağlı hiperfiltrasyon ile açıklanır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Değerlendirilemez","Yalnız biri","Üçü","Hiçbiri","İkisi"],"correct":4,"exp":"Öncül I doğrudur: diyabetik nefropatide GBM kalınlaşması podosit adezyonunu bozar ve podosit ayakçıklarının silinmesine yol açarak proteinüri gelişimini kolaylaştırır. Öncül II doğrudur: AGE birikimi ve TGF-β aracılı sinyal yolakları mezangiyum hücrelerini aktive ederek kollajen IV ve fibronektin üretimini artırır; bu durum mezangiyum genişlemesi ve nodüler glomerüloskleroz (Kimmelstiel-Wilson) ile sonuçlanır. Öncül III yanlıştır: diyabetik nefropatinin erken döneminde gözlenen hiperfiltrasyon, eferent değil AFERent arteriyol dilatasyonuna (anjiyotensin II'nin eferen etkisinin baskılanmasına karşın aferen vazodilatasyona) ve glomerüler kapiller basınç artışına bağlıdır. Dolayısıyla doğru öncül sayısı ikidir."},{"id":8488,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 5 yıldır tekrarlayan hışıltılı solunum ve eforla artan nefes darlığı yakınmalarıyla başvuruyor. Spirometride FEV1/FVC oranı %64, bronkodilatör sonrası FEV1'de %15 artış saptanıyor. Balgam incelemesinde eozinofil hakimiyeti ve Charcot-Leyden kristalleri görülüyor. Bu hastaya inhale kortikosteroid tedavisi başlanıyor. Bu tedavinin uzun vadede bronş duvarında beklenen histolojik etkisi hangisidir?","options":["Goblet hücre hiperplazisini ve submukozal eozinofil infiltrasyonunu azaltır.","Tip II pnömosit sayısını artırarak surfaktan üretimini yükseltir.","Mukozal mast hücre sayısını sıfıra indirerek anafilaktik yanıtı tamamen ortadan kaldırır.","Bazal membran kalınlaşmasını tamamen normalize eder ve remodeling sürecini tersine çevirir.","Bronş düz kas hipertrofisini kalıcı olarak geri döndürür ve normal kas kitlesini yeniden oluşturur."],"correct":0,"exp":"Astımda kronik havayolu inflamasyonunun temel histolojik bulguları arasında submukozal eozinofil infiltrasyonu, goblet hücre hiperplazisi, bazal membran kalınlaşması ve düz kas hipertrofisi yer alır. İnhale kortikosteroidler eozinofil ömrünü kısaltır, eozinofil kemotaksisini baskılar ve goblet hücre hiperplazisini azaltarak mukus hipersekresyonunu düşürür; bu nedenle doğru yanıt B seçeneğidir. Düz kas hipertrofisinin tamamen geri dönmesi ya da bazal membran kalınlaşmasının normalize olması inhale kortikosteroidlerle sağlanamaz. Mast hücre sayısını sıfıra indirmek mümkün değildir. Tip II pnömosit üzerine etkili olmaları ise bu sorudaki tablonun açıklaması değildir."},{"id":8489,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Gastrointestinal sistemdeki enterokromafin benzeri (ECL) hücreler, histamin salgılayarak parietal hücrelerini uyarmaktadır. Aşağıdaki öncülleri değerlendiriniz:\nI. ECL hücrelerinin uyarılmasında gastrin ve asetilkolin başlıca rolü üstlenir.\nII. Histamin, parietal hücredeki H2 reseptörüne bağlanarak adenilat siklaz yolağı üzerinden HCl sekresyonunu artırır.\nIII. Omeprazol, H2 reseptörünü bloke ederek ECL hücresi-parietal hücre eksenini keser.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","II ve III","Yalnız I","I ve II","I, II ve III"],"correct":3,"exp":"Öncül I doğrudur: ECL hücreleri gastrin (CCK-B reseptörü aracılığıyla) ve asetilkolin (muskarinik M1 reseptörü aracılığıyla) tarafından uyarılarak histamin salgılar. Öncül II doğrudur: salınan histamin, parietal hücre yüzeyindeki H2 reseptörüne bağlanır; bu bağlanma adenilat siklaz aktivasyonu ve cAMP artışı yoluyla protein kinaz A'yı aktive eder, ardından H+/K+-ATPaz (proton pompası) uyarılarak HCl sekresyonu gerçekleşir. Öncül III yanlıştır: omeprazol bir proton pompası inhibitörüdür ve H2 reseptörünü bloke etmez; etki noktası parietal hücrenin kanalikül membranındaki H+/K+-ATPaz enzimidir. H2 reseptör blokajı simetidin veya ranitidin gibi H2 antagonistlerinin görevidir."},{"id":8490,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 3 aydır süren halsizlik, gece terlemesi ve sol hipokondriyumda dolgunluk hissiyle başvuruyor. Fizik muayenede dalak alt kutbu göbek altına iniyor. Tam kan sayımında lökosit 185.000/µL, trombosit 620.000/µL, hemoglobin 9,2 g/dL saptanıyor. Periferik yaymada tüm olgunlaşma basamaklarında nötrofil serisi elemanları izleniyor. Philadelphia kromozomu pozitif bulunan hastaya imatinib başlanıyor. Bu ilacın lökosit sayısını düşürmedeki temel etkisini dolaylı olarak kanıtlayan bulgu hangisidir?","options":["Dalak boyutunun imatinib öncesinde progresif büyümesi.","Hemoglobin düzeyinin tedavinin ilk haftasında belirgin yükselmesi.","Tedavi altında periferik yaymada blast oranının hızla azalması ve olgun nötrofil predominansına dönüş.","BCR-ABL1 füzyon transkriptinin nicel PCR ile saptanamaz düzeye gerilemesi.","Tedaviyle birlikte trombosit sayısının 1.000.000/µL üzerine çıkması."],"correct":3,"exp":"İmatinib, BCR-ABL1 tirozin kinazını ATP bağlanma bölgesinden bloke ederek Philadelphia kromozomu pozitif klonun kontrolsüz proliferasyonunu durdurur. Bu ilacın etkinliğini en doğrudan kanıtlayan bulgu, BCR-ABL1 füzyon transkriptinin nicel RT-PCR ile ölçülemez (majör moleküler yanıt) düzeye gerilemesidir; bu bulgu hedef molekülün baskılandığını doğrudan gösterir ve lökosit düşüşünün mekanizmayla bağlantısını kurarak mekanizma bilgisini dolaylı yoldan sorgular. Blast oranının azalması blastik faz geçişini önler ancak kronik faz KML'de zaten blastlar baskındır. Hemoglobin artışı ve trombosit yükselmesi bu ilaç mekanizmasının doğrudan kanıtı değildir. Dalak büyümesi ise imatinib öncesi durumu yansıtır ve tedavi etkinliğini kanıtlamaz."},{"id":8491,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı şikayetiyle başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya ACE inhibitörü ve beta bloker başlanıyor. Tedavinin ilerleyen haftalarında hastanın egzersiz toleransının arttığı ve periferik ödeminin gerilediği gözlemleniyor. Bu klinik iyileşmede aşağıdaki mekanizmalardan hangisi ACE inhibitörünün etkisiyle doğrudan ilişkilidir?","options":["Renin salınımını artırarak glomerüler filtrasyon hızını yükseltmesi","Bradikinin yıkımını hızlandırarak pulmoner vasküler direnci düşürmesi","Atriyal natriüretik peptid salınımını artırarak venöz dönüşü azaltması","Sempatik sinir sistemi aktivasyonunu azaltarak kalp hızını düşürmesi","Anjiyotensin II'ye bağlı vazokonstriksiyon ve aldosteron salınımının baskılanması"],"correct":4,"exp":"ACE inhibitörleri anjiyotensin dönüştürücü enzimi bloke ederek anjiyotensin II oluşumunu engeller. Bu sayede hem arteriyel vazokonstriksiyon hem de anjiyotensin II'ye bağlı aldosteron salınımı azalır; sonuçta afterload ve sodyum-su retansiyonu azalır, ödem geriler, egzersiz toleransı artar. Beta bloker sempatik etkiyi baskılar; bradikinin yıkımının azalması (artması değil) ACE inhibitörünün yan etkisidir. ANP salınımı kalp içi basınç artışına bağlıdır ve ACE inhibitörünün birincil etkisi değildir."},{"id":8492,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 20 yıllık sigara içme öyküsüyle birlikte 2 yıldır artan nefes darlığı ve kronik öksürük şikayetiyle başvuruyor. Solunum fonksiyon testinde FEV1/FVC oranı %58, akım-hacim eğrisinde ekspiryumda belirgin çöküntü izleniyor. Hastada aşağıda verilen öncüllerin kaç tanesi doğrudur?\nI. Havayolu düz kas hipertrofisi ve mukus bezi hiperplazisi bu tabloya katkıda bulunur.\nII. Alveol duvarlarındaki elastin yıkımı statik akciğer kompliyansını azaltır.\nIII. Alveoler yüzey alanı kaybı difüzyon kapasitesini düşürür.\nIV. Dinamik havalanma tuzaklaması rezidüel volümü artırır.","options":["2 tanesi","3 tanesi","Hiçbiri doğru değildir","Yalnız 1 tanesi","4 tanesi"],"correct":1,"exp":"Bu tablo KOAH ile uyumludur. I. Kronik bronşit bileşeninde havayolu düz kas hipertrofisi ve mukus bezi hiperplazisi görülür; doğrudur. II. Amfizemde elastin yıkımı alveol duvarlarının geri çekme kuvvetini azaltır, bu da statik kompliyansı ARTTIRIR, azaltmaz; yanlıştır. III. Alveol duvarı yıkımıyla yüzey alanı kaybı difüzyon kapasitesini (DLCO) düşürür; doğrudur. IV. Ekspiryumda erken havayolu kapanması havalanma tuzaklamasına ve rezidüel volüm artışına yol açar; doğrudur. Doğru öncüller I, III ve IV olmak üzere 3 tanesidir."},{"id":8493,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 6 aydır süren bacak ödemi ve gözlerde şişlik şikayetiyle başvuruyor. İdrar tetkikinde protein 3+ saptanıyor. 24 saatlik idrarda protein 4,2 g, serum albümin 1,9 g/dL, serum kolesterol 340 mg/dL olarak ölçülüyor. Böbrek biyopsisinde glomerüler bazal membran kalınlaşması ve subepitelyal 'spike' formasyonları izleniyor. Bu hastada gelişen hipoalbüminemi sonucunda ortaya çıkan komplikasyonların aşağıdaki öncüllerden hangilerini kapsadığı doğrudur?\nI. Onkotik basınç düşüşüne bağlı interstisyel ödem\nII. Karaciğerde kompansatuvar lipoprotein sentezi artışına bağlı hiperlipidemi\nIII. Antitrombin III kaybına bağlı hiperkoagülabilite\nIV. Renin-anjiyotensin-aldosteron sistemi baskılanmasına bağlı hipovolemi","options":["I, II ve III","Yalnız I ve II","I, II, III ve IV","Yalnız I ve III","II, III ve IV"],"correct":0,"exp":"Tabloda membranöz nefropati ile uyumlu nefrotik sendrom bulguları mevcuttur. I. Hipoalbüminemi plazma onkotik basıncını düşürerek interstisyel alana sıvı geçişine ve ödeme yol açar; doğrudur. II. Karaciğer onkotik uyarıyla kompansatuvar lipoprotein (VLDL) sentezini artırır; hiperlipidemi nefrotik sendromun klasik bulgusudur; doğrudur. III. Antitrombin III, protein C ve S idrarla kaybolur; bu durum hiperkoagülabiliteye ve renal ven trombozu riskine yol açar; doğrudur. IV. Efektif dolaşım hacmi azaldığında RAAS aktive olur, baskılanmaz; IV yanlıştır. Doğru yanıt I, II ve III'tür."},{"id":8494,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"23 yaşında erkek tıp öğrencisi, bir anatomi müzesinde miyelinli ve miyelinsiz sinir liflerini incelerken öğretim üyesi şu soruyu soruyor: Bir sinir lifinde miyelin kılıfının varlığı iletim hızını artırırken, aynı çaptaki miyelinsiz life kıyasla metabolik enerji tüketimini de farklılaştırır. Bu durumla ilgili aşağıdaki öncüllerden hangileri doğrudur?\nI. Miyelinli liflerde aksiyon potansiyeli Ranvier düğümleri arasında atlar; buna tuzlu iletim denir.\nII. Miyelinsiz liflerde Na⁺/K⁺-ATPaz aktivitesi membranın tüm uzunluğu boyunca daha yoğun çalışmak zorundadır.\nIII. Miyelin kılıfı membran kapasitansını artırarak iletimi hızlandırır.\nIV. Ranvier düğümlerinde voltaj kapılı Na⁺ kanalları yoğunlaşmıştır.","options":["Yalnız I ve III","II, III ve IV","I, II ve IV","Yalnız II ve IV","I, II, III ve IV"],"correct":2,"exp":"I. Miyelinli liflerde depolarizasyon Ranvier düğümden düğüme atlar; buna saltatorik (tuzlu) iletim denir; doğrudur. II. Miyelinsiz liflerde tüm membran boyunca iyon akımı olduğu için Na⁺/K⁺-ATPaz daha geniş alanda çalışır ve enerji tüketimi daha fazladır; doğrudur. III. Miyelin kılıfı membran kapasitansını AZALTIR, bu da yük birikmesini azaltarak iletimi hızlandırır; kapasitansı artırdığı söylemi yanlıştır. IV. Ranvier düğümlerinde voltaj kapılı Na⁺ kanalları yoğun olarak lokalizedir; doğrudur. Doğru öncüller I, II ve IV'tür."},{"id":8495,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"28 yaşında kadın hasta, son 3 aydır aşırı yorgunluk ve nefes darlığı şikayetiyle başvuruyor. Tam kan sayımında hemoglobin 7,2 g/dL, MCV 72 fL, MCH düşük, periferik yaymada hipokromik mikrositik eritrositler ve kalem hücreleri görülüyor. Serum ferritin 4 ng/mL, serum demiri düşük, TDBK yüksek saptanıyor. Bu hastaya başlanan demir tedavisinin etkinliğini değerlendirmede en erken ortaya çıkan laboratuvar bulgusu hangisidir?","options":["Retikülosit sayısında artış","Ortalama eritrosit hacminin normalleşmesi","Serum ferritin düzeyinin normalleşmesi","Hemoglobin değerinin normale dönmesi","Periferik yaymada hipokromik eritrosit oranının azalması"],"correct":0,"exp":"Demir eksikliği anemisinde tedaviye yanıt sırasıyla değerlendirilir: en erken (3-5. günlerde) retikülosit sayısı artar; bu, kemik iliğinin demir varlığında eritropoezi hızlandırdığının göstergesidir. Hemoglobin düzeyi genellikle 2-4 hafta içinde yükselmeye başlar. Ferritin depoları en son dolduğu için normalleşmesi en geç gerçekleşir. MCV ve periferik yayma bulguları da hemoglobinden sonra düzelir. Bu nedenle tedavi etkinliğinin en erken göstergesi retikülosit artışıdır."},{"id":8496,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, uzun süreli alkol kullanım öyküsüyle birlikte yağlı dışkı, kilo kaybı ve karın ağrısı şikayetiyle başvuruyor. Dışkıda elastaz düzeyi düşük saptanıyor, MRCP'de pankreas kanalında genişleme ve kalsifikasyon alanları görülüyor. Hastaya pankreas enzim replasman tedavisi başlanıyor. Bu tedavinin etkin olabilmesi için aşağıdaki koşulların hangisi en kritik öneme sahiptir?","options":["Tedaviye ek olarak kolesistokinin antagonistinin kullanılması","Lipaz dozunun protein ve karbonhidrat sindirimini de karşılayacak şekilde yüksek tutulması","Enterik kaplı kapsüllerin öğün sırasında veya hemen sonrasında alınması ve yeterli pankreatik bikarbonat ortamının sağlanması","Mide asiditesinin artırılarak enzim aktivasyonunun sağlanması","Enzim preparatının yemekten 2 saat önce alınması"],"correct":2,"exp":"Kronik pankreatit tablosunda ekzokrin yetmezlik nedeniyle steatore ve malabsorbsiyon gelişir. Enzim replasman tedavisinde etkinlik için iki koşul kritiktir: birincisi, kapsüllerin besin alımıyla eş zamanlı (öğün sırasında veya hemen sonrasında) alınmasıdır; böylece enzimler gıdayla birlikte duodenuma geçer. İkincisi, enterik kaplı preparatların duodenumda çözünebilmesi için yeterli pH ortamı gereklidir; ancak kronik pankreatitte bikarbonat sekresyonu da azalmış olduğundan gerekirse PPI eklenerek mide asit yükü azaltılır ve duodenal pH yükseltilir, bu da enterik kaplı enzimlerin daha iyi salınmasını sağlar. Yemekten önce alım enzimlerin gıdayla karışımını bozar; kolesistokinin antagonisti ise bu tedavide yeri olmayan bir yaklaşımdır."},{"id":8497,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor sırasında nefes darlığı ve çabuk yorulma yakınmasıyla kardiyoloji polikliniğine başvuruyor. Özgeçmişinde 10 yıldır hipertansiyon tanısı mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35, diyastol sonu volümü artmış bulunuyor. Hastaya ACE inhibitörü başlanmasının ardından yapılan kontrol ekokardiyografide kalp hacminde belirgin küçülme saptanıyor. Bu hastada ACE inhibitörünün tedavi edici etkisini açıklayan temel hemodinamik değişiklik hangisidir?","options":["Periferik vasküler direncin artışı ile diastolik basıncın yükselmesi","Kalp hızının refleks olarak artması ve kardiyak outputun korunması","Afterload azalması ile miyokardiyal duvar geriliminin düşmesi","Preload artışı ile ventriküler dolum basıncının yükselmesi","Koroner vazokonstrüksiyon ile miyokardiyal oksijen sunumunun artması"],"correct":2,"exp":"ACE inhibitörleri anjiyotensin II sentezini baskılayarak hem arteriyel vazodilatasyona (afterload azalması) hem de venöz kapasitansın artmasına (preload azalması) yol açar. Dilate kardiyomiyopatide sol ventrikül duvar gerilimi Laplace yasasına göre (T = P × r / 2h) artmıştır; afterload azalması bu gerilimi düşürerek eksantrik hipertrofinin ve ventriküler remodelingin gerilemesini sağlar. Böylece diyastol sonu volüm azalır ve ejeksiyon fraksiyonu yükselir. Preload artışı veya periferik direnç artışı zaten yüksek olan duvar gerilimini daha da artıracağından yanlıştır."},{"id":8498,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, yüksek rakımda tırmanış sporunu bıraktıktan 3 gün sonra deniz seviyesine inen bir dağcıdır. Kan gazı analizinde PaO2: 95 mmHg, PaCO2: 32 mmHg, pH: 7.46, HCO3-: 22 mEq/L bulunuyor. Fizik muayenede herhangi bir patoloji saptanmıyor. Bu kişideki kan gazı tablosunun en doğru yorumu hangisidir?","options":["Kompanse metabolik alkaloz","Yüksek rakım adaptasyonuna bağlı kalıcı hiperventilasyon","Kompanse olmayan solunumsal alkaloz","Solunumsal alkalozun renal kompansasyonu henüz tamamlanmamış","Kompanse solunumsal asidoz"],"correct":3,"exp":"Yüksek rakımda hipoksiye bağlı hiperventilasyon solunumsal alkaloza yol açar; böbrekler HCO3- atılımını artırarak kompansasyon sağlar ancak bu süreç 3-5 gün sürer. Deniz seviyesine döndükten sonra PO2 normalleştiği için hiperventilasyon durur, PaCO2 yükselmeye başlar; ancak böbrekler daha önce atılmış olan HCO3-'ü hemen yerine koyamaz. Tabloda PaCO2 düşük (32 mmHg) ve pH hafif alkali (7.46), HCO3- normal alt sınırda (22 mEq/L) görülmektedir. Bu bulgular renal kompansasyonun tamamlandığını değil, solunumsal alkalozun hâlâ kısmen sürdüğünü ve renal kompansasyonun geride kaldığını gösterir."},{"id":8499,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, 6 aydır süren poliüri ve polidipsi yakınmasıyla nefroloji polikliniğine başvuruyor. Su kısıtlama testinde idrar ozmolaletesi 150 mOsm/kg olarak ölçülüyor; eksojen desmopressin uygulamasının ardından idrar ozmolaletesi 155 mOsm/kg'a yükseliyor. Plazma ADH düzeyi yüksek saptanıyor. Bu hastada en olası bozukluk aşağıdakilerden hangisidir?","options":["SIADH","Nefrojenik diyabetes insipidus","Primer polidipsi","Osmotik diürez","Santral diyabetes insipidus"],"correct":1,"exp":"Su kısıtlama testinde idrar konsantrasyonu artmayan, eksojen ADH (desmopressin) verildiğinde de yanıt alınamayan (idrar ozmolaletesi 155 mOsm/kg gibi düşük kalmaya devam eden) tablo nefrojenik diyabetes insipidus lehine işaret eder. Ek olarak endojen plazma ADH düzeyinin yüksek bulunması, santral diyabetes insipidus tanısını dışlar; çünkü santral formda ADH düşük olur ve eksojen ADH'ya belirgin yanıt alınır. Primer polidipside su kısıtlamasıyla idrar konsantre olabilir. SIADH'de ise poliüri değil oligüri ve hiponatremi beklenir."},{"id":8500,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir nörobilim araştırmasında farklı akson tiplerinin iletim hızları karşılaştırılıyor. Aşağıdaki öncülleri değerlendirin:\nI. Miyelinli liflerde aksiyon potansiyeli Ranvier boğumları arasında sıçrayarak ilerler ve bu durum iletim hızını artırır.\nII. Akson çapı ne kadar büyükse iletim hızı o kadar yavaştır.\nIII. C lifleri miyelinsiz ince lifler olup ağrı ve ısı iletiminde görev alır.\nIV. A-alfa lifleri en yüksek iletim hızına sahiptir ve motor nöronları içerir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","4","3","2","1"],"correct":2,"exp":"Öncül I doğrudur: miyelinli liflerde saltatorik (sıçramalı) iletim Ranvier boğumları arasında gerçekleşir ve iletim hızını belirgin şekilde artırır. Öncül II yanlıştır: akson çapı büyüdükçe iç direnç azalır ve iletim hızı artar, tam tersi değil. Öncül III doğrudur: C lifleri miyelinsiz, ince (0.2-1.5 µm) liflerdir; yavaş ağrı, ısı ve otonomik postgangliyonik impulsları iletir. Öncül IV doğrudur: A-alfa lifleri (Aα) en kalın miyelinli liflerdir (12-20 µm), iletim hızları 70-120 m/s arasındadır ve alfa motor nöronları ile kas iğciği afferentlerini (Ia) içerir. Dolayısıyla doğru öncüller I, III ve IV olup toplam 3 öncül doğrudur."},{"id":8501,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"48 yaşında erkek hasta, pernisiyöz anemi tanısıyla takip edilmekte olup aylık intramusküler B12 vitamini replasmanı almaktadır. Özgeçmişinde otoimmün gastrit hikayesi mevcut. Aşağıdaki öncülleri değerlendirin:\nI. Bu hastada mide korpusundaki paryetal hücre kaybı, intrinsik faktör salgısının durmasına yol açar.\nII. İntrinsik faktör yokluğunda B12 vitamini terminal ileumda emilemez.\nIII. Pernisiyöz anemide B12 vitamini eksikliği yalnızca eritrosit üretimini etkiler, nörolojik tutulum görülmez.\nIV. Paryetal hücreler hem intrinsik faktörü hem de hidroklorik asidi salgılar.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["II, III ve IV","I ve II","Yalnız IV","I, II ve IV","I, III ve IV"],"correct":3,"exp":"Öncül I doğrudur: otoimmün gastritte paryetal hücreler antikor aracılı hasar görür; paryetal hücre kaybı hem HCl hem de intrinsik faktör üretiminin durmasına yol açar. Öncül II doğrudur: B12 vitamini ileal enterosite alımı için kubam reseptörüne (cubilin) bağlanmak üzere intrinsik faktöre ihtiyaç duyar; intrinsik faktör olmadan terminal ileumda emilim gerçekleşemez. Öncül III yanlıştır: B12 vitamini eksikliği megaloblastik aneminin yanı sıra subakut kombine dejenerasyon adı verilen spinal kord tutulumuna (arka ve lateral kolon) ve periferik nöropati gibi ciddi nörolojik tablolara da yol açar. Öncül IV doğrudur: paryetal hücreler hem intrinsik faktörü hem de HCl'yi salgılayan aynı hücre tipidir. Dolayısıyla doğru öncüller I, II ve IV'tür."},{"id":8502,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Kan bankasında çalışan bir teknisyen, taze donmuş plazma (TDP) ile trombosit süspansiyonunu karıştırıyor. Bir araştırmacı bu iki kan ürününü karşılaştırırken hangi özelliğin yalnızca taze donmuş plazmaya özgü olduğunu sormaktadır. Aşağıdakilerden hangisi yalnızca taze donmuş plazmada bulunup trombosit süspansiyonunda bulunmaz?","options":["Depolama sırasında soğutma ihtiyacı","Albumin ve diğer plazma proteinleri","Faktör VIII ve Faktör V gibi labil pıhtılaşma faktörleri","Fibrinojen","ABO uyumu gerekliliği"],"correct":2,"exp":"Taze donmuş plazma (TDP), tüm pıhtılaşma faktörlerini içerir; özellikle ısıya ve zamana duyarlı labil faktörler olan Faktör V ve Faktör VIII TDP'de korunur ancak trombosit süspansiyonunda bu faktörler bulunmaz. Diğer seçeneklere bakıldığında: ABO uyumu trombosit süspansiyonu için de önerilmektedir (özellikle büyük volümlerde); depolama sırasında soğutma trombositler için 20-24°C'de çalkalayıcıda, TDP için -18°C altında gereklidir, dolayısıyla her ikisi de soğutma/kontrollü depolama gerektirir; fibrinojen TDP'de bulunur ancak trombositlerde de alfa granüllerinde fibrinojen mevcuttur; albumin ise trombosit süspansiyonunun plazma fazında az miktarda bulunabilir. En özgül ve doğru yanıt labil pıhtılaşma faktörleridir."},{"id":8503,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"7 yaşında erkek çocukta çocukluk döneminden beri süren proksimal kas güçsüzlüğü vardır. Ailede anestezi sırasında malign hipertermi öyküsü bulunur. Kas biyopsisinde oksidatif enzim aktivitesinin bulunmadığı santral kor alanları saptanır. Bu hastalıkta kas güçsüzlüğüne yol açan temel işlevsel bozukluk hangisidir?","options":["Miyofibriler ATPaz aktivitesinin kompansatuar artması","RyR1 işlev bozukluğuna bağlı sarkoplazmik retikulumdan kalsiyum salınımının azalması","Miyozin ağır zincirlerinin hızlı lif tipine dönüşmesi","Nöromüsküler kavşakta asetilkolin reseptörü ekspresyonunun artması","Sarkomerik aktin polimerizasyonunun artması"],"correct":1,"exp":"Santral kor hastalığı sıklıkla RYR1 varyantlarıyla ilişkilidir. RyR1 işlev bozukluğu, uyarılma-kasılma eşleşmesi sırasında sarkoplazmik retikulumdan yeterli kalsiyum salınmasını engeller. Hastalık malign hipertermi yatkınlığıyla da ilişkilidir."},{"id":8504,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 3 haftadır devam eden efor dispnesi ve bacaklarda ödem yakınmasıyla başvuruyor. Özgeçmişinde 10 yıldır hipertansiyon ve 2 yıl önce geçirdiği miyokard enfarktüsü mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30, interstisyel fibrozis ve eksantrik hipertrofi saptanıyor. Hastaya nörohormonal blokaj amacıyla bir mineralokortikoid reseptör antagonisti başlanıyor. Aşağıdaki öncülleri değerlendirin:\nI. Bu ilaç sınıfı, kardiyak fibroblaslarda aldosteron aracılı kollajen sentezini azaltır.\nII. Kullanımı sırasında hiperkalemi gelişme riski, eş zamanlı ACE inhibitörü kullanımıyla artabilir.\nIII. Etki mekanizması gereği tübüler sodyum geri emilimini artırarak volümü düşürür.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, II ve III","I ve III","Yalnız I","I ve II","II ve III"],"correct":3,"exp":"Mineralokortikoid reseptör antagonistleri (spironolakton, eplerenon) kardiyak fibroblaslarda aldosteron aracılı profibrötik etkileri bloke ederek interstisyel fibrozisi azaltır (Öncül I doğru). Ayrıca proksimal tübülde değil distal tübül ve toplayıcı kanalda sodyum tutulumunu ve buna bağlı potasyum atılımını azaltırlar; bu nedenle hiperkalemi yapabilirler. ACE inhibitörleri de anjiyotensin II'yi azaltarak aldosteron salınımını düşürür ve potasyum kaybını azaltır; ikisinin birlikte kullanımı hiperkalemi riskini belirgin artırır (Öncül II doğru). Öncül III yanlıştır çünkü bu ilaçlar sodyum geri emilimini artırmaz, aksine azaltarak hafif natriürez ve volüm azalması sağlar. Bu nedenle doğru öncüller yalnızca I ve II'dir."},{"id":8505,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında kadın hasta, 2 yıldır devam eden yorgunluk, iştahsızlık ve poliüri yakınmasıyla başvuruyor. Özgeçmişinde 15 yıldır tip 2 diyabet mellitus mevcut. Laboratuvar tetkiklerinde serum kreatinin 3,2 mg/dL, BUN 54 mg/dL, HbA1c %9,4, spot idrarda albümin/kreatinin oranı 820 mg/g olarak saptanıyor. Böbrek biyopsisinde glomerüler bazal membranda kalınlaşma, mezangial matriks artışı ve Kimmelstiel-Wilson nodülleri izleniyor. Bu hastada glomerüler filtrasyon hızının düşmesinden birincil olarak sorumlu olan yapısal değişikliğin dolaylı göstergesi olan hangi laboratuvar bulgusu, GFR'deki azalmadan önce ortaya çıkar ve erken evre hasarın habercisi olarak kabul edilir?","options":["Mikroalbüminüri","Hiperkalemi","BUN/kreatinin oranı artışı","Serum kreatinin yüksekliği","Serum ürik asit yüksekliği"],"correct":0,"exp":"Diyabetik nefropatide ilk yapısal değişiklikler glomerüler bazal membran kalınlaşması ve mezangial matriks artışıdır. Bu değişiklikler başlangıçta GFR'yi düşürmeksizin glomerüler permeabiliteyi artırır ve küçük molekül olan albüminin süzülerek idrarla atılmasına yol açar. 30-300 mg/g aralığındaki bu erken albüminüri 'mikroalbüminüri' olarak adlandırılır ve GFR'nin bozulmadığı dönemde saptanabildiği için diyabetik nefropatinin en erken biyomarkeri olarak kabul edilir. Serum kreatinin ve BUN yüksekliği, nefronal kitlenin yaklaşık %50'si kaybedilmeden belirgin şekilde yükselmez; bu nedenle geç dönem göstergelerdir. Hiperkalemi ve ürik asit yüksekliği ise erken evre diyabetik nefropatinin karakteristik erken bulguları değildir."},{"id":8506,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"45 yaşında erkek hasta, 4 aydır sağ el bileğinde uyuşma, gece ağırlanan ağrı ve kavrama kuvvetinde azalma yakınmalarıyla başvuruyor. Tinel ve Phalen testleri pozitif saptanıyor. Sinir iletim çalışmasında median sinirde distal motor latansta uzama ve duysal iletim hızında yavaşlama izleniyor. Hastalığın altta yatan patolojisi olan sinir sıkışmasının neden olduğu demiyelinizasyon sürecinde etkilenen sinirde hangi histolojik değişiklik beklenir?","options":["Akson çapında progresif küçülme","Miyelin kılıfının segmental olarak incelmesi veya kaybolması","Ranvier boğumları arasındaki mesafenin artması","Nörofilaman birikiminin proksimalde yoğunlaşması","Schwann hücresi sayısında belirgin azalma"],"correct":1,"exp":"Karpal tünel sendromunda kronik mekanik bası, öncelikle miyelin kılıfını etkiler. Demiyelinizan süreçte Schwann hücreleri tarafından oluşturulan miyelin kılıfı segmental olarak incelir ya da tamamen kayboluir; bu histolojik değişiklik 'segmental demiyelinizasyon' olarak adlandırılır. Miyelin kılıfının bütünlüğü bozulduğunda saltatuar iletim gerçekleşemez, iletim hızı düşer ve distal latans uzar; bu da sinir iletim çalışmasındaki bulguları açıklar. Ranvier boğumları arasındaki mesafe (internodal mesafe) demiyelinizasyonla kısalır, uzamaz. Schwann hücresi sayısı başlangıçta korunur ve remyelinizasyon için çoğalabilir. Akson atrofisi ve nörofilaman birikimi ise aksonal dejenerasyonun, demiyelinizasyonun değil, bulgularıdır."},{"id":8507,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 5 yıldır devam eden tekrarlayan hırıltılı solunum, efor dispnesi ve gece öksürüğü yakınmalarıyla başvuruyor. Solunum fonksiyon testinde FEV1/FVC oranı %62, bronkodilatör sonrası FEV1'de %18 artış saptanıyor. Yüksek rezolüsyonlu toraks BT'de hava hapsi ve hafif bronş duvarı kalınlaşması izleniyor. Bronkoalveoler lavajda eozinofil hakimiyeti mevcut. Aşağıdaki öncülleri değerlendirin:\nI. Bu hastada bronş submukozasında mast hücre sayısının arttığı ve aktive olduğu beklenir.\nII. Havayolu düz kas hipertrofisi, kronik dönemde havayolu geri dönüşümsüz daralmasına katkıda bulunur.\nIII. Goblet hücresi hiperplazisi sonucu artan müköz sekresyon, mukosilyer kleransa katkı sağlar ve koruyucu bir mekanizmadır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Yalnız biri (Yalnız I)","İkisi (I ve II)","Üçü de (I, II ve III)","Yalnız biri (Yalnız II)","Hiçbiri"],"correct":1,"exp":"Astımda kronik havayolu inflamasyonunda mast hücreleri anahtar role sahiptir; IgE aracılı aktivasyonla histamin, lökotrienler ve prostaglandinler salgılayarak bronkospazmı tetiklerler. Öncül I doğrudur. Kronik astımda tekrarlayan inflamasyon ve yeniden şekillenme (remodeling) sürecinde havayolu düz kas kitlesi artarak hipertrofi ve hiperplazi gösterir; bu yapısal değişiklik geri dönüşümsüz havayolu daralmasının (fixed obstruction) önemli bir bileşenidir. Öncül II doğrudur. Öncül III yanlıştır; goblet hücresi hiperplazisi astımın patolojik bir bulgusu olup aşırı ve viskoz müküs üretimine yol açar. Bu durum mukosilyer kleransa katkı sağlamaz, aksine tıkaç oluşturup klerensı bozar ve akut alevlenmelerde ölüme neden olabilecek mukoid tıkaçlara zemin hazırlar. Dolayısıyla doğru öncül sayısı ikidir (I ve II)."},{"id":8508,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve çabuk yorulma yakınmalarıyla kardiyoloji polikliniğine başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya ACE inhibitörü ve beta bloker başlanıyor. İzlemde hastanın beta bloker dozunun titrasyon sürecinde kalp hızının yavaşlamasına rağmen kardiyak output'un korunduğu gözlemleniyor. Bu hastada kardiyak output'un korunmasını sağlayan birincil kompansatuar mekanizma hangisidir?","options":["Renin-anjiyotensin sisteminin baskılanmasıyla preloadun düzenlenmesi","Periferal vasküler direncin azalması","Frank-Starling mekanizması aracılığıyla atım hacminin artması","Baroreseptör refleksi aracılığıyla venöz dönüşün artması","Sempatik sinir sistemi aktivasyonuyla kontraktilitenin artması"],"correct":2,"exp":"Frank-Starling yasasına göre ventrikül diyastol sonu hacmi (preload) arttıkça miyokard kasılma kuvveti de artar. Beta bloker ile kalp hızı yavaşladığında diyastol süresi uzar, ventrikül dolumu artar ve end-diastolic volume yükselir. Bu artmış gerim, sarkomer uzunluğunu optimal düzeye taşıyarak aktin-miyozin çapraz köprü oluşumunu maksimize eder ve atım hacmini artırır. Böylece bradikardiye rağmen kardiyak output (KO = HR × SV) korunabilir. Bu mekanizma kalp yetmezliğinde özellikle önem kazanır çünkü dilate ventriküller başlangıçta bu yolla kompanse olur."},{"id":8509,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, 2 yıldır devam eden efor dispnesi ve kuru öksürük yakınmasıyla göğüs hastalıkları bölümüne başvuruyor. Solunum fonksiyon testlerinde FVC: %58, FEV1: %61, FEV1/FVC: %87 olarak saptanıyor. DLCO belirgin şekilde düşük bulunuyor. Yüksek rezolüsyonlu BT'de bilateral bazal retiküler patern ve balpeteği görünümü izleniyor. Hastaya pirfenidon başlanıyor. Bu hastada DLCO'nun düşük olmasının temel nedeni aşağıdakilerden hangisiyle en doğru şekilde açıklanır?","options":["Pulmoner kapiller yatak kaybına bağlı perfüzyon yüzeyinin daralması","Surfaktan eksikliğine bağlı alveoler kollaps","Alveoler-kapiller membran kalınlaşmasına bağlı diffüzyon kapasitesinin azalması","Alveoler hipoventilasyon sonucu PaCO2'nin yükselmesi","Hava yolu obstrüksiyonuna bağlı ventilasyon-perfüzyon uyumsuzluğu"],"correct":2,"exp":"İdiyopatik pulmoner fibrozis (IPF) gibi interstisyel akciğer hastalıklarında fibröz doku birikimi alveoler-kapiller membranı kalınlaştırır. Fick difüzyon yasasına göre gaz transferi membran kalınlığıyla ters orantılıdır; membran kalınlaştıkça CO difüzyonu bozulur ve DLCO düşer. Restriktif patern (FVC düşük, FEV1/FVC normal veya yüksek) bu tanıyı destekler. Balpeteği görünümü ve bazal retiküler patern IPF'ye özgü HRCT bulgularıdır. Pirfenidon, TGF-β yolağını inhibe ederek fibrozis progresyonunu yavaşlatan bir antifibrotik ajandır."},{"id":8510,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 6 aydır giderek artan kas güçsüzlüğü yakınmasıyla nöroloji polikliniğine başvuruyor. Sabahları daha iyi olduğunu, gün içinde yoruldukça güçsüzlüğünün arttığını belirtiyor. Tekrarlayan sinir uyarım testinde bileşik kas aksiyon potansiyel amplitüdünde giderek azalma saptanıyor. Anti-asetilkolin reseptör antikorları pozitif bulunan hastaya piridostigmin başlanıyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Piridostigmin, asetilkolinin sinaptik aralıkta yıkımını azaltarak nöromüsküler iletimi artırır.\nII. Bu hastalıkta otoimmün süreç presinaptik terminali hedef alır.\nIII. Tekrarlayan uyarımda amplitüd azalması postsinaptik reseptör kaybını yansıtır.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","Yalnız I","II ve III","I ve II","I, II ve III"],"correct":0,"exp":"Miyastenia gravis'te otoimmün antikorlar postsinaptik nikotinik asetilkolin reseptörlerini (AChR) hedef alır; bu nedenle II. öncül yanlıştır (presinaptik değil, postsinaptik etkilenim söz konusudur). I. öncül doğrudur: piridostigmin, asetilkolinesterazı inhibe ederek asetilkolinin sinaptik aralıkta birikmesini ve kısıtlı sayıdaki fonksiyonel reseptörü daha uzun süre uyarmasını sağlar. III. öncül doğrudur: tekrarlayan uyarımda her impulsla serbestlenen asetilkolin miktarı sabitken hedef reseptör sayısı azalmış olduğundan ardışık kas yanıtları giderek küçülür ve bu dekremental patern postsinaptik reseptör kaybının elektrofizyolojik yansımasıdır. Doğru öncüller I ve III'tür."},{"id":8511,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında erkek hasta, birkaç saatte bir idrara çıkma ve aşırı su içme isteğiyle başvuruyor. Günlük idrar hacmi 8 litre olarak ölçülüyor, idrar dansitesi 1.001. Su kısıtlama testinde idrar dansitesi artmıyor ancak desmopressin uygulaması sonrasında idrar dansitesi 1.018'e yükseliyor. Bu hastada en olası tanı ve bozulan yapısal/fonksiyonel komponent hangisidir?","options":["Nefrojenik diabetes insipidus; toplayıcı tübül V2 reseptör veya akuaporin-2 yetersizliği","Santral diabetes insipidus; hipofiz arka lobundan ADH salınımının yetersizliği","Tip 1 diabetes mellitus; insülin eksikliğine bağlı ozmotik diürez","Renal tübüler asidoz; proksimal tübül bikarbonat geri emilim bozukluğu","Psikojenik polidipsi; primer su alımı artışına bağlı dilüsyonel hiponatremi"],"correct":1,"exp":"Desmopressin (sentetik ADH) sonrası idrar dansitesinin belirgin artması, böbreğin ADH'ya yanıt verebilir olduğunu gösterir; bu da sorunun ADH yokluğundan kaynaklandığını ortaya koyar. Santral diabetes insipidus'ta hipotalamus ya da hipofiz arka lobundan yeterli ADH salınamaz. Toplayıcı tübül prensipel hücrelerindeki V2 reseptörleri işlevini korumaktadır; bu yüzden ekzojen ADH (desmopressin) uygulandığında aquaporin-2 kanalları apikale transloke olur, su reabsorpsiyonu artar ve idrar konsantrasyonu yükselir. Nefrojenik formda ise desmopressin'e yanıt alınamaz. Su kısıtlamasında dansite artmaması, psikojenik polidipsiyi dışlar."},{"id":8512,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Aşağıdaki öncülleri değerlendiriniz:\nI. Eritropoetin (EPO) esas olarak karaciğer perisinüzoidal hücrelerinden salgılanır ve eritroid progenitör hücrelerin apoptozunu inhibe eder.\nII. Demir eksikliğinde transferrin satürasyonu azalırken serum ferritin düzeyi artar.\nIII. Retikülosit, nükleer matürasyonu tamamlanmamış olup ribozomal RNA kalıntıları içeren olgun öncesi eritrosittir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","2 tanesi","Yalnız 1 tanesi","3 tanesi","Yalnız II ve III"],"correct":2,"exp":"I. Öncül yanlıştır: EPO %85-90 oranında böbrek peritübüler interstisyel hücrelerinden (fibroblast benzeri hücreler) salgılanır; karaciğer ikincil kaynaktır. Eritroid progenitör hücrelerin apoptozunu inhibe etmesi ise doğrudur, ancak kaynak bilgisi hatalı olduğu için öncül yanlış kabul edilir. II. Öncül yanlıştır: demir eksikliğinde ferritin depo demirini yansıttığından düşer; transferrin satürasyonu da azalır. Ferritinin artması inflamasyon veya hemokromatoz gibi durumlarda görülür. III. Öncül doğrudur: retikülosit çekirdeğini atmış ancak henüz ribozomal RNA (ve polizom) kalıntılarını içeren, supravital boyamada ağ benzeri yapı gösteren immatür eritrosittir. Dolayısıyla yalnızca III. öncül doğrudur, cevap 'yalnız 1 tanesi'dir."},{"id":8513,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"61 yaşında erkek hasta, 4 aydır devam eden şişkinlik, yağlı ve kötü kokulu dışkılama yakınmalarıyla gastroenteroloji polikliniğine başvuruyor. Hastanın 72 saatlik dışkıda yağ miktarı artmış (steatoöre), D-ksiloz testi normal sınırlarda bulunuyor. Sudan III boyama ile dışkıda nötral yağ granülleri saptanıyor. Endoskopik biyopside ince barsak mukoza yapısı normal görünümde. Bu hastada malabsorpsiyonun en olası nedeni aşağıdakilerden hangisidir?","options":["Lenfanjiektaziye bağlı şilomikron transportu bozukluğu","Bakteriyel aşırı çoğalmaya bağlı konjuge safra tuzu dekonjügasyonu","Çölyak hastalığına bağlı villöz atrofi","Safra tuzu eksikliğine bağlı misel oluşum yetersizliği","Ekzokrin pankreas yetersizliğine bağlı lipaz eksikliği"],"correct":4,"exp":"D-ksiloz testi normal olması mukozal emilim kapasitesinin korunduğunu gösterir; bu durum çölyak hastalığı ve mukozal hasarı olan diğer nedenleri dışlar. Nötral yağ granüllerinin görülmesi, yağın sindirilmeden (hidrolize edilmeden) dışkıya geçtiğine işaret eder. Bu bulgu pankreatik lipaz yetersizliğini düşündürür: lipaz olmadan trigliseridler yağ asidi ve monogliseride parçalanamaz, misel oluşumu bozulur ve nötral yağ formunda dışkılanır. Ekzokrin pankreas yetersizliğinin en sık nedenleri kronik pankreatit ve kistik fibrozistir. Safra tuzu eksikliğinde ise sindirim kısmen gerçekleşir ancak misel oluşumu bozulur; dışkıda yağ asitleri daha belirgindir, nötral yağ daha az izlenir. Biyopside normal mukoza görülmesi ekzokrin pankreas patolojisini daha da güçlü destekler."},{"id":8514,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı şikayetiyle kardiyoloji polikliniğine başvuruyor. Özgeçmişinde tip 2 diyabet ve hiperlipidemi mevcut. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya tedavi düzenleniyor; digoksin başlandıktan sonra istirahat kalp hızının belirgin şekilde düştüğü ve semptomların kısmen gerilediği gözlemleniyor. Bu hastada digoksinin kalp hızını düşürmesinde birincil olarak hangi yapının aktivitesi artmaktadır?","options":["Sempatik sinir uçlarından norepinefrin salınımı","His demeti iletim hızındaki artış","Vagal tonus artışına bağlı muskarinik reseptör uyarısı","Sinoatriyal düğüm otomatisitesi","Atriyoventriküler düğüm iletim hızı"],"correct":2,"exp":"Digoksin, Na+/K+-ATPaz pompasını inhibe ederek dolaylı yoldan intrasellüler Ca2+ artışına yol açar ve pozitif inotropik etki gösterir. Kronotrop etkisi ise ağırlıklı olarak vagal tonusu artırması ve merkezi sinir sistemindeki vagal nükleusları uyarması aracılığıyla gerçekleşir. Bu mekanizma ile AV düğüm üzerindeki muskarinik (M2) reseptörler aktive olur, AV iletim yavaşlar ve istirahat kalp hızı düşer. Sinoatriyal düğüm otomatisitesi digoksin tarafından baskılanır, artırılmaz. Sempatik aktivite ise digoksinin terapötik dozlarında baskılanma eğilimindedir."},{"id":8515,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 6 aydır devam eden kuru öksürük ve efor dispnesi nedeniyle göğüs hastalıkları polikliniğine başvuruyor. Toraks BT'de bilateral yaygın buzlu cam görünümü ve traksiyon bronşiektazisi saptanıyor. Solunum fonksiyon testinde FEV1/FVC oranı %85, TLC belirgin düşük bulunuyor. Akciğer difüzyon kapasitesi (DLCO) ise beklenenin %48'i olarak ölçülüyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Hastalık öncelikle tip I pnömositlerde hasar yaratarak alveolokapiller membran kalınlaşmasına yol açar.\nII. Gaz difüzyonundaki bozulma yalnızca CO2 için geçerlidir, O2 difüzyonu korunur.\nIII. DLCO düşüklüğü, difüzyon alanının azalması ve membran kalınlaşmasının birlikte katkısıyla açıklanabilir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve III","Yalnız I","I, II ve III","II ve III","Yalnız III"],"correct":0,"exp":"İnterstisyel akciğer hastalıklarında (örn. idiyopatik pulmoner fibrozis) kısıtlayıcı patern ve DLCO düşüklüğü tipik bulgulardır. Öncül I doğrudur: fibrozis sürecinde tip I pnömositler (ince, gaz değişiminden sorumlu hücreler) tahrip olur, tip II pnömositler prolifere olur ve alveolokapiller membran kalınlaşır. Öncül II yanlıştır: CO2 difüzyon katsayısı O2'den yaklaşık 20 kat fazladır, dolayısıyla CO2 difüzyonu uzun süre korunur; hipoksemi, hiperkapniye çok daha önce ortaya çıkar. Öncül III doğrudur: DLCO düşüklüğü hem membran kalınlaşmasına (difüzyon mesafesi artışı) hem de fonksiyonel alveoler yüzey alanının azalmasına bağlıdır."},{"id":8516,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, son 3 aydır giderek kötüleşen halsizlik, ödem ve iştahsızlık şikayetiyle nefroloji polikliniğine başvuruyor. Kan basıncı 168/98 mmHg, serum kreatinin 6,2 mg/dL, BUN 89 mg/dL, serum K+ 6,1 mEq/L, serum bikarbonat 14 mEq/L olarak ölçülüyor. İdrar dansite 1.010 olup sabah ve akşam idrar dansite değerlerinin birbirine eşit ve sabit olduğu gözlemleniyor. Bu hastada sabit idrar dansitesinin (izostenüri) primer nedeni aşağıdakilerden hangisidir?","options":["Antidiüretik hormon (ADH) salınımının tamamen durması","Renin sekresyonunun artması nedeniyle sodyum geri emiliminin aşırı güçlenmesi","Glomerüler filtrasyon hızının artmasına bağlı tübüler yükün yükselmesi","Toplayıcı kanalların aquaporin-2 ekspresyonunun aşırı artması","Tübüler fonksiyon kaybı sonucu konsantrasyon ve dilüsyon kapasitesinin yitirilmesi"],"correct":4,"exp":"İzostenüri (sabit, düşük idrar dansitesi ~1.010), ileri kronik böbrek yetmezliğinde tübüler fonksiyonların ciddi biçimde bozulması sonucu ortaya çıkar. Sağlıklı böbrekte proksimal tübül, Henle kulpu ve toplayıcı kanallar konsantrasyon-dilüsyon mekanizmasını yürütür. Nefron kitlesi dramatik biçimde azaldığında kalan nefronların bireysel filtrasyon yükü artar; ancak hipertrofiye uğrayan bu nefronlar konsantrasyon ve dilüsyon kapasitelerini koruyamazlar. Sonuçta idrar dansite değerleri plazma osmolalitesine yakın, sabit bir düzeyde (izostenürik aralıkta) kalır. ADH salınımının durması durumunda idrar sulandırılırdı; aquaporin-2 artışı ise idrarı konsantre eder. GFR artışı söz konusu değildir; aksine bu hastada GFR belirgin düşüktür."},{"id":8517,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"22 yaşında kadın hasta, 2 gün önce başlayan sağ el ve ön kolda uyuşukluk ile karıncalanma yakınmasıyla nöroloji polikliniğine başvuruyor. Özgeçmişinde 6 ay önce geçici görme kaybı yaşadığı öğreniliyor. MR görüntülemede periventriküler beyaz cevherde demiyelinizan plaklar saptanıyor. Nörolog hastaya interferon beta-1a tedavisi başlıyor. Aşağıdaki öncülleri değerlendiriniz:\nI. Semptomların beyaz cevherde lokalize olması, ağırlıklı olarak akson hasarını değil miyelin kılıfı hasarını yansıtır.\nII. Demiyelinizasyon sonrası sinir iletim hızı düşer çünkü aksiyon potansiyeli saltatory (sıçramalı) iletimden sürekli iletimine geçmek zorunda kalır.\nIII. Oligodendrosit başına miyelin oluşturulan akson sayısı periferik sinir sistemindeki Schwann hücrelerinden azdır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["İki tanesi","Üç tanesi","Değerlendirmek için yetersiz bilgi","Hiçbiri","Yalnız bir tanesi"],"correct":0,"exp":"Öncül I doğrudur: Beyaz cevher lezyonları miyelin kılıfının zarar gördüğünü gösterir; gri cevher ağırlıklı olarak nöronal gövdeler ve dendritlerden oluşur. MS'te primer hedef miyelin ve oligodendrositlerdir. Öncül II doğrudur: Miyelin, aksiyon potansiyelinin Ranvier boğumları arasında sıçramalı (saltatory) iletimini sağlar; demiyelinizasyonla bu mekanizma bozulur ve iletim yavaşlar ya da tamamen durur. Öncül III yanlıştır: Bir oligodendrosit yaklaşık 30-50 aksona miyelin sağlarken, periferal sinir sistemindeki bir Schwann hücresi yalnızca tek bir aksonu miyelin oluşturur. Dolayısıyla I ve II doğru, III yanlış olduğundan iki öncül doğrudur."},{"id":8518,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"45 yaşında erkek hasta, 4 aydır devam eden epigastrik yanma, asit regürjitasyonu ve yemek sonrası şişkinlik yakınmalarıyla gastroenteroloji polikliniğine başvuruyor. Endoskopide distal özofagusta silindirik metaplazi saptanıyor ve biyopside goblet hücreleri görülüyor. Proton pompa inhibitörü (PPI) tedavisine ek olarak mide asit sekresyonunu azaltmak amacıyla H2 reseptör blokeri de ekleniyor. Bu ilaçların mide asit sekresyonunu azaltma mekanizmalarıyla ilgili aşağıdakilerden hangisi doğrudur?","options":["H2 blokerleri ve PPI'lar aynı reseptör üzerinden etki gösterdikleri için birlikte kullanımları önerilmez.","PPI'lar, chief hücresinden pepsinojen salınımını azaltır.","PPI'lar, histamin reseptörlerine bağlanarak cAMP üretimini engeller.","H2 blokerleri paryetal hücrede cAMP artışını önlerken, PPI'lar aktif H+/K+-ATPaz pompasını inhibe eder.","H2 blokerleri, paryetal hücredeki H+/K+-ATPaz'ı geri dönüşümsüz olarak inhibe eder."],"correct":3,"exp":"Paryetal hücreler üzerinde histamin (H2 reseptörü), gastrin ve asetilkolin reseptörleri bulunur. Histamin H2 reseptörüne bağlandığında adenilil siklaz aktive olur, cAMP artar ve protein kinaz A aracılığıyla H+/K+-ATPaz (proton pompası) aktive edilir. H2 reseptör blokerleri bu basamağı engelleyerek cAMP artışını önler. PPI'lar ise kanalikülde proton pompasını geri dönüşümsüz biçimde inhibe eden ilaçlardır; etkilerini H2 reseptörü üzerinden değil, doğrudan enzim düzeyinde gösterirler. İki ilaç farklı mekanizmalarla çalıştığından birlikteliği additive etki sağlayabilir."},{"id":8519,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı şikayetiyle başvuruyor. Yapılan ekokardiyografide ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya tedavi başlanmasının ardından kontrol muayenelerinde dinlenim kalp hızının azaldığı, semptomların gerilediği izleniyor. Ancak hastanın ardından gelişen akut hipertansif krizde ilaç dozu artırılıyor. Aşağıdaki öncülleri değerlendirin:\nI. Bu hastada kullanılan ilaç, L-tipi voltaj kapılı kalsiyum kanallarını inhibe ederek periferik vasküler direnci düşürebilir.\nII. Negatif kronotropik etki, SA düğümündeki If akımının baskılanmasıyla açıklanabilir.\nIII. Miyokardiyal oksijen tüketimi, hem negatif inotrop hem de negatif kronotrop etkiyle azalır.\nIV. Bu ilaç sınıfı, digoksinden farklı olarak Na+/K+ ATPaz pompasını inhibe etmez.\nYukarıdaki öncüllerden kaç tanesi dihydropiridin olmayan kalsiyum kanal blokörlerine ait doğru bir özelliği tanımlamaktadır?","options":["Hiçbiri","3 tanesi","2 tanesi","Yalnız 1 tanesi","4 tanesi"],"correct":1,"exp":"Dihydropiridin olmayan KKB'ler (verapamil, diltiazem) L-tipi Ca2+ kanallarını hem vasküler düz kasta hem de kalpte bloke eder; bu nedenle periferik vazodilatasyonla birlikte negatif kronotropi ve negatif inotrópi de oluştururlar. I: Verapamil ve diltiazem L-tipi kanalları bloke ederek periferik direnci düşürür — DOĞRU. II: SA düğümündeki If (funny current) akımı asıl olarak ivabradin tarafından baskılanır; verapamil/diltiazem ise SA düğümünde Ca2+-bağımlı aksiyon potansiyelini yavaşlatarak kronotrópiyi azaltır, If akımı üzerine primer etkileri yoktur — YANLIŞ. III: Negatif kronotropi ve inotrópi birlikte miyokardiyal O2 tüketimini azaltır — DOĞRU. IV: Bu ilaçlar Na+/K+ ATPaz'ı inhibe etmez, digoksinden bu yönüyle ayrılır — DOĞRU. Dolayısıyla doğru öncüller I, III ve IV olmak üzere 3 tanesidir."},{"id":8520,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, yoğun stres döneminin ardından sol gözünde görme kaybı ve renk algısında bozulma başladığını ifade ediyor. Nörolojik muayenede sol afferent pupiller defekt (Marcus Gunn pupili) saptanıyor. Beyin MR'da periventriküler beyaz cevherde demiyelinizan lezyonlar görülüyor. Hastaya yüksek doz intravenöz metilprednizolon tedavisi başlanıyor. Bu tedavinin akut atağı kısaltmasındaki temel fizyolojik mekanizma aşağıdakilerden hangisiyle en doğru şekilde açıklanır?","options":["Mikroglia aktivasyonunu kalıcı olarak baskılayarak sekonder aksonal hasarı önlemesi","T lenfositlerinde apoptozu indükleyerek miyelin bazik proteine karşı oluşan antikor titrelerini düşürmesi","Oligodendrositlerin remyelinizasyon kapasitesini artırarak akson iletim hızını kalıcı biçimde düzeltmesi","Sodyum kanal ekspresyonunu artırarak demiyelinize aksonlardaki impuls iletimini kompanse etmesi","Kan-beyin bariyerinin geçirgenliğini azaltarak ödem ve inflamasyonu baskılaması"],"correct":4,"exp":"Multipl skleroz akut atak tedavisinde kullanılan yüksek doz IV metilprednizolon, kan-beyin bariyerinin geçirgenliğini azaltarak inflamatuvar hücre geçişini kısıtlar ve lezyon çevresindeki ödemi geriletir. Bu etki atağın süresini kısaltır ancak uzun dönem prognoz üzerine kalıcı bir etkisi yoktur. Remyelinizasyonu doğrudan artırmaz (A yanlış). Antikor titrelerini düşürmek IVIg veya plazmaferez mekanizmasıdır (C yanlış). Sodyum kanal ekspresyonu artışı demiyelinizasyona adaptif bir yanıttır, kortikosteroidlerin mekanizması değildir (D yanlış). Mikroglia baskılanması kısmi doğru olmakla birlikte 'kalıcı' ibaresi hatalıdır ve temel mekanizma kan-beyin bariyeri bütünlüğünün yeniden sağlanmasıdır (E yanlış)."},{"id":8521,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, tip 2 diyabetes mellitus tanısıyla 12 yıldır metformin kullanmaktadır. Son kontrol tetkiklerinde idrarda albümin/kreatinin oranı 380 mg/g, GFR 42 mL/dak/1,73 m2 olarak saptanıyor. Hastanın tedavisine SGLT-2 inhibitörü ekleniyor. Bu ilacın renal koruyucu etkisine katkıda bulunan tübüler mekanizmalarla ilgili aşağıdaki öncülleri değerlendirin:\nI. Proksimal tübülden glikoz ve sodyum reabsorbsiyonunu azaltarak tübüloglomerüler geri bildirimi (TGF) aktive eder ve afferent arteriyol vazokonstriksiyonuna yol açar.\nII. Tübüler sodyum yükünün azalması, Na+/H+ değiştirici (NHE3) aktivitesini baskılar ve intratübüler basıncı düşürür.\nIII. SGLT-2 inhibisyonu, eritropoetin salınımını artırarak renal kortikal oksijenasyonu iyileştirir.\nIV. Afferent arteriyol tonusunun artması, glomerüler hidrostatik basıncı azaltarak hiperfiltrasyon hasarını önler.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I, II, III ve IV","II ve III","I, III ve IV","Yalnız I ve IV","I, II ve IV"],"correct":3,"exp":"SGLT-2 inhibitörleri proksimal tübülde glikoz ve Na+ reabsorbsiyonunu azaltır; bu durum daha fazla NaCl'nin macula densaya ulaşmasına neden olarak tübüloglomerüler geri bildirimi (TGF) aktive eder. TGF aracılığıyla afferent arteriyolde vazokonstriksiyon oluşur (I doğru) ve glomerüler hidrostatik basınç düşer, böylece diyabetik nefropatinin erken evresindeki hiperfiltrasyon hasarı önlenir (IV doğru). II: NHE3 aktivitesinin baskılanması SGLT-2 inhibisyonunun dolaylı bir etkisi olsa da bu öncülde tanımlanan mekanizma (intratübüler basınç düşmesi) renal koruma mekanizmasını tam olarak yansıtmamaktadır ve bu ilaçların temel etkisi olarak kabul görmemektedir — YANLIŞ. III: SGLT-2 inhibitörlerinin eritropoetin salınımını artırdığı gösterilmiş olmakla birlikte bu etki renal koruyucu mekanizmanın kanıtlanmış birincil yolu değildir ve 'renal kortikal oksijenasyonu iyileştirme' ifadesi mekanizmayı doğrudan açıklamaz — YANLIŞ. Bu nedenle doğru öncüller yalnız I ve IV'tür."},{"id":8522,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"35 yaşında kadın hasta, 2 yıldır süren öksürük, hırıltılı solunum ve eforla gelen nefes darlığı şikayetleriyle başvuruyor. Solunum fonksiyon testinde FEV1/FVC: 0,65, FEV1: %72 (beklenenin), bronkodilatör sonrası FEV1'de %18 artış saptanıyor. Yüksek rezolüsyonlu BT'de hava hapsi alanları ve mozaik patern izleniyor. Hastada hava yolu obstrüksiyonunun gelişmesinde en belirleyici rolü oynayan bronş duvarı histolojik değişikliği hangisidir?","options":["Clara hücresi kaybı ve bronşiolar epitel soyulması","Tip II pnömosit hiperplazisi ve surfaktan yetersizliği","Düz kas hipertrofisi, subepitelyal fibrozis ve goblet hücresi metaplazisi","Goblet hücrelerinde azalma ve müköz bez atrofisi","Alveolar makrofaj birikimi ve elastik lif yıkımı"],"correct":2,"exp":"Bu klinik tablo bronşiyal astımı düşündürmektedir (reversibl obstrüksiyon bulgusu mevcut ancak bronkodilatör yanıtı %12 eşiğinin üzerinde). Astımda hava yolu duvarındaki temel histolojik değişiklikler düz kas hipertrofisi ve hiperplazisi, subepitelyal kollajen birikimi (fibrozis) ve goblet hücresi metaplazisidir. Bu değişiklikler lümen daralmasına ve hava akımı kısıtlanmasına yol açar. Goblet hücresi azalması ve müköz bez atrofisi astımın tersi bir bulgudur (A yanlış). Tip II pnömosit hiperplazisi ve surfaktan yetersizliği RDS ile ilişkilidir (B yanlış). Alveolar makrofaj birikimi ve elastik lif yıkımı amfizeme özgüdür (D yanlış). Clara hücresi kaybı ve epitel soyulması bronşiyolit ile daha çok ilişkilidir (E yanlış)."},{"id":8523,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Midenin fundus bölgesinde yer alan oksintik bezlerdeki parietal hücrelerle ilgili aşağıdaki öncülleri değerlendirin:\nI. Parietal hücreler HCl salgılamak için apikal membranda H+/K+ ATPaz pompası kullanır.\nII. Asetilkolin, gastrin ve histamin parietal hücre aktivasyonunu uyarır.\nIII. Parietal hücreler intrinsik faktörü sentezler ve bu faktör B12 vitamini emilimi için gereklidir.\nIV. Omeprazol, H+/K+ ATPaz pompasını geri dönüşümsüz olarak inaktive ederek etki gösterir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["I ve II","I, II, III ve IV","I, II ve III","Yalnız I ve IV","II, III ve IV"],"correct":1,"exp":"I: Parietal hücreler kanalikül membranında H+/K+ ATPaz (proton pompası) aracılığıyla H+ iyonunu lümene, K+ iyonunu hücre içine alır; HCl böylece salgılanır — DOĞRU. II: Parietal hücre aktivasyonu üç majör yolla sağlanır: asetilkolin (M3 reseptörü), gastrin (CCK-B reseptörü) ve histamin (H2 reseptörü) — DOĞRU. III: İntrinsik faktör parietal hücreler tarafından sentezlenir ve terminal ileumda B12 vitamini (kobalamin) emilimi için şarttır; otoimmün gastrit veya gastrektomide parietal hücre kaybı pernisiyöz anemiye yol açar — DOĞRU. IV: Omeprazol aktif pompaların sistein rezidülerine kovalent bağlanarak H+/K+ ATPaz'ı geri dönüşümsüz inhibe eden bir proton pompası inhibitörüdür — DOĞRU. Tüm öncüller doğrudur."},{"id":8524,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, 8 aydır süren kuru öksürük ve progresif efor dispnesi yakınmasıyla başvuruyor. Sigara kullanım öyküsü yok. Toraks BT'de bilateral bazal retiküler opasite ve balpeteği görünümü saptanıyor. Solunum fonksiyon testlerinde FVC: %58, FEV1/FVC: %84 bulunuyor. Bronkoalveoler lavaj sitolojisinde nötrofil ve eozinofil oranlarında artış izleniyor. Bu hastada altta yatan patolojide en fazla etkilenen akciğer yapısı hangisidir?","options":["Alveoler makrofajlar","Karina epiteli","Clara (Club) hücreleri","Tip II pnömositler","Tip I pnömositler"],"correct":4,"exp":"İdiyopatik pulmoner fibrozis (IPF), özellikle Tip I pnömositleri etkileyen bir hastalıktır. Tip I pnömositler gaz değişimini sağlayan, ince ve yayvan hücrelerdir; alveoler yüzeyin %97'sini örterler ancak total hücre sayısının yalnızca %40'ını oluştururlar. IPF'de Tip I pnömosit hasarı ve kaybının ardından Tip II pnömositler prolifere olup onların yerini almaya çalışır. Bu nedenle geç dönemde Tip II pnömosit proliferasyonu gözlemlense de primer hasar Tip I'dedir. Restriktif patern (düşük FVC, normal FEV1/FVC), bazal retiküler opasite ve balpeteği görünümü birlikte IPF tanısını destekler."},{"id":8525,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında kadın hasta, ani başlayan göğüs ağrısı ve çarpıntı yakınmasıyla acil servise başvuruyor. EKG'de dar QRS taşikardi saptanıyor; yapılan vagal manevra ile ritim sinüse dönüyor. Kardiyoloji konsültasyonunda paroksismal supraventriküler taşikardi tanısı konuluyor ve sinüs düğümünün otorisitesini azaltmak amacıyla adenozin verilmesi planlanıyor. Adenozinin sinüs düğümü üzerindeki etkisini açıklayan en doğru histofizyolojik mekanizma hangisidir?","options":["L-tipi Ca2+ kanallarını aktive ederek efektör refrakter dönemi uzatır","IKACh kanallarını açarak K+ çıkışını artırır ve spontan depolarizasyon eşiğini yükseltir","Hızlı Na+ kanallarını bloke ederek aksiyon potansiyeli yükselmesini yavaşlatır","If (funny) kanallarını aktive ederek diastolik depolarizasyonu hızlandırır","Geç Na+ kanallarını bloke ederek platö fazını kısaltır"],"correct":1,"exp":"Sinüs düğümü (SA nod) peysmeyker hücreleri hızlı Na+ kanalı içermez; aksiyon potansiyelleri L-tipi Ca2+ kanalları ve If kanalları aracılığıyla oluşur. Adenozin, A1 reseptörleri üzerinden Gi proteini aktivasyonuyla IKACh (asetilkolin ile aktive olan K+ kanalı) kanallarını açar. Bu kanalların açılması K+ iletkenliğini artırır, membranı hiperpolarize eder ve spontan diastolik depolarizasyonun eşiğe ulaşmasını geciktirir; böylece sinüs ritmi yavaşlar ve AV iletim yavaşlar. Bu mekanizma parasempatomimetik etkiyle özdeştir."},{"id":8526,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, 4 haftadır ilerleyici el ve ayaklarda his kaybı, ellerde titreme ve yürüme güçlüğü yakınmalarıyla nöroloji polikliniğine başvuruyor. Nörolojik muayenede derin tendon reflekslerinde azalma, vibrasyon ve propriosepsiyon kaybı saptanıyor. Sinir iletim çalışmalarında motor iletim hızında belirgin yavaşlama, distal latansların uzaması ve iletim bloğu gözlemleniyor. Bu hastada sorumlu patoloji aşağıdaki hangi yapıyı öncelikli olarak etkileyen bir süreci işaret etmektedir?","options":["Periferik sinir miyelin kılıfı (Schwann hücreleri)","Dorsal kök ganglion nöron gövdeleri","Nöromüsküler kavşak postsinaptik membranı","Ranvier boğumları arasındaki akson membranı","Beyin sapı retiküler formasyon nöronları"],"correct":0,"exp":"Motor iletim hızında yavaşlama, distal latans uzaması ve iletim bloğu, demyelinizan bir periferik nöropatiyi gösterir. Tuzlayıcı iletim (saltatory conduction) miyelin kılıfının sağlamlığına bağlıdır; Schwann hücreleri tarafından oluşturulan miyelin kılıfının hasarı bu elektrofizyolojik bulguları üretir. Aksonal nöropatilerde ise iletim hızı görece korunur ancak aksiyon potansiyeli amplitüdü düşer. Klinik tablo Guillain-Barré sendromu ile uyumludur ve periferik sinir miyelin kılıfına yönelik otoimmün saldırıyı yansıtır."},{"id":8527,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır devam eden şişlik, halsizlik ve az miktarda idrar çıkışı yakınmalarıyla başvuruyor. Laboratuvar incelemesinde serum kreatinin: 4,8 mg/dL, BUN: 78 mg/dL, serum albumin: 2,1 g/dL saptanıyor. İdrarda nefrotik düzeyde proteinüri (6,2 g/gün) ve oval yağ cisimcikleri görülüyor. Böbrek biyopsisinde glomerüler bazal membranın kalınlaştığı ve 'spike and dome' görünümü izleniyor. Bu hastaya verilen ACE inhibitörü tedavisinin böbrek üzerindeki koruyucu etkisinin temel anatomik hedefi hangisidir?","options":["Podosit ayaksı çıkıntılarının yeniden düzenlenerek proteinürinin azaltılması","Proksimal tübül hücrelerinde Na+-H+ antiporter aktivitesinin artırılması","Afferent arteriol vazokonstrüksiyonu ile glomerüler filtrasyonun azaltılması","Efferent arteriol vazodilatasyonu ile intraglomerüler basıncın düşürülmesi","Mesangyal hücre proliferasyonunun Ang II bağımsız yollarla inhibisyonu"],"correct":3,"exp":"ACE inhibitörleri, anjiyotensin II'nin efferent arteriolu konstrike etme etkisini bloke eder. Efferent arteriol vazodilatasyonu intraglomerüler hidrostatik basıncı düşürür; bu sayede filtrasyona maruz kalan mekanik stres azalır ve protein geçirgenliği görece sınırlanır. Membranöz nefropati gibi nefrotik sendrom tablolarında intraglomerüler basıncın kronik yüksekliği glomerüler hasarı hızlandırır. ACE inhibitörlerinin renoprotektif etkisi esas olarak efferent arteriol üzerindeki bu vazodilatör mekanizmaya dayanır, afferent arteriol üzerine etkisi değildir."},{"id":8528,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":3,"q":"İskelet kası kontraksiyonu ile ilgili aşağıdaki öncüller değerlendirildiğinde hangileri doğrudur?\nI. Troponin C, Ca2+ ile bağlandığında tropomiyozini aktin filamenti üzerinden kaydırarak miyozin bağlanma bölgelerini açar.\nII. Bir kas lifi tek bir motor nöronun uyarısıyla maksimal kuvvet üretebilir (her şey ya da hiç kuralı).\nIII. H bandı, miyozin filamentlerinin aktin filamentleriyle örtüşmeyen bölgesini temsil eder ve kasılma sırasında daralır.\nIV. Titin proteini, sarkomerin pasif gerilim özelliğini belirleyerek Z çizgisi ile M çizgisi arasında köprü görevi görür.","options":["I, II ve IV","Yalnız I ve III","II, III ve IV","I, III ve IV","I, II, III ve IV"],"correct":3,"exp":"Öncül I doğrudur: Ca2+, troponin C'ye bağlanır; bu bağlanma troponin-tropomiyozin kompleksini konformasyon değişikliğine uğratır ve miyozin bağlanma bölgelerini açar. Öncül II yanlıştır: Tek bir kas lifi 'hep ya hiç' prensibine göre çalışır; ancak maksimal kuvvet üretimi tüm motor birimlerin eş zamanlı istemli aktivasyonunu ve tetanik kasılmayı gerektirir; tek bir uyarıyla maksimal kuvvet üretilemez. Öncül III doğrudur: H bandı, aktin filamentlerinin miyozin arasına giremediği miyozin-sadece bölgedir ve kasılma sırasında sarkomerin kısalmasıyla daralır. Öncül IV doğrudur: Titin (connectin), Z çizgisinden M çizgisine uzanan elastik bir protein olup sarkomerin pasif kuvvetini ve geri yaylanma özelliğini belirler. Doğru öncüller I, III ve IV'tür."},{"id":8529,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"28 yaşında kadın hasta, gebeliğinin 10. haftasında rutin kontrole geliyor. Tam kan sayımında Hb: 10,2 g/dL, MCV: 72 fL, MCH: 22 pg saptanıyor. Serum ferritin düzeyi 6 ng/mL olarak ölçülüyor. Bu hastada en çok hangi eritrosit morfolojisi beklenir?","options":["Hedef hücresi ve akantosit","Normositoz ve normokromi","Sferosit ve polikromazi","Makrositoz ve hiperkromi","Mikrositoz ve hipokromi"],"correct":4,"exp":"Ferritin demir depo proteinidir ve düşük ferritin değeri demir eksikliği anemisinin en erken ve özgül göstergesidir. Demir eksikliğinde yetersiz hem sentezi nedeniyle eritrositler küçük (mikrositik, MCV < 80 fL) ve soluk (hipokromik, MCH < 27 pg) görünür. Düşük MCV (72 fL) ve düşük MCH (22 pg) bu tanıyı destekler. Makrositoz B12 veya folat eksikliğinde, normositoz kronik hastalık anemisinin erken döneminde görülür. Sferositoz herediter sferositozda, hedef hücresi talasemi ve karaciğer hastalığında izlenir."},{"id":8530,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, 6 aydır giderek artan kas güçsüzlüğü yakınmasıyla başvuruyor. Proksimal kaslarda belirgin olan güçsüzlük eforla artıyor, dinlenmekle kısmen düzeliyor. EMG'de tekrarlayan sinir uyarımında amplitüd azalması saptanıyor. Tensilon (edrophonium) testi pozitif bulunan hastaya pridostigmin başlanıyor. Bu ilacın tedavideki etkinliği aşağıdaki öncüllerden hangileriyle açıklanabilir?\nI. Nöromüsküler kavşakta asetilkolinin yıkımını engelleyerek sinaptik aralıktaki konsantrasyonunu artırır.\nII. Kas lifi membranında nikotinik reseptör sayısını artırarak iletimi güçlendirir.\nIII. Asetilkolin salınımını artırarak presinaptik etkiyle nörotransmitter havuzunu genişletir.","options":["I, II ve III","I ve II","I ve III","Yalnız I","Yalnız II"],"correct":3,"exp":"Pridostigmin bir asetilkolinesteraz inhibitörüdür; nöromüsküler kavşakta asetilkolini yıkan enzimi geri dönüşümlü olarak bloke ederek sinaptik aralıkta asetilkolin konsantrasyonunun artmasını sağlar. Bu sayede mevcut (ancak antikor tarafından azaltılmış) nikotinik reseptörler daha uzun ve yoğun uyarı alır. Reseptör sayısını artırmaz (II yanlış), presinaptik asetilkolin salınımını etkilemez (III yanlış). Dolayısıyla yalnız I doğrudur."},{"id":8531,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, ani başlayan çarpıntı ve baş dönmesi yakınmasıyla acil servise getiriliyor. EKG'de P dalgası izlenmiyor, RR aralıkları düzensiz ve dar QRS kompleksleri mevcut. Hasta hemodinamik olarak stabil. Kalp hızı 140/dk olarak ölçülüyor. Hastaya diltiazem IV uygulandıktan sonra kalp hızı 85/dk'ya geriliyor ancak ritim düzensizliği sürüyor. Bu tedaviye yanıt açısından aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Diltiazem, SA ve AV düğümdeki L-tipi voltaj kapılı kalsiyum kanallarını bloke ederek hız kontrolü sağlar.\nII. Diltiazem, ventriküllerin diyastolik doluş süresini uzatır.\nIII. Diltiazemin etkisiyle atriyal fibrilasyon sinüs ritmine dönmüştür.\nIV. Diltiazem, AV iletim hızını yavaşlatarak ventriküle ulaşan impuls sayısını azaltır.","options":["2","3","Hiçbirisi","1","4"],"correct":0,"exp":"I doğru: Diltiazem bir non-dihidropiridin kalsiyum kanal blokörüdür; SA ve AV düğümdeki L-tipi kanalları bloke ederek otomatisiteyi ve AV iletimini yavaşlatır. II doğru: Kalp hızı azalınca RR aralığı uzar, bu da diyastol süresinin (dolayısıyla doluş süresinin) uzaması anlamına gelir. III yanlış: Soruda ritim düzensizliğinin devam ettiği açıkça belirtilmiştir; diltiazem hız kontrolü sağlar, kardiyoversiyon yapmaz. IV doğru: AV düğüm iletimini yavaşlatması ventriküllere ulaşan atriyal impuls sayısını azaltır, bu da kalp hızının düşmesini açıklar. Doğru öncüller I, II ve IV olup toplam 3 tanesi doğrudur."},{"id":8532,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında kadın hasta, tip 2 diyabet ve hipertansiyon tanılarıyla 10 yıldır takip edilmektedir. Son kontrol tetkiklerinde idrar albumin/kreatinin oranı 380 mg/g, eGFR 38 mL/dk/1,73 m² olarak saptanıyor. Hastanın glomerül bazal membranında negatif yük kaybı ile podosit süreç füzyonunun geliştiği öğreniliyor. Bu bulgular doğrultusunda hastanın idrarında beklenen en belirgin değişiklik hangisidir?","options":["Hematüri","Albüminüri","Silendrüri (eritrosit silendiri)","Glukozüri","Lökosite"],"correct":1,"exp":"Glomerül bazal membranı negatif yükler (heparan sülfat proteoglikanlar) içerir ve bu yük seçiciliği albüminin (negatif yüklü) geçişini engeller. Podositler ise boyut seçiciliğini sağlar. Diyabetik nefropatide her iki mekanizma bozulunca yoğun albüminüri ortaya çıkar. Sorudaki albumin/kreatinin oranı 380 mg/g zaten belirgin albüminüriye işaret etmektedir. Glukozüri proksimal tübül patolojisiyle ilişkilidir, hematüri glomerüler inflamasyon veya proliferatif değişikliklerle görülür, eritrosit silendiri nefritik sendromda beklenir; bu bulgular diyabetik nefropatinin bu evresinde öne çıkmaz."},{"id":8533,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"28 yaşında erkek hasta, 4 yıldır süren eforla artan nefes darlığı ve tekrarlayan solunum yolu enfeksiyonları nedeniyle başvuruyor. Spirometride FEV1/FVC: 0,62, FVC normal sınırlarda. Toraks HRCT'de hava hapsi ve sentrilobüler amfizem görünümü izleniyor. Yaşı ve sigara öyküsünün olmaması göz önüne alındığında araştırılan patolojide karaciğerde PAS pozitif globüller saptanıyor. Bu hastadaki akciğer hasarının temel mekanizmasını en iyi yansıtan bulgu aşağıdakilerden hangisidir?","options":["Nötrofil elastazın doku inhibitörünün yetersizliği nedeniyle alveol duvarlarının yıkılması","Mast hücre degranülasyonu ile bronkospazm gelişmesi","Artmış mukus sekresyonu ile bronş lümeninin tıkanması","Surfaktan yetersizliği nedeniyle alveol kollapsı","Pulmoner arteriyollerde düz kas hipertrofisi"],"correct":0,"exp":"Karaciğerde PAS pozitif globüller ve genç yaşta amfizem, sigara öyküsü olmaksızın alfa-1 antitripsin (AAT) eksikliğini düşündürür. AAT, nötrofil elastaza karşı başlıca inhibitördür. AAT yokluğunda elastaz alveol duvarlarını (özellikle bazal lobları) yıkarak panlobüler amfizeme yol açar; sentrilobüler amfizem sigara ile ilişkili olmakla birlikte AAT eksikliğinde de görülebilir. Diğer seçenekler sırasıyla kronik bronşit, astım, RDS ve pulmoner hipertansiyonla ilgilidir."},{"id":8534,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Mide fundusunda yer alan parietal hücreler hakkında aşağıdaki ifadelerden kaç tanesi doğrudur?\nI. HCl sekresyonu için H⁺/K⁺-ATPaz pompasını kullanırlar.\nII. İntrinsik faktör salgılayarak B12 vitamininin terminal ileumdan emilimini sağlarlar.\nIII. Pepsinojen salgılayarak gastrik proteolize katkıda bulunurlar.\nIV. Gastrin ve asetilkolin uyarısıyla aktive olurlar.","options":["1","Hiçbirisi","2","3","4"],"correct":3,"exp":"I doğru: Parietal hücreler kanalikül membranındaki H⁺/K⁺-ATPaz (proton pompası) aracılığıyla H⁺ salgılar. II doğru: İntrinsik faktör parietal hücrelerden salgılanır ve B12 vitamininin ileum mukozasından emilimi için zorunludur. III yanlış: Pepsinojen, mide mukozasının baş hücrelerinden (chief/zimogen hücreler) salgılanır; parietal hücrelerden değil. IV doğru: Gastrin (G hücrelerinden), asetilkolin (vagal uyarı) ve histamin (enterokromafin benzeri hücrelerden) parietal hücreleri aktive eden üç ana uyarandır. Doğru öncüller I, II ve IV olup 3 tanesi doğrudur."},{"id":8535,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"45 yaşında erkek hasta, 3 haftadır ilerleyici bacak güçsüzlüğü ve his kaybı yakınmasıyla başvuruyor. Nörolojik muayenede alt ekstremitelerde spastik paraparezi, hiperrefleksi ve bilateral Babinski pozitifliği saptanıyor. MR'da servikal bölgede intramedüller sinyal değişikliği izleniyor. Semptomların başlangıcından önce geçirilmiş viral enfeksiyon öyküsü mevcut. Bu hastada lezyon lokalizasyonu ve bulgularla en uyumlu tanı hangisidir?","options":["Servikal disk hernisi","Transvers miyelit","Amyotrofik lateral skleroz","Guillain-Barré sendromu","Multipl skleroz (servikal plak)"],"correct":1,"exp":"Spastik paraparezi, hiperrefleksi ve bilateral Babinski üst motor nöron (UMN) tutulumunu gösterir; bu da lezyonun omurilikte olduğunu doğrular. Geçirilmiş viral enfeksiyon sonrası gelişen akut/subakut intramedüller tablo transvers miyeliti düşündürür. Guillain-Barré alt motor nöron bulgularıyla (flasik paralizi, hipofleksi) ve tipik olarak çıkan patern ile seyreder. ALS hem UMN hem de alt motor nöron bulgularını birlikte verir ancak akut başlangıç ve enfeksiyon tetikleyicisi ön planda değildir. MS plaklarda genellikle relaps-remisyon öyküsü ve çok odaklı bulgular beklenir. Servikal disk hernisi ise intramedüller sinyal değişikliği yaratmaz, ekstramedüller bası bulgularıyla seyreder."},{"id":8536,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor dispnesi ve bacaklarda ödem yakınmasıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30 olarak saptanıyor. Hastaya digoksin başlanıyor. Digoksinin pozitif inotropik etkisinin temel nedeni aşağıdakilerden hangisidir?","options":["Fosfodiesteraz enzimini inhibe ederek hücre içi cAMP düzeyini yükseltmesi","β₁ adrenerjik reseptörleri uyararak adenilat siklaz aktivasyonunu sağlaması","Ryanodine reseptörlerini bloke ederek sarkoplazma retikulumundan Ca²⁺ salınımını azaltması","L tipi Ca²⁺ kanallarını doğrudan aktive ederek sistol sırasında Ca²⁺ girişini artırması","Na⁺/K⁺-ATPaz inhibisyonu sonucu hücre içi Na⁺ artışı ve Na⁺/Ca²⁺ değiştiricisi üzerinden hücre içi Ca²⁺ yükselmesi"],"correct":4,"exp":"Digoksin, kardiyomiyosit zarındaki Na⁺/K⁺-ATPaz pompasını inhibe eder. Bu inhibisyon hücre içi Na⁺ birikimini sağlar; yükselen Na⁺ gradyanı, Na⁺/Ca²⁺ değiştiricisinin (NCX) ters modda çalışmasına yol açar ve hücre içi Ca²⁺ artar. Artan Ca²⁺ sarkoplazma retikulumunu doldurarak sonraki sistollerde daha fazla Ca²⁺ salınımını tetikler; bu mekanizma pozitif inotropik etkinin temelidir. Diğer seçenekler digoksinin etki mekanizmasıyla uyuşmaz."},{"id":8537,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, ani başlangıçlı nefes darlığı ve taşikardi ile acil servise getiriliyor. Kan gazı analizinde PaO₂: 55 mmHg, PaCO₂: 30 mmHg, pH: 7.48 bulunuyor. Toraks BT'de sağ alt lobda dolma defekti saptanıyor. Hipoksemiyi açıklamak için aşağıdaki öncüller değerlendiriliyor:\nI. Ventilasyon-perfüzyon (V/Q) uyumsuzluğu\nII. Alveolokapiller difüzyon kapasitesinde artış\nIII. Anatomik sağ-sol şant Bu hastada hipoksemi mekanizmasını açıklamada yukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız III","II ve III","I ve III","Yalnız I","I, II ve III"],"correct":2,"exp":"Pulmoner tromboembolide tıkalı dalın beslediği bölgede perfüzyon durur; bu alanlar ventile olup perfüze olmadığından V/Q oranı yükselir (ölü boşluk artışı). Aynı zamanda tıkanıklık nedeniyle distal atelektazi ve surfaktan kaybı gelişerek perfüze olmaya devam eden hipoventile alanlarda düşük V/Q ve sağ-sol şant bileşeni ortaya çıkar. Bu iki mekanizmanın birlikte işlemesi hipoksiyi açıklar. Difüzyon kapasitesi akut PE'de artmaz, azalabilir veya değişmeyebilir; bu nedenle II. öncül yanlıştır. Doğru öncüller I ve III'tür."},{"id":8538,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında diyabetik erkek hasta, rutin kontrolde idrar tetkikinde protein pozitifliği saptanması üzerine nefroloji polikliniğine yönlendiriliyor. 24 saatlik idrarda protein atılımı 4,2 g olarak ölçülüyor. Glomerüler filtrasyon hızı (GFH) 38 mL/dak. Hastaya ACE inhibitörü başlanmasının beklenen birincil etkisi aşağıdakilerden hangisidir?","options":["Toplayıcı tübülde aldosteron reseptörlerinin blokajı","Efferent arteriyol vazodilatasyonu yoluyla glomerüler kapiller hidrostatik basıncın düşürülmesi","Proksimal tübülde sodyum-glukoz kotransporter-2 inhibisyonu","Mezangial hücre proliferasyonunun doğrudan önlenmesi","Afferent arteriyol vazokonstriksiyonu yoluyla renal kan akımının azaltılması"],"correct":1,"exp":"ACE inhibitörleri anjiyotensin II sentezini azaltır. Anjiyotensin II'nin efferent arteriyol üzerindeki vazokonstriksiyon etkisi ortadan kalkar, efferent arteriyol dilate olur. Böylece glomerüler kapiller hidrostatik basınç düşer, ultrafiltrasyon basıncı azalır ve proteinüri belirgin biçimde gerilir. Afferent arteriyol üzerine baskın etkisi değil, efferent etki nefroprotektif mekanizmanın merkezidir. SGLT-2 inhibisyonu ve aldosteron blokajı başka ilaç sınıflarının etkisidir."},{"id":8539,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Aşağıdaki öncüllerin demir eksikliği anemisindeki hematolojik bulgularla ilişkisi değerlendiriliyor:\nI. Periferik yaymada mikrositik hipokrom eritrositler görülür.\nII. Serum ferritin düzeyi yükselir.\nIII. Total demir bağlama kapasitesi (TDBK) artar.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["I ve III doğrudur","Yalnız I doğrudur","II ve III doğrudur","Yalnız III doğrudur","I, II ve III doğrudur"],"correct":0,"exp":"Demir eksikliği anemisinde hemoglobin sentezi için gerekli demir azaldığından eritrositler küçük (mikrositik) ve soluk (hipokrom) görünür; I. öncül doğrudur. Ferritin demir depolarının göstergesidir; demir eksikliğinde depolar azaldığından ferritin düşer, yükselmeyen II. öncül yanlıştır. TDBK ise vücudun daha fazla demir bağlamaya çalışması nedeniyle artar; III. öncül doğrudur. Doğru öncüller I ve III olduğundan yanıt 'I ve III doğrudur' seçeneğidir."},{"id":8540,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 haftadır ilerleyici seyirden bacaklarda güçsüzlük ve parestezi yakınmasıyla başvuruyor. Nörolojik muayenede alt ekstremitelerde derin tendon refleksleri alınamıyor, vibrasyon ve propriosepsiyon bozuk, ancak yüzeyel ağrı ve ısı duyusu korunmuş. Beyin omurilik sıvısı incelemesinde protein yüksekliği saptanıyor, hücre sayısı normal. Bu tabloda sorumlu patolojik süreç en çok hangi yapıyı etkilemektedir?","options":["Nöromüsküler kavşak postsinaptik membranı","Spinotalamik traktus lifleri","Spinal kord ön boynuz motor nöronları","Santral sinir sistemi oligodendrositleri","Periferik sinir miyelin kılıfı"],"correct":4,"exp":"Klinik tablo Guillain-Barré sendromu ile uyumludur. Simetrik yükselen motor zayıflık, arefleksi, derin duyu bozukluğu ve albüminositolojik disosiyasyon (yüksek protein, normal hücre) periferik demiyelinizasyonun klasik bulgularıdır. Yüzeyel ağrı ve ısı duyusunun korunması spinotalamik traktusun etkilenmediğini gösterir. Ön boynuz motor nöron hasarında fasikülasyon ve atrofi ön plandadır. Nöromüsküler kavşak hasarında derin duyu etkilenmez. Oligodendrosit hasarı santral sinir sistemini etkiler ve farklı klinik tablo doğurur."},{"id":8541,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"48 yaşında erkek hasta, kronik alkolizm öyküsü ile birlikte tekrarlayan yağlı dışkılama, kilo kaybı ve karın ağrısı yakınmalarını 8 aydır taşıdığını belirtiyor. Dışkıda yağ pozitif, serum amilaz ve lipaz düzeyleri normal sınırlarda. Görüntülemede pankreas kanalında dilatasyon ve kalsifikasyon saptanıyor. Bu hastada malabsorbsiyon gelişmesinin temel nedeni aşağıdakilerden hangisidir?","options":["Ekzokrin pankreas yetmezliği nedeniyle intralüminal sindirim enzimlerinin yetersizliği","Karaciğer hasarına bağlı safra asidi sentezinin durması","Mide paryetal hücresi kaybına bağlı intrinsik faktör eksikliği","İnce barsak villus atrofisi nedeniyle emilim yüzeyinin azalması","Whipple hastalığına özgü makrofaj infiltrasyonuyla lenfatik tıkanma"],"correct":0,"exp":"Kronik alkolizme bağlı kronik pankreatitte asinar hücreler zamanla tahrip olur ve ekzokrin pankreas işlevi bozulur. Lipaz, proteaz ve amilaz salgısı kritik eşiğin altına düştüğünde (normal kapasitenin yaklaşık %10'unun altı) intralüminal sindirim yetersizleşir. Özellikle yağ sindirimi en erken etkilenen süreçtir ve steatore ortaya çıkar. Serum enzim düzeylerinin normal bulunması, akut inflamasyon değil kronik hasar ve fibrozisi yansıtır. Villus atrofisi çölyakta, safra asidi bozukluğu primer biliyer hastalıkta görülür; bu vakada bu mekanizmalar primer değildir."},{"id":8542,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, efor sırasında nefes darlığı ve çarpıntı yakınmasıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya tedavi başlandıktan 3 ay sonra yapılan kontrol ekokardiyografisinde ejeksiyon fraksiyonunun %50'ye yükseldiği görülüyor. Kapiller yatakta önceki tedaviye kıyasla afterload'u azaltarak bu iyileşmeye en fazla katkıda bulunan tedavi hangisidir?","options":["Digoksin","Beta bloker","Furosemid","Spironolakton","ACE inhibitörü"],"correct":4,"exp":"Kalp yetersizliğinde afterload'u azaltmanın temel mekanizması arteriyel direncin düşürülmesidir. ACE inhibitörleri anjiyotensin II sentezini engelleyerek arteriyel vazodilatasyon sağlar; bu sayede sol ventrikül duvar stresi azalır, kardiyak remodeling yavaşlar ve ejeksiyon fraksiyonu artabilir. Beta blokerler kalp hızı ve kontraktiliteyi azaltarak preload ve oksijen tüketimini düşürür, ancak temel etkileri afterload azaltma değil nörohormonal blokladır. Digoksin pozitif inotroptur, afterload üzerine primer etkisi yoktur. Furosemid preload'u (venöz dönüşü) azaltır. Spironolakton aldosteron antagonizması yoluyla fibrozu önler, afterload üzerine etkisi minimal düzeydedir."},{"id":8543,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında kadın hasta, 1 yıldır giderek artan denge bozukluğu, yutma güçlüğü ve konuşma bozukluğu yakınmalarıyla başvuruyor. Nörolojik muayenede serebellar ataksi, disartri ve hiperrefleksi saptanıyor. Yapılan MR'da beyinsapı ve serebellar atrofi izleniyor. Anti-Yo antikorları pozitif bulunuyor. Bu hastada en olası patolojik süreç aşağıdakilerden hangisiyle ilişkilidir?","options":["Granül hücre apoptozu","Bergmann glia hipertrofisi","Mikroglia aktivasyonuna bağlı nöroinflasyon","Oligodendrosit kaybına bağlı demiyelinizasyon","Purkinje hücrelerine karşı gelişen otoimmün hasar"],"correct":4,"exp":"Anti-Yo (anti-CDR2) antikorları, paraneoplastik serebellar dejenerasyonla ilişkili en sık antikordur; genellikle over veya meme karsinomuyla birlikte görülür. Bu antikorlar Purkinje hücrelerindeki CDR2 proteinine karşı gelişir ve immün aracılı Purkinje hücresi kaybına yol açar. Purkinje hücreleri, serebellar korteksin tek çıkış nöronu olup Bergmann gliaları ile yakın ilişki içindedir. Purkinje hücrelerinin kaybı serebellar ataksi, disartri ve göz hareketi bozukluklarına neden olur. Oligodendrosit kaybı MS gibi demiyelinizan hastalıklarda görülür; anti-Yo ile ilişkili değildir. Mikroglia aktivasyonu akut nöroinflasyon süreçlerine işaret eder, kronik paraneoplastik tabloya uymaz."},{"id":8544,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan idrar yolu enfeksiyonları nedeniyle kullandığı antibiyotik tedavisinin ardından poliüri ve noktüri yakınmalarıyla başvuruyor. Serum sodyumu 148 mEq/L, serum osmolalitesi 305 mOsm/kg, idrar osmolalitesi 120 mOsm/kg olarak ölçülüyor. Desmopressin (dDAVP) uygulaması sonrasında idrar osmolalitesi değişmiyor. Bu hastada toplayıcı kanalda bozulmuş olan temel işlev aşağıdakilerden hangisidir?","options":["İnterkale hücrelerde proton sekresyonu","Bazolateral membranda AQP3/AQP4 ekspresyonu","Prensipyal hücrelerde AQP2 kanallarının apikale translokasyonu","Prensipyal hücrelerde ENaC aktivasyonu","Toplayıcı kanal epitelinde üre geri emilimi"],"correct":2,"exp":"Nefrojenik diabetes insipidusda ADH (AVP) sekresyonu normaldir ancak toplayıcı kanallar ADH'ya yanıt veremez; bu nedenle desmopressin uygulamasına rağmen idrar osmolalitesi artmaz. ADH'nın etkisi; prensipyal hücrelerde V2 reseptörü üzerinden adenilil siklaz/PKA yolağını aktive ederek intrasellüler AQP2 veziküllerinin apikal membrana translokasyonunu sağlamaktır. Bu translokasyon olmadığında luminal su geçirgenliği artar. İnterkale hücrelerdeki proton sekresyonu asit-baz dengesini etkiler, su reabsorbsiyonuyla doğrudan ilişkili değildir. Üre geri emilimi iç medüller toplayıcı kanalda gerçekleşir ve hipertonik medüller interstisyum oluşumuna katkıda bulunur, ancak bu mekanizma ADH'dan bağımsız olarak da kısmen işlev görebilir. ENaC aktivasyonu sodyum geri emilimini, AQP3/AQP4 ise bazolateral su çıkışını sağlar; her ikisi de sekonder süreçlerdir."},{"id":8545,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"Solunum sisteminin histolojik yapısına ilişkin aşağıdaki öncüller değerlendirildiğinde kaç tanesi doğrudur?\nI. Tip I pnömositler, alveol yüzeyinin yaklaşık %95'ini örter ve gaz değişiminin gerçekleştiği ince yapılı hücrelerdir.\nII. Tip II pnömositler, surfaktan üretiminin yanı sıra alveolar hasarın ardından Tip I pnömositlerin yenilenmesini sağlar.\nIII. Bronşiollerde kıkırdak doku bulunur ve bu yapı bronşiyol duvarına destek sağlar.\nIV. Klub (Clara) hücreleri, terminal bronşiyollerde mukus salgısını azaltmak için proteaz salgılar.","options":["3","4","2","1","0"],"correct":2,"exp":"Öncül I doğrudur: Tip I pnömositler yassı, geniş hücreler olup alveol yüzeyinin %90-95'ini kaplar; difüzyon mesafesini minimize ederek gaz değişimine ortam hazırlar. Öncül II doğrudur: Tip II pnömositler küboidal yapıda olup hem surfaktan sentezler hem de alveolar hasarda Tip I pnömosit öncülü olarak görev yapar. Öncül III yanlıştır: Kıkırdak doku bronşlarda bulunur; bronşiyollerde kıkırdak yoktur, duvar bütünlüğü düz kas ve elastik liflerle sağlanır. Öncül IV yanlıştır: Klub (Clara) hücreleri, klorla zengin sıvı, proteaz inhibitörleri ve sürfaktan apoproteinleri salgılar; proteaz değil, proteaz inhibitörü salgılar ve mukus yapımı bu hücrelerin ana işlevi değildir. Dolayısıyla I ve II olmak üzere 2 öncül doğrudur."},{"id":8546,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, 6 aydır devam eden kronik ishal, steatore ve 12 kg kilo kaybı yakınmasıyla başvuruyor. Yapılan ince bağırsak biyopsisinde villüs körleşmesi, kript hiperplazisi ve intraepitelyal lenfosit artışı saptanıyor. Hastaya glüten içermeyen diyet başlanmasının ardından semptomların gerilediği görülüyor. Bu hastada malabsorbsiyonun temel histolojik nedeni aşağıdakilerden hangisidir?","options":["Goblet hücresi hiperplazisi nedeniyle mukus tabakasının kalınlaşması","Lamina propriada plazma hücresi infiltrasyonunun besin emilimini mekanik olarak engellemesi","Paneth hücrelerinin kaybolması sonucu antimikrobiyal savunmanın çökmesi","Kript bazındaki kök hücre havuzunun tükenmesi","Villüs yüzeyindeki absortif enterosit sayısının ve fırça kenarı enzim aktivitesinin azalması"],"correct":4,"exp":"Çölyak hastalığında gliadin peptitlerine karşı gelişen immün yanıt, villüs atrofisi ve kript hiperplazisine yol açar. Villüslerin körleşmesiyle birlikte absortif yüzey alanı dramatik biçimde azalır; ayrıca enterosit fırça kenarında laktaz, sukraz-izomaltaz ve peptidazlar gibi sindirim enzimleri yetersiz kalır. Bu iki mekanizmanın birlikteliği malabsorbsiyonun temel nedenidir. Goblet hücresi hiperplazisi kolitis gibi inflamatuvar durumlarda görülür; villüs atrofisiyle birincil ilişkisi yoktur. Paneth hücresi kaybı immün savunmayı etkiler, doğrudan besin emilimini bozmaz. Kript kök hücre havuzu çölyakta tükenmez; aksine kript hiperplazisi ile artış gösterir. Lamina propria infiltrasyonu mekanik bir engel oluşturmaz, patoloji enterosit düzeyindedir."},{"id":8547,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Eritrosit yapısı ve işlevi açısından aşağıdakilerden hangisi doğrudur?","options":["Eritrositler bikonkav disk şekilleri sayesinde yüzey alanı/hacim oranını artırarak gaz difüzyonunu kolaylaştırır.","Olgun eritrositler mitokondri içerdiğinden enerji ihtiyaçlarını oksidatif fosforilasyonla karşılar.","Eritrositler deformabiliteyi artırmak için mikrotubuler bir iskelet yapısına sahiptir.","Eritrositler lizozom içerdiğinden hasarlı hemoglobini hücre içinde parçalayabilir.","Eritrosit zarındaki spektrin proteini hemoglobin sentezinden doğrudan sorumludur."],"correct":0,"exp":"Eritrositler ~7,5 µm çaplı bikonkav disk yapısındadır; bu şekil, düz bir diske kıyasla yüzey alanını yaklaşık %20-30 oranında artırır ve oksijenin hemoglobine difüzyon mesafesini minimalize eder. Olgun eritrositler çekirdek, mitokondri, ribozom ve lizozom içermez; enerji ihtiyaçlarını yalnızca anaerobik glikoliz (Embden-Meyerhof yolağı) ve pentoz fosfat yoluyla karşılarlar. Spektrin, eritrosit membranının iç yüzünde bir çevre iskeleti oluşturur ve hücre şeklini ile deformabiliteyi korur; hemoglobin sentezinde rolü yoktur. Deformabilite, mikrotübüller değil, alfa-beta spektrin ağından oluşan aktine bağlı submembranöz iskelet sayesinde sağlanır. Lizozom içermemesi nedeniyle eritrositler hasarlı proteinlerini intrasellüler olarak parçalayamaz."},{"id":8548,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"55 yaşında erkek hasta, 2 yıldır giderek artan yorgunluk, proksimal kas güçsüzlüğü ve egzersiz intoleransı yakınmasıyla başvuruyor. Yapılan elektromiyografide miyopatik patern saptanıyor; kas biyopsisinde tip I liflerde atrofi, tip II liflerde ise hipertrofi görülüyor. Serum kreatin kinaz düzeyi hafif yüksek bulunuyor. Bu hastada kas biyopsisi bulguları aşağıdaki durumların hangisiyle en uyumludur?","options":["Mitokondriyal miyopatiye bağlı ragged-red fiber varlığı","Tiroid hormon eksikliğine bağlı miyopati","Duchenne musküler distrofiye bağlı miyopati","Kortikosteroid kullanımına bağlı miyopati","Dermatomiyozite bağlı perivasküler inflamasyon"],"correct":3,"exp":"Kortikosteroid miyopatisinde selektif tip II (hızlı, glikolitik) lif atrofisi beklenir; ancak kronik kullanımda kompansatuar tip I lif atrofisi ve tip II lif hipertrofisi tablosu da görülebilir. Daha önemlisi, bu tablonun ayırt edici özelliği CK'nın hafif yüksek ya da normal olması ve biyopside inflamasyon yokluğudur. Hipotiroid miyopatisinde tip I lif atrofisi olur ancak tip II hipertrofisi eşlik etmez. DMD'de distrofin kaybına bağlı nekroz ve rejenerasyon ile her iki tip lif etkilenir. Dermatomiyozitte perifasiküler atrofi ve perivasküler inflamasyon hakimdir. Mitokondriyal miyopatide Gomori trikrom boyasında ragged-red fiber patognomiktir. Soruda sunulan tip I atrofi + tip II hipertrofi kombinasyonu, uzun süreli kortikosteroid kullanım tablosuna en uygun yanıttır."},{"id":8549,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Aşağıda kapak yapıları ve histolojik özellikleriyle ilgili öncüller verilmiştir:\nI. Kalp kapakları endokard kökenli olup yüzeyleri endotel hücreleriyle kaplıdır.\nII. Aortik kapak, ventriküler yüzünde daha kalın bir fibroza tabakası içerirken atriyel yüzünde spongioza tabakası öne çıkar.\nIII. Kapak interstisyel hücreleri (VIC), hem miyofibroblast hem de düz kas hücre fenotipini sergileyebilen plastik hücrelerdir.\nIV. Kapak endotel hücreleri, sistemik vasküler endotelden farklı olarak kan akımına dik yönde hizalanır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["2","1","0","3","4"],"correct":3,"exp":"Öncül I doğrudur; kalp kapakları endokard invaginasyonundan gelişir ve yüzeyleri endotel hücreleriyle örtülüdür. Öncül II yanlıştır; fibroza tabakası ventriküler yüzde değil, eğer aortik kapak söz konusuysa akım yüzünde (ventriküler tarafta değil, aortik tarafta yani fibroza) kalındır; atriyoventriküler kapaklarda ise atriyel yüzde fibroza öne çıkar, ventriküler yüzde ventriküler tabaka bulunur. Aortik kapakta üç tabaka (fibroza-aortik yüz, spongioza-orta, ventriküler tabaka) mevcuttur ve fibroza yüzeyi kan akımıyla karşı karşıyadır, ventriküler yüzde değil. Dolayısıyla öncül II yanlıştır. Öncül III doğrudur; VIC'ler, fizyolojik ve patolojik koşullara bağlı olarak quiescent fibroblast, miyofibroblast ve düz kas hücre fenotipleri arasında geçiş yapabilen plastik hücrelerdir. Öncül IV doğrudur; kapak endotel hücreleri, laminar akıma paralel hizalanmak yerine akıma dik yönde organize olur; bu özellik sistemik endotelden histolojik olarak ayırt edici bir bulgudur. Doğru öncüller: I, III ve IV → 3 tanesi doğrudur."},{"id":8550,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, 6 aydır gece idrara kalkma, idrar yaparken yanma ve hematüri şikayetiyle başvuruyor. Sistoskopide mesane mukozasında papiller kitleler izleniyor; biyopsi sonucu 'yüksek dereceli papiller ürotelyal karsinom' olarak raporlanıyor. Patoloji raporunda aynı zamanda 'muskularis propria invazyonu mevcut' ifadesi yer alıyor. Bu bulgunun tedavi açısından önemi değerlendirildiğinde, aşağıdakilerden hangisi en doğru yorumdur?","options":["Tümör evresi T1 olup yalnızca intravesikal kemoterapi protokolü başlanmalıdır.","Muskularis mukoza invazyonu ile eşdeğer olup transüretral rezeksiyon yeterlidir.","Muskularis propria (detrüsör kası) invazyonu, radikal sistektomi endikasyonunu ortaya koyar.","Lenf nodu tutulumu olmadığı sürece sistektomi gerekmez ve kemoterapi izlemi yapılır.","Tümör lamina propriaya sınırlı olduğu için BCG intravesikal tedavisi yeterlidir."],"correct":2,"exp":"Mesane duvarının histolojik katları şu sıradadır: üroteliyum, lamina propria (içinde muskularis mukoza ince bir tabaka halinde bulunabilir), muskularis propria (detrüsör kası) ve perivesikal yağ dokusu. T1 tümör lamina propriayı geçmiş ancak detrüsörü geçmemişken; T2 tümör muskularis propriayı (detrüsörü) invaze etmiştir. Muskularis propria invazyonu T2 veya üzeri evreyi ifade eder ve standart tedavi radikal sistektomidir (neoadjuvan sisplatin bazlı kemoterapi eşliğinde). BCG ve intravesikal tedaviler kas invaziv olmayan mesane kanserinde (NMIBC, Ta-T1) uygulanır. Muskularis mukoza ile muskularis propria karıştırılmamalıdır; muskularis mukoza lamina propria içinde ince bir tabaka olup bu tabakayı geçmek T1 evreyi değiştirmez. Dolayısıyla doğru yorum: muskularis propria invazyonu radikal sistektomi endikasyonudur."},{"id":8551,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"32 yaşında kadın hasta, 3 haftadır giderek kötüleşen görme bulanıklığı, sağ gözde ağrı ve renk görmede bozulma yakınmasıyla başvuruyor. Oftalmolojik muayenede sağ gözde relatif afferent pupil defekti (RAPD) saptanıyor. Beyin MR'da optik sinirde T2 hiperintensitesi ve kontrast tutulumu izleniyor. Kısa süreli yüksek doz intravenöz metilprednizolon tedavisi başlanıyor. Bu tedavinin bu hastadaki temel beklenen etkisi hangisidir?","options":["Akson dejenerasyonunu durdurmak ve kalıcı görme keskinliğini iyileştirmek","Optik sinirdeki inflamasyon ve ödemi baskılayarak iyileşme sürecini kısaltmak","Uzun vadede nöral remyelinizasyonu kalıcı olarak hızlandırmak","Hastalığın tekrarlama oranını kalıcı biçimde azaltmak","Kan-beyin bariyerini yeniden yapılandırarak demyelinizasyonu tersine çevirmek"],"correct":1,"exp":"Sunulan klinik tablo (genç kadın, tek taraflı ağrılı görme kaybı, RAPD, MR'da optik sinir lezyonu) akut optik nörit ile uyumludur ve çoğunlukla multipl skleroz ilk atağı olarak karşımıza çıkar. İntravenöz metilprednizolon tedavisi optik nörit atağında inflamasyon ve vasojenik ödemi baskılayarak nöral iyileşme sürecini kısaltır ve görmenin daha hızlı geri dönmesini sağlar; ancak uzun vadeli görsel prognoz üzerine kalıcı bir etkisi yoktur. Tedavi hastalığın tekrarlamasını önlemez, akson dejenerasyonunu durdurmaz ve remyelinizasyonu kalıcı olarak hızlandırmaz. Kan-beyin bariyeri üzerindeki etkisi geçici olup demyelinizasyonu tersine çevirmez. Dolayısıyla doğru yanıt: inflamasyon ve ödemi baskılayarak iyileşme sürecini kısaltmak."},{"id":8552,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Aşağıda gastrointestinal kanalın bölgesel histolojik özellikleriyle ilgili öncüller verilmiştir:\nI. Özofagus alt üçte birinde düz kas, üst üçte birinde çizgili kas, orta üçte birinde her ikisi birlikte bulunur.\nII. Mide fundusundaki oksintik bezlerde parietal hücreler intrinsik faktör salgılar; chief hücreler ise pepsinojen salgılar.\nIII. Duodenumun submukozasında Brunner bezleri bulunur; bu bezler alkali müköz salgı üreterek pilor asidini nötralize eder.\nIV. İleumda Peyer plakları en yoğun biçimde mukoza ve submukozada yerleşir; bu yapılar M hücreleri içerir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız III","I ve III","II ve IV","II, III ve IV","I ve II"],"correct":3,"exp":"Öncül I yanlıştır: Özofagus musküler yapısında üst üçte birde çizgili kas, alt üçte birde düz kas, orta üçte birde geçiş (her ikisi) bulunur; bu sıralama doğrudur ancak öncülde 'üst üçte bir düz kas, alt üçte bir çizgili kas' şeklinde ters yazılmıştır, dolayısıyla öncül I yanlıştır. Öncül II doğrudur: Mide fundus ve korpusundaki oksintik (gastrik) bezlerde parietal hücreler hem HCl hem de intrinsik faktör salgılar; chief hücreler pepsinojen salgılar. Öncül III doğrudur: Brunner bezleri duodenuma özgü submukoza bezidir; bikarbonatça zengin alkali müköz salgı üreterek gastrik asidi nötralize eder ve duodenal mukozayı korur. Öncül IV doğrudur: Peyer plakları ileum mukozası ve submukozasında yerleşik organize lenfoid dokulardır; üzerlerindeki özelleşmiş M hücreleri antijenleri örnekleyerek immün yanıtı başlatır. Doğru öncüller: II, III ve IV."},{"id":8553,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, 6 aydır giderek ilerleyen yürüme güçlüğü, istirahat tremoru ve konuşma bozukluğu yakınmasıyla başvuruyor. Nörolojik muayenede dişli çark rijiditeleri, bradikinezi ve postural instabilite saptanıyor. Parkinson hastalığı tanısı alan hastaya levodopa/karbidopa tedavisi başlanıyor. Tedavinin başlamasından 3 yıl sonra hasta, özellikle öğleden sonra saatlerde istemsiz ağız-çene hareketleri, dil çıkarma ve yüz buruşturma hareketleri geliştiğini fark ediyor. Hastada gelişen bu tabloda en çok hangi reseptör değişikliği sorumludur?","options":["Striatal dopamin reseptörlerinin pulsatil uyarıya bağlı supersensitivitesi","Striatal D1 reseptörlerinin up-regülasyonu","Dopaminerjik nöronlarda presinaptik otoreseptör duyarsızlaşması","Striatal D2 reseptörlerinin down-regülasyonu","Nigrostriatal yolakta glutamat reseptörlerinin down-regülasyonu"],"correct":0,"exp":"Levodopa tedavisine bağlı geç dönem görülen orofasiyal diskineziler (tardiv diskinezi değil, levodopa kaynaklı diskinezi), nigrostriatal yolaktaki dopaminerjik nöron kaybı sonrasında postsinaptik D1 ve D2 reseptörlerinin pulsatil (fizyolojik olmayan aralıklı) uyarıya bağlı supersensitivite (aşırı duyarlılık) kazanmasıyla açıklanır. Normalde dopamin, striatumda tonik ve sürekli salınır; oral levodopa ise pik-vadi dalgalanmaları oluşturur. Bu pulsatil uyarı, özellikle D1 reseptörü üzerinden direkt yolak aşırı aktivasyonuna yol açarak diskineziye neden olur. D2 down-regülasyonu ya da glutamat reseptör değişiklikleri bu tablonun primer mekanizması değildir. Doğru yanıt: striatal dopamin reseptörlerinin pulsatil uyarıya bağlı supersensitivitesi."},{"id":8554,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbrek tübül fizyolojisiyle ilgili aşağıdaki öncülleri değerlendirin:\nI. Proksimal tübülde Na+ geri emilimi, apikal membranda Na+/H+ değiştirici (NHE3) aracılığıyla gerçekleşir.\nII. Henle kulpunun ince çıkan kolu suya geçirgendir, solütlere ise geçirgen değildir.\nIII. Toplayıcı kanalda aldosteron, ana hücrelerdeki apikal ENaC kanallarının ekspresyonunu artırır.\nIV. Distal tübülde tiazid diüretikleri, Na+/Cl- kotransporterini (NCC) inhibe ederek etki gösterir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["3","2","1","Hiçbiri","4"],"correct":0,"exp":"Öncül I doğrudur: Proksimal tübül apikal membranında NHE3 (Na+/H+ antiporter), Na+ geri emiliminin temel mekanizmasıdır; H+ lümene verilirken Na+ hücre içine alınır. Öncül II yanlıştır: Henle kulpunun ince çıkan kolu (ince desendan kol) suya oldukça geçirgendir; solütlere ise görece geçirgen değildir. Ancak ince ÇIKAN kol (ince asendan kol) suya geçirgen değil, solütlere geçirgendir. Öncül II 'ince çıkan kol suya geçirgen' dediği için doğru, ancak 'solütlere geçirgen değil' ifadesi ince çıkan kol için büyük ölçüde doğrudur, bu nedenle öncül II doğru kabul edilir. Öncül III doğrudur: Aldosteron, toplayıcı kanal ana hücrelerinde ENaC kanallarının hem sentezini hem de membrana yerleşimini artırarak Na+ geri emilimini güçlendirir. Öncül IV doğrudur: Tiazid diüretikler, distal kıvrımlı tübülde apikal membranda bulunan NCC (SLC12A3) kotransporterini kompetitif olarak bloke eder. Toplamda 3 öncül doğrudur."},{"id":9958,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan proksimal kas güçsüzlüğü, yutma güçlüğü ve egzersiz intoleransı yakınmalarıyla başvuruyor. Aile öyküsünde babasının benzer şikayetlerle 60'lı yaşlarda hayatını kaybettiği öğreniliyor. Kas biyopsisinde tip I kas liflerinde vakuoler dejenerasyon ve PAS pozitif granüler birikimler saptanıyor. Kas enzim düzeyleri hafif yüksek bulunuyor. Bu hastada aşağıdaki tedavi seçeneklerinden hangisi uygulanırsa, kas lizozomlarındaki substrat birikimine en doğrudan etki sağlanmış olur?","options":["Statinlerin kesilmesi ve karnitin replasmanı","Kreatin monohidrat ve CoQ10 kombinasyonu","Piridostigmin ile nöromüsküler iletimin güçlendirilmesi","İmmünsüpresif dozda prednizolon tedavisi","Alglukozidaz alfa (rekombinant asit alfa-glukozidaz) infüzyonu"],"correct":4,"exp":"Vakada tarif edilen tablo; otozomal resesif kalıtım, proksimal miyopati, yutma güçlüğü, kas biyopsisinde PAS pozitif vakuoler birikimler ve hafif CK yüksekliğiyle Pompe hastalığı (glikojen depo hastalığı tip II) ile uyumludur. Pompe hastalığında lizozomal asit alfa-glukozidaz (GAA) enzim eksikliği nedeniyle glikojen lizozomda birikir. Alglukozidaz alfa, rekombinant insan GAA enzimidir ve enzim replasman tedavisi olarak lizozoma hedeflenerek glikojen birikimini azaltır. Steroid tedavisi inflamatuar miyopatilerde (dermatomiyozit/polimiyozit) endikedir; bu vakada biyopside inflamasyon yoktur. Kreatin ve CoQ10 mitokondriyel miyopatilerde kullanılır. Statin kesilmesi statin miyopatisinde düşünülür ancak ailevi öykü ve biyopsi bulguları bu tanıyı dışlar. Piridostigmin miyastenia graviste etkilidir, nöromüsküler kavşak hastalığı değil kas depo hastalığı söz konusudur."},{"id":9959,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, ani başlayan nefes darlığı ve çarpıntı şikayetiyle acil servise getiriliyor. Bilinen hipertansiyonu ve 2 yıl önce geçirdiği miyokard infarktüsü öyküsü mevcut. EKG'de geniş QRS kompleksli taşikardi saptanıyor. Hasta hemodinamik açıdan stabil. İntravenöz amiodaron başlanıyor. Amiodaron tedavisinin etkinliğini açıklamak için miyokard hücresindeki hangi yapısal ve işlevsel özelliğin bilinmesi gerektiği değerlendirildiğinde, aşağıdaki öncüllerden hangileri doğrudur?\nI. Miyokard aksiyon potansiyelinin faz 3'ünde dominan rol oynayan kanal, hızlı gecikmeli düzeltici potasyum kanalıdır (IKr).\nII. Amiodaron, faz 0'da görev yapan hızlı sodyum kanallarını bloke ederek iletim hızını azaltır.\nIII. Gap junction proteinleri (konneksin 43) yokluğunda amiodaronun antiaritmik etkisi ortadan kalkar.\nIV. İnterkalar disk yapısı, miyokard hücrelerinin elektrik sinyalini senkron biçimde iletmesini sağlar.","options":["Yalnız IV","I ve IV","II ve III","I, III ve IV","I, II ve IV"],"correct":4,"exp":"Amiodaron; potasyum kanallarını (IKr, IKs), sodyum kanallarını ve kalsiyum kanallarını bloke eden Sınıf III antiaritmiktir. Faz 3 repolarizasyonundan sorumlu başlıca kanal hızlı gecikmeli düzeltici K+ kanalı (IKr) olduğundan öncül I doğrudur. Amiodaron faz 0'daki hızlı Na+ kanallarını da bloke ederek iletim hızını azaltır; bu nedenle öncül II de doğrudur. Öncül III yanlıştır; gap junctionların yokluğunda uyarı iletimi durur, fakat amiodaronun primer hedefi membran iyon kanallarıdır, konneksin 43 değildir. Öncül IV doğrudur; interkalasyonlu disk (disk interkalaris), desmozomlar ve gap junctionları barındırarak miyokardın fonksiyonel bir sinsisyum gibi çalışmasını sağlar. Bu nedenle doğru öncüller I, II ve IV'tür."},{"id":9960,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, doğumdan bu yana tekrarlayan bronşiektazi atakları, kronik sinüzit ve sağa yerleşik kalp nedeniyle kardiyoloji polikliniğine yönlendiriliyor. Daha önce çocuk sahibi olmak istemiş ancak bunu başaramamış. Bronkoalveoler lavajda silier hareket analizi yapıldığında silierin ilerleyici (propulsif) hareket yerine sadece titreşim yaptığı gözlemleniyor. Bu hastada aşağıdakilerden hangisinin gösterilmesi hem tanıyı kesinleştirir hem de kısırlığın nedenini en doğrudan açıklar?","options":["Mukus viskozitesinin artmış olması","Nötrofil elastaz düzeyinin bronkoalveoler lavajda yüksek bulunması","Alfa-1 antitripsin düzeyinin düşük bulunması","CFTR gen mutasyonunun PCR ile saptanması","Elektron mikroskopide dış dynein kol eksikliği"],"correct":4,"exp":"Vakada Kartagener sendromu (primer silier diskinezi ile birlikte situs inversus totalis) tarif edilmektedir. Sinüzit, bronşiektazi, situs inversus ve infertilite tetradı bu sendromu düşündürür. Primer silier diskineziyle, silier aksoneme entegre olan dynein kolları (özellikle dış dynein kolları) işlevini kaybeder; silia 9+2 mikrotübül yapısını korur ancak ATP hidrolizi ile aktive olan dynein ATPaz olmaksızın güç üretemez. Tuba uterinadaki silia defekti tubal taşınmayı bozarak kısırlığa neden olur; erkeklerde ise sperm kuyruğu aynı aksonemal yapıyı paylaştığından azoospermi görülür. CFTR mutasyonu kistik fibrozisi, alfa-1 antitripsin eksikliği amfizem ve karaciğer hastalığını açıklar; her ikisinde de situs inversus beklenmez. Nötrofil elastaz yüksekliği ve artmış mukus viskozitesi sekonder bulgulardır, nedensel değildir."},{"id":9961,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında erkek hasta, böbrek nakli sonrası 3. ayında rutin kontrole geliyor. Biyopsi yapılan hastada tübüler bazal membranın kalınlaştığı, proksimal tübül hücrelerinin lizozomlarında siklosporin birikintileri ve mitokondriyal şişme saptanıyor; glomerüller normal. Bu bulgular ışığında siklosporin nefrotoksisitesinin hedef aldığı hücre tipi ve bu hücredeki en kritik işlev bozukluğu değerlendirildiğinde aşağıdakilerden hangisi doğrudur?","options":["Distal tübül hücresinde aldosteron reseptörü blokajına bağlı sodyum kaybı","Proksimal tübül hücresinde Na+-K+-ATPaz inhibisyonuna bağlı izozmotik geri emilim bozukluğu","Toplayıcı kanal prensipyal hücresinde ADH direncine bağlı serbest su kaybı","Proksimal tübül hücresinde oksidatif fosforilasyon bozukluğuna bağlı aktif transport kapasitesinin azalması","Podositlerde nefrin ekspresyonunun azalmasına bağlı proteinüri"],"correct":3,"exp":"Siklosporin nefrotoksisitesi öncelikle proksimal tübül hücrelerini etkiler; bu hücreler metabolik olarak son derece aktif olup enerji gereksinimlerini neredeyse tamamen oksidatif fosforilasyon yoluyla karşılarlar. Glukoz yeniden sentezi, aminoasit, fosfat, bikarbonat ve organik iyon transportu aktif işlemler olduğundan mitokondri sağlığına bağımlıdır. Biyopside mitokondriyal şişme (toksik mitokondriyal hasar belirtisi) ve lizozomal birikintiler bu hücresel hedefi doğrudan destekler. Na+-K+-ATPaz inhibisyonu da proksimal tübülde olur ancak mitokondriyal patoloji daha temel ve primer mekanizmadır; Na+-K+-ATPaz zaten mitokondriyal ATP'ye bağlıdır. Distal tübül aldosteron hedefi, toplayıcı kanal ADH hedefi ve podositler glomerüler filtrasyon bariyerini oluştururken bunların hiçbirinde biyopside değişiklik tanımlanmamıştır."},{"id":9962,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Periferik sinir sistemindeki bir Schwann hücresinin tek bir akson segmentini sarmalamasıyla oluşan miyelin kılıfı incelendiğinde aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Ranvier boğumlarında voltaj kapılı Na+ kanalları yoğunlaşmıştır ve aksiyon potansiyeli bu noktalardan atlar.\nII. Merkezi sinir sistemindeki miyelin kılıfı Schwann hücreleri tarafından değil oligodendrosit hücreleri tarafından oluşturulur.\nIII. Miyelin kılıfı, aksonun membran kapasitansını artırarak aksiyon potansiyelinin iletim hızını yükseltir.\nIV. Schmidt-Lanterman yarıkları, Schwann hücresinin sitoplazmasının kılıf içinde dar kanallar biçiminde korunduğu bölgelerdir.","options":["Dördü","Hiçbiri","Yalnız biri","Üçü","İkisi"],"correct":3,"exp":"Öncül I doğrudur: Ranvier boğumları aksonun miyelinle örtülü olmadığı bölgelerdir ve yüksek yoğunlukta voltaj kapılı Na+ kanalı içerirler; saltatory (sıçramalı) ileti bu boğumlar arasında gerçekleşir. Öncül II doğrudur: MSS'de miyelin oligodendrositler tarafından üretilir; bir oligodendrosit birden fazla aksonu sarabilirken, bir Schwann hücresi yalnızca bir akson segmentini sarar. Öncül III yanlıştır: Miyelin kılıfı membran kapasitansını AZALTIR (izole edici tabaka görevi görür) ve buna bağlı olarak iletim hızı artar; kapasitansı artırması durumunda iletim yavaşlardı. Öncül IV doğrudur: Schmidt-Lanterman yarıkları (inkizürler), miyelin kılıfının kompakt olmayan bölgeleridir ve Schwann hücresinin ince sitoplazmik kanallarını barındırır; metabolit alışverişine aracılık ettiği düşünülmektedir. Doğru öncüller I, II ve IV olduğundan cevap 3'tür. Bu nedenle doğru yanıt Üçü seçeneğidir."},{"id":9963,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı şikayetiyle başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya ACE inhibitörü ve beta bloker başlanıyor. Tedavinin ilerleyen haftalarında hastanın semptomlarında belirgin düzelme gözlemleniyor. Bu hastada beta bloker kullanımının sağladığı hemodinamik düzelmenin temelinde aşağıdakilerden hangisi yatar?","options":["Sempatik aktivasyona bağlı maladaptif kardiyak remodeling sürecinin yavaşlaması","Pozitif inotropik etki ile sistolik disfonksiyonun akut olarak düzeltilmesi","Renin salınımının artmasıyla nörohormonal dengenin yeniden kurulması","Preload azalması ile pulmoner kapiller basıncın düşmesi","Afterload azalması ile periferik vasküler direncin gerilemesi"],"correct":0,"exp":"Kronik kalp yetmezliğinde sempatik sinir sistemi kompansatuar olarak aşırı aktive olur; bu durum başlangıçta kardiyak debiyi korusa da uzun vadede beta-1 reseptörleri aşırı uyararak kardiyomiyosit apoptozunu, fibrozisi ve ventriküler dilatasyonu tetikler (maladaptif remodeling). Beta blokerler bu kronik sempatik bombardımanı keserek remodeling sürecini yavaşlatır, ejeksiyon fraksiyonunu zamanla artırır. Preload ve afterload azaltma ACE inhibitörünün, renin baskılama ise ACE inhibitörü/ARB sınıfının öne çıkan etkisidir. Beta blokerler negatif inotropiktir; akut sistolik disfonksiyonda dikkatli kullanılır, pozitif inotropi sağlamaz."},{"id":9964,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, 2 yıldır devam eden eforla nefes darlığı, kuru öksürük ve egzersiz intoleransı yakınmalarıyla başvuruyor. Yüksek çözünürlüklü bilgisayarlı tomografide bilateral bazal ağırlıklı 'buzlu cam' görünümü ve traksiyon bronşiektazisi saptanıyor. Solunum fonksiyon testinde FVC: %58, FEV1/FVC: 0,88 olarak ölçülüyor. Bu hastada gaz değişim bozukluğunun primer mekanizması aşağıdakilerden hangisidir?","options":["İnterstisyel fibrozise bağlı diffüzyon kapasitesinin azalması ve ventilasyon-perfüzyon uyumsuzluğu","Surfaktan yetersizliğine bağlı alveolar kollaps","Havayolu direncinin artmasına bağlı obstrüktif ventilasyon bozukluğu","Üst hava yolu obstrüksiyonuna bağlı inspiratuar akım kısıtlaması","Pulmoner vasküler yeniden şekillenmeye bağlı ölü boşluk ventilasyonunun artması"],"correct":0,"exp":"Klinik tablo, görüntüleme bulguları ve restriktif patern (düşük FVC, korunmuş FEV1/FVC oranı) idiyopatik pulmoner fibrozis (IPF) ile uyumludur. IPF'de alveoller arası interstisyumda kollajen birikimi alveolokapiller membranın kalınlaşmasına yol açar; bu da CO diffüzyon kapasitesini (DLCO) düşürür. Eş zamanlı oluşan fibrotik değişiklikler ventilasyon-perfüzyon uyumsuzluğunu da artırır. Obstrüksiyon, surfaktan yetersizliği veya üst hava yolu patolojisi bu tablonun açıklayıcısı değildir."},{"id":9965,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında erkek hasta, 10 yıldır tip 2 diyabetes mellitus tanısıyla takip edilmekte olup son 1 yılda ayak bileklerinde ödem ve köpüklü idrar şikayeti gelişiyor. İdrar analizinde protein: +++ ve idrar albumin/kreatinin oranı 3.200 mg/g olarak saptanıyor. Serum albumini 2,1 g/dL, kreatinin 1,8 mg/dL. Bu hastada glomerüler filtrasyon bariyer hasarının histolojik olarak ilk etkilenen bileşeni aşağıdakilerden hangisidir?","options":["Parietal epitel hücreleri","Glomerüler bazal membran kalınlaşması ve podosit hasarı","Mezangiyum hücreleri ve matriks genişlemesi sonucu podosit ayak çıkıntılarının silinmesi","Endotelyal fenestrasyonların kapanması","Bowman kapsülünün fibrozisi"],"correct":1,"exp":"Diyabetik nefropatide ilk histolojik değişiklik glomerüler bazal membranın (GBM) kalınlaşması ve mezangiyum genişlemesidir; ancak proteinürinin doğrudan sorumlusu podosit (visseral epitel hücresi) hasarıdır. Podositler filtrasyonun elektrostatik ve boyut seçiciliğini sağlayan ayak çıkıntılarını (pedicel) oluşturur; bu çıkıntıların silinmesi (effacement) nefrotik düzeyde albümin kaçışına neden olur. Parietal epitel hücreleri ve Bowman kapsülü fibrozu ilerleyen evrelerde görülür. Endotelyal fenestrasyonlar diyabetik nefropatide kapanmaz; aksine glikokaliks bozulması ile geçirgenlikleri artar."},{"id":9966,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir nöronda aksiyon potansiyeli oluşumu ve iletimi ile ilgili aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Depolarizasyon fazında hücre dışından hücre içine Na+ akışı gerçekleşir.\nII. Mutlak refrakter dönemde voltaj kapılı Na+ kanallarının büyük çoğunluğu inaktif konumdadır.\nIII. Miyelinli liflerde iletim, miyelinsiz liflere kıyasla daha yavaş gerçekleşir.\nIV. Repolarizasyon fazında voltaj kapılı K+ kanalları açılır ve K+ hücre dışına çıkar.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Yalnız biri","İkisi","Hiçbiri","Üçü","Dördü"],"correct":3,"exp":"I. Doğru: Depolarizasyonda eşik potansiyeli aşıldığında voltaj kapılı Na+ kanalları açılır ve Na+ konsantrasyon gradiyenti ile elektrik gradiyenti doğrultusunda hücre içine akar. II. Doğru: Mutlak refrakter dönem, Na+ kanallarının inaktif (kapalı-inaktif) konumda bulunduğu süreye karşılık gelir; bu dönemde hiçbir uyaran yeni aksiyon potansiyeli oluşturamaz. III. Yanlış: Miyelinli liflerde saltatory iletim sayesinde aksiyon potansiyeli Ranvier boğumları arasında 'sıçrayarak' iletilir; bu durum iletim hızını belirgin biçimde artırır. IV. Doğru: Repolarizasyon fazında voltaj kapılı K+ kanalları gecikmeli olarak açılır, K+ hücre dışına çıkar ve membran potansiyeli negatif değerlere döner. Dolayısıyla I, II ve IV doğru olup 3 tanesi doğrudur. Bu nedenle doğru yanıt Üçü seçeneğidir."},{"id":9967,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Mide fundusunda bulunan ve pepsinojen salgılayan hücre tipi aşağıdakilerden hangisidir?","options":["G hücresi","Paryetal hücre","D hücresi","Baş hücre (Chief cell)","Müköz boyun hücresi"],"correct":3,"exp":"Mide fundus ve korpusundaki oksintik bezlerde üç temel ekzokrin hücre tipi bulunur: paryetal hücreler (HCl ve intrinsik faktör salgılar), baş hücreler (chief cell / zimogenik hücre; pepsinojen salgılar) ve müköz boyun hücreleri (müsin salgılar). G hücreleri antrumda gastrin salgılar; D hücreleri somatostatin salgılayarak gastrin ve asit sekresyonunu inhibe eder. Pepsinojen, asidik ortamda aktif enzim pepsine dönüşerek protein sindirimini başlatır."},{"id":9968,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"28 yaşındaki kadın hasta 6 aydır halsizlik, solukluk ve egzersiz intoleransıyla başvuruyor. Hb 7,2 g/dL, MCV 118 fL, lökosit 4.100/µL, trombosit 98.000/µL; periferik yaymada hipersegmente nötrofiller var. Serum B12 68 pg/mL (referans: 200-900 pg/mL). Schilling testinde oral radyoaktif B12 sonrası idrarla atılım düşük, intrinsik faktörle birlikte verildiğinde normal bulunuyor. Bu hastada gelişen patolojinin histolojik temelini oluşturan birincil mekanizma aşağıdakilerden hangisidir?","options":["Kemik iliğinde B12 eksikliğine bağlı DNA sentez bozukluğu sonucu çekirdek-sitoplazma olgunlaşma uyumsuzluğu","Otoimmün hemolize bağlı eritrosit ömrünün kısalması","Folat antagonisti ilaca bağlı pürin sentez bozukluğu","Eritrosit membranındaki spektrin proteininin genetik defekti","Demir eksikliğine bağlı hem sentezinin aksaması"],"correct":0,"exp":"Schilling testi, B12 malabsorpsiyonunun intrinsik faktör (IF) eksikliğinden kaynaklandığını göstermektedir; bu tablo pernisyöz anemi ile uyumludur. IF, mide paryetal hücrelerinden salgılanır ve B12'nin terminal ileumdan emilimi için zorunludur. B12, DNA sentezinde metiyonin döngüsü ve timidilat sentezi için kritik kofaktördür; eksikliğinde nükleer DNA replikasyonu yavaşlar ancak sitoplazmik büyüme devam eder. Bu uyumsuzluk (nükleer-sitoplazmik asenkroni) megaloblastik değişikliklere yol açar: büyük oval eritrositler, hipersegmente nötrofiller ve pansitopeni. Spektrin defekti herediter sferositoz, otoimmün hemoliz Coombs pozitif anemi, demir eksikliği mikrositer anemi tablosuyla kendini gösterir."},{"id":9969,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, 6 aydır ilerleyici proksimal kas güçsüzlüğü ve efor sonrası belirginleşen yorgunluk yakınmasıyla başvuruyor. Aile öyküsünde benzer şikayet yok. Serum kreatin kinaz düzeyi belirgin yüksek, elektromiyografide miyopatik patern saptanıyor. Kas biyopsisinde tip II kas lifi atrofisi ve mitokondriyel anormallikler tespit ediliyor. Bu hastada aşağıdaki öncüllerden hangileri doğrudur?\n\nI. Tip II kas lifleri, yavaş kasılan ve yorulmaya dirençli liflerdir.\nII. Miyozin ağır zincir izoformları, kas lifi tipini belirleyen temel moleküler faktördür.\nIII. Tip I kas liflerine kıyasla tip II liflerde mitokondri yoğunluğu daha düşüktür.","options":["I ve III","Yalnız II","II ve III","Yalnız I","I, II ve III"],"correct":2,"exp":"Tip II kas lifleri hızlı kasılan, çabuk yorulan liflerdir; yavaş kasılan ve yorulmaya dirençli olanlar tip I liflerdir. Bu nedenle öncül I yanlıştır. Miyozin ağır zincir izoformları (MHC I, IIa, IIx/IIb) kas lifi tipini belirleyen temel moleküler belirteçlerdir; öncül II doğrudur. Tip I lifler yoğun mitokondri ve yüksek oksidatif kapasiteyle karakterizeyken tip II liflerde mitokondri yoğunluğu görece düşüktür ve glikoliz ön plandadır; öncül III doğrudur. Dolayısıyla doğru öncüller II ve III'tür."},{"id":9970,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"Sakubitril/valsartan tedavisi başlanan kalp yetersizliği hastasında tedavi yanıtını izlemek için NT-proBNP’nin BNP’ye göre daha güvenilir olmasının nedeni hangisidir?","options":["Sakubitrilin BNP sentezini tamamen durdurması","Valsartanın NT-proBNP sentezini doğrudan artırması","BNP’nin yalnız böbrekte sentezlenmesi","NT-proBNP’nin aktif natriüretik hormon olması","NT-proBNP’nin neprilisin tarafından yıkılmaması"],"correct":4,"exp":"Sakubitril neprilisini inhibe eder; BNP neprilisin substratı olduğundan tedavi sırasında BNP düzeyi geçici olarak yükselebilir veya yorumlanması güçleşebilir. NT-proBNP neprilisin substratı değildir ve duvar geriliminin azalmasıyla genellikle düşer."},{"id":9971,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında diyabetik kadın hasta, uzun süredir insülin kullanmaktadır. Son aylarda poliüri ve hipernatremi saptanması üzerine araştırılan hastada idrar ozmolalitesi 95 mOsm/kg, serum ozmolalitesi 308 mOsm/kg olarak bulunuyor. Su kısıtlama testi sonrasında idrar ozmolalitesi 105 mOsm/kg'a ulaşıyor, ardından uygulanan desmopressin (DDAVP) sonrasında ise idrar ozmolalitesi 320 mOsm/kg'a yükseliyor. Bu hastada nefron segmentleri ile ilgili aşağıdaki öncüllerden kaç tanesi doğrudur?\n\nI. İdrar konsantrasyonunun ana belirleyicisi, toplayıcı kanal epitelindeki AQP-2 kanallarının ekspresyonudur.\nII. Henle kulpu ince çıkan kolunun üreye geçirgen olması kortikomeduller ozmotik gradyanın oluşumuna katkı sağlar.\nIII. Bu hastada toplayıcı kanal hücrelerinde V2 reseptörlerine bağlı sinyal yolağı muhtemelen bozulmamıştır.","options":["Hiçbiri","İki tanesi","Yalnız II ve III","Üç tanesi","Yalnız bir tanesi"],"correct":3,"exp":"Desmopressin sonrası idrar ozmolalitesinin belirgin artması, toplayıcı kanal V2 reseptörlerinin ve aşağı yönlü AQP-2 yolağının işlevsel olduğuna işaret eder; bu tablo santral diyabetes insipidusa uygundur. Öncül I doğrudur: AQP-2 kanalları toplayıcı kanalda ADH'ya yanıtı düzenleyen temel yapıdır. Öncül II doğrudur: Henle kulpu ince çıkan kolu üreye geçirgen olmakla birlikte tam doğru ifade, üre geçirgenliğinin iç meduller toplayıcı kanala özgü olduğu şeklindedir; ancak ince çıkan kolun suya görece geçirgen, solütlere daha az geçirgen olması ve karşı akım çarpıcı sistemi ile medüller hiperozmolariteye katkısı bağlamında öncül genel olarak doğru kabul edilir. Öncül III doğrudur: DDAVP'ye yanıt alınması V2 reseptör yolağının sağlam olduğunu kanıtlar. Üç öncül de doğrudur."},{"id":9972,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, ani başlayan çift görme, sağ göz kapağında düşüklük ve sağ pupilada midriazis yakınmasıyla acile başvuruyor. Nörolojik muayenede sağ gözde aşağı ve dışa deviasyon saptanıyor. MR anjiografide sağ posterior kommunikan arterde anevrizma tespit ediliyor. Bu hastada gelişen klinik tablonun açıklanmasında sinir sistemi histofizyolojisi açısından en doğru ifade hangisidir?","options":["Okulomotor sinirin parasempatik lifleri sinirin periferinde seyrettiğinden kompresyon durumunda pupil tutulumu erken ortaya çıkar.","Pupil dilatasyonu, sempatik liflerin baskılanması sonucu sfinkter pupilla kasının tonusunun artmasıyla oluşur.","Aşağı ve dışa deviasyon, abdusen ve troklear sinirin birlikte tutulumundan kaynaklanmaktadır.","Ptoz, Müller kasının parasempatik innervasyonunun kesilmesine bağlıdır.","Okulomotor sinirin parasempatik lifleri sinirin merkezinde seyrettiğinden kompresyona bağlı pupil tutulumu geç görülür."],"correct":0,"exp":"N. oculomotorius (III. kranyal sinir), parasempatik liflerini sinirin dış periferinde taşır. Bu anatomik düzenleme nedeniyle dışarıdan baskı yapan lezyonlar (anevrizma, transtentoryal herniasyon) öncelikle parasempatik lifleri etkiler ve pupil dilatasyonu (midriyazis) erken bulgu olarak ortaya çıkar; bu 'cerrahi III. sinir felci' olarak adlandırılır. İskemik lezyonlar ise sinirin merkezindeki motor lifleri etkiler ve pupil göreceli korunur. Ptoz levator palpebra superiorisinin motor paralizisinden, aşağı-dışa deviasyon ise IV. ve VI. sinir kaslarının antagonize edilmeden çalışmasından kaynaklanır. Bu nedenle doğru yanıt Okulomotor sinirin parasempatik lifleri sinirin periferinde seyrettiğinden kompresyon durumunda pupil tutulumu erken ortaya çıkar. seçeneğidir."},{"id":9973,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"45 yaşında erkek hasta, 3 aydır süren epigastrik ağrı, şişkinlik ve yağlı gıdalara karşı intolerans yakınmalarıyla başvuruyor. Yapılan tetkikler sonucunda ekzokrin pankreas yetmezliği tanısı konuluyor ve pankreas enzim replasman tedavisi başlanıyor. Bu hastada ince barsak lümenindeki sindirim süreciyle ilgili aşağıdaki öncüllerden hangileri doğrudur?\n\nI. Pankreatik lipaz, yağları ince barsak lümeninde en etkin şekilde midgut villüs yüzeyindeki fırçamsı kenarda hidrolize eder.\nII. Pankreatik bikarbonat salgısı, duodenal lümeni alkalize ederek pankreatik enzimlerin optimal pH aralığında çalışmasına olanak tanır.\nIII. Kolesistokinin (CCK) ince barsağın I hücrelerinden salgılanarak pankreas asiner hücrelerini uyarır.","options":["II ve III","Yalnız II","Yalnız I","I ve III","I, II ve III"],"correct":0,"exp":"Öncül I yanlıştır: Pankreatik lipaz, yağları lümen içinde misel ortamında hidrolize eder; fırçamsı kenar lipazları farklı bir grubu oluşturur ve pankreatik lipazın primer etki yeri lümen içidir, fırçamsı kenar değildir. Öncül II doğrudur: Pankreas duktus hücrelerinden salgılanan bikarbonat zengin sıvı, mide asitiyle gelen kimyayı nötralize ederek duodenal pH'ı 6-7'ye çıkarır ve pankreatik enzimlerin optimum aktivite göstermesini sağlar. Öncül III doğrudur: CCK, duodenum ve jejunumun I hücrelerinden salgılanır; yağ ve protein içeriğine yanıt olarak asiner hücreleri uyararak enzim sekresyonunu artırır. Bu nedenle doğru yanıt II ve III seçeneğidir."},{"id":9974,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, 2 yıldır progresif proksimal kas güçsüzlüğü yakınmasıyla başvuruyor. Aile öyküsünde annesinin erkek kardeşinde benzer şikayetler mevcut. EMG'de miyopatik patern saptanıyor; kas biyopsisinde dystrophin boyaması negatif bulunuyor. Hastada görülen patolojide aşağıdaki öncüllerin hangileri doğrudur?\nI. Etkilenen proteinin yokluğunda sarkolemma mekanik strese karşı daha kırılgan hale gelir.\nII. Hastalık X'e bağlı resesif kalıtılır ve dystrophin geninin delesyonlarıyla ilişkilidir.\nIII. Kalp kası tutulumu bu hastalıkta görülmez çünkü kardiyomiyositlerde dystrophin eksprese edilmez.\nIV. Dystrophin normalde aktin filamentlerini ekstrasellüler matrikse bağlayan dystrophin-associated protein complex'in bir parçasıdır.","options":["Yalnız III ve IV","Yalnız I ve II","I, II ve IV","II, III ve IV","I, II, III ve IV"],"correct":2,"exp":"Dystrophin, sarkolemmanın iç yüzünde F-aktin ile dystrophin-associated protein complex (DAPC) arasında köprü kurarak ekstrasellüler matrikse bağlantı sağlar; bu yapı kas kontraksiyonu sırasında mekanik stresi dağıtır. Dystrophinin yokluğunda sarkolemma kırılganlaşır ve tekrarlayan kontraksiyonlarla yırtılır (Öncül I doğru). Duchenne musküler distrofi X'e bağlı resesif geçer ve dystrophin geninin büyük delesyonları en sık nedendir (Öncül II doğru). Dystrophin kardiyomiyositlerde de eksprese edilir; bu nedenle dilate kardiyomiyopati bu hastalığın önemli bir komplikasyonudur, Öncül III yanlıştır. Öncül IV doğrudur: Dystrophin DAPC'nin sitoplazmik bileşenidir ve aktini ekstrasellüler matrikse bağlar. Dolayısıyla I, II ve IV doğrudur."},{"id":9975,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, efor sırasında ortaya çıkan göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Yapılan koroner anjiyografide sol ön inen arterde %85 darlık saptanıyor ve perkütan koroner girişim planlanıyor. Girişim öncesi fizyopatoloji değerlendirilirken miyokardın iskemiye olan yanıtı tartışılıyor. Aşağıdakilerden hangisi bu hastada koroner kan akımının azalmasına bağlı olarak gelişecek ilk hücresel değişikliği en iyi açıklar?","options":["Mitokondriyal şişme ve iç membran bütünlüğünün kaybı","Na+/K+-ATPaz aktivitesinin azalmasına bağlı hücre içi sodyum birikimi","Sarkoplazmik retikulumdan kontrolsüz kalsiyum salınımı","Kontraktil proteinlerin proteolitik degradasyonu","Anaerobik glikolizin devreye girmesiyle intraselüler pH'nın düşmesi"],"correct":4,"exp":"İskeminin ilk dakikalarında oksijen yetersizliğiyle birlikte aerobik fosforilasyon durur ve hücre anaerobik glikolize geçer. Laktik asit birikimi intraselüler pH'ı düşürür; bu, iskeminin en erken ve geri dönüşümlü aşamasıdır. Na+/K+-ATPaz bozukluğu ve sarkoplazmik retikulum disfonksiyonu biraz daha ileri evrelerde ortaya çıkar. Mitokondriyal yapısal bozulma ve proteoliz ise geri dönüşümsüz hasar evresine aittir. Bu nedenle doğru yanıt anaerobik glikoliz ve pH düşüşüdür."},{"id":9976,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"24 yaşında kadın hasta, 6 aydır intermitan diplopi, 3 haftadır ise alt ekstremitelerde güçsüzlük ve uyuşma yakınmalarıyla nöroloji polikliniğine başvuruyor. MR'da periventriküler beyaz cevherde T2 hiperintens plaklar saptanıyor; BOS incelemesinde oligoklonal bantlar pozitif bulunuyor. Bu tablonun temelindeki patoloji değerlendirilirken aşağıdaki öncüllerin hangileri doğrudur?\nI. Hastalık, MSS'de miyelin üreten oligodendrositleri hedef alan inflamatuvar bir süreçtir.\nII. Akson hasarı hiçbir zaman görülmez; semptomlar yalnızca demiyelinizasyona bağlıdır.\nIII. Saltatory iletinin bozulması, aksiyon potansiyelinin Ranvier boğumları arasında atlayamamasına yol açarak iletim hızını düşürür.\nIV. Semptomların ısıyla kötüleşmesi, ısının demiyelinize segmentlerdeki aksiyon potansiyeli iletimini daha da bozmasıyla açıklanır.","options":["I, II ve IV","I, II, III ve IV","I ve III","I, III ve IV","II, III ve IV"],"correct":3,"exp":"Multipl skleroz MSS'de oligodendrositlerin ve miyelin kılıfının otoimmün hasarıyla seyreder (Öncül I doğru). Aksonal hasar özellikle ileri evrelerde görülür ve kalıcı nörolojik defisitin önemli bir nedenidir; dolayısıyla Öncül II yanlıştır. Miyelin kılıfının kaybı, saltatory iletimi ortadan kaldırır ve iletim hızı belirgin şekilde düşer (Öncül III doğru). Uhthoff fenomeni olarak bilinen ısıyla semptom kötüleşmesi, ısının demiyelinize aksonlarda aksiyon potansiyeli eşiğini yükseltmesi ve iletimi daha da bozmasıyla açıklanır (Öncül IV doğru). Böylece I, III ve IV doğrudur."},{"id":9977,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"67 yaşında erkek hasta, 10 yıldır tip 2 diyabetes mellitus tanısıyla takip edilmekte olup son 1 yıldır ayak bileklerinde ödem ve köpüklü idrar yakınması başlamıştır. Laboratuvar incelemesinde 24 saatlik idrarda protein 4,2 g, serum albümin 2,1 g/dL, serum kreatinin 2,4 mg/dL saptanıyor. Böbrek biyopsisinde glomerüler bazal membranda diffüz kalınlaşma ve Kimmelstiel-Wilson nodülleri görülüyor. Bu hastada proteinürinin gelişmesindeki temel yapısal bozukluk hangisidir?","options":["Jukstaglomerüler aparatın renin salgısını artırarak tübüler sodyum geri emilimini artırması","Podosit foot process füzyonu olmaksızın mezangial hücre proliferasyonu","Glomerüler bazal membranda heparan sülfat proteoglikan kaybına bağlı aniyon bariyer yıkımı","Proksimal tübül epitel hücrelerinin lizozomal disfonksiyonu","Afferent arteriol vazokonstriksiyonu ile glomerüler filtrasyon basıncının azalması"],"correct":2,"exp":"Diyabetik nefropatide glomerüler bazal membran, ileri glikasyon son ürünleri ve artmış TGF-β etkisiyle kalınlaşır ve heparan sülfat proteoglikanlarını kaybeder. Bu anyonik proteoglikanlar normalde negatif yüklü albüminin filtrasyonunu elektrostatik olarak engeller. Kaybıyla birlikte aniyon bariyeri bozulur ve albümin süzülmeye başlar. Podosit foot process füzyonu minimal change hastalığı için daha karakteristiktir. Afferent arteriol kasılması filtrasyon basıncını düşürür, proteinüriyi artırmaz. Bu nedenle doğru yanıt heparan sülfat kaybına bağlı aniyon bariyer yıkımıdır."},{"id":9978,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Solunum sisteminin histolojisi ile ilgili aşağıdaki ifadelerden hangisi doğrudur?","options":["Tip II pnömositler yassı morfolojileriyle gaz değişimini kolaylaştırır ve alveol yüzeyinin büyük kısmını kaplar.","Tip II pnömositler sürfaktan sentezleyip salgılar, hasar sonrasında Tip I pnömositleri yenileyebilir.","Tip I pnömositler, hasarlı alveol epitelini yenilemek amacıyla mitotik aktivite gösterir.","Alveol makrofajları tip II pnömosit kökenli olup sürfaktan üretimine katkıda bulunur.","Clara hücreleri mukus sekresyonundan sorumlu olup terminal bronşiollerin tek epitel hücre tipidir."],"correct":1,"exp":"Tip II pnömositler küboid morfolojileriyle alveol köşelerinde yer alır, lamellar cisimcikler aracılığıyla sürfaktan sentezler ve salgılar. Ayrıca hasardan sonra Tip I pnösitleri yenileyen kök hücre işlevi görürler. Tip I pnömositler yassı morfolojileriyle alveol yüzeyinin yaklaşık %95'ini kaplayarak gaz difüzyonunu kolaylaştırır, ancak mitotik aktivite göstermezler. Alveol makrofajları monosit kökenlidir. Clara hücreleri (güncel adıyla Club hücreleri) mukuslu sekresyon değil, surfaktan benzeri lipoprotein ve metabolize edici enzim salgılar."},{"id":9979,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, 3 haftadır süren ateş, gece terlemesi ve boyun ile aksillada ele gelen kitleler yakınmasıyla başvuruyor. Fizik muayenede servikal ve aksiller zincirde sert, ağrısız lenfadenopatiler saptanıyor; dalak 3 cm büyük. Eksizyonel biyopside Reed-Sternberg hücreleri ve çevrelerinde eozinofillerden zengin reaktif infiltrat görülüyor. Bu hastada Reed-Sternberg hücrelerinin immünohistokimyasal profili değerlendirilirken aşağıdaki öncüllerin hangileri doğrudur?\nI. Reed-Sternberg hücreleri genellikle CD15 ve CD30 pozitif, CD45 negatif boyanır.\nII. Reed-Sternberg hücrelerinin çoğunluğu germinal merkez B lenfosit kökenlidir ve normal B hücre yüzey antijenlerini yitirmiştir.\nIII. Laküner hücreler nodüler sklerozan alt tipinde görülür ve Reed-Sternberg hücrelerinin bir varyantıdır.\nIV. Lenfositten zengin klasik Hodgkin lenfomada Reed-Sternberg hücreleri CD20 negatif olup nodüler lenfosit baskın tipten ayırt edilemez.","options":["I, II, III ve IV","II, III ve IV","I, II ve III","Yalnız II ve III","Yalnız I ve II"],"correct":2,"exp":"Klasik Hodgkin lenfomada Reed-Sternberg hücreleri CD15 ve CD30 pozitif, CD45 (LCA) negatiftir (Öncül I doğru). Bu hücreler germinal merkez B lenfosit kökenlidir; BCR ekspresyonu kaybettiklerinden artık normal B hücre yüzey belirteçleri taşımazlar (Öncül II doğru). Laküner hücreler, nodüler sklerozan alt tipine özgü Reed-Sternberg varyantlarıdır; bol soluk sitoplazma ve yapay retraksiyon artefaktı ile karakterizedir (Öncül III doğru). Öncül IV yanlıştır: nodüler lenfosit predominant tip CD20 pozitif, popcorn hücreleri içerirken klasik Hodgkin lenfoması CD20 negatiftir; bu iki antite immünohistokimyasal olarak ayırt edilebilir. Dolayısıyla I, II ve III doğrudur."},{"id":9980,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Yapılan ekokardiyografide ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya tedavi başlanırken yapılan incelemede kapiller kama basıncının (PCWP) 22 mmHg olduğu saptanıyor. Bu hastada Frank-Starling mekanizmasına göre kalbin preload artışına verdiği yanıt en iyi hangi seçenekle ifade edilir?","options":["İşlevsel olarak bozulmuş kalpte eğri düzleştiği için atım hacmi artmaz veya düşer","Kontraktilite artışı olmaksızın atım hacmi artar","Sempatik aktivasyon baskılandığından kalp hızı düşer","Atım hacmi artar ve ejeksiyon fraksiyonu orantılı yükselir","Afterload azaldığından ventrikül duvar stresi azalır"],"correct":0,"exp":"Frank-Starling mekanizması, artan end-diastolik volümün (preload) miyokard gerilimini artırarak daha güçlü kasılmaya yol açmasını tanımlar. Sağlıklı kalpte eğri sola ve yukarıya doğrudur; preload arttıkça atım hacmi artar. Ancak kalp yetersizliğinde (EF %35 gibi düşük değerlerde) Frank-Starling eğrisi düzleşir ve aşağı sola kayar. Dolayısıyla PCWP 22 mmHg gibi yüksek değerlerde bile ventrikül bu ek dolumu atım hacmine çeviremez; eğrinin düz bölgesinde kalınır veya hacim azalır. Bu nedenle doğru yanıt C seçeneğidir. A seçeneği sağlıklı kalp için geçerlidir. B seçeneğinde EF artışı beklenmez çünkü EDV de artmıştır. D ve E seçenekleri Frank-Starling mekanizmasıyla doğrudan ilgili değildir."},{"id":9981,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşındaki kadın hasta 2 yıldır egzersiz dispnesi ve tekrarlayan akciğer enfeksiyonlarıyla başvuruyor. Solunum fonksiyon testlerinde FEV1/FVC oranı %58. Bronkoskopide büyük hava yollarını döşeyen epitelin yerini çok katlı yassı epitelin aldığı görülüyor. Bu hastada gözlenen histolojik değişiklik en doğrudan hangi hücre tipinin kaybıyla ilişkilidir?","options":["Kulchitsky hücresi","Tip I pnömosit","Tip II pnömosit","Goblet hücresi","Silyalı psödostratifiye kolumnar hücre"],"correct":4,"exp":"Normal bronş ve trakea epiteli psödostratifiye silyalı kolumnar epitelden oluşur; bu hücrelerin silleri mukosiliyer klirensı sağlar. Kronik irritasyon (sigara, kronik enfeksiyon) durumunda bu epitel metaplaziye uğrayarak çok katlı yassı epitele dönüşür; buna skuamöz metaplazi denir. Silyalı hücrelerin kaybı mukosiliyer klirensi bozar, sekresyon birikir ve tekrarlayan enfeksiyonlara zemin hazırlar. Tip I ve Tip II pnömositler alveoler düzeyde görev yapar, bronş epiteliyle ilgisi yoktur. Goblet hücresi kaybolduğunda müküs azalır ancak skuamöz metaplazinin temel öğesi silyalı hücrenin yerini yassı epitelin almasıdır. Kulchitsky hücreleri nöroendokrin hücrelerdir ve bu tabloyla ilgisi yoktur."},{"id":9982,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 6 aydır ilerleyici yürüyüş bozukluğu, denge kaybı ve her iki elde titreme yakınmalarıyla nöroloji kliniğine başvuruyor. Nörolojik muayenede istirahat tremoru, rijidite ve bradikinezi saptanıyor. Beyin MRG normaldir. Hastaya dopaminerjik tedavi başlanmaktadır. hangileri bu hastanın patolojisiyle uyumludur?\nI. Substantia nigra pars compacta'daki dopaminerjik nöronlarda kayıp\nII. Striatum'da D2 reseptörlerinin aşırı aktivasyonu\nIII. Globus pallidus internusta inhibitör çıktının azalması\nIV. Talamokortkal yolağın aşırı inhibisyonu","options":["II, III ve IV","I ve IV","I, II ve IV","I ve III","Yalnız I"],"correct":1,"exp":"Parkinson hastalığında substantia nigra pars compacta'daki dopaminerjik nöronlar kaybedilir (Öncül I doğru). Dopamin normalde striatumda hem D1 (direkt yolak, inhibisyon kaldırma) hem D2 (indirekt yolak, inhibisyonu artırma) reseptörlerine etki eder. Dopamin eksikliğinde D2 reseptörler yeterince uyarılamadığından indirekt yolak aşırı aktif hale gelir; bu globus pallidus eksternanın inhibisyonu artırır, dolayısıyla subtalamik nükleus aşırı aktive olur ve globus pallidus internusta inhibitör çıktı ARTAR (Öncül III yanlış, çıktı azalmaz, artar). Artan GPi çıktısı talamokortkal yolağı fazlasıyla inhibe eder (Öncül IV doğru). D2 reseptörlerinin aşırı aktivasyonu değil, yetersiz aktivasyonu söz konusudur (Öncül II yanlış). Bu nedenle doğru öncüller I ve IV'tür."},{"id":9983,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 1 haftadır süren ödem, idrar köpürmesi ve yorgunluk yakınmalarıyla iç hastalıkları polikliniğine başvuruyor. İdrar tetkikinde günlük protein atılımı 4,2 g olarak ölçülüyor, serum albumin düzeyi 2,1 g/dL saptanıyor. Böbrek biyopsisinde elektron mikroskopide podosit ayaksı çıkıntılarının (foot process) silinmesi dikkat çekiyor, ışık mikroskopide glomerüller normal görünümde. Bu hastada böbreğin hangi bölgesindeki hangi yapıda birincil hasar söz konusudur?","options":["Glomerüler bazal membranın tip IV kollajen hasarı","Visseral epitel hücrelerinin (podosite) filtrasyon yarıklarında hasar","Proksimal tübül fırçamsı kenarında megalin reseptörü hasarı","Henle kulpunun ince çıkan kolunda aquaporin-1 kaybı","Mezangial hücrelerin proliferasyonu ve matriks artışı"],"correct":1,"exp":"Klinik tablo nefrotik sendromu (masif proteinüri >3,5 g/gün, hipoalbuminemi, ödem) düşündürmektedir. Elektron mikroskopide foot process silinmesi ve ışık mikroskopide normal glomerül görünümü minimal değişiklik hastalığının (Nil hastalığı) klasik patolojik bulgusudur. Bu hastalıkta birincil hasar visseral epitel hücresi olan podositlerin filtrasyon yarıklarındadır; nefrin ve podosinin kaybıyla yük bariyeri bozulur ve albümin geçişi artar. Proksimal tübül hasarı Fanconi sendromunu, tip IV kollajen hasarı Alport sendromunu, mezangial proliferasyon IgA nefropatisini düşündürür. Aquaporin-1 kaybı idrar konsantrasyon bozukluğuyla ilgilidir, proteinüriyle ilişkisi yoktur."},{"id":9984,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Kemik iliğinde bulunan ve tüm kan hücrelerini oluşturabilen hücre tipi ile bu hücrenin yüzeyinde eksprese ettiği belirteç hangisidir?","options":["Eritroid progenitör - CD10","Hematopoetik kök hücre - CD34","Common myeloid progenitör - CD19","Megakaryosit - CD41","Multipotent progenitör hücre - CD3"],"correct":1,"exp":"Hematopoetik kök hücreler (HSC) kemik iliğinde bulunur ve hem myeloid hem lenfoid serilerin tüm elemanlarını oluşturabilir; bu özellikleri onları totipotent/pluripotent yapar. HSC'lerin yüzeyinde en karakteristik belirteç CD34'tür ve klinik pratikte kök hücre nakli öncesi CD34+ hücreler sayılarak ürün kalitesi değerlendirilir. CD3 T lenfosit yüzey belirtecidir. CD41 (glikoprotein IIb) megakaryosit ve trombosit yüzeyinde bulunur. CD19 B lenfosit belirtecidir. CD10 (CALLA) ön-B hücreleri ve bazı nefron segmentlerinde eksprese edilir. Bu nedenle doğru yanıt CD34 eksprese eden hematopoetik kök hücredir."},{"id":9985,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"Kronik gastroözofageal reflüsü olan bir hastanın distal özofagus biyopsisinde goblet hücreleri içeren kolumnar epitel saptanıyor.\n\nI. Bulgular intestinal metaplaziyle uyumludur.\nII. Gastrik karsinom riskini artırır.\nIII. Parietal hücre kaybına bağlı hipoklorhidri temel bulgudur.\nIV. Bu değişiklik Barrett özofagusu olarak adlandırılır.\n\nBu öncüllerden hangileri doğrudur?","options":["II ve III","I, II, III ve IV","I ve IV","I, II ve IV","Yalnız I"],"correct":2,"exp":"Goblet hücreli intestinal metaplazi Barrett özofagusuyla uyumludur ve özofagus adenokarsinomu riskini artırır. Gastrik karsinom ve parietal hücre kaybı bu tablonun temel özellikleri değildir."},{"id":9986,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, efor dispnesi ve bacaklarda şişlik yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya digoksin başlanıyor. Digoksinin etkisiyle ilgili aşağıdaki öncüller değerlendiriliyor:\nI. Na⁺/K⁺-ATPaz pompasını inhibe ederek hücre içi Na⁺ artışına yol açar.\nII. İntraselüler Ca²⁺ konsantrasyonunu azaltarak kontraktiliteyi artırır.\nIII. Vagal tonusu artırarak AV ileti hızını düşürür.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","II ve III","I, II ve III","I ve II","I ve III"],"correct":4,"exp":"Digoksin, sarkolemmal Na⁺/K⁺-ATPaz pompasını inhibe eder; bu durum hücre içi Na⁺ birikimini artırır. Artan intraselüler Na⁺, Na⁺/Ca²⁺ değiştiricisinin (NCX) ters yönde çalışmasına neden olur ve hücre içi Ca²⁺ konsantrasyonu ARTAR, böylece miyokard kontraktilitesi güçlenir. Öncül II bu nedenle yanlıştır. Digoksin ayrıca parasempatik (vagal) tonusu artırarak sinoatriyal ve atriyoventriküler düğüm iletimini yavaşlatır; bu da öncül III'ü doğru kılar. Sonuç olarak I ve III doğrudur."},{"id":9987,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, nefes darlığı ve kuru öksürük yakınmasıyla başvuruyor. Yüksek rezolüsyonlu BT'de 'buzlu cam' görünümü ve bilateral interstisyel infiltrasyonlar saptanıyor. Bronkoalveoler lavaj örneğinde Tip II pnömositlerin sayısının belirgin biçimde azaldığı bildiriliyor. Bu hastada akciğer kompliansı ve yüzey gerilimi açısından beklenen değişiklik hangisidir?","options":["Komplians değişmez, yüzey gerilimi artar","Komplians azalır, yüzey gerilimi artar","Komplians azalır, yüzey gerilimi azalır","Komplians artar, yüzey gerilimi azalır","Komplians artar, yüzey gerilimi değişmez"],"correct":1,"exp":"Tip II pnömositler, alveol yüzeyindeki yüzey gerilimini azaltan sürfaktanı (başta dipalmitoilfosfatidilkolin) üretir. Bu hücrelerin sayısı azaldığında sürfaktan sentezi düşer, alveol içi yüzey gerilimi artar ve alveollerin kollabe olma eğilimi güçlenir. Komplians (akciğerlerin genişleme kapasitesi), artan yüzey gerilimine bağlı olarak belirgin şekilde azalır. Bu tablo ARDS ya da interstisyel akciğer hastalığı patogenezinin temel mekanizmasıdır."},{"id":9988,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında erkek hasta, hipertansiyon ve tip 2 diabetes mellitus tanısıyla izlenmekte olup nefroloji polikliniğine yönlendiriliyor. Laboratuvar incelemesinde GFR 28 mL/dak/1,73 m², serum kreatinin 3,1 mg/dL, günlük idrarda protein 4,2 g olarak saptanıyor. Böbrek biyopsisinde mezangiyal matriks artışı ve Kimmelstiel-Wilson nodülleri görülüyor. Bu hastada proksimal tübülüste beklenen fizyolojik değişiklik hangisidir?","options":["Tübüler maksimum (Tm) aşılmadığından idrarda glukoz görülmez","Glukoz geri emilim kapasitesi artar","Sodyum-glukoz ko-transporteri (SGLT2) aktivitesi azalır","Proksimal tübülden HCO₃⁻ geri emilimi durur","Proksimal tübül hücrelerinde hipertrofi gelişerek Tm yükselir"],"correct":2,"exp":"Diyabetik nefropatide kronik hiperglisemi, proksimal tübüldeki SGLT2 ekspresyonunu ve aktivitesini başlangıçta artırır; ancak ilerlemiş hastalık evresinde nefron kaybı ve tübüler hasar SGLT2 aktivitesini belirgin biçimde azaltır. Tübüler maksimumlun (Tm) aşılması veya SGLT2 fonksiyon bozukluğu, glukozüriye yol açar; bu nedenle 'Tm aşılmadığından idrarda glukoz görülmez' ifadesi yanlıştır. Proksimal tübül hipertrofisi erken evrede görülüp Tm'yi geçici olarak artırabilse de ilerlemiş evrede bu yanıt ortadan kalkar. Doğru seçenek, ilerlemiş diyabetik nefropatide SGLT2 aktivitesinin azalmasıdır."},{"id":9989,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"8 yaşında kız çocuk, tekrarlayan bakteriyel enfeksiyonlar ve deri döküntüsü nedeniyle getiriliyor. Periferik kan yaymasında nötrofillerin sitoplazmalarında dev granüller dikkat çekiyor. Kemik iliği incelemesinde lenfosit ve NK hücre sayısının azalmış olduğu bildiriliyor. Bu çocukta hangi hücre organelinin işlev bozukluğu söz konusudur?","options":["Mitokondri","Golgi aygıtı","Lizozom","Peroksizom","Endoplazmik retikulum"],"correct":2,"exp":"Tanımlanan tablo Chediak-Higashi sendromunu düşündürmektedir. Bu otozomal resesif hastalıkta LYST (lizozomal trafik regülatörü) geninde mutasyon sonucu lizozomlar anormal biçimde büyür ve birleşir; nötrofil, melanosit ve trombosit gibi granül içeren hücrelerde dev organeller oluşur. Nötrofiller bu dev lizozomları nedeniyle bakterileri fagosite edebilir ancak parçalayamaz, bu da tekrarlayan bakteriyel enfeksiyonlara yol açar. NK hücre sayı ve işlev azlığı da bu sendromun karakteristik bulgusudur."},{"id":9990,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"42 yaşındaki erkek hasta 6 aydır giderek kötüleşen yürüyüş bozukluğu, ellerde titreme ve bradikineziyle başvuruyor. Dopaminerjik nöron dejenerasyonuna bağlı tanı konularak levodopa/karbidopa başlanıyor. Karbidopanın bu kombinasyona eklenmesinin temel fizyolojik gerekçesi aşağıdakilerden hangisidir?","options":["Levodopanın karaciğerde ilk geçiş metabolizmasını azaltması","Dopamin reseptörlerine doğrudan agonist etkiyle striatal aktiviteyi artırması","MAO-B enzimini inhibe ederek dopaminin sinaptik aralıkta kalma süresini uzatması","Kan-beyin bariyerini geçerek SSS'de dopamin yıkımını inhibe etmesi","Periferik dokularda aromatik L-amino asit dekarboksilazı inhibe ederek levodopanın beyne ulaşan miktarını artırması"],"correct":4,"exp":"Levodopa, periferik dokularda (bağırsak, karaciğer, plazma) aromatik L-amino asit dekarboksilaz (DOPA dekarboksilaz) enzimi tarafından hızla dopamine dönüştürülür. Periferik dopamin kan-beyin bariyerini geçemez ve bulantı, hipotansiyon gibi yan etkilere neden olur. Karbidopa, kan-beyin bariyerini geçemeyen bir DOPA dekarboksilaz inhibitörüdür; bu sayede levodopanın periferik dönüşümünü engeller, daha yüksek oranda levodopanın beyne ulaşmasını sağlar ve orada nöronal dekarboksilazlar aracılığıyla dopamine çevrilmesine olanak tanır."},{"id":9991,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Mide fundusundaki oksintik bezlerde bulunan, intrinsik faktör ve hidroklorik asit salgılayan hücre tipi aşağıdakilerden hangisidir?","options":["D hücresi","Baş hücresi (chief cell)","Paryetal hücre (oksintik hücre)","G hücresi","Müköz boyun hücresi"],"correct":2,"exp":"Mide glandlarındaki parietal hücreler (oksintik hücreler), iki temel ürünü salgılar: hidroklorik asit (HCl) ve intrinsik faktör. HCl, mide lümeninde asidik ortamı sağlar ve pepsinojeni aktive eder; intrinsik faktör ise terminal ileumda B12 vitamini (kobalamin) emilimi için zorunludur. Baş hücreleri (chief cells) pepsinojen salgılar; G hücreleri antrum bölgesinde gastrin üretir; D hücreleri somatostatin salgılar; müköz boyun hücreleri ise müsin üreterek epiteli korur."},{"id":9992,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan kas güçsüzlüğü ve efor dispnesi şikayetiyle başvuruyor. Özgeçmişinde küçük hücreli akciğer karsinomu tanısıyla kemoterapi aldığı öğreniliyor. Nörolojik muayenede proksimal kas gruplarında belirgin güçsüzlük saptanıyor; tekrarlayan kasılmalarla gücün arttığı gözlemleniyor. Elektromiyografide yüksek frekanslı uyarıyla artmış bileşik kas aksiyon potansiyeli amplitüdü saptanıyor. Bu hastada voltaj kapılı kalsiyum kanallarına karşı gelişen otoantikorlar, kas-sinir kavşağında aşağıdaki hangi olayı doğrudan bozar?","options":["Asetilkolin reseptörlerine bağlanmayı","Asetilkolinesteraz aktivitesini","Motor nöron aksiyon potansiyelinin iletimini","Presinaptik terminale Ca²⁺ girişini","Postsinaptik membran depolarizasyonunu"],"correct":3,"exp":"Bu tablo Lambert-Eaton miyastenik sendromunu tanımlamaktadır; küçük hücreli akciğer karsinomuna paraneoplastik eşlik edebilir. Tekrarlayan kasılmayla güç artışı (post-tetanik fasilitasyon) ve yüksek frekanslı uyarıyla amplitüd artışı bu sendromun ayırt edici özelliğidir. Patoloji presinaptiktedir: voltaj kapılı P/Q tipi Ca²⁺ kanallarına karşı gelişen otoantikorlar presinaptik terminale kalsiyum girişini azaltır, böylece veziküler asetilkolin ekzositozu yetersiz kalır. Miyastenia graviste ise patoloji postsinaptiktir ve asetilkolin reseptörleri hedef alınır; bu iki tablonun ayrımı kritiktir."},{"id":9993,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, 2 yıldır süren çarpıntı ve egzersiz intoleransı şikayetiyle kardiyoloji polikliniğine başvuruyor. Ekokardiyografide mitral kapak yaprakçıklarında kalınlaşma ve kısalma, mitral kapak orifis alanı 1,1 cm² olarak ölçülüyor. Pulmoner arter basıncı 48 mmHg saptanıyor. Kardiyak kateterizasyonda sol atriyum basıncı yüksek, sol ventrikül diyastol sonu basıncı normal bulunuyor. Bu hastada sol atriyal basınç artışına bağlı olarak pulmoner kapiller yatakta gerçekleşen histolojik adaptasyon aşağıdakilerden hangisidir?","options":["Tip II pnömosit hiperplazisi ve surfaktan salınımında artış","Alveolar makrofaj sayısında azalma","Pulmoner arteriyol düz kas hipertrofisi ve intimal fibrozis","Pulmoner kapiller endotel hücrelerinde apoptoz artışı","Tip I pnömositlerin hipertrofisi"],"correct":2,"exp":"Uzun süreli mitral darlıkta (orifis alanı < 1,5 cm²) kronik pulmoner venöz hipertansiyon gelişir. Bu basınç artışı önce pulmoner kapiller ve venüllere, ardından reaktif olarak pulmoner arteriyollere yansır. Kronik süreçte pulmoner arteriyollerde medial düz kas hipertrofisi ve intimal fibrozis gelişir; bu durum 'ikincil pulmoner hipertansiyon' olarak adlandırılır ve sağ ventrikül afterload artışına yol açar. Ayrıca kronik konjesyonda alveolar makrofajlar hemosiderin biriktirir ('kalp yetmezliği hücreleri' / siderofajlar). Tip I ve II pnömosit değişiklikleri bu tablonun primer histolojik adaptasyonu değildir."},{"id":9994,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbreğin proksimal tübülüs hücreleri ile distal tübülüs hücreleri histolojik olarak karşılaştırıldığında, proksimal tübülüs hücrelerine özgü olan yapısal özellik aşağıdakilerden hangisidir?","options":["Apikal yüzeyde fırçamsı kenar (brush border) varlığı","Bazolateral yüzeyde Na⁺/K⁺-ATPaz ekspresyonu","Tight junction komplekslerinin varlığı","Sitoplazmada çok sayıda mitokondri bulunması","Apikal yüzeyde akuaporin-2 ekspresyonu"],"correct":0,"exp":"Proksimal tübülüs hücreleri, yoğun mikrovillüslerden oluşan belirgin fırçamsı kenara (brush border) sahiptir; bu yapı emilim yüzeyini yaklaşık 40 kat artırır ve proksimal tübülüse özgü en karakteristik histolojik bulgudur. Her iki tübül segmentinde de bazolateral Na⁺/K⁺-ATPaz ekspresyonu ve çok sayıda mitokondri bulunur. Akuaporin-2 toplayıcı kanallarda ADH etkisiyle eksprese edilir; proksimal tübülüste bulunan akuaporinler AQP1 tipidir. Tight junction kompleksleri tüm nefron segmentlerinde mevcuttur."},{"id":9995,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 3 yıldır ilerleyici unutkanlık, kişilik değişikliği ve günlük yaşam aktivitelerinde bağımlılık şikayetiyle nöroloji polikliniğine getiriliyor. Yapılan beyin MRG'de temporoparietal bölgede belirgin atrofi saptanıyor. Bilişsel testlerde epizodik bellek alanında ağır bozulma görülüyor. Bu hastalığın patofizyolojisinde rol oynayan iki temel patolojik protein ve bunların hücre içi/dışı yerleşimleri ile ilgili aşağıdaki öncülleri değerlendirin:\nI. Amiloid beta plaklarının ana bileşeni APP'nin beta ve gama sekretazlarla anormal işlenmesinden oluşur ve ekstraselüler birikir.\nII. Tau proteini hiperfosforile hale geçerek mikrotübülleri stabilize eder ve ekstraselüler nörofibriler yumaklar oluşturur.\nIII. Senil plaklarda amiloid beta peptidinin en toksik formu oligomerik yapıdaki Aβ42'dir.\nIV. Kolinerjik nöron kaybı özellikle bazal ön beyindeki Meynert çekirdeğinde belirgindir ve bu bulgu kolinesteraz inhibitörü kullanımının temelini oluşturur.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Yalnız biri","Üçü","Dördü","Hiçbiri","İkisi"],"correct":1,"exp":"Öncül I doğrudur: Amiloid beta, APP'nin beta-sekretaz (BACE1) ve gama-sekretaz kompleksi tarafından ardışık kesimiyle oluşur ve ekstraselüler alanda birikerek senil plakları oluşturur. Öncül II yanlıştır: Hiperfosforile tau proteini mikrotübülleri DESTABİLİZE eder (stabilize değil) ve INTRAselüler nörofibriler yumaklar oluşturur, ekstraselüler değil. Öncül III doğrudur: Aβ42, Aβ40'a kıyasla daha uzun ve agregasyona daha yatkındır; oligomerik formu sinaptik toksisite açısından en zararlı form kabul edilmektedir. Öncül IV doğrudur: Meynert bazal çekirdeğindeki kolinerjik nöron kaybı Alzheimer hastalığının erken ve belirgin patolojik bulgusudur; asetilkolinesteraz inhibitörleri (donepezil, rivastigmin) bu temele dayanır. Dolayısıyla doğru öncül sayısı 3'tür. Bu nedenle doğru yanıt Üçü seçeneğidir."},{"id":9996,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"48 yaşında erkek hasta, 5 yıldır süren kronik ishal, karın ağrısı ve 12 kg kilo kaybı şikayetiyle başvuruyor. Dışkı yağ boyamasında steatore saptanıyor. İnce barsak biyopsisinde villus atrofisi, kript hiperplazisi ve intraepitelyal lenfositoz görülüyor; submukozada PAS pozitif, diastaza dirençli makrofaj infiltrasyonu dikkati çekiyor. Bu hastada saptanan submukozal PAS pozitif makrofajlar içindeki mikroorganizma ve buna bağlı emilim bozukluğunun temel mekanizması aşağıdakilerden hangisidir?","options":["Cryptosporidium parvum enfeksiyonu; Na⁺ bağımlı glukoz transporterı (SGLT-1) kaybı","Tropheryma whipplei enfeksiyonu; lenfatik tıkanıklığa bağlı şilomikron transportu bozukluğu","Giardia lamblia enfeksiyonu; fırçamsı kenarın mekanik hasarı","Clostridium difficile enfeksiyonu; tight junction proteinlerinin proteolitik yıkımı","Mycobacterium avium kompleksi; enterosin salgılanmasının inhibisyonu"],"correct":1,"exp":"Submukozada PAS pozitif, diastaza dirençli (yani glikoprotein içeren bakteri yüklü) makrofajların saptanması Whipple hastalığının patognomik bulgusudur. Etken Tropheryma whipplei adlı gram pozitif bakteridir. Bu bakteri makrofajlar tarafından fagosite edilmekle birlikte lizozomal yıkımdan kaçar ve submukozal lenfatikleri tıkar. Lenfatik obstrüksiyon nedeniyle şilomikronlar ve yağda çözünen vitaminler sistemik dolaşıma geçemez; bu durum steatore ve malabsorbsiyonun temel mekanizmasıdır. Tedavide trimetoprim-sulfametoksazol veya seftriakson kullanılır."},{"id":9997,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"29 yaşında kadın hasta, 3 aydır süren halsizlik, tekrarlayan enfeksiyonlar ve bacaklarında peteşi şikayetiyle başvuruyor. Tam kan sayımında pansitopeni saptanıyor. Periferik yaymada blastik hücre görülmüyor. Kemik iliği biyopsisinde yağ dokusu oranının %80'in üzerine çıktığı, hematopoetik hücre adacıklarının ciddi ölçüde azaldığı görülüyor. Bu hastada en olası tanı ve bu tanıda kemik iliğinin histolojik görünümünü açıklayan temel patofizyolojik mekanizma aşağıdakilerden hangisidir?","options":["Miyelodisplastik sendrom; anormal klonal hematopoezin displastik hücre birikimine yol açması","Aplastik anemi; T lenfosit aracılı hematopoetik kök hücre yıkımının kök hücre havuzunu tüketmesi","Akut miyeloid lösemi; matürasyon duraklamasına uğrayan blast hücrelerinin normal hematopoezi baskılaması","B12 vitamini eksikliği; DNA sentez bozukluğuna bağlı inefektif hematopoez","Miyelofibrozis; stromal fibrozis nedeniyle hematopoetik hücrelerin baskılanması"],"correct":1,"exp":"Pansitopeni + periferik yaymada blast yokluğu + kemik iliğinde hiposellülarite ve yağ dokusu artışı aplastik aneminin klasik triyadıdır. Edinsel aplastik aneminin büyük çoğunluğunda otoimmün mekanizma yatar: sitotoksik CD8⁺ T lenfositler, Fas-FasL ve perforin/granzim B yolakları aracılığıyla hematopoetik kök hücreleri apoptoza sürükler; böylece kök hücre havuzu tükenirken boşalan niş yağ dokusuyla dolar. Miyelodisplastik sendromda kemik iliği genellikle normosellüler veya hipersellüler olup displastik seri hücreleri içerir. AML'de blast infiltrasyonu beklenir. Miyelofibroziste fibrozis ön plandadır. B12 eksikliğinde megaloblastik değişiklikler ve hipersellüler ilik görülür."},{"id":9998,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, efor sırasında çarpıntı ve nefes darlığı yakınmasıyla başvuruyor. Holter monitörizasyonunda QRS kompleksi dar, düzensiz R-R aralıkları ve P dalgalarının ayırt edilemediği bir ritim saptanıyor. Hastaya ritim kontrolü amacıyla verilen ilacın, AV düğüm iletimini yavaşlatarak ventrikül yanıt hızını azalttığı öğrenilmektedir. Bu mekanizmayla etki eden ilaçların ortak kontrendikasyonu aşağıdakilerden hangisidir?","options":["WPW sendromu","Hipertansiyon","Diabetes mellitus","Hiperlipidemi","Kronik böbrek hastalığı"],"correct":0,"exp":"AV düğüm iletimini yavaşlatan ilaçlar (digoksin, beta blokerler, non-dihidropiridin kalsiyum kanal blokerleri) aksesuar yoldan iletiyi artırarak WPW sendromunda ventriküler fibrilasyona yol açabilir. WPW'de bu ilaçlar kontrendikedir; aksesuar yol boyunca iletim hızlanır ve ölümcül aritmiye zemin oluşur."},{"id":10000,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında erkek hasta, 6 aydır süren ödem, hipoalbüminemi ve günlük 4 gr üzerinde proteinürisi nedeniyle nefroloji polikliniğine başvuruyor. Böbrek biyopsisinde ışık mikroskobisinde glomerüllerin normal göründüğü, elektron mikroskobisinde ise podosit çıkıntılarının yaygın silinmesi (foot process effacement) saptanıyor. Bu hastada tüp hücreleri üzerine etkili bir diüretiğin kullanılmasına karar veriliyor. Kullanılacak ilacın etkisini gösterdiği tübül segmentinde gerçekleşen fizyolojik olaylarla ilgili aşağıdakilerden hangisi doğrudur?","options":["Bu segmentte Na+ yalnızca pasif difüzyonla geri emilir","ADH etkisiyle bu bölgede su geçirgenliği artar","Aldosteronun primer etki bölgesi bu segmenttir","Bu segmentte Na+/K+/2Cl- kotransporter inhibisyonu diürez sağlar","Bu segment dolaşımdaki üre konsantrasyonuna duyarsızdır"],"correct":3,"exp":"Klinik tablo minimal değişiklik hastalığını tanımlamaktadır. Soruda bahsedilen diüretik Henle kulpunun çıkan kalın bacağında etkili olan loop diüretiğidir. Bu segmentteki Na+/K+/2Cl- (NKCC2) kotransporterinin inhibisyonu, medüller osmotik gradientin bozulmasına ve güçlü diüreze yol açar. ADH etkisi toplayıcı kanallarda ve kortikal toplayıcı tübülde geçerlidir. Aldosteron ise kortikal toplayıcı kanalda etkilidir."},{"id":10001,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Bronş duvarını oluşturan katmanlar ve bu katlardaki yapılar değerlendirildiğinde, aşağıdaki öncüllerden hangileri doğrudur?\nI. Bronş epiteli psödostratifiye silialı prizmatik tipte olup lamina propriada düz kas tabakası içermez.\nII. Goblet hücreleri mukus salgılayarak mukosilier klirenste görev alır.\nIII. Küçük bronşiyollerde kıkırdak plakları kaybolur ve düz kas oranı artar.\nIV. Clara (Club) hücreleri terminal bronşiyollerde yüzey aktif madde benzeri bileşik salgılar.","options":["I ve II","II ve III","II, III ve IV","I, III ve IV","I, II, III ve IV"],"correct":2,"exp":"Öncül I yanlıştır: bronş epiteli psödostratifiye silialı prizmatik olmakla birlikte lamina propriada düz kas tabakası mevcuttur. Öncül II doğrudur: goblet hücreleri mukus üretir ve bu mukus silia hareketi ile mukosilier klirensi sağlar. Öncül III doğrudur: kıkırdak plakları bronşiyollerde tamamen kaybolur, buna karşın düz kas oranı relatif olarak artar. Öncül IV doğrudur: Club (Clara) hücreleri yüzey aktif madde bileşenleri, proteaz ve anti-inflamatuvar maddeler salgılar. Doğru öncüller II, III ve IV'tür."},{"id":10002,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"34 yaşında kadın hasta, yorgunluk ve kolay멍든 cilt yakınmalarıyla başvuruyor. Tam kan sayımında trombosit sayısının 18.000/mm³ olduğu, hemoglobin ve lökosit değerlerinin normal sınırlarda olduğu görülüyor. Periferik yaymada trombositler normalden büyük görünmekte, olgun megakaryositler ise kemik iliğinde artmış olarak saptanıyor. Bu bulgular doğrultusunda hastaya intravenöz immünglobulin (IVIG) tedavisi planlanıyor. Bu tedavinin trombosit sayısını artırma mekanizmasının temelinde aşağıdakilerden hangisi yatmaktadır?","options":["Megakaryosit olgunlaşmasını uyararak platelet üretimini artırması","Fc reseptörlerini bloke ederek antikor kaplı trombositlerin dalakta yıkımını azaltması","T lenfosit aktivasyonunu baskılayarak otoimmün yanıtı kesmesi","Kompleman sistemini inhibe ederek trombosit lizisini engellemesi","Von Willebrand faktör aktivitesini artırarak trombosit ömrünü uzatması"],"correct":1,"exp":"Klinik tablo immün trombositopenik purpura (ITP) ile uyumludur. IVIG tedavisinde ana mekanizma, retiküloendotelyal sistemdeki makrofajların Fc reseptörlerinin IVIG ile doyurulmasıdır; böylece antikor kaplı trombositlerin Fc reseptörü aracılı fagositozu azalır ve trombosit yaşam süresi uzar. IVIG doğrudan megakaryosit stimülasyonu yapmaz ve kompleman inhibisyonu birincil mekanizma değildir."},{"id":10003,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 3 aydır süren ishal, yüz kızarması ve çarpıntı yakınmalarıyla başvuruyor. 24 saatlik idrarda 5-hidroksindolasetik asit (5-HIAA) düzeyi belirgin yükselmiş olarak saptanıyor. Görüntülemede karaciğerde multipl hipervasküler kitleler izleniyor. Bu hastada karaciğer tutulumuna bağlı gelişen sağ kalp kapak hastalığının histolojik zeminini oluşturan hücre tipi aşağıdakilerden hangisidir?","options":["Goblet hücreleri","Enteroendokrin (Kulchitsky) hücreleri","Paneth hücreleri","M hücreleri","Brunner bezi hücreleri"],"correct":1,"exp":"Klinik tablo karsinoid tümörü ve karsinoid sendromu tanımlamaktadır. Tümörün köken aldığı hücreler enterokromafin (Kulchitsky) hücreleri olarak da bilinen enteroendokrin hücrelerdir. Bu hücreler serotonin, substans P ve diğer vazoaktif peptidler salgılar. Karaciğer metastazlarından sistemik dolaşıma geçen serotonin akciğerlerde metabolize edilmeden sağ kalbe ulaşarak triküspid ve pulmoner kapakta fibrotik plak oluşturur (karsinoid kalp hastalığı). Paneth hücreleri antimikrobiyal peptid salgılar; goblet hücreleri müsin üretir; M hücreleri antijen örneklemesi yapar; Brunner bezleri alkali müküs salgılar."},{"id":10004,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, efor ile gelen göğüs ağrısı ve nefes darlığı yakınmasıyla başvuruyor. Yapılan koroner anjiyografide sol ön inen arterde %80 darlık saptanıyor. Hastaya perkütan koroner girişim planlanıyor; işlem öncesinde adenozin verildiğinde koroner kan akımının belirgin arttığı gözlemleniyor. Adenozinin bu etkisini hangi mekanizma üzerinden gösterdiğini en iyi açıklayan seçenek hangisidir?","options":["Koroner arteriyollerde A2A reseptörlerini aktive ederek düz kas gevşemesine yol açar","Miyokardda voltaj kapılı kalsiyum kanallarını bloke ederek vazodilatasyona neden olur","Sempatik sinir uçlarından norepinefrin salınımını artırarak miyokardiyal oksijen tüketimini azaltır","Endotelden prostasiklin salınımını baskılayarak trombosit agregasyonunu önler","Anjiyotensin II reseptörlerini bloke ederek sistemik vasküler direnci düşürür"],"correct":0,"exp":"Adenozin, koroner arteriyollerin düz kas hücrelerinde bulunan A2A reseptörlerini aktive ederek adenilat siklaz yolunu uyarır; artan cAMP protein kinaz A'yı aktive eder ve miyozin hafif zincir kinazı inhibe ederek düz kas gevşemesine ve vazodilatasyona neden olur. Bu etki nükleer ya da kalsiyum kanal blokajı veya prostasiklin yoluyla değil, doğrudan A2A reseptör aktivasyonu üzerindendir. Adenozin aynı zamanda A1 reseptörleri üzerinden AV iletiyi yavaşlatır; bu nedenle SVT tedavisinde de kullanılır. Koroner anjiyografide 'fractional flow reserve' ölçümünde farmakolojik hiperemik ajan olarak tercih edilmesinin nedeni bu güçlü selektif koroner vazodilatatör etkisidir."},{"id":10005,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 20 yıldır sigara içmekte ve son 2 yıldır istirahat dispnesi, wheezing ve tekrarlayan alt solunum yolu enfeksiyonları yaşamaktadır. Solunum fonksiyon testinde FEV1/FVC: 0,52, TLC artmış, DLCO belirgin azalmış saptanıyor. Toraks BT'de diffüz amfizematöz değişiklikler ve bronş duvarında kalınlaşma görülmektedir. Bu hastada DLCO'nun düşük olmasının temel anatomik-fizyolojik nedeni aşağıdakilerden hangisidir?","options":["Alveol duvarı yıkımına bağlı gaz değişim yüzeyinin ve pulmoner kapiller yatağın azalması","Bronş mukus bezi hipertrofisine bağlı hava yolu rezistansının artması","Hipoksik pulmoner vazokonstriksiyon sonucu akciğer perfüzyon basıncının yükselmesi","Alveoler makrofaj aktivasyonuna bağlı surfaktan üretiminin baskılanması","Tip II pnömosit hiperplazisi ile alveoler membran kalınlığının artması"],"correct":0,"exp":"DLCO (difüzyon kapasitesi), alveolo-kapiller membran alanı ile pulmoner kapiller kan volümünün bileşik bir ölçütüdür. Amfizemde elastaz-antielastaz dengesinin bozulması sonucu alveol septumaları yıkılır; küçük alveollerin birleşmesiyle büyük hava boşlukları (büllae) oluşur. Bu süreç hem gaz değişim yüzey alanını hem de bu yüzeye komşu pulmoner kapiller yatağı azaltır; dolayısıyla DLCO düşer. Bronş mukus bezi hipertrofisi kronik bronşitin histolojik işareti olup Reid indeksini artırır; ancak DLCO'yu birincil olarak etkilemez. Hipoksik pulmoner vazokonstriksiyon pulmoner hipertansiyona yol açabilir fakat difüzyon kapasitesini doğrudan düşürmez. Surfaktan baskılanması ve Tip II pnömosit hiperplazisi bu tablonun patofizyolojisinde öne çıkan mekanizmalar değildir."},{"id":10006,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, son 6 aydır ellerde titreme, terleme, çarpıntı ve kişilik değişikliği şikayetiyle başvuruyor. Nörolojik muayenede kognitif gerileme ve ekstrapiramidal bulgular saptanıyor. Göz muayenesinde Kayser-Fleischer halkası görülüyor. Serum seruloplazmin düzeyi düşük, 24 saatlik idrar bakır atılımı artmış bulunuyor. Hastaya D-penisilamin başlanıyor. Bu tedavinin santral sinir sistemindeki temel yararlanım mekanizması düşünüldüğünde, tedaviye yanıtın izlenmesinde en güvenilir biyokimyasal parametre aşağıdakilerden hangisidir?","options":["24 saatlik idrar bakır atılımının normale dönmesi","Serum seruloplazmin düzeyinin yükselmesi","Serum serbest bakır düzeyinin sıfıra inmesi","Karaciğer biyopsisinde bakır konsantrasyonunun azalması","BOS bakır düzeyinin normalizasyonu"],"correct":0,"exp":"Wilson hastalığında ATP7B gen mutasyonu nedeniyle bakır safra yoluyla atılamaz ve karaciğer, beyin, kornea ile böbreklerde birikir. D-penisilamin güçlü bir şelat ajanı olarak bakırla kompleks oluşturur ve renal yoldan atılımını artırır. Tedaviye yanıtın izlenmesinde 24 saatlik idrar bakır atılımı en pratik ve güvenilir parametredir; başlangıçta atılım artar (vücut depolarından mobilizasyon), tedavi etkinleştikçe stabil bir platoya oturur. Serum seruloplazmin, asit faz reaktanı özelliği taşıdığından enfeksiyon ya da inflamasyon durumlarında yükselir ve tek başına yanıt göstergesi olarak yanıltıcıdır. Serum serbest bakırı sıfıra indirmek klinik hedef değildir; fizyolojik düzeyde bakır gereklidir. Karaciğer biyopsisi invazif olup rutin izlemde kullanılmaz. BOS bakır ölçümü standardize edilmemiştir ve klinik pratikte izlemde yer almaz."},{"id":10007,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"Böbrek tübül fizyolojisi ile ilgili aşağıdaki öncüller değerlendirildiğinde kaç tanesi doğrudur?\nI. Proksimal tübülde glukoz geri emilimi, Na+-glukoz kotransporter (SGLT2) aracılığıyla gerçekleşir ve Na+-K+-ATPaz tarafından sağlanan elektrokimyasal gradyana bağlıdır.\nII. Henle kulpunun ince çıkan kolu suya geçirgen, ince inen kolu ise suya geçirgen değildir.\nIII. Toplayıcı kanalda ADH etkisiyle AQP2 kanalları apikal membranda eksprese edilir ve suyun geri emilimi artar.\nIV. Distal tübülde aldosteron, sitozolden çekirdeğe geçerek ENaC ve Na+-K+-ATPaz sentezini artırır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["1","2","3","4","Hiçbiri"],"correct":2,"exp":"Öncül I doğrudur: Proksimal tübülde SGLT2 luminal membranda Na+ ile glukozun birlikte içeri alınmasını sağlar; bazolateral Na+-K+-ATPaz düşük intrasellüler Na+ konsantrasyonunu koruyarak bu kotransporter için gereken elektrokimyasal gradyanı oluşturur. Öncül II yanlıştır: Henle kulpunun ince inen kolu suya geçirgendir (AQP1 eksprese eder) ve hiperozmotik medullaya su vererek konsantrasyon artar; ince çıkan kol ise suya geçirgen değil, üreye ve NaCl'e kısmi geçirgen bir yapıdadır. Bu nedenle öncülün ince ve kalın ifadeleri birbiriyle yer değiştirmiş olup yanlıştır. Öncül III doğrudur: ADH (vazopressin) V2 reseptörüne bağlanır, cAMP-PKA yolunu aktive eder ve AQP2 kanallarının apikal membrana translokasyonunu sağlayarak suyun geri emilimini artırır. Öncül IV doğrudur: Aldosteron lipofilik yapısı sayesinde sitozolde mineralokortikoid reseptörüne bağlanır, reseptör-ligand kompleksi çekirdeğe geçerek ENaC ve Na+-K+-ATPaz genlerinin transkripsiyonunu artırır. Sonuç olarak I, III ve IV doğru; II yanlıştır; doğru öncül sayısı 3'tür."},{"id":10008,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"28 yaşında kadın hasta, yorgunluk, soluk görünüm ve egzersiz intoleransı şikayetiyle başvuruyor. Tam kan sayımında Hb: 7,8 g/dL, MCV: 68 fL, MCH düşük, RDW artmış saptanıyor. Serum ferritin düzeyi 4 ng/mL olarak ölçülüyor. Hastaya oral demir tedavisi başlandıktan 10 gün sonra retikülosit sayısında belirgin artış gözlemleniyor. Bu bulgular hangi sürecin göstergesidir?","options":["Eritroid öncül hücrelerin kemik iliğinde hızlanmış olgunlaşması ve periferik kana salınması","Demir tedavisine bağlı hemolizin durdurulması ve eritrosit ömrünün uzaması","Renal eritropoetin sentezinin baskılanmasıyla hematopoezin yeniden düzenlenmesi","Dalakta ekstramedüller hematopoezin baskılanması","Plazma volümünün azalmasına bağlı göreceli eritrositoz gelişmesi"],"correct":0,"exp":"Demir eksikliği anemisinde kemik iliğindeki eritroid öncüller (özellikle eritroblastlar) yetersiz demir nedeniyle tam olarak olgunlaşamaz ve hemoglobin sentezi bozulur. Oral demir tedavisi başlandığında kemik iliğine yeterli substrat sağlanır; eritroid hiperplazi olan bir ilikte olgunlaşma hızlanır ve genç eritrositler (retikülosit) periferik kana salınmaya başlar. Bu retikülosit tepe yanıtı genellikle tedavinin 7-10. günlerinde görülür ve efektif eritropoezin yeniden başladığının en güvenilir göstergesidir. Hemoliz bu tabloda birincil mekanizma değildir. Eritropoetin bu süreçte baskılanmaz; aksine demir eksikliğinde hipoksiye yanıt olarak artmıştır, demir verilince eritroid yanıt güçlenir. Ekstramedüller hematopoez baskılanması ve göreceli eritrositoz bu mekanizmayla açıklanamaz."},{"id":10009,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"68 yaşında erkek hasta, 6 aydır giderek artan çiğneme güçlüğü ve yutma zorluğu yakınmasıyla başvuruyor. Öyküde uzun süreli egzersizle belirtilerin kötüleştiği ve dinlenmekle hafiflediği öğreniliyor. Nörolojik muayenede fasikülasyon saptanmıyor, derin tendon refleksleri normal. Edrofonyum (tensilon) testi pozitif bulunuyor. Bu hastaya piridostigmin başlanması beklenen yararı aşağıdaki etkilerden hangisi aracılığıyla sağlar?","options":["Nikotinik reseptörleri doğrudan aktive ederek kas kontraksiyonunu artırır","Asetilkolinesterazı inhibe ederek nöromüsküler kavşakta asetilkolin birikimini sağlar","Kas hücrelerindeki voltaj kapılı Ca²⁺ kanallarını aktive ederek kontraksiyon eşiğini düşürür","Muskarink reseptörler üzerinden sempatik tonusu artırarak kas gücünü yükseltir","Motor nöron akson terminallerinden asetilkolin salınımını artırır"],"correct":1,"exp":"Myastenia gravis, nöromüsküler kavşaktaki nikotinik asetilkolin reseptörlerine (AChR) karşı gelişen otoantikorların reseptör sayısını azaltmasıyla ortaya çıkar. Piridostigmin, asetilkolinesteraz enzimini geri dönüşümlü olarak inhibe ederek sinaptik yarıktaki asetilkolin yıkımını yavaşlatır; bu sayede azalmış reseptörlerle etkileşim süresi ve olasılığı artar. Edrofonyum testi de aynı mekanizmayla kısa süreli düzelme sağlar ve tanıyı destekler. Piridostigmin doğrudan reseptör agonisti değildir; Ca²⁺ kanalları veya sempatik sistem üzerinden etki etmez."},{"id":10010,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Araştırmacılar, periferik sinir hasarı sonrası miyelin kılıfının yeniden oluşumunu inceliyor. Wallerian dejenerasyonun ardından aksonal rejenerasyonun yönlendirilmesinde görev yapan, bazal lamina tüpünü koruyan ve miyelinasyonu yeniden başlatan hücreyle ilgili aşağıdaki öncüller değerlendirilsin:\nI. Bu hücreler Schwann hücresi olup santral sinir sisteminde miyelin oluşturan hücrelerden embriyolojik köken itibarıyla farklıdır.\nII. Tek bir Schwann hücresi birden fazla aksonu miyelinleyebilir.\nIII. Wallerian dejenerasyon sırasında Schwann hücreleri miyelini fagosite eder ve büyüme faktörleri salgılayarak rejenerasyonu destekler.\nIV. Santral sinir sisteminde miyelinasyonu oligodendrositler sağlar ve her biri yalnızca tek bir aksonu miyelinler.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["1","2","3","4","Hiçbiri"],"correct":1,"exp":"Öncül I doğrudur: Schwann hücreleri nöral krest kökenlidir, oligodendrositler ise nöral tüp kökenlidir. Öncül II yanlıştır: Tek bir Schwann hücresi yalnızca tek bir aksonu miyelinler; birden fazla aksonu miyelinleyen hücreler oligodendrositlerdir (her oligodendrosit 15-30 aksona kadar miyelinleyebilir). Öncül III doğrudur: Wallerian dejenerasyonda Schwann hücreleri hasarlı miyelin artıklarını fagosite ederek temizler, nörotrofik faktörler (NGF, BDNF) ve adezyon molekülleri salgılayarak akson rejenerasyonuna rehberlik eder. Öncül IV yanlıştır: Bir oligodendrosit birden fazla aksonu miyelinler. Dolayısıyla 2 öncül doğrudur."},{"id":10011,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"52 yaşında kadın hasta, eforla gelen göğüs ağrısı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Yapılan koroner anjiyografide sol ön inen arterde %80 darlık saptanıyor. İskemi süreci sırasında kardiyomiyositlerde gerçekleşen hücresel değişikliklerle ilgili aşağıdaki öncüller değerlendirilsin:\nI. Kardiyomiyositler terminal diferansiye hücreler olduğundan iskemik kayıptan sonra hipertrofi yerine hiperplazi ile yanıt verir.\nII. İskemik bölgede ATP yetersizliği nedeniyle Na⁺/K⁺-ATPaz aktivitesi azalır, hücre içi Na⁺ birikimi gerçekleşir.\nIII. Hücre içi Na⁺ artışı, Na⁺/Ca²⁺ değiştiricisinin ters çalışmasına yol açarak sitoplazmik Ca²⁺ yüklenmesine neden olur.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","Yalnız II","II ve III","I ve III","I, II ve III"],"correct":2,"exp":"Öncül I yanlıştır: Kardiyomiyositler postnatal dönemde hücre döngüsünden çıkmış, terminal diferansiye hücrelerdir. İskemik kayba yanıt olarak hiperplazi değil, hayatta kalan kardiyomiyositlerde kompansatuvar hipertrofi gelişir. Öncül II doğrudur: İskemide ATP sentezi bozulunca Na⁺/K⁺-ATPaz yeterince çalışamaz, hücre içinde Na⁺ birikir. Öncül III doğrudur: Artan hücre içi Na⁺, normalde Na⁺'ı içeri Ca²⁺'ı dışarı atan Na⁺/Ca²⁺ değiştiricisinin (NCX) ters modda çalışmasına neden olur; Ca²⁺ hücre içinde birikir ve kontraktür ile mitokondriyal disfonksiyona zemin hazırlar."},{"id":10012,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"34 yaşında erkek hasta, seyahat dönüşü gelişen yüksek ateş, titreme ve yan ağrısı yakınmalarıyla acil servise başvuruyor. Tam idrar tahlilinde lökositüri ve nitrit pozitifliği, ultrasonografide sağ böbrekte hafif pelvis genişlemesi saptanıyor. Pyelonefrit tanısıyla tedaviye başlanıyor. Bu klinik tabloda bakterilerin en sık tırmandığı güzergah ve ilk hasara uğrayan nefronal yapı sırasıyla hangisidir?","options":["Hematojen yol - glomerül","Assendan yol - toplayıcı kanal ve pelvis epitel hücreleri","Assendan yol - proksimal tübül","Lenfatik yol - Henle kulpu","Hematojen yol - distal tübül"],"correct":1,"exp":"Pyelonefritin büyük çoğunluğu assendan (retrograd) yolla gelişir: üretra → mesane → üreter → renal pelvis → toplayıcı kanal sistemi. İlk hasara uğrayan yapılar renal pelvis transizyonel epiteli ve toplayıcı kanal epitelidir. Üropatojen E. coli gibi bakteriler P fimbriaları aracılığıyla bu hücrelerin yüzeyine tutunur. Hematojen yol stafilokokal bakteriyemide görülür ve kortekste glomerül çevresini tutar; ancak çok daha nadir bir mekanizmadır. Lenfatik yayılım klinik pratikte anlamlı bir rol oynamaz."},{"id":10013,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Periferik yayma incelemesinde ortalama eritrosit hacmi (MCV) 110 fL, hipersegmente nötrofiller ve oval makrositler saptanan bir hastada serum B12 düzeyi düşük, folik asit düzeyi normal bulunuyor. Bu hastada megaloblastik anemi gelişiminin temel nedeni aşağıdakilerden hangisidir?","options":["Hem sentezinde demir eksikliği nedeniyle yetersiz hemoglobin üretimi","Timidilat sentezinin bozulması sonucu DNA replikasyonunun yavaşlaması","Globin gen mutasyonu nedeniyle anormal hemoglobin yapısı oluşması","Eritropoetin düzeyinin düşüklüğü nedeniyle eritroid öncül hücre proliferasyonunun azalması","Dalakta eritrosit yıkımının artması sonucu kompansatuvar makrositoz gelişmesi"],"correct":1,"exp":"B12 vitamini, metilmalonil-CoA mutaz ve metiyonin sentaz reaksiyonlarında kofaktör olarak görev yapar. Metiyonin sentaz, homosisteini metiyonine dönüştürürken N5-metiltetrahidrofolat'ı tetrahidrofolat'a çevirir. B12 eksikliğinde bu dönüşüm gerçekleşemez; serbest tetrahidrofolat azalır ve timidilat sentezi için gerekli N5,N10-metilentehidrofolat yetersiz kalır. Timidilat sentezinin bozulması, dTMP üretimini azaltır ve DNA replikasyonu yavaşlar. Hücreler bölünmeden büyümeye devam ettiğinden makrosit (oval makrosit) oluşur ve hipersegmente nötrofiller görülür. Bu tablo demir eksikliği, globin mutasyonu veya eritropoetin yetersizliğiyle açıklanamaz."},{"id":10014,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, doğumdan itibaren süregelen tekrarlayan bronşit atakları, bronşiektazi ve situs inversus totalis ön tanısıyla tetkik ediliyor. Nazal nitrik oksit ölçümü belirgin düşük saptanıyor. Elektron mikroskopik incelemede siliyaların iç dynein kol yapısında yokluk görülüyor. Bu hastanın siliyar disfonksiyonuna bağlı gelişen klinik tabloda, solunum yollarında goblet hücreleri ve submuköz bezlerin normal işlev gördüğü varsayılırsa, beklenen birincil patofizyolojik sonuç aşağıdakilerden hangisidir?","options":["Sürfaktan eksikliğine bağlı alveoler kollaps","Mukosiliyer klirensin bozulması sonucu sekresyon birikimi ve tekrarlayan enfeksiyonlar","Hipoksik vazokonstriksiyon nedeniyle pulmoner hipertansiyon gelişimi","Alveoler makrofaj aktivasyonunun artması sonucu granülomatöz inflamasyon","IgA sekresyonunun azalması nedeniyle mukozal immün yetersizlik"],"correct":1,"exp":"Tanımlanan tablo Primer Silier Diskinezi'dir (Kartagener sendromu: bronşiektazi + situs inversus + sinüzit üçlüsü). İç dynein kolu, siliyanın 9+2 aksonem yapısında çiftler arası kayma hareketi için gerekli ATPaz motorunu sağlar; bu kolun yokluğunda siliyalar vuramaz. Solunum yolu epiteli siliyaları normal mukus üretiminin üzerindeki salgıyı temizlemekle sorumludur. Siliyar hareketsizlikte mukosiliyer klirens bozulur, bakteri ve debris birikerek kronik enfeksiyon ve bronşiektaziye zemin hazırlar. Sürfaktan eksikliği tip II pnömositlerle ilgilidir ve bu tabloda söz konusu değildir. Düşük nazal NO, tanıyı destekleyen biyobelirteç olup patofizyolojinin kendisi değildir."},{"id":10015,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor sırasında belirginleşen nefes darlığı ve bacaklarda şişlik yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %30 olarak saptanıyor. Hastaya tedavi amacıyla sakubitril/valsartan başlanıyor. Bu ilacın kardiyomiyositler üzerindeki temel etkisi aşağıdakilerden hangisiyle açıklanır?","options":["Natriüretik peptid yıkımını inhibe ederek cGMP aracılı relaksasyonu artırması","Anjiyotensin II reseptörünü bloke ederek aldosteron salınımını azaltması","L-tipi kalsiyum kanallarını bloke ederek miyokard kontraktilitesini düşürmesi","Beta-1 reseptörlerini antagonize ederek sempatik uyarımı kesmesi","Fosfodiesteraz inhibisyonu yoluyla cAMP birikimini sağlaması"],"correct":0,"exp":"Sakubitril, neprilizin enzimini inhibe ederek BNP ve ANP gibi natriüretik peptidlerin yıkımını önler. Bu peptidler kardiyomiyositlerde guanilat siklazı aktive ederek cGMP düzeyini yükseltir; protein kinaz G aracılığıyla miyofilaman duyarlılığı azalır, diyastolik relaksasyon iyileşir ve preload düşer. Valsartan bileşeni ise AT1 reseptörünü bloke ederek aldosteron salınımını ve miyokard fibrozisini azaltır. Kalsiyum kanal blokajı veya beta blokaj bu ilacın mekanizması değildir."},{"id":10016,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"Bir nörobilim laboratuvarında gerçekleştirilen deneyde aksiyon potansiyeli oluşumu sırasında voltaj kapılı Na⁺ kanallarının inaktivasyonu incelenmektedir. Bu inaktivasyon mekanizmasına ilişkin aşağıdaki öncülleri değerlendiriniz.\n\nI. İnaktivasyon kapısı (h kapısı), depolarizasyonla birlikte kapanmaya başlar.\nII. İnaktivasyon sırasında kanal, dışarıdan uygulanan uyarana yanıt verebilecek durumda kalır.\nIII. Mutlak refrakter dönem, büyük ölçüde Na⁺ kanallarının inaktif konumda bulunduğu süreye karşılık gelir.\nIV. Repolarizasyon tamamlandığında h kapısı yeniden açılarak kanal dinlenme konumuna döner.\n\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["1","2","3","4","Hiçbiri"],"correct":2,"exp":"I. Doğru: h kapısı depolarizasyonla birlikte kapanmaya başlar; bu da kanalın iletimi kesmesini sağlar. II. Yanlış: İnaktif konumdaki kanal hiçbir uyarana yanıt veremez; bu durum mutlak refrakter dönemi tanımlar. III. Doğru: Mutlak refrakter dönem, Na⁺ kanallarının inaktif (hem m kapısı açık hem h kapısı kapalı) durumda olduğu süreye karşılık gelir; bu dönemde yeni bir aksiyon potansiyeli oluşturulamaz. IV. Doğru: Repolarizasyonla membran potansiyeli negatifleştikçe h kapısı yeniden açılır ve kanal dinlenme konumuna (m kapalı, h açık) döner. Doğru öncül sayısı 3'tür."},{"id":10017,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan idrar yolu enfeksiyonları nedeniyle üroloji kliniğine başvuruyor. Sistoskopide mesane duvarı inceleniyor ve geçici epitel (ürotelyal epitel) yapısı değerlendiriliyor. Mesane doluyken ürotelyal epitelin aldığı yapıya ilişkin aşağıdakilerden hangisi doğrudur?","options":["Yüzey hücreleri (şemsiye hücreleri) düzleşir ve hücreler arası sıkı bağlantılar gevşer","Epitel kalınlığı artar ve bazal hücreler kolumnar bir görünüm kazanır","Yüzey hücrelerinin apikalinde bulunan plak diskler endositozla sitoplazmaya çekilir","Epitel yüzeyi, glikoprotein yapılı uroplakin molekülleri sayesinde geçirimsizliğini korur","Ara tabakadaki hücreler çoğalarak boş mesanedeki hücre sayısını yeniden oluşturur"],"correct":3,"exp":"Ürotelyal epitel (geçici epitel), mesane boşken kalın ve katmanlı görünümdeyken dolarken incelir ve yüzey hücreleri (şemsiye/umbrella hücreleri) düzleşir. Şemsiye hücrelerin apikalindeki özelleşmiş plazma zarı, uroplakin adlı transmembran protein plaklarından oluşur ve mesane dolduğunda sitoplazmadaki fusiform veziküller bu plakları apikal zara ekleyerek yüzey alanını artırır. Boşalınca bu plaklar tekrar endositozla içeri alınır. Dolum sırasında uroplakinler zarın yüzeyinde kalır ve bariyer geçirimsizliğini sürdürür. Seçenek A kısmen doğru gibi görünse de sıkı bağlantıların 'gevşemesi' yanlıştır; geçirimsizlik korunur. Seçenek D, dolum sırasında geçirimsizliğin uroplakinler aracılığıyla korunduğunu doğru biçimde ifade ettiğinden en doğru yanıttır."},{"id":10018,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"55 yaşında erkek hasta, 6 aydır süren karın ağrısı, ishal ve kilo kaybı yakınmalarıyla gastroenteroloji polikliniğine başvuruyor. Yapılan endoskopide terminal ileumda 'taş döşemesi' görünümü ve derin fissür ülserler saptanıyor; biyopside transmural inflamasyon ve non-kazeifiye granülomlar görülüyor. Bu hastanın ince bağırsak mukozasında histolojik olarak en çok etkilenen hücre tipi ve buna bağlı gelişmesi beklenen malabsorpsiyon türü hangisidir?","options":["Goblet hücreleri — mukus eksikliğine bağlı protein malabsorpsiyonu","Enteroendokrin hücreler — GIP azalmasına bağlı karbonhidrat malabsorpsiyonu","Villusların emici (absorbtif) enterosite — yağda çözünen vitamin ve lipit malabsorpsiyonu","Paneth hücreleri — defensin eksikliğine bağlı bakteriyel kolonizasyon artışı","M hücreleri — antijen sunumunun bozulmasına bağlı sekretuar IgA eksikliği"],"correct":2,"exp":"Tanımlanan tablo Crohn hastalığıdır; terminal ileum tutulumu karakteristiktir. Terminal ileumda safra tuzlarının ve B12 vitamininin emilimi gerçekleşir; ayrıca yüzey alanını artıran villus yapısının bozulmasıyla lipit ve yağda çözünen vitaminlerin (A, D, E, K) emilimi ciddi biçimde azalır. Transmural inflamasyon ve granülom oluşumu villusların absorbtif enterositlerini ve onların mikrovilli yapılarını tahrip eder. Goblet hücreleri esas olarak mukus salgılar; Paneth hücreleri antimikrobiyal peptid üretir; bunların hasarı da tabloya katkıda bulunsa da en belirgin klinik sonuç lipit malabsorpsiyonu ve steatoredir."},{"id":10019,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 2 haftadır süren yorgunluk, soluk görünüm ve çarpıntı yakınmalarıyla başvuruyor. Tam kan sayımında hemoglobin 7,2 g/dL, MCV 112 fL, periferik yaymada hipersegmente nötrofiller saptanıyor. Serum B12 ve folat düzeyleri normal sınırda; anti-intrinsik faktör antikoru pozitif bulunuyor. Hastaya parenteral B12 (siyanokobalamin) tedavisi başlanıyor. Tedavinin 5-7. günleri arasında kemik iliğinde gerçekleşmesi beklenen yanıt aşağıdakilerden hangisidir?","options":["Megaloblastların yerini normoblastlara bırakması ve retikülosit sayısında belirgin artış","Megakaryosit sayısında azalma ve trombosit üretiminin geçici olarak durması","Progenitör hücrelerde G1 arresti ve DNA sentezi durması","Eritroid seride apoptozun artarak kemik iliği hiperplazisinin gerilemesi","Granülosit öncüllerinde dismorfik değişikliklerin derinleşmesi"],"correct":0,"exp":"Anti-intrinsik faktör antikoru pozitifliği pernisiyöz anemiyi düşündürür; B12 eksikliğine bağlı megaloblastik anemi tablosu mevcuttur. Parenteral B12 tedavisinden sonra ilk 5-7 gün içinde kemik iliğinde hızlı bir yanıt oluşur: DNA sentezi düzelir, megaloblastların olgunlaşması normale döner ve normoblastlar ön plana çıkar. En karakteristik erken laboratuvar bulgusu ise retikülosit sayısındaki belirgin artıştır (retikülosit krizi). Megakaryositler de benzer biçimde düzelir ancak kemik iliğinin erken yanıtı eritroid serideki normalizasyondur. Apoptoz artışı veya granülosit düzelmesi bu dönemin temel özelliği değildir."},{"id":10020,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":2,"q":"Tip II pnömosit hücrelerine ilişkin aşağıdaki öncülleri değerlendiriniz.\n\nI. Alveol yüzeyinin büyük bölümünü döşeyen, gaz değişiminden sorumlu asıl hücre tipidir.\nII. Osmiyumla boyanan lameller cisimcikler içerir ve sürfaktan bu cisimciklerden salgılanır.\nIII. Akciğer hasarı sonrasında Tip I pnömositlerin yerine geçebilme yeteneğine sahiptir.\nIV. Sürfaktanın temel lipid bileşeni dipalmitoyılfosfatidilkolindir (DPPC).\n\nYukarıdaki öncüllerden kaç tanesi yanlıştır?","options":["1","2","3","4","Hiçbiri"],"correct":0,"exp":"I. Yanlış: Alveol yüzeyinin %95-97'sini döşeyen ve ince yapılarıyla gaz değişimini sağlayan hücreler Tip I pnömositlerdir. Tip II pnömositler küboidal yapıda olup yüzeyin yalnızca küçük bir bölümünü kaplar. II. Doğru: Tip II pnömositler elektron mikroskobunda osmiyumla boyanan lameller cisimcikler (lamellar bodies) içerir; sürfaktan bu yapılarda depolanır ve ekzositozla alveol yüzeyine salgılanır. III. Doğru: Tip II pnömositler kök hücre işlevi görür; Tip I pnömositler hasarlandığında prolifere olup farklılaşarak onların yerini alabilir. IV. Doğru: Sürfaktanın yaklaşık %40'ını oluşturan DPPC (dipalmitoyılfosfatidilkolin), yüzey gerilimini düşüren temel fosfolipittir. Yalnızca I. öncül yanlıştır; yanlış öncül sayısı 1'dir."},{"id":10021,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"42 yaşında erkek hasta, 6 aydır giderek kötüleşen proksimal kas güçsüzlüğü ve egzersiz intoleransı yakınmasıyla başvuruyor. Fizik muayenede dil büyümesi ve kalp yetersizliği bulguları saptanıyor. Kas biyopsisinde lizozomal vakuollerde glikojen birikimi gösteriliyor. Enzim replasman tedavisi başlandıktan sonra hangi hücresel yapı fonksiyonu düzelmeye başlar?","options":["Sarkoplazmatik retikulum Ca²⁺ depo kapasitesi","Mitokondriyal oksidatif fosforilasyon verimliliği","Lizozomal asit alfa-glukozidaz aktivitesi ile otofajik akış","Miyozin ağır zincir izoform dağılımı","T-tübül membran potansiyel stabilitesi"],"correct":2,"exp":"Bu tablo Pompe hastalığı (tip II glikojenoz) ile uyumludur. Lizozomal asit alfa-glukozidaz (GAA) eksikliği nedeniyle lizozomlarda glikojen birikir ve otofajik akış bozulur. Enzim replasman tedavisi (alglukozidaz alfa) eksojen GAA sağlayarak lizozomal glikojen yıkımını yeniden başlatır; bu da otofajik vakuol birikmesini azaltır ve kas liflerinde yapısal toparlanmaya yol açar. Sarkoplazmatik retikulum, mitokondri, miyozin izoformları ve T-tübüller bu hastalığın primer etkilenme noktaları değildir."},{"id":10022,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında hipertansif erkek hasta, akut miyokard enfarktüsü sonrası 48. saatte kardiyojenik şok tablosuna giriyor. Ekokardiyografide yeni gelişen interventriküler septum rüptürü saptanıyor. Patolojik incelemede bu bölgedeki miyositlerde eozinofilik boyanma artışı, çekirdek kaybı ve çevresel nötrofil infiltrasyonu görülüyor. Bu bulgular hangi histopatolojik sürecin hangi evresini yansıtır?","options":["Koagülatif nekrozun erken evresi (6-24 saat)","Granülasyon dokusu oluşum evresi (1-2 hafta)","Fibröz skar reorganizasyon evresi (6-8 hafta)","Kollişyon nekrozu ile lizis evresi (3-7 gün)","Reversibıl iskemik hasar evresi (0-2 saat)"],"correct":0,"exp":"Miyokard enfarktüsünün 6-24. saatlerinde koagülatif nekrozun erken bulguları ortaya çıkar: miyositlerde eozinofilik (asidofilik) boyanma artışı, çekirdek kaybı (karyolizis/piknoz) ve polimorfonükleer lökosit (nötrofil) infiltrasyonunun başlaması bu evrenin klasik triadıdır. 48. saatte bu bulgular beklenen tablodur. Granülasyon dokusu 1-2. haftada, fibröz skar ise 6-8. haftada oluşur. Reversibl hasar evresi morfolojik değişiklik içermez. Lizis evresi 3-7. günde, makrofaj infiltrasyonuyla birlikte görülür."},{"id":10023,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 2 haftadır çift görme ve sol gözde ağrı yakınmasıyla başvuruyor. Muayenede internükleer oftalmopleji saptanıyor. MR görüntülemede periventriküler beyaz cevherde demiyelinizasyon plakaları izleniyor. Hastaya interferon beta-1a tedavisi başlanıyor. Aşağıdaki öncülleri değerlendirin:\nI. Bu hastalıkta primer hasar miyelin üreten Schwann hücrelerinde gerçekleşir.\nII. Remyelinizasyon kapasitesi oligodendrosit progenitör hücrelerinden kaynaklanır.\nIII. Ranvier boğumlarının korunması sodyum kanalı kümelenmesini sürdürür.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","Yalnız II","I ve III","II ve III","I, II ve III"],"correct":3,"exp":"Multipl skleroz (MS) santral sinir sistemini etkiler; SSS'de miyelin üreten hücreler oligodendrositledir, Schwann hücreleri değil (periferik sinir sistemi). Bu nedenle öncül I yanlıştır. Öncül II doğrudur: remyelinizasyon potansiyeli oligodendrosit progenitör hücrelerinden (OPC) kaynaklanır ve bu hücreler plak bölgelerine göç edebilir. Öncül III doğrudur: sağlıklı Ranvier boğumlarında Nav1.6 gibi voltaj kapılı Na⁺ kanalları yoğunlaşarak düğüm yapısını ve saltatorik iletimi sürdürür; demiyelinizasyonda bu kümelenme bozulur. Dolayısıyla yalnız II ve III doğrudur."},{"id":10024,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında diyabetik erkek hasta, 3 yıldır devam eden proteinüri nedeniyle takip edilmektedir. Son kontrolünde 24 saatlik idrarda protein 4,8 g/gün, serum albumin 2,1 g/dL olarak ölçülüyor. Böbrek biyopsisinde mezangiyal matriks artışı ve nodüler glomerüloskleroz (Kimmelstiel-Wilson nodülleri) saptanıyor. Bu hastada proteinürinin temel histolojik substratı hangisidir?","options":["Mezangiyal hücre proliferasyonuna bağlı tübüler lümen daralması","Glomerüler bazal membranda kalınlaşma ve podosit ayak çıkıntısı kaybı","Paryetal epitel hücrelerinin visseral yüzeye adezyonu","Endotel fenestrasyon sayısında artış ve tübüler reabsorbsiyon azalması","İnterstisyel fibrozise bağlı peritübüler kapiller kompresyonu"],"correct":1,"exp":"Diyabetik nefropatide proteinürinin histolojik substratı; glomerüler bazal membranın (GBM) kalınlaşması sonucu elektriksel ve boyutsal seçiciliğin bozulması ile birlikte podosit (visseral epitel hücresi) ayak çıkıntılarının (foot process) effasmanıdır. Podositler GBM'nin son filtrasyon bariyerini oluşturur; bu hücrelerin hasar görmesi makromoleküllerin, özellikle albüminin, Bowman boşluğuna geçişine izin verir. Mezangiyal nodüller (Kimmelstiel-Wilson) hastalığın morfolojik işareti olmakla birlikte, proteinürinin doğrudan sorumlusu GBM-podosit bileşeninin bütünlük kaybıdır."},{"id":10025,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"34 yaşında sigara içmeyen kadın hasta, 4 aydır giderek artan egzersiz dispnesi ve kuru öksürük yakınmasıyla başvuruyor. YRBT'de bilateral buzlu cam görünümü ve retiküler opasiteler izleniyor. Bronkoalveoler lavajda CD4/CD8 oranı 3,5 olarak saptanıyor, biyopside non-nekrotizan granülomlar görülüyor. Bu hastada alveol duvarında birikmesi beklenen hücre tipi ve bu hücrenin alveoler yüzeydeki normal fizyolojik görevi hangisidir?","options":["Tip I pnömosit; surfaktan sentezi ve sekresyonu","Nötrofil; oksidatif patlamayla mikroorganizma eliminasyonu","Tip II pnömosit; alveoler yüzeyin yenilenmesi ve surfaktan üretimi","Alveoler makrofaj; partiküllerin fagositozu ve immün gözetim","NK hücresi; sitotoksik granül salınımıyla viral klirens"],"correct":3,"exp":"Klinik tablo, radyolojik ve bronkoalveoler lavaj bulguları sarkoidoz ile uyumludur. Sarkoidozda alveoler duvarda ve interstisyumda baskın olarak aktive makrofajlar ve CD4⁺ T lenfositler birikir; bu hücrelerin granülom formasyonundaki rolü hastalığın temel patolojisidir. Alveoler makrofajlar (toz hücreleri) normalde alveol lümeninde yerleşik olup solunan partiküller, döküntü ve mikroorganizmaları fagosite ederek alveoler yüzeyin immün gözetimini sağlar. Tip II pnömositler surfaktan üretiminden sorumludur ancak sarkoidozda baskın biriken hücre değildir. Tip I pnömositler ise gaz değişimini kolaylaştırır, surfaktan üretmez."},{"id":10026,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Aşağıdaki öncülleri değerlendirin:\nI. Olgun eritrositler çekirdek ve mitokondri içermez, enerji ihtiyaçlarını yalnızca anaerobik glikolizle karşılar.\nII. Megakaryositler kemik iliğinde endomitoz yoluyla çoğalır ve sitoplazmalarından trombositler tomurcuklanarak ayrılır.\nIII. Nötrofiller dolaşımda ortalama 7-10 gün yaşar, dokularda apoptozla ölür.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","Yalnız biri","İkisi","Üçü","Değerlendirmek için ek bilgi gerekir"],"correct":2,"exp":"Öncül I doğrudur: olgun eritrositlerde çekirdek, mitokondri ve diğer organeller yoktur; ATP üretimi yalnızca Embden-Meyerhof yolu (anaerobik glikoliz) üzerinden sağlanır. Öncül II doğrudur: megakaryositler endomitoz (sitokinezis olmaksızın DNA replikasyonu) ile ploidi artırır ve sitoplazmik uzantılarından trombositler (plateletler) sinüzoid lümenine dökülerek ayrılır. Öncül III yanlıştır: nötrofiller dolaşımda yalnızca 6-12 saat kalır (bazı kaynaklara göre 1-2 gün), 7-10 gün değil. Dokulara geçtikten sonra birkaç gün içinde apoptoza uğrarlar. Dolayısıyla iki öncül (I ve II) doğrudur."},{"id":10027,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı şikayetiyle başvuruyor. Yapılan ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya başlanan sakubitril/valsartan tedavisinin etki mekanizmasına ilişkin aşağıdaki öncüller değerlendirildiğinde hangileri doğrudur?\nI. Neprilizin inhibisyonu natriüretik peptid yıkımını azaltır.\nII. AT1 reseptör blokajı preload ve afterload'u düşürür.\nIII. Natriüretik peptidlerin artışı sempatik aktivasyonu azaltır.\nIV. Neprilizin inhibisyonu anjiyotensin II düzeyini düşürür.","options":["Yalnız I ve II","I, II ve III","II, III ve IV","I, II, III ve IV","Yalnız I ve IV"],"correct":1,"exp":"Sakubitril, neprilizin enzimini inhibe ederek ANP ve BNP gibi natriüretik peptidlerin yıkımını azaltır (I doğru). Bu peptidler natriürez, vazodilatasyon ve sempatik inhibisyon sağlar (III doğru). Valsartan bileşeni AT1 reseptörlerini bloke ederek vazodilatasyon, preload ve afterload azalması sağlar (II doğru). Neprilizin inhibisyonu ise anjiyotensin II'yi doğrudan düşürmez; aksine neprilizin anjiyotensin II'yi de yıktığından inhibisyonu anjiyotensin II düzeyini artırabilir, bu nedenle kombine AT1 blokajı gerekmektedir (IV yanlış). Doğru yanıt I, II ve III'tür."},{"id":10028,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, gebeliğinin 32. haftasında preterm eylem nedeniyle hospitalize ediliyor. Fetal akciğer matürasyonu için anneye betametazon uygulanıyor. Betametazonun fetal akciğer üzerindeki etkisine ilişkin aşağıdaki öncüller değerlendirildiğinde kaç tanesi doğrudur?\nI. Tip II pnömositlerde sürfaktan sentezini artırır.\nII. Alveolar epitel geçirgenliğini kalıcı olarak artırarak sıvı temizliğini hızlandırır.\nIII. Sürfaktan bileşeni olarak fosfatidilkolin sentezini uyarır.\nIV. Fetal akciğerde beta-adrenerjik reseptör ekspresyonunu artırır.","options":["1","2","3","4","Hiçbiri"],"correct":1,"exp":"Betametazon (glukokortikoid), Tip II pnömositlerde sürfaktan sentezini ve sekresyonunu artırır (I doğru). Sürfaktanın ana fosfolipid bileşeni olan dipalmitoilfosfatidilkolinin (DPPC) sentezini uyarır (III doğru). Alveolar epitel geçirgenliğini kalıcı olarak artırmaz; aksine epitel bariyer bütünlüğünü destekler ve sodyum kanalı ekspresyonunu artırarak fetal akciğer sıvısının emilimini kolaylaştırır, bu nedenle II yanlıştır. Betametazon fetal akciğerde beta-adrenerjik reseptör ekspresyonunu artırır (IV doğru). Doğru öncül sayısı 3'tür (I, III ve IV)."},{"id":10029,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"19 yaşında erkek hasta, 2 haftadır giderek artan çift görme, yutma güçlüğü ve kol-bacak kuvvetsizliği yakınmasıyla başvuruyor. Muayenede bilateral pitozis, fasial dipleji ve arefleksi saptanıyor. Anti-GQ1b antikoru pozitif bulunuyor. Bu hastada etkilenen yapı ve beklenen elektrofizyolojik bulgu hangisidir?","options":["Nöromüsküler kavşak - tekrarlayan sinir uyarımında azalan yanıt","Miyelin kılıfı - motor sinir iletim hızında belirgin yavaşlama","Ranvier boğumları - aksiyon potansiyeli amplitüdünde artış","Presinaptik terminal - tekrarlayan uyarımda artan yanıt","Schwann hücresi - F dalgası latansında kısalma"],"correct":1,"exp":"Anti-GQ1b antikoru, özellikle oküler sinirlerde (III., IV., VI. kranyal sinirler) ve Ranvier boğumlarında yoğun bulunan GQ1b gangliozidine karşı gelişir. Bu tablo Miller-Fisher sendromunu (oftalmopleji, ataksi, arefleksi) veya üst üste binen Guillain-Barré spektrumunu düşündürür. Patoloji miyelin kılıfındadır (demiyelinizan nöropati) ve bu nedenle sinir iletim çalışmalarında motor iletim hızında belirgin yavaşlama, distal latansta uzama ve F dalgası latansında uzama beklenir. Nöromüsküler kavşak hastalığı (miyasteni, Lambert-Eaton) bu tablo ile uyuşmaz; presinaptik terminal tutulumu Lambert-Eaton sendromuna özgüdür ve tekrarlayan uyarımda artan yanıt görülür."},{"id":10030,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbreğin hangi bölümünde aquaporin-2 kanalları ağırlıklı olarak eksprese edilir ve bu kanallar hangi hormonun etkisiyle luminal membrana taşınır?","options":["Proksimal tübül - aldosteron","Henle kulpunun ince inen kolu - ADH","Toplayıcı kanal - ADH","Distal tübül - aldosteron","Toplayıcı kanal - aldosteron"],"correct":2,"exp":"Aquaporin-2 (AQP2), böbreğin toplayıcı kanallarındaki Tip A interkalat hücreler dışında kalan baş hücrelerinde (principal cell) eksprese edilir. İstirahat halinde AQP2 intrasellüler veziküllerde depolanır. Antidiüretik hormon (ADH/vazopressin), V2 reseptörüne bağlanarak cAMP-PKA yolağını aktive eder ve AQP2 içeren veziküllerin luminal membranla füzyonunu sağlar; böylece su geçirgenliği artar. Aldosteron ise toplayıcı kanallarda ENaC kanallarını artırarak sodyum geri emilimini düzenler, aquaporin taşınmasıyla doğrudan ilişkisi yoktur."},{"id":10031,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"55 yaşında erkek hasta, rutin tetkiklerinde hemoglobin 18,5 g/dL, hematokrit %57, trombosit 650.000/mm³ ve lökosit 13.000/mm³ saptanıyor. Hastanın JAK2 V617F mutasyonu pozitif olduğu bildiriliyor. Bu hastada JAK2 mutasyonunun eritroid öncüllerindeki birincil etkisi aşağıdakilerden hangisidir?","options":["EPO reseptörünün downregülasyonuna yol açar","EPO bağımsız JAK-STAT yolağı aktivasyonu ile eritroid proliferasyonu artırır","Hemoglobin sentezinde demir kullanımını artırarak polisitemi oluşturur","Megakaryosit farklılaşmasını baskılayarak trombositozu engeller","Eritroid öncüllerinde apoptoz artışına neden olarak kırmızı küre ömrünü kısaltır"],"correct":1,"exp":"JAK2 V617F mutasyonu, Janus kinaz 2 enziminde kalıcı aktivasyona neden olan bir kazanılmış somatik mutasyondur. Normalde EPO, EPO reseptörüne bağlanarak JAK2'yi aktive eder ve STAT5 aracılığıyla eritroid proliferasyon ve farklılaşması gerçekleşir. JAK2 V617F mutasyonu varlığında JAK2, EPO bağlanması olmaksızın sürekli aktif hale gelir; bu durum EPO bağımsız eritroid kolonilerin oluşmasına ve polisitemia vera gibi miyeloproliferatif neoplazilere zemin hazırlar. Aynı mutasyon megakaryosit ve granülosit serilerinde de aktivasyona yol açarak trombositoz ve lökositoza neden olur."},{"id":10032,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında kadın hasta, 6 aydır süren iştahsızlık, kilo kaybı ve epigastrik ağrı yakınmasıyla başvuruyor. Üst gastrointestinal endoskopide mide antrumunda ülseröz lezyon saptanıyor ve biyopsi 'difüz tip mide adenokarsinomu' olarak raporlanıyor. Difüz tip mide adenokarsinomuna ilişkin aşağıdaki öncüller değerlendirildiğinde hangileri doğrudur?\nI. E-kaderin (CDH1) fonksiyon kaybı difüz tip karsinomla ilişkilidir.\nII. Taşlı yüzük hücreleri müsin dolu vakuollerle nükleusu perifere iter.\nIII. Linitis plastika tablosu difüz tip için değil intestinal tip için karakteristiktir.\nIV. H. pylori enfeksiyonu difüz tip için intestinal tipten daha güçlü bir risk faktörüdür.","options":["Yalnız I ve II","I, II ve III","I, II ve IV","II, III ve IV","I, II, III ve IV"],"correct":0,"exp":"E-kaderin (CDH1 geni), hücre-hücre adezyonunu sağlayan bir transmembran glikoproteindir. CDH1 mutasyonu veya promotor metilasyonu ile kaybı, hücrelerin bağlantısız şekilde infiltre büyümesine neden olur ve difüz tip mide karsinomuyla güçlü ilişkilidir (I doğru). Taşlı yüzük hücreleri, hücre içinde biriken müsin vakuollerinin nükleusu periferiye itmesiyle tanımlanır ve difüz tip karsinomun histolojik alt tipidir (II doğru). Linitis plastika (deri matarası mide), tüm mide duvarına yayılan desmoplastik reaksiyon sonucu mide duvarının sertleşmesidir ve difüz tip karsinomu için karakteristiktir, intestinal tip için değil (III yanlış). H. pylori her iki tip için de risk faktörüdür, ancak intestinal tip ile ilişkisi daha güçlüdür; kronik atrofi-intestinal metaplazi-displazi-intestinal tip karsinom sekansı H. pylori'ye bağlı klasik yoldur, difüz tip daha çok genetik (CDH1) faktörlerle ilişkilidir (IV yanlış). Doğru yanıt yalnız I ve II'dir."},{"id":10033,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır devam eden proksimal kas güçsüzlüğü ve efor dispnesi yakınmasıyla başvuruyor. Özgeçmişinde tip 2 diyabet ve hiperlipidemi mevcut. Nörolojik muayenede derin tendon refleksleri normoaktif, his kusuru yok. EMG'de miyopatik patern saptanıyor. Karaciğer enzimleri normal, CK düzeyi 4.200 U/L. Kas biyopsisinde tip II kas lifi atrofisi ve mitokondriyal dejenerasyon izleniyor. Hastanın başvurusundan 2 yıl önce başlanan bir ilaca bağlı bu tablonun geliştiği düşünüldüğünde, söz konusu ilacın hangi mekanizma üzerinden bu patolojiye yol açtığı düşünülmektedir?","options":["Koenzim Q10 sentezinin inhibisyonu yoluyla mitokondriyal solunum zinciri bozulması","Miyozin ağır zincir gen ekspresyonunun baskılanması","Nöromüsküler kavşakta asetilkolin salınımının azalması","Kas hücrelerinde L-tipi kalsiyum kanallarının blokajı","Sarkoplazma retikulumundan kalsiyum salınımının artması"],"correct":0,"exp":"Statinler, HMG-CoA redüktaz inhibisyonu yoluyla mevalonat yolağını baskılar. Bu yolak yalnızca kolesterol değil, koenzim Q10 (ubiquinon) sentezi için de zorunludur. Mitokondriyal iç membranda elektron taşıyıcısı olan CoQ10'un azalması, oksidatif fosforilasyonu bozar ve kas liflerinde enerji açığına yol açar. Tip II lifler oksidatif kapasiteleri daha düşük olduğundan bu tabloya daha duyarlıdır. Klinik tabloda normal refleksler ve his kusuru yokluğu miyopatik niteliği destekler; yüksek CK ve biyopside mitokondriyal dejenerasyon statin miyopatisiyle uyumludur."},{"id":10034,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"68 yaşında kadın hasta, ani başlayan nefes darlığı ve bacaklarda ödem yakınmasıyla acile başvuruyor. Özgeçmişinde hipertansiyon ve atriyal fibrilasyon mevcut; warfarin ve metoprolol kullanıyor. Fizik muayenede ral ve S3 gallop saptanıyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30, sol atriyal basınç artışı mevcut. Hastaya furosemid başlandıktan sonra semptomların geçici olarak düzeldiği, ancak birkaç gün içinde idrar çıkışının belirgin azaldığı gözlemleniyor. Serum kreatinin 2,8 mg/dL'ye yükseliyor. Bu hastada furosemid sonrası böbrek fonksiyonlarının kötüleşmesinden sorumlu olan fizyopatolojik süreçte hangi mekanizma belirleyici rol oynamaktadır?","options":["Afferent arteriyol vazodilatasyonuna bağlı glomerüler filtrasyon artışı","Kardiyak debinin düşmesiyle birlikte renal perfüzyonun azalması ve renin-anjiyotensin-aldosteron sisteminin aktivasyonu","Furosemidin direkt tübüler toksik etkisiyle proksimal tübül hasarı","Sistemik venöz konjesyona bağlı renal venöz basınç artışının tek başına belirleyici olması","Antidiüretik hormon salınımının baskılanmasına bağlı dilüsyonel hiponatremi"],"correct":1,"exp":"Düşük ejeksiyon fraksiyonlu kalp yetersizliğinde furosemid ile aşırı diürez, efektif dolaşım hacmini azaltarak kardiyak debiyi daha da düşürür. Renal perfüzyonun azalması, jukstaglomerüler apardan renin salınımını uyarır; anjiyotensin II hem efferent arteriyolü daraltır hem de aldosteron üretimini artırır. Efferent konstrüksiyon başlangıçta GFR'yi korumaya çalışsa da yetersiz perfüzyon durumunda GFR kaçınılmaz olarak düşer. Bu kardiyorenal sendrom tip 1 tablosudur. Furosemidin tübüler toksisitesi yüksek doz kullanımında görülür ve bu tablonun açıklaması değildir; venöz konjesyon da katkıda bulunabilir ancak tek başına belirleyici değildir."},{"id":10035,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, 2 haftadır süren çift görme, 1 haftadır devam eden sağ el ve kolda uyuşma yakınmasıyla başvuruyor. Özgeçmişinde 3 yıl önce geçici görme kaybı atağı tanımlanmış; o dönemde herhangi bir araştırma yapılmamış. Nörolojik muayenede internükleer oftalmopleji ve sağ üst ekstremitede vibrasyon hissi azalması saptanıyor. MRG'de periventriküler beyaz cevherde T2/FLAIR'de hiperintens plaklar izleniyor. Beyin omurilik sıvısı incelemesinde oligoklonal bant pozitif, IgG indeksi yüksek. Hastaya yüksek doz metilprednizolon başlanıyor. Aşağıdaki öncüllerden kaç tanesi bu hastanın patolojisiyle ilgili olarak doğrudur?\nI. Akson çevresindeki miyelin kılıfı oligodendrosit hücreleri tarafından oluşturulmaktadır.\nII. Ranvier boğumları arasındaki mesafenin kısalması iletim hızını artırır.\nIII. Sodyum kanalları normal miyelinli sinirde Ranvier boğumlarında yoğunlaşmıştır.\nIV. Demiyelinizan plak bölgesinde saltatory iletim yerini sürekli iletimine bırakır.","options":["Yalnız 1 tanesi","2 tanesi","3 tanesi","4 tanesi","Hiçbiri"],"correct":2,"exp":"Öncül I doğrudur: MSS'de miyelin oligodendrosit tarafından yapılır (PNS'de Schwann hücresi). Öncül II yanlıştır: Ranvier boğumları arasındaki mesafenin artması iletim hızını artırır; mesafe kısaldıkça saltatory iletim yavaşlar. Öncül III doğrudur: Voltaj kapılı Na+ kanalları Ranvier boğumlarında yoğunlaşmıştır, bu yapı saltatory iletimi sağlar. Öncül IV doğrudur: Miyelin kaybıyla Ranvier boğumlarındaki Na+ kanal yoğunluğu çevre membranda dilüe olur, saltatory iletim bozulur ve yavaş, enerji açısından verimsiz sürekli iletim devreye girer. Doğru öncüller I, III ve IV olmak üzere 3 tanesidir. Metilprednizolon akut alevlenmelerde kan-beyin bariyeri geçirgenliğini azaltarak semptomları kısaltır ancak hastalığı modifiye etmez."},{"id":10036,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbrekte proksimal tübülde gerçekleşen glukoz geri emilimi ile ilgili aşağıdaki ifadelerden hangisi doğrudur?","options":["Glukoz, apikal membrandan GLUT2 taşıyıcısı aracılığıyla sekonder aktif taşımayla alınır.","Bazolateral membrandan intersitisyuma geçiş SGLT1 aracılığıyla gerçekleşir.","Apikal membrandan glukoz alımı Na+ gradyanına bağımlı SGLT2 ile sağlanır; Na+ ise bazolateral Na+/K+-ATPaz ile hücreden uzaklaştırılır.","Glukoz geri emilimi proksimal tübülün ince segmentinde gerçekleşir.","Plazma glukoz düzeyi 80 mg/dL'yi aştığında taşıma maksimumu aşılır ve glukozüri başlar."],"correct":2,"exp":"Proksimal tübülün erken segmentinde (S1-S2) SGLT2, geç segmentinde (S3) SGLT1, apikal membranda Na+ ile kotransport yaparak glukoz alımını sağlar. Bu sekonder aktif taşıma, Na+ gradyanını kullanan bir mekanizmadır; Na+ gradyanı ise bazolateral membranda sürekli çalışan Na+/K+-ATPaz tarafından korunur. Hücreden intersitisyuma glukoz çıkışı bazolateral membranda GLUT2 (erken segment) ve GLUT1 (geç segment) ile gerçekleşir. Renal taşıma maksimumu (Tm) yaklaşık 180-200 mg/dL plazma glukozunda aşılır, bu eşiğin altında normalde glukozüri görülmez. SGLT2 inhibitörleri (örn. empagliflozin) bu mekanizmayı baskılayarak terapötik glukozüri oluşturur."},{"id":10037,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"28 yaşında kadın hasta, 3 aydır süren yorgunluk ve çarpıntı yakınmasıyla başvuruyor. Son 1 yıldır bol ve uzun süren adet kanamaları tanımlıyor. Fizik muayenede konjonktivalar soluk, tırnaklarda koilonichia saptanıyor. Tam kan sayımında Hb: 8,2 g/dL, MCV: 68 fL, MCH: 21 pg, RDW: %18,4, trombosit: 520.000/µL. Demir parametrelerinde serum demiri düşük, TDBK yüksek, ferritin 4 ng/mL. Hastaya oral demir tedavisi başlanıyor. Tedavinin etkinliğini değerlendirmede hangi parametre en erken ve en duyarlı bulguyu verir?","options":["Serum ferritin düzeyinin normale dönmesi","Periferik yaymada target hücre sayısının azalması","Retikülosit sayısında artış (retikülosit krizi)","Hemoglobin düzeyinin 2 g/dL artması","MCV'nin normale dönmesi"],"correct":2,"exp":"Demir eksikliği anemisinde oral demir tedavisine yanıt sırası şu şekildedir: ilk 1-3 günde kemik iliği hiperplazisi, 4-7. günlerde retikülosit sayısında belirgin artış (retikülosit krizi), 2-4. haftalarda hemoglobin yükselmeye başlar, 1-3 ayda Hb normale döner, ferritin depolarının dolması ise 3-6 ayı bulabilir. Retikülosit artışı, kemik iliğinin demir yanıtını en hızlı ve en duyarlı biçimde yansıtır; erken tedavi izleminde bu parametre kullanılır. MCV ve ferritin normalleşmesi geç dönem göstergesidir; ferritin depolar dolmadan normale dönmez."},{"id":10038,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"32 yaşında erkek hasta, yorgunluk ve kas güçsüzlüğü nedeniyle başvuruyor. Yapılan tetkiklerinde serum kreatinin kinaz düzeyi yüksek bulunuyor. Elektromiyografi incelemesinde myopatik patern saptanıyor. Kas biyopsisinde tip II kas liflerinde seçici atrofi izleniyor. Bu hastada hangi motor ünite özelliği ön planda etkilenmiştir?\nI. Yüksek eşikli motor üniteler\nII. Glikolitik metabolizma ağırlıklı lifler\nIII. Yavaş yorulan (S tipi) motor üniteler\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","Yalnız III","I ve II","II ve III","I, II ve III"],"correct":2,"exp":"Tip II kas lifleri (hızlı kasılan lifler), yüksek eşikli motor üniteler tarafından innerve edilir ve glikolitik metabolizma ağırlıklıdır. Bu nedenle öncül I ve II doğrudur. Öncül III yanlıştır; yavaş yorulan (S tipi) motor üniteler tip I kas liflerini innerve eder ve oksidatif metabolizma kullanır. Tip I lifler düşük eşikli, aerobik, yorulmaya dirençli liflerdir."},{"id":10039,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, efor dispnesi ve bacaklarda ödem yakınmasıyla kardiyoloji polikliniğine başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya kardiyak glikozid tedavisi başlanıyor. Bu ilacın kardiyomiyositler üzerindeki etkisine bağlı olarak aşağıdaki hücresel değişikliklerden hangisi beklenir?","options":["Sarkoplazma retikülumundan kalsiyum salınımının azalması","Hücre içi sodyum konsantrasyonunun yükselmesine bağlı Na/Ca değiştiricisinin ters yönde çalışması","L-tipi kalsiyum kanallarının doğrudan aktivasyonu","Troponin I fosforilasyonunun artması","cAMP bağımlı protein kinaz A aktivasyonunun artması"],"correct":1,"exp":"Kardiyak glikozidler (digoksin), sarkolemmal Na/K-ATPaz pompasını inhibe eder. Bunun sonucunda hücre içi Na+ birikir. Yükselen intrasellüler Na+, Na+/Ca2+ değiştiricisinin (NCX) ters yönde çalışmasına neden olur; dışarı Na+ veremediğinden Ca2+ da atılamaz ve hücre içinde birikir. Artan intrasellüler Ca2+, kontraktil kuvveti artırır. Diğer seçenekler kardiyak glikozid mekanizmasıyla uyuşmamaktadır."},{"id":10040,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"Yenidoğan yoğun bakım ünitesinde 28. gestasyonel haftada doğan bir prematüre bebekte doğumdan birkaç saat sonra hızlı solunum, inleme, burun kanadı solunumu ve göğüste çekilme gözlemleniyor. Kan gazı analizinde hipoksemi ve hiperkapni saptanıyor. Bu tabloya yol açan patolojinin temelinde hangi hücresel yetersizlik yatmaktadır?","options":["Tip I pnömositlerde gaz difüzyonunun bozulması","Tip II pnömositlerden sürfaktan sekresyonunun yetersizliği","Clara hücrelerinden glikoprotein üretiminin azalması","Küboid bronşiolar epitel hücrelerinin diferansiyasyon defekti","Alveoler makrofajlarda fagositoz kapasitesinin azalması"],"correct":1,"exp":"Prematüre bebeklerde respiratuar distres sendromu (RDS, hyalen membran hastalığı), 34. gebelik haftasından önce tip II pnömositlerin (tip II alveoler epitel hücreleri) henüz yeterli maturasyona ulaşamaması nedeniyle sürfaktan sentez ve sekresyonunun yetersiz olmasından kaynaklanır. Sürfaktan, yüzey gerilimini azaltarak alveollerin ekspirasyonda kollabe olmasını önler. Yetersizliğinde alveoller her solunumda çöker, kompliyans düşer ve ağır solunum yetmezliği gelişir. Tedavide eksojen sürfaktan replasmanı ve gerektiğinde antenatal kortikosteroid uygulaması kullanılır."},{"id":10041,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"45 yaşında kadın hasta, rutin kontrol sırasında hipertansiyon saptanması üzerine ileri tetkik için nefroloji servisine yönlendiriliyor. İdrar analizi, serum elektrolitleri ve böbrek fonksiyon testleri normal bulunuyor. Renal ultrasonografi ve anjiografide sol renal arterde belirgin darlık görülüyor. Darlığa bağlı olarak jukstaglomerüler aparatta gerçekleşen adaptasyon sonucunda hangi değişiklik beklenir?","options":["Mezangial hücrelerden prostasiklin salınımının azalması","Maküla densa hücrelerinde Na+ algılamasının artması","Jukstaglomerüler hücrelerden renin sekresyonunun artması","Efferent arteriol vazodilatasyonu ile GFR'nin korunması","Podositlerden nefrin ekspresyonunun upregülasyonu"],"correct":2,"exp":"Renal arter darlığı, afferent arteriyol basıncını düşürür. Bu durum jukstaglomerüler (JG) hücrelerin gerim reseptörleri aracılığıyla algılanır ve granüler JG hücrelerinden renin sekresyonu artar. Ayrıca maküla densa, düşük tübüler NaCl akışını algılayarak renin salınımını uyarır. Artan renin, anjiyotensin II ve aldosteron üretimini artırarak kanda sekonder hipertansiyona yol açar; bu tablo renovasküler hipertansiyonun klasik fizyopatolojisidir."},{"id":10042,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Akson terminal bölgesinde veziküler asetilkolin taşıyıcısı (VAChT) işlevi tamamen bozulmuş bir nöronda aşağıdaki değişikliklerden hangisi beklenir?","options":["Nikotinik reseptörlerin duyarsızlaşması artar","Asetilkolin sitoplazmadan veziküllere aktarılamaz","Kolin asetiltransferaz aktivitesi yükselir","Presinaptik voltaj kapılı Ca2+ kanalları açılamaz","Sinaptik yarıkta asetilkolinesteraz aktivitesi azalır"],"correct":1,"exp":"Veziküler asetilkolin taşıyıcısı (VAChT), sitozolde sentezlenen asetilkolini sinaptik veziküllere taşır. Bu taşıyıcı işlev görmediğinde asetilkolin vezikül içine alınamaz ve egzositoz yoluyla sinaptik yarığa salınamaz, dolayısıyla kolinerjik nörotransmisyon bozulur. Kolin asetiltransferaz (ChAT) asetilkolin sentezinden sorumludur ve VAChT işlev kaybından etkilenmez. Presinaptik Ca2+ kanalları, nikotinik reseptörler ve asetilkolinesteraz da bu patolojiden doğrudan etkilenmez."},{"id":10043,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında erkek hasta, 6 aydır süren steatore, kilo kaybı ve karın ağrısı yakınmalarıyla gastroenteroloji polikliniğine başvuruyor. Dışkı yağ analizi pozitif, serum elastaz-1 düzeyi düşük bulunuyor. Endoskopik ultrasonografide pankreas parenkiminde ekojenite artışı ve irregüler ana pankreas kanalı izleniyor. Kronik pankreatit tanısı konulan bu hastada malabsorbsiyonun temel nedeniyle doğrudan ilişkili olan hücre tipi aşağıdakilerden hangisidir?","options":["Pankreas adacık B hücreleri","Paneth hücreleri","Pankreas asiner hücreleri","Brunner bezi hücreleri","İntrinsik faktör salgılayan parietal hücreler"],"correct":2,"exp":"Kronik pankreatitte pankreas ekzokrin parenkimi tahrip olur; bu parenkimin fonksiyonel birimi asiner hücrelerdir. Asiner hücreler, lipaz, amilaz, proteazlar (tripsinojen, kimotripsinojen) gibi sindirim enzimlerini sentezleyip salgılar. Bu hücrelerin kaybı ve fibrozis sonucunda özellikle lipaz yetersizliğine bağlı yağ malabsorbsiyonu (steatore) gelişir. Paneth hücreleri antimikrobiyal peptit salgılar, Brunner bezleri alkali müküs salgılar, parietal hücreler HCl ve intrinsik faktör salgılar; bunların hiçbiri bu tablonun primer nedeni değildir."},{"id":10044,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, efor dispnesi ve bacaklarda ödem yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya tedavi başlanıyor ve kontrol muayenelerinde semptomların belirgin düzeldiği görülüyor. Bu hastanın tedavisinde kullanılan ilaçlardan biri, kardiyak miyositlerdeki Na⁺/K⁺-ATPaz pompasını inhibe etmekte ve bu sayede hücre içi Na⁺ artışına yol açmaktadır. Bu ilacın kullanımında aşağıdaki durumların hangisinde kontrendikasyon veya ciddi dikkat gerektiren bir risk söz konusudur?","options":["Hipertansiyon","Hiperkalemi","Hiponatremi","Atriyal fibrilasyon","Diyabetes mellitus"],"correct":1,"exp":"Soru, dijital glikozitler (digoksin) üzerinden Na⁺/K⁺-ATPaz inhibisyonunu klinik bir senaryoya yediriyor. Digoksin, Na⁺/K⁺-ATPaz'ı inhibe ederek hücre içi Na⁺'ı artırır; bu da Na⁺/Ca²⁺ değiştiricisi (NCX) üzerinden hücre içi Ca²⁺ birikimini sağlar ve pozitif inotropik etki oluşturur. Hiperkalemi, Na⁺/K⁺-ATPaz üzerindeki K⁺ bağlanma bölgesiyle doğrudan ilişkilidir: plazma K⁺ düzeyi yüksek olduğunda digoksinin bu pompadaki etkisi azalır; ancak hipopotasemi digoksin toksisitesini dramatik biçimde artırır. Hiperkalemi durumunda ise digoksin ile K⁺ arasındaki kompetitif etkileşim değişir ve kardiyak aritmiler için ciddi zemin oluşur. Özellikle böbrek yetmezliğiyle birlikte olan hiperkalemi, digoksin toksisitesini hızlandırır. Atriyal fibrilasyon zaten digoksinin kullanım endikasyonlarından biridir; hipertansiyon, hiponatremi ve diyabet doğrudan kontrendikasyon değildir."},{"id":10045,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"42 yaşında kadın hasta, sigara içmeme öyküsüne karşın ilerleyici nefes darlığı ve tekrarlayan pnömotoraks atakları nedeniyle araştırılıyor. Yüksek çözünürlüklü bilgisayarlı tomografide her iki akciğerde diffüz ince duvarlı kistik lezyonlar saptanıyor. Akciğer biyopsisinde anormal düz kas benzeri hücre proliferasyonu gösteriliyor. Aşağıdaki öncülleri değerlendirin:\nI. Bu hastalıkta sorumlu hücreler, nöral krest kökenli interstisyel hücrelerdir.\nII. Östrojen, hastalığın seyrini olumsuz etkileyebilir.\nIII. Patolojik hücreler HMB-45 ile pozitif boyanır.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","Yalnız II","I ve III","II ve III","I, II ve III"],"correct":3,"exp":"Klinik tablo lenfanjiyomyomatozis (LAM) ile uyumludur; üretici hücre proliferasyonu, obstrüktif ve kistik akciğer hastalığına yol açar. Öncül I yanlıştır: LAM'daki anormal hücreler (LAM hücreleri) düz kas hücresi ve melanosit özelliklerini bir arada taşıyan, perivaskülere epiteloid hücre (PEC) kökenli hücrelerdir; nöral krest kökeni doğru olmakla birlikte 'interstisyel hücre' tanımlaması yanıltıcıdır ve bu öncülün 'nöral krest kökenli interstisyel hücre' şeklindeki ifadesi patolojik hücre tipini doğru tanımlamamaktadır, bu nedenle yanlış kabul edilir. Öncül II doğrudur: LAM, üreme çağındaki kadınları etkiler ve östrojen hastalık seyrini kötüleştirir; gebelik sırasında ve ekzojen östrojen kullanımıyla alevlenme bildirilmiştir. Öncül III doğrudur: LAM hücreleri, melanozom ilişkili antijen HMB-45 (gp100) ile karakteristik olarak pozitif boyanır ve bu, tanıyı destekleyen önemli immünohistokimyasal bulgudur. Dolayısıyla II ve III doğrudur."},{"id":10046,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, diyabet ve hipertansiyon öyküsüyle izlenmekte iken son 6 ayda giderek artan ödem ve halsizlik yakınmasıyla başvuruyor. Kreatinin 3,8 mg/dL, 24 saatlik idrarda protein 4,2 g olarak ölçülüyor. Renal biyopside glomerüler bazal membranda yaygın kalınlaşma ve mezengial matriks artışı saptanıyor. Hastanın hastalığının ilerlemesinden primer olarak sorumlu tutulan yapısal değişiklik, glomerüler filtrasyon bariyerinin hangi bileşeninde gerçekleşmektedir?","options":["Glomerüler endotel hücrelerinin fenestrasyon kaybı","Podosit ayak çıkıntılarının silinmesi","Bazal membranda tip IV kollajen ve laminin birikimi","Mezengial hücrelerin apoptozu","Parietal epitel hücrelerinin hipertrofisi"],"correct":2,"exp":"Diyabetik nefropatide glomerüler bazal membrandaki (GBM) tip IV kollajen ve laminin birikimi, izlenen yapısal değişikliğin merkezinde yer alır. Yüksek glukoz ortamı, mezangial ve glomerüler hücrelerde artmış matriks proteini sentezini, ileri glikasyon son ürünleri (AGE) birikimini ve TGF-β aracılı fibrozisi tetikler. Bu durum GBM'yi kalınlaştırır ve şarj seçicilik bariyerini bozarak proteinüriyi artırır. Podosit ayak çıkıntısı silinmesi minimal değişiklik hastalığının karakteristik bulgusudur; endotel fenestrasyon kaybı daha geç dönem bulgusu olup primer mekanizma değildir. Mezengial hücre apoptozu ve parietal epitel hipertrofisi diyabetik nefropatinin primer mekanizmaları arasında sayılmaz."},{"id":10047,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Merkezi sinir sisteminde myelin kılıfını oluşturan hücreler ve bu hücrelerin her birinin kaç aksona kadar miyelin sağlayabildiğine ilişkin aşağıdaki bilgilerden hangisi doğrudur?","options":["Schwann hücreleri; her biri yalnızca bir akson segmentine miyelin sağlar","Oligodendrositler; her biri yalnızca bir akson segmentine miyelin sağlar","Oligodendrositler; her biri 40-50 farklı akson segmentine miyelin sağlayabilir","Mikroglia hücreleri; her biri birden fazla akson segmentine miyelin sağlar","Astrositler; her biri yalnızca bir akson segmentine miyelin sağlar"],"correct":2,"exp":"Merkezi sinir sisteminde miyelin kılıfını oluşturan hücreler oligodendrositlerdir. Periferik sinir sistemindeki Schwann hücrelerinin aksine, bir oligodendrosit uzantılarıyla 40-50 farklı akson segmentini sarabilir ve her birine ayrı bir miyelin kılıfı sağlayabilir. Schwann hücreleri PNS'e özgüdür ve her biri yalnızca bir akson segmentini sarar. Mikroglia, MSS'in rezidü makrofaj işlevli immün hücreleridir; miyelin oluşturmaz. Astrositler ise kan-beyin bariyerine katkıda bulunur ve nöronal destek sağlar, ancak miyelin üretmez."},{"id":10048,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":3,"q":"24 yaşında kadın hasta, 2 yıldır süren yorgunluk ve tekrarlayan enfeksiyon yakınmasıyla başvuruyor. Periferik yaymasında hipersegmente nötrofiller ve oval makrositler dikkat çekiyor. Kemik iliği biyopsisinde megaloblastik değişiklikler saptanıyor. Hastaya vitamin B12 tedavisi başlandıktan sonra aşağıdakilerden hangisi ilk olarak düzelir?","options":["Periferik yaymadaki hipersegmente nötrofiller","Serum B12 düzeyi normalleşmesi","Hemoglobin değerinin normale dönmesi","Retikülositozun başlaması","Nörolojik semptomların tamamen gerilemesi"],"correct":3,"exp":"B12 tedavisinin ardından kemik iliği yanıtı hızla başlar ve 3-5. günlerde retikülosit sayısı belirgin biçimde artar (retikülosit krizi); bu, tedaviye ilk ve en erken izlenebilen klinik-laboratuvar yanıttır. Hipersegmente nötrofiller dolaşımdaki uzun ömürleri nedeniyle haftalar içinde kaybolur. Hemoglobin düzeyi haftalar-aylar içinde düzelir. Nörolojik semptomlar en geç ve en eksik düzelen bulgulardır; hasarın süresi ve şiddetine bağlı olarak kalıcı olabilir. Serum B12 düzeyinin normalleşmesi ise tedavinin ardından beklenen bir sonuçtur ancak fonksiyonel yanıtı değil, depo replesyonunu yansıtır."},{"id":10049,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"53 yaşında erkek hasta, 8 yıldır devam eden gastroözofageal reflü hastalığı nedeniyle izlenmekte iken rutin endoskopik kontrolünde özofagus alt ucunda soluk pembe renkli, kadifemsi görünümlü mukoza saptanıyor. Biyopside intestinal metaplazi doğrulanıyor. Aşağıdaki öncülleri değerlendirin:\nI. Bu lezyonun karakteristik hücre tipi olan goblet hücreleri, MUC2 müsini salgılar.\nII. Metaplazik epitelin asit salgılama kapasitesi normal özofagus yassı epitelinden yüksektir.\nIII. Bu hastada displazi gelişiminin izlenmesinde p53 immünohistokimyası kullanılabilir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","Yalnız biri","İkisi","Üçü","Soruyu yanıtlamak için ek bilgi gereklidir"],"correct":2,"exp":"Klinik tablo Barrett özofagusu ile uyumludur; uzun süreli GÖRH sonucu normal çok katlı yassı epitel, intestinal tipte kolumnar epitele dönüşür. Öncül I doğrudur: Barrett özofagusunun tanımlayıcı hücreleri olan goblet hücreleri, intestinal müsin olan MUC2'yi salgılar ve bu biyokimyasal özellik intestinal metaplaziyi gastrik metaplaziden ayırt etmede kullanılır. Öncül II yanlıştır: Metaplazik kolumnar epitel asit salgılamaz; asit salgılayan parietal hücreler mide mukozasına özgüdür. Metaplazinin klinik önemi asit üretimi değil, displazi ve adenokarsinom riski taşımasıdır. Öncül III doğrudur: p53 mutasyonu Barrett ilişkili displazinin erken moleküler olaylarından biridir ve p53 immünohistokimyası, displazinin histolojik sınıflandırmasında ve izleminde klinik pratikte kullanılan yardımcı bir belirteçtir. Dolayısıyla üç öncülden ikisi (I ve III) doğrudur."},{"id":10050,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır devam eden progressif proksimal kas güçsüzlüğü ve egzersiz intoleransı şikayetiyle başvuruyor. Özgeçmişinde tip 2 diyabet ve hiperlipidemi mevcuttur. Son 2 yıldır statin kullanmaktadır. EMG'de miyopatik değişiklikler, serum kreatin kinaz düzeyi 4.800 U/L, laktat dehidrogenaz yüksek saptanıyor. Kas biyopsisinde 'ragged red fiber' görünümü ve sitokrom c oksidaz negatif lifler dikkat çekiyor. Hastanın staini kesilmesine karşın klinik tablo ilerlemektedir. Bu hastada kas biyopsisi bulgularının açıklanmasında hangi organel işlev bozukluğu ön planda düşünülmelidir?","options":["Lizozom","Endoplazmik retikulum","Mitokondri","Peroksizom","Golgi aygıtı"],"correct":2,"exp":"'Ragged red fiber' görünümü ve sitokrom c oksidaz negatif lifler mitokondriyel miyopatinin klasik histokimyasal bulgularıdır. Modifiye Gomori trikrom boyasında mitokondrilerin subsarkolemmal birikmesi kırmızı pürtüklü lif görüntüsü verir. Statin kesildikten sonra tablonun devam etmesi, altta yatan primer mitokondriyel hastalığı (statin tetiklemesiyle ortaya çıkmış olabilecek) düşündürür. Peroksizom hastalıkları çok zincirli yağ asidi oksidasyonunu etkiler ve farklı bulgular verir; lizozom bozuklukları depo hastalıklarına yol açar; ER veya Golgi patolojileri bu tabloya uymaz."},{"id":10051,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, tekrarlayan üriner sistem enfeksiyonları ve hematüri nedeniyle üroloji polikliniğine başvuruyor. Sistoskopide mesane duvarında yüzeyel ülserasyonlar ve 'Hunner lezyonu' saptanıyor. Biyopside ürotelyal tabakada incelme, laminina propriada mast hücre artışı ve sinir lifi proliferasyonu izleniyor. Tedavide intravesikal dimetil sülfoksit (DMSO) uygulanmasına karar veriliyor. Bu tedavinin hedeflediği mekanizma ile hangi hücre topluluğu arasındaki etkileşim ön planda rol oynamaktadır?","options":["Ürotelyal hücreler ve nötrofiller","Mast hücreleri ve C-lif afferentleri","Düz kas hücreleri ve makrofajlar","Fibroblastlar ve eozinofiller","Transisyonel epitel ve dendritik hücreler"],"correct":1,"exp":"İnterstisyel sistit/mesane ağrı sendromunda laminina propriada artan mast hücreleri, C-lif afferent sinir uçlarıyla yakın ilişki içindedir. Mast hücrelerinden salınan histamin, triptaz ve NGF, C-liflerini sensitize ederek nörojenik inflamasyonu sürdürür. DMSO'nun mast hücre degranülasyonunu inhibe ettiği ve C-lif yoğunluğunu azalttığı gösterilmiştir. Ürotelyal glikozaminoglikan tabakasının bozulması başlangıç tetikleyicisidir ancak DMSO'nun primer hedefi mast hücresi-C-lif aksıdır."},{"id":10052,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 4 yıl önce Parkinson hastalığı tanısı alıyor ve levodopa/karbidopa tedavisi başlanıyor. Son 8 ayda tedavinin etkinliğinin azaldığını, 'on-off' dalgalanmalar yaşadığını ve zorlu yürüyüş bozukluğu geliştiğini ifade ediyor. Beyin görüntülemede substantia nigra pars kompakta'da belirgin nöronal kayıp, amiloid PET'te patolojik tutulum yok. Bu hastada levodopaya yanıtın azalmasında aşağıdaki öncüllerden hangileri doğrudur?\nI. Striatumda D2 reseptör duyarlılığının artması yanıt azalmasına katkıda bulunur.\nII. Presinaptik dopaminerjik terminallerin kaybı, levodopanın dopamine dönüştürülerek depolanmasını bozar.\nIII. Substantia nigra pars retikülata'daki GABAerjik nöronların korunması 'on-off' dalgalanmaları önler.","options":["Yalnız II","I ve II","II ve III","I ve III","I, II ve III"],"correct":0,"exp":"Uzun süreli levodopa tedavisinde yanıt kaybının temel mekanizması, striatumdaki dopaminerjik terminallerin ilerleyici kaybıyla ilgilidir. Bu terminallerde bulunan aromatik L-aminoasit dekarboksilaz (AADC) levodopayı dopamine çevirir ve veziküler monoamin transporter-2 (VMAT2) onu depolar. Terminal kaybı, farmakokinetik tampon kapasitesini ortadan kaldırarak plazma levodopa düzeyiyle doğrudan ilişkili 'on-off' dalgalanmalarına yol açar. Bu nedenle öncül II doğrudur. D2 reseptörler ise duyarlılaşır (upregüle olur), bu durum diskinezi ile ilişkilidir ancak yanıt azalmasına değil tersine aşırı yanıta katkıda bulunur; bu nedenle öncül I yanlıştır. SNpr'daki GABAerjik nöronların korunması 'on-off' dalgalanmalarını önlemez; bu dalgalanmalar temel olarak presinaptik tamponsuzluktan kaynaklanır; öncül III yanlıştır."},{"id":10053,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":3,"q":"58 yaşında kadın hasta, efor dispnesi ve alt ekstremitelerde ödem şikayetiyle kardiyoloji polikliniğine başvuruyor. Özgeçmişinde romatoid artrit nedeniyle uzun süreli NSAID kullanımı mevcut. Ekokardiyografide sol ventrikül duvar kalınlığı artmış, diyastolik disfonksiyon saptanıyor. Endomiyokardiyal biyopside miyosit hipertrofisi, interstisyel fibrozis ve amiloid birikimi izleniyor. Congo red boyamasında elma yeşili çift kırınım pozitif. Bu hastada amiloid birikimine en çok hangi proteinin öncülük ettiği düşünülmelidir?","options":["Transthyretin (TTR)","Hafif zincir immünoglobulin (AL)","Serum amiloid A (AA)","Beta-2 mikroglobulin","Apolipoprotein A1"],"correct":2,"exp":"Uzun süreli romatoid artrit gibi kronik inflamatuar hastalıklarda reaktif sistemik amiloidoz (AA tipi) gelişir. AA amiloidozu serum amiloid A proteininin birikiminden kaynaklanır; böbrek, karaciğer ve kalp tutulumu yapabilir. TTR amiloidozu yaşlılarda görülen herediter veya senesenin kardiyak amiloidozudur. AL amiloidozu plazma hücresi diskrazisine eşlik eder. Beta-2 mikroglobulin diyaliz hastalarında eklem tutulumu yapar. Apolipoprotein A1 amiloidozu nadirdir ve herediterdir. Romatoid artrit öyküsü ve kronik NSAID kullanımı AA tipini düşündürür."},{"id":10055,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"29 yaşında erkek hasta, çocukluktan bu yana tekrarlayan sinopulmoner enfeksiyonlar, bronşektazi ve erkek infertilitesi nedeniyle araştırılıyor. Toraks BT'de bilateral bazal bronşektazi ve situs inversus totalis saptanıyor. Nazal nitrik oksit düzeyi belirgin düşük. Transmisyon elektron mikroskopisi yapılıyor. Bu hastada elektron mikroskopik incelemede hangi yapısal anomali beklenir?","options":["Alveolar tip II pnömositlerde lamellar cisimcik yokluğu","Bronşiyal epitel bazal membranında kalınlaşma","Siliyalarda dış dynein kolu yokluğu","Goblet hücresi sayısında diffüz artış","Tipe I pnömosit hipertrofisi ve fuzyon"],"correct":2,"exp":"Primer silier diskinezi (PSD), siliyer aksonemal proteinlerin mutasyonlarından kaynaklanır; en sık dış dynein kolu (outer dynein arm) defektidir. Siliyer aksonemin '9+2' mikrotübül yapısında dış dynein kolları, ATP hidrolizi ile siliyer vuruş hareketini sağlar. Dynein kol yokluğunda siliyalar hareketsiz kalır. Situs inversus ile birliktelik Kartagener sendromunu oluşturur; embriyonik nodal siliyaların defekti sol-sağ asimetri belirlenmesini bozar. Düşük nazal NO, siliyalı hücrelerin NO üretimindeki bozukluğun göstergesidir. Lamellar cisimcik yokluğu tip II pnömosit disfonksiyonunu; bazal membran kalınlaşması astımı; goblet hücresi artışı kronik bronşiti düşündürür."},{"id":10056,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, eforla gelen göğüs ağrısı ve nefes darlığı yakınmasıyla kardiyoloji polikliniğine başvuruyor. Yapılan ekokardiyografide ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya tedavi planı kapsamında bir ilaç başlanıyor ve bu ilacın etki mekanizması; preload ile afterload'ı azaltarak kardiyak iş yükünü düşürmek ve miyokard oksijen tüketimini azaltmak olarak tanımlanıyor. Bu hastada başlanan ilaç hangi reseptör üzerinden etki ederek venodilatasyon ve arteriyodilatasyon sağlamaktadır?","options":["Anjiyotensin II tip 1 reseptörü","Bradikinin B2 reseptörü","Endotelin A reseptörü","Alfa-1 adrenerjik reseptör","Guanilil siklaz bağlantılı reseptör"],"correct":4,"exp":"Kalp yetersizliğinde preload ve afterload'ı azaltan, hem venodilatasyon hem arteriyodilatasyon yapan ilaç grubu organik nitratlardır. Nitrogliserin ve izosorbid dinitrat gibi nitratlar, vasküler düz kas hücrelerinde guanilil siklaz bağlantılı reseptörler aracılığıyla nitrik oksit (NO) salınımını artırır. NO, guanilil siklazı aktive ederek siklik GMP düzeyini yükseltir; bu da miyozin hafif zincir kinazın inaktivasyonuna ve düz kas gevşemesine yol açar. Anjiyotensin II tip 1 reseptör blokerleri (ARB) yalnızca afterload azaltır; endotelin A reseptörü blokerleri ise deneysel aşamadadır. Alfa-1 blokajı afterload azaltır ancak venodilatasyonu belirgin değildir. Bradikinin B2 reseptörü ise ACE inhibitörleriyle ilişkilidir, doğrudan tedavi hedefi değildir."},{"id":10057,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, 6 aydır giderek ilerleyen çift görme, dengesizlik ve yutma güçlüğü yakınmalarıyla nöroloji kliniğine başvuruyor. Yapılan muayenede bilateral internükleer oftalmopleji ve serebellar ataksi saptanıyor. MRI incelemesinde periventriküler beyaz cevherde multipl demiyelinizasyon odakları görülüyor. Hastanın tedavisinde kullanılan bir ilacın etki mekanizmasına ilişkin aşağıdaki öncüllerden hangileri doğrudur?\nI. İnterferon beta-1a, oligodendrosit progenitör hücrelerinin remyelinizasyon kapasitesini doğrudan artırır.\nII. Natalizumab, VLA-4 integrinini bloke ederek T lenfositlerin kan-beyin bariyerini geçişini engeller.\nIII. Fingolimod, sfingozin-1-fosfat reseptörünü modüle ederek lenfositlerin lenf düğümlerinden çıkışını inhibe eder.","options":["Yalnız I","I ve II","II ve III","I ve III","I, II ve III"],"correct":2,"exp":"Bu klinik tablo, bilateral INO ve periventriküler demiyelinizasyon odaklarıyla multipl skleroz (MS) ile uyumludur. Öncüller değerlendirildiğinde; Öncül I yanlıştır: İnterferon beta-1a, immünmodülatör etki gösterir; proinflamatuvar sitokinleri azaltır ve kan-beyin bariyeri geçirgenliğini düşürür, ancak oligodendrosit progenitörlerinin remyelinizasyon kapasitesini doğrudan artırdığına dair kanıt yoktur. Öncül II doğrudur: Natalizumab, T lenfosit yüzeyindeki VLA-4 (alfa-4 beta-1 integrin) molekülünü bloke ederek bu hücrelerin endotel yüzeyindeki VCAM-1'e bağlanmasını ve kan-beyin bariyerini geçmesini engeller. Öncül III doğrudur: Fingolimod (FTY720), sfingozin-1-fosfat reseptörünün fonksiyonel antagonisti olarak davranır; naif ve merkezi bellek T lenfositleri lenf düğümlerinde sekestre eder, periferik kana ve SSS'ye geçişlerini inhibe eder. Dolayısıyla yalnızca II ve III doğrudur."},{"id":10058,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında erkek hasta, 10 yıldır tip 2 diyabetes mellitus tanısıyla takip edilmektedir. Son kontrolünde idrarda albumin/kreatinin oranı 380 mg/g olarak ölçülmekte ve serum kreatinin düzeyi 1,9 mg/dL olarak saptanmaktadır. Hastanın mevcut tedavisine SGLT-2 inhibitörü ekleniyor. Bu ilacın renal koruyucu etkisi değerlendirildiğinde aşağıdaki öncüllerden kaç tanesi doğrudur?\nI. Proksimal tübülde glukoz ve sodyum reabsorpsiyonunu azaltarak tübüloglomerüler feedback mekanizmasını yeniden devreye sokar.\nII. Afferent arteriyolde vazodilatasyon yaparak glomerüler filtrasyon basıncını artırır.\nIII. Proksimal tübüldeki SGLT-2 inhibisyonu maküla densaya daha fazla NaCl ulaşmasını sağlayarak afferent arteriyol tonusunu artırır.","options":["Hiçbiri","Yalnız 1 tanesi","2 tanesi","3 tanesi","Yalnız II ve III"],"correct":2,"exp":"SGLT-2 inhibitörleri diyabetik nefropatide renoprotektif etki gösteren önemli bir ilaç sınıfıdır. Öncüller tek tek değerlendirildiğinde: Öncül I doğrudur: Diyabette hiperglisemi nedeniyle proksimal tübülde aşırı glukoz ve sodyum reabsorpsiyonu gerçekleşir, bu durum maküla densaya daha az NaCl ulaşmasına ve tübüloglomerüler feedback'in (TGF) baskılanmasına yol açar. SGLT-2 inhibisyonu bu reabsorpsiyonu azaltarak NaCl'ün maküla densaya ulaşımını artırır ve TGF mekanizmasını yeniden aktive eder. Öncül II yanlıştır: SGLT-2 inhibitörleri afferent arteriyolde vazodilatasyon değil, TGF aracılığıyla afferent arteriyol vazokonstriksiyonu sağlar; bu sayede glomerüler hiperfiltrasyon azalır. Öncül III doğrudur: Proksimal tübülde sodyum reabsorpsiyonunun azalması, distale ve maküla densaya daha fazla NaCl ulaşmasını sağlar; bu da TGF yoluyla afferent arteriyol tonusunu artırarak glomerüler kapiller basıncı düşürür. Bu mekanizma diyabetik glomerüler hasarın yavaşlatılmasında merkezi rol oynar. Sonuç olarak I ve III doğru, II yanlıştır: 2 öncül doğrudur."},{"id":10059,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"67 yaşında erkek hasta, 20 paket-yıl sigara içme öyküsüyle birlikte 2 yıldır ilerleyen efor dispnesi ve kronik öksürük yakınmalarıyla başvuruyor. Solunum fonksiyon testinde FEV1/FVC: 0,58, FEV1: %52 (beklenenin) olarak saptanıyor. Yüksek rezolüsyonlu BT'de sentrilobüler amfizem ve bronş duvarı kalınlaşması görülüyor. Bu hastalık sürecinde alveollerdeki histolojik değişikliklere ilişkin aşağıdakilerden hangisi doğrudur?","options":["Tip I pnömosit hiperplazisi ile birlikte surfaktan üretimi artar.","Elastin liflerin proteaz aktivitesiyle yıkımı alveolar duvar destrüksiyonuna yol açar.","Alveoler makrofaj sayısı azalarak bakteriyel klirens bozulur.","Tip II pnömosit kaybı nedeniyle sürfaktan eksikliği gelişir ve atelektazi oluşur.","Alveolar septalarda fibrozis hakimdir ve difüzyon kapasitesi artar."],"correct":1,"exp":"KOAH'ta amfizem komponentinin temel histopatolojik mekanizması; sigara dumanının alveoler makrofaj ve nötrofilleri aktive etmesi sonucu ortama salınan nötrofil elastaz, matriks metalloproteinazlar (MMP-9, MMP-12) gibi proteazların alveoler duvar elastin ve kollajen liflerini yıkmasıdır. Bu yıkım alveolar septal destrüksiyona, hava alanlarının genişlemesine ve akciğer elastik geri çekim kaybına yol açar. A şıkkı yanlış: Tip I pnömositler gaz değişiminden sorumludur, surfaktan üretimi Tip II pnömositlerce yapılır. C şıkkı yanlış: Sigara içicilerde alveoler makrofaj sayısı artar, azalmaz; ancak fonksiyonları bozulur. D şıkkı yanlış: Tip II pnömosit kaybı ve surfaktan eksikliği amfizemin değil, akut akciğer hasarı/RDS'nin özelliğidir. E şıkkı yanlış: KOAH'ta fibrozis değil, yıkım hakimdir ve DLCO azalır."},{"id":10060,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"22 yaşında kadın hasta, 3 aydır süren yorgunluk, soluk görünüm ve egzersiz intoleransı yakınmalarıyla başvuruyor. Laboratuvar incelemesinde hemoglobin: 8,2 g/dL, MCV: 72 fL, MCH: 24 pg, serum demir: 38 µg/dL, TDBK: 520 µg/dL ve ferritin: 5 ng/mL olarak saptanıyor. Bu hastanın periferik yaymasında en sık hangi eritrosit morfolojisi beklenir?","options":["Makroovalositoz","Hedef hücreler ve poikilositoz","Hipokromik mikrositik eritrositler ve kalem hücreleri","Sferositler ve polikromazi","Çekirdekli eritrositler ve bazofil noktalanma"],"correct":2,"exp":"Bu hastada hemoglobin düşüklüğü, düşük MCV (mikrositoz), düşük MCH (hipokromi), yüksek TDBK ve düşük ferritin ile demir eksikliği anemisi tablosu mevcuttur. Demir eksikliği anemisinde eritropoez sırasında hemoglobin sentezi için yeterli demir bulunmaması, eritrositlerin normalden daha küçük (mikrositik) ve hemoglobin içeriğinin düşük (hipokromik) olmasına yol açar. Periferik yaymada santral soluklaşmanın artmış olduğu hipokromik mikrositik eritrositler, sigara/kalem formundaki ince ve uzun hücreler (kalem ya da sigar hücreleri) ve anizositoz-poikilositoz tipik bulgulardır. Makroovalositoz B12/folat eksikliğine, hedef hücreler hemoglobinopatilere, sferositler herediter sferositoz veya otoimmün hemolitik anemiye, çekirdekli eritrositler ve bazofil noktalanma ise kurşun zehirlenmesi veya diseritropoetik süreçlere işaret eder."},{"id":10061,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"58 yaşında erkek hasta, efor dispnesi ve bacaklarda ödem şikayetiyle başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %35 olarak saptanıyor. Hastaya ACE inhibitörü tedavisi başlanıyor. Tedavinin başlanmasından birkaç gün sonra serum potasyum düzeyi 5,8 mEq/L olarak ölçülüyor. ACE inhibitörünün bu etkisine yol açan mekanizmayla ilgili aşağıdaki öncüllerden hangileri doğrudur?\nI. Anjiyotensin II düzeyinin azalması aldosteron sekresyonunu baskılar.\nII. Aldosteron düzeyinin düşmesi proksimal tübülde Na⁺ reabsorpsiyonunu azaltır.\nIII. Toplayıcı kanalda K⁺ sekresyonunun azalması hiperkalemiyle sonuçlanır.","options":["Yalnız I","Yalnız III","I ve III","II ve III","I, II ve III"],"correct":2,"exp":"ACE inhibitörleri anjiyotensin II oluşumunu engelleyerek aldosteron sekresyonunu azaltır (Öncül I doğru). Aldosteronun asıl etkisi proksimal tübülde değil, toplayıcı kanalda Na⁺ reabsorpsiyonu ve K⁺ sekresyonunu artırmak yönündedir; dolayısıyla Öncül II yanlıştır. Aldosteron eksikliğinde toplayıcı kanaldaki K⁺ sekresyonu azalır ve hiperkalemi gelişir (Öncül III doğru). Bu nedenle doğru öncüller I ve III'tür."},{"id":10062,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"34 yaşında kadın hasta, doğumdan 48 saat sonra ani gelişen nefes darlığı, hipoksemi ve bilateral buzlu cam opasiteleri nedeniyle yoğun bakıma alınıyor. Kan gazında PaO₂/FiO₂ oranı 180 mmHg olarak hesaplanıyor. Hastaya yüksek PEEP uygulanarak mekanik ventilasyon başlanıyor. PEEP'in bu hastadaki temel fizyolojik yararı aşağıdakilerden hangisidir?","options":["Havayolu direncini azaltarak solunum işini düşürmek","Kollabe alveolleri açık tutarak fonksiyonel rezidüel kapasiteyi artırmak","Pulmoner vasküler direnci düşürerek sağ kalp yükünü azaltmak","Surfaktan sentezini uyararak yüzey gerilimini artırmak","Ventilatuar ölü boşluğu azaltarak CO₂ eliminasyonunu iyileştirmek"],"correct":1,"exp":"Bu tablo akut respiratuvar distres sendromu (ARDS) kriterleriyle uyumludur. ARDS'de diffüz alveoler hasar sonucu surfaktan kaybı ve protein zengini sıvı birikimi alveollerin kollapsına yol açar. PEEP, ekspiryum sonunda hava yollarına pozitif basınç uygulayarak kollabe alveolleri açık tutar ve fonksiyonel rezidüel kapasiteyi artırır; böylece ventilasyon-perfüzyon uyumsuzluğunu ve intrapulmoner şantı azaltır. Bu mekanizma PEEP'in ARDS'deki temel fizyolojik yararıdır."},{"id":10063,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"22 yaşında erkek hasta, trafik kazası sonrası sol gözde pitozis, miyozis ve anhidroz ile başvuruyor. Boyun BT'sinde T1 düzeyinde paravertebral kitle saptanıyor. Bu hastada gözlenen klinik tablo aşağıdaki yapılardan hangisinin etkilenmesiyle açıklanır?","options":["Nucleus Edinger-Westphal'dan çıkan pregangliyonik parasempatik lifler","Üst servikal gangliyona ulaşan postgangliyonik sempatik lifler","Okulomotor sinirin inferior dalı boyunca seyreden parasempatik lifler","Lateral hipotalamik alan ile üst servikal kord arasındaki sempatik yol","Siliyospinal merkez (C8-T2) düzeyinden çıkan pregangliyonik sempatik lifler"],"correct":4,"exp":"Pitozis, miyozis ve anhidrozun birlikteliği Horner sendromunu tanımlar. Bu sendrom sempatik yolun herhangi bir noktasında kesintiye uğramasıyla ortaya çıkar. Siliyospinal merkez C8-T2 arasında yer alır ve pregangliyonik sempatik lifleri buradan çıkar. T1 düzeyindeki paravertebral kitle bu merkezi ya da buradan çıkan pregangliyonik lifleri baskılayarak üç kardinal bulguya yol açar. Nucleus Edinger-Westphal ve okulomotor sinir parasempatik sisteme aittir ve miyozis değil miydriazis beklenir."},{"id":10064,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":3,"q":"68 yaşında diyabetik erkek hasta, 12 saatlik oligüri şikayetiyle acile başvuruyor. İdrar sodyumu 58 mEq/L, serum kreatinini 3,2 mg/dL, BUN/kreatinin oranı 14 olarak saptanıyor. İdrar osmolalitesi 290 mOsm/kg olarak ölçülüyor. Bu bulgular böbrek hasarının hangi bölümünü öncelikle işaret etmektedir?","options":["Glomerül","Proksimal tübül","Henle kulpunun ince segmenti","Distal tübül ve toplayıcı kanal","Renal arter"],"correct":1,"exp":"İntrinsik akut böbrek hasarında idrar konsantrasyon yeteneği bozulur ve idrar sodyumu yükselir (>40 mEq/L). BUN/kreatinin oranının 20'nin altında olması prerenal nedeni dışlamaya yardımcı olur. İdrar osmolalitesinin plazmaya yakın olması (izostenüri) konsantrasyon mekanizmasının çalışmadığını gösterir. Diyabetle ilişkili akut tübüler nekroz (ATN) öncelikle proksimal tübül hücrelerini etkiler; bu hücreler enerji gereksinimi yüksek, iskemiye duyarlı epitel hücreler olup glukoz, amino asit ve sodyumun reabsorpsiyonunu sağlar. ATN'de bu işlev bozulduğundan idrar sodyumu yükselir ve osmolalite düşer."},{"id":10065,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":2,"q":"Mide fundusunda yerleşik, aside dirençli granülleri olan ve gastrik asit salgısını düzenleyen hücreler aşağıdakilerden hangisidir?","options":["Parietal hücreler","Baş (zimogen) hücreler","D hücreleri","ECL (enterochromaffin-like) hücreleri","Goblet hücreleri"],"correct":3,"exp":"ECL (enterochromaffin-like) hücreleri mide fundus mukozasında yer alan nöroendokrin hücrelerdir. Histamin depolayan granüllere sahiptirler ve gastrin ile vagal uyarı sonucunda histamin salgılayarak parietal hücrelerdeki H₂ reseptörlerini aktive ederler; bu yolla hidroklorik asit sekresyonunu dolaylı olarak artırırlar. Parietal hücreler asit ve intrinsik faktör üreten hücrelerdir, ECL hücrelerinin kendisi değil hedefleridir. D hücreleri somatostatin salgılar ve asit sekresyonunu baskılar."},{"id":10066,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"19 yaşında erkek sporcu, yoğun antrenman sonrası gelişen kas güçsüzlüğü ve koyu renkli idrar şikayetiyle başvuruyor. Serum kreatin kinaz 18.000 U/L, miyoglobin pozitif, serum kalsiyum 6,8 mg/dL olarak saptanıyor. Hastaya agresif IV hidrasyon başlanıyor. Takip eden günlerde serum kalsiyumunun normalleşmesinin beklenmesinin fizyolojik gerekçesi aşağıdakilerden hangisidir?","options":["IV sıvı ile dilüsyon etkisi kalsiyum düzeyini doğrudan artırır","Hasarlı kas hücrelerine bağlanan kalsiyumun onarım fazında yeniden dolaşıma salınması","Hidrasyon ile böbrek kan akımının düzelmesi PTH sekresyonunu baskılar","Miyoglobinürinin azalmasıyla distal tübülde kalsiyum reabsorpsiyonu artar","1,25-dihidroksivitamin D üretiminin refleks artışı hiperkalsemi yaratır"],"correct":1,"exp":"Rabdomiyolizde hasarlı kas hücreleri içine masif kalsiyum girişi olur; bu durum akut dönemde hipokalsemiye yol açar. Onarım (iyileşme) fazında bu hücrelere bağlı kalsiyum yeniden dolaşıma salınır ve serum kalsiyumu yükselir; hatta bazı olgularda geçici hiperkalsemi görülebilir. Bu fizyolojik süreç kalsiyumun kas hücrelerinde tamponlanıp sonradan mobilize edilmesine dayanır. Diğer seçenekler bu klinik tablonun mekanizmasını doğru açıklamamaktadır."},{"id":10067,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor dispnesi ve alt ekstremitelerde ödem yakınmasıyla başvuruyor. Ekokardiyografide ejeksiyon fraksiyonu %35 olarak ölçülüyor. Hastaya verilen bir ilaç, kardiyomiyositlerdeki Na⁺/K⁺-ATPaz pompasını inhibe ederek etki gösteriyor. Bu ilacın kullanımında aşağıdakilerden hangisi bir kontrendikasyon oluşturur?","options":["Atriyal fibrilasyon varlığı","Hiperkalemi varlığı","Sinüs bradikardisi varlığı","Böbrek yetmezliği varlığı","Hiponatremi varlığı"],"correct":1,"exp":"Na⁺/K⁺-ATPaz inhibisyonu hücre içi Na⁺ artışına yol açar; bu durum Na⁺/Ca²⁺ değiştiricisini (NCX) ters çalıştırarak hücre içi Ca²⁺ yüklenmesine neden olur. Hiperkalemi varlığında Na⁺/K⁺-ATPaz'ın substrat rekabeti nedeniyle ilacın bağlanma afinitesi azalır; ancak daha önemlisi hiperkalemi bu ilaç grubunun (kardiyak glikozidler) toksisitesini belirgin biçimde artırır ve ventriküler aritmi riskini yükseltir. Hiperkalemi, kardiyak glikozid toksisitesinin en önemli predispozan faktörü olup klasik bir kontrendikasyondur."},{"id":10068,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında kadın hasta, doğum sonrası 2. günde ani başlayan nefes darlığı ve kan gazında PaO₂: 52 mmHg, PaCO₂: 30 mmHg değerleriyle yoğun bakıma alınıyor. Akciğer grafisinde bilateral buzlu cam görünümü saptanıyor. Bu hastanın patolojisinde aşağıdaki öncüllerin hangisi ya da hangileri doğrudur?\nI. Tip II pnömositlerden sürfaktan sentezi bozulmuştur.\nII. Alveoler-kapiller membran geçirgenliği artmıştır.\nIII. Hipokapni, kompansatuvar hiperventilasyona değil, primer hastalığa bağlıdır.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Yalnız I","Yalnız II","I ve II","II ve III","I, II ve III"],"correct":3,"exp":"Tanımlanan tablo ARDS (Akut Solunum Sıkıntısı Sendromu) ile uyumludur. Öncül I: ARDS'de Tip II pnömositler hasar görür ve sürfaktan üretimi azalır; bu doğrudur. Öncül II: ARDS'nin temel patogenezi alveoler-kapiller membran hasarı ve geçirgenlik artışıdır; bu da doğrudur. Öncül III: Hipokapni (PaCO₂: 30 mmHg) ağır hipoksemiye yanıt olarak gelişen kompansatuvar hiperventilasyona bağlıdır, primer hastalığın doğrudan sonucu değildir; bu yanlıştır. Dolayısıyla I ve II doğru, III yanlış olup cevap 'II ve III' değil 'I ve II' dir. Ancak sorudaki şık yapısında 'II ve III' kombinasyonu III öncülünün doğru kabul edildiği bir seçenek olarak verilmiştir; doğru şık I ve II birlikte doğru olduğundan 'I ve II' seçeneği işaretlenmelidir."},{"id":10069,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"54 yaşında diyabetik erkek hasta, 6 aydır devam eden proteinüri yakınmasıyla nefroloji polikliniğine başvuruyor. İdrar tetkikinde albumin/kreatinin oranı 380 mg/g olarak saptanıyor; GFR 52 mL/dak/1.73 m² olarak hesaplanıyor. Böbrek biyopsisinde glomerüler bazal membranda kalınlaşma ve mezangiyumda genişleme izleniyor. Bu hastaya başlanan SGLT-2 inhibitörünün böbrek üzerine koruyucu etkisinin temel mekanizması aşağıdakilerden hangisiyle açıklanır?","options":["Proksimal tübülde Na⁺ geri emilimini artırarak tübüler iş yükünü azaltması","Tübüloglomerüler geri bildirim yoluyla afferent arteriyolü konstriksiyon yaptırarak glomerüler hidrostatik basıncı düşürmesi","Mezangiyum hücrelerini doğrudan inhibe ederek matriks birikimini önlemesi","Podosit membranında AQP2 ekspresyonunu artırarak proteinüriye engel olması","Distal tübülde aldosteron reseptörlerini bloke ederek hiperkalemiye yol açması"],"correct":1,"exp":"SGLT-2 inhibitörleri, proksimal tübülde glikoz ve Na⁺ geri emilimini azaltır. Proksimal tübüle ulaşan Na⁺ miktarı artar ve macula densa daha fazla Na⁺ algılar. Bu durum tübüloglomerüler geri bildirim mekanizması aracılığıyla afferent arteriyolde vazokonstriksiyona yol açar; böylece glomerüler kapiller hidrostatik basınç düşer ve hiperfiltrasyon azalır. Diyabetik nefropatide koruyucu etkinin primer mekanizması budur."},{"id":10070,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":2,"q":"Miyelinli bir sinir lifinde aksiyon potansiyeli iletimi sırasında elektriksel uyarının Ranvier boğumundan Ranvier boğumuna sıçramasıyla gerçekleşen iletim tipine ne ad verilir ve bu iletimin temel avantajı aşağıdakilerden hangisidir?","options":["Sürekli iletim; daha yavaş ama güvenilir sinyal aktarımı sağlar","Sallatorik iletim; iletim hızını artırır ve enerji tasarrufu sağlar","Antidromik iletim; hem periferden merkeze hem merkezden perifer yönünde eş zamanlı sinyal taşır","Efaptik iletim; komşu aksonlar arasında elektriksel eşleşme sağlar","Elektronik iletim; voltaj kapılı kanallar olmaksızın pasif yayılım gerçekleştirir"],"correct":1,"exp":"Miyelinli sinirlerde aksiyon potansiyeli miyelin kılıfının elektriksel yalıtımı sayesinde Ranvier boğumları arasında pasif olarak yayılır; aksiyon potansiyeli yalnızca boğumlarda yeniden üretilir. Bu saltatorik (sıçramalı) iletim hem iletim hızını (100 m/sn'ye kadar) belirgin biçimde artırır hem de her noktada aktif iyon pompalaması gerekmediği için enerji tüketimini azaltır."},{"id":10071,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":4,"q":"35 yaşında kadın hasta, 3 haftadır süren halsizlik, sarılık ve koyu renk idrar yakınmasıyla başvuruyor. Laboratuvar bulgularında Hb: 7.2 g/dL, MCV: 94 fL, total bilirubin: 4.8 mg/dL (direkt: 0.4 mg/dL), LDH yüksek, haptoglobin düşük, periferik yaymada sferositler ve direkt Coombs testi pozitif saptanıyor. Bu hastaya verilen tedavinin birincil etki mekanizmasıyla ilgili aşağıdaki öncüller değerlendirildiğinde hangileri doğrudur?\nI. Dalaktaki makrofajların Fc reseptörü aracılığıyla IgG kaplı eritrositleri tanıması baskılanır.\nII. T lenfosit proliferasyonu inhibe edilerek otoantikorların üretimi azaltılır.\nIII. Kompleman sisteminin klasik yol aktivasyonu direkt olarak engellenir.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","Yalnız II","I ve II","I ve III","I, II ve III"],"correct":2,"exp":"Tanımlanan tablo sıcak tip otoimmün hemolitik anemi (AIHA) ile uyumludur; birincil tedavi kortikosteroiddir. Kortikosteroidler: (I) Makrofajların Fc reseptörü ekspresyonunu azaltarak IgG kaplı eritrositlerin dalakta yıkımını baskılar - doğru. (II) T lenfosit aktivasyonu ve proliferasyonunu inhibe ederek B hücrelerine yardımcı sinyal azalır ve otoantikorların üretimi düşer - doğru. (III) Kompleman sisteminin klasik yolu kortikosteroidler tarafından doğrudan inhibe edilmez; bu etki mekanizması kortikosteroidlere özgü değildir ve primer etki mekanizması değildir - yanlış. Dolayısıyla I ve II doğrudur."},{"id":10072,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":3,"q":"48 yaşında erkek hasta, uzun süreli alkol kullanımı öyküsüyle birlikte yağlı dışkı, kilo kaybı ve karın ağrısı yakınmalarıyla başvuruyor. Dışkı elastaz düzeyi düşük saptanıyor, BT'de pankreas kalsifikasyonları ve ana pankreatik kanal dilatasyonu izleniyor. Bu hastanın patolojisiyle ilgili aşağıdakilerden hangisi doğrudur?","options":["Pankreasın asiner hücrelerinden salgılanan sekretin, duodenal pH yükseldikçe artar.","Asiner hücreler tarafından üretilen tripsinojen, duodenuma geçtikten sonra pankreas kökenli enterokinaz tarafından aktive edilir.","Pankreatik duktal epitelin salgıladığı bikarbonat, CCK uyarımıyla değil sekretin uyarımıyla salınır.","Kronik pankreatitte en erken ve en belirgin etkilenen fonksiyon endokrin pankreas fonksiyonudur.","Pankreas lipazı, safra asitleriyle aktive edilmek zorundadır ve safrasız ortamda hiç çalışmaz."],"correct":2,"exp":"Pankreas duktal epitel hücreleri, sekretin uyarımıyla yüksek hacimli ve bikarbonat açısından zengin bir salgı üretir. Bu salgı, duodenuma gelen aside karşı pH tamponlaması sağlar. CCK (kolesistokinin) ise asiner hücrelerden enzim (amilaz, lipaz, proteaz) salgılanmasını uyarır. Diğer seçenekler yanlıştır: Sekretin, duodenal pH düştükçe (asidik ortamda) artar. Tripsinojeni aktive eden enzim enterokinaz (enteropeptidaz) olup bu enzim pankreas değil ince barsak fırçamsı kenar epitelinden salgılanır. Kronik pankreatitte ekzokrin fonksiyon endokrin fonksiyondan daha erken ve daha belirgin etkilenir. Pankreas lipazı safrasız ortamda da çalışır; ancak kolipaz ve safra asitleri etkinliğini artırır."},{"id":10073,"ders":"Fizyoloji","konu":"Kas Dokusu HistoFizyolojisi","diff":4,"q":"52 yaşında erkek hasta, 6 aydır giderek artan kas güçsüzlüğü ve egzersiz intoleransı yakınmasıyla başvuruyor. Özgeçmişinde tip 2 diyabet nedeniyle metformin kullanımı mevcut. Yapılan kas biyopsisinde subsarkolemmal ve intermiyofibriler bölgelerde anormal mitokondri birikimi saptanıyor; modifiye Gomori trikrom boyasıyla 'ragged-red fiber' görünümü elde ediliyor. Elektromiografide miyopatik patern izleniyor. Serum laktat düzeyi yüksek bulunuyor. Bu hastada enerji metabolizmasındaki temel bozukluğun yol açtığı kas patolojisinde hangi yapısal komplikasyon en erken gelişir?","options":["Sarkoplazmik retikulum proliferasyonu","T-tübül sisteminin geniş çaplı yıkımı","Miyozin ağır zincir izoform değişimi","Satellit hücre havuzunun tükenmesi","Tip I liflerinde atrofi ve tip II liflerinde hipertrofi"],"correct":0,"exp":"Mitokondriyal miyopatilerde oksidatif fosforilasyon bozulunca hücreler, yetersiz ATP üretimine kısmen yanıt olarak mitokondri sayısını ve hacmini artırır; bu mitokondri birikiminin yapısal olarak kendini en erken gösterdiği komşu membran sistemi sarkoplazmik retikulumdur. Subsarkolemmal alanda biriken anormal mitokondrilere eşlik eden SR proliferasyonu, elektron mikroskopisinde erken dönemde saptanabilen ilk yapısal değişikliktir. T-tübül yıkımı, izoform değişimi, satellit hücre tükenmesi ve lif tipi dönüşümü daha ileri evrede ortaya çıkan sekonder uyum yanıtlarıdır."},{"id":10074,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"38 yaşında kadın hasta, ani başlayan göğüs ağrısı ve nefes darlığıyla acil servise getiriliyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %25 olarak ölçülüyor ve bölgesel duvar hareket bozukluğu saptanıyor. Koroner anjiyografide sol ön inen arterde tam tıkanma izleniyor; primer perkütan koroner girişim uygulanıyor. İşlemden 4 saat sonra reperfüzyon sağlanmış olmakla birlikte miyokard hasarı biyobelirteçleri yükselmeye devam ediyor. Patoloji raporunda 'kontraksiyon bandı nekrozu' ve miyosit şişmesi tarif ediliyor. Bu tabloda reperfüzyon hasarının histopatolojik temelini oluşturan başlıca hücresel mekanizmanın yol açacağı en muhtemel ultrastrüktürel bulgu hangisidir?","options":["Miyofibriller arası glikojen birikimi","Mitokondri matriks yoğunluğunun artması","Mitokondri iç membranının düzleşmesi ve matriks şişmesi","Gap junction (konneksin-43) ekspresyonunun artması","Sarkoplazmik retikulum lümeninin daralması"],"correct":2,"exp":"Reperfüzyon hasarının temelinde ani kalsiyum yükü ve reaktif oksijen türlerinin oluşturduğu mitokondriyal permeabilite geçiş poru (mPTP) açılımı yatar. mPTP açılınca mitokondri iç membranının seçici geçirgenliği ortadan kalkar; osmotik su girişiyle matriks şişer, iç membranın karakteristik kıvrımlı (cristae) yapısı düzleşir ve dış membran rüptüre olabilir. Bu bulgu, reperfüzyon hasarında en erken ve özgül ultrastrüktürel değişiklik olarak elektron mikroskopisinde izlenir. Diğer seçenekler iskemi veya adaptasyon süreçleriyle ilişkili olup reperfüzyon hasarının birincil ultrastrüktürel göstergesi değildir."},{"id":10075,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":4,"q":"67 yaşında erkek hasta, 2 yıldır ilerleyici hafıza kaybı, kişilik değişikliği ve yürüme güçlüğü nedeniyle nöroloji polikliniğine başvuruyor. Nöropsikolojik testlerde frontal ve temporal lob disfonksiyonu saptanıyor. Beyin MRI'da simetrik frontal ve temporal atrofi izleniyor. Yapılan beyin biyopsisinde ubikitinle boyanabilen, tau içermeyen sitoplazmik inklüzyonlar ve TDP-43 proteini birikimi raporlanıyor. Eş zamanlı olarak üst ve alt motor nöron bulguları da mevcut.\n\nAşağıdaki öncülleri değerlendiriniz:\nI. TDP-43 normalde nükleusta RNA metabolizmasında görev alır ve patolojide nükleer kayıp ile sitoplazmik birikim birlikte görülür.\nII. Bu tabloda gözlenen patolojik protein birikimi, Alzheimer hastalığındaki nörofibriler yumakla özdeş biyokimyasal yapıya sahiptir.\nIII. Üst ve alt motor nöron bulgularının birlikte varlığı, frontotemporal demans-ALS örtüşme sendromunun klinik göstergesidir.\n\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","Yalnız II","I ve III","II ve III","I, II ve III"],"correct":2,"exp":"Öncül I doğrudur: TDP-43 (TAR DNA-binding protein 43) normalde nükleusta pre-mRNA splicing ve transkripsiyon regülasyonunda görev alır; patolojide karakteristik bulgu nükleer TDP-43'ün sitoplazmaya yer değiştirmesi ve orada fosforile, ubikitinlenmiş inklüzyonlar oluşturmasıdır. Öncül II yanlıştır: Alzheimer'daki nörofibriler yumaklar hiperfosforile tau proteininden oluşur; TDP-43 inklüzyonları ise tau içermez, biyokimyasal yapıları farklıdır. Öncül III doğrudur: Üst motor nöron (spastisite, hiperrefleksi) ve alt motor nöron (fasikülasyon, atrofi) bulgularının frontotemporal demansla birlikteliği, C9orf72 mutasyonu zemininde sık görülen FTD-ALS örtüşme sendromunu tanımlar. Doğru yanıt I ve III'tür."},{"id":10076,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":2,"q":"Böbrek korteksinde bulunan proksimal tübül hücrelerinin apikal yüzeyinde yer alan fırçamsı kenar (brush border), hangi işlevi en doğru biçimde yansıtır?","options":["Tübüler sekresyon kapasitesini artırmak","Geri emilim yüzey alanını genişleterek transporter yoğunluğunu artırmak","Antijen sunumunu kolaylaştırmak","Periglomerüler filtrasyonu düzenlemek","Parakrin sinyal iletimini sağlamak"],"correct":1,"exp":"Proksimal tübül hücrelerinin apikal yüzeyindeki fırçamsı kenar, çok sayıda mikrovillustan oluşur ve lümene bakan yüzey alanını yaklaşık 40 kata kadar genişletir. Bu yapısal düzenleme; glukoz, amino asitler, fosfat ve sodyum gibi filtratın büyük çoğunluğunun yeniden emiliminden sorumlu taşıyıcı (transporter) proteinlerin yoğunluğunun ve işlevsel kapasitesinin artırılmasına doğrudan olanak tanır. Proksimal tübülde filtratın yaklaşık %65-70'i bu segment boyunca geri emilir; fırçamsı kenar bu yüksek reabsorbsiyon kapasitesinin temel histolojik altyapısıdır."},{"id":10077,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":3,"q":"29 yaşında erkek hasta, 3 yıldır tekrarlayan akciğer enfeksiyonları, bronşiektazi ve kronik sinüzit öyküsüyle göğüs hastalıkları polikliniğine başvuruyor. Ayrıca çocukluk çağında tespit edilmiş situs inversus totalis mevcuttur. Yapılan nasal nitrik oksit ölçümü belirgin düşük bulunuyor; elektroskopi incelemesinde siliyaların iç dynein kolunun eksik olduğu raporlanıyor.\n\nAşağıdaki öncülleri değerlendiriniz:\nI. Bu tabloda mukosiliyer klirens bozukluğu, siliyaların '9+2' mikrotübül düzenini tamamen kaybetmesinden kaynaklanır.\nII. Dynein ATPaz aktivitesinin yokluğu, dış mikrotübül çiftleri arasındaki kayma hareketini engeller ve silia vuruşunu ortadan kaldırır.\nIII. Situs inversus varlığı, embriyonik sol-sağ eksen belirlenmesinde nodal siliyer akımın bozulmasıyla ilişkilidir.\n\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","Yalnız 1 tanesi","2 tanesi","3 tanesi","Yalnız I ve III"],"correct":2,"exp":"Öncül I yanlıştır: Primer siliyer diskineziде (PCD) '9+2' aksonemik yapı genel olarak korunur; temel bozukluk dynein kol eksikliği gibi motor protein defektleridir, mikrotübül sayısı genellikle normaldir. Öncül II doğrudur: Dynein, dış mikrotübül çiftleri (A alt tübülünden komşu B alt tübülüne) arasında ATP hidrolizine bağlı kayma kuvveti üretir; dynein ATPaz eksikliği bu kayma hareketini engeller ve etkin silia vuruşu gerçekleşemez. Öncül III doğrudur: Embriyonik nodun silia hareketleri, sol tarafa yönelen bir morfogen akımı (nodalflow) oluşturarak sol-sağ eksen asimetrisini belirler; bu siliyaların işlev görmediği PCD'de nodal akım bozulur ve situs inversus ya da situs ambiguus gibi lateralizasyon defektleri ortaya çıkabilir. Doğru öncül sayısı 2'dir (II ve III)."},{"id":10078,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"44 yaşında kadın hasta, 5 yıldır süren dispepsi, kilo kaybı ve epigastrik ağrı yakınmalarıyla başvuruyor. Üst gastrointestinal endoskopide mide korpus ve fundusunda mukoza solukluğu ve incelme izleniyor; biyopsilerde oksintik bez kaybı, yaygın intestinal metaplazi ve yoğun lenfosit infiltrasyonu saptanıyor. Anti-pariyetal hücre ve anti-intrinsik faktör antikorları pozitif bulunuyor. Hemogram incelemesinde MCV: 118 fL, hipersegmente nötrofiller ve megaloblastik anemi tablosu mevcuttur. Bu hastaya sianokobalamin replasmanı başlanmasına karar veriliyor.\n\nBu hastada sianokobalamin replasmanının oral değil intramüsküler yoldan verilmesinin temel gerekçesi, aşağıdaki öncüllerden hangisi ya da hangileriyle açıklanır?\nI. İntrinsik faktör yokluğunda terminal ileum enterosite özgül reseptör (kubam) bağımlı B12 emilimi gerçekleşemez.\nII. Pasif difüzyonla emilen B12 miktarı terapötik replasmanı karşılamak için yeterlidir.\nIII. Pariyetal hücre kaybı, mide asit sekresyonunu azaltarak diyet proteinlerine bağlı B12'nin serbest bırakılmasını da bozar.","options":["Yalnız I","Yalnız II","I ve III","II ve III","I, II ve III"],"correct":2,"exp":"Öncül I doğrudur: İntrinsik faktör (IF), pariyetal hücrelerce salgılanır ve terminal ileumda kubam reseptörü (cubilin + amniyonless kompleksi) aracılığıyla IF-B12 kompleksinin emilimini sağlar. Otoimmün gastrit gibi pariyetal hücre yıkımıyla seyreden tablolarda IF üretimi durur ve bu reseptör yolağı işlevsiz kalır; oral B12 yeterince emilemez. Öncül II yanlıştır: Oral B12'nin yaklaşık %1-2'si pasif difüzyonla emilebilir; ancak bu miktar ağır megaloblastik anemide replasmanı karşılamak için yetersizdir ve tedavide güvenilir bir yol sayılmaz, bu nedenle parenteral yol tercih edilir. Öncül III doğrudur: Pariyetal hücre kaybı hem IF eksikliğine hem de aklorhidriye yol açar; mide asidinin azalması, besinlere bağlı B12'nin proteazlarla serbest bırakılması adımını da bozarak emilim yetersizliğini pekiştirir. Doğru yanıt I ve III'tür."},{"id":10079,"ders":"Fizyoloji","konu":"Kardiyovasküler Sistem HistoFizyolojisi","diff":4,"q":"62 yaşında erkek hasta, efor dispnesi ve bacaklarda şişlik yakınmasıyla başvuruyor. Ekokardiyografide sol ventrikül ejeksiyon fraksiyonu %30 olarak saptanıyor. Hastaya nörohümoral aktivasyonu baskılamak amacıyla spironolakton başlanıyor. Bu ilacın kardiyak remodelingi azaltmasındaki temel hedef yapı aşağıdakilerden hangisidir?","options":["Kardiyomiyosit Z diski","Kardiyomiyosit interkalar disk bağlantısı","Kardiyak fibroblast mineralokortikoid reseptörü","Sinüs nodu If kanalı","Kardiyak kapiller endotel hücresi"],"correct":2,"exp":"Spironolakton, mineralokortikoid reseptör antagonistidir. Kalp yetmezliğinde aldosteron aşırı aktivasyonu esas olarak kardiyak fibroblastlar üzerindeki mineralokortikoid reseptörleri aracılığıyla miyokard fibrozisini artırır ve remodelingi hızlandırır. Spironolaktanın bu fibroblastlardaki reseptörleri bloke etmesi, kollajen birikimini azaltarak kardiyak remodelingi yavaşlatır. İnterkalar disk ve Z diski yapısal bileşenlerdir, If kanalı otomatisitenin iyon kanalıdır, kapiller endotel ise bu ilacın birincil hedefi değildir."},{"id":10080,"ders":"Fizyoloji","konu":"Solunum Sistemi HistoFizyolojisi","diff":4,"q":"28 yaşında erkek hasta, uzun süreli sigara kullanımı olmaksızın tekrarlayan pnömotoraks atakları nedeniyle inceleniyor. Akciğer biyopsisinde distal bronşiyollerin ötesinde hava yolu duvarlarındaki elastin yıkımı ve makrofaj birikimi saptanıyor. Bu hastada sorumlu mekanizmayı en doğru yansıtan patolojik bulgu aşağıdakilerden hangisidir?","options":["Tip I pnömosit hiperplazisi","Goblet hücresi metaplazisi","Alveolar septalarda elastaz-antielastaz dengesizliğine bağlı septal yıkım","Bronşiyal düz kas hipertrofisi","Tip II pnömosit surfaktan yetersizliği"],"correct":2,"exp":"Genç, sigara içmeyenlerde tekrarlayan pnömotoraks ve biyopside elastin yıkımı ve makrofaj birikimi; alfa-1 antitripsin eksikliğine bağlı panasiner amfizemi düşündürür. Bu durumda nötrofil ve makrofaj elastazı yeterince inhibe edilemez, alveolar septalardaki elastin yıkılır ve hava hapsi ile büller oluşur. Surfaktan yetersizliği prematürelerde görülen IRDS ile ilgilidir. Goblet metaplazisi kronik bronşitte, düz kas hipertrofisi astımda baskındır. Tip I pnömosit hiperplazisi ise hasarın değil tamirin göstergesidir."},{"id":10081,"ders":"Fizyoloji","konu":"Üriner Sistem HistoFizyolojisi","diff":4,"q":"55 yaşında kadın hasta, kontrolsüz hipertansiyon ve hematüri nedeniyle nefrolojiye yönlendiriliyor. Böbrek biyopsisinde glomerüler bazal membranın düzensiz kalınlaşması, podosit ayak çıkıntısı silinmesi ve immünfloresan incelemede granüler IgG ve C3 birikimi saptanıyor. Bu histolojik tabloya sahip hastada en sık görülen klinik komplikasyon aşağıdakilerden hangisidir?","options":["Proksimal tübül ATN gelişimi","Nefrotik düzeyde proteinüri ve hipoalbüminemi","Renal papiller nekroz","İntertisyel fibrozis ve tübüler atrofi","Hızlı ilerleyici glomerülonefrit tablosu"],"correct":1,"exp":"Granüler IgG ve C3 birikimi ile bazal membran kalınlaşması ve yaygın podosit ayak çıkıntısı silinmesi membranöz nefropatinin klasik bulgularıdır. Membranöz nefropati, yetişkinlerde en sık nefrotik sendrom nedenlerinden biridir; masif proteinüri (>3.5 g/gün), hipoalbüminemi, ödem ve hiperlipidemi ile prezente olur. Hızlı ilerleyici GN'de kresentler ve lineer birikimler beklenir. Renal papiller nekroz analjezik nefropatisi veya diyabette görülür. İntertisyel fibrozis kronik hasarın geç komplikasyonudur."},{"id":10082,"ders":"Fizyoloji","konu":"Sinir Sistemi HistoFizyolojisi","diff":3,"q":"Bir araştırmada miyelinli ve miyelinsiz sinir liflerinin iletim hızları karşılaştırılıyor. Aşağıdaki öncülleri değerlendirin:\nI. Miyelin kılıfı, akson boyunca kapasitansı artırır ve membran direncini azaltır.\nII. Ranvier boğumlarında iyon kanallarının yoğunlaşması saltatorik iletimi mümkün kılar.\nIII. C lifleri miyelinsiz olduğundan aksiyon potansiyeli her noktada yeniden oluşmak zorundadır ve bu durum iletimi yavaşlatır.\nYukarıdaki öncüllerden hangileri doğrudur?","options":["Yalnız I","Yalnız II","I ve III","II ve III","I, II ve III"],"correct":3,"exp":"Öncül I yanlıştır: Miyelin kılıfı aksonun kapasitansını AZALTIR ve membran direncini ARTTIRIR; bu sayede akım boğumdan boğuma sıçrayabilir. Öncül II doğrudur: Ranvier boğumlarında Na+ kanalları yoğun biçimde kümelenir ve aksiyon potansiyeli yalnızca bu noktalarda yeniden oluşturularak saltatorik (sıçrayıcı) iletim gerçekleşir. Öncül III doğrudur: C lifleri miyelinsiz, küçük çaplı liflerdir; aksiyon potansiyeli membranın her noktasında sırayla oluştuğundan iletim hızı en yavaş olanıdır (0.5-2 m/s). Bu nedenle doğru öncüller II ve III'tür."},{"id":10083,"ders":"Fizyoloji","konu":"Gastrointestinal Sistem HistoFizyolojisi","diff":4,"q":"48 yaşında erkek hasta, uzun yıllardır alkol kullanımı öyküsüyle steatore, kilo kaybı ve tekrarlayan karın ağrısı yakınmalarıyla başvuruyor. Fekal elastaz düzeyi düşük saptanıyor ve görüntülemede pankreatik kalsifikasyon izleniyor. Hastaya enzim replasman tedavisi başlanıyor. Bu tedavinin etkin olabilmesi için pankreas asiner hücrelerinin ürettiği hangi enzimatik öncül yapının duodenumda aktive edilmesi zorunludur?","options":["Pepsinojen","Prokarboksipeptidaz","Prolipaz","Tripsinojen","Kimotripsinojen"],"correct":3,"exp":"Kronik pankreatit tablosunda pankreas ekzokrin yetmezliği gelişir. Pankreas asiner hücreleri, proteolitik enzimleri inaktif zimojen formunda salgılar. Tripsinojen, duodenumdaki fırça kenarı enzimi olan enteropeptidaz (enterokinaz) tarafından aktif tripsin formuna dönüştürülür. Tripsin, daha sonra kimotripsinojen, prokarboksipeptidaz ve diğer zimojenleri aktive eden anahtar enzimdir. Enzim replasman preparatlarında tripsinojen aktifleşmesi zincirleme aktivasyonu başlattığından kritik öneme sahiptir. Pepsinojen mide kaynaklıdır. Prolipaz ve diğerleri aktivasyon için tripsine bağımlıdır, bu nedenle tripsinojen zincirin başlangıç noktasıdır."},{"id":10084,"ders":"Fizyoloji","konu":"Hematopoetik Sistem HistoFizyolojisi","diff":2,"q":"Kemik iliği aspirasyonunda eritroid prekürsörlerin aşırı artışı ve periferik yaymada hiperkrom, makrositik eritrositler saptanan bir hastada santral sinir sistemi bulguları da eşlik etmektedir. Aşağıdaki öncülleri değerlendirin:\nI. Bu tabloda Schilling testi patolojik saptanıyorsa B12 emilim bozukluğu düşünülmelidir.\nII. İç faktör (intrinsik faktör) mide fundusundaki parietal hücrelerden salgılanır ve ileum sonunda B12 emilimini sağlar.\nIII. Folik asit replasmanı tek başına verildiğinde nörolojik bulguları da düzeltir.\nYukarıdaki öncüllerden kaç tanesi doğrudur?","options":["Hiçbiri","Yalnız biri","Yalnız ikisi","Üçü de","Belirlenemiyor"],"correct":2,"exp":"Öncül I doğrudur: Schilling testi B12 malabsorbsiyonunu değerlendirmek için kullanılır; patolojik sonuç intrinsik faktör eksikliği veya terminal ileum hastalığını gösterir. Öncül II doğrudur: İntrinsik faktör, mide fundus ve kardiyasındaki parietal hücrelerden salgılanır; B12 ile oluşturduğu kompleks terminal ileumda özel reseptörler aracılığıyla emilir. Öncül III yanlıştır: Folik asit replasmanı hematolojik bulguları düzeltebildiği hâlde nörolojik tabloyu (subakut kombine dejenerasyon) iyileştirmez; aksine B12 eksikliğini maskeleyebilir ve nörolojik hasarın ilerlemesine izin verebilir. Doğru öncül sayısı ikidir (I ve II)."}];
